// menu_produto.js
// v4.0 - Sincronização automática Omie→PostgreSQL antes de abrir produto
const API_BASE = window.location.origin; // já serve https://intranet-30av.onrender.com

window.storagePublicUrl = function storagePublicUrl(relativePath) {
  const base = String(window.__STORAGE_PUBLIC_BASE_URL || '').replace(/\/$/, '');
  const rel = String(relativePath || '').replace(/^\/+/, '');
  return base ? `${base}/${rel}` : '';
};

// Silencia TODOS os logs de console EXCETO diagnóstico de produtos
;(function silenceAllLogs(){
  try {
    const _log = console.log.bind(console);
    const _warn = console.warn.bind(console);
    const _error = console.error.bind(console);
    console.log = (...args) => {
      // Permite apenas logs de DIAGNÓSTICO-PRODUTO
      if (typeof args[0] === 'string' && args[0].includes('[DIAGNÓSTICO-PRODUTO]')) {
        _log(...args);
        return;
      }
    };
    console.warn = () => {};
    console.error = () => {};
  } catch {}
})();

// ============================================================================
// SISTEMA CENTRAL DE NAVEGAÇÃO - Garante que só 1 página seja visível por vez
// ============================================================================
window.clearMainContainer = function() {
  try {
    const main = document.querySelector('.main-container');
    if (!main) return;
    
    // Força TODOS os filhos a ficarem invisíveis
    Array.from(main.children).forEach(el => {
      if (!el) return;
      // Use apenas display para não quebrar layout/restauração
      el.style.display = 'none';
      // Limpa quaisquer efeitos anteriores caso existam
      el.style.visibility = '';
      el.style.opacity = '';
      el.style.position = '';
      el.style.left = '';
    });
    
    console.log('[NAV] Container principal limpo - todos os filhos ocultos');
  } catch(e) {
    console.error('[NAV] Erro ao limpar container:', e);
  }
};

window.showOnlyInMain = function(element) {
  try {
    if (!element) {
      console.warn('[NAV] showOnlyInMain: elemento inválido');
      return;
    }
    
    // Limpa TUDO primeiro
    window.clearMainContainer();
    
    // Mostra SOMENTE o elemento especificado
    // Use 'flex' se o elemento é tab-pane (CSS o define com display:flex), caso contrário use 'block'
    const displayValue = element.classList?.contains('tab-pane') ? 'flex' : 'block';
    element.style.display = displayValue;
    // Restaura propriedades possivelmente alteradas por outras telas
    element.style.visibility = '';
    element.style.opacity = '';
    element.style.position = '';
    element.style.left = '';
    
    console.log('[NAV] Mostrando apenas:', element.id || element.className, '(display:', displayValue + ')');
  } catch(e) {
    console.error('[NAV] Erro ao mostrar elemento:', e);
  }
};

window.forceShowInicio = function() {
  try {
    // Garante que o overlay de boot não cubra o calendário
    try {
      document.body.classList.add('app-ready');
      const ov = document.getElementById('app-boot-overlay');
      if (ov) ov.remove();
    } catch (_) {}

    const main = document.querySelector('.main-container');
    const inicio = document.getElementById('paginaInicio');
    if (!main || !inicio) return;

    Array.from(main.children).forEach((el) => {
      if (!el) return;
      el.style.display = 'none';
    });

    // Use 'flex' se o elemento é tab-pane (CSS o define com display:flex)
    const displayValue = inicio.classList?.contains('tab-pane') ? 'flex' : 'block';
    inicio.style.display = displayValue;
    inicio.style.visibility = 'visible';

    const produtoTabs = document.getElementById('produtoTabs');
    const kanbanTabs = document.getElementById('kanbanTabs');
    const armazemTabs = document.getElementById('armazemTabs');
    const armazemContent = document.getElementById('armazemContent');
    if (produtoTabs) produtoTabs.style.display = 'none';
    if (kanbanTabs) kanbanTabs.style.display = 'none';
    if (armazemTabs) armazemTabs.style.display = 'none';
    if (armazemContent) armazemContent.style.display = 'none';

    const mainHeader = document.querySelector('.main-header');
    if (mainHeader) mainHeader.style.display = 'none';

    const menuInicio = document.getElementById('menu-inicio');
    document.querySelectorAll('.header .header-menu > .menu-link').forEach((a) => a.classList.remove('is-active'));
    if (menuInicio) menuInicio.classList.add('is-active');
  } catch (_) {}
};

// Inicializa a página mostrando APENAS o painel inicial
document.addEventListener('DOMContentLoaded', () => {
  console.log('[NAV] Inicializando navegação - mostrando página inicial');
  const paginaInicio = document.getElementById('paginaInicio');
  if (paginaInicio) {
    window.showOnlyInMain(paginaInicio);
  } else {
    window.forceShowInicio?.();
  }

  const menuInicio = document.getElementById('menu-inicio');
  if (menuInicio && !menuInicio.dataset.forceInicioBound) {
    menuInicio.dataset.forceInicioBound = '1';
    menuInicio.addEventListener('click', (ev) => {
      ev.preventDefault();
      window.forceShowInicio?.();
    }, true);
  }
});

// Central mobile: cards da Início são montados pelo sistema de preferências (flag_inicio).

// ============================================================================
// GUIAS: Lista de produtos / Solicitações
// ============================================================================
document.addEventListener('DOMContentLoaded', () => {
  const tabBtns = document.querySelectorAll('.lp-tab-btn[data-lp-tab]');
  const tabPanes = {
    listaProdutosConteudo: document.getElementById('listaProdutosConteudo'),
    solicitacoesConteudo: document.getElementById('solicitacoesConteudo'),
    kanbanSolicitacoesConteudo: document.getElementById('kanbanSolicitacoesConteudo'),
  };

  tabBtns.forEach(btn => {
    btn.addEventListener('click', () => {
      const targetId = btn.dataset.lpTab;
      // Atualiza botões
      tabBtns.forEach(b => b.classList.remove('lp-tab-active'));
      btn.classList.add('lp-tab-active');

      // Mostra/esconde conteúdo
      Object.entries(tabPanes).forEach(([id, el]) => {
        if (!el) return;
        el.style.display = id === targetId ? '' : 'none';
      });

      // Remove tooltip kanban que possa ter ficado visível ao trocar aba
      window._kanbanTooltipEl?.remove();
      window._kanbanTooltipEl = null;
      clearTimeout(window._kanbanTooltipTimer);

      // Carrega/recarrega solicitações e kanban sempre que a aba é aberta
      if (targetId === 'solicitacoesConteudo' && typeof window._loadSolicitacoesTab === 'function') {
        window._loadSolicitacoesTab.force = true;
        window._loadSolicitacoesTab();
      }
      if (targetId === 'kanbanSolicitacoesConteudo' && typeof window._loadKanbanSolicitacoesTab === 'function') {
        window._loadKanbanSolicitacoesTab.force = true;
        window._loadKanbanSolicitacoesTab();
      }
    });
  });

  // Botão de refresh da aba solicitações
  const refreshSolicBtn = document.getElementById('solicitacoesRefreshBtn');
  if (refreshSolicBtn) {
    refreshSolicBtn.addEventListener('click', () => {
      const board = document.getElementById('solicitacoesKanbanBoard');
      if (board) delete board.dataset.loaded;
      window._loadSolicitacoesTab.force = true;
      window._loadSolicitacoesTab();
    });
  }

  const solicitacoesPesquisa = document.getElementById('solicitacoesPesquisa');
  const solicitacoesPesquisaLimpar = document.getElementById('solicitacoesPesquisaLimpar');
  let solicitacoesPesquisaTimer = null;
  const pesquisarSolicitacoes = () => {
    if (solicitacoesPesquisaLimpar) {
      solicitacoesPesquisaLimpar.style.display = solicitacoesPesquisa?.value.trim() ? '' : 'none';
    }
    window._loadSolicitacoesTab.force = true;
    window._loadSolicitacoesTab();
  };
  solicitacoesPesquisa?.addEventListener('input', () => {
    clearTimeout(solicitacoesPesquisaTimer);
    solicitacoesPesquisaTimer = setTimeout(pesquisarSolicitacoes, 300);
  });
  solicitacoesPesquisaLimpar?.addEventListener('click', () => {
    if (solicitacoesPesquisa) solicitacoesPesquisa.value = '';
    clearTimeout(solicitacoesPesquisaTimer);
    pesquisarSolicitacoes();
    solicitacoesPesquisa?.focus();
  });

  document.getElementById('arm3dPlanejarSepFechar')?.addEventListener('click', () => {
    if (typeof window._arm3dFecharPlanejarSeparacao === 'function') {
      window._arm3dFecharPlanejarSeparacao();
    }
  });
  document.getElementById('arm3dPlanejarSepModal')?.addEventListener('click', (e) => {
    if (e.target?.id === 'arm3dPlanejarSepModal' && typeof window._arm3dFecharPlanejarSeparacao === 'function') {
      window._arm3dFecharPlanejarSeparacao();
    }
  });

  // Botão de refresh do kanban de solicitações
  const refreshKanbanBtn = document.getElementById('kanbanSolicRefreshBtn');
  if (refreshKanbanBtn) {
    refreshKanbanBtn.addEventListener('click', () => {
      window._loadKanbanSolicitacoesTab.force = true;
      window._loadKanbanSolicitacoesTab();
    });
  }

  // Atualiza contadores das guias ao carregar a página
  if (typeof window._updateTabCounters === 'function') {
    window._updateTabCounters();
  }
});

// Helpers compartilhados pela aba de solicitações
function _solFmtQty(q) {
  const n = parseFloat(q);
  return Number.isInteger(n) ? String(n) : n.toFixed(3).replace(/\.?0+$/, '');
}
function _solBtnLoading(btn, label) {
  if (!btn || btn.dataset.solLoading === '1') return;
  btn.dataset.solOrigHtml = btn.innerHTML;
  btn.dataset.solLoading = '1';
  btn.disabled = true;
  btn.innerHTML = `<i class="fa-solid fa-spinner fa-spin" style="margin-right:3px;"></i>${label != null ? label : '...'}`;
}
function _solBtnRestore(btn, fallbackHtml) {
  if (!btn) return;
  btn.disabled = false;
  btn.dataset.solLoading = '0';
  btn.innerHTML = btn.dataset.solOrigHtml || fallbackHtml || '';
  delete btn.dataset.solOrigHtml;
}
function _solRowLoading(row, loading) {
  if (!row) return;
  row.querySelectorAll('button').forEach(b => { b.disabled = !!loading; });
  const qtyWrap = row.querySelector('.sep-qty-wrap');
  if (qtyWrap) qtyWrap.style.opacity = loading ? '0.55' : '1';
  let sp = row.querySelector('.sep-row-loading');
  if (loading) {
    if (!sp && qtyWrap) {
      sp = document.createElement('span');
      sp.className = 'sep-row-loading';
      sp.style.cssText = 'display:inline-flex;align-items:center;margin-left:4px;';
      sp.innerHTML = '<i class="fa-solid fa-spinner fa-spin" style="color:#93c5fd;font-size:.72rem;"></i>';
      qtyWrap.appendChild(sp);
    }
  } else {
    sp?.remove();
  }
}
function _solFmtDataPrevista(d) {
  if (!d) return '';
  const s = String(d).substring(0, 10); // garante "YYYY-MM-DD"
  const parts = s.split('-');
  if (parts.length !== 3) return '';
  return `${parts[2]}/${parts[1]}/${parts[0]}`;
}
function _solFmtDataHora(d) {
  if (!d) return '';
  const dt = new Date(d);
  if (Number.isNaN(dt.getTime())) return '';
  return dt.toLocaleString('pt-BR', {
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit'
  });
}
function _solStatusBadge(status) {
  const map = {
    'pendente':  { color: '#6b7280', bg: '#1f2937', label: 'Pendente' },
    'Separação': { color: '#f59e0b', bg: '#292218', label: 'Separação' },
    'Separado':  { color: '#22c55e', bg: '#0f2018', label: 'Separado' },
  };
  const s = map[status] || { color: '#6b7280', bg: '#1f2937', label: status || '?' };
  return `<span style="display:inline-block;padding:2px 7px;border-radius:20px;font-size:.68rem;font-weight:700;color:${s.color};background:${s.bg};border:1px solid ${s.color}33;">${s.label}</span>`;
}
function _solKanbanLoading(show, label) {
  const id = 'solKanbanLoadingOverlay';
  if (!show) {
    document.getElementById(id)?.remove();
    return;
  }
  document.getElementById(id)?.remove();
  const el = document.createElement('div');
  el.id = id;
  el.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,.5);z-index:10045;display:flex;align-items:center;justify-content:center;';
  el.innerHTML = `<div style="background:#1c1c1c;border:1px solid #333;border-radius:12px;padding:22px 30px;display:flex;flex-direction:column;align-items:center;gap:10px;box-shadow:0 12px 40px rgba(0,0,0,.5);">
    <i class="fa-solid fa-spinner fa-spin" style="font-size:1.6rem;color:#f59e0b;"></i>
    <span style="color:#d1d5db;font-size:.85rem;font-weight:600;">${label || 'Carregando...'}</span>
  </div>`;
  document.body.appendChild(el);
}
async function _solCarregarEnderecoBatch(codigos) {
  const list = [...new Set((codigos || []).map(c => String(c || '').trim()).filter(Boolean))];
  if (!list.length) return {};
  try {
    const r = await fetch('/api/logistica/endereco-pp/batch?codigos=' + encodeURIComponent(list.join(',')), { credentials: 'include' });
    const d = await r.json();
    return d.ok ? (d.dados || {}) : {};
  } catch (_) {
    return {};
  }
}
function _solMergeEnderecoBatch(itens, batch) {
  const map = { ...(batch || {}) };
  for (const it of (itens || [])) {
    const cod = String(it.codigo_produto || '').trim();
    if (!cod) continue;
    const ep = it.endereco_pp;
    if (Array.isArray(ep) && ep.length && (!map[cod] || !map[cod].length)) map[cod] = ep;
  }
  return map;
}

function _solEnderecoLegendaHtml(registros) {
  const segmentos = Math.max(0, ...(registros || []).map(ep =>
    String(ep.endereco || ep.completo || '').trim().split('-').filter(Boolean).length
  ));
  const campos = segmentos >= 4
    ? [['R', 'Rua'], ['NV', 'Nível'], ['AP', 'Apartamento'], ['VÃO', 'Vão']]
    : segmentos === 3
      ? [['R', 'Rua'], ['NV', 'Nível'], ['AP', 'Apartamento']]
      : [['R', 'Rua'], ['AP', 'Apartamento']];
  return `<div class="sep-endereco-legenda">
    <div>${campos.map(([sigla]) => `<strong>${sigla}</strong>`).join('<span>|</span>')}</div>
    <small>${campos.map(([, nome]) => nome.toUpperCase()).join(' - ')}</small>
  </div>`;
}

function _solEnderecamentoHtml(codigo, enderecoMap, itemFallback) {
  const cod = String(codigo || '').trim();
  let registros = cod ? enderecoMap?.[cod] : null;
  if ((!Array.isArray(registros) || !registros.length) && cod && enderecoMap) {
    const altKey = Object.keys(enderecoMap).find(k => String(k).trim() === cod);
    if (altKey) registros = enderecoMap[altKey];
  }
  if ((!Array.isArray(registros) || !registros.length) && itemFallback) {
    const fromItem = itemFallback.endereco_pp || itemFallback.enderecos_pp;
    if (Array.isArray(fromItem) && fromItem.length) registros = fromItem;
  }
  if (!Array.isArray(registros) || !registros.length) return '';
  const gridCols = 'minmax(120px,1fr) minmax(64px,auto)';
  const head = '';
  const linhas = registros.map(ep => {
    const end = escapeHtml(String(ep.endereco || ep.completo || '').trim());
    if (!end) return '';
    const qtd = escapeHtml(String(ep.qtd != null ? ep.qtd : '0'));
    const un = escapeHtml(String(ep.unidade || 'UN'));
    return `<div style="display:grid;grid-template-columns:${gridCols};gap:4px 8px;padding:4px 0;border-top:1px solid #854d0e33;font-size:.68rem;line-height:1.35;align-items:center;">
      <span style="color:#fde68a;font-weight:700;word-break:break-word;">${end}</span>
      <span style="color:#cbd5e1;font-weight:700;text-align:right;">${qtd} ${un}</span>
    </div>`;
  }).filter(Boolean).join('');
  if (!linhas) return '';
  return `<div style="padding:6px 8px;background:#1a1508;border:1px solid #854d0e55;border-radius:8px;">
    ${_solEnderecoLegendaHtml(registros)}
    ${head}${linhas}
  </div>`;
}

function _solEtqSelecaoKey(sel) {
  return String((sel && (sel.id || sel.endereco)) || '');
}

function _solLerSelecoesEtq(row) {
  try {
    const arr = JSON.parse(row?.dataset?.etqSelecoes || '[]');
    return Array.isArray(arr) ? arr : [];
  } catch (_) {
    return [];
  }
}

/** Extrai o ID numérico do QR da etiqueta (formato COD|DESC|LOTE|ID123 ou só número). */
function _solParseEtqIdFromQr(valor) {
  const raw = String(valor || '').trim();
  if (!raw) return null;
  const parts = raw.split('|');
  const last = parts[parts.length - 1];
  const m = String(last).match(/^ID(\d+)$/i);
  if (m) return parseInt(m[1], 10);
  const only = raw.match(/ID(\d+)/i);
  if (only) return parseInt(only[1], 10);
  const n = parseInt(raw, 10);
  return Number.isFinite(n) && n > 0 && String(n) === raw.replace(/\s+/g, '') ? n : null;
}

/** Seleciona IDs do menor → maior até cobrir a qtd necessária. */
function _solPickIdsFifoAteQty(etiquetas, qtyNeeded) {
  const need = Math.max(0, parseFloat(qtyNeeded) || 0);
  const sorted = (Array.isArray(etiquetas) ? etiquetas.slice() : [])
    .filter(e => (Number(e.qtd) || 0) > 0 && e.id != null)
    .sort((a, b) => Number(a.id) - Number(b.id));
  let remaining = need;
  const out = [];
  for (const e of sorted) {
    if (remaining <= 1e-9) break;
    const saldo = Math.max(0, parseFloat(e.qtd) || 0);
    if (saldo <= 0) continue;
    const tirar = Math.min(saldo, remaining);
    out.push({
      id: Number(e.id),
      qtd: saldo,
      tirar,
      unidade: e.unidade || 'UN',
      endereco: String(e.endereco || '').trim()
    });
    remaining = Math.max(0, remaining - tirar);
  }
  return { ids: out, remaining };
}

function _solRenderIdsFifoHtml(idsFifo, unidade) {
  const lista = Array.isArray(idsFifo) ? idsFifo : [];
  if (!lista.length) {
    return `<div class="sep-etq-ids-fifo" style="margin-top:6px;width:100%;max-width:220px;padding:6px 8px;border-radius:8px;background:#0f172a;border:1px solid #334155;font-size:.62rem;color:#94a3b8;">
      Nenhum ID com saldo no Porta Pallet para esta qtd.
    </div>`;
  }
  const rows = lista.map((e, idx) => {
    const next = idx === 0 ? '1' : '0';
    return `<div class="sep-etq-id-row" data-etq-id="${e.id}" data-next="${next}"
      style="display:flex;justify-content:space-between;gap:6px;padding:3px 0;border-top:1px solid #1e293b;${idx === 0 ? 'color:#86efac;font-weight:700;' : 'color:#cbd5e1;'}">
      <span>ID ${e.id}${idx === 0 ? ' ← ler' : ''}</span>
      <span style="white-space:nowrap;">${_solFmtQty(e.tirar)} ${escapeHtml(unidade || e.unidade || 'UN')}</span>
    </div>`;
  }).join('');
  return `<div class="sep-etq-ids-fifo" style="margin-top:6px;width:100%;max-width:220px;padding:6px 8px;border-radius:8px;background:#0f172a;border:1px solid #334155;">
    <div style="font-size:.58rem;color:#94a3b8;font-weight:700;margin-bottom:2px;letter-spacing:.03em;text-transform:uppercase;">IDs a coletar (menor → maior)</div>
    ${rows}
    <button type="button" class="btn-ler-etq-fifo"
      style="margin-top:6px;width:100%;padding:5px 8px;border:none;border-radius:6px;background:#059669;color:#ecfdf5;font-size:.68rem;font-weight:700;cursor:pointer;">
      <i class="fa-solid fa-qrcode" style="margin-right:4px;"></i>Ler próxima etiqueta
    </button>
    <button type="button" class="btn-sem-leitura-etq" title="Consome automaticamente os menores IDs, sem escanear"
      style="margin-top:5px;width:100%;padding:5px 8px;border:1px solid #475569;border-radius:6px;background:#1e293b;color:#cbd5e1;font-size:.66rem;font-weight:700;cursor:pointer;">
      <i class="fa-solid fa-forward" style="margin-right:4px;"></i>Sem leitura
    </button>
  </div>`;
}

/* ===== Câmera do leitor de etiquetas: helpers para evitar a lente 0.5x ===== */

function _sepEtqEhLenteAuxiliar(lbl) {
  return /ultra|wide|angular|tele|macro|depth|profundidade|0[.,]5/i.test(String(lbl || ''));
}

/* Android costuma expor "camera2 0, facing back" — o índice 0 é quase sempre a principal */
function _sepEtqIdxCamera(lbl) {
  const m = /camera2?\s+(\d+)/i.exec(String(lbl || ''));
  return m ? Number(m[1]) : null;
}

async function _sepEtqListarTraseiras() {
  try {
    const devices = await navigator.mediaDevices.enumerateDevices();
    const cams = devices.filter(d => d.kind === 'videoinput');
    const traseiras = cams.filter(d => /back|rear|tras|environment/i.test(d.label || ''));
    const lista = traseiras.length ? traseiras : cams.filter(d => !/front|frontal|user|selfie/i.test(d.label || ''));
    return lista.slice().sort((a, b) => {
      const ia = _sepEtqIdxCamera(a.label);
      const ib = _sepEtqIdxCamera(b.label);
      if (ia != null && ib != null) return ia - ib;
      return 0;
    });
  } catch (_) { return []; }
}

/* Se o navegador expõe controle de zoom (câmera lógica), garante pelo menos 1.0x */
async function _sepEtqNormalizarZoom(streamAtual) {
  try {
    const t = streamAtual?.getVideoTracks?.()[0];
    const caps = t?.getCapabilities?.() || {};
    if (!caps.zoom || typeof caps.zoom.min !== 'number') return;
    const alvo = Math.min(Math.max(1, caps.zoom.min), caps.zoom.max || 1);
    const atual = Number(t.getSettings?.().zoom);
    if (atual >= alvo) return;
    try { await t.applyConstraints({ advanced: [{ zoom: alvo }] }); }
    catch (_) { await t.applyConstraints({ zoom: alvo }).catch(() => {}); }
  } catch (_) { /* aparelho sem suporte a zoom via browser */ }
}

/**
 * Garante que o leitor use a câmera traseira PRINCIPAL (1.0x), não a
 * ultra-wide (0.5x) que alguns celulares entregam com facingMode:environment.
 * 1) Se a lente atual parece auxiliar (ou tem índice maior que a "camera 0"),
 *    troca para a traseira principal.
 * 2) Normaliza o zoom para pelo menos 1.0 quando o browser expõe o controle.
 */
async function _sepEtqGarantirCameraPrincipal(streamAtual) {
  try {
    const track = streamAtual?.getVideoTracks?.()[0];
    if (!track) return streamAtual;
    const atualId = track.getSettings?.().deviceId || null;
    const traseiras = await _sepEtqListarTraseiras();

    let principal = null;
    if (traseiras.length > 1) {
      const normais = traseiras.filter(d => !_sepEtqEhLenteAuxiliar(d.label));
      principal = (normais.length ? normais : traseiras)[0] || null;
    }

    const idxAtual = _sepEtqIdxCamera(track.label);
    const idxPrincipal = principal ? _sepEtqIdxCamera(principal.label) : null;
    const trocar = principal && principal.deviceId && principal.deviceId !== atualId &&
      (_sepEtqEhLenteAuxiliar(track.label) ||
        (idxAtual != null && idxPrincipal != null && idxPrincipal < idxAtual));

    if (trocar) {
      streamAtual.getTracks().forEach(t => t.stop());
      try {
        streamAtual = await navigator.mediaDevices.getUserMedia({
          video: { deviceId: { exact: principal.deviceId } },
          audio: false
        });
      } catch (_) {
        streamAtual = await navigator.mediaDevices.getUserMedia({
          video: { facingMode: { ideal: 'environment' } },
          audio: false
        });
      }
    }
  } catch (_) { /* mantém o stream que conseguiu */ }
  await _sepEtqNormalizarZoom(streamAtual);
  return streamAtual;
}

/**
 * Modal câmera para ler QR das etiquetas (sem digitar).
 * Exige FIFO: sempre o menor ID pendente; outro ID → pedir permissão ao suporte
 * (bypass só com "Permitir sem saldo no endereço").
 */
function _solAbrirLeitorQrIdsSep({ codigoProduto, qtyNeeded, unidade, idsEsperados, permitirForaOrdem }) {
  const cod = String(codigoProduto || '').trim();
  const need = Math.max(0, parseFloat(qtyNeeded) || 0);
  const un = String(unidade || 'UN');
  const fila = (Array.isArray(idsEsperados) ? idsEsperados : [])
    .map(e => ({
      id: Number(e.id),
      saldo: Math.max(0, parseFloat(e.qtd != null ? e.qtd : e.saldo) || 0),
      tirar: Math.max(0, parseFloat(e.tirar) || 0),
      endereco: String(e.endereco || '').trim()
    }))
    .filter(e => e.id && e.tirar > 0)
    .sort((a, b) => a.id - b.id);

  return new Promise((resolve) => {
    const overlay = document.createElement('div');
    overlay.id = 'sepEtqQrOverlay';
    overlay.style.cssText = 'position:fixed;inset:0;z-index:12000;background:rgba(0,0,0,.88);display:flex;align-items:center;justify-content:center;padding:12px;';
    const proximoTxt = fila[0] ? `Próximo: ID <strong style="color:#86efac;">${fila[0].id}</strong>` : 'Nenhum ID na fila';
    overlay.innerHTML = `
      <div style="background:#1e293b;border:1px solid #334155;border-radius:14px;width:min(460px,96vw);overflow:hidden;box-shadow:0 24px 64px rgba(0,0,0,.6);position:relative;">
        <div style="display:flex;align-items:center;justify-content:space-between;padding:14px 18px;background:#0f172a;border-bottom:1px solid #334155;">
          <div style="display:flex;align-items:center;gap:8px;">
            <i class="fa-solid fa-qrcode" style="color:#34d399;font-size:1.1rem;"></i>
            <span style="font-weight:700;color:#f1f5f9;font-size:.95rem;">Ler QR da etiqueta</span>
          </div>
          <button type="button" id="sepEtqQrFechar" style="background:none;border:none;color:#94a3b8;font-size:1.4rem;cursor:pointer;line-height:1;">&times;</button>
        </div>
        <div style="padding:10px 16px 0;font-size:.78rem;color:#94a3b8;line-height:1.4;">
          Produto <strong style="color:#fbbf24;">${escapeHtml(cod)}</strong> · ${_solFmtQty(need)} ${escapeHtml(un)}<br>
          ${proximoTxt} · só leitura (sem digitar)
        </div>
        <div style="position:relative;background:#000;width:100%;aspect-ratio:4/3;overflow:hidden;margin-top:10px;">
          <video id="sepEtqQrVideo" autoplay playsinline muted style="width:100%;height:100%;object-fit:contain;display:block;background:#000;"></video>
          <div style="position:absolute;inset:0;display:flex;align-items:center;justify-content:center;pointer-events:none;">
            <div id="sepEtqQrMira" style="width:200px;height:200px;border:3px solid rgba(52,211,153,.85);border-radius:12px;box-shadow:0 0 0 3000px rgba(0,0,0,.38);"></div>
          </div>
          <button type="button" id="sepEtqQrTrocarCam" title="Trocar câmera"
            style="position:absolute;right:10px;bottom:10px;z-index:5;width:44px;height:44px;border:none;border-radius:50%;background:rgba(15,23,42,.85);color:#e2e8f0;font-size:1.1rem;cursor:pointer;display:flex;align-items:center;justify-content:center;box-shadow:0 2px 8px rgba(0,0,0,.5);">
            <i class="fa-solid fa-camera-rotate"></i>
          </button>
        </div>
        <div id="sepEtqQrStatus" style="padding:12px 16px 16px;font-size:.85rem;color:#94a3b8;text-align:center;min-height:44px;"></div>
        <div id="sepEtqQrLidos" style="padding:0 16px 14px;font-size:.72rem;color:#cbd5e1;max-height:100px;overflow-y:auto;"></div>
        <!-- Campo oculto só para leitor USB (wedge); usuário não digita. -->
        <input id="sepEtqQrInput" type="text" autocomplete="off" tabindex="-1"
          style="position:absolute;left:-9999px;width:1px;height:1px;opacity:0;" aria-hidden="true" />
      </div>`;
    document.body.appendChild(overlay);

    const statusEl = overlay.querySelector('#sepEtqQrStatus');
    const lidosEl = overlay.querySelector('#sepEtqQrLidos');
    const inputEl = overlay.querySelector('#sepEtqQrInput');
    const video = overlay.querySelector('#sepEtqQrVideo');
    const mira = overlay.querySelector('#sepEtqQrMira');
    let stream = null;
    let interval = null;
    let busy = false;
    const leituras = [];
    let remaining = need;
    let filaRestante = fila.slice();

    function _atualizarLidos() {
      const total = leituras.reduce((s, l) => s + (Number(l.tirar) || 0), 0);
      const prox = filaRestante[0];
      if (!leituras.length && !prox) {
        lidosEl.innerHTML = '';
        return;
      }
      lidosEl.innerHTML = leituras.map(l =>
        `<div>✓ ID <strong style="color:#86efac;">${l.id}</strong> → ${_solFmtQty(l.tirar)} ${escapeHtml(un)}</div>`
      ).join('') +
        (prox
          ? `<div style="margin-top:4px;color:#fde68a;">Próximo a ler: <strong>ID ${prox.id}</strong> (${_solFmtQty(prox.tirar)} ${escapeHtml(un)})</div>`
          : '') +
        `<div style="margin-top:2px;color:#94a3b8;">Lido ${_solFmtQty(total)} / ${_solFmtQty(need)} · falta ${_solFmtQty(remaining)}</div>`;
    }

    function _setStatus(msg, cor) {
      if (statusEl) {
        statusEl.textContent = msg;
        statusEl.style.color = cor || '#94a3b8';
      }
    }

    async function _pararCamera() {
      if (interval) { clearInterval(interval); interval = null; }
      if (stream) {
        stream.getTracks().forEach(t => t.stop());
        stream = null;
      }
      if (video) video.srcObject = null;
    }

    function _fechar(ok) {
      _pararCamera();
      overlay.remove();
      resolve(ok ? { ok: true, leituras: leituras.slice() } : { ok: false });
    }

    async function _processarValor(valor) {
      if (busy || remaining <= 1e-9) return;
      const etqId = _solParseEtqIdFromQr(valor);
      if (inputEl) inputEl.value = '';
      if (!etqId) {
        _setStatus('QR não reconhecido. Aponte para a etiqueta.', '#f87171');
        return;
      }
      if (leituras.some(l => Number(l.id) === etqId)) {
        _setStatus(`ID ${etqId} já foi lido.`, '#fbbf24');
        return;
      }

      const proximo = filaRestante[0];
      if (proximo && Number(proximo.id) !== etqId) {
        if (!permitirForaOrdem) {
          _setStatus(
            `ID ${etqId} não é o menor pendente (próximo: ${proximo.id}). Peça permissão ao suporte para liberar fora da ordem.`,
            '#f87171'
          );
          return;
        }
      }

      busy = true;
      _setStatus(`Validando ID ${etqId}...`, '#94a3b8');
      try {
        const r = await fetch(`/api/etiquetas/rec-impresso/${etqId}`, { credentials: 'include' });
        const d = await r.json().catch(() => ({}));
        if (!r.ok || !d.ok || !d.etiqueta) throw new Error(d.error || 'Etiqueta não encontrada.');
        const etq = d.etiqueta;
        const codOk = String(etq.codigo || '').trim();
        const omieOk = String(etq.codigo_omie || '').trim();
        if (cod && codOk && codOk !== cod && omieOk !== cod) {
          throw new Error(`ID ${etqId} é de outro produto (${codOk || omieOk}).`);
        }
        const saldo = Math.max(0, parseFloat(etq.qtd) || 0);
        if (saldo <= 0) throw new Error(`ID ${etqId} sem saldo.`);

        let esperado = filaRestante.find(f => Number(f.id) === etqId);
        if (!esperado && !permitirForaOrdem) {
          throw new Error(`ID ${etqId} não está na lista desta SEP. Peça permissão ao suporte.`);
        }
        const tirarPref = esperado ? Number(esperado.tirar) || 0 : remaining;
        const tirar = Math.min(saldo, remaining, tirarPref > 0 ? tirarPref : remaining);
        if (tirar <= 0) throw new Error(`ID ${etqId} não cobre quantidade.`);

        leituras.push({
          id: String(etqId),
          endereco: String(etq.endereco || esperado?.endereco || '').trim(),
          saldo,
          tirar
        });
        remaining = Math.max(0, remaining - tirar);
        filaRestante = filaRestante.filter(f => Number(f.id) !== etqId);

        if (mira) {
          mira.style.borderColor = '#4ade80';
          setTimeout(() => { if (mira) mira.style.borderColor = 'rgba(52,211,153,.85)'; }, 500);
        }
        _atualizarLidos();
        if (remaining <= 1e-9) {
          _setStatus('Quantidade completa.', '#4ade80');
          setTimeout(() => _fechar(true), 400);
          return;
        }
        const prox = filaRestante[0];
        _setStatus(
          prox ? `OK. Agora leia o ID ${prox.id}.` : `Falta ${_solFmtQty(remaining)} ${un}.`,
          '#fbbf24'
        );
      } catch (e) {
        _setStatus(e.message || 'Erro ao validar etiqueta.', '#f87171');
      } finally {
        busy = false;
        setTimeout(() => inputEl?.focus(), 50);
      }
    }

    function _lerCamSalva() {
      try { return localStorage.getItem('sepEtqCamId') || null; } catch (_) { return null; }
    }

    function _salvarCam(deviceId) {
      try { localStorage.setItem('sepEtqCamId', deviceId || ''); } catch (_) {}
    }

    function _aplicarStreamNoVideo() {
      try {
        const tCam = stream?.getVideoTracks?.()[0];
        console.log('[sepEtq] câmera em uso:', tCam?.label, '| zoom:', tCam?.getSettings?.().zoom);
      } catch (_) {}
      if (video && stream) {
        video.srcObject = stream;
        video.play().catch(() => {});
      }
    }

    /* Alterna entre as câmeras do aparelho e memoriza a escolha */
    let camLista = [];
    let camIdxAtual = -1;
    async function _trocarCamera() {
      try {
        const devices = await navigator.mediaDevices.enumerateDevices();
        camLista = devices.filter(d => d.kind === 'videoinput');
        if (camLista.length < 2) {
          _setStatus('Este aparelho só expõe uma câmera.', '#fbbf24');
          return;
        }
        const atualId = stream?.getVideoTracks?.()[0]?.getSettings?.().deviceId || null;
        if (camIdxAtual < 0) {
          camIdxAtual = Math.max(0, camLista.findIndex(d => d.deviceId === atualId));
        }
        camIdxAtual = (camIdxAtual + 1) % camLista.length;
        const alvo = camLista[camIdxAtual];
        if (stream) stream.getTracks().forEach(t => t.stop());
        stream = await navigator.mediaDevices.getUserMedia({
          video: { deviceId: { exact: alvo.deviceId }, width: { ideal: 1920 }, height: { ideal: 1080 } },
          audio: false
        });
        await _sepEtqNormalizarZoom(stream);
        _aplicarStreamNoVideo();
        _salvarCam(alvo.deviceId);
        const nome = alvo.label || `câmera ${camIdxAtual + 1} de ${camLista.length}`;
        _setStatus(`Usando: ${nome}`, '#94a3b8');
      } catch (_) {
        _setStatus('Não foi possível trocar a câmera. Tente de novo.', '#f87171');
      }
    }

    async function _iniciarCamera() {
      try {
        // 1) Se o usuário já escolheu uma câmera antes, usa a mesma
        const camSalva = _lerCamSalva();
        if (camSalva) {
          try {
            stream = await navigator.mediaDevices.getUserMedia({
              video: { deviceId: { exact: camSalva }, width: { ideal: 1920 }, height: { ideal: 1080 } },
              audio: false
            });
            await _sepEtqNormalizarZoom(stream);
          } catch (_) { stream = null; /* câmera salva não existe mais */ }
        }
        // 2) Senão, abre a traseira e corrige para a lente principal
        if (!stream) {
          stream = await navigator.mediaDevices.getUserMedia({
            video: {
              facingMode: { ideal: 'environment' },
              width: { ideal: 1920 },
              height: { ideal: 1080 }
            },
            audio: false
          });
          stream = await _sepEtqGarantirCameraPrincipal(stream);
        }
        _aplicarStreamNoVideo();
        _setStatus(
          fila[0] ? `Aponte para o QR do ID ${fila[0].id} (menor da fila).` : 'Aponte para o QR da etiqueta.',
          '#94a3b8'
        );
      } catch (_) {
        _setStatus('Câmera indisponível. Use o leitor de código de barras USB.', '#f59e0b');
      }
      if ('BarcodeDetector' in window) {
        const detector = new BarcodeDetector({ formats: ['qr_code', 'data_matrix'] });
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        interval = setInterval(async () => {
          if (!video || video.readyState < 2 || busy || remaining <= 1e-9) return;
          canvas.width = video.videoWidth;
          canvas.height = video.videoHeight;
          ctx.drawImage(video, 0, 0);
          try {
            const barcodes = await detector.detect(canvas);
            if (barcodes.length > 0) await _processarValor(barcodes[0].rawValue);
          } catch (_) { /* frame */ }
        }, 350);
      }
    }

    // Acumula leitura rápida do wedge USB no input oculto
    let wedgeBuf = '';
    let wedgeTimer = null;
    overlay.addEventListener('keydown', (ev) => {
      if (ev.key === 'Escape') { _fechar(false); return; }
      if (busy) return;
      if (ev.key === 'Enter') {
        ev.preventDefault();
        const v = (inputEl?.value || wedgeBuf || '').trim();
        wedgeBuf = '';
        if (inputEl) inputEl.value = '';
        if (v) void _processarValor(v);
        return;
      }
      if (ev.key.length === 1 && !ev.ctrlKey && !ev.metaKey && !ev.altKey) {
        wedgeBuf += ev.key;
        clearTimeout(wedgeTimer);
        wedgeTimer = setTimeout(() => { wedgeBuf = ''; }, 120);
      }
    });

    overlay.querySelector('#sepEtqQrFechar')?.addEventListener('click', () => _fechar(false));
    overlay.querySelector('#sepEtqQrTrocarCam')?.addEventListener('click', () => { void _trocarCamera(); });
    overlay.addEventListener('click', (ev) => { if (ev.target === overlay) _fechar(false); });

    _atualizarLidos();
    _iniciarCamera();
    setTimeout(() => inputEl?.focus(), 200);
  });
}

/** Aloca a quantidade nos endereços/IDs na ordem de seleção (primeiro leva o máximo possível). */
function _solCalcularAlocacaoEtq(selecoes, qtyNeeded) {
  let remaining = Math.max(0, parseFloat(qtyNeeded) || 0);
  const alocs = [];
  for (const s of selecoes || []) {
    const saldo = Math.max(0, parseFloat(s.saldo) || 0);
    const tirarPref = parseFloat(s.tirar);
    const tirar = remaining > 0
      ? Math.min(saldo, remaining, Number.isFinite(tirarPref) && tirarPref > 0 ? tirarPref : saldo)
      : 0;
    alocs.push({
      id: s.id != null ? String(s.id) : '',
      endereco: String(s.endereco || '').trim(),
      saldo,
      tirar
    });
    remaining = Math.max(0, remaining - tirar);
  }
  const totalTirar = alocs.reduce((s, a) => s + (Number(a.tirar) || 0), 0);
  return { alocs, remaining, totalTirar };
}

function _solAplicarVisualAlocacaoEtq(row, qtyNeeded) {
  if (!row) return null;
  const selecoes = _solLerSelecoesEtq(row);
  const calc = _solCalcularAlocacaoEtq(selecoes, qtyNeeded);
  const byEndereco = new Map();
  for (const a of calc.alocs) {
    const end = String(a.endereco || '').trim();
    if (!end || !(a.tirar > 0)) continue;
    const prev = byEndereco.get(end) || { tirar: 0, ids: [] };
    prev.tirar += Number(a.tirar) || 0;
    if (a.id) prev.ids.push(a.id);
    byEndereco.set(end, prev);
  }
  row.querySelectorAll('.sep-etq-endereco-row').forEach(el => {
    const end = String(el.dataset.etqEndereco || '').trim();
    const info = byEndereco.get(end);
    const active = !!info;
    el.dataset.selected = active ? '1' : '0';
    el.style.borderColor = active ? '#22c55e' : '#854d0e33';
    el.style.background = active ? '#1a2e1a' : '#1a1508';
    const badge = el.querySelector('.sep-etq-tirar');
    if (badge) {
      if (active && info.tirar > 0) {
        const idsTxt = info.ids.length ? ` · ID ${info.ids.join(',')}` : '';
        badge.textContent = `Tirar ${_solFmtQty(info.tirar)}${idsTxt}`;
        badge.style.display = 'inline-block';
      } else {
        badge.textContent = '';
        badge.style.display = 'none';
      }
    }
  });
  const comTirar = calc.alocs.filter(a => a.tirar > 0);
  row.dataset.etqAlocacoes = JSON.stringify(comTirar);
  if (comTirar.length) {
    const saldoTotal = comTirar.reduce((s, a) => s + (Number(a.saldo) || 0), 0);
    row.dataset.etqId = String(comTirar[0].id || '');
    row.dataset.etqEndereco = String(comTirar[0].endereco || '');
    row.dataset.etqQtd = String(saldoTotal);
  } else {
    row.dataset.etqId = '';
    row.dataset.etqEndereco = '';
    row.dataset.etqQtd = '';
    row.dataset.etqAlocacoes = '[]';
  }
  return calc;
}

function _solEnderecamentoSepInline(codigo, enderecoMap, itemFallback) {
  const cod = String(codigo || '').trim();
  let registros = cod ? enderecoMap?.[cod] : null;
  if ((!Array.isArray(registros) || !registros.length) && cod && enderecoMap) {
    const altKey = Object.keys(enderecoMap).find(k => String(k).trim() === cod);
    if (altKey) registros = enderecoMap[altKey];
  }
  if ((!Array.isArray(registros) || !registros.length) && itemFallback) {
    const fromItem = itemFallback.endereco_pp || itemFallback.enderecos_pp;
    if (Array.isArray(fromItem) && fromItem.length) registros = fromItem;
  }
  registros = (registros || []).filter(ep => String(ep.endereco || ep.completo || '').trim());
  if (!registros.length) {
    return `<div style="font-size:.62rem;color:#6b7280;font-style:italic;padding:4px 0;">
      Nenhum endereço cadastrado no ETQ
    </div>`;
  }
  const gridCols = 'minmax(90px,1fr) minmax(52px,auto) minmax(58px,auto)';
  const head = '';
  const linhas = registros.map(ep => {
    const end = escapeHtml(String(ep.endereco || ep.completo || '').trim());
    if (!end) return '';
    const id = String(ep.id != null ? ep.id : '');
    const qtd = Number(ep.qtd || 0);
    const un = escapeHtml(String(ep.unidade || 'UN'));
    const qtdColor = qtd > 0 ? '#cbd5e1' : '#fbbf24';
    return `<button type="button" class="sep-etq-endereco-row" data-etq-id="${escapeHtml(id)}" data-etq-endereco="${end}" data-etq-qtd="${qtd}" data-selected="0"
      style="display:grid;grid-template-columns:${gridCols};gap:3px 6px;width:100%;padding:5px 4px;border:1px solid #854d0e33;border-radius:6px;background:#1a1508;color:inherit;font:inherit;cursor:pointer;text-align:left;align-items:center;">
      <span style="color:#fde68a;font-weight:700;word-break:break-word;font-size:.65rem;">${end}</span>
      <span style="color:${qtdColor};font-weight:700;font-size:.64rem;text-align:right;">${qtd} ${un}</span>
      <span class="sep-etq-tirar" style="display:none;font-size:.58rem;font-weight:800;color:#86efac;text-align:right;white-space:nowrap;"></span>
    </button>`;
  }).filter(Boolean).join('');
  if (!linhas) return '';
  return `<div class="sep-etq-endereco-list" style="padding:6px 8px;background:#141006;border:1px solid #854d0e55;border-radius:8px;">
    ${_solEnderecoLegendaHtml(registros)}
    <div style="font-size:.58rem;color:#94a3b8;margin:2px 0 4px;line-height:1.3;">Toque no endereço ou use "Ler próxima etiqueta". Sempre o ID menor primeiro. A qtd do endereço é a soma de todos os registros.</div>
    ${head}${linhas}
  </div>`;
}

function _solRenderOrigemSepFase(locais, enderecoMap, codigoProd, princArmz) {
  const sorted = (Array.isArray(locais) ? locais : [])
    .filter(l => Number(l?.saldo) > 0)
    .slice()
    .sort((a, b) => {
      if (String(a.local_codigo) === princArmz) return -1;
      if (String(b.local_codigo) === princArmz) return 1;
      return String(a?.local_nome || a?.local_codigo || '')
        .localeCompare(String(b?.local_nome || b?.local_codigo || ''), 'pt-BR');
    });
  if (!sorted.length) {
    return `<div style="font-size:.63rem;color:#6b7280;font-style:italic;">Sem origem com saldo</div>`;
  }
  const temAlmox = sorted.some(l => String(l.local_codigo) === princArmz);
  const origensHtml = sorted.map((l, idx) => {
    const cod = String(l.local_codigo || '');
    const isAlmox = cod === princArmz;
    const nome = (l.local_nome || cod).replace(/"/g, '&quot;');
    const qty2 = Number(l.saldo).toLocaleString('pt-BR', { minimumFractionDigits: 0, maximumFractionDigits: 2 });
    const endHtml = isAlmox ? _solEnderecamentoSepInline(codigoProd, enderecoMap) : '';
    const isDefault = isAlmox || (!temAlmox && idx === 0);
    const isExtra = temAlmox ? !isAlmox : idx > 0;
    return `<div class="sol-origem-sep-wrap${isExtra ? ' sep-origem-extra' : ''}" style="display:${isExtra ? 'none' : 'flex'};flex-direction:column;gap:4px;width:100%;">
      <button type="button" class="sol-origem-sep-btn" data-cod="${cod}" data-nome="${nome}" data-is-almox="${isAlmox ? '1' : '0'}" data-selected="${isDefault ? '1' : '0'}"
        style="padding:5px 9px;border-radius:6px;font-size:.65rem;font-weight:700;cursor:pointer;white-space:normal;word-break:break-word;text-align:left;line-height:1.35;width:100%;
               border:2px solid ${isDefault ? '#16a34a' : '#374151'};
               background:${isDefault ? '#14532d' : '#111827'};
               color:${isDefault ? '#86efac' : '#9ca3af'};">
        ${l.local_nome || cod} · ${qty2} ${l.unidade || 'UN'}
      </button>
      ${isAlmox ? `<div class="sol-origem-sep-etq" style="display:${isDefault ? 'block' : 'none'};">${endHtml}</div>` : ''}
    </div>`;
  }).join('');
  const extras = sorted.length - 1;
  const toggle = extras > 0
    ? `<button type="button" class="sep-origem-toggle" data-expanded="0"><i class="fa-solid fa-eye"></i> Desocultar outros armazéns (${extras})</button>`
    : '';
  return origensHtml + toggle;
}

function _solDestinoHtml(it, compact = false) {
  const endList = it?.enderecos_pp;
  if (endList && Array.isArray(endList) && endList.length > 0) {
    return endList.map(e => `
      <div style="display:${compact ? 'block' : 'inline-flex'};flex-direction:column;gap:1px;background:#1e293b;border:1px solid #334155;border-radius:4px;padding:3px 6px;font-size:.63rem;line-height:1.5;${compact ? 'white-space:normal;word-break:break-word;max-width:100%;' : 'white-space:nowrap;'}">
        <span><span style="color:#6b7280;">rua:</span> <span style="color:#67e8f9;font-weight:700;">${e.rua || '—'}</span></span>
        <span><span style="color:#6b7280;">andar:</span> <span style="color:#67e8f9;font-weight:700;">${e.andar || '—'}</span></span>
        <span><span style="color:#6b7280;">edif.:</span> <span style="color:#67e8f9;font-weight:700;">${e.edificio || '—'}</span></span>
        <span><span style="color:#6b7280;">apto:</span> <span style="color:#67e8f9;font-weight:700;">${e.apartamento || '—'}</span></span>
      </div>`).join('');
  }
  if (it?.nome_local || it?.cod_local) {
    const destino = it.nome_local || it.cod_local;
    return `<div style="font-size:.68rem;color:#c4b5fd;font-weight:700;">${destino}</div>`;
  }
  return `<div style="font-size:.65rem;color:#6b7280;font-style:italic;">Não endereçado</div>`;
}

// Feedback global curto para qualquer botão clicado.
(function initGlobalButtonClickFeedback() {
  if (window.__globalButtonClickFeedbackInitialized) return;
  window.__globalButtonClickFeedbackInitialized = true;

  const style = document.createElement('style');
  style.textContent = `
    .global-btn-click-spinner {
      display: inline-flex;
      align-items: center;
      justify-content: center;
      margin-left: 6px;
      width: 12px;
      height: 12px;
      border: 2px solid currentColor;
      border-right-color: transparent;
      border-radius: 999px;
      animation: globalBtnSpin .65s linear infinite;
      vertical-align: middle;
      opacity: .9;
    }
    @keyframes globalBtnSpin {
      to { transform: rotate(360deg); }
    }
  `;
  document.head.appendChild(style);

  document.addEventListener('click', (event) => {
    const button = event.target.closest('button');
    if (!button) return;
    if (button.dataset.noGlobalSpinner === '1') return;
    if (button.querySelector('.global-btn-click-spinner')) return;
    if (button.querySelector('.fa-spinner, .fa-spin')) return;

    const spinner = document.createElement('span');
    spinner.className = 'global-btn-click-spinner';
    spinner.setAttribute('aria-hidden', 'true');
    button.appendChild(spinner);

    window.setTimeout(() => {
      spinner.remove();
    }, 900);
  }, true);
})();

// mode: 'normal' | 'separado-btn' | 'disabled'
function _solGetMiniImgHtml(codigoProduto, descricaoProduto) {
  const codigo = String(codigoProduto || '').trim();
  const descricao = String(descricaoProduto || '').trim();
  let imgUrl = '';

  if (codigo && Array.isArray(window.produtosCatalogoOmie) && window.produtosCatalogoOmie.length) {
    const produtoComImagem = window.produtosCatalogoOmie.find(p =>
      p.codigo === codigo || String(p.codigo_produto || '') === codigo
    );
    imgUrl = String(produtoComImagem?.url_imagem || '').trim();
  }

  let urlExpirada = false;
  if (imgUrl && imgUrl.includes('Expires=')) {
    const match = imgUrl.match(/Expires=(\d+)/);
    if (match) {
      const expiresTimestamp = parseInt(match[1], 10);
      const agora = Math.floor(Date.now() / 1000);
      urlExpirada = expiresTimestamp < agora;
    }
  }

  if (imgUrl && !urlExpirada) {
    return `<img data-sep-img-code="${escapeHtml(codigo)}" src="${imgUrl}" alt="${escapeHtml(descricao || codigo)}" style="width:100%;height:100%;object-fit:contain;background:#f8fafc;padding:2px;" onclick='event.stopPropagation();ampliarImagemProduto(${JSON.stringify(imgUrl)}, ${JSON.stringify(descricao || codigo)}, ${JSON.stringify(codigo)})'>`;
  }

  setTimeout(_solHidratarImagensPendentes, 0);
  return `<img data-sep-img-code="${escapeHtml(codigo)}" alt="${escapeHtml(descricao || codigo)}" style="width:100%;height:100%;object-fit:contain;background:#f8fafc;padding:2px;">`;
}

async function _solHidratarImagensPendentes() {
  const imagens = [...document.querySelectorAll('img[data-sep-img-code]:not([data-sep-img-loading])')];
  await Promise.all(imagens.map(async img => {
    img.dataset.sepImgLoading = '1';
    const codigo = String(img.dataset.sepImgCode || '').trim();
    if (!codigo || img.getAttribute('src')) return;
    try {
      const resp = await fetch(`/api/produtos/imagem/${encodeURIComponent(codigo)}`, { credentials: 'include' });
      const data = resp.ok ? await resp.json() : null;
      const url = String(data?.url_imagem || '').trim();
      if (!url) return;
      img.src = url;
      img.closest('.sep-thumb')?.addEventListener('click', event => {
        event.stopPropagation();
        ampliarImagemProduto(url, img.alt || codigo, codigo);
      }, { once: true });
    } catch (_) {
      // Produto sem foto permanece com o fundo neutro, sem imagem quebrada.
    }
  }));
}

function _solRenderItemRow(item, mode, enderecoMap) {
  const solicIds = Array.isArray(item.solic_ids) ? item.solic_ids : (item.solic_id ? [item.solic_id] : []);
  const carrIds  = Array.isArray(item.carr_ids)  ? item.carr_ids  : (item.carr_id  ? [item.carr_id]  : []);
  const qty      = parseFloat(item.quantidade) || 0;
  const rowKey   = item.codigo_produto || (solicIds[0] || '');
  const dataPrev = _solFmtDataPrevista(item.data_prevista);
  const horario  = item.horario || '';
  const dataHora = [dataPrev, horario].filter(Boolean).join(' ');
  const op = mode === 'disabled' ? 'opacity:.45;pointer-events:none;' : '';
  const enderecamentoLinha = enderecoMap ? _solEnderecamentoHtml(item.codigo_produto, enderecoMap) : '';
  let btnHtml = '';
  if (mode === 'separado-btn') {
    btnHtml = `
      <div style="display:flex;flex-direction:column;align-items:flex-end;gap:4px;flex-shrink:0;">
        <button class="btn-item-separado"
          data-solic-ids='${JSON.stringify(solicIds)}'
          data-carr-ids='${JSON.stringify(carrIds)}'
          data-qty="${qty}"
          style="padding:4px 10px;border:none;border-radius:6px;background:#374151;color:#d1d5db;font-weight:700;font-size:.72rem;cursor:pointer;white-space:nowrap;transition:background .2s;">
          <i class="fa-solid fa-check" style="margin-right:3px;"></i>Separado
        </button>
        <div class="sep-qty-form" style="display:none;align-items:center;gap:4px;">
          <input type="text" inputmode="decimal" class="sep-qty-input" value="${qty}"
            style="width:60px;padding:3px 6px;border-radius:5px;border:1px solid #4b5563;background:#111;color:#f0f0f0;font-size:.75rem;-moz-appearance:textfield;">
          <span style="font-size:.72rem;color:#9ca3af;">/${_solFmtQty(qty)}</span>
          <button class="btn-sep-ok" style="padding:3px 8px;border:none;border-radius:5px;background:#16a34a;color:#fff;font-weight:700;font-size:.72rem;cursor:pointer;">OK</button>
          <button class="btn-sep-x" style="padding:3px 7px;border:none;border-radius:5px;background:#374151;color:#d1d5db;font-weight:700;font-size:.72rem;cursor:pointer;">&#x2715;</button>
        </div>
      </div>`;
  }
  return `
    <div data-item-row="${rowKey}" style="display:flex;align-items:center;gap:12px;padding:10px 16px;border-top:1px solid #222;${op}">
      <div style="width:40px;height:40px;border-radius:8px;background:#0f0f0f;overflow:hidden;flex-shrink:0;">
        ${_solGetMiniImgHtml(item.codigo_produto, item.descricao || '')}
      </div>
      <div style="flex:1;min-width:0;">
        <div style="font-weight:700;font-size:.80rem;color:#f59e0b;">${item.codigo_produto}</div>
        <div style="font-size:.78rem;color:#d1d5db;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${item.descricao || '—'}</div>
        <div style="font-size:.73rem;color:#9ca3af;margin-top:2px;display:flex;align-items:center;gap:6px;flex-wrap:wrap;">
          ${dataHora ? `<i class="fa-regular fa-calendar" style="color:#6b7280;"></i><span>${dataHora}</span>` : ''}
          <span style="font-weight:700;color:#f0f0f0;">${_solFmtQty(item.quantidade)}</span>
          <span>${item.unidade || 'UN'}</span>
          ${_solStatusBadge(item.status || 'pendente')}
        </div>
        ${enderecamentoLinha ? `<div style="margin-top:5px;">${enderecamentoLinha}</div>` : ''}
      </div>
      ${btnHtml}
    </div>`;
}

// ============================================================================
// FUNÇÕES DE ATUALIZAÇÃO DE CONTADORES DAS GUIAS
// ============================================================================

// Atualiza os contadores das guias "Tela de separação" e "Kanban solicitações"
window._updateTabCounters = async function() {
  try {
    // O badge da aba representa somente a quantidade de SEPs em Solicitado.
    const solicitacoesCountEl = document.getElementById('solicitacoesCount');
    if (solicitacoesCountEl) {
      try {
        const respSol = await fetch('/api/logistica/solicitacoes-kanban', { credentials: 'include' });
        if (respSol.ok) {
          const dataSol = await respSol.json();
          const colunas = dataSol.colunas || {};
          solicitacoesCountEl.textContent = _solContarSepsSolicitadas(colunas);
        }
      } catch (err) {
        console.warn('[UPDATE-COUNTERS] Erro ao atualizar contador solicitações:', err);
      }
    }

    // Contador para "Kanban solicitações": apenas "Aguardando retirada"
    const kanbanSolicitacoesCountEl = document.getElementById('kanbanSolicitacoesCount');
    if (kanbanSolicitacoesCountEl) {
      try {
        const respKan = await fetch('/api/logistica/kanban', { credentials: 'include' });
        if (respKan.ok) {
          const dataKan = await respKan.json();
          const colunas = dataKan.colunas || {};
          const contKan = colunas['Aguardando retirada']?.length || 0;
          kanbanSolicitacoesCountEl.textContent = contKan;
        }
      } catch (err) {
        console.warn('[UPDATE-COUNTERS] Erro ao atualizar contador kanban:', err);
      }
    }
  } catch (err) {
    console.warn('[UPDATE-COUNTERS] Erro geral:', err);
  }
};

function _solContarSepsSolicitadas(colunas) {
  return Array.isArray(colunas?.Solicitado) ? colunas.Solicitado.length : 0;
}

function _solSolicIdsParaIniciarSep(itens) {
  const elegivel = new Set(['pendente', 'Stund-by']);
  return (itens || [])
    .filter(it => elegivel.has(String(it.status || '')))
    .map(it => parseInt(it.solic_id, 10))
    .filter(id => !Number.isNaN(id));
}

function _solBuildKanbanItensUrl(nSolic, opts = {}) {
  const params = new URLSearchParams();
  if (nSolic) params.set('n_solic', nSolic);
  if (opts.includeDerivados) params.set('include_derivados', '1');
  if (opts.escopoItens === 'global') params.set('escopo', 'global');
  const query = params.toString();
  return `/api/logistica/kanban/itens${query ? `?${query}` : ''}`;
}

const _VIPP_MSG_INDISPONIVEL = 'VIPP fora do ar, aguarde alguns minutos e tente novamente.';

function _vippErroIndisponivel(texto) {
  const t = String(texto || '');
  return t.includes(_VIPP_MSG_INDISPONIVEL) || /GTW-00|Token expirado|cartaopostagem|Token N[aã]o Retornado|Problemas Na Autentica|IdCorreios|Codigo de acesso|Falha ao conectar com VIPP|Tempo limite|Servi[cç]o indispon[ií]vel|Usuario Nao Logado|\b502\b|\b503\b/i.test(t);
}

/** Mensagem amigável para falhas temporárias do VIPP (Envio de mercadoria, AT e Solicitação de envio). */
function _vippMsgErroUsuario(errOrMsg, payload) {
  if (payload && payload.vippIndisponivel) return _VIPP_MSG_INDISPONIVEL;
  if (Array.isArray(payload?.erros) && payload.erros.some(_vippErroIndisponivel)) return _VIPP_MSG_INDISPONIVEL;
  const bruto = typeof errOrMsg === 'string' ? errOrMsg : (errOrMsg?.message || String(errOrMsg || ''));
  return _vippErroIndisponivel(bruto) ? _VIPP_MSG_INDISPONIVEL : (bruto || 'Erro ao comunicar com VIPP.');
}

/** Gera código ECT (Correios) via VIPP ao iniciar separação — libera Imprimir em Envio de mercadoria */
async function _solDispararVippGerarEtiqueta(nSolic, opts = {}) {
  if (!nSolic) return { ok: false, skipped: true };
  try {
    const vc = await fetch(`/api/vipp/sep-check?n_solic=${encodeURIComponent(nSolic)}`, { credentials: 'include' })
      .then(r => r.json()).catch(() => ({ idVipp: null }));
    if (!vc?.idVipp) return { ok: false, skipped: true };
    const r = await fetch('/api/vipp/gerar-etiqueta', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({ idConhecimento: vc.idVipp, n_solic: nSolic })
    });
    const d = await r.json().catch(() => ({}));
    if (!r.ok || !d.ok) {
      const msg = _vippMsgErroUsuario(d.error || `Falha HTTP ${r.status}`, d);
      console.warn('[VIPP] gerar-etiqueta SEP', nSolic, msg);
      if (opts.alertarErro) alert(msg);
      return { ok: false, error: msg, vippIndisponivel: !!d.vippIndisponivel || msg === _VIPP_MSG_INDISPONIVEL };
    }
    if (opts.recarregarEnvio && typeof carregarSacSolicitacoes === 'function' && envioMercadoriaTabelaBodyPane) {
      carregarSacSolicitacoes(envioMercadoriaTabelaBodyPane, { filaLogistica: true });
    }
    return { ok: true, ectCode: d.ectCode };
  } catch (e) {
    console.warn('[VIPP] gerar-etiqueta:', e);
    const msg = _vippMsgErroUsuario(e);
    if (opts.alertarErro) alert(msg);
    return { ok: false, error: msg, vippIndisponivel: msg === _VIPP_MSG_INDISPONIVEL };
  }
}

let _solicitacoesLoadSeq = 0;

// Carrega e renderiza a aba de solicitações como kanban do separador
window._loadSolicitacoesTab = async function() {
  const board    = document.getElementById('solicitacoesKanbanBoard');
  const statusEl = document.getElementById('solicitacoesKanbanStatus');
  const countEl  = document.getElementById('solicitacoesCount');
  const searchTerm = String(document.getElementById('solicitacoesPesquisa')?.value || '').trim();
  if (!board) return;

  const isMobileBoard = window.matchMedia('(max-width: 640px), (max-width: 900px) and (max-height: 500px)').matches;
  board.style.display = isMobileBoard ? 'grid' : 'flex';
  board.style.gridTemplateColumns = isMobileBoard ? '1fr' : '';
  board.style.gap = '14px';
  board.style.overflowX = isMobileBoard ? 'hidden' : 'auto';

  if (board.dataset.loaded === '1' && !window._loadSolicitacoesTab.force) return;
  window._loadSolicitacoesTab.force = false;
  const loadSeq = ++_solicitacoesLoadSeq;

  board.innerHTML = '<p style="color:#9ca3af;padding:16px;font-size:.85rem;">Carregando...</p>';
  if (statusEl) statusEl.textContent = '';

  const COLS = [
    { key: 'Solicitado',           label: 'Solicitado',           icon: 'fa-clock',          color: '#3b82f6', bg: '#0f1929', acao: 'iniciar'  },
    { key: 'Stund-by',            label: 'Stund-by',            icon: 'fa-bag-shopping',   color: '#ec4899', bg: '#1f0d1a', acao: 'modal'    },
    { key: 'Em Separação',         label: 'Em Separação',         icon: 'fa-boxes-stacked',  color: '#f59e0b', bg: '#1c1500', acao: 'modal'    },
    { key: 'Separado',             label: 'Separado',             icon: 'fa-check-circle',   color: '#22c55e', bg: '#0a1f0f', acao: 'modal'    },
    { key: 'Aguardando retirada',  label: 'Aguardando retirada',  icon: 'fa-hourglass-half', color: '#a78bfa', bg: '#140d2a', acao: 'visualizar' },
    { key: 'Concluído',            label: 'Concluído',            icon: 'fa-flag-checkered', color: '#9ca3af', bg: '#111',    acao: 'visualizar' },
  ];

  try {
    const searchParams = new URLSearchParams();
    if (searchTerm) searchParams.set('q', searchTerm);
    const searchQuery = searchParams.toString();
    const resp = await fetch(`/api/logistica/solicitacoes-kanban${searchQuery ? `?${searchQuery}` : ''}`, { credentials: 'include' });
    if (!resp.ok) throw new Error(`HTTP ${resp.status}`);
    const data = await resp.json();
    if (loadSeq !== _solicitacoesLoadSeq) return;
    const colunas = data.colunas || {};

    board.innerHTML = '';
    let totalCards = 0;
    COLS.forEach(col => {
      const cards = colunas[col.key] || [];
      totalCards += cards.length;

      const colEl = document.createElement('div');
      colEl.style.cssText = isMobileBoard
        ? 'width:100%;min-width:0;display:flex;flex-direction:column;'
        : 'flex:0 0 200px;display:flex;flex-direction:column;';

      const cardsHtml = cards.length === 0
        ? `<div style="padding:14px;text-align:center;color:#374151;font-size:.73rem;">Nenhum</div>`
        : cards.map(sep => {
            const criadoEm = _solFmtDataHora(sep.criado_em_min);
            const cursor   = col.acao ? 'cursor:pointer;' : 'cursor:default;';
            const hint     = col.acao === 'iniciar'
              ? `<span style="font-size:.65rem;color:#22c55e88;margin-top:3px;display:block;"><i class="fa-solid fa-eye" style="margin-right:2px;"></i>Clique para ver itens</span>
                 <button class="solic-sep-start-btn" data-n-solic="${sep.n_solic}" style="margin-top:6px;padding:4px 8px;border:none;border-radius:6px;background:#1d4ed8;color:#dbeafe;font-size:.68rem;font-weight:700;cursor:pointer;"><i class="fa-solid fa-play" style="margin-right:3px;"></i>Iniciar separação</button>`
              : (col.key === 'Stund-by')
                ? `<span style="font-size:.65rem;color:#22c55e55;margin-top:3px;display:block;"><i class="fa-solid fa-eye" style="margin-right:2px;"></i>Ver itens</span>
                   <button type="button" class="solic-sep-excluir-btn" data-n-solic="${sep.n_solic}" style="margin-top:6px;padding:4px 8px;border:1px solid #7f1d1d;border-radius:6px;background:transparent;color:#f87171;font-size:.68rem;font-weight:700;cursor:pointer;width:100%;"><i class="fa-solid fa-trash-can" style="margin-right:3px;"></i>Excluir</button>`
              : (col.acao === 'modal' || col.acao === 'visualizar')
                ? `<span style="font-size:.65rem;color:#22c55e55;margin-top:3px;display:block;"><i class="fa-solid fa-eye" style="margin-right:2px;"></i>Ver itens</span>`
                : '';
            const emProcessoSep = col.key === 'Em Separação' || col.key === 'Separado';
            const mostraUrgente = col.key === 'Solicitado' || col.key === 'Stund-by' || emProcessoSep;
            const separadorNome = String(sep.usuario_separando || '').trim();
            const separadorHtml = emProcessoSep && separadorNome
              ? `<div style="margin-top:5px;display:flex;align-items:center;gap:5px;">
                  <i class="fa-solid fa-boxes-stacked" style="color:#f59e0b;font-size:.72rem;flex-shrink:0;"></i>
                  <span style="font-size:.72rem;color:#fbbf24;font-weight:600;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;" title="Separando: ${separadorNome}">${separadorNome}</span>
                </div>`
              : '';
            const urgenteHtml = mostraUrgente && sep.tem_urgente
              ? `<div style="margin-top:4px;display:inline-flex;align-items:center;gap:4px;padding:2px 7px;border-radius:20px;font-size:.65rem;font-weight:700;color:#fca5a5;background:#450a0a;border:1px solid #ef4444;" title="Esta SEP tem item urgente">
                  <i class="fa-solid fa-bolt" style="font-size:.62rem;"></i>Urgente
                </div>`
              : '';
            const emCompraHtml = (col.key === 'Stund-by' && sep.tem_em_compra)
              ? `<div style="margin-top:4px;display:inline-flex;align-items:center;gap:4px;padding:2px 7px;border-radius:20px;font-size:.65rem;font-weight:700;color:#93c5fd;background:#1e3a5f;border:1px solid #3b82f6;" title="Há produto desta SEP com compra em andamento">
                  <i class="fa-solid fa-cart-shopping" style="font-size:.62rem;"></i>Em compra
                </div>`
              : '';
            return `
              <div class="solic-kanban-card sep-kanban-card"
                data-n-solic="${sep.n_solic}"
                data-col-acao="${col.acao || ''}"
                data-col-status="${col.key}"
                style="background:#1a1a1a;border:1px solid #2a2a2a;border-radius:9px;padding:10px 12px;${cursor}transition:border-color .15s;${sep.tem_urgente && mostraUrgente ? 'border-left:3px solid #ef4444;' : ''}"
                onmouseenter="this.style.borderColor='${col.color}66'"
                onmouseleave="this.style.borderColor='#2a2a2a'">
                <div style="display:flex;align-items:center;gap:6px;flex-wrap:wrap;">
                  <span style="font-weight:800;font-size:.85rem;color:#f59e0b;letter-spacing:.03em;">${sep.n_solic}</span>
                  ${urgenteHtml}
                  ${emCompraHtml}
                </div>
                <div class="sep-kanban-meta" style="margin-top:5px;display:flex;align-items:center;gap:5px;">
                  <i class="fa-solid fa-user-circle" style="color:#6b7280;font-size:.75rem;flex-shrink:0;"></i>
                  <span style="font-size:.75rem;color:#d1d5db;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;"><strong>De:</strong> ${sep.nome_user}</span>
                </div>
                ${criadoEm ? `
                <div class="sep-kanban-meta" style="margin-top:4px;display:flex;align-items:center;gap:5px;">
                  <i class="fa-regular fa-clock" style="color:#6b7280;font-size:.72rem;flex-shrink:0;"></i>
                  <span style="font-size:.70rem;color:#6b7280;"><strong>Solicitado em:</strong> ${criadoEm}</span>
                </div>` : ''}
                ${separadorHtml}
                <div class="sep-kanban-item-count">
                  <i class="fa-solid fa-box"></i>
                  <strong>${sep.total_itens}</strong> ${sep.total_itens === 1 ? 'item' : 'itens'}
                </div>
                ${hint}
              </div>`;
          }).join('');

      colEl.innerHTML = `
        <div class="sep-kanban-column" style="--sep-accent:${col.color};border-radius:10px;overflow:hidden;background:#111;border:1px solid #2a2a2a;height:100%;">
          <div class="sep-kanban-column-header" style="display:flex;align-items:center;gap:7px;padding:10px 12px;background:${col.bg};border-bottom:2px solid ${col.color}33;">
            <i class="fa-solid ${col.icon}" style="color:${col.color};font-size:.88rem;"></i>
            <span style="font-weight:700;font-size:.80rem;color:${col.color};">${col.label}</span>
            <span style="margin-left:auto;font-size:.72rem;font-weight:700;color:${col.color};background:${col.color}22;padding:1px 7px;border-radius:20px;">${cards.length}</span>
          </div>
          <div style="display:flex;flex-direction:column;gap:7px;padding:8px;min-height:60px;max-height:calc(100vh - 300px);overflow-y:auto;">
            ${cardsHtml}
          </div>
        </div>`;

      board.appendChild(colEl);
    });

    if (countEl && !searchTerm) countEl.textContent = _solContarSepsSolicitadas(colunas);
    if (statusEl) {
      const agora = new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });
      statusEl.textContent = searchTerm
        ? `${totalCards} SEP(s) encontrada(s) para "${searchTerm}"`
        : `Atualizado às ${agora} · ${totalCards} SEP(s)`;
    }
    board.dataset.loaded = '1';

    requestAnimationFrame(() => {
      const firstCard = board.querySelector('.solic-kanban-card');
      if (firstCard && board.scrollWidth > board.clientWidth) {
        board.scrollLeft = Math.max(0, firstCard.offsetLeft - 14);
      }
    });

    // Delegação de clique nos cards
    board.querySelectorAll('.solic-sep-excluir-btn').forEach(btn => {
      btn.addEventListener('click', async (ev) => {
        ev.preventDefault();
        ev.stopPropagation();
        const nSolic = btn.dataset.nSolic;
        if (!nSolic || btn.disabled) return;
        if (!confirm(`Excluir a SEP ${nSolic} do Stand-by?\n\nEla sai da Tela de separação e do Kanban solicitações.`)) return;
        btn.disabled = true;
        const htmlAntes = btn.innerHTML;
        btn.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i>';
        try {
          const r = await fetch(`/api/logistica/sep/${encodeURIComponent(nSolic)}/excluido`, {
            method: 'PATCH',
            credentials: 'include',
            headers: { 'Content-Type': 'application/json' },
            body: '{}'
          });
          const d = await r.json().catch(() => ({}));
          if (!r.ok || !d.ok) throw new Error(d.error || 'Erro ao excluir.');
          window._loadSolicitacoesTab && (window._loadSolicitacoesTab.force = true, window._loadSolicitacoesTab());
          window._loadKanbanSolicitacoesTab && (window._loadKanbanSolicitacoesTab.force = true, window._loadKanbanSolicitacoesTab());
        } catch (e) {
          alert('Erro: ' + (e.message || e));
          btn.disabled = false;
          btn.innerHTML = htmlAntes;
        }
      });
    });

    board.querySelectorAll('.solic-kanban-card').forEach(cardEl => {
      const acao   = cardEl.dataset.colAcao;
      const nSolic = cardEl.dataset.nSolic;
      if (!acao || !nSolic) return;

      cardEl.addEventListener('click', async () => {
        if (cardEl._loading) return;
        if (acao === 'iniciar') {
          await _abrirModalAguardandoRetiradaSep(nSolic, {
            tituloColuna: 'Solicitado',
            permitirRecebido: false,
            escopoItens: 'global'
          });
          return;
        }
        if (acao === 'visualizar') {
          await _abrirModalAguardandoRetiradaSep(nSolic, {
            tituloColuna: cardEl.dataset.colStatus || 'Aguardando retirada',
            permitirRecebido: false,
            somenteLeitura: true,
            escopoItens: 'global'
          });
          return;
        }
        cardEl._loading = true;
        _solKanbanLoading(true, 'Carregando itens...');
        try {
          // Sempre busca do servidor (cache só acelerava abertura e escondia itens novos).
          const ri = await fetch(_solBuildKanbanItensUrl(nSolic, { escopoItens: 'global' }), { credentials: 'include' });
          const di = await ri.json();
          if (!di.ok) throw new Error(di.error || 'Erro ao buscar itens');
          const itens = (di.itens || []).map(it => ({ ...it, solic_ids: [it.solic_id], carr_ids: [it.carr_id] }));
          if (!itens.length) throw new Error('Nenhum item encontrado');

          if (acao === 'modal') {
            const codigos = [...new Set(itens.map(it => it.codigo_produto).filter(Boolean))];
            let preloaded = {};
            if (codigos.length) {
              try {
                const [re, endMap, rid] = await Promise.all([
                  fetch('/api/logistica/estoque/batch?codigos=' + encodeURIComponent(codigos.join(',')), { credentials: 'include' }),
                  _solCarregarEnderecoBatch(codigos),
                  fetch('/api/etiquetas/rec-impresso/ids-fifo-batch?codigos=' + encodeURIComponent(codigos.join(',')), { credentials: 'include' })
                ]);
                const de = await re.json();
                const did = await rid.json().catch(() => ({}));
                preloaded = {
                  estoqueBatch: de.ok ? (de.dados || {}) : {},
                  enderecoBatch: _solMergeEnderecoBatch(itens, endMap || {}),
                  etqIdsBatch: did.ok ? (did.dados || {}) : {}
                };
              } catch (_) {}
            }
            const grupoAtual = { nome_user: itens[0]?.nome_user || nSolic, n_solic: nSolic, itens, origem_status: cardEl.dataset.colStatus || '', escopoItens: 'global' };
            _solSetSepModalCache(nSolic, 'global', {
              grupoAtual,
              gruposConflito: [],
              preloaded
            });
            void _abrirModalSeparacao(
              grupoAtual,
              [],
              preloaded
            ).catch(err => console.warn('[SEP] abrir modal:', err));
          }
        } catch (err) {
          alert('Erro: ' + err.message);
        } finally {
          cardEl._loading = false;
          _solKanbanLoading(false);
        }
      });
    });

    // Botão único por SEP: inicia separação de todos os itens da requisição
    board.querySelectorAll('.solic-sep-start-btn').forEach(btn => {
      btn.addEventListener('click', async (ev) => {
        ev.stopPropagation();
        const nSolic = btn.dataset.nSolic;
        if (!nSolic || btn.disabled) return;
        btn.disabled = true;
        btn.innerHTML = '<i class="fa-solid fa-spinner fa-spin" style="margin-right:3px;"></i>Iniciando...';
        try {
          // ── Gera código ECT (libera Imprimir em Envio de mercadoria) ───────
          await _solDispararVippGerarEtiqueta(nSolic, { alertarErro: true, recarregarEnvio: true });

          // ── Busca solic_ids e inicia separação ───────────────────────────
          const ri = await fetch(_solBuildKanbanItensUrl(nSolic, { escopoItens: 'global' }), { credentials: 'include' });
          const di = await ri.json();
          if (!di.ok) throw new Error(di.error || 'Erro ao buscar itens da SEP.');
          const solicIds = _solSolicIdsParaIniciarSep(di.itens || []);
          if (!solicIds.length) {
            throw new Error('Esta SEP já saiu de Solicitado. Role o kanban até a coluna "Aguardando retirada" (à direita).');
          }

          const r = await fetch('/api/logistica/itens_solicitados/separacao', {
            method: 'PATCH',
            headers: { 'Content-Type': 'application/json' },
            credentials: 'include',
            body: JSON.stringify({ solic_ids: solicIds })
          });
          const d = await r.json();
          if (!d.ok) throw new Error(d.error || 'Erro ao iniciar separação da SEP.');

          window._loadSolicitacoesTab.force = true;
          window._loadSolicitacoesTab();
          window._loadKanbanSolicitacoesTab.force = true;
          window._loadKanbanSolicitacoesTab();
        } catch (err) {
          alert('Erro: ' + (err.message || err));
          btn.disabled = false;
          btn.innerHTML = '<i class="fa-solid fa-play" style="margin-right:3px;"></i>Iniciar separação';
        }
      });
    });
  } catch (err) {
    if (loadSeq !== _solicitacoesLoadSeq) return;
    console.warn('[SOLIC-KANBAN] Erro:', err.message);
    board.innerHTML = '<p style="color:#ef4444;padding:16px;font-size:.85rem;">Erro ao carregar kanban</p>';
    if (statusEl) statusEl.textContent = 'Erro ao carregar';
    if (countEl) countEl.textContent = '0';
  }
};

function _solCurrentUserName() {
  return String(
    window.__sessionUser?.username ||
    window.__sessionUser?.login ||
    window.__sessionUser?.nome ||
    ''
  ).trim();
}

function _solLocalEhAlmoxGlobal(local) {
  const codigo = String(local?.local_codigo || '').trim();
  const nome = String(local?.local_nome || local?.descricao || '').toUpperCase();
  return codigo === '10717096386' || nome.includes('ALMOXARIFADO') || nome.includes('#ALMOX');
}

function _solRenderOrigemResumoGlobal(locais, emptyText = 'Carregando origem...') {
  const list = (Array.isArray(locais) ? locais : [])
    .filter(l => Number(l?.saldo) > 0)
    .slice()
    .sort((a, b) => {
      const aAlmox = _solLocalEhAlmoxGlobal(a);
      const bAlmox = _solLocalEhAlmoxGlobal(b);
      if (aAlmox && !bAlmox) return -1;
      if (!aAlmox && bAlmox) return 1;
      return String(a?.local_nome || a?.local_codigo || '')
        .localeCompare(String(b?.local_nome || b?.local_codigo || ''), 'pt-BR');
    });

  if (!list.length) {
    return `<div style="font-size:.63rem;color:#6b7280;font-style:italic;">${emptyText}</div>`;
  }

  const almox = list.find(_solLocalEhAlmoxGlobal) || list[0];
  const outros = list.filter(l => l !== almox);

  const renderLinha = (l, destaque = false) => {
    const qty2 = Number(l.saldo).toLocaleString('pt-BR', { minimumFractionDigits: 0, maximumFractionDigits: 2 });
    const nome = l.local_nome || l.local_codigo || 'â€”';
    const isAlmox = _solLocalEhAlmoxGlobal(l);
    return `<div style="display:flex;flex-direction:column;line-height:1.15;padding:1px 0;">
      <span style="font-size:.61rem;color:${isAlmox || destaque ? '#86efac' : '#cbd5e1'};font-weight:${isAlmox ? '800' : '600'};white-space:normal;word-break:break-word;">
        ${nome}${isAlmox ? ' <span style="display:inline-block;margin-left:4px;padding:0 5px;border-radius:999px;background:#14532d;border:1px solid #166534;color:#86efac;font-size:.52rem;font-weight:800;vertical-align:middle;">ALMOX</span>' : ''}
      </span>
      <span style="font-size:.66rem;color:#f0f0f0;font-weight:700;">${qty2} ${l.unidade || 'UN'}</span>
    </div>`;
  };

  if (!outros.length) {
    return renderLinha(almox, true);
  }

  const extraId = `origens-extra-${Math.random().toString(36).slice(2, 9)}`;
  const totalOutros = outros.length;
  return `<div style="display:flex;flex-direction:column;gap:3px;width:100%;position:relative;overflow:visible;">
    ${renderLinha(almox, true)}
    <button type="button" class="sol-origem-toggle" aria-expanded="false" aria-controls="${extraId}"
      onclick="var d=document.getElementById('${extraId}'); if(d){ var abriu=d.style.display==='none' || d.hidden; d.hidden=false; d.style.display=abriu ? 'flex' : 'none'; this.setAttribute('aria-expanded', String(abriu)); this.textContent = abriu ? 'Ocultar outros armazéns' : 'Desocultar outros armazéns'; }"
      style="align-self:flex-start;padding:2px 7px;border-radius:999px;border:1px solid rgba(148,163,184,.28);background:rgba(15,23,42,.72);color:#93c5fd;font-size:.58rem;font-weight:700;cursor:pointer;white-space:nowrap;line-height:1;">
      Desocultar outros armazéns (${totalOutros})
    </button>
    <div id="${extraId}" hidden style="position:absolute;left:0;right:0;top:calc(100% + 4px);display:none;flex-direction:column;gap:5px;padding:8px 10px;border:1px solid rgba(148,163,184,.25);border-radius:10px;background:rgba(15,23,42,.98);box-shadow:0 12px 30px rgba(2,6,23,.38);z-index:20;max-height:140px;overflow:auto;">
      <div style="font-size:.58rem;color:#94a3b8;font-weight:700;text-transform:uppercase;letter-spacing:.04em;">Outras origens</div>
      ${outros.map(l => renderLinha(l, false)).join('')}
    </div>
  </div>`;
}

// Modal de separação — agrega por cod_omie, toggle Separado/Separação, parcial gera SEP.X
const __solSepModalCache = new Map();
const __solSepModalCacheTtlMs = 5 * 60 * 1000;
const __solAguardRetCache = new Map();
const __solAguardRetCacheTtlMs = 5 * 60 * 1000;

function _solSepModalCacheKey(nSolic, escopoItens = 'global') {
  return `${String(escopoItens || 'global').trim()}::${String(nSolic || '').trim()}`;
}

function _solGetSepModalCache(nSolic, escopoItens = 'global') {
  const key = _solSepModalCacheKey(nSolic, escopoItens);
  const entry = __solSepModalCache.get(key);
  if (!entry) return null;
  if ((Date.now() - entry.at) > __solSepModalCacheTtlMs) {
    __solSepModalCache.delete(key);
    return null;
  }
  return entry.data || null;
}

function _solSetSepModalCache(nSolic, escopoItens = 'global', data = {}) {
  const key = _solSepModalCacheKey(nSolic, escopoItens);
  __solSepModalCache.set(key, { at: Date.now(), data });
}

function _solInvalidateSepModalCache(nSolic, escopoItens = 'global') {
  const key = _solSepModalCacheKey(nSolic, escopoItens);
  __solSepModalCache.delete(key);
}

function _solAguardRetCacheKey(nSolic, tituloColuna = 'Aguardando retirada', escopoItens = '') {
  return `${String(tituloColuna || 'Aguardando retirada').trim()}::${String(escopoItens || '').trim()}::${String(nSolic || '').trim()}`;
}

function _solGetAguardRetCache(nSolic, tituloColuna = 'Aguardando retirada', escopoItens = '') {
  const key = _solAguardRetCacheKey(nSolic, tituloColuna, escopoItens);
  const entry = __solAguardRetCache.get(key);
  if (!entry) return null;
  if ((Date.now() - entry.at) > __solAguardRetCacheTtlMs) {
    __solAguardRetCache.delete(key);
    return null;
  }
  return entry.data || null;
}

function _solSetAguardRetCache(nSolic, tituloColuna = 'Aguardando retirada', escopoItens = '', data = {}) {
  const key = _solAguardRetCacheKey(nSolic, tituloColuna, escopoItens);
  __solAguardRetCache.set(key, { at: Date.now(), data });
}

function _solInvalidateAguardRetCache(nSolic, tituloColuna = 'Aguardando retirada', escopoItens = '') {
  const key = _solAguardRetCacheKey(nSolic, tituloColuna, escopoItens);
  __solAguardRetCache.delete(key);
}

async function _abrirModalSeparacao(grupoAtual, gruposConflito, preloaded = {}) {
  document.querySelectorAll('#modalSeparacaoLogistica').forEach(el => el.remove());
  const origemStatus = String(grupoAtual?.origem_status || '').trim();
  const refreshAoFechar = origemStatus === 'Solicitado';
  let houveMudanca = false;

  const isStandby = origemStatus === 'Stund-by';
  let usuarioSeparando = (grupoAtual.itens || [])
    .map(it => String(it.usuario_separando || '').trim())
    .find(Boolean) || '';
  const currentUser = _solCurrentUserName();
  let podeAgirSep = !isStandby && (!usuarioSeparando || usuarioSeparando === currentUser);
  let perdeuSeparacaoParaOutro = false;
  const nSolicHdr = grupoAtual.n_solic || '';
  const PRINC_ARMZ = '10717096386';
  let podeCancelarSep = !isStandby
    && (origemStatus === 'Em Separação' || origemStatus === 'Separado')
    && !!usuarioSeparando
    && usuarioSeparando === currentUser;

  function _extrairUsuarioSeparando(itens) {
    return (itens || [])
      .map(it => String(it.usuario_separando || '').trim())
      .find(Boolean) || '';
  }

  function _syncSepLockFromItens(itens) {
    const eraAtivo = podeAgirSep;
    usuarioSeparando = _extrairUsuarioSeparando(itens);
    const novoPodeAgir = !isStandby && (!usuarioSeparando || usuarioSeparando === currentUser);
    if (eraAtivo && !novoPodeAgir && usuarioSeparando && usuarioSeparando !== currentUser) {
      perdeuSeparacaoParaOutro = true;
    }
    if (novoPodeAgir) perdeuSeparacaoParaOutro = false;
    podeAgirSep = novoPodeAgir;
    podeCancelarSep = !isStandby
      && (origemStatus === 'Em Separação' || origemStatus === 'Separado')
      && !!usuarioSeparando
      && usuarioSeparando === currentUser;
    grupoAtual.itens = itens;
  }

  function _htmlBannerSepLock() {
    if (isStandby || podeAgirSep || !usuarioSeparando) return '';
    if (perdeuSeparacaoParaOutro) {
      return `<div style="margin:12px 16px 0;padding:10px 12px;border-radius:8px;background:#1f2937;border:1px solid #374151;font-size:.78rem;color:#d1d5db;">
        <i class="fa-solid fa-user-lock" style="color:#f59e0b;margin-right:6px;"></i>
        Separação assumida por <strong style="color:#fbbf24;">${usuarioSeparando}</strong>.
      </div>`;
    }
    return `<div style="margin:12px 16px 0;padding:10px 12px;border-radius:8px;background:#1f2937;border:1px solid #374151;font-size:.78rem;color:#d1d5db;display:flex;align-items:center;gap:10px;flex-wrap:wrap;">
      <span style="flex:1;min-width:200px;">
        <i class="fa-solid fa-user-lock" style="color:#f59e0b;margin-right:6px;"></i>
        Separação em andamento por <strong style="color:#fbbf24;">${usuarioSeparando}</strong>. Você pode visualizar, mas não alterar os itens.
      </span>
      <button type="button" id="btnAssumirSeparacao" style="padding:6px 12px;border:none;border-radius:8px;background:#1d4ed8;color:#dbeafe;font-weight:700;font-size:.76rem;cursor:pointer;white-space:nowrap;">
        <i class="fa-solid fa-hand" style="margin-right:4px;"></i>Assumir separação
      </button>
    </div>`;
  }

  function _aplicarEstadoSeparadorAtivo(nomeSeparador) {
    const nome = String(nomeSeparador || currentUser).trim();
    usuarioSeparando = nome;
    perdeuSeparacaoParaOutro = false;
    podeAgirSep = !isStandby && !!nome && nome === currentUser;
    podeCancelarSep = !isStandby
      && (origemStatus === 'Em Separação' || origemStatus === 'Separado')
      && !!usuarioSeparando
      && usuarioSeparando === currentUser;
    (grupoAtual.itens || []).forEach(it => { it.usuario_separando = nome; });
  }

  function _atualizarUiLockSep() {
    const host = document.getElementById('modalSepLockBanner');
    if (host) host.innerHTML = _htmlBannerSepLock();
    const footCancel = document.getElementById('modalSepFooterCancel');
    if (footCancel) footCancel.style.display = 'flex';
    const btnCancel = document.getElementById('btnCancelarSeparacao');
    if (btnCancel) btnCancel.style.display = podeCancelarSep ? 'inline-flex' : 'none';
    _renderLista();
  }

  function _atualizarBannerSep() {
    _atualizarUiLockSep();
  }

  function _atualizarCacheModalSep() {
    _solInvalidateSepModalCache(grupoAtual.n_solic, grupoAtual.escopoItens || 'global');
    _solSetSepModalCache(grupoAtual.n_solic, grupoAtual.escopoItens || 'global', {
      grupoAtual: { ...grupoAtual, itens: [...(grupoAtual.itens || [])] },
      gruposConflito,
      preloaded: { estoqueBatch, enderecoBatch }
    });
  }

  async function _fetchItensModalSep() {
    const r = await fetch(_solBuildKanbanItensUrl(grupoAtual.n_solic, { escopoItens: grupoAtual.escopoItens }), { credentials: 'include' });
    const d = await r.json();
    if (!d.ok) return null;
    return (d.itens || []).map(it => ({ ...it, solic_ids: [it.solic_id], carr_ids: [it.carr_id] }));
  }

  async function _verificarSeparadorSep() {
    if (isStandby || !podeAgirSep) return podeAgirSep;
    try {
      const mapped = await _fetchItensModalSep();
      if (!mapped) return true;
      const sep = _extrairUsuarioSeparando(mapped);
      if (sep && sep !== currentUser) {
        _syncSepLockFromItens(mapped);
        _atualizarBannerSep();
        _renderLista();
        return false;
      }
      return true;
    } catch (_) {
      return true;
    }
  }

  function _tratarErroSeparadorPerdido(err) {
    const msg = String(err?.message || err || '');
    const m = msg.match(/Separação assumida por\s+(.+?)\.?$/i);
    if (m) {
      usuarioSeparando = m[1].trim();
      perdeuSeparacaoParaOutro = true;
      podeAgirSep = false;
      podeCancelarSep = false;
      _atualizarBannerSep();
      _renderLista();
      return true;
    }
    return false;
  }
  const modalTitle = isStandby
    ? `Stund-by — ${nSolicHdr}`
    : (origemStatus === 'Em Separação' || origemStatus === 'Separado')
      ? `Em fase de separação — ${nSolicHdr}`
      : `Em Separação — ${nSolicHdr}`;
  const isFaseSeparacao = origemStatus === 'Em Separação' || origemStatus === 'Separado';

  function _solSepPayloadFromRow(row) {
    const cod = String(row.dataset.origemCod || '').trim();
    const base = {
      cod_local_origem: cod || undefined,
      codigo_produto: row.dataset.codigo || undefined
    };
    if (!row || row.dataset.requerEtq !== '1' || cod !== PRINC_ARMZ) return base;
    let alocs = [];
    try { alocs = JSON.parse(row.dataset.etqAlocacoes || '[]'); } catch (_) { alocs = []; }
    if (!Array.isArray(alocs) || !alocs.length) {
      const calc = _solAplicarVisualAlocacaoEtq(row, parseFloat(row.dataset.qtyTotal || '0') || 0);
      alocs = (calc?.alocs || []).filter(a => a.tirar > 0);
    }
    if (alocs.length) {
      return {
        ...base,
        etq_enderecos: alocs.map(a => ({
          etq_id: a.id ? parseInt(a.id, 10) : undefined,
          endereco: a.endereco || undefined,
          qtd: Number(a.tirar) || 0
        })),
        etq_id: alocs[0].id ? parseInt(alocs[0].id, 10) : undefined,
        endereco_origem: alocs[0].endereco || undefined
      };
    }
    return {
      ...base,
      etq_id: row.dataset.etqId ? parseInt(row.dataset.etqId, 10) : undefined,
      endereco_origem: row.dataset.etqEndereco || undefined
    };
  }

  function _modalSepIgnorarSaldoEtq() {
    return !!document.getElementById('modalSepIgnorarSaldoEtq')?.checked;
  }

  function _solSepPayloadExtras() {
    return _modalSepIgnorarSaldoEtq() ? { ignorar_saldo_etq: true } : {};
  }

  function _solValidarOrigemSepRow(row, qty) {
    const codOrigem = String(row?.dataset?.origemCod || '').trim();
    if (!codOrigem) {
      alert('Selecione o armazém de origem antes de separar.');
      return false;
    }
    return _solValidarEtqSepRow(row, qty);
  }

  function _solValidarEtqSepRow(row, qty) {
    if (_modalSepIgnorarSaldoEtq()) return true;
    if (!row || row.dataset.requerEtq !== '1') return true;
    const codOrigem = String(row.dataset.origemCod || '').trim();
    if (codOrigem !== PRINC_ARMZ) return true;
    const qtd = parseFloat(qty);
    const calc = _solAplicarVisualAlocacaoEtq(row, Number.isFinite(qtd) ? qtd : (parseFloat(row.dataset.qtyTotal || '0') || 0));
    const selecoes = _solLerSelecoesEtq(row);
    if (!selecoes.length) {
      alert('Leia o QR das etiquetas (IDs) na ordem do menor para o maior antes de separar.');
      return false;
    }
    const semId = selecoes.filter(s => !String(s.id || '').trim());
    if (semId.length) {
      alert('Leia o QR Code da etiqueta (ID) antes de separar.');
      return false;
    }
    if (!Number.isFinite(qtd) || qtd <= 0) return true;
    if (calc && calc.remaining > 1e-9) {
      const cod = row.dataset.codigo || 'item';
      alert(
        `Item ${cod}: os IDs lidos somam ${_solFmtQty(calc.totalTirar)}, ` +
        `mas são necessários ${_solFmtQty(qtd)}. Use "Ler próxima etiqueta".`
      );
      return false;
    }
    return true;
  }

  const STATUS_TRABALHO_MODAL_SEP = new Set(['Separação', 'Em Separação', 'Separado', 'Stund-by']);
  function _itensVisiveisModalSep(itens) {
    return (itens || []).filter(it => {
      const st = String(it.status || '');
      return STATUS_TRABALHO_MODAL_SEP.has(st) || st === 'Aguardando retirada';
    });
  }

  // Códigos com compra ativa — preenchido abaixo quando isStandby
  let emCompraCodigos = new Set();

  // Agrega itens por cod_omie (fallback: codigo_produto), somando quantidades
  function _aggItens(itens) {
    const map = new Map();
    const seenSolic = new Set();
    itens.forEach(it => {
      const sid = it.solic_id;
      const sidKey = sid != null ? String(sid) : null;
      if (sidKey && seenSolic.has(sidKey)) return;
      if (sidKey) seenSolic.add(sidKey);

      const st = String(it.status || '');
      const bucket = st === 'Aguardando retirada' ? 'conferido' : 'trabalho';
      const key = `${it.cod_omie || it.codigo_produto}|${bucket}`;
      if (!map.has(key)) {
        map.set(key, {
          ...it,
          solic_ids: [],
          carr_ids: [],
          quantidade: 0,
          quantidade_solicitada: null,
          quantidade_separada: null,
          urgente: false,
          _allSep: true,
          _isConferido: bucket === 'conferido'
        });
      }
      const a = map.get(key);
      if (it.urgente) a.urgente = true;
      if (!a.nome_local && it.nome_local) a.nome_local = it.nome_local;
      if (!a.cod_local && it.cod_local) a.cod_local = it.cod_local;
      if ((!a.endereco_pp || !a.endereco_pp.length) && Array.isArray(it.endereco_pp) && it.endereco_pp.length) {
        a.endereco_pp = it.endereco_pp;
      }
      const cid = it.carr_id;
      if (sid && !a.solic_ids.includes(sid)) a.solic_ids.push(sid);
      if (cid && !a.carr_ids.includes(cid))  a.carr_ids.push(cid);
      if (Array.isArray(it.solic_ids)) it.solic_ids.forEach(id => { if (!a.solic_ids.includes(id)) a.solic_ids.push(id); });
      if (Array.isArray(it.carr_ids))  it.carr_ids.forEach(id  => { if (!a.carr_ids.includes(id))  a.carr_ids.push(id);  });
      a.quantidade += parseFloat(it.quantidade) || 0;
      const qSol = parseFloat(it.quantidade_solicitada);
      const qSep = parseFloat(it.quantidade_separada);
      if (Number.isFinite(qSol)) a.quantidade_solicitada = (parseFloat(a.quantidade_solicitada) || 0) + qSol;
      if (Number.isFinite(qSep)) a.quantidade_separada = (parseFloat(a.quantidade_separada) || 0) + qSep;
      if (a._isConferido) a.status = 'Aguardando retirada';
      else if (it.status !== 'Separado') a._allSep = false;
    });
    map.forEach(a => {
      if (!a._isConferido) a.status = a._allSep ? 'Separado' : 'Separação';
      delete a._allSep;
      delete a._isConferido;
    });
    return [...map.values()];
  }

  function _renderAggItem(it, nSolic) {
    const isCompact = window.matchMedia('(max-width: 640px), (max-width: 900px) and (max-height: 500px)').matches;
    const qty      = parseFloat(it.quantidade) || 0;
    const isConferido = it.status === 'Aguardando retirada';
    const isSep    = it.status === 'Separado';
    const isEmSeparacao = ['Separação', 'Em Separação'].includes(String(it.status || ''));
    const readonlySep = isStandby || !podeAgirSep;
    const dp       = _solFmtDataPrevista(it.data_prevista);
    const dh       = [dp, it.horario].filter(Boolean).join(' ');
    const hasObs = !!String(it.observacao || '').trim();
    const obsText = (it.observacao || '').trim();
    // Renderizar histórico de troca se existir
    const swapHistory = it.codigo_produto_ant && it.codigo_produto_novo 
      ? `<div style="font-size:.70rem;color:#a78bfa;margin-top:2px;display:flex;align-items:center;gap:4px;"><i class="fa-solid fa-arrows-rotate" style="color:#a78bfa;"></i><span>${it.codigo_produto_ant} → ${it.codigo_produto_novo}</span></div>`
      : '';
    const destinoHtml = _solDestinoHtml(it, isCompact);

    const locais = (estoqueBatch[it.codigo_produto] || [])
      .filter(l => Number(l.saldo) > 0)
      .slice()
      .sort((a, b) => String(a.local_codigo) === PRINC_ARMZ ? -1 : String(b.local_codigo) === PRINC_ARMZ ? 1 : 0);
    const temAlmoxOrigem = locais.some(l => String(l.local_codigo) === PRINC_ARMZ);
    const usarOrigemSepFase = isFaseSeparacao && temAlmoxOrigem;
    const enderecamentoHtml = isFaseSeparacao
      ? ''
      : _solEnderecamentoHtml(it.codigo_produto, enderecoBatch, it);
    let origemHtml = usarOrigemSepFase
      ? _solRenderOrigemSepFase(locais, enderecoBatch, it.codigo_produto, PRINC_ARMZ)
      : _solRenderOrigemResumoGlobal(
          estoqueBatch[it.codigo_produto] || [],
          Object.keys(estoqueBatch).length ? 'Sem origem com saldo' : 'Carregando origem...'
        );
    if (false && isSep) {
      if (locais.length) {
        const btns = locais.map((l, idx) => {
          const isDefault = String(l.local_codigo) === PRINC_ARMZ || (idx === 0);
          const cod = String(l.local_codigo);
          const nome = l.local_nome || cod;
          const qty2 = Number(l.saldo).toLocaleString('pt-BR', { minimumFractionDigits: 0, maximumFractionDigits: 2 });
          return `<button class="armazem-btn" data-cod="${cod}" data-nome="${nome.replace(/"/g,'&quot;')}" data-selected="${isDefault ? '1' : '0'}"
            style="padding:4px 9px;border-radius:5px;font-size:.65rem;font-weight:700;cursor:pointer;white-space:normal;word-break:break-word;text-align:left;line-height:1.35;max-width:100%;
                   border:2px solid ${isDefault ? '#16a34a' : '#374151'};
                   background:${isDefault ? '#14532d' : '#111827'};
                   color:${isDefault ? '#86efac' : '#9ca3af'};">
            ${nome} · ${qty2} ${l.unidade || 'UN'}
          </button>`;
        }).join('');
        origemHtml = `<div style="display:flex;flex-direction:column;gap:4px;width:100%;">${btns}</div>`;
      } else if (Object.keys(estoqueBatch).length > 0) {
        origemHtml = `<div style="font-size:.63rem;color:#fbbf24;font-style:italic;">
          <i class="fa-solid fa-triangle-exclamation" style="margin-right:3px;"></i>Sem armazém com saldo positivo
        </div>`;
      } else {
        origemHtml = `<div style="font-size:.63rem;color:#6b7280;font-style:italic;">Carregando origem...</div>`;
      }
    } else if (false && locais.length) {
      origemHtml = locais.map(l => {
        const qty2 = Number(l.saldo).toLocaleString('pt-BR', { minimumFractionDigits: 0, maximumFractionDigits: 2 });
        return `<div style="display:flex;flex-direction:column;line-height:1.35;padding:2px 0;">
          <span style="font-size:.63rem;color:#86efac;">${l.local_nome || l.local_codigo}</span>
          <span style="font-size:.68rem;color:#f0f0f0;font-weight:700;">${qty2} ${l.unidade || 'UN'}</span>
        </div>`;
      }).join('');
    } else if (false && Object.keys(estoqueBatch).length > 0) {
      origemHtml = `<div style="font-size:.63rem;color:#6b7280;font-style:italic;">Sem origem com saldo</div>`;
    } else if (false) {
      origemHtml = `<div style="font-size:.63rem;color:#6b7280;font-style:italic;">Carregando origem...</div>`;
    }

    const localizacaoHtml = `
      <div class="sep-loc-stack" style="margin-top:6px;display:flex;flex-direction:column;gap:6px;">
        ${enderecamentoHtml}
        <div class="sep-destino-inline">
          <span>Destino</span>
          ${destinoHtml}
        </div>
        <div>
          <div class="sep-loc-box sep-loc-box--origin" style="min-width:0;padding:6px 8px;background:#101826;border:1px solid #253041;border-radius:8px;">
            <div style="font-size:.60rem;color:#60a5fa;font-weight:700;text-transform:uppercase;letter-spacing:.04em;margin-bottom:4px;">Origem</div>
            ${origemHtml}
          </div>
        </div>
      </div>`;

    const unidade = it.unidade || 'UN';
    const qtyOrig = parseFloat(it.quantidade_solicitada);
    const qtySepReg = parseFloat(it.quantidade_separada);
    const qtyAlterada = (isSep || isConferido) && Number.isFinite(qtyOrig) && Number.isFinite(qtySepReg)
      && Math.abs(qtyOrig - qtySepReg) > 0.0001;
    const qtdManualPendente = isEmSeparacao && Number.isFinite(qtyOrig) && Number.isFinite(qtySepReg)
      && Math.abs(qtyOrig - qtySepReg) > 0.0001;
    const qtyStandbyPend = qtdManualPendente && qtySepReg < qtyOrig ? qtyOrig - qtySepReg : 0;
    const qtyExtraPend = qtdManualPendente && qtySepReg > qtyOrig ? qtySepReg - qtyOrig : 0;

    const qtyHtml = isConferido
      ? (qtyAlterada
        ? `<div style="display:flex;flex-direction:column;align-items:flex-end;gap:4px;min-width:88px;">
             <span style="font-size:.80rem;font-weight:700;color:#86efac;">${_solFmtQty(qtySepReg)} ${unidade}</span>
             <table style="font-size:.62rem;border-collapse:collapse;border:1px solid #374151;border-radius:4px;overflow:hidden;">
               <tr style="background:#1f2937;"><td style="padding:2px 6px;color:#9ca3af;">Solicitado</td><td style="padding:2px 6px;font-weight:700;color:#d1d5db;text-decoration:line-through;">${_solFmtQty(qtyOrig)} ${unidade}</td></tr>
               <tr style="background:#292419;"><td style="padding:2px 6px;color:#fbbf24;">Separado</td><td style="padding:2px 6px;font-weight:700;color:#fbbf24;">${_solFmtQty(qtySepReg)} ${unidade}</td></tr>
             </table>
           </div>`
        : `<span style="font-size:.80rem;font-weight:700;color:#86efac;">${_solFmtQty(qty)} ${unidade}</span>`)
      : isSep
      ? (qtyAlterada
        ? `<div style="display:flex;flex-direction:column;align-items:flex-end;gap:4px;min-width:88px;">
             <span style="font-size:.80rem;font-weight:700;color:#f0f0f0;">${_solFmtQty(qtySepReg)} ${unidade}</span>
             <table style="font-size:.62rem;border-collapse:collapse;border:1px solid #374151;border-radius:4px;overflow:hidden;">
               <tr style="background:#1f2937;">
                 <td style="padding:2px 6px;color:#9ca3af;white-space:nowrap;">Solicitado</td>
                 <td style="padding:2px 6px;font-weight:700;color:#d1d5db;text-decoration:line-through;">${_solFmtQty(qtyOrig)} ${unidade}</td>
               </tr>
               <tr style="background:#292419;">
                 <td style="padding:2px 6px;color:#fbbf24;white-space:nowrap;"><i class="fa-solid fa-pen" style="margin-right:2px;font-size:.58rem;"></i>Separado</td>
                 <td style="padding:2px 6px;font-weight:700;color:#fbbf24;">${_solFmtQty(qtySepReg)} ${unidade}</td>
               </tr>
             </table>
           </div>`
        : `<span style="font-size:.80rem;font-weight:700;color:#f0f0f0;">${_solFmtQty(qty)} ${unidade}</span>`)
      : qtdManualPendente
      ? `<div style="display:flex;flex-direction:column;align-items:flex-end;gap:4px;min-width:100px;">
           <span style="font-size:.68rem;color:#fbbf24;font-weight:700;"><i class="fa-solid fa-hourglass-half" style="margin-right:2px;font-size:.58rem;"></i>Aguardando Separado</span>
           <table style="font-size:.62rem;border-collapse:collapse;border:1px solid #374151;border-radius:4px;overflow:hidden;">
             <tr style="background:#1f2937;"><td style="padding:2px 6px;color:#9ca3af;white-space:nowrap;">Original</td><td style="padding:2px 6px;font-weight:700;color:#d1d5db;">${_solFmtQty(qtyOrig)} ${unidade}</td></tr>
             <tr style="background:#292419;"><td style="padding:2px 6px;color:#86efac;white-space:nowrap;">Separar</td><td style="padding:2px 6px;font-weight:700;color:#86efac;">${_solFmtQty(qtySepReg)} ${unidade}</td></tr>
             ${qtyStandbyPend > 0.0001 ? `<tr style="background:#2a1a2a;"><td style="padding:2px 6px;color:#ec4899;white-space:nowrap;">Stand-by</td><td style="padding:2px 6px;font-weight:700;color:#ec4899;">${_solFmtQty(qtyStandbyPend)} ${unidade}</td></tr>` : ''}
             ${qtyExtraPend > 0.0001 ? `<tr style="background:#1a2a1a;"><td style="padding:2px 6px;color:#a78bfa;white-space:nowrap;">A mais</td><td style="padding:2px 6px;font-weight:700;color:#a78bfa;">${_solFmtQty(qtyExtraPend)} ${unidade}</td></tr>` : ''}
           </table>
         </div>`
      : `<div class="sep-qty-wrap" style="display:flex;align-items:center;gap:4px;flex-shrink:0;">
           <span class="sep-qty-label" style="font-size:.80rem;font-weight:700;color:#f0f0f0;white-space:nowrap;">${_solFmtQty(qty)} ${unidade}</span>
         </div>`;
    const isUrgente = !!it.urgente;
    return `
      <div class="sep-row sep-row--work" data-item-row="${it.cod_omie || it.codigo_produto}"
           data-n-solic="${nSolic || ''}"
           data-solic-ids='${JSON.stringify(it.solic_ids)}'
           data-carr-ids='${JSON.stringify(it.carr_ids)}'
           data-qty-total="${qty}"
           data-qty-orig="${Number.isFinite(qtyOrig) ? qtyOrig : ''}"
           data-qty-sep-reg="${Number.isFinite(qtySepReg) ? qtySepReg : ''}"
           data-status="${it.status}"
           data-urgente="${isUrgente ? '1' : '0'}"
           data-codigo="${String(it.codigo_produto || '').replace(/"/g, '&quot;')}"
           data-descricao="${encodeURIComponent(it.descricao || '')}"
           data-observacao="${encodeURIComponent(obsText)}"
           data-unidade="${String(it.unidade || 'UN').replace(/"/g, '&quot;')}"
           data-requer-etq="${usarOrigemSepFase ? '1' : '0'}"
           data-origem-cod="${usarOrigemSepFase ? PRINC_ARMZ : ''}"
           data-etq-id=""
           data-etq-endereco=""
           data-etq-qtd=""
           style="display:flex;align-items:flex-start;gap:12px;padding:10px 16px;border-top:1px solid #222;${isConferido ? 'background:#0c1812;border-left:3px solid #22c55e;' : ''}${isUrgente ? 'border-left:3px solid #ef4444 !important;' : ''}">
        <div class="sep-thumb" data-preview-title="${String(it.codigo_produto || '').replace(/"/g, '&quot;')} - ${String(it.descricao || '').replace(/"/g, '&quot;')}" style="width:40px;height:40px;border-radius:8px;background:#0f0f0f;overflow:hidden;flex-shrink:0;margin-top:2px;cursor:zoom-in;">
          ${_solGetMiniImgHtml(it.codigo_produto, it.descricao || '')}
        </div>
        <div class="sep-main" style="flex:1;min-width:0;">
          <div style="font-weight:700;font-size:.80rem;color:#f59e0b;">${it.codigo_produto}</div>
          <div style="font-size:.78rem;color:#d1d5db;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${it.descricao || '—'}</div>
          <div class="sep-meta" style="font-size:.73rem;color:#9ca3af;margin-top:2px;display:flex;align-items:center;gap:6px;flex-wrap:wrap;">
            ${dh ? `<i class="fa-regular fa-calendar" style="color:#6b7280;"></i><span>${dh}</span>` : ''}
            ${isConferido
              ? `<span style="display:inline-flex;align-items:center;gap:4px;padding:2px 8px;border-radius:20px;font-size:.68rem;font-weight:700;color:#86efac;background:#0f2018;border:1px solid #22c55e55;">
                   <i class="fa-solid fa-clipboard-check" style="font-size:.62rem;"></i>Conferido
                 </span>
                 <span style="font-size:.65rem;color:#6ee7b7;font-style:italic;">aguardando demais itens</span>`
              : _solStatusBadge(it.status || 'Separação')}
            ${hasObs ? `<span title="Item com observação" style="display:inline-flex;align-items:center;justify-content:center;width:16px;height:16px;border-radius:999px;background:#f97316;color:#111;font-weight:800;font-size:.70rem;line-height:1;">!</span>` : ''}
            ${isStandby && emCompraCodigos.has(String(it.codigo_produto || '').trim().toUpperCase())
              ? `<button type="button" class="btn-item-em-compra"
                   onclick="event.stopPropagation();abrirModalEmCompra('${String(it.codigo_produto || '').replace(/'/g, "\\'")}')"
                   title="Ver dados da compra"
                   style="display:inline-flex;align-items:center;gap:4px;padding:2px 8px;border-radius:20px;font-size:.67rem;font-weight:700;cursor:pointer;border:1px solid #3b82f6;background:#1e3a5f;color:#93c5fd;">
                   <i class="fa-solid fa-cart-shopping" style="font-size:.62rem;"></i>Em compra
                 </button>`
              : ''}
            ${readonlySep ? '' : `<button class="btn-item-urgente" title="Urgente, entregar o quanto antes este item"
              style="display:inline-flex;align-items:center;gap:3px;padding:2px 7px;border-radius:20px;font-size:.67rem;font-weight:700;cursor:pointer;border:1px solid ${isUrgente ? '#ef4444' : '#374151'};background:${isUrgente ? '#450a0a' : 'transparent'};color:${isUrgente ? '#fca5a5' : '#6b7280'};transition:all .15s;">
              <i class="fa-solid fa-bolt" style="font-size:.63rem;"></i>${isUrgente ? 'Urgente' : ''}
            </button>`}
          </div>
          ${swapHistory}
          ${localizacaoHtml}
        </div>
          <div class="sep-qty">${qtyHtml}</div>
          ${readonlySep
            ? ''
            : isConferido
            ? `<div style="display:grid;grid-template-columns:${isCompact ? '1fr 1fr' : 'auto'};gap:6px;align-items:flex-start;justify-content:flex-end;flex-shrink:0;width:${isCompact ? '100%' : 'auto'};">
                 <button class="btn-item-retificar" title="Voltar item para Separado"
                   style="padding:4px 9px;border:none;border-radius:6px;background:#4b5563;color:#e5e7eb;font-weight:700;font-size:.70rem;cursor:pointer;white-space:nowrap;min-height:32px;">
                   <i class="fa-solid fa-rotate-left" style="margin-right:3px;"></i>Retificar
                 </button>
               </div>`
            : isSep
            ? `<div style="display:grid;grid-template-columns:${isCompact ? '1fr 1fr' : 'auto auto auto'};gap:6px;align-items:flex-start;justify-content:flex-end;flex-shrink:0;width:${isCompact ? '100%' : 'auto'};">
                 <button class="btn-item-conferido" title="Enviar para Aguardando retirada"
                   style="padding:4px 9px;border:none;border-radius:6px;background:#16a34a;color:#dcfce7;font-weight:700;font-size:.70rem;cursor:pointer;white-space:nowrap;min-height:32px;">
                   <i class="fa-solid fa-clipboard-check" style="margin-right:3px;"></i>Conferido
                 </button>
                 <button class="btn-item-retificar" title="Voltar item para Em Separação"
                   style="padding:4px 9px;border:none;border-radius:6px;background:#4b5563;color:#e5e7eb;font-weight:700;font-size:.70rem;cursor:pointer;white-space:nowrap;min-height:32px;">
                   <i class="fa-solid fa-rotate-left" style="margin-right:3px;"></i>Retificar
                 </button>
                 <button class="btn-item-trocar" title="Trocar este produto"
                   style="padding:4px 9px;border:none;border-radius:6px;background:#7c3aed;color:#f3e8ff;font-weight:700;font-size:.70rem;cursor:pointer;white-space:nowrap;min-height:32px;">
                   <i class="fa-solid fa-arrows-rotate" style="margin-right:3px;"></i>Trocar
                 </button>
               </div>`
            : `<div style="display:flex;flex-direction:column;align-items:flex-end;gap:4px;width:${isCompact ? '100%' : 'auto'};">
                 <div style="display:grid;grid-template-columns:1fr 1fr;gap:4px;width:100%;">
                   <button class="btn-item-sep-tudo"
                     style="padding:4px 6px;border:none;border-radius:6px;background:#166534;color:#dcfce7;font-weight:700;font-size:.67rem;cursor:pointer;white-space:nowrap;text-align:center;min-height:32px;">
                     <i class="fa-solid fa-check" style="margin-right:2px;"></i>Separei tudo
                   </button>
                   <button class="btn-item-sep-parcial"
                     style="padding:4px 6px;border:none;border-radius:6px;background:#b45309;color:#ffedd5;font-weight:700;font-size:.67rem;cursor:pointer;white-space:nowrap;text-align:center;min-height:32px;">
                     <i class="fa-solid fa-scale-balanced" style="margin-right:2px;"></i>Informar qtd
                   </button>
                   ${isEmSeparacao ? `
                   <button class="btn-item-nao-sep"
                     style="padding:4px 6px;border:none;border-radius:6px;background:#7c2d12;color:#ffedd5;font-weight:700;font-size:.67rem;cursor:pointer;white-space:nowrap;text-align:center;min-height:32px;">
                     <i class="fa-solid fa-xmark" style="margin-right:2px;"></i>Não separei
                   </button>
                   <button class="btn-item-trocar" title="Trocar este produto"
                     style="padding:4px 6px;border:none;border-radius:6px;background:#7c3aed;color:#f3e8ff;font-weight:700;font-size:.67rem;cursor:pointer;white-space:nowrap;text-align:center;min-height:32px;">
                     <i class="fa-solid fa-arrows-rotate" style="margin-right:2px;"></i>Trocar
                   </button>` : ''}
                 </div>
                 ${usarOrigemSepFase ? _solRenderIdsFifoHtml(_idsFifoDoItem(it, qty), unidade) : ''}
                 ${obsText ? `<div style="font-size:.63rem;color:#93c5fd;text-align:${isCompact ? 'left' : 'right'};max-width:${isCompact ? '100%' : '200px'};word-break:break-word;"><i class="fa-solid fa-comment" style="margin-right:3px;color:#6b7280;"></i>${obsText}</div>` : ''}
               </div>`}
      </div>`;
  }

  let aggItens = _aggItens(_itensVisiveisModalSep(grupoAtual.itens));
  let estoqueBatch = preloaded.estoqueBatch || {};
  let enderecoBatch = _solMergeEnderecoBatch(
    [...(grupoAtual.itens || []), ...aggItens],
    preloaded.enderecoBatch || {}
  );
  let etqIdsBatch = preloaded.etqIdsBatch || {};

  if (isStandby) {
    try {
      const mapa = await getProdutosEmCompra();
      emCompraCodigos = new Set([...(mapa || new Map()).keys()]);
    } catch (_) {
      emCompraCodigos = new Set();
    }
  }

  function _idsFifoDoItem(it, qty) {
    const cod = String(it?.codigo_produto || '').trim();
    const lista = (cod && etqIdsBatch[cod]) ? etqIdsBatch[cod] : [];
    return _solPickIdsFifoAteQty(lista, qty).ids;
  }

  function _renderLista() {
    const lista = document.getElementById('modalSepItemsList');
    if (lista) lista.innerHTML = aggItens.map(it => _renderAggItem(it, grupoAtual.n_solic)).join('');
    if (gruposConflito.length) {
      modal.querySelectorAll('.modal-sep-conflito').forEach((block, idx) => {
        const g = gruposConflito[idx];
        const host = block.querySelector('.modal-sep-conflito-itens');
        if (host && g) host.innerHTML = g.itensConflito.map(i => _solRenderItemRow(i, 'disabled', enderecoBatch)).join('');
      });
    }
  }

  async function _carregarEstoque() {
    const codigosAgg = aggItens.map(it => it.codigo_produto);
    const codigosConfl = gruposConflito.flatMap(g => (g.itensConflito || []).map(i => i.codigo_produto));
    const codigos = [...new Set([...codigosAgg, ...codigosConfl].filter(Boolean))];
    if (!codigos.length) return;
    try {
      const [re, rep, rid] = await Promise.all([
        fetch('/api/logistica/estoque/batch?codigos=' + encodeURIComponent(codigos.join(',')), { credentials: 'include' }),
        fetch('/api/logistica/endereco-pp/batch?codigos=' + encodeURIComponent(codigos.join(',')), { credentials: 'include' }),
        fetch('/api/etiquetas/rec-impresso/ids-fifo-batch?codigos=' + encodeURIComponent(codigos.join(',')), { credentials: 'include' })
      ]);
      const de = await re.json();
      const dep = await rep.json();
      const did = await rid.json().catch(() => ({}));
      if (de.ok) estoqueBatch = { ...estoqueBatch, ...(de.dados || {}) };
      if (dep.ok) enderecoBatch = _solMergeEnderecoBatch(aggItens, { ...enderecoBatch, ...(dep.dados || {}) });
      else enderecoBatch = _solMergeEnderecoBatch(aggItens, enderecoBatch);
      if (did.ok) etqIdsBatch = { ...etqIdsBatch, ...(did.dados || {}) };
    } catch (_) {}
    if (document.getElementById('modalSeparacaoLogistica')) _renderLista();
  }

  async function _abrirLeituraFifoDoRow(row) {
    if (!row) return;
    const qty = parseFloat(row.dataset.qtyTotal || '0') || 0;
    const codigo = row.dataset.codigo || '';
    const unidade = row.dataset.unidade || 'UN';
    const idsEsperados = _idsFifoDoItem({ codigo_produto: codigo }, qty);
    if (!idsEsperados.length) {
      alert('Não há IDs com saldo no Porta Pallet para este produto.');
      return;
    }
    // Já lidos: mantém; falta o restante da fila
    let selecoes = _solLerSelecoesEtq(row);
    const lidos = new Set(selecoes.map(s => Number(s.id)).filter(Boolean));
    const pendentes = idsEsperados.filter(e => !lidos.has(Number(e.id)));
    if (!pendentes.length) {
      alert('Todos os IDs necessários já foram lidos.');
      return;
    }
    const falta = Math.max(0, qty - selecoes.reduce((s, a) => s + (Number(a.tirar) || 0), 0));
    if (falta <= 1e-9) {
      alert('Quantidade já completa com os IDs lidos.');
      return;
    }
    const result = await _solAbrirLeitorQrIdsSep({
      codigoProduto: codigo,
      qtyNeeded: falta,
      unidade,
      idsEsperados: pendentes,
      permitirForaOrdem: _modalSepIgnorarSaldoEtq()
    });
    if (!result?.ok || !Array.isArray(result.leituras) || !result.leituras.length) return;
    selecoes = _solLerSelecoesEtq(row);
    for (const l of result.leituras) {
      const idNum = Number(l.id);
      if (selecoes.some(s => Number(s.id) === idNum)) continue;
      selecoes.push({
        id: String(l.id),
        endereco: String(l.endereco || ''),
        saldo: Number(l.saldo) || 0,
        tirar: Number(l.tirar) || 0
      });
    }
    row.dataset.etqSelecoes = JSON.stringify(selecoes);
    _solAplicarVisualAlocacaoEtq(row, qty);
    _marcarIdsLidosNaLista(row, selecoes);
  }

  function _marcarIdsLidosNaLista(row, selecoes) {
    const lidosAgora = new Set((selecoes || []).map(s => Number(s.id)).filter(Boolean));
    row.querySelectorAll('.sep-etq-id-row').forEach(el => {
      const id = Number(el.dataset.etqId);
      if (lidosAgora.has(id)) {
        el.style.color = '#86efac';
        el.style.opacity = '0.85';
        const span = el.querySelector('span');
        if (span && !span.textContent.includes('✓')) span.textContent = span.textContent.replace(' ← ler', '') + ' ✓';
      }
    });
  }

  /* "Sem leitura": consome automaticamente os menores IDs (FIFO), sem escanear.
     Paliativo até os IDs físicos estarem organizados nos produtos. */
  function _aplicarSemLeituraDoRow(row) {
    if (!row) return;
    const qty = parseFloat(row.dataset.qtyTotal || '0') || 0;
    const codigo = row.dataset.codigo || '';
    const idsEsperados = _idsFifoDoItem({ codigo_produto: codigo }, qty);
    if (!idsEsperados.length) {
      alert('Não há IDs com saldo no Porta Pallet para este produto.');
      return;
    }
    let selecoes = _solLerSelecoesEtq(row);
    const lidos = new Set(selecoes.map(s => Number(s.id)).filter(Boolean));
    const pendentes = idsEsperados.filter(e => !lidos.has(Number(e.id)));
    const falta = Math.max(0, qty - selecoes.reduce((s, a) => s + (Number(a.tirar) || 0), 0));
    if (!pendentes.length || falta <= 1e-9) {
      alert('Quantidade já completa com os IDs lidos.');
      return;
    }
    if (!confirm(
      `Dar baixa SEM leitura?\n\nO sistema vai consumir automaticamente os menores IDs:\n` +
      pendentes.map(p => `• ID ${p.id} → ${_solFmtQty(p.tirar)} ${p.unidade || 'UN'}`).join('\n')
    )) return;
    for (const p of pendentes) {
      selecoes.push({
        id: String(p.id),
        endereco: String(p.endereco || ''),
        saldo: Number(p.qtd) || 0,
        tirar: Number(p.tirar) || 0
      });
    }
    row.dataset.etqSelecoes = JSON.stringify(selecoes);
    _solAplicarVisualAlocacaoEtq(row, qty);
    _marcarIdsLidosNaLista(row, selecoes);
    // Marca o endereço do Porta Pallet como selecionado visualmente
    row.querySelectorAll('.sep-etq-endereco-row').forEach(el => {
      el.dataset.selected = '1';
      el.style.borderColor = '#22c55e';
      el.style.background = '#1a2e1a';
    });
    const btnSem = row.querySelector('.btn-sem-leitura-etq');
    if (btnSem) {
      btnSem.style.background = '#14532d';
      btnSem.style.borderColor = '#16a34a';
      btnSem.style.color = '#86efac';
      btnSem.innerHTML = '<i class="fa-solid fa-check" style="margin-right:4px;"></i>Baixa sem leitura aplicada';
    }
  }

  // Recarrega o SEP original do servidor e re-renderiza lista (sem sub-SEPs — .1 vai para fila pendente)
  let _reloadPending = false;
  async function reloadItems(opts = {}) {
    if (_reloadPending) return;
    _reloadPending = true;
    const lockAntes = { usuarioSeparando, podeAgirSep, perdeuSeparacaoParaOutro, podeCancelarSep };
    try {
      const r = await fetch(_solBuildKanbanItensUrl(grupoAtual.n_solic, { escopoItens: grupoAtual.escopoItens }), { credentials: 'include' });
      const d = await r.json();
      if (!d.ok) return;
      const mapped = (d.itens || []).map(it => ({ ...it, solic_ids: [it.solic_id], carr_ids: [it.carr_id] }));
      const visiveis = _itensVisiveisModalSep(mapped);
      if (!visiveis.length) {
        fecharModal();
        return;
      }
      aggItens = _aggItens(visiveis);
      grupoAtual.itens = mapped;
      if (opts.skipLockSync) {
        usuarioSeparando = lockAntes.usuarioSeparando;
        podeAgirSep = lockAntes.podeAgirSep;
        perdeuSeparacaoParaOutro = lockAntes.perdeuSeparacaoParaOutro;
        podeCancelarSep = lockAntes.podeCancelarSep;
      } else {
        _syncSepLockFromItens(mapped);
      }
      await _carregarEstoque();
      if (!opts.skipLockSync) _atualizarUiLockSep();
      else _renderLista();
    } catch (_) {} finally { _reloadPending = false; }
  }

  async function _postRegistrarQtdManual(row, qtySep, motivo) {
    const solicIds = JSON.parse(row.dataset.solicIds || '[]');
    const carrIds  = JSON.parse(row.dataset.carrIds  || '[]');
    const r = await fetch('/api/logistica/itens_solicitados/registrar-qtd-manual', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({
        solic_ids: solicIds,
        carr_ids: carrIds,
        quantidade_separada: qtySep,
        motivo: motivo || '',
        ..._solSepPayloadFromRow(row),
        ..._solSepPayloadExtras()
      })
    });
    const d = await r.json();
    if (!d.ok) throw new Error(d.error || 'Erro ao registrar quantidade manual.');
    houveMudanca = true;
    await reloadItems();
    window._loadSolicitacoesTab.force = true;
    window._loadSolicitacoesTab();
    window._loadKanbanSolicitacoesTab.force = true;
    window._loadKanbanSolicitacoesTab();
    return d;
  }

  async function _postExecutarSepParcial(row, qtySep, motivo) {
    const solicIds = JSON.parse(row.dataset.solicIds || '[]');
    const carrIds  = JSON.parse(row.dataset.carrIds  || '[]');
    const r = await fetch('/api/logistica/itens_solicitados/separar-parcial', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({
        solic_ids: solicIds,
        carr_ids: carrIds,
        quantidade_separada: qtySep,
        motivo: motivo || '',
        ..._solSepPayloadFromRow(row),
        ..._solSepPayloadExtras()
      })
    });
    const d = await r.json();
    if (!d.ok) throw new Error(d.error || 'Erro ao processar separação parcial.');
    houveMudanca = true;
    await reloadItems();
    window._loadSolicitacoesTab.force = true;
    window._loadSolicitacoesTab();
    window._loadKanbanSolicitacoesTab.force = true;
    window._loadKanbanSolicitacoesTab();
    return d;
  }

  async function _executarSeparadoItem(row) {
    if (!(await _verificarSeparadorSep())) return false;
    const qtyTotal = parseFloat(row.dataset.qtyTotal || '0') || 0;
    const solicIds = JSON.parse(row.dataset.solicIds || '[]');
    const qtySepReg = parseFloat(row.dataset.qtySepReg || '');
    const qtyOrigReg = parseFloat(row.dataset.qtyOrig || '');
    const temQtdManual = Number.isFinite(qtySepReg) && Number.isFinite(qtyOrigReg)
      && Math.abs(qtyOrigReg - qtySepReg) > 0.0001;

    if (temQtdManual) {
      if (!_solValidarOrigemSepRow(row, qtySepReg)) return false;
      _solRowLoading(row, true);
      try {
        const motivo = decodeURIComponent(row.dataset.observacao || '');
        const d = await _postExecutarSepParcial(row, qtySepReg, motivo);
        if (d.reintegrado) {
          alert(`Produto devolvido à SEP original (${d.n_solic || 'original'}).`);
        }
        return true;
      } catch (err) {
        if (!_tratarErroSeparadorPerdido(err)) alert('Erro: ' + (err.message || err));
        return false;
      } finally {
        _solRowLoading(row, false);
      }
    }

    if (!_solValidarOrigemSepRow(row, qtyTotal)) return false;
    _solRowLoading(row, true);
    try {
      const r = await fetch('/api/logistica/itens_solicitados/separar', {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({ solic_ids: solicIds, ..._solSepPayloadFromRow(row), ..._solSepPayloadExtras() })
      });
      const d = await r.json();
      if (!d.ok) throw new Error(d.error || 'Erro ao registrar item separado.');
      if (d.reintegrado) {
        alert(`Produto devolvido à SEP original (${d.n_solic || 'original'}).`);
      }
      houveMudanca = true;
      await reloadItems();
      window._loadSolicitacoesTab.force = true;
      window._loadSolicitacoesTab();
      window._loadKanbanSolicitacoesTab.force = true;
      window._loadKanbanSolicitacoesTab();
      return true;
    } catch (err) {
      if (!_tratarErroSeparadorPerdido(err)) alert('Erro: ' + (err.message || err));
      return false;
    } finally {
      _solRowLoading(row, false);
    }
  }

  async function _postSepParcial(row, qtySep, motivo) {
    return _postRegistrarQtdManual(row, qtySep, motivo);
  }

  async function _confirmarSepParcial(row, qtySep, opts = {}) {
    if (!(await _verificarSeparadorSep())) return false;
    if (!_solValidarOrigemSepRow(row, qtySep)) return false;
    const unidade  = row.dataset.unidade || 'UN';
    const qtyTotal = parseFloat(row.dataset.qtyTotal || '0') || 0;
    if (!Number.isFinite(qtySep) || qtySep <= 0) {
      alert('Quantidade inválida. Use um valor maior que 0.');
      return false;
    }
    if (qtySep > qtyTotal && !opts.skipHighConfirm) {
      const ok = confirm(`Você informou ${_solFmtQty(qtySep)} ${unidade}, maior que o solicitado (${_solFmtQty(qtyTotal)} ${unidade}). Confirmar esta quantidade separada?`);
      if (!ok) return false;
    }
    let motivo = opts.motivo;
    if (motivo == null && qtySep < qtyTotal) {
      motivo = prompt('Motivo da separação parcial:', '') || '';
    }
    _solRowLoading(row, true);
    try {
      await _postSepParcial(row, qtySep, motivo);
      return true;
    } catch (err) {
      if (!_tratarErroSeparadorPerdido(err)) alert('Erro: ' + (err.message || err));
      return false;
    } finally {
      _solRowLoading(row, false);
    }
  }

  function fecharModal() {
    modal.remove();
    document.querySelectorAll('#modalSeparacaoLogistica').forEach(el => el.remove());
    if (houveMudanca || refreshAoFechar) {
      _solInvalidateSepModalCache(grupoAtual.n_solic, grupoAtual.escopoItens || 'global');
      window._loadSolicitacoesTab.force = true;
      window._loadSolicitacoesTab();
      window._loadKanbanSolicitacoesTab.force = true;
      window._loadKanbanSolicitacoesTab();
    }
  }

  // Pré-carrega estoque + endereçamento antes de montar o modal (igual ao Solicitado)
  await _carregarEstoque();

  let conflitosHtml = '';
  if (gruposConflito.length > 0) {
    conflitosHtml = `
      <div style="margin-top:18px;padding-top:14px;border-top:2px solid #333;">
        <div style="font-size:.75rem;color:#6b7280;font-weight:700;padding:0 16px 8px;letter-spacing:.05em;text-transform:uppercase;">Outros usuários com os mesmos produtos</div>
        ${gruposConflito.map(g => {
          const idsConflito = g.itensConflito.flatMap(i => Array.isArray(i.solic_ids) ? i.solic_ids : (i.solic_id ? [i.solic_id] : []));
          return `
            <div class="modal-sep-conflito" data-conflito-user="${g.nome_user.replace(/"/g, '&quot;')}" style="background:#171717;border:1px solid #2a2a2a;border-radius:10px;margin:0 12px 10px;overflow:hidden;">
              <div style="display:flex;align-items:center;gap:8px;padding:10px 14px;border-bottom:1px solid #2a2a2a;">
                <i class="fa-solid fa-user-circle" style="color:#f59e0b;font-size:1rem;"></i>
                <span style="font-weight:700;font-size:.88rem;color:#f0f0f0;">${g.nome_user}</span>
                <button class="btn-modal-sep-conflito"
                  data-solic-ids='${JSON.stringify(idsConflito)}'
                  data-nome-user="${g.nome_user.replace(/"/g, '&quot;')}"
                  style="margin-left:auto;padding:4px 10px;border:none;border-radius:6px;background:#f59e0b;color:#111;font-weight:700;font-size:.73rem;cursor:pointer;white-space:nowrap;">
                  <i class="fa-solid fa-boxes-stacked" style="margin-right:3px;"></i>Iniciar separação
                </button>
              </div>
              <div class="modal-sep-conflito-itens">${g.itensConflito.map(i => _solRenderItemRow(i, 'disabled', enderecoBatch)).join('')}</div>
            </div>`;
        }).join('')}
      </div>`;
  }

  const modal = document.createElement('div');
  modal.id = 'modalSeparacaoLogistica';
  modal.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,.65);z-index:10050;display:flex;align-items:center;justify-content:center;';
  modal.innerHTML = `
    <div style="position:relative;background:#1c1c1c;border:1px solid #2a2a2a;border-radius:16px;width:min(760px,96vw);max-height:92vh;display:flex;flex-direction:column;overflow:hidden;box-shadow:0 20px 60px rgba(0,0,0,.6);">
      <div style="display:flex;align-items:center;gap:10px;padding:16px 20px;border-bottom:1px solid #2a2a2a;background:#171717;flex-shrink:0;">
        <i class="fa-solid ${isStandby ? 'fa-bag-shopping' : 'fa-boxes-stacked'}" style="color:${isStandby ? '#ec4899' : '#f59e0b'};font-size:1.1rem;"></i>
        <span style="font-weight:700;font-size:1rem;color:#f0f0f0;" id="modalSeparacaoTitle">${modalTitle}</span>
        <button id="btnModalSepFechar" style="margin-left:auto;background:none;border:none;color:#9ca3af;font-size:1.3rem;cursor:pointer;padding:2px 6px;line-height:1;">&#x2715;</button>
      </div>
      <div id="modalSepInner" style="overflow-y:auto;flex:1;padding-bottom:16px;">
        <div id="modalSepLockBanner">${_htmlBannerSepLock()}</div>
        <div style="display:flex;align-items:center;justify-content:space-between;gap:12px;padding:12px 16px 4px;flex-wrap:wrap;">
          <div style="font-size:.75rem;color:#6b7280;font-weight:700;letter-spacing:.05em;text-transform:uppercase;">${isStandby ? 'Itens em stand-by' : 'Itens em separação'}</div>
          ${!isStandby ? `
          <label title="Permite concluir a separação e transferir na Omie sem debitar saldo em ETQ_rec_impresso quando o endereço estiver zerado ou abaixo do solicitado." style="display:flex;align-items:center;gap:6px;cursor:pointer;user-select:none;font-size:.72rem;color:#9ca3af;font-weight:600;">
            <input type="checkbox" id="modalSepIgnorarSaldoEtq" style="accent-color:#f59e0b;cursor:pointer;width:14px;height:14px;" />
            Permitir sem saldo no endereço
          </label>` : ''}
        </div>
        <div id="modalSepItemsList">
          ${aggItens.map(it => _renderAggItem(it, grupoAtual.n_solic)).join('')}
        </div>
        ${conflitosHtml}
      </div>
      ${isStandby ? `
      <div style="padding:12px 16px;border-top:1px solid #2a2a2a;display:flex;justify-content:space-between;align-items:center;gap:8px;background:#171717;flex-wrap:wrap;">
        <button type="button" id="btnPlanejarSeparacaoModal" title="Ver no Armazém 3D onde estão os itens desta SEP"
          style="padding:7px 14px;border:none;border-radius:8px;background:#0ea5e9;color:#e0f2fe;font-weight:700;font-size:.82rem;cursor:pointer;">
          <i class="fa-solid fa-warehouse" style="margin-right:4px;"></i>Planejar separação
        </button>
        <div style="display:flex;gap:8px;flex-wrap:wrap;">
          <button id="btnStandbySolicitarCompra" style="padding:7px 14px;border:1px solid #4b5563;border-radius:8px;background:transparent;color:#d1d5db;font-weight:700;font-size:.82rem;cursor:pointer;">
            <i class="fa-solid fa-cart-shopping" style="margin-right:4px;"></i>Solicitar compra
          </button>
          <button id="btnStandbyIniciarSep" style="padding:7px 14px;border:none;border-radius:8px;background:#1d4ed8;color:#dbeafe;font-weight:700;font-size:.82rem;cursor:pointer;">
            <i class="fa-solid fa-play" style="margin-right:4px;"></i>Iniciar separação
          </button>
        </div>
      </div>` : ''}
      ${!isStandby ? `
      <div id="modalSepFooterCancel" style="padding:12px 16px;border-top:1px solid #2a2a2a;display:flex;justify-content:space-between;align-items:center;gap:8px;background:#171717;flex-wrap:wrap;">
        <button id="btnCancelarSeparacao" style="padding:7px 14px;border:1px solid #7f1d1d;border-radius:8px;background:transparent;color:#f87171;font-weight:700;font-size:.82rem;cursor:pointer;display:${podeCancelarSep ? 'inline-flex' : 'none'};align-items:center;">
          <i class="fa-solid fa-ban" style="margin-right:4px;"></i>Cancelar separação
        </button>
        <button type="button" id="btnPlanejarSeparacaoModal" title="Ver no Armazém 3D onde estão os itens desta SEP"
          style="padding:7px 14px;border:none;border-radius:8px;background:#0ea5e9;color:#e0f2fe;font-weight:700;font-size:.82rem;cursor:pointer;margin-left:auto;">
          <i class="fa-solid fa-warehouse" style="margin-right:4px;"></i>Planejar separação
        </button>
      </div>` : ''}
    </div>`;

  document.body.appendChild(modal);

  document.getElementById('btnModalSepFechar')?.addEventListener('click', () => fecharModal());
  modal.addEventListener('click', e => { if (e.target === modal) fecharModal(); });

  document.getElementById('btnPlanejarSeparacaoModal')?.addEventListener('click', (ev) => {
    ev.preventDefault();
    ev.stopPropagation();
    const codigos = [...new Set(
      (aggItens || [])
        .map(it => String(it.codigo_produto || '').trim())
        .filter(Boolean)
    )];
    const btnEl = ev.currentTarget;
    if (typeof window._arm3dAbrirPlanejarSeparacao !== 'function') {
      alert('Função de planejamento não carregada. Dê F5 e tente de novo.');
      return;
    }
    void window._arm3dAbrirPlanejarSeparacao({
      codigos,
      nSolic: grupoAtual.n_solic,
      btn: btnEl
    }).catch((err) => {
      console.error('[planejar-sep click]', err);
      alert('Erro ao planejar: ' + (err?.message || err));
      if (btnEl) {
        btnEl.disabled = false;
        if (btnEl.dataset._html) btnEl.innerHTML = btnEl.dataset._html;
      }
    });
  });

  document.getElementById('btnCancelarSeparacao')?.addEventListener('click', async () => {
    const btn = document.getElementById('btnCancelarSeparacao');
    if (!btn || btn.disabled) return;
    if (!confirm('Cancelar a separação desta SEP? Ela voltará para o kanban Solicitado e seu nome será removido como separador.')) return;
    const solicIds = (grupoAtual.itens || [])
      .filter(it => ['Separação', 'Em Separação', 'Separado'].includes(String(it.status || '')))
      .map(it => parseInt(it.solic_id, 10))
      .filter(id => !Number.isNaN(id));
    if (!solicIds.length) {
      alert('Nenhum item em separação para cancelar.');
      return;
    }
    btn.disabled = true;
    btn.innerHTML = '<i class="fa-solid fa-spinner fa-spin" style="margin-right:4px;"></i>Cancelando...';
    try {
      const r = await fetch('/api/logistica/itens_solicitados/cancelar-separacao', {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({ solic_ids: solicIds })
      });
      const d = await r.json();
      if (!d.ok) throw new Error(d.error || 'Erro ao cancelar separação.');
      houveMudanca = true;
      fecharModal();
      window._loadSolicitacoesTab.force = true;
      window._loadSolicitacoesTab();
      window._loadKanbanSolicitacoesTab.force = true;
      window._loadKanbanSolicitacoesTab();
      window._updateTabCounters?.();
    } catch (err) {
      alert('Erro: ' + (err.message || err));
      btn.disabled = false;
      btn.innerHTML = '<i class="fa-solid fa-ban" style="margin-right:4px;"></i>Cancelar separação';
    }
  });

  document.getElementById('btnStandbySolicitarCompra')?.addEventListener('click', () => {
    alert('Função "Solicitar compra" em configuração. Em breve estará disponível.');
  });

  document.getElementById('btnStandbyIniciarSep')?.addEventListener('click', async () => {
    const btn = document.getElementById('btnStandbyIniciarSep');
    if (!btn || btn.disabled) return;
    const solicIds = (grupoAtual.itens || [])
      .filter(it => String(it.status || '') === 'Stund-by')
      .map(it => parseInt(it.solic_id, 10))
      .filter(id => !Number.isNaN(id));
    if (!solicIds.length) {
      alert('Nenhum item em stand-by para iniciar separação.');
      return;
    }
    btn.disabled = true;
    btn.innerHTML = '<i class="fa-solid fa-spinner fa-spin" style="margin-right:4px;"></i>Iniciando...';
    try {
      await _solDispararVippGerarEtiqueta(grupoAtual.n_solic, { alertarErro: true, recarregarEnvio: true });
      const r = await fetch('/api/logistica/itens_solicitados/separacao', {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({ solic_ids: solicIds })
      });
      const d = await r.json();
      if (!d.ok) throw new Error(d.error || 'Erro ao iniciar separação.');

      fecharModal();

      const ri = await fetch(_solBuildKanbanItensUrl(grupoAtual.n_solic, { escopoItens: grupoAtual.escopoItens }), { credentials: 'include' });
      const di = await ri.json();
      if (!di.ok) throw new Error(di.error || 'Erro ao buscar itens após iniciar separação.');
      const itensAtualizados = (di.itens || []).map(it => ({ ...it, solic_ids: [it.solic_id], carr_ids: [it.carr_id] }));
      if (itensAtualizados.length) {
        await _abrirModalSeparacao(
          { nome_user: itensAtualizados[0]?.nome_user || grupoAtual.nome_user, n_solic: grupoAtual.n_solic, itens: itensAtualizados, origem_status: 'Em Separação', escopoItens: grupoAtual.escopoItens },
          []
        );
      }

      window._loadSolicitacoesTab.force = true;
      window._loadSolicitacoesTab();
      window._loadKanbanSolicitacoesTab.force = true;
      window._loadKanbanSolicitacoesTab();
    } catch (err) {
      alert('Erro: ' + (err.message || err));
      btn.disabled = false;
      btn.innerHTML = '<i class="fa-solid fa-play" style="margin-right:4px;"></i>Iniciar separação';
    }
  });

  const modalInner = document.getElementById('modalSepInner');

  modalInner.addEventListener('click', async (e) => {
    const btnAssumir = e.target.closest('#btnAssumirSeparacao');
    if (btnAssumir && !btnAssumir.disabled) {
      const solicIds = (grupoAtual.itens || [])
        .filter(it => ['Separação', 'Em Separação', 'Separado'].includes(String(it.status || '')))
        .map(it => parseInt(it.solic_id, 10))
        .filter(id => !Number.isNaN(id));
      if (!solicIds.length) {
        alert('Nenhum item em separação para assumir.');
        return;
      }
      if (!confirm(`Assumir a separação que está com ${usuarioSeparando}? O separador anterior perderá o controle.`)) return;
      btnAssumir.disabled = true;
      btnAssumir.innerHTML = '<i class="fa-solid fa-spinner fa-spin" style="margin-right:4px;"></i>Assumindo...';
      try {
        const r = await fetch('/api/logistica/itens_solicitados/assumir-separacao', {
          method: 'PATCH',
          headers: { 'Content-Type': 'application/json' },
          credentials: 'include',
          body: JSON.stringify({ solic_ids: solicIds })
        });
        const d = await r.json();
        if (!d.ok) throw new Error(d.error || 'Erro ao assumir separação.');
        _aplicarEstadoSeparadorAtivo(d.usuario_separando || currentUser);
        houveMudanca = true;
        await reloadItems({ skipLockSync: true });
        _aplicarEstadoSeparadorAtivo(d.usuario_separando || currentUser);
        _atualizarUiLockSep();
        _atualizarCacheModalSep();
        window._loadSolicitacoesTab.force = true;
        window._loadSolicitacoesTab();
        window._loadKanbanSolicitacoesTab.force = true;
        window._loadKanbanSolicitacoesTab();
      } catch (err) {
        alert('Erro: ' + (err.message || err));
        btnAssumir.disabled = false;
        btnAssumir.innerHTML = '<i class="fa-solid fa-hand" style="margin-right:4px;"></i>Assumir separação';
      }
      return;
    }
  });

  async function _abrirModalAcaoItemSep(row, coluna) {
    document.getElementById('modalAcaoItemSep')?.remove();
    const codigo = row.dataset.codigo || '';
    const descricao = decodeURIComponent(row.dataset.descricao || '');
    const observacao = decodeURIComponent(row.dataset.observacao || '');
    const unidade = row.dataset.unidade || 'UN';
    const qtyTotal = parseFloat(row.dataset.qtyTotal || '0') || 0;
    const solicIds = JSON.parse(row.dataset.solicIds || '[]');
    const carrIds = JSON.parse(row.dataset.carrIds || '[]');
    const status = row.dataset.status || 'Separação';
    const nSolicItem = row.dataset.nSolic || '';

    const modal = document.createElement('div');
    modal.id = 'modalAcaoItemSep';
    modal.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,.65);z-index:10080;display:flex;align-items:center;justify-content:center;';
    modal.innerHTML = `
      <div style="background:#1c1c1c;border:1px solid #2a2a2a;border-radius:16px;width:min(520px,95vw);display:flex;flex-direction:column;overflow:hidden;box-shadow:0 20px 60px rgba(0,0,0,.6);">
        <div style="display:flex;align-items:center;gap:10px;padding:16px 20px;border-bottom:1px solid #2a2a2a;background:#171717;">
          <i class="fa-solid fa-list-check" style="color:#f59e0b;font-size:1.05rem;"></i>
          <span style="font-weight:700;font-size:1rem;color:#f0f0f0;">${coluna || 'Ação do item'}${nSolicItem ? ` — ${nSolicItem}` : ''}</span>
          <button id="btnAcaoItemFechar" style="margin-left:auto;background:none;border:none;color:#9ca3af;font-size:1.3rem;cursor:pointer;padding:2px 6px;line-height:1;">&#x2715;</button>
        </div>
        <div style="padding:14px 16px;display:flex;flex-direction:column;gap:8px;">
          <div style="font-size:.78rem;color:#f59e0b;font-weight:700;">${codigo}</div>
          <div style="font-size:.84rem;color:#d1d5db;">${descricao || '—'}</div>
          <div style="font-size:.78rem;color:#93c5fd;">Observação: ${observacao || 'Sem observação'}</div>
          <div style="font-size:.82rem;color:#f0f0f0;font-weight:700;">Quantidade original: ${_solFmtQty(qtyTotal)} ${unidade}</div>
        </div>
        <div style="padding:12px 16px;border-top:1px solid #2a2a2a;display:flex;gap:8px;flex-wrap:wrap;justify-content:flex-end;background:#171717;">
          <button id="btnAcaoSepTudo" style="padding:7px 12px;border:none;border-radius:8px;background:#166534;color:#dcfce7;font-weight:700;font-size:.82rem;cursor:pointer;">Separado</button>
          <button id="btnAcaoSepParcial" style="padding:7px 12px;border:none;border-radius:8px;background:#b45309;color:#ffedd5;font-weight:700;font-size:.82rem;cursor:pointer;">Informar quantidade</button>
          ${status !== 'Stund-by' ? `<button id="btnAcaoNaoSep" style="padding:7px 12px;border:none;border-radius:8px;background:#7c2d12;color:#ffedd5;font-weight:700;font-size:.82rem;cursor:pointer;">Não separei</button>` : ''}
        </div>
      </div>`;
    document.body.appendChild(modal);

    const closeModal = () => modal.remove();
    document.getElementById('btnAcaoItemFechar').addEventListener('click', closeModal);
    modal.addEventListener('click', ev => { if (ev.target === modal) closeModal(); });

    document.getElementById('btnAcaoSepTudo').addEventListener('click', async () => {
      const btn = document.getElementById('btnAcaoSepTudo');
      if (!(await _verificarSeparadorSep())) return;
      _solBtnLoading(btn, 'Processando...');
      try {
        closeModal();
        await _executarSeparadoItem(row);
      } catch (err) {
        if (!_tratarErroSeparadorPerdido(err)) alert('Erro: ' + (err.message || err));
        _solBtnRestore(btn, 'Separado');
      }
    });

    document.getElementById('btnAcaoSepParcial').addEventListener('click', async () => {
      if (!(await _verificarSeparadorSep())) return;
      const qtyInput = prompt(`Quantidade separada (${unidade}). Pode ser maior que o solicitado quando a embalagem fechada vier com mais unidades:`, _solFmtQty(qtyTotal));
      if (qtyInput === null) return;
      const qtySep = parseFloat(String(qtyInput).replace(',', '.'));
      closeModal();
      await _confirmarSepParcial(row, qtySep);
    });

    const btnNaoSep = document.getElementById('btnAcaoNaoSep');
    if (btnNaoSep) {
      btnNaoSep.addEventListener('click', async () => {
        if (!(await _verificarSeparadorSep())) return;
        const ok = confirm('Confirmar que este item não foi separado?');
        if (!ok) return;
        _solBtnLoading(btnNaoSep, 'Processando...');
        try {
          for (const sid of solicIds) {
            const r = await fetch('/api/logistica/itens_solicitados/nao-separar', {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              credentials: 'include',
              body: JSON.stringify({ solic_id: sid })
            });
            const d = await r.json();
            if (!d.ok) throw new Error(d.error || 'Erro ao marcar item como não separado.');
          }
          houveMudanca = true;
          closeModal();
          await reloadItems();
          window._loadSolicitacoesTab.force = true;
          window._loadSolicitacoesTab();
          window._loadKanbanSolicitacoesTab.force = true;
          window._loadKanbanSolicitacoesTab();
        } catch (err) {
          if (!_tratarErroSeparadorPerdido(err)) alert('Erro: ' + (err.message || err));
          _solBtnRestore(btnNaoSep, '<i class="fa-solid fa-xmark" style="margin-right:2px;"></i>Não separei');
        }
      });
    }

  }

  // Busca inline de troca de produto (sem abrir modal sobre modal)
  async function _abrirTrocaInline(row) {
    if (!row) return;
    if (!(await _verificarSeparadorSep())) return;

    // Mantém somente um editor de troca aberto por vez
    modalInner.querySelectorAll('.sep-troca-inline-wrap').forEach(el => el.remove());

    const solicIds = JSON.parse(row.dataset.solicIds || '[]');
    if (!solicIds.length) return;
    const solicId = solicIds[0];
    const codigoAtual = String(row.dataset.codigo || '').trim();
    const descricaoAtual = decodeURIComponent(row.dataset.descricao || '');
    const quantidadeAtual = parseFloat(row.dataset.qtyTotal || '0') || null;

    const wrap = document.createElement('div');
    wrap.className = 'sep-troca-inline-wrap';
    wrap.style.cssText = 'padding:10px 16px 14px;border-top:1px solid #2a2a2a;background:#141a27;display:flex;flex-direction:column;gap:8px;';
    wrap.innerHTML = `
      <div style="display:flex;align-items:center;gap:8px;">
        <i class="fa-solid fa-arrows-rotate" style="color:#a78bfa;"></i>
        <span style="font-size:.80rem;color:#e5e7eb;font-weight:700;">Trocar produto ${codigoAtual ? `(${codigoAtual})` : ''}</span>
        <button type="button" class="btn-troca-inline-fechar" style="margin-left:auto;padding:3px 8px;border:1px solid #4b5563;border-radius:6px;background:transparent;color:#d1d5db;cursor:pointer;font-size:.74rem;">Fechar</button>
      </div>
      <div style="font-size:.73rem;color:#9ca3af;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${descricaoAtual || 'Selecione um novo produto abaixo'}</div>
      <div style="position:relative;">
        <input type="text" class="sep-troca-input" placeholder="Pesquisar produto (código ou descrição)..." autocomplete="off"
          style="width:100%;padding:7px 10px;border:1px solid #475569;border-radius:8px;font-size:12px;background:#1f2937;color:#f8fafc;box-sizing:border-box;" />
        <div class="sep-troca-resultados" style="display:none;position:static;max-height:300px;overflow-y:auto;background:#1f2937;border:1px solid #475569;border-radius:8px;box-shadow:0 12px 28px rgba(0,0,0,.35);margin-top:6px;"></div>
      </div>
      <div style="display:flex;justify-content:flex-end;gap:8px;">
        <button type="button" class="btn-troca-inline-cancelar" style="padding:5px 10px;border:1px solid #4b5563;border-radius:6px;background:transparent;color:#d1d5db;cursor:pointer;font-size:.75rem;">Cancelar</button>
      </div>
    `;

    row.insertAdjacentElement('afterend', wrap);

    const input = wrap.querySelector('.sep-troca-input');
    const resultadosEl = wrap.querySelector('.sep-troca-resultados');
    const btnFechar = wrap.querySelector('.btn-troca-inline-fechar');
    const btnCancelar = wrap.querySelector('.btn-troca-inline-cancelar');

    let timer = null;
    let lastQ = '';
    let resultados = [];

    const fechar = () => {
      if (timer) clearTimeout(timer);
      wrap.remove();
    };

    btnFechar.addEventListener('click', fechar);
    btnCancelar.addEventListener('click', fechar);

    input.addEventListener('input', () => {
      const q = (input.value || '').trim();
      if (timer) clearTimeout(timer);

      if (q.length < 2) {
        resultados = [];
        resultadosEl.style.display = 'none';
        resultadosEl.innerHTML = '';
        return;
      }

      resultadosEl.style.display = 'block';
      resultadosEl.innerHTML = '<div style="padding:10px 12px;color:#93c5fd;font-size:12px;">Buscando...</div>';
      lastQ = q;

      timer = setTimeout(async () => {
        try {
          const resp = await fetch('/api/logistica/produtos/buscar?q=' + encodeURIComponent(q), { credentials: 'include' });
          const data = await resp.json();
          if (!data?.ok || lastQ !== q) return;

          resultados = Array.isArray(data.resultados) ? data.resultados : [];
          if (!resultados.length) {
            resultadosEl.innerHTML = '<div style="padding:10px 12px;color:#9ca3af;font-size:12px;">Nenhum produto encontrado.</div>';
            return;
          }

          resultadosEl.innerHTML = resultados.map((p, idx) => `
            <div class="sep-troca-item" data-idx="${idx}" style="padding:8px 12px;cursor:pointer;border-bottom:1px solid #334155;display:flex;flex-direction:column;gap:2px;">
              <span style="font-weight:600;color:#f8fafc;font-size:12px;">${String(p.codigo || '—')}</span>
              <span style="color:#cbd5e1;font-size:11px;">${String(p.descricao || '—')}</span>
            </div>
          `).join('');
        } catch (err) {
          resultadosEl.innerHTML = '<div style="padding:10px 12px;color:#fca5a5;font-size:12px;">Erro ao buscar produtos.</div>';
        }
      }, 260);
    });

    resultadosEl.addEventListener('click', async (e) => {
      const itemEl = e.target.closest('.sep-troca-item');
      if (!itemEl) return;
      const idx = Number(itemEl.dataset.idx);
      const prod = resultados[idx];
      if (!prod?.codigo) return;
      if (!(await _verificarSeparadorSep())) return;

      input.disabled = true;
      resultadosEl.innerHTML = '<div style="padding:10px 12px;color:#93c5fd;font-size:12px;">Aplicando troca...</div>';

      try {
        const r = await fetch('/api/logistica/itens_solicitados/trocar', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          credentials: 'include',
          body: JSON.stringify({
            solic_id: solicId,
            codigo_novo: prod.codigo,
            descricao_novo: prod.descricao || '',
            unidade_novo: prod.unidade || 'UN',
            quantidade_nova: quantidadeAtual
          })
        });
        const d = await r.json();
        if (!d?.ok) throw new Error(d?.error || 'Erro ao trocar produto.');

        houveMudanca = true;
        fechar();
        await reloadItems();
        window._loadSolicitacoesTab.force = true;
        window._loadSolicitacoesTab();
        window._loadKanbanSolicitacoesTab.force = true;
        window._loadKanbanSolicitacoesTab();
      } catch (err) {
        if (!_tratarErroSeparadorPerdido(err)) alert('Erro: ' + (err.message || err));
        input.disabled = false;
        resultadosEl.style.display = 'none';
        resultadosEl.innerHTML = '';
      }
    });

    setTimeout(() => input.focus(), 0);
  }

  // Delegação de clique — ações do item
  modalInner.addEventListener('click', async (e) => {
    const toggleOrigens = e.target.closest('.sep-origem-toggle');
    if (toggleOrigens) {
      const box = toggleOrigens.closest('.sep-loc-box--origin');
      const expanded = toggleOrigens.dataset.expanded === '1';
      box?.querySelectorAll('.sep-origem-extra').forEach(el => {
        el.style.display = expanded ? 'none' : 'flex';
      });
      toggleOrigens.dataset.expanded = expanded ? '0' : '1';
      toggleOrigens.innerHTML = expanded
        ? '<i class="fa-solid fa-eye"></i> Desocultar outros armazéns'
        : '<i class="fa-solid fa-eye-slash"></i> Ocultar outros armazéns';
      return;
    }
    const btnOrigemSep = e.target.closest('.sol-origem-sep-btn');
    if (btnOrigemSep) {
      const row = btnOrigemSep.closest('[data-item-row]');
      if (!row) return;
      const wrap = btnOrigemSep.closest('.sep-loc-box--origin') || btnOrigemSep.closest('.sep-loc-box');
      if (wrap) {
        wrap.querySelectorAll('.sol-origem-sep-btn').forEach(b => {
          const active = b === btnOrigemSep;
          b.dataset.selected = active ? '1' : '0';
          b.style.border = '2px solid ' + (active ? '#16a34a' : '#374151');
          b.style.background = active ? '#14532d' : '#111827';
          b.style.color = active ? '#86efac' : '#9ca3af';
        });
        wrap.querySelectorAll('.sol-origem-sep-etq').forEach(p => {
          p.style.display = 'none';
        });
      }
      const etqPanel = btnOrigemSep.parentElement?.querySelector('.sol-origem-sep-etq');
      if (etqPanel) etqPanel.style.display = 'block';
      const cod = btnOrigemSep.dataset.cod || '';
      row.dataset.origemCod = cod;
      if (cod !== PRINC_ARMZ) {
        row.dataset.etqId = '';
        row.dataset.etqEndereco = '';
        row.dataset.etqQtd = '';
        row.dataset.etqSelecoes = '[]';
        row.dataset.etqAlocacoes = '[]';
        row.querySelectorAll('.sep-etq-endereco-row').forEach(el => {
          el.style.borderColor = '#854d0e33';
          el.style.background = '#1a1508';
          el.dataset.selected = '0';
          const badge = el.querySelector('.sep-etq-tirar');
          if (badge) { badge.textContent = ''; badge.style.display = 'none'; }
        });
      }
      return;
    }

    const btnEtq = e.target.closest('.sep-etq-endereco-row');
    if (btnEtq) {
      const row = btnEtq.closest('[data-item-row]');
      if (!row) return;
      const endereco = String(btnEtq.dataset.etqEndereco || '').trim();
      if (!endereco) return;

      let selecoes = _solLerSelecoesEtq(row);
      const jaNoEndereco = selecoes.filter(s => String(s.endereco || '').trim() === endereco);
      if (jaNoEndereco.length) {
        selecoes = selecoes.filter(s => String(s.endereco || '').trim() !== endereco);
        row.dataset.etqSelecoes = JSON.stringify(selecoes);
        const qty = parseFloat(row.dataset.qtyTotal || '0') || 0;
        _solAplicarVisualAlocacaoEtq(row, qty);
        return;
      }

      // Seleciona o endereço visualmente e abre leitura FIFO (menor ID → maior)
      btnEtq.dataset.selected = '1';
      btnEtq.style.borderColor = '#22c55e';
      btnEtq.style.background = '#1a2e1a';
      await _abrirLeituraFifoDoRow(row);
      return;
    }

    const btnLerFifo = e.target.closest('.btn-ler-etq-fifo');
    if (btnLerFifo) {
      const row = btnLerFifo.closest('[data-item-row]');
      if (!row) return;
      btnLerFifo.disabled = true;
      try {
        await _abrirLeituraFifoDoRow(row);
      } finally {
        btnLerFifo.disabled = false;
      }
      return;
    }

    const btnSemLeitura = e.target.closest('.btn-sem-leitura-etq');
    if (btnSemLeitura) {
      const row = btnSemLeitura.closest('[data-item-row]');
      if (!row) return;
      _aplicarSemLeituraDoRow(row);
      return;
    }

    // Seleção de armazém inline
    const btnArm = e.target.closest('.armazem-btn');
    if (btnArm) {
      const wrap = btnArm.closest('.armazem-sel-wrap');
      if (!wrap) return;
      wrap.querySelectorAll('.armazem-btn').forEach(b => {
        const active = b === btnArm;
        b.dataset.selected = active ? '1' : '0';
        b.style.border = '2px solid ' + (active ? '#16a34a' : '#374151');
        b.style.background = active ? '#14532d' : '#111827';
        b.style.color = active ? '#86efac' : '#9ca3af';
      });
      return;
    }

    const btnConferido = e.target.closest('.btn-item-conferido');
    if (btnConferido && !btnConferido.disabled) {
      const row = btnConferido.closest('[data-item-row]');
      if (!row) return;
      const solicIds = JSON.parse(row.dataset.solicIds || '[]');
      if (!solicIds.length) return;

      // Lê armazém selecionado no DOM (botão com data-selected="1")
      const selBtn = row.querySelector('.armazem-btn[data-selected="1"]');
      const cod_local  = selBtn ? selBtn.dataset.cod  : null;
      const nome_local = selBtn ? selBtn.dataset.nome : null;
      const quantidade = parseFloat(row.dataset.qtyTotal) || 1;

      _solBtnLoading(btnConferido);

      try {
        const r = await fetch('/api/logistica/itens_solicitados/aguardando-retirada', {
          method: 'PATCH',
          headers: { 'Content-Type': 'application/json' },
          credentials: 'include',
          body: JSON.stringify({ solic_ids: solicIds, cod_local, nome_local, quantidade })
        });
        const d = await r.json();
        if (!d.ok) throw new Error(d.error || 'Erro ao marcar como aguardando retirada.');
        houveMudanca = true;
        window._loadSolicitacoesTab.force = true;
        window._loadSolicitacoesTab();
        window._loadKanbanSolicitacoesTab.force = true;
        window._loadKanbanSolicitacoesTab();
        await reloadItems();
      } catch (err) {
        alert('Erro: ' + (err.message || err));
        _solBtnRestore(btnConferido, '<i class="fa-solid fa-clipboard-check" style="margin-right:3px;"></i>Conferido');
      }
      return;
    }

    const btnRetificar = e.target.closest('.btn-item-retificar');
    if (btnRetificar && !btnRetificar.disabled) {
      const row = btnRetificar.closest('[data-item-row]');
      if (!row) return;
      const solicIds = JSON.parse(row.dataset.solicIds || '[]');
      if (!solicIds.length) return;

      _solBtnLoading(btnRetificar);
      const stRow = row.dataset.status || '';
      const urlRet = stRow === 'Aguardando retirada'
        ? '/api/logistica/itens_solicitados/reverter-conferido'
        : '/api/logistica/itens_solicitados/reverter-separacao';
      try {
        const r = await fetch(urlRet, {
          method: 'PATCH',
          headers: { 'Content-Type': 'application/json' },
          credentials: 'include',
          body: JSON.stringify({ solic_ids: solicIds })
        });
        const d = await r.json();
        if (!d.ok) throw new Error(d.error || 'Erro ao retificar item.');
        houveMudanca = true;
        await reloadItems();
        window._loadSolicitacoesTab.force = true;
        window._loadSolicitacoesTab();
        window._loadKanbanSolicitacoesTab.force = true;
        window._loadKanbanSolicitacoesTab();
      } catch (err) {
        alert('Erro: ' + (err.message || err));
        _solBtnRestore(btnRetificar, '<i class="fa-solid fa-rotate-left" style="margin-right:3px;"></i>Retificar');
      }
      return;
    }

    const btnTrocar = e.target.closest('.btn-item-trocar');
    if (btnTrocar && !btnTrocar.disabled) {
      const row = btnTrocar.closest('[data-item-row]');
      if (!row) return;
      if (!(await _verificarSeparadorSep())) return;
      _solBtnLoading(btnTrocar);
      try {
        await _abrirTrocaInline(row);
      } finally {
        _solBtnRestore(btnTrocar);
      }
      return;
    }

    const btnSepTudo = e.target.closest('.btn-item-sep-tudo');
    if (btnSepTudo && !btnSepTudo.disabled) {
      const row = btnSepTudo.closest('[data-item-row]');
      if (!row) return;
      _solBtnLoading(btnSepTudo);
      try {
        await _executarSeparadoItem(row);
      } finally {
        _solBtnRestore(btnSepTudo, '<i class="fa-solid fa-check" style="margin-right:2px;"></i>Separado');
      }
      return;
    }

    const btnSepParcial = e.target.closest('.btn-item-sep-parcial');
    if (btnSepParcial && !btnSepParcial.disabled) {
      const row = btnSepParcial.closest('[data-item-row]');
      if (!row) return;
      if (!(await _verificarSeparadorSep())) return;
      const unidade  = row.dataset.unidade || 'UN';
      const qtyTotal = parseFloat(row.dataset.qtyTotal || '0') || 0;
      const qtyInput = prompt(`Quantidade separada (${unidade}). Pode ser maior que o solicitado quando a embalagem fechada vier com mais unidades:`, _solFmtQty(qtyTotal));
      if (qtyInput === null) return;
      const qtySep = parseFloat(String(qtyInput).replace(',', '.'));
      _solBtnLoading(btnSepParcial, 'Registrando...');
      try {
        await _confirmarSepParcial(row, qtySep);
      } finally {
        _solBtnRestore(btnSepParcial, '<i class="fa-solid fa-scale-balanced" style="margin-right:2px;"></i>Manual');
      }
      return;
    }

    const btnNaoSep = e.target.closest('.btn-item-nao-sep');
    if (btnNaoSep && !btnNaoSep.disabled) {
      const row = btnNaoSep.closest('[data-item-row]');
      if (!row) return;
      if (!(await _verificarSeparadorSep())) return;
      const solicIds = JSON.parse(row.dataset.solicIds || '[]');
      const ok = confirm('Confirmar que este item não foi separado?');
      if (!ok) return;
      _solBtnLoading(btnNaoSep, 'Processando...');
      try {
        for (const sid of solicIds) {
          const r = await fetch('/api/logistica/itens_solicitados/nao-separar', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            credentials: 'include',
            body: JSON.stringify({ solic_id: sid })
          });
          const d = await r.json();
          if (!d.ok) throw new Error(d.error || 'Erro ao marcar item como não separado.');
        }
        houveMudanca = true;
        await reloadItems();
        window._loadSolicitacoesTab.force = true;
        window._loadSolicitacoesTab();
        window._loadKanbanSolicitacoesTab.force = true;
        window._loadKanbanSolicitacoesTab();
      } catch (err) {
        if (!_tratarErroSeparadorPerdido(err)) alert('Erro: ' + (err.message || err));
        _solBtnRestore(btnNaoSep, '<i class="fa-solid fa-xmark" style="margin-right:2px;"></i>Não separei');
      }
      return;
    }

    const btnUrgente = e.target.closest('.btn-item-urgente');
    if (btnUrgente && !btnUrgente.disabled) {
      const row = btnUrgente.closest('[data-item-row]');
      if (!row) return;
      const solicIds = JSON.parse(row.dataset.solicIds || '[]');
      if (!solicIds.length) return;
      const novoUrgente = row.dataset.urgente !== '1';
      btnUrgente.disabled = true;
      try {
        const r = await fetch('/api/logistica/itens_solicitados/urgente', {
          method: 'PATCH',
          headers: { 'Content-Type': 'application/json' },
          credentials: 'include',
          body: JSON.stringify({ solic_ids: solicIds, urgente: novoUrgente })
        });
        const d = await r.json();
        if (!d.ok) throw new Error(d.error || 'Erro ao atualizar urgência.');
        row.dataset.urgente = novoUrgente ? '1' : '0';
        row.style.borderLeft = novoUrgente ? '3px solid #ef4444' : '';
        btnUrgente.style.border = `1px solid ${novoUrgente ? '#ef4444' : '#374151'}`;
        btnUrgente.style.background = novoUrgente ? '#450a0a' : 'transparent';
        btnUrgente.style.color = novoUrgente ? '#fca5a5' : '#6b7280';
        btnUrgente.innerHTML = `<i class="fa-solid fa-bolt" style="font-size:.63rem;"></i>${novoUrgente ? 'Urgente' : ''}`;
      } catch (err) {
        alert('Erro: ' + (err.message || err));
      } finally {
        btnUrgente.disabled = false;
      }
      return;
    }

    // Botão "Iniciar separação" dos grupos conflitantes
    const conflBtn = e.target.closest('.btn-modal-sep-conflito');
    if (conflBtn && !conflBtn.disabled) {
      const ids      = JSON.parse(conflBtn.dataset.solicIds || '[]');
      const nomeUser = conflBtn.dataset.nomeUser || '';
      if (!ids.length) return;
      _solBtnLoading(conflBtn);
      try {
        const r = await fetch('/api/logistica/itens_solicitados/separacao', {
          method: 'PATCH',
          headers: { 'Content-Type': 'application/json' },
          credentials: 'include',
          body: JSON.stringify({ solic_ids: ids })
        });
        const res = await r.json();
        if (res.ok) {
          conflBtn.closest('.modal-sep-conflito')?.remove();
          const mainCard = document.querySelector(`[data-user-card="${CSS.escape(nomeUser)}"]`);
          mainCard?.remove();
          if (window._solicitacoesGruposData) delete window._solicitacoesGruposData[nomeUser];
          await window._updateTabCounters?.();
        } else {
          alert('Erro: ' + res.error);
          _solBtnRestore(conflBtn, '<i class="fa-solid fa-boxes-stacked" style="margin-right:3px;"></i>Iniciar separação');
        }
      } catch (err) {
        alert('Erro ao iniciar separação.');
        _solBtnRestore(conflBtn, '<i class="fa-solid fa-boxes-stacked" style="margin-right:3px;"></i>Iniciar separação');
      }
    }
  });
}

// ============================================================================
// KANBAN DE SOLICITAÇÕES
// ============================================================================
window._loadKanbanSolicitacoesTab = async function() {
  const board    = document.getElementById('kanbanSolicBoard');
  const statusEl = document.getElementById('kanbanSolicStatus');
  if (!board) return;

  const isMobileBoard = window.matchMedia('(max-width: 640px), (max-width: 900px) and (max-height: 500px)').matches;
  board.style.display = 'grid';
  board.style.gridTemplateColumns = isMobileBoard ? '1fr' : 'repeat(6, minmax(0, 1fr))';
  board.style.gap = '12px';
  board.style.overflowX = isMobileBoard ? 'hidden' : 'visible';

  if (board.dataset.loaded === '1' && !window._loadKanbanSolicitacoesTab.force) return;
  window._loadKanbanSolicitacoesTab.force = false;

  board.innerHTML = '<p style="color:#9ca3af;padding:16px;font-size:.85rem;">Carregando...</p>';
  if (statusEl) statusEl.textContent = '';

  const COLS = [
    { key: 'pendente',              label: 'Solicitado',            icon: 'fa-clock',          color: '#3b82f6', bg: '#0f1929', bgLight: '#eff6ff', editable: true  },
    { key: 'Stund-by',             label: 'Stund-by',             icon: 'fa-bag-shopping',   color: '#ec4899', bg: '#1f0d1a', bgLight: '#fdf2f8', editable: false },
    { key: 'Separação',             label: 'Em Separação',          icon: 'fa-boxes-stacked',  color: '#f59e0b', bg: '#1c1500', bgLight: '#fffbeb', editable: false },
    { key: 'Separado',              label: 'Separado',              icon: 'fa-check-circle',   color: '#22c55e', bg: '#0a1f0f', bgLight: '#f0fdf4', editable: false },
    { key: 'Aguardando retirada',   label: 'Aguardando retirada',   icon: 'fa-hourglass-half', color: '#a78bfa', bg: '#140d2a', bgLight: '#f5f3ff', editable: false, acao: 'recebido' },
    { key: 'Concluído',             label: 'Concluído',             icon: 'fa-flag-checkered', color: '#9ca3af', bg: '#111',    bgLight: '#f9fafb', editable: false, acao: 'visualizar' },
  ];
  const editableCols = new Set(['pendente']);

  try {
    const resp = await fetch('/api/logistica/kanban', { credentials: 'include' });
    if (!resp.ok) throw new Error(`HTTP ${resp.status}`);
    const data = await resp.json();
    const colunas = data.colunas || {};
    const isLight = document.documentElement.classList.contains('light-mode');

    board.innerHTML = '';
    let totalCards = 0;

    COLS.forEach(col => {
      const cards = colunas[col.key] || [];
      totalCards += cards.length;

      const colEl = document.createElement('div');
      colEl.style.cssText = isMobileBoard
        ? 'width:100%;min-width:0;display:flex;flex-direction:column;'
        : 'flex:0 0 200px;display:flex;flex-direction:column;';

      const colBg = isLight ? '#ffffff' : '#141a27';
      const colBorder = isLight ? '#e2e8f0' : '#1e293b';
      const headerBg = isLight ? col.bgLight : col.bg;
      const cardBg = isLight ? '#f9fafb' : '#1e293b';
      const cardBorder = isLight ? '#e2e8f0' : '#334155';
      const cardHoverBorder = isLight ? col.color + '88' : col.color + '66';
      const cardHoverLeave = isLight ? '#e2e8f0' : '#334155';
      const sepColor = isLight ? '#b45309' : '#f59e0b';
      const userColor = isLight ? '#374151' : '#d1d5db';
      const dateColor = isLight ? '#6b7280' : '#9ca3af';
      const iconColor = isLight ? '#9ca3af' : '#6b7280';
      const emptyColor = isLight ? '#9ca3af' : '#4b5563';
      const hintColor = isLight ? '#9ca3af' : '#4b5563';
      const noCarrinhoColor = isLight ? '#6b7280' : '#6b7280';

      const cardsHtml = cards.length === 0
        ? `<div style="padding:14px;text-align:center;color:${emptyColor};font-size:.73rem;">Nenhum</div>`
        : cards.map(card => {
            const dataPrev = _solFmtDataPrevista(card.data_prevista);
            const criadoEm = _solFmtDataHora(card.criado_em_min);
            const sepLabel = card.n_solic
              ? `<span style="font-weight:800;font-size:.85rem;color:${sepColor};letter-spacing:.03em;">${card.n_solic}</span>`
              : `<span style="font-weight:700;font-size:.78rem;color:${noCarrinhoColor};font-style:italic;">No carrinho</span>`;
            const isClickable = col.editable || col.acao === 'recebido' || col.acao === 'visualizar';
            const cursor = isClickable ? 'cursor:pointer;' : 'cursor:default;';
            const editHint = col.editable
              ? `<span style="font-size:.65rem;color:${hintColor};margin-top:3px;display:block;">clique para editar</span>`
              : (col.acao === 'recebido'
                ? `<span style="font-size:.65rem;color:${hintColor};margin-top:3px;display:block;">clique para receber</span>`
                : (col.acao === 'visualizar'
                  ? `<span style="font-size:.65rem;color:${hintColor};margin-top:3px;display:block;">clique para ver itens</span>`
                  : ''));
            const emCompraHtml = (col.key === 'Stund-by' && card.tem_em_compra)
              ? `<div style="margin-top:4px;display:inline-flex;align-items:center;gap:4px;padding:2px 7px;border-radius:20px;font-size:.65rem;font-weight:700;color:${isLight ? '#1e40af' : '#93c5fd'};background:${isLight ? '#dbeafe' : '#1e3a5f'};border:1px solid #3b82f6;" title="Há produto desta SEP com compra em andamento">
                  <i class="fa-solid fa-cart-shopping" style="font-size:.62rem;"></i>Em compra
                </div>`
              : '';
            return `
              <div class="kanban-sep-card"
                data-n-solic="${card.n_solic || ''}"
                data-col="${col.key}"
                style="background:${cardBg};border:1px solid ${cardBorder};border-radius:9px;padding:10px 12px;${cursor}transition:border-color .15s;"
                onmouseenter="this.style.borderColor='${cardHoverBorder}'"
                onmouseleave="this.style.borderColor='${cardHoverLeave}'">
                <div style="display:flex;align-items:center;gap:6px;flex-wrap:wrap;">
                  ${sepLabel}
                  ${emCompraHtml}
                </div>
                <div style="margin-top:5px;display:flex;align-items:center;gap:5px;">
                  <i class="fa-solid fa-user-circle" style="color:${iconColor};font-size:.75rem;flex-shrink:0;"></i>
                  <span style="font-size:.75rem;color:${userColor};white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${card.nome_user}</span>
                </div>
                ${dataPrev ? `
                <div style="margin-top:4px;display:flex;align-items:center;gap:5px;">
                  <i class="fa-regular fa-calendar" style="color:${iconColor};font-size:.72rem;flex-shrink:0;"></i>
                  <span style="font-size:.72rem;color:${dateColor};">${dataPrev}</span>
                </div>` : ''}
                ${criadoEm ? `
                <div style="margin-top:4px;display:flex;align-items:center;gap:5px;">
                  <i class="fa-regular fa-clock" style="color:${iconColor};font-size:.72rem;flex-shrink:0;"></i>
                  <span style="font-size:.70rem;color:${dateColor};">Solicitado em ${criadoEm}</span>
                </div>` : ''}
                ${editHint}
              </div>`;
          }).join('');

      colEl.innerHTML = `
        <div style="border-radius:10px;overflow:hidden;background:${colBg};border:1px solid ${colBorder};height:100%;">
          <div style="display:flex;align-items:center;gap:7px;padding:10px 12px;background:${headerBg};border-bottom:2px solid ${col.color}33;">
            <i class="fa-solid ${col.icon}" style="color:${col.color};font-size:.88rem;"></i>
            <span style="font-weight:700;font-size:.80rem;color:${col.color};">${col.label}</span>
            <span style="margin-left:auto;font-size:.72rem;font-weight:700;color:${col.color};background:${col.color}22;padding:1px 7px;border-radius:20px;">${cards.length}</span>
          </div>
          <div style="display:flex;flex-direction:column;gap:7px;padding:8px;min-height:60px;max-height:calc(100vh - 300px);overflow-y:auto;">
            ${cardsHtml}
          </div>
        </div>`;

      board.appendChild(colEl);
    });

    if (statusEl) {
      const agora = new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });
      statusEl.textContent = `Atualizado às ${agora} · ${totalCards} SEP(s)`;
    }
    board.dataset.loaded = '1';

    // Tooltip hover — variáveis globais para evitar persistência ao trocar de aba
    board.querySelectorAll('.kanban-sep-card').forEach(cardEl => {
      cardEl.addEventListener('mouseenter', async () => {
        // Não abre tooltip se modal de edição estiver aberto
        if (document.getElementById('modalEdicaoSep')) return;
        clearTimeout(window._kanbanTooltipTimer);
        window._kanbanTooltipTimer = setTimeout(async () => {
          // Verifica novamente antes de exibir
          if (document.getElementById('modalEdicaoSep')) return;
          const nSolic = cardEl.dataset.nSolic || '';
          const url = nSolic
            ? `/api/logistica/kanban/itens?n_solic=${encodeURIComponent(nSolic)}`
            : '/api/logistica/kanban/itens';
          try {
            const r = await fetch(url, { credentials: 'include' });
            const d = await r.json();
            if (!d.ok || !d.itens?.length) return;
            if (document.getElementById('modalEdicaoSep')) return;

            window._kanbanTooltipEl?.remove();
            window._kanbanTooltipEl = document.createElement('div');
            window._kanbanTooltipEl.style.cssText = 'position:fixed;z-index:99999;background:#1c1c1c;border:1px solid #3a3a3a;border-radius:10px;padding:10px 14px;min-width:220px;max-width:300px;box-shadow:0 8px 32px rgba(0,0,0,.6);pointer-events:none;';
            window._kanbanTooltipEl.innerHTML = d.itens.map(it => `
              <div style="display:flex;gap:8px;align-items:flex-start;padding:5px 0;border-bottom:1px solid #222;">
                <div style="flex:1;min-width:0;">
                  <div style="font-weight:700;font-size:.75rem;color:#f59e0b;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${it.codigo_produto}</div>
                  <div style="font-size:.72rem;color:#d1d5db;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${it.descricao || '—'}</div>
                </div>
                <div style="flex-shrink:0;font-size:.73rem;font-weight:700;color:#f0f0f0;">${_solFmtQty(it.quantidade)} ${it.unidade || 'UN'}</div>
              </div>`).join('');
            document.body.appendChild(window._kanbanTooltipEl);

            const rect = cardEl.getBoundingClientRect();
            const top  = Math.min(rect.top, window.innerHeight - window._kanbanTooltipEl.offsetHeight - 10);
            const left = rect.right + 8 + window._kanbanTooltipEl.offsetWidth > window.innerWidth
              ? rect.left - window._kanbanTooltipEl.offsetWidth - 8
              : rect.right + 8;
            window._kanbanTooltipEl.style.top  = `${top}px`;
            window._kanbanTooltipEl.style.left = `${left}px`;
          } catch (_) {}
        }, 350);
      });
      cardEl.addEventListener('mouseleave', () => {
        clearTimeout(window._kanbanTooltipTimer);
        window._kanbanTooltipEl?.remove();
        window._kanbanTooltipEl = null;
      });

      // Clique — abre modal de edição (só em colunas editáveis)
      if (editableCols.has(cardEl.dataset.col)) {
        cardEl.addEventListener('click', () => { _abrirModalEdicaoSep(cardEl.dataset.nSolic || null); });
      }

      // Clique — coluna "Aguardando retirada" abre modal com ação "Recebido"
      if (cardEl.dataset.col === 'Aguardando retirada') {
        cardEl.addEventListener('click', () => {
          _abrirModalAguardandoRetiradaSep(cardEl.dataset.nSolic || null, {
            tituloColuna: 'Aguardando retirada',
            permitirRecebido: true
          });
        });
      }

      // Clique — coluna "Concluído" abre modal de visualização com o mesmo detalhamento
      if (cardEl.dataset.col === 'Concluído') {
        cardEl.addEventListener('click', () => {
          _abrirModalAguardandoRetiradaSep(cardEl.dataset.nSolic || null, {
            tituloColuna: 'Concluído',
            permitirRecebido: false
          });
        });
      }

      // Clique — coluna Stund-by abre modal de itens (mesmo da Tela de separação)
      if (cardEl.dataset.col === 'Stund-by') {
        cardEl.style.cursor = 'pointer';
        cardEl.addEventListener('click', async () => {
          if (cardEl._loading) return;
          const nSolic = cardEl.dataset.nSolic;
          if (!nSolic) return;
          cardEl._loading = true;
          _solKanbanLoading(true, 'Carregando itens...');
          clearTimeout(window._kanbanTooltipTimer);
          window._kanbanTooltipEl?.remove();
          window._kanbanTooltipEl = null;
          try {
            const ri = await fetch(_solBuildKanbanItensUrl(nSolic, { escopoItens: 'global' }), { credentials: 'include' });
            const di = await ri.json();
            if (!di.ok) throw new Error(di.error || 'Erro ao buscar itens');
            const itens = (di.itens || []).map(it => ({ ...it, solic_ids: [it.solic_id], carr_ids: [it.carr_id] }));
            if (!itens.length) throw new Error('Nenhum item encontrado');

            const codigos = [...new Set(itens.map(it => it.codigo_produto).filter(Boolean))];
            let preloaded = {};
            if (codigos.length) {
              try {
                const [re, endMap, rid] = await Promise.all([
                  fetch('/api/logistica/estoque/batch?codigos=' + encodeURIComponent(codigos.join(',')), { credentials: 'include' }),
                  _solCarregarEnderecoBatch(codigos),
                  fetch('/api/etiquetas/rec-impresso/ids-fifo-batch?codigos=' + encodeURIComponent(codigos.join(',')), { credentials: 'include' })
                ]);
                const de = await re.json();
                const did = await rid.json().catch(() => ({}));
                preloaded = {
                  estoqueBatch: de.ok ? (de.dados || {}) : {},
                  enderecoBatch: _solMergeEnderecoBatch(itens, endMap || {}),
                  etqIdsBatch: did.ok ? (did.dados || {}) : {}
                };
              } catch (_) {}
            }

            const grupoAtual = {
              nome_user: itens[0]?.nome_user || nSolic,
              n_solic: nSolic,
              itens,
              origem_status: 'Stund-by',
              escopoItens: 'global'
            };
            void _abrirModalSeparacao(grupoAtual, [], preloaded)
              .catch(err => console.warn('[KANBAN-SOLIC] abrir modal Stand-by:', err));
          } catch (err) {
            alert('Erro: ' + (err.message || err));
          } finally {
            cardEl._loading = false;
            _solKanbanLoading(false);
          }
        });
      }
    });
  } catch (err) {
    console.warn('[KANBAN-SOLIC] Erro:', err.message);
    board.innerHTML = '<p style="color:#ef4444;padding:16px;font-size:.85rem;">Erro ao carregar kanban</p>';
    if (statusEl) statusEl.textContent = 'Erro ao carregar';
  }
};

async function _abrirModalAguardandoRetiradaSep(nSolic, opts = {}) {
  if (!nSolic) return;

  const tituloColuna = String(opts.tituloColuna || 'Aguardando retirada');
  const permitirRecebido = !!opts.permitirRecebido;
  const somenteLeitura = !!opts.somenteLeitura || tituloColuna === 'Concluído';
  const escopoItens = String(opts.escopoItens || '');

  clearTimeout(window._kanbanTooltipTimer);
  window._kanbanTooltipEl?.remove();
  window._kanbanTooltipEl = null;

  let itens = [];
  let itensDerivados = [];
  let estoqueBatch = {};
  let enderecoBatch = {};
  // Solicitado: nunca usar cache — itens podem ser adicionados enquanto o modal fica aberto.
  const isSolicitadoEarly = tituloColuna === 'Solicitado';
  const cacheHit = isSolicitadoEarly ? null : _solGetAguardRetCache(nSolic, tituloColuna, escopoItens);
  if (cacheHit) {
    itens = Array.isArray(cacheHit.itens) ? cacheHit.itens : [];
    itensDerivados = Array.isArray(cacheHit.itensDerivados) ? cacheHit.itensDerivados : [];
    estoqueBatch = cacheHit.estoqueBatch || {};
    enderecoBatch = cacheHit.enderecoBatch || {};
  } else {
    _solKanbanLoading(true, 'Carregando solicitação...');
    try {
      const r = await fetch(_solBuildKanbanItensUrl(nSolic, { includeDerivados: true, escopoItens }), { credentials: 'include' });
      const d = await r.json();
      if (!d.ok) {
        alert('Erro ao carregar itens: ' + (d.error || ''));
        return;
      }
      itens = Array.isArray(d.itens) ? d.itens : [];
      itensDerivados = Array.isArray(d.itens_derivados) ? d.itens_derivados : [];

      const codigos = [...new Set([
        ...itens.map(it => it.codigo_produto),
        ...itensDerivados.map(it => it.codigo_produto)
      ].filter(Boolean))];
      if (codigos.length) {
        try {
          const [re, rep] = await Promise.all([
            fetch('/api/logistica/estoque/batch?codigos=' + encodeURIComponent(codigos.join(',')), { credentials: 'include' }),
            fetch('/api/logistica/endereco-pp/batch?codigos=' + encodeURIComponent(codigos.join(',')), { credentials: 'include' })
          ]);
          const de = await re.json();
          const dep = await rep.json();
          if (de.ok) estoqueBatch = de.dados || {};
          if (dep.ok) enderecoBatch = dep.dados || {};
          enderecoBatch = _solMergeEnderecoBatch([...itens, ...itensDerivados], enderecoBatch);
        } catch (_) { /* silencia */ }
      } else {
        enderecoBatch = _solMergeEnderecoBatch([...itens, ...itensDerivados], enderecoBatch);
      }
      _solSetAguardRetCache(nSolic, tituloColuna, escopoItens, {
        itens,
        itensDerivados,
        estoqueBatch,
        enderecoBatch
      });
    } catch (err) {
      alert('Erro de rede ao carregar a solicitação.');
      return;
    } finally {
      _solKanbanLoading(false);
    }
  }

  if (!itens.length) {
    alert('Nenhum item encontrado para esta solicitação.');
    return;
  }

  document.getElementById('modalAguardandoRetiradaSep')?.remove();

  const currentUserId = String(window.__sessionUser?.id || '');
  const isAutor = itens.length > 0 && String(itens[0]?.id_user || '') === currentUserId;
  const isSolicitado = tituloColuna === 'Solicitado';

  const renderLinha = (it) => {
    const destinoCard = _solDestinoHtml(it);
    const enderecamentoCard = _solEnderecamentoHtml(it.codigo_produto, enderecoBatch, it);

    // Armazéns — local_codigo 10717096386 sempre primeiro
    const PRINCIPAL = '10717096386';
    let locais = (estoqueBatch[it.codigo_produto] || []).slice();
    locais.sort((a, b) => {
      if (String(a.local_codigo) === PRINCIPAL) return -1;
      if (String(b.local_codigo) === PRINCIPAL) return  1;
      return 0;
    });
    let origemColuna = _solRenderOrigemResumoGlobal(
      estoqueBatch[it.codigo_produto] || [],
      Object.keys(estoqueBatch).length ? 'Sem origem com saldo' : 'Carregando origem...'
    );
    if (false && locais.length) {
      origemColuna = locais.map(l =>
        `<div style="display:flex;flex-direction:column;line-height:1.3;padding:2px 0;">
          <span style="font-size:.63rem;color:#86efac;">${l.local_nome || l.local_codigo}</span>
          <span style="font-size:.68rem;color:#f0f0f0;font-weight:700;">${Number(l.saldo).toLocaleString('pt-BR',{minimumFractionDigits:0,maximumFractionDigits:2})} ${l.unidade||'UN'}</span>
        </div>`
      ).join('');
    } else if (false) {
      origemColuna = `<span style="font-size:.63rem;color:#6b7280;font-style:italic;">Sem origem com saldo</span>`;
    }

    const isUrg = !!it.urgente;
    return `
    <div class="sep-request-row" data-solic-id="${it.solic_id || ''}" style="display:flex;align-items:flex-start;gap:10px;padding:10px 12px;border-top:1px solid #222;${isUrg ? 'border-left:3px solid #ef4444;' : ''}">
      <div class="sep-thumb" style="width:40px;height:40px;border-radius:8px;background:#0f0f0f;overflow:hidden;flex-shrink:0;cursor:zoom-in;">
        ${_solGetMiniImgHtml(it.codigo_produto, it.descricao || '')}
      </div>
      <div class="sep-request-main" style="flex:1;min-width:0;">
        <div style="display:flex;align-items:center;gap:6px;flex-wrap:wrap;">
          <span style="font-weight:700;font-size:.78rem;color:#f59e0b;">${it.codigo_produto || '—'}</span>
          ${somenteLeitura
            ? (isUrg ? `<span style="display:inline-flex;align-items:center;gap:3px;padding:2px 7px;border-radius:20px;font-size:.67rem;font-weight:700;border:1px solid #ef4444;background:#450a0a;color:#fca5a5;"><i class="fa-solid fa-bolt" style="font-size:.63rem;"></i>Urgente</span>` : '')
            : `<button class="btn-urg-solic" data-solic-id="${it.solic_id || ''}" data-urgente="${isUrg ? '1' : '0'}"
            title="Urgente, entregar o quanto antes este item"
            style="display:inline-flex;align-items:center;gap:3px;padding:2px 7px;border-radius:20px;font-size:.67rem;font-weight:700;cursor:pointer;border:1px solid ${isUrg ? '#ef4444' : '#374151'};background:${isUrg ? '#450a0a' : 'transparent'};color:${isUrg ? '#fca5a5' : '#6b7280'};">
            <i class="fa-solid fa-bolt" style="font-size:.63rem;"></i>${isUrg ? 'Urgente' : ''}
          </button>`}
        </div>
        <div style="font-size:.75rem;color:#d1d5db;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${it.descricao || '—'}</div>
        <div style="margin-top:6px;display:flex;flex-direction:column;gap:6px;">
          ${enderecamentoCard}
          <div class="sep-destino-inline">
            <span>Destino</span>
            ${destinoCard}
          </div>
          <div>
            <div style="min-width:0;padding:6px 8px;background:#101826;border:1px solid #253041;border-radius:8px;">
              <div style="font-size:.60rem;color:#60a5fa;font-weight:700;text-transform:uppercase;letter-spacing:.04em;margin-bottom:4px;">Origem</div>
              <div style="display:flex;flex-direction:column;gap:3px;min-width:130px;">
                ${origemColuna}
              </div>
            </div>
          </div>
        </div>
      </div>
      <div style="font-size:.74rem;font-weight:700;color:#f0f0f0;white-space:nowrap;">${_solFmtQty(it.quantidade)} ${it.unidade || 'UN'}</div>
      <div style="font-size:.70rem;color:#9ca3af;white-space:nowrap;">${it.status || '—'}</div>
      ${isSolicitado && isAutor
        ? `<button class="btn-del-item-sep" data-solic-id="${it.solic_id || ''}" title="Remover este item da solicitação"
             style="padding:5px 8px;border:none;border-radius:7px;background:#2a1b1b;color:#f87171;cursor:pointer;flex-shrink:0;">
             <i class="fa-solid fa-trash-can" style="font-size:.75rem;"></i>
           </button>`
        : ''}
    </div>`;
  };

  const renderLinhaDerivado = (it) => {
    const enderecamentoDeriv = _solEnderecamentoHtml(it.codigo_produto, enderecoBatch, it);
    return `
    <div style="display:flex;align-items:flex-start;gap:10px;padding:9px 12px;border-top:1px solid #1f2937;">
      <div style="flex:1;min-width:0;">
        <div style="font-weight:700;font-size:.74rem;color:#a78bfa;">${it.n_solic || 'SEP.x'} · ${it.codigo_produto || '—'}</div>
        <div style="font-size:.72rem;color:#cbd5e1;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${it.descricao || '—'}</div>
        ${(String(it.status || '') === 'Stund-by' && String(it.motivo || it.observacao || '').trim())
          ? `<div style="font-size:.70rem;color:#fbbf24;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">Motivo: ${it.motivo || it.observacao}</div>`
          : ''}
        ${enderecamentoDeriv ? `<div style="margin-top:4px;">${enderecamentoDeriv}</div>` : ''}
      </div>
      <div style="font-size:.72rem;color:#e5e7eb;white-space:nowrap;">${_solFmtQty(it.quantidade)} ${it.unidade || 'UN'}</div>
      <div style="font-size:.70rem;color:#9ca3af;white-space:nowrap;">${it.status || '—'}</div>
    </div>`;
  };

  const modal = document.createElement('div');
  modal.id = 'modalAguardandoRetiradaSep';
  modal.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,.65);z-index:10070;display:flex;align-items:center;justify-content:center;';
  modal.innerHTML = `
    <div style="background:#1c1c1c;border:1px solid #2a2a2a;border-radius:16px;width:min(720px,96vw);max-height:90vh;display:flex;flex-direction:column;overflow:hidden;box-shadow:0 20px 60px rgba(0,0,0,.6);">
      <div style="display:flex;align-items:center;gap:10px;padding:16px 20px;border-bottom:1px solid #2a2a2a;background:#171717;flex-shrink:0;">
        <i class="fa-solid fa-hourglass-half" style="color:#a78bfa;font-size:1.05rem;"></i>
        <span style="font-weight:700;font-size:1rem;color:#f0f0f0;">${tituloColuna} — ${nSolic}</span>
        <button id="btnModalAguardRetFechar" style="margin-left:auto;background:none;border:none;color:#9ca3af;font-size:1.3rem;cursor:pointer;padding:2px 6px;line-height:1;">&#x2715;</button>
      </div>

      <div style="overflow-y:auto;flex:1;">
        <div style="font-size:.75rem;color:#6b7280;font-weight:700;padding:12px 12px 4px;letter-spacing:.05em;text-transform:uppercase;">Itens desta solicitação</div>
        <div id="modalAguardRetItensLista">${itens.map(renderLinha).join('')}</div>

        <div style="margin-top:10px;font-size:.75rem;color:#6b7280;font-weight:700;padding:10px 12px 4px;letter-spacing:.05em;text-transform:uppercase;border-top:1px solid #2a2a2a;">Itens que saíram desta solicitação (SEP.x)</div>
        <div id="modalAguardRetDerivLista" style="padding-bottom:6px;">
          ${itensDerivados.length
            ? itensDerivados.map(renderLinhaDerivado).join('')
            : '<div style="padding:10px 12px;color:#9ca3af;font-size:.74rem;">Nenhum item derivado encontrado.</div>'}
        </div>
      </div>

      <div style="padding:12px 16px;border-top:1px solid #2a2a2a;display:flex;justify-content:space-between;align-items:center;gap:8px;background:#171717;flex-wrap:wrap;">
        <div>
          ${isSolicitado && isAutor
            ? `<button id="btnDelSepInteira" style="padding:7px 12px;border:1px solid #7f1d1d;border-radius:8px;background:transparent;color:#f87171;font-weight:700;font-size:.82rem;cursor:pointer;">
                 <i class="fa-solid fa-trash-can" style="margin-right:4px;"></i>Excluir SEP
               </button>`
            : ''}
        </div>
        <div style="display:flex;gap:8px;">
          ${tituloColuna === 'Solicitado'
            ? `<button id="btnAguardRetIniciarSep" style="padding:7px 14px;border:none;border-radius:8px;background:#1d4ed8;color:#dbeafe;font-weight:700;font-size:.82rem;cursor:pointer;"><i class="fa-solid fa-play" style="margin-right:4px;"></i>Iniciar separação</button>`
            : `<button id="btnAguardRetCancelar" style="padding:7px 14px;border:1px solid #4b5563;border-radius:8px;background:transparent;color:#d1d5db;font-weight:700;font-size:.82rem;cursor:pointer;">Fechar</button>`}
          ${permitirRecebido
            ? `<button id="btnAguardRetRecebido" style="padding:7px 14px;border:none;border-radius:8px;background:#16a34a;color:#dcfce7;font-weight:700;font-size:.82rem;cursor:pointer;">
                 <i class="fa-solid fa-box-open" style="margin-right:4px;"></i>Recebido
               </button>`
            : ''}
        </div>
      </div>
    </div>`;

  document.body.appendChild(modal);

  /** Busca a lista atual da SEP no servidor (usada ao Iniciar separação). */
  async function _recarregarItensAguardRetAntesIniciar() {
    const r = await fetch(_solBuildKanbanItensUrl(nSolic, { includeDerivados: true, escopoItens }), { credentials: 'include' });
    const d = await r.json();
    if (!d.ok) throw new Error(d.error || 'Erro ao atualizar itens da SEP.');
    const idsAntes = new Set(itens.map(it => String(it.solic_id)));
    itens = Array.isArray(d.itens) ? d.itens : [];
    itensDerivados = Array.isArray(d.itens_derivados) ? d.itens_derivados : [];
    const qtdNovos = itens.filter(it => !idsAntes.has(String(it.solic_id))).length;

    const listaEl = document.getElementById('modalAguardRetItensLista');
    if (listaEl) listaEl.innerHTML = itens.map(renderLinha).join('');
    const derivEl = document.getElementById('modalAguardRetDerivLista');
    if (derivEl) {
      derivEl.innerHTML = itensDerivados.length
        ? itensDerivados.map(renderLinhaDerivado).join('')
        : '<div style="padding:10px 12px;color:#9ca3af;font-size:.74rem;">Nenhum item derivado encontrado.</div>';
    }
    _solInvalidateAguardRetCache(nSolic, tituloColuna, escopoItens);
    return { novos: qtdNovos, total: itens.length };
  }

  const closeModal = () => modal.remove();
  document.getElementById('btnModalAguardRetFechar')?.addEventListener('click', closeModal);
  document.getElementById('btnAguardRetCancelar')?.addEventListener('click', closeModal);
  modal.addEventListener('click', (ev) => { if (ev.target === modal) closeModal(); });

  // Delegação: ⚡ urgente e 🗑 excluir item
  modal.addEventListener('click', async (ev) => {
    // Botão urgente por item
    const btnUrg = ev.target.closest('.btn-urg-solic');
    if (btnUrg && !btnUrg.disabled) {
      const solicId = parseInt(btnUrg.dataset.solicId, 10);
      if (!solicId) return;
      const novoUrgente = btnUrg.dataset.urgente !== '1';
      btnUrg.disabled = true;
      try {
        const r = await fetch('/api/logistica/itens_solicitados/urgente', {
          method: 'PATCH', headers: { 'Content-Type': 'application/json' },
          credentials: 'include',
          body: JSON.stringify({ solic_ids: [solicId], urgente: novoUrgente })
        });
        const d = await r.json();
        if (!d.ok) throw new Error(d.error || 'Erro.');
        btnUrg.dataset.urgente = novoUrgente ? '1' : '0';
        btnUrg.style.border = `1px solid ${novoUrgente ? '#ef4444' : '#374151'}`;
        btnUrg.style.background = novoUrgente ? '#450a0a' : 'transparent';
        btnUrg.style.color = novoUrgente ? '#fca5a5' : '#6b7280';
        btnUrg.innerHTML = `<i class="fa-solid fa-bolt" style="font-size:.63rem;"></i>${novoUrgente ? 'Urgente' : ''}`;
        const row = btnUrg.closest('[data-solic-id]');
        if (row) row.style.borderLeft = novoUrgente ? '3px solid #ef4444' : '';
      } catch (e) {
        alert('Erro: ' + e.message);
      } finally {
        btnUrg.disabled = false;
      }
      return;
    }

    // Botão excluir item
    const btnDel = ev.target.closest('.btn-del-item-sep');
    if (btnDel && !btnDel.disabled) {
      const solicId = parseInt(btnDel.dataset.solicId, 10);
      if (!solicId) return;
      if (!confirm('Remover este item da solicitação? O item voltará para o seu carrinho.')) return;
      btnDel.disabled = true;
      try {
        const r = await fetch(`/api/logistica/itens_solicitados/${solicId}/sep`, {
          method: 'DELETE', credentials: 'include'
        });
        const d = await r.json();
        if (!d.ok) throw new Error(d.error || 'Erro ao remover item.');
        _solInvalidateAguardRetCache(nSolic, tituloColuna, escopoItens);
        _solInvalidateSepModalCache(nSolic, escopoItens);
        btnDel.closest('[data-solic-id]')?.remove();
        // Se não sobrou nenhum item, fecha o modal
        const restantes = modal.querySelectorAll('[data-solic-id]').length;
        if (restantes === 0) {
          closeModal();
          window._loadSolicitacoesTab && (window._loadSolicitacoesTab.force = true, window._loadSolicitacoesTab());
          window._loadKanbanSolicitacoesTab && (window._loadKanbanSolicitacoesTab.force = true, window._loadKanbanSolicitacoesTab());
        }
      } catch (e) {
        alert('Erro: ' + e.message);
        btnDel.disabled = false;
      }
      return;
    }
  });

  // Excluir SEP inteira
  document.getElementById('btnDelSepInteira')?.addEventListener('click', async () => {
    if (!confirm(`Excluir a SEP ${nSolic} inteira? Todos os itens voltarão para o carrinho.`)) return;
    const btn = document.getElementById('btnDelSepInteira');
    btn.disabled = true;
    btn.innerHTML = '<i class="fa-solid fa-spinner fa-spin" style="margin-right:4px;"></i>Excluindo...';
    try {
      const r = await fetch(`/api/logistica/sep/${encodeURIComponent(nSolic)}`, {
        method: 'DELETE', credentials: 'include'
      });
      const d = await r.json();
      if (!d.ok) throw new Error(d.error || 'Erro ao excluir SEP.');
      _solInvalidateAguardRetCache(nSolic, tituloColuna, escopoItens);
      _solInvalidateSepModalCache(nSolic, escopoItens);
      closeModal();
      window._loadSolicitacoesTab && (window._loadSolicitacoesTab.force = true, window._loadSolicitacoesTab());
      window._loadKanbanSolicitacoesTab && (window._loadKanbanSolicitacoesTab.force = true, window._loadKanbanSolicitacoesTab());
    } catch (e) {
      alert('Erro: ' + e.message);
      btn.disabled = false;
      btn.innerHTML = '<i class="fa-solid fa-trash-can" style="margin-right:4px;"></i>Excluir SEP';
    }
  });

  document.getElementById('btnAguardRetIniciarSep')?.addEventListener('click', async () => {
    const btn = document.getElementById('btnAguardRetIniciarSep');
    if (!btn || btn.disabled) return;
    btn.disabled = true;
    btn.innerHTML = '<i class="fa-solid fa-spinner fa-spin" style="margin-right:4px;"></i>Atualizando...';
    try {
      // Carrega TODOS os itens atuais desta SEP (antes do bloqueio de entrada)
      const refresh = await _recarregarItensAguardRetAntesIniciar();
      const solicIds = _solSolicIdsParaIniciarSep(itens);
      if (!solicIds.length) {
        alert('Esta SEP não tem itens em Solicitado. Se já foi separada, veja a coluna "Aguardando retirada" no kanban (role para a direita).');
        btn.disabled = false;
        btn.innerHTML = '<i class="fa-solid fa-play" style="margin-right:4px;"></i>Iniciar separação';
        return;
      }
      if (refresh.novos > 0) {
        alert(
          `${refresh.novos} item(ns) entraram nesta SEP antes do início.\n` +
          `Total atualizado: ${refresh.total} item(ns).\n\n` +
          `Todos serão incluídos. Depois disso, novos pedidos geram SEP nova.`
        );
      }
      btn.innerHTML = '<i class="fa-solid fa-spinner fa-spin" style="margin-right:4px;"></i>Iniciando...';

      // ── Gera código ECT (libera Imprimir em Envio de mercadoria) ──────────
      await _solDispararVippGerarEtiqueta(nSolic, { alertarErro: true, recarregarEnvio: true });

      // ── Avança itens para "Em Separação" (servidor também leva irmãos da SEP) ──
      const r = await fetch('/api/logistica/itens_solicitados/separacao', {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({ solic_ids: solicIds })
      });
      const d = await r.json();
      if (!d.ok) throw new Error(d.error || 'Erro ao iniciar separação.');
      _solInvalidateAguardRetCache(nSolic, tituloColuna, escopoItens);
      _solInvalidateSepModalCache(nSolic, escopoItens);

      closeModal();

      // Recarrega os itens atualizados e abre direto o modal Em Separação
      const ri = await fetch(_solBuildKanbanItensUrl(nSolic, { escopoItens }), { credentials: 'include' });
      const di = await ri.json();
      if (!di.ok) throw new Error(di.error || 'Erro ao buscar itens após iniciar separação.');
      const itensAtualizados = (di.itens || []).map(it => ({ ...it, solic_ids: [it.solic_id], carr_ids: [it.carr_id] }));
      if (itensAtualizados.length) {
        await _abrirModalSeparacao({ nome_user: itensAtualizados[0]?.nome_user || nSolic, n_solic: nSolic, itens: itensAtualizados, origem_status: 'Em Separação', escopoItens }, []);
      }

      window._loadSolicitacoesTab.force = true;
      window._loadSolicitacoesTab();
      window._loadKanbanSolicitacoesTab.force = true;
      window._loadKanbanSolicitacoesTab();
    } catch (err) {
      alert('Erro: ' + (err.message || err));
      btn.disabled = false;
      btn.innerHTML = '<i class="fa-solid fa-play" style="margin-right:4px;"></i>Iniciar separação';
    }
  });

  document.getElementById('btnAguardRetRecebido')?.addEventListener('click', async () => {
    const solicIds = itens.map(it => parseInt(it.solic_id, 10)).filter(id => !isNaN(id));
    if (!solicIds.length) {
      alert('Não foi possível identificar os itens para concluir.');
      return;
    }

    const btn = document.getElementById('btnAguardRetRecebido');
    btn.disabled = true;
    btn.innerHTML = '<i class="fa-solid fa-spinner fa-spin" style="margin-right:4px;"></i>Processando...';

    try {
      const r = await fetch('/api/logistica/itens_solicitados/concluido', {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({ solic_ids: solicIds })
      });
      const d = await r.json();
      if (!d.ok) throw new Error(d.error || 'Erro ao concluir solicitação.');
      _solInvalidateAguardRetCache(nSolic, tituloColuna, escopoItens);
      _solInvalidateSepModalCache(nSolic, escopoItens);

      closeModal();
      window._loadKanbanSolicitacoesTab.force = true;
      window._loadKanbanSolicitacoesTab();
      window._loadSolicitacoesTab.force = true;
      window._loadSolicitacoesTab();
    } catch (err) {
      alert('Erro: ' + (err.message || err));
      btn.disabled = false;
      btn.innerHTML = '<i class="fa-solid fa-box-open" style="margin-right:4px;"></i>Recebido';
    }
  });
}

// Modal para registrar justificativa de "Não separar"
async function _abrirModalNaoSeparar(solicId, callback) {
  document.getElementById('modalNaoSeparar')?.remove();

  const modal = document.createElement('div');
  modal.id = 'modalNaoSeparar';
  modal.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,.65);z-index:10070;display:flex;align-items:center;justify-content:center;';
  modal.innerHTML = `
    <div style="background:#1c1c1c;border:1px solid #2a2a2a;border-radius:16px;width:min(450px,95vw);display:flex;flex-direction:column;overflow:hidden;box-shadow:0 20px 60px rgba(0,0,0,.6);">
      <div style="display:flex;align-items:center;gap:10px;padding:16px 20px;border-bottom:1px solid #2a2a2a;background:#171717;flex-shrink:0;">
        <i class="fa-solid fa-triangle-exclamation" style="color:#f97316;font-size:1.1rem;"></i>
        <span style="font-weight:700;font-size:1rem;color:#f0f0f0;">Justificar não separação</span>
        <button id="btnModalNaoSepFechar" style="margin-left:auto;background:none;border:none;color:#9ca3af;font-size:1.3rem;cursor:pointer;padding:2px 6px;line-height:1;">&#x2715;</button>
      </div>
      <div style="padding:16px;flex:1;">
        <label style="display:block;font-size:.85rem;font-weight:700;color:#f0f0f0;margin-bottom:8px;">Por que não separar este item?</label>
        <textarea id="txtJustificativa" 
          placeholder="Ex: Produto fora de estoque, item danificado, etc."
          style="width:100%;height:120px;padding:10px 12px;border-radius:8px;border:1px solid #4b5563;background:#111;color:#f0f0f0;font-size:.85rem;font-family:inherit;resize:vertical;"></textarea>
        <div style="font-size:.72rem;color:#6b7280;margin-top:6px;">Esta observação será registrada no sistema.</div>
      </div>
      <div style="padding:12px 16px;border-top:1px solid #2a2a2a;display:flex;justify-content:flex-end;gap:8px;flex-shrink:0;background:#171717;">
        <button id="btnNaoSepCancel" style="padding:7px 20px;border:1px solid #4b5563;border-radius:8px;background:transparent;color:#d1d5db;font-weight:700;font-size:.85rem;cursor:pointer;">Cancelar</button>
        <button id="btnNaoSepConfirm" style="padding:7px 20px;border:none;border-radius:8px;background:#f97316;color:#111;font-weight:700;font-size:.85rem;cursor:pointer;">
          <i class="fa-solid fa-ban" style="margin-right:4px;"></i>Não Separar
        </button>
      </div>
    </div>`;
  document.body.appendChild(modal);

  const closeModal = () => modal.remove();
  document.getElementById('btnModalNaoSepFechar').addEventListener('click', closeModal);
  document.getElementById('btnNaoSepCancel').addEventListener('click', closeModal);
  modal.addEventListener('click', e => { if (e.target === modal) closeModal(); });

  document.getElementById('btnNaoSepConfirm').addEventListener('click', async () => {
    const justificativa = document.getElementById('txtJustificativa').value.trim();
    if (!justificativa) { alert('Por favor, escreva uma justificativa.'); return; }

    const btn = document.getElementById('btnNaoSepConfirm');
    btn.disabled = true;
    btn.innerHTML = '<i class="fa-solid fa-spinner fa-spin" style="margin-right:4px;"></i>Processando...';

    try {
      const r = await fetch('/api/logistica/itens_solicitados/nao-separar', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({ solic_id: solicId, justificativa })
      });
      const d = await r.json();
      if (!d.ok) { alert('Erro: ' + (d.error || 'Falha ao processar')); btn.disabled = false; return; }

      closeModal();
      if (callback) callback();
    } catch (err) {
      console.error('[nao-separar] erro:', err);
      alert('Erro ao processar solicitação.');
      btn.disabled = false;
    }
  });
}

// Modal de edição de SEP (carrinho ou pendente)
async function _abrirModalEdicaoSep(nSolic) {
  // Fecha tooltip caso esteja visível
  clearTimeout(window._kanbanTooltipTimer);
  window._kanbanTooltipEl?.remove();
  window._kanbanTooltipEl = null;

  _solKanbanLoading(true, 'Carregando itens...');

  const url = nSolic
    ? `/api/logistica/kanban/itens?n_solic=${encodeURIComponent(nSolic)}`
    : '/api/logistica/kanban/itens';

  let itens;
  let enderecoBatch = {};
  try {
    const r = await fetch(url, { credentials: 'include' });
    const d = await r.json();
    if (!d.ok) { alert('Erro ao carregar itens: ' + (d.error || '')); return; }
    itens = d.itens || [];
    const codigos = [...new Set(itens.map(it => it.codigo_produto).filter(Boolean))];
    if (codigos.length) enderecoBatch = await _solCarregarEnderecoBatch(codigos);
    enderecoBatch = _solMergeEnderecoBatch(itens, enderecoBatch);
  } catch (e) { alert('Erro de rede.'); return; }
  finally { _solKanbanLoading(false); }

  // Verifica se algum item mudou para status não editável
  const bloqueados = itens.filter(it => it.status && it.status !== 'pendente' && it.status !== 'carrinho');
  if (bloqueados.length) {
    alert(`Esta solicitação já está em "${bloqueados[0].status}" e não pode mais ser editada.`);
    return;
  }

  document.getElementById('modalEdicaoSep')?.remove();

  const renderLinha = (it) => {
    const enderecamentoEdit = _solEnderecamentoHtml(it.codigo_produto, enderecoBatch, it);
    return `
    <div data-sep-row="${it.carr_id}" style="display:flex;align-items:center;gap:10px;padding:10px 16px;border-top:1px solid #222;">
      <div style="flex:1;min-width:0;">
        <div style="font-weight:700;font-size:.80rem;color:#f59e0b;">${it.codigo_produto}</div>
        <div style="font-size:.76rem;color:#d1d5db;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${it.descricao || '—'}</div>
        <div style="font-size:.72rem;color:#9ca3af;margin-top:2px;">${_solFmtDataPrevista(it.data_prevista) || ''}${it.horario ? ' ' + it.horario : ''}</div>
        ${enderecamentoEdit ? `<div style="margin-top:4px;">${enderecamentoEdit}</div>` : ''}
      </div>
      <div style="display:flex;align-items:center;gap:6px;flex-shrink:0;">
        <input type="text" inputmode="decimal"
          class="sep-edit-qty"
          data-carr-id="${it.carr_id}"
          data-original="${it.quantidade}"
          value="${_solFmtQty(it.quantidade)}"
          onfocus="this.select()"
          style="width:64px;padding:4px 7px;border-radius:6px;border:1px solid #4b5563;background:#111;color:#f0f0f0;font-size:.80rem;text-align:center;">
        <span style="font-size:.72rem;color:#6b7280;">${it.unidade || 'UN'}</span>
        <button class="sep-edit-nao-separar" data-solic-id="${it.solic_id}" title="Marcar como não separado"
          style="background:none;border:none;color:#f97316;cursor:pointer;font-size:.95rem;padding:2px 4px;">
          <i class="fa-solid fa-ban"></i>
        </button>
        <button class="sep-edit-del" data-carr-id="${it.carr_id}" title="Excluir item"
          style="background:none;border:none;color:#ef4444;cursor:pointer;font-size:.95rem;padding:2px 4px;">
          <i class="fa-solid fa-trash-can"></i>
        </button>
      </div>
    </div>`;
  };

  const modal = document.createElement('div');
  modal.id = 'modalEdicaoSep';
  modal.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,.65);z-index:10060;display:flex;align-items:center;justify-content:center;';
  modal.innerHTML = `
    <div style="background:#1c1c1c;border:1px solid #2a2a2a;border-radius:16px;width:min(480px,95vw);max-height:85vh;display:flex;flex-direction:column;overflow:hidden;box-shadow:0 20px 60px rgba(0,0,0,.6);">
      <div style="display:flex;align-items:center;gap:10px;padding:16px 20px;border-bottom:1px solid #2a2a2a;background:#171717;flex-shrink:0;">
        <i class="fa-solid fa-pen-to-square" style="color:#f59e0b;font-size:1.1rem;"></i>
        <span style="font-weight:700;font-size:1rem;color:#f0f0f0;">${nSolic ? `Editar — ${nSolic}` : 'Editar Carrinho'}</span>
        <button id="btnModalEdicaoSepFechar" style="margin-left:auto;background:none;border:none;color:#9ca3af;font-size:1.3rem;cursor:pointer;padding:2px 6px;line-height:1;">&#x2715;</button>
      </div>
      <div id="sepEditLista" style="overflow-y:auto;flex:1;">
        ${itens.map(it => renderLinha(it)).join('')}
      </div>
      <div style="padding:12px 16px;border-top:1px solid #2a2a2a;display:flex;justify-content:flex-end;gap:8px;flex-shrink:0;background:#171717;">
        <button id="btnSepEditSalvar" style="padding:7px 20px;border:none;border-radius:8px;background:#f59e0b;color:#111;font-weight:700;font-size:.85rem;cursor:pointer;">
          <i class="fa-solid fa-floppy-disk" style="margin-right:4px;"></i>Salvar alterações
        </button>
      </div>
    </div>`;
  document.body.appendChild(modal);

  document.getElementById('btnModalEdicaoSepFechar').addEventListener('click', () => modal.remove());
  modal.addEventListener('click', e => { if (e.target === modal) modal.remove(); });

  // Botões excluir
  modal.querySelectorAll('.sep-edit-del').forEach(btn => {
    btn.addEventListener('click', async () => {
      const carrId = parseInt(btn.dataset.carrId, 10);
      if (!confirm('Excluir este item da solicitação?')) return;
      _solBtnLoading(btn);
      try {
        const r = await fetch(`/api/logistica/carrinho/${carrId}`, { method: 'DELETE', credentials: 'include' });
        const d = await r.json();
        if (d.ok) {
          btn.closest('[data-sep-row]')?.remove();
          const lista = document.getElementById('sepEditLista');
          if (lista && !lista.querySelectorAll('[data-sep-row]').length) {
            modal.remove();
            window._loadKanbanSolicitacoesTab.force = true;
            window._loadKanbanSolicitacoesTab();
            window._loadSolicitacoesTab.force = true;
            window._loadSolicitacoesTab();
          }
        } else { alert('Erro: ' + d.error); _solBtnRestore(btn, '<i class="fa-solid fa-trash-can"></i>'); }
      } catch (_) { alert('Erro ao excluir.'); _solBtnRestore(btn, '<i class="fa-solid fa-trash-can"></i>'); }
    });
  });

  // Botões "Não separar" — abre modal com campo de observação
  modal.querySelectorAll('.sep-edit-nao-separar').forEach(btn => {
    btn.addEventListener('click', async () => {
      const solicId = parseInt(btn.dataset.solicId, 10);
      if (!solicId) { alert('ID do item não encontrado.'); return; }
      _solBtnLoading(btn);
      // Abre modal para inserir justificativa
      _abrirModalNaoSeparar(solicId, () => {
        _solBtnRestore(btn, '<i class="fa-solid fa-ban"></i>');
        // Callback: após salvar, remove a linha e fecha modal se estiver vazio
        btn.closest('[data-sep-row]')?.remove();
        const lista = document.getElementById('sepEditLista');
        if (lista && !lista.querySelectorAll('[data-sep-row]').length) {
          modal.remove();
          window._loadKanbanSolicitacoesTab.force = true;
          window._loadKanbanSolicitacoesTab();
          window._loadSolicitacoesTab.force = true;
          window._loadSolicitacoesTab();
        }
      });
    });
  });

  // Salvar quantidades alteradas
  document.getElementById('btnSepEditSalvar').addEventListener('click', async () => {
    const inputs = modal.querySelectorAll('.sep-edit-qty');
    const alterados = [];
    for (const inp of inputs) {
      const orig = parseFloat(inp.dataset.original);
      const novo = parseFloat(inp.value.replace(',', '.'));
      if (isNaN(novo) || novo <= 0) { alert('Quantidade inválida: ' + inp.value); return; }
      if (Math.abs(novo - orig) > 0.0001) alterados.push({ carrId: parseInt(inp.dataset.carrId, 10), qty: novo });
    }
    if (!alterados.length) { modal.remove(); return; }

    const btn = document.getElementById('btnSepEditSalvar');
    btn.disabled = true;
    btn.innerHTML = '<i class="fa-solid fa-spinner fa-spin" style="margin-right:4px;"></i>Salvando...';
    let erros = 0;
    for (const a of alterados) {
      try {
        const r = await fetch(`/api/logistica/carrinho/${a.carrId}/quantidade`, {
          method: 'PATCH', headers: { 'Content-Type': 'application/json' },
          credentials: 'include',
          body: JSON.stringify({ quantidade: a.qty })
        });
        const d = await r.json();
        if (!d.ok) { alert('Erro ao salvar: ' + d.error); erros++; }
      } catch (_) { erros++; }
    }
    if (!erros) {
      modal.remove();
      window._loadKanbanSolicitacoesTab.force = true;
      window._loadKanbanSolicitacoesTab();
      window._loadSolicitacoesTab.force = true;
      window._loadSolicitacoesTab();
    } else {
      btn.disabled = false;
      btn.innerHTML = '<i class="fa-solid fa-floppy-disk" style="margin-right:4px;"></i>Salvar alterações';
    }
  });
}

// ============================================================================
// FUNÇÃO GLOBAL PARA ABRIR O CHAT - Disponível imediatamente
// ============================================================================
window.openChat = async function() {
  console.log('[CHAT] openChat chamado - VERSÃO COM LOGS v1.1');
  console.log('[CHAT] Verificando __chatLoadUsers:', typeof window.__chatLoadUsers);
  
  // Aguarda o DOM estar pronto
  if (!document.getElementById('chatPane')) {
    console.warn('[CHAT] chatPane ainda não existe no DOM, aguardando...');
    await new Promise(resolve => {
      if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', resolve, { once: true });
      } else {
        resolve();
      }
    });
  }
  
  const chatPane = document.getElementById('chatPane');
  if (!chatPane) {
    console.error('[CHAT] chatPane não encontrado no DOM');
    return;
  }
  
  // precisa estar logado
  if (!window.__sessionUser?.id) {
    console.warn('[CHAT] Usuário não autenticado');
    console.log('[CHAT] Valor de window.__sessionUser:', window.__sessionUser);
    document.getElementById('profile-icon')?.click();
    return;
  }
  
  console.log('[CHAT] Abrindo chat...');
  
  // Limpa TUDO antes
  window.clearMainContainer();
  
  // Garante que módulos especiais também sejam escondidos
  try { if (typeof hideArmazem === 'function') hideArmazem(); } catch {}
  try { if (typeof hideKanban === 'function') hideKanban(); } catch {}
  document.getElementById('produtoTabs')?.setAttribute('style','display:none');
  document.getElementById('kanbanTabs')?.setAttribute('style','display:none');
  document.getElementById('armazemTabs')?.setAttribute('style','display:none');
  
  // Remove destaque de qualquer link de topo
  try {
    document.querySelectorAll('.header .header-menu > .menu-link, a[id^="menu-"]').forEach(a => a.classList.remove('is-active'));
  } catch {}

  // Mostra SOMENTE o chat
  window.showOnlyInMain(chatPane);

  // Limpa histórico e nome do usuário
  const chatWith = document.getElementById('chatWith');
  if (chatWith) chatWith.textContent = 'Selecione um usuário';
  const chatMessages = document.getElementById('chatMessages');
  if (chatMessages) chatMessages.innerHTML = '';
  const chatText = document.getElementById('chatText');
  if (chatText) {
    chatText.value = '';
    chatText.disabled = true;
    chatText.placeholder = 'Digite uma mensagem';
  }
  const chatSend = document.getElementById('chatSend');
  if (chatSend) chatSend.disabled = true;

  // Atualiza hash para evitar lógicas que forçam #inicio
  try { if (location.hash !== '#chat') location.hash = '#chat'; } catch {}

  // Carrega usuários se a função existir
  if (typeof window.__chatLoadUsers === 'function') {
    await window.__chatLoadUsers();
  }

  console.log('[CHAT] Chat aberto com sucesso');
};

// ============================================================================
// Definição da função de carregamento de usuários do chat - ANTES DO IIFE
// ============================================================================
window.__chatLoadUsers = async function() {
  // Só executa se usuário estiver logado
  if (!window.__sessionUser) {
    console.log('[CHAT] Usuário não logado - ignorando carregamento');
    const bellNumber = document.querySelector('.notification-number');
    if (bellNumber) { bellNumber.textContent = ''; bellNumber.style.display = 'none'; }
    return;
  }
  
  console.log('[CHAT] __chatLoadUsers chamado');
  try {
    const r = await fetch('/api/chat/users', { credentials:'include' });
    console.log('[CHAT] Response status:', r.status);
    if (!r.ok) {
      console.error('[CHAT] Erro ao carregar usuários, status:', r.status);
      // zera badge do sino em caso de erro/deslogado
      const bellNumber = document.querySelector('.notification-number');
      if (bellNumber) { bellNumber.textContent = ''; bellNumber.style.display = 'none'; }
      return;
    }
    const data = await r.json();
    console.log('[CHAT] Usuários recebidos:', data);
    
    const currentUserId = window.__sessionUser?.id;
    console.log('[CHAT] ID do usuário logado:', currentUserId);
    
    const users = (data.users||[]).filter(u => !currentUserId || String(u.id) !== String(currentUserId));
    console.log('[CHAT] Total de usuários após filtro:', users.length);
    
    // 1) Atualiza badge do sino independente do DOM do chat
    let usersWithUnread = 0;
    users.forEach(u => { if (u.unreadCount && u.unreadCount > 0) usersWithUnread++; });
    const bellNumber = document.querySelector('.notification-number');
    if (bellNumber) {
      bellNumber.textContent = usersWithUnread > 0 ? String(usersWithUnread) : '';
      bellNumber.style.display = usersWithUnread > 0 ? 'inline-flex' : 'none';
    }
    
    // 2) Renderiza a lista somente se o chat estiver no DOM
    const chatUserList = document.getElementById('chatUserList');
    if (!chatUserList) {
      return; // nada mais a fazer quando não está na tela
    }
    
    chatUserList.innerHTML = '';
    if (!users || users.length === 0) {
      console.warn('[CHAT] Nenhum usuário para renderizar');
      return;
    }

    users.forEach(u => {
      const li = document.createElement('li');
      li.className = 'chat-user-item';
      li.dataset.userId = u.id;

      // Nome do usuário
      const nameSpan = document.createElement('span');
      nameSpan.textContent = u.username;
      li.appendChild(nameSpan);

      // Indicador de não lidas
      if (u.unreadCount && u.unreadCount > 0) {
        const unread = document.createElement('span');
        unread.className = 'chat-user-unread';
        unread.textContent = u.unreadCount;
        li.appendChild(unread);
      }

      li.addEventListener('click', () => selectChatUser(u));
      chatUserList.appendChild(li);
      console.log('[CHAT] Usuário adicionado à lista:', u.username, 'ID:', u.id, 'Não lidas:', u.unreadCount);
    });
    // badge do sino já atualizado acima
  } catch (err) {
    console.error('[CHAT] Erro ao carregar usuários:', err);
    const bellNumber = document.querySelector('.notification-number');
    if (bellNumber) { bellNumber.textContent = ''; bellNumber.style.display = 'none'; }
  }
};

// ============================================================================
// Estado global do chat
// ============================================================================
window.__chatState = {
  selectedUserId: null,
  selectedUsername: null
};

// ============================================================================
// Seleciona um usuário para conversar
// ============================================================================
function selectChatUser(user) {
  console.log('[CHAT] Usuário selecionado:', user.username, 'ID:', user.id);
  
  window.__chatState.selectedUserId = user.id;
  window.__chatState.selectedUsername = user.username;
  
  // Atualiza o nome do usuário selecionado
  const chatWith = document.getElementById('chatWith');
  if (chatWith) chatWith.textContent = user.username;
  
  // Habilita o campo de mensagem e botão enviar
  const chatText = document.getElementById('chatText');
  const chatSend = document.getElementById('chatSend');
  if (chatText) {
    chatText.disabled = false;
    chatText.placeholder = `Digite uma mensagem para ${user.username}...`;
    chatText.focus();
  }
  if (chatSend) chatSend.disabled = false;
  
  // Marca o usuário como ativo na lista
  document.querySelectorAll('.chat-user-item').forEach(li => {
    li.classList.toggle('is-active', li.dataset.userId === user.id);
  });

  // Otimista: remove indicador de não lidas deste usuário imediatamente
  const activeLi = document.querySelector(`.chat-user-item[data-user-id="${user.id}"]`);
  const badge = activeLi?.querySelector('.chat-user-unread');
  if (badge) badge.remove();

  // Recalcula badge do sino com base nos restantes
  const remainingUnread = document.querySelectorAll('.chat-user-unread').length;
  const bellNumber = document.querySelector('.notification-number');
  if (bellNumber) {
    bellNumber.textContent = remainingUnread > 0 ? String(remainingUnread) : '';
    bellNumber.style.display = remainingUnread > 0 ? 'inline-flex' : 'none';
  }
  
  // Carrega o histórico de mensagens
  loadChatConversation(user.id);
}

// ============================================================================
// Carrega o histórico de mensagens com um usuário
// ============================================================================
async function loadChatConversation(userId) {
  // Verifica se está logado antes de carregar conversa
  if (!window.__sessionUser) {
    console.warn('[CHAT] Usuário não logado - impossível carregar conversa');
    return;
  }
  
  console.log('[CHAT] Carregando conversa com usuário ID:', userId);
  try {
    const r = await fetch(`/api/chat/conversation?userId=${userId}`, { credentials:'include' });
    if (!r.ok) {
      console.error('[CHAT] Erro ao carregar conversa, status:', r.status);
      const errorData = await r.json().catch(() => ({}));
      console.error('[CHAT] Erro do backend:', errorData);
      return;
    }
    const data = await r.json();
    console.log('[CHAT] Mensagens recebidas:', data.messages?.length || 0);
    
    renderChatMessages(data.messages || []);
  } catch (err) {
    console.error('[CHAT] Erro ao carregar conversa:', err);
  }
}

// ============================================================================
// Renderiza as mensagens no histórico
// ============================================================================
function renderChatMessages(messages) {
  const chatMessages = document.getElementById('chatMessages');
  if (!chatMessages) {
    console.error('[CHAT] Elemento chatMessages não encontrado');
    return;
  }
  
  chatMessages.innerHTML = '';
  const currentUserId = window.__sessionUser?.id;
  
  messages.forEach(msg => {
    const div = document.createElement('div');
    const isMine = String(msg.from) === String(currentUserId);
    div.className = `chat-message ${isMine ? 'chat-message-sent' : 'chat-message-received'}`;

    const text = document.createElement('div');
    text.className = 'chat-message-text';
    text.textContent = msg.text;

    const time = document.createElement('div');
    time.className = 'chat-message-time';
    time.textContent = new Date(msg.timestamp).toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });

    // Ícone de visualização vv azul se lida
    if (isMine && msg.read) {
      const visto = document.createElement('span');
      visto.className = 'chat-message-visto';
      visto.innerHTML = '<i class="fa fa-check-double"></i>';
      time.appendChild(visto);
    }

    div.appendChild(text);
    div.appendChild(time);
    chatMessages.appendChild(div);
  });
  
  // Scroll para o final
  chatMessages.scrollTop = chatMessages.scrollHeight;
  console.log('[CHAT] Mensagens renderizadas:', messages.length);
}

// ============================================================================
// Envia uma mensagem
// ============================================================================
async function sendChatMessage() {
  // Verifica se está logado antes de enviar mensagem
  if (!window.__sessionUser) {
    console.warn('[CHAT] Usuário não logado - impossível enviar mensagem');
    return;
  }
  
  const chatText = document.getElementById('chatText');
  if (!chatText || !chatText.value.trim()) return;
  
  const text = chatText.value.trim();
  const to = window.__chatState.selectedUserId;
  
  if (!to) {
    console.warn('[CHAT] Nenhum usuário selecionado');
    return;
  }
  
  console.log('[CHAT] Enviando mensagem para usuário ID:', to);
  
  try {
    const r = await fetch('/api/chat/send', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({ to, text })
    });
    
    if (!r.ok) {
      console.error('[CHAT] Erro ao enviar mensagem, status:', r.status);
      const errorData = await r.json().catch(() => ({}));
      console.error('[CHAT] Erro do backend:', errorData);
      return;
    }
    
    const data = await r.json();
    console.log('[CHAT] Mensagem enviada com sucesso:', data);
    
    // Limpa o campo
    chatText.value = '';
    
    // Recarrega a conversa para mostrar a nova mensagem
    loadChatConversation(to);
  } catch (err) {
    console.error('[CHAT] Erro ao enviar mensagem:', err);
  }
}

// ============================================================================
// Bind de eventos do chat
// ============================================================================
document.addEventListener('DOMContentLoaded', () => {
  const chatSend = document.getElementById('chatSend');
  const chatText = document.getElementById('chatText');
  
  if (chatSend) {
    chatSend.addEventListener('click', sendChatMessage);
  }
  
  if (chatText) {
    chatText.addEventListener('keypress', (e) => {
      if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        sendChatMessage();
      }
    });
  }

  // Zera badge "5" do HTML ao carregar
  const bellNumber = document.querySelector('.notification-number');
  if (bellNumber) { bellNumber.textContent = ''; bellNumber.style.display = 'none'; }

  // Atualiza imediatamente e inicia polling a cada 1s SOMENTE se estiver logado
  if (window.__sessionUser && typeof window.__chatLoadUsers === 'function') {
    window.__chatLoadUsers();
  }
  if (window.__chatPollingInterval) clearInterval(window.__chatPollingInterval);
  window.__chatPollingInterval = setInterval(() => {
    // Só faz polling se usuário estiver logado
    if (window.__sessionUser && typeof window.__chatLoadUsers === 'function') {
      window.__chatLoadUsers();
    }
  }, 5000);
});

// Estado compartilhado do multiplicador da PCP (fator aplicado às quantidades)
if (!Number.isFinite(window.__pcpFactorValue) || window.__pcpFactorValue <= 0) {
  window.__pcpFactorValue = 1;
}
window.__pcpFactorInput = window.__pcpFactorInput || null;
window.__pcpFactorHandler = window.__pcpFactorHandler || null;

function pcpGetFactorValue() {
  const raw = Number(window.__pcpFactorValue ?? 1);
  return (!Number.isFinite(raw) || raw <= 0) ? 1 : raw;
}

function pcpSetFactorValue(newValue, { syncInput = true } = {}) {
  let val = Number(newValue);
  if (!Number.isFinite(val) || val <= 0) val = 1;
  window.__pcpFactorValue = val;

  if (syncInput) {
    const input = document.getElementById('pcp-factor');
    if (input && document.activeElement !== input) {
      input.value = val;
    }
  }
  return val;
}


// refs do modal de colaboradores
