const qualidadeListaMestraRecarregarBtn = document.getElementById('qualidadeListaMestraRecarregarBtn');
const qualidadeListaMestraEditModal = document.getElementById('qualidadeListaMestraEditModal');
const qualidadeListaMestraArquivoModal = document.getElementById('qualidadeListaMestraArquivoModal');
let qualidadeListaMestraCarregando = false;
let qualidadeListaMestraItens = [];
let qualidadeListaMestraHistoricoAtual = [];

function ocultarQualidadeManuaisLista() {
  if (qualidadeManuaisListaWrap) qualidadeManuaisListaWrap.style.display = 'none';
  if (qualidadeManuaisMeta) qualidadeManuaisMeta.textContent = '';
}

function parseDataListaMestra(valor) {
  const s = String(valor || '').trim();
  if (!s) return null;
  const partes = s.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
  if (!partes) return null;
  let d = Number.parseInt(partes[1], 10);
  let m = Number.parseInt(partes[2], 10);
  const y = Number.parseInt(partes[3], 10);
  if (m > 12 && d <= 12) {
    const tmp = d;
    d = m;
    m = tmp;
  }
  if (!y || m < 1 || m > 12 || d < 1 || d > 31) return null;
  const dt = new Date(y, m - 1, d);
  if (dt.getFullYear() !== y || dt.getMonth() !== m - 1 || dt.getDate() !== d) return null;
  return dt;
}

function proximaRevisaoListaMestraVencida(valor) {
  const dt = parseDataListaMestra(valor);
  if (!dt) return false;
  const hoje = new Date();
  hoje.setHours(0, 0, 0, 0);
  dt.setHours(0, 0, 0, 0);
  return dt < hoje;
}

function formatarDataHoraListaMestra(valor) {
  if (!valor) return '';
  const dt = new Date(valor);
  if (Number.isNaN(dt.getTime())) return String(valor);
  return dt.toLocaleString('pt-BR');
}

function usuarioPodeAtualizarListaMestraArquivo() {
  return Number(window.__sessionUser?.sector_id) === 2;
}

function atualizarPermissaoUploadListaMestra() {
  const pode = usuarioPodeAtualizarListaMestraArquivo();
  const wrap = document.getElementById('qualidadeListaMestraArquivoUploadWrap');
  const restrito = document.getElementById('qualidadeListaMestraArquivoUploadRestrito');
  if (wrap) wrap.style.display = pode ? 'block' : 'none';
  if (restrito) restrito.style.display = pode ? 'none' : 'block';
}

function renderQualidadeListaMestraTabela(itens = []) {
  if (!qualidadeListaMestraTbody) return;
  const lista = Array.isArray(itens) ? itens : [];
  if (!lista.length) {
    qualidadeListaMestraTbody.innerHTML = `
      <tr><td colspan="10" style="text-align:center;color:var(--inactive-color);padding:18px;">Nenhum documento cadastrado.</td></tr>
    `;
    return;
  }
  qualidadeListaMestraTbody.innerHTML = lista.map((item) => {
    const proxima = String(item.proxima_revisao || '').trim();
    const proximaStyle = proximaRevisaoListaMestraVencida(proxima)
      ? 'color:#dc2626;font-weight:700;'
      : '';
    const temArquivo = !!String(item.documento || '').trim();
    const docLabel = temArquivo ? 'Ver documento' : 'Enviar arquivo';
    const docIcon = temArquivo ? 'fa-file-lines' : 'fa-cloud-arrow-up';
    return `
    <tr class="qualidade-lista-mestra-row" data-id="${item.id}" style="cursor:pointer;" title="Clique na linha para editar os dados">
      <td>${qualidadeManuaisEscapeHtml(item.numero_formulario)}</td>
      <td>${qualidadeManuaisEscapeHtml(item.descricao)}</td>
      <td>${qualidadeManuaisEscapeHtml(item.autor)}</td>
      <td>${qualidadeManuaisEscapeHtml(item.classificacao)}</td>
      <td>${qualidadeManuaisEscapeHtml(item.numero_revisao)}</td>
      <td>${qualidadeManuaisEscapeHtml(item.data_criacao)}</td>
      <td>${qualidadeManuaisEscapeHtml(item.revisado)}</td>
      <td>${qualidadeManuaisEscapeHtml(item.revisado_por)}</td>
      <td style="${proximaStyle}">${qualidadeManuaisEscapeHtml(proxima)}</td>
      <td>
        <button type="button" class="content-button qualidade-lista-mestra-doc-btn" data-id="${item.id}"
          style="display:inline-flex;align-items:center;gap:6px;font-size:12px;padding:5px 10px;background:linear-gradient(135deg,#9333ea 0%,#7e22ce 100%);color:white;">
          <i class="fa-solid ${docIcon}"></i>
          <span>${docLabel}</span>
        </button>
      </td>
    </tr>`;
  }).join('');
}

async function carregarQualidadeListaMestra({ force = false } = {}) {
  if (qualidadeListaMestraCarregando) return;
  qualidadeListaMestraCarregando = true;
  try {
    ocultarQualidadeManuaisLista();
    if (qualidadeListaMestraWrap) qualidadeListaMestraWrap.style.display = 'block';
    if (qualidadeListaMestraMeta) qualidadeListaMestraMeta.textContent = 'Carregando...';
    if (qualidadeListaMestraTbody) {
      qualidadeListaMestraTbody.innerHTML = `
        <tr><td colspan="10" style="text-align:center;color:var(--inactive-color);padding:18px;">
          <i class="fa-solid fa-spinner fa-spin"></i> Carregando lista mestra...
        </td></tr>`;
    }
    const cacheBust = force ? `?t=${Date.now()}` : '';
    const response = await fetch(`${API_BASE}/api/qualidade/lista-mestra${cacheBust}`, { credentials: 'include' });
    if (!response.ok) throw new Error(`HTTP ${response.status}`);
    const data = await response.json();
    qualidadeListaMestraItens = Array.isArray(data?.itens) ? data.itens : [];
    renderQualidadeListaMestraTabela(qualidadeListaMestraItens);
    if (qualidadeListaMestraMeta) {
      qualidadeListaMestraMeta.textContent = `Total: ${qualidadeListaMestraItens.length} documento(s)`;
    }
  } catch (error) {
    console.error('[QUALIDADE] Erro ao carregar lista mestra:', error);
    if (qualidadeListaMestraMeta) qualidadeListaMestraMeta.textContent = 'Erro ao carregar a lista mestra.';
    if (qualidadeListaMestraTbody) {
      qualidadeListaMestraTbody.innerHTML = `
        <tr><td colspan="10" style="text-align:center;color:#b91c1c;padding:18px;">Erro ao carregar os documentos.</td></tr>`;
    }
  } finally {
    qualidadeListaMestraCarregando = false;
  }
}

function formatarDataHojeListaMestra() {
  const hoje = new Date();
  const d = String(hoje.getDate()).padStart(2, '0');
  const m = String(hoje.getMonth() + 1).padStart(2, '0');
  const y = hoje.getFullYear();
  return `${d}/${m}/${y}`;
}

function adicionarMesesDataListaMestra(dataStr, meses) {
  const dt = parseDataListaMestra(dataStr);
  if (!dt) return '';
  const alvo = new Date(dt.getFullYear(), dt.getMonth() + meses, dt.getDate());
  const d = String(alvo.getDate()).padStart(2, '0');
  const m = String(alvo.getMonth() + 1).padStart(2, '0');
  const y = alvo.getFullYear();
  return `${d}/${m}/${y}`;
}

function obterUsuarioListaMestra() {
  return window.__sessionUser?.fullName
    || window.__sessionUser?.username
    || window.__sessionUser?.login
    || window.__sessionUser?.nome
    || 'sistema';
}

function abrirQualidadeListaMestraEditModal(item) {
  if (!item || !qualidadeListaMestraEditModal) return;
  const setVal = (id, val) => {
    const el = document.getElementById(id);
    if (el) el.value = val ?? '';
  };
  setVal('qualidadeListaMestraEditId', item.id);
  setVal('qualidadeListaMestraEditNumero', item.numero_formulario);
  setVal('qualidadeListaMestraEditDescricao', item.descricao);
  setVal('qualidadeListaMestraEditTipoDocumento', item.tipo_documento);
  setVal('qualidadeListaMestraEditFormato', item.formato);
  setVal('qualidadeListaMestraEditClassificacao', item.classificacao);
  setVal('qualidadeListaMestraEditAutor', item.autor);
  setVal('qualidadeListaMestraEditRevisao', item.numero_revisao);
  setVal('qualidadeListaMestraEditDataCriacao', item.data_criacao);
  setVal('qualidadeListaMestraEditRevisado', item.revisado);
  setVal('qualidadeListaMestraEditRevisadoPor', item.revisado_por);
  setVal('qualidadeListaMestraEditProximaRevisao', item.proxima_revisao);
  setVal('qualidadeListaMestraEditResponsavel', item.responsavel_arquivar_eliminar);
  setVal('qualidadeListaMestraEditTempoRetencao', item.tempo_retencao);
  setVal('qualidadeListaMestraEditStatus', item.status);
  setVal('qualidadeListaMestraEditDataArquivamento', item.data_arquivamento);
  qualidadeListaMestraEditModal.style.display = 'flex';
}

function coletarPayloadListaMestraEdit() {
  return {
    numero_formulario: document.getElementById('qualidadeListaMestraEditNumero')?.value || '',
    descricao: document.getElementById('qualidadeListaMestraEditDescricao')?.value || '',
    tipo_documento: document.getElementById('qualidadeListaMestraEditTipoDocumento')?.value || '',
    formato: document.getElementById('qualidadeListaMestraEditFormato')?.value || '',
    classificacao: document.getElementById('qualidadeListaMestraEditClassificacao')?.value || '',
    autor: document.getElementById('qualidadeListaMestraEditAutor')?.value || '',
    numero_revisao: document.getElementById('qualidadeListaMestraEditRevisao')?.value || '',
    data_criacao: document.getElementById('qualidadeListaMestraEditDataCriacao')?.value || '',
    revisado: document.getElementById('qualidadeListaMestraEditRevisado')?.value || '',
    revisado_por: document.getElementById('qualidadeListaMestraEditRevisadoPor')?.value || '',
    proxima_revisao: document.getElementById('qualidadeListaMestraEditProximaRevisao')?.value || '',
    responsavel_arquivar_eliminar: document.getElementById('qualidadeListaMestraEditResponsavel')?.value || '',
    tempo_retencao: document.getElementById('qualidadeListaMestraEditTempoRetencao')?.value || '',
    status: document.getElementById('qualidadeListaMestraEditStatus')?.value || '',
    data_arquivamento: document.getElementById('qualidadeListaMestraEditDataArquivamento')?.value || ''
  };
}

function fecharQualidadeListaMestraEditModal() {
  if (qualidadeListaMestraEditModal) qualidadeListaMestraEditModal.style.display = 'none';
}

qualidadeListaMestraBtn?.addEventListener('click', (e) => {
  e.preventDefault();
  carregarQualidadeListaMestra();
});

qualidadeListaMestraRecarregarBtn?.addEventListener('click', (e) => {
  e.preventDefault();
  carregarQualidadeListaMestra({ force: true });
});

qualidadeListaMestraTbody?.addEventListener('click', (e) => {
  const docBtn = e.target.closest('.qualidade-lista-mestra-doc-btn');
  if (docBtn) {
    e.preventDefault();
    e.stopPropagation();
    const id = Number(docBtn.dataset.id);
    const item = qualidadeListaMestraItens.find((i) => Number(i.id) === id);
    if (item) abrirQualidadeListaMestraArquivoModal(item);
    return;
  }
  const row = e.target.closest('.qualidade-lista-mestra-row');
  if (!row) return;
  const id = Number(row.dataset.id);
  const item = qualidadeListaMestraItens.find((i) => Number(i.id) === id);
  if (item) abrirQualidadeListaMestraEditModal(item);
});

document.getElementById('qualidadeListaMestraEditModalClose')?.addEventListener('click', fecharQualidadeListaMestraEditModal);
document.getElementById('qualidadeListaMestraEditCancelarBtn')?.addEventListener('click', fecharQualidadeListaMestraEditModal);
qualidadeListaMestraEditModal?.addEventListener('click', (e) => {
  if (e.target === qualidadeListaMestraEditModal) fecharQualidadeListaMestraEditModal();
});

document.getElementById('qualidadeListaMestraMarcarRevisadoBtn')?.addEventListener('click', async () => {
  const id = document.getElementById('qualidadeListaMestraEditId')?.value;
  if (!id) return;
  const hoje = formatarDataHojeListaMestra();
  const usuario = obterUsuarioListaMestra();
  const revisadoEl = document.getElementById('qualidadeListaMestraEditRevisado');
  const revisadoPorEl = document.getElementById('qualidadeListaMestraEditRevisadoPor');
  const proximaEl = document.getElementById('qualidadeListaMestraEditProximaRevisao');
  const proxima = adicionarMesesDataListaMestra(hoje, 24);
  if (revisadoEl) revisadoEl.value = hoje;
  if (revisadoPorEl) revisadoPorEl.value = usuario;
  if (proximaEl) proximaEl.value = proxima;

  const btn = document.getElementById('qualidadeListaMestraMarcarRevisadoBtn');
  if (btn) { btn.disabled = true; btn.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i>'; }
  try {
    const payload = { ...coletarPayloadListaMestraEdit(), revisado: hoje, revisado_por: usuario, proxima_revisao: proxima };
    const response = await fetch(`${API_BASE}/api/qualidade/lista-mestra/${id}`, {
      method: 'PUT',
      credentials: 'include',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload)
    });
    const data = await response.json().catch(() => ({}));
    if (!response.ok) throw new Error(data?.error || `HTTP ${response.status}`);
    const idx = qualidadeListaMestraItens.findIndex((i) => Number(i.id) === Number(id));
    if (idx >= 0 && data?.item) qualidadeListaMestraItens[idx] = data.item;
    renderQualidadeListaMestraTabela(qualidadeListaMestraItens);
  } catch (error) {
    console.error('[QUALIDADE] Erro ao registrar revisão:', error);
    alert(error?.message || 'Não foi possível registrar a revisão.');
  } finally {
    if (btn) {
      btn.disabled = false;
      btn.innerHTML = '<i class="fa-solid fa-check"></i> Revisado';
    }
  }
});

document.getElementById('qualidadeListaMestraEditSalvarBtn')?.addEventListener('click', async () => {
  const id = document.getElementById('qualidadeListaMestraEditId')?.value;
  if (!id) return;
  const payload = coletarPayloadListaMestraEdit();
  const btn = document.getElementById('qualidadeListaMestraEditSalvarBtn');
  if (btn) { btn.disabled = true; btn.textContent = 'Salvando...'; }
  try {
    const response = await fetch(`${API_BASE}/api/qualidade/lista-mestra/${id}`, {
      method: 'PUT',
      credentials: 'include',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload)
    });
    const data = await response.json().catch(() => ({}));
    if (!response.ok) throw new Error(data?.error || `HTTP ${response.status}`);
    const idx = qualidadeListaMestraItens.findIndex((i) => Number(i.id) === Number(id));
    if (idx >= 0 && data?.item) qualidadeListaMestraItens[idx] = data.item;
    renderQualidadeListaMestraTabela(qualidadeListaMestraItens);
    fecharQualidadeListaMestraEditModal();
  } catch (error) {
    console.error('[QUALIDADE] Erro ao salvar lista mestra:', error);
    alert(error?.message || 'Não foi possível salvar o documento.');
  } finally {
    if (btn) {
      btn.disabled = false;
      btn.innerHTML = '<i class="fa-solid fa-floppy-disk"></i> Salvar';
    }
  }
});

function atualizarQualidadeListaMestraDownloadLink(item) {
  const link = document.getElementById('qualidadeListaMestraArquivoBaixarLink');
  const semArquivo = document.getElementById('qualidadeListaMestraArquivoSemArquivo');
  const temDoc = !!String(item?.documento || '').trim();
  const id = Number(item?.id || 0);
  if (link) {
    if (temDoc && id) {
      link.href = `${API_BASE}/api/qualidade/lista-mestra/${id}/download`;
      link.style.display = 'inline-flex';
    } else {
      link.href = '#';
      link.style.display = 'none';
    }
  }
  if (semArquivo) semArquivo.style.display = temDoc ? 'none' : 'inline';
}

function renderQualidadeListaMestraHistorico(historico = []) {
  const tbody = document.getElementById('qualidadeListaMestraHistoricoTbody');
  if (!tbody) return;
  const lista = Array.isArray(historico) ? historico : [];
  if (!lista.length) {
    tbody.innerHTML = `<tr><td colspan="5" style="text-align:center;color:var(--inactive-color);padding:14px;">Nenhuma versão registrada.</td></tr>`;
    return;
  }
  tbody.innerHTML = lista.map((h) => {
    const docId = document.getElementById('qualidadeListaMestraArquivoId')?.value;
    const histLink = h.documento && docId
      ? `<a href="${qualidadeManuaisEscapeHtml(`${API_BASE}/api/qualidade/lista-mestra/${docId}/download?historico_id=${h.id}`)}" style="color:#2563eb;">Baixar</a>`
      : '—';
    return `
    <tr>
      <td>${qualidadeManuaisEscapeHtml(h.numero_revisao)}</td>
      <td>${qualidadeManuaisEscapeHtml(h.descricao_alteracao || '—')}</td>
      <td>${qualidadeManuaisEscapeHtml(h.inserido_por)}</td>
      <td>${qualidadeManuaisEscapeHtml(formatarDataHoraListaMestra(h.inserido_em))}</td>
      <td>${histLink}</td>
    </tr>`;
  }).join('');
}

async function abrirQualidadeListaMestraArquivoModal(item) {
  if (!item || !qualidadeListaMestraArquivoModal) return;
  document.getElementById('qualidadeListaMestraArquivoId').value = item.id;
  document.getElementById('qualidadeListaMestraArquivoModalTitulo').textContent =
    `${item.numero_formulario || 'Documento'} — Rev. ${item.numero_revisao || '—'}`;
  const info = document.getElementById('qualidadeListaMestraArquivoInfo');
  if (info) {
    info.textContent = item.descricao
      ? `${item.descricao} | Rev. atual: ${item.numero_revisao || '—'}`
      : `Rev. atual: ${item.numero_revisao || '—'}`;
  }
  document.getElementById('qualidadeListaMestraArquivoDescricao').value = '';
  document.getElementById('qualidadeListaMestraArquivoInput').value = '';
  atualizarQualidadeListaMestraDownloadLink(item);
  atualizarPermissaoUploadListaMestra();
  qualidadeListaMestraArquivoModal.style.display = 'flex';

  try {
    const response = await fetch(`${API_BASE}/api/qualidade/lista-mestra/${item.id}/arquivo`, { credentials: 'include' });
    if (!response.ok) throw new Error(`HTTP ${response.status}`);
    const data = await response.json();
    if (data?.item) {
      const idx = qualidadeListaMestraItens.findIndex((i) => Number(i.id) === Number(item.id));
      if (idx >= 0) qualidadeListaMestraItens[idx] = data.item;
      atualizarQualidadeListaMestraDownloadLink(data.item);
      if (info) {
        info.textContent = data.item.descricao
          ? `${data.item.descricao} | Rev. atual: ${data.item.numero_revisao || '—'}`
          : `Rev. atual: ${data.item.numero_revisao || '—'}`;
      }
      document.getElementById('qualidadeListaMestraArquivoModalTitulo').textContent =
        `${data.item.numero_formulario || 'Documento'} — Rev. ${data.item.numero_revisao || '—'}`;
    }
    qualidadeListaMestraHistoricoAtual = Array.isArray(data?.historico) ? data.historico : [];
    renderQualidadeListaMestraHistorico(qualidadeListaMestraHistoricoAtual);
  } catch (error) {
    console.error('[QUALIDADE] Erro ao carregar histórico:', error);
    qualidadeListaMestraHistoricoAtual = [];
    renderQualidadeListaMestraHistorico([]);
  }
}

function fecharQualidadeListaMestraArquivoModal() {
  if (!qualidadeListaMestraArquivoModal) return;
  qualidadeListaMestraArquivoModal.style.display = 'none';
}

document.getElementById('qualidadeListaMestraArquivoModalClose')?.addEventListener('click', fecharQualidadeListaMestraArquivoModal);
qualidadeListaMestraArquivoModal?.addEventListener('click', (e) => {
  if (e.target === qualidadeListaMestraArquivoModal) fecharQualidadeListaMestraArquivoModal();
});

document.getElementById('qualidadeListaMestraArquivoEnviarBtn')?.addEventListener('click', async () => {
  const id = document.getElementById('qualidadeListaMestraArquivoId')?.value;
  const arquivoInput = document.getElementById('qualidadeListaMestraArquivoInput');
  const descricao = document.getElementById('qualidadeListaMestraArquivoDescricao')?.value || '';
  const arquivo = arquivoInput?.files?.[0];
  if (!id) return;
  if (!arquivo) {
    alert('Selecione um arquivo para enviar.');
    return;
  }
  const btn = document.getElementById('qualidadeListaMestraArquivoEnviarBtn');
  if (btn) { btn.disabled = true; btn.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> Enviando...'; }
  try {
    const form = new FormData();
    form.append('arquivo', arquivo);
    form.append('descricao_alteracao', descricao);
    const response = await fetch(`${API_BASE}/api/qualidade/lista-mestra/${id}/arquivo`, {
      method: 'POST',
      credentials: 'include',
      body: form
    });
    const data = await response.json().catch(() => ({}));
    if (!response.ok) throw new Error(data?.error || `HTTP ${response.status}`);
    if (data?.item) {
      const idx = qualidadeListaMestraItens.findIndex((i) => Number(i.id) === Number(id));
      if (idx >= 0) qualidadeListaMestraItens[idx] = data.item;
      renderQualidadeListaMestraTabela(qualidadeListaMestraItens);
      document.getElementById('qualidadeListaMestraArquivoModalTitulo').textContent =
        `${data.item.numero_formulario || 'Documento'} — Rev. ${data.item.numero_revisao || '—'}`;
      const info = document.getElementById('qualidadeListaMestraArquivoInfo');
      if (info) {
        info.textContent = data.item.descricao
          ? `${data.item.descricao} | Rev. atual: ${data.item.numero_revisao || '—'}`
          : `Rev. atual: ${data.item.numero_revisao || '—'}`;
      }
      atualizarQualidadeListaMestraDownloadLink(data.item);
    }
    qualidadeListaMestraHistoricoAtual = Array.isArray(data?.historico) ? data.historico : [];
    renderQualidadeListaMestraHistorico(qualidadeListaMestraHistoricoAtual);
    if (arquivoInput) arquivoInput.value = '';
    document.getElementById('qualidadeListaMestraArquivoDescricao').value = '';
    alert('Nova versão enviada com sucesso.');
  } catch (error) {
    console.error('[QUALIDADE] Erro ao enviar arquivo:', error);
    alert(error?.message || 'Não foi possível enviar o arquivo.');
  } finally {
    if (btn) {
      btn.disabled = false;
      btn.innerHTML = '<i class="fa-solid fa-cloud-arrow-up"></i> Enviar nova versão';
    }
  }
});

// ── Busca e vínculo de produtos aos manuais ──
let _buscaManualTimer = null;
window._manualBuscaResultados = window._manualBuscaResultados || {};
window._manualBuscaSelecionados = window._manualBuscaSelecionados || {};
window._manualBuscaModoSelecao = window._manualBuscaModoSelecao || {};
window._manualBuscaPressTimers = window._manualBuscaPressTimers || {};
window._manualBuscaIgnorarClickAte = window._manualBuscaIgnorarClickAte || {};
window._manualBuscaEnviando = window._manualBuscaEnviando || {};

function renderBuscaProdutosManual(manualId) {
  const container = document.getElementById(`manual-busca-resultados-${manualId}`);
  if (!container) return;

  const produtos = Array.isArray(window._manualBuscaResultados?.[manualId]) ? window._manualBuscaResultados[manualId] : [];
  const selecionados = new Set(window._manualBuscaSelecionados?.[manualId] || []);
  const emSelecao = !!window._manualBuscaModoSelecao?.[manualId];

  if (!produtos.length) {
    container.innerHTML = '<div style="padding:10px;font-size:12px;color:var(--inactive-color);text-align:center;">Nenhum produto encontrado</div>';
    container.style.display = 'block';
    return;
  }

  const qtdSelecionados = selecionados.size;
  const enviando = !!window._manualBuscaEnviando?.[manualId];
  const tituloAcao = enviando
    ? 'Enviando...'
    : emSelecao
      ? (qtdSelecionados > 0 ? `${qtdSelecionados} selecionado(s)` : 'Selecione os itens abaixo')
      : `Todos os ${produtos.length} resultados`;

  const topoHtml = `
    <div onclick="vincularTodosProdutosAoManual(${manualId})" style="position:sticky;top:0;z-index:5;padding:9px 12px;cursor:${enviando ? 'wait' : 'pointer'};font-size:12px;border-bottom:1px solid #475569;display:flex;align-items:center;gap:8px;background:linear-gradient(135deg,#2563eb 0%,#1d4ed8 100%);color:#fff;font-weight:700;box-shadow:0 4px 10px rgba(0,0,0,.18);" onmouseover="if(!${enviando ? 'true' : 'false'}) this.style.filter='brightness(1.08)'" onmouseout="this.style.filter='none'">
      <i class="fa-solid ${enviando ? 'fa-spinner fa-spin' : (emSelecao ? 'fa-check-double' : 'fa-layer-group')}"></i>
      <span>${enviando ? 'Enviando itens selecionados...' : tituloAcao}</span>
    </div>`;

  const itensHtml = produtos.map(p => {
    const codigoProduto = qualidadeManuaisEscapeHtml(p.codigo_produto);
    const marcado = selecionados.has(String(p.codigo_produto || ''));
    const bg = marcado ? '#1e3a8a' : '#1f2937';
    const borda = marcado ? '#60a5fa' : '#334155';
    return `
      <div
        onclick="clicarResultadoProdutoManual(event, ${manualId}, '${codigoProduto}')"
        onmousedown="iniciarPressaoProdutoManual(${manualId}, '${codigoProduto}')"
        onmouseup="cancelarPressaoProdutoManual(${manualId})"
        onmouseleave="cancelarPressaoProdutoManual(${manualId})"
        ontouchstart="iniciarPressaoProdutoManual(${manualId}, '${codigoProduto}')"
        ontouchend="cancelarPressaoProdutoManual(${manualId})"
        style="padding:8px 12px;cursor:pointer;font-size:12px;border-bottom:1px solid ${borda};display:flex;flex-direction:column;gap:2px;background:${bg};position:relative;">
        ${marcado ? '<span style="position:absolute;right:8px;top:8px;color:#93c5fd;"><i class="fa-solid fa-check-circle"></i></span>' : ''}
        <span style="font-weight:600;color:#f8fafc;">${qualidadeManuaisEscapeHtml(p.codigo)}</span>
        <span style="color:#cbd5e1;font-size:11px;">${qualidadeManuaisEscapeHtml(p.descricao)}</span>
      </div>`;
  }).join('');

  container.innerHTML = topoHtml + itensHtml;
  container.style.display = 'block';
}

window.buscarProdutoParaManual = function(manualId, termo) {
  clearTimeout(_buscaManualTimer);
  const container = document.getElementById(`manual-busca-resultados-${manualId}`);
  if (!container) return;
  const q = (termo || '').trim();
  if (q.length < 2) {
    container.style.display = 'none';
    window._manualBuscaModoSelecao[manualId] = false;
    window._manualBuscaSelecionados[manualId] = [];
    return;
  }
  _buscaManualTimer = setTimeout(async () => {
    try {
      const resp = await fetch(`${API_BASE}/api/produtos/search?q=${encodeURIComponent(q)}&limit=10`, { credentials: 'include' });
      if (!resp.ok) return;
      const data = await resp.json();
      const produtos = Array.isArray(data?.produtos) ? data.produtos : [];
      window._manualBuscaResultados[manualId] = produtos;
      window._manualBuscaModoSelecao[manualId] = false;
      window._manualBuscaSelecionados[manualId] = [];
      renderBuscaProdutosManual(manualId);
    } catch (err) {
      console.error('[Manuais] Erro busca produto:', err);
    }
  }, 300);
};

window.iniciarPressaoProdutoManual = function(manualId, codigoProduto) {
  cancelarPressaoProdutoManual(manualId);
  window._manualBuscaPressTimers[manualId] = setTimeout(() => {
    window._manualBuscaModoSelecao[manualId] = true;
    const selecionados = new Set(window._manualBuscaSelecionados?.[manualId] || []);
    selecionados.add(String(codigoProduto || ''));
    window._manualBuscaSelecionados[manualId] = Array.from(selecionados);
    window._manualBuscaIgnorarClickAte[manualId] = Date.now() + 700;
    renderBuscaProdutosManual(manualId);
  }, 450);
};

window.cancelarPressaoProdutoManual = function(manualId) {
  if (window._manualBuscaPressTimers?.[manualId]) {
    clearTimeout(window._manualBuscaPressTimers[manualId]);
    delete window._manualBuscaPressTimers[manualId];
  }
};

window.clicarResultadoProdutoManual = function(event, manualId, codigoProduto) {
  if (event) {
    event.preventDefault();
    event.stopPropagation();
  }
  if (Date.now() < (window._manualBuscaIgnorarClickAte?.[manualId] || 0)) return;

  if (window._manualBuscaModoSelecao?.[manualId]) {
    const selecionados = new Set(window._manualBuscaSelecionados?.[manualId] || []);
    const chave = String(codigoProduto || '');
    if (selecionados.has(chave)) selecionados.delete(chave);
    else selecionados.add(chave);
    window._manualBuscaSelecionados[manualId] = Array.from(selecionados);
    if (selecionados.size === 0) window._manualBuscaModoSelecao[manualId] = false;
    renderBuscaProdutosManual(manualId);
    return;
  }

  vincularProdutoAoManual(manualId, codigoProduto);
};

window.vincularProdutoAoManual = async function(manualId, codigoProduto) {
  try {
    const resp = await fetch(`${API_BASE}/api/manuais-chatbot/${manualId}/produtos`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({ codigo_produto: codigoProduto })
    });
    const data = await resp.json();
    if (!resp.ok || !data.ok) throw new Error(data.error || 'Erro ao vincular');
    const input = document.getElementById(`manual-busca-${manualId}`);
    const resultados = document.getElementById(`manual-busca-resultados-${manualId}`);
    if (input) input.value = '';
    if (resultados) resultados.style.display = 'none';
    window._manualBuscaModoSelecao[manualId] = false;
    window._manualBuscaSelecionados[manualId] = [];
    atualizarBadgesProdutosManual(manualId, data.produtos);
  } catch (err) {
    alert(err.message || 'Erro ao vincular produto.');
  }
};

window.vincularTodosProdutosAoManual = async function(manualId) {
  const produtos = Array.isArray(window._manualBuscaResultados?.[manualId]) ? window._manualBuscaResultados[manualId] : [];
  if (!produtos.length || window._manualBuscaEnviando?.[manualId]) return;

  const selecionados = new Set(window._manualBuscaSelecionados?.[manualId] || []);
  const usarSelecionados = !!window._manualBuscaModoSelecao?.[manualId] && selecionados.size > 0;
  const listaEnvio = usarSelecionados
    ? produtos.filter(p => selecionados.has(String(p.codigo_produto || '')))
    : produtos;

  if (!listaEnvio.length) return;

  try {
    window._manualBuscaEnviando[manualId] = true;
    renderBuscaProdutosManual(manualId);
    let produtosAtualizados = [];
    for (const p of listaEnvio) {
      const codigoProduto = String(p.codigo_produto || '').trim();
      if (!codigoProduto) continue;
      const resp = await fetch(`${API_BASE}/api/manuais-chatbot/${manualId}/produtos`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({ codigo_produto: codigoProduto })
      });
      const data = await resp.json();
      if (resp.ok && data.ok) {
        produtosAtualizados = Array.isArray(data.produtos) ? data.produtos : produtosAtualizados;
      }
    }
    const input = document.getElementById(`manual-busca-${manualId}`);
    const resultados = document.getElementById(`manual-busca-resultados-${manualId}`);
    if (input) input.value = '';
    if (resultados) resultados.style.display = 'none';
    window._manualBuscaModoSelecao[manualId] = false;
    window._manualBuscaSelecionados[manualId] = [];
    atualizarBadgesProdutosManual(manualId, produtosAtualizados);
  } catch (err) {
    alert(err.message || 'Erro ao vincular os produtos selecionados.');
  } finally {
    window._manualBuscaEnviando[manualId] = false;
  }
};

window.removerProdutoDoManual = async function(manualId, codigoProduto) {
  if (!confirm(`Remover produto ${codigoProduto} deste manual?`)) return;
  try {
    const resp = await fetch(`${API_BASE}/api/manuais-chatbot/${manualId}/produtos/${encodeURIComponent(codigoProduto)}`, {
      method: 'DELETE',
      credentials: 'include'
    });
    const data = await resp.json();
    if (!resp.ok || !data.ok) throw new Error(data.error || 'Erro ao remover');
    atualizarBadgesProdutosManual(manualId, data.produtos);
  } catch (err) {
    alert(err.message || 'Erro ao remover produto.');
  }
};

function atualizarBadgesProdutosManual(manualId, produtos) {
  const container = document.getElementById(`manual-produtos-${manualId}`);
  if (!container) return;
  const lista = Array.isArray(produtos) ? produtos : [];
  if (!lista.length) {
    container.innerHTML = '<span style="font-size:11px;color:var(--inactive-color);">Nenhum produto vinculado</span>';
    return;
  }
  container.innerHTML = lista.map(item => {
    const codigoInterno = qualidadeManuaisEscapeHtml(item?.codigo_produto || item || '');
    const codigoExibicao = qualidadeManuaisEscapeHtml(item?.codigo || item?.codigo_produto || item || '');
    const descricaoProduto = qualidadeManuaisEscapeHtml(item?.descricao || '');
    return `<span class="manual-produto-badge" title="${descricaoProduto}" style="display:inline-flex;align-items:center;gap:4px;padding:3px 8px;border-radius:6px;background:#e0e7ff;color:#3730a3;font-size:11px;font-weight:600;">
      ${codigoExibicao}
      <button onclick="removerProdutoDoManual(${manualId},'${codigoInterno}')" style="background:none;border:none;color:#6366f1;cursor:pointer;font-size:12px;padding:0 2px;" title="Remover">&times;</button>
    </span>`;
  }).join('');
}

// Fecha dropdowns de busca ao clicar fora
document.addEventListener('click', (e) => {
  if (!e.target.closest('[id^="manual-busca-"]')) {
    document.querySelectorAll('[id^="manual-busca-resultados-"]').forEach(el => el.style.display = 'none');
  }
});

function obterCodigoProdutoQualidadeAtual() {
  // Preferir ID Omie fixo (codigo_produto); SKU (codigo) só como fallback
  return String(
    qualidadeCodigoProdutoReal?.value ||
    qualidadeCodProduto?.value ||
    window.codigoSelecionado ||
    ''
  ).trim();
}

async function carregarStatusVerificacaoPirQualidade(codigoProduto) {
  if (!qualidadePirVerificacaoCheckbox) return;
  const codigo = String(codigoProduto || '').trim();
  if (!codigo) {
    qualidadePirVerificacaoCheckbox.checked = false;
    qualidadePirVerificacaoCheckbox.disabled = true;
    return;
  }

  qualidadePirVerificacaoCheckbox.disabled = true;
  try {
    const response = await fetch(`${API_BASE}/api/pir/produto/${encodeURIComponent(codigo)}/verificacao`, {
      credentials: 'include'
    });

    if (response.status === 404) {
      qualidadePirVerificacaoCheckbox.checked = false;
      return;
    }
    if (!response.ok) throw new Error('Erro ao carregar verificação PIR');

    const data = await response.json();
    qualidadePirVerificacaoCheckbox.checked = data?.pir === true;
  } catch (error) {
    console.error('[QUALIDADE] Erro ao carregar Verificação PIR:', error);
  } finally {
    qualidadePirVerificacaoCheckbox.disabled = false;
  }
}

async function renderQualidadeListaPirCodigos() {
  if (!qualidadeListaPirCodigosBody) return;

  qualidadeListaPirCodigosBody.innerHTML = `
    <tr>
      <td colspan="3" style="padding:14px;color:var(--inactive-color);text-align:center;">
        <i class="fa-solid fa-spinner fa-spin"></i> Carregando lista...
      </td>
    </tr>
  `;

  const endpoint = qualidadeListaPirOrigem === 'produtos_omie'
    ? `${API_BASE}/api/pir/resumo/produtos-omie`
    : `${API_BASE}/api/pir/resumo/codigos`;

  const response = await fetch(endpoint, { credentials: 'include' });
  if (!response.ok) throw new Error(`HTTP ${response.status}`);
  const data = await response.json();
  const itens = Array.isArray(data?.itens) ? data.itens : [];

  if (qualidadeListaPirCodigosMeta) {
    const origemLabel = qualidadeListaPirOrigem === 'produtos_omie' ? 'Fonte: produtos_omie' : 'Fonte: qualidade.pir';
    qualidadeListaPirCodigosMeta.textContent = `${origemLabel} | Total: ${itens.length}`;
  }

  if (qualidadeListaPirAlternarOrigemBtn) {
    const textoBtn = qualidadeListaPirOrigem === 'produtos_omie'
      ? 'Usar qualidade.pir'
      : 'Usar produtos_omie';
    qualidadeListaPirAlternarOrigemBtn.innerHTML = `<i class="fa-solid fa-shuffle"></i><span>${textoBtn}</span>`;
  }

  if (!itens.length) {
    qualidadeListaPirCodigosBody.innerHTML = `
      <tr>
        <td colspan="3" style="padding:14px;color:var(--inactive-color);text-align:center;">Nenhum registro encontrado para a origem selecionada.</td>
      </tr>
    `;
    return;
  }

  const escapeHtml = (value) => String(value ?? '').replace(/[&<>\"]/g, (ch) => ({
    '&': '&amp;',
    '<': '&lt;',
    '>': '&gt;',
    '"': '&quot;'
  }[ch]));

  qualidadeListaPirCodigosBody.innerHTML = itens.map((item, idx) => {
    const codigo = String(item?.codigo || '').trim();
    const descricao = String(item?.descricao || '').trim();
    const checked = item?.pir === true ? 'checked' : '';
    return `
      <tr>
        <td style="padding:10px;border-bottom:1px solid #334155;white-space:nowrap;">
          <a href="#" class="qualidade-pir-codigo-link" data-codigo="${escapeHtml(codigo)}" style="color:#93c5fd;text-decoration:underline;cursor:pointer;">${escapeHtml(codigo)}</a>
        </td>
        <td style="padding:10px;border-bottom:1px solid #334155;white-space:nowrap;">${escapeHtml(descricao || '-')}</td>
        <td style="padding:10px;border-bottom:1px solid #334155;text-align:center;">
          <input type="checkbox" class="qualidade-pir-codigo-check" data-codigo="${escapeHtml(codigo)}" data-idx="${idx}" ${checked} style="width:16px;height:16px;cursor:pointer;" />
        </td>
      </tr>
    `;
  }).join('');

  qualidadeListaPirCodigosBody.querySelectorAll('.qualidade-pir-codigo-check').forEach((checkbox) => {
    checkbox.addEventListener('change', async (event) => {
      const input = event.target;
      const codigo = String(input.getAttribute('data-codigo') || '').trim();
      const valorNovo = input.checked;
      const valorAnterior = !valorNovo;

      input.disabled = true;
      try {
        await salvarStatusVerificacaoPIR(codigo, valorNovo);
        const codigoAtualQualidade = obterCodigoProdutoQualidadeAtual();
        if (codigoAtualQualidade && codigoAtualQualidade === codigo && qualidadePirVerificacaoCheckbox) {
          qualidadePirVerificacaoCheckbox.checked = valorNovo;
        }
      } catch (err) {
        console.error('[QUALIDADE] Erro ao atualizar Verificação PIR na lista:', err);
        input.checked = valorAnterior;
        alert(err?.message || 'Erro ao atualizar Verificação PIR.');
      } finally {
        input.disabled = false;
      }
    });
  });

  qualidadeListaPirCodigosBody.querySelectorAll('.qualidade-pir-codigo-link').forEach((link) => {
    link.addEventListener('click', async (event) => {
      event.preventDefault();
      const codigo = String(link.getAttribute('data-codigo') || '').trim();
      if (!codigo) return;
      await abrirProdutoPirPorCodigo(codigo);
    });
  });
}

qualidadeListaPirAlternarOrigemBtn?.addEventListener('click', async (e) => {
  e.preventDefault();
  const btn = qualidadeListaPirAlternarOrigemBtn;
  try {
    qualidadeListaPirOrigem = qualidadeListaPirOrigem === 'produtos_omie' ? 'pir' : 'produtos_omie';
    if (btn) {
      btn.disabled = true;
      btn.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i><span>Alternando...</span>';
    }
    await renderQualidadeListaPirCodigos();
  } catch (err) {
    console.error('[QUALIDADE] erro ao alternar origem da lista PIR', err);
    alert('Erro ao alternar a origem da lista PIR.');
  } finally {
    if (btn) btn.disabled = false;
  }
});

function mostrarPainelQualidade(modo = 'registro') {
  if (qualidadePirPendentesWrap) {
    qualidadePirPendentesWrap.style.display = modo === 'registro' ? 'block' : 'none';
  }
  if (qualidadeRelatorioTabelaWrap) {
    qualidadeRelatorioTabelaWrap.style.display = modo === 'tabela' ? 'block' : 'none';
  }
  if (qualidadeListaPirCodigosWrap) {
    qualidadeListaPirCodigosWrap.style.display = modo === 'lista-codigos' ? 'block' : 'none';
  }
  if (qualidadeRegistroBtn) {
    qualidadeRegistroBtn.style.display = modo === 'registro' ? 'none' : 'inline-flex';
  }
}

function qualidadePirEscapeHtml(value) {
  return String(value ?? '').replace(/[&<>\"]/g, (ch) => ({
    '&': '&amp;',
    '<': '&lt;',
    '>': '&gt;',
    '"': '&quot;'
  }[ch]));
}

function formatarDataPirPendente(valor) {
  if (!valor) return '-';
  const d = new Date(valor);
  if (Number.isNaN(d.getTime())) return String(valor);
  return d.toLocaleString('pt-BR');
}

function renderQualidadePirPendentes(itens = []) {
  if (!qualidadePirPendentesBody) return;
  const lista = Array.isArray(itens) ? itens : [];
  if (qualidadePirPendentesCount) {
    const sufixo = qualidadePirMostrarSemMp ? ' (sem MP)' : ' (MP)';
    qualidadePirPendentesCount.textContent = `${lista.length} pendente${lista.length === 1 ? '' : 's'}${sufixo}`;
  }
  if (!lista.length) {
    qualidadePirPendentesBody.innerHTML = `
      <tr>
        <td colspan="7" style="text-align:center;padding:36px;color:#94a3b8;">
          Nenhum item aguardando inspeção PIR.
        </td>
      </tr>`;
    return;
  }
  qualidadePirPendentesBody.innerHTML = lista.map((item) => {
    const id = Number(item?.id) || 0;
    const lote = qualidadePirEscapeHtml(item?.lote || '-');
    const nfe = qualidadePirEscapeHtml(item?.numero_nfe || '-');
    const codigo = qualidadePirEscapeHtml(item?.codigo_produto || '-');
    const desc = qualidadePirEscapeHtml(item?.descricao_produto || '-');
    const qtd = item?.qtd != null
      ? qualidadePirEscapeHtml(formatarQuantidadeExibicao(item.qtd))
      : '-';
    const un = item?.unidade ? ` ${qualidadePirEscapeHtml(item.unidade)}` : '';
    const criado = qualidadePirEscapeHtml(formatarDataPirPendente(item?.criado_em));

    const icons = [];
    if (item?.primeira_vez) {
      icons.push(`<span title="Produto novo — primeira vez no cadastro / 1º recebimento" style="display:inline-flex;align-items:center;justify-content:center;width:28px;height:28px;border-radius:8px;background:#dbeafe;color:#1d4ed8;" aria-label="Produto novo"><i class="fa-solid fa-seedling"></i></span>`);
    }
    if (item?.fornecedor_mudou) {
      const ant = qualidadePirEscapeHtml(item?.fornecedor_anterior || '?');
      const atu = qualidadePirEscapeHtml(item?.fornecedor_atual || '?');
      icons.push(`<span title="Fornecedor mudou: ${ant} → ${atu}" style="display:inline-flex;align-items:center;justify-content:center;width:28px;height:28px;border-radius:8px;background:#ffedd5;color:#c2410c;" aria-label="Fornecedor mudou"><i class="fa-solid fa-truck-arrow-right"></i></span>`);
    }
    if (item?.produto_customizado) {
      icons.push(`<span title="Produto customizado" style="display:inline-flex;align-items:center;justify-content:center;width:28px;height:28px;border-radius:8px;background:#f3e8ff;color:#7e22ce;" aria-label="Produto customizado"><i class="fa-solid fa-puzzle-piece"></i></span>`);
    }
    if (item?.tem_alteracao) {
      const qtdAlt = Number(item?.qtd_alteracoes || 0);
      const codBusca = qualidadePirEscapeHtml(
        String(item?.po_codigo_produto || item?.po_codigo || item?.codigo_produto || '').trim()
      );
      icons.push(`<button type="button" class="qualidade-pir-btn-alteracao" data-codigo="${codBusca}" data-desc="${desc}"
        title="Há alteração de engenharia${qtdAlt ? ` (${qtdAlt})` : ''} — clique para ver"
        style="display:inline-flex;align-items:center;justify-content:center;width:28px;height:28px;border-radius:8px;background:#fee2e2;color:#b91c1c;border:none;cursor:pointer;"
        aria-label="Alteração de produto"><i class="fa-solid fa-screwdriver-wrench"></i></button>`);
    }
    const alertasHtml = icons.length
      ? `<div style="display:flex;align-items:center;justify-content:center;gap:6px;flex-wrap:wrap;">${icons.join('')}</div>`
      : `<span style="color:#94a3b8;font-size:12px;">—</span>`;

    return `
      <tr class="qualidade-pir-pendente-row" data-id="${id}"
          style="cursor:pointer;border-bottom:1px solid var(--border-color);"
          title="Abrir registro de inspeção">
        <td style="padding:10px 12px;text-align:center;vertical-align:middle;">${alertasHtml}</td>
        <td style="padding:12px 14px;white-space:nowrap;">${lote}</td>
        <td style="padding:12px 14px;white-space:nowrap;">${nfe}</td>
        <td style="padding:12px 14px;white-space:nowrap;color:#93c5fd;font-weight:600;">${codigo}</td>
        <td style="padding:12px 14px;">${desc}</td>
        <td style="padding:12px 14px;text-align:right;white-space:nowrap;">${qtd}${un}</td>
        <td style="padding:12px 14px;white-space:nowrap;color:var(--inactive-color);font-size:12px;">${criado}</td>
      </tr>`;
  }).join('');

  qualidadePirPendentesBody.querySelectorAll('.qualidade-pir-pendente-row').forEach((row) => {
    row.addEventListener('click', () => {
      const id = Number(row.getAttribute('data-id') || 0);
      const item = lista.find((x) => Number(x.id) === id);
      if (item) abrirModalInspecaoQualidade(item);
    });
    row.addEventListener('mouseenter', () => { row.style.background = 'rgba(20,184,166,0.08)'; });
    row.addEventListener('mouseleave', () => { row.style.background = ''; });
  });

  qualidadePirPendentesBody.querySelectorAll('.qualidade-pir-btn-alteracao').forEach((btn) => {
    btn.addEventListener('click', (e) => {
      e.preventDefault();
      e.stopPropagation();
      const codigo = String(btn.getAttribute('data-codigo') || '').trim();
      const desc = String(btn.getAttribute('data-desc') || '').trim();
      abrirModalAlteracoesProdutoPir(codigo, desc);
    });
  });
}

async function carregarQualidadePirPendentes(q = '') {
  if (!qualidadePirPendentesBody) return;
  qualidadePirPendentesBody.innerHTML = `
    <tr>
      <td colspan="7" style="text-align:center;padding:36px;color:#94a3b8;">
        <i class="fa-solid fa-spinner fa-spin" style="font-size:22px;margin-bottom:8px;"></i>
        <div>Carregando pendentes...</div>
      </td>
    </tr>`;
  try {
    const params = new URLSearchParams();
    if (q) params.set('q', q);
    if (qualidadePirMostrarSemMp) params.set('sem_mp', '1');
    const url = '/api/etiquetas/recebimento/pendentes-pir' + (params.toString() ? `?${params}` : '');
    const resp = await fetch(url, { credentials: 'include' });
    if (!resp.ok) throw new Error(`HTTP ${resp.status}`);
    const data = await resp.json();
    renderQualidadePirPendentes(data.etiquetas || []);
  } catch (err) {
    console.error('[QUALIDADE] erro ao carregar pendentes PIR', err);
    qualidadePirPendentesBody.innerHTML = `
      <tr>
        <td colspan="7" style="text-align:center;padding:36px;color:#f87171;">
          Erro ao carregar: ${qualidadePirEscapeHtml(err?.message || 'falha')}
        </td>
      </tr>`;
  }
}

function atualizarBotaoPirSemMp() {
  if (!qualidadePirSemMpBtn) return;
  if (qualidadePirMostrarSemMp) {
    qualidadePirSemMpBtn.style.background = 'linear-gradient(135deg,#f59e0b 0%,#d97706 100%)';
    qualidadePirSemMpBtn.innerHTML = '<i class="fa-solid fa-filter"></i><span>Ver só MP</span>';
    qualidadePirSemMpBtn.title = 'Voltar a exibir apenas MP (família ou código xx.MP....)';
  } else {
    qualidadePirSemMpBtn.style.background = '#64748b';
    qualidadePirSemMpBtn.innerHTML = '<i class="fa-solid fa-filter"></i><span>Ver sem MP</span>';
    qualidadePirSemMpBtn.title = 'Exibir itens que não são MP (nem família nem código xx.MP....)';
  }
}

async function salvarProdutoCustomizadoInspecao(codigoProduto, valor) {
  const codigo = String(codigoProduto || '').trim();
  if (!codigo) throw new Error('Informe o Cod_produto para marcar como customizado.');
  const resp = await fetch(`/api/produtos/${encodeURIComponent(codigo)}/produto-customizado`, {
    method: 'PUT',
    headers: { 'Content-Type': 'application/json' },
    credentials: 'include',
    body: JSON.stringify({ produto_customizado: valor === true })
  });
  const data = await resp.json().catch(() => ({}));
  if (!resp.ok || data.ok === false) {
    throw new Error(data.error || `Falha ao salvar produto customizado (HTTP ${resp.status})`);
  }
  return data;
}

async function carregarStatusProdutoCustomizadoInspecao(codigoProduto) {
  if (!qualidadeProdutoCustomizadoCheck) return;
  const codigo = String(codigoProduto || '').trim();
  if (!codigo) {
    qualidadeProdutoCustomizadoCheck.checked = false;
    qualidadeProdutoCustomizadoCheck.disabled = true;
    return;
  }
  qualidadeProdutoCustomizadoCheck.disabled = true;
  try {
    const resp = await fetch(`/api/produtos/${encodeURIComponent(codigo)}/produto-customizado`, {
      credentials: 'include'
    });
    if (resp.status === 404) {
      qualidadeProdutoCustomizadoCheck.checked = false;
      return;
    }
    if (!resp.ok) throw new Error(`HTTP ${resp.status}`);
    const data = await resp.json();
    qualidadeProdutoCustomizadoCheck.checked = data?.produto_customizado === true;
  } catch (err) {
    console.warn('[QUALIDADE] falha ao carregar produto_customizado', err);
  } finally {
    qualidadeProdutoCustomizadoCheck.disabled = false;
  }
}

// Salva na hora ao marcar/desmarcar no modal Registro de inspeção
let qualidadeProdutoCustomizadoSalvando = false;
qualidadeProdutoCustomizadoCheck?.addEventListener('change', async (event) => {
  if (qualidadeProdutoCustomizadoSalvando) return;
  const codigo = String(
    qualidadeCodigoProdutoReal?.value ||
    qualidadeCodProduto?.value ||
    ''
  ).trim();
  const marcado = event.target.checked === true;
  if (!codigo) {
    alert('Informe o Cod_produto antes de marcar como customizado.');
    event.target.checked = false;
    return;
  }

  qualidadeProdutoCustomizadoSalvando = true;
  event.target.disabled = true;
  try {
    await salvarProdutoCustomizadoInspecao(codigo, marcado);
    // Atualiza a lista de pendentes para refletir o ícone
    if (qualidadePirPendentesWrap?.style.display !== 'none') {
      carregarQualidadePirPendentes(qualidadePirPendentesBusca?.value?.trim() || '');
    }
  } catch (err) {
    console.error('[QUALIDADE] erro ao salvar produto customizado', err);
    event.target.checked = !marcado;
    alert(err?.message || 'Erro ao salvar Produto customizado.');
  } finally {
    qualidadeProdutoCustomizadoSalvando = false;
    event.target.disabled = false;
  }
});

function abrirModalInspecaoQualidade(item = null) {
  resetFormularioInspecaoQualidade();
  qualidadePirEtqAtualId = item?.id ? Number(item.id) : null;
  if (qualidadeEtqRecebimentoId) {
    qualidadeEtqRecebimentoId.value = qualidadePirEtqAtualId ? String(qualidadePirEtqAtualId) : '';
  }

  if (item) {
    const codigo = String(item.codigo_produto || '').trim();
    const desc = String(item.descricao_produto || '').trim();
    const nfe = String(item.numero_nfe || '').trim();
    const qtd = item.qtd != null ? formatarQuantidadeExibicao(item.qtd) : '';
    const pareceIdOmie = /^\d{8,}$/.test(codigo);
    if (qualidadeCodProduto) qualidadeCodProduto.value = pareceIdOmie ? '' : codigo;
    if (qualidadeCodigoProdutoReal) qualidadeCodigoProdutoReal.value = pareceIdOmie ? codigo : '';
    if (qualidadeDescricaoProduto) qualidadeDescricaoProduto.value = desc;
    if (qualidadeProdutoBusca) qualidadeProdutoBusca.value = codigo || desc;
    if (qualidadeNfe) qualidadeNfe.value = nfe;
    if (qualidadeQuantidadeOk && qtd && qtd !== '-') qualidadeQuantidadeOk.value = qtd;
    if (qualidadeProdutoCustomizadoCheck) {
      qualidadeProdutoCustomizadoCheck.checked = item?.produto_customizado === true;
      qualidadeProdutoCustomizadoCheck.disabled = !codigo;
    }
    if (codigo) {
      carregarStatusVerificacaoPirQualidade(codigo);
      carregarStatusProdutoCustomizadoInspecao(codigo);
      // Resolve id Omie para carregar plano PIR / imagem / NFe
      (async () => {
        try {
          const resp = await fetch('/api/produtos/busca', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            credentials: 'include',
            body: JSON.stringify({ q: codigo })
          });
          if (resp.ok) {
            const data = await resp.json();
            const itens = Array.isArray(data?.itens) ? data.itens : (Array.isArray(data) ? data : []);
            const match = itens.find((it) => String(it.codigo || '').trim() === codigo)
              || itens.find((it) => String(it.codigo_produto || '').trim() === codigo)
              || itens[0];
            if (match) {
              if (qualidadeCodProduto && match.codigo) qualidadeCodProduto.value = match.codigo;
              if (qualidadeDescricaoProduto && match.descricao) qualidadeDescricaoProduto.value = match.descricao;
              if (qualidadeCodigoProdutoReal) qualidadeCodigoProdutoReal.value = match.codigo_produto || '';
              const idOmie = match.codigo_produto || codigo;
              carregarQualidadePirItens(idOmie);
              carregarQualidadeImagemProduto(idOmie);
              carregarQualidadeNfeList(idOmie);
              if (match.codigo_produto || match.codigo) {
                carregarStatusProdutoCustomizadoInspecao(match.codigo_produto || match.codigo);
                carregarStatusVerificacaoPirQualidade(match.codigo_produto || match.codigo);
              }
              return;
            }
          }
        } catch (_) { /* fallback abaixo */ }
        carregarQualidadeImagemProduto(codigo);
        carregarQualidadeNfeList(codigo);
      })();
    }
  }

  if (qualidadeInspecaoModal) qualidadeInspecaoModal.style.display = 'flex';
}

function fecharModalInspecaoQualidade() {
  if (qualidadeInspecaoModal) qualidadeInspecaoModal.style.display = 'none';
  qualidadePirEtqAtualId = null;
  if (qualidadeEtqRecebimentoId) qualidadeEtqRecebimentoId.value = '';
  resetFormularioInspecaoQualidade();
}

async function marcarEtqRecebimentoPir(id) {
  const etqId = Number(id);
  if (!etqId) return;
  const resp = await fetch(`/api/etiquetas/recebimento/${etqId}/pir`, {
    method: 'PATCH',
    headers: { 'Content-Type': 'application/json' },
    credentials: 'include',
    body: JSON.stringify({ pir: true })
  });
  const data = await resp.json().catch(() => ({}));
  if (!resp.ok) throw new Error(data.error || `Falha ao marcar PIR (HTTP ${resp.status})`);
  return data;
}

function formatarCampoTabelaRelatorio(chave, valor) {
  if (valor == null) return '';
  if (typeof valor === 'boolean') return valor ? 'Sim' : 'Não';
  const texto = String(valor);
  if (/data|created|updated|hora|dt_/i.test(chave)) {
    const d = new Date(texto);
    if (!Number.isNaN(d.getTime())) return d.toLocaleString('pt-BR');
  }
  return texto;
}

function renderQualidadeRelatorioTabela(rows = []) {
  if (!qualidadeRelatorioTabelaHead || !qualidadeRelatorioTabelaTbody) return;

  const itens = Array.isArray(rows) ? rows : [];
  if (!itens.length) {
    qualidadeRelatorioTabelaHead.innerHTML = '';
    qualidadeRelatorioTabelaTbody.innerHTML = `
      <tr>
        <td style="padding:16px;text-align:center;color:var(--inactive-color);">Nenhum registro encontrado.</td>
      </tr>
    `;
    return;
  }

  const escapeHtml = (value) => String(value ?? '').replace(/[&<>\"]/g, (ch) => ({
    '&': '&amp;',
    '<': '&lt;',
    '>': '&gt;',
    '"': '&quot;'
  }[ch]));

  const preferidas = [
    'cod_produto', 'descricao_produto', 'nfe', 'frequencia', 'quantidade_ok', 'quantidade_nok', 'created_at'
  ];
  const chavesBase = Object.keys(itens[0] || {});
  const chaves = [
    ...preferidas.filter((k) => chavesBase.includes(k)),
    ...chavesBase.filter((k) => !preferidas.includes(k))
  ];

  qualidadeRelatorioTabelaHead.innerHTML = `
    <tr>
      ${chaves.map((ch) => `<th style="position:sticky;top:0;background:#1f2937;color:#f8fafc;padding:10px;border-bottom:1px solid #334155;text-align:left;white-space:nowrap;">${escapeHtml(ch)}</th>`).join('')}
    </tr>
  `;

  qualidadeRelatorioTabelaTbody.innerHTML = itens.map((row) => `
    <tr>
      ${chaves.map((ch) => `<td style="padding:9px 10px;border-bottom:1px solid #334155;white-space:nowrap;">${escapeHtml(formatarCampoTabelaRelatorio(ch, row?.[ch]))}</td>`).join('')}
    </tr>
  `).join('');
}

async function carregarQualidadeRelatorioTabela() {
  if (!qualidadeRelatorioTabelaTbody) return;
  qualidadeRelatorioTabelaTbody.innerHTML = `
    <tr>
      <td style="padding:14px;color:var(--inactive-color);text-align:center;">
        <i class="fa-solid fa-spinner fa-spin"></i> Carregando tabela...
      </td>
    </tr>
  `;

  const resp = await fetch('/api/qualidade/produtos-liberado', { credentials: 'include' });
  if (!resp.ok) throw new Error(`HTTP ${resp.status}`);
  const data = await resp.json();
  const rows = Array.isArray(data?.itens) ? data.itens : [];
  renderQualidadeRelatorioTabela(rows);
}

function renderQualidadePirLista(itens = []) {
  if (!qualidadePirListaConteudo) return;
  const escapeHtml = (value) => String(value ?? '').replace(/[&<>"]/g, (ch) => ({
    '&': '&amp;',
    '<': '&lt;',
    '>': '&gt;',
    '"': '&quot;'
  }[ch]));
  const formatarFrequencia = (value) => {
    const raw = String(value ?? '').trim();
    if (!raw) return '';
    return raw.includes('%') ? raw : `${raw}%`;
  };
  const lista = Array.isArray(itens) ? itens : [];
  if (!lista.length) {
    qualidadePirListaConteudo.innerHTML = '<div style="color:var(--inactive-color);font-size:13px;">Nenhum plano de inspeção encontrado.</div>';
    if (qualidadeFrequencia) qualidadeFrequencia.value = '';
    return;
  }
  qualidadePirListaConteudo.innerHTML = lista.map((item) => {
    const freq = item?.frequencia ?? '';
    const oQue = item?.o_que_verificar ?? '';
    return `
      <div style="display:grid;grid-template-columns:120px 1fr;gap:10px;align-items:start;">
        <input type="text" value="${escapeHtml(formatarFrequencia(freq))}" readonly style="width:100%;" />
        <textarea rows="2" readonly style="width:100%;resize:vertical;">${escapeHtml(oQue)}</textarea>
      </div>
    `;
  }).join('');
  if (qualidadeFrequencia) {
    const primeiro = lista[0]?.frequencia;
    qualidadeFrequencia.value = primeiro == null ? '' : String(primeiro);
  }
}

function renderQualidadeImagemProduto(url) {
  if (!qualidadeImagemProdutoPlaceholder) return;
  const imageUrl = String(url || '').trim();
  if (!imageUrl) {
    qualidadeImagemProdutoPlaceholder.innerHTML = '<i class="fa-solid fa-image"></i><span>Imagem do produto não encontrada</span>';
    return;
  }
  qualidadeImagemProdutoPlaceholder.innerHTML = `
    <img src="${imageUrl}" alt="Imagem do produto" style="width:100%;max-height:220px;object-fit:contain;border-radius:8px;" />
  `;
}

// Qualidade: exibe estado de carregamento no carretel de imagens
function renderQualidadeCarretelLoading() {
  if (!qualidadeCarretelImagemPlaceholder) return;
  qualidadeCarretelImagemPlaceholder.innerHTML = `
    <div style="display:flex;align-items:center;gap:10px;padding:12px;color:var(--inactive-color);">
      <i class="fa-solid fa-spinner fa-spin"></i>
      <span>Carregando imagens...</span>
    </div>
  `;
}

// Qualidade: popula listbox de NFe no mesmo formato do Pesquisar produto
function renderQualidadeNfeList(itens = []) {
  if (!qualidadeNfeLista || !qualidadeNfe) return;
  const lista = Array.isArray(itens) ? itens : [];
  if (!lista.length) {
    qualidadeNfeLista.innerHTML = '<li style="padding:6px 10px;color:#e5e7eb;">Nenhum resultado</li>';
    qualidadeNfeLista.style.display = 'block';
    return;
  }
  qualidadeNfeLista.innerHTML = lista.map((nfe) => {
    const valor = String(nfe || '').trim();
    if (!valor) return '';
    return `
      <li data-nfe="${valor}" style="padding:8px 12px;cursor:pointer;border-bottom:1px solid #1f2937;line-height:1.2;color:#f9fafb;background:#0f172a;height:auto;display:block;align-items:initial;font-size:13px;">
        <div style="font-weight:700;font-size:13px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${valor}</div>
        <div style="font-size:12px;color:#d1d5db;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">NFe localizada</div>
      </li>
    `;
  }).join('');
  qualidadeNfeLista.style.display = 'block';

  qualidadeNfeLista.querySelectorAll('li').forEach((li) => {
    li.addEventListener('mousedown', () => {
      qualidadeNfe.value = li.dataset.nfe || '';
      qualidadeNfeLista.style.display = 'none';
    });
    li.addEventListener('mouseenter', () => { li.style.background = '#1f2937'; });
    li.addEventListener('mouseleave', () => { li.style.background = '#0f172a'; });
  });
}

// Qualidade: busca as 3 NFe mais recentes para o produto
async function carregarQualidadeNfeList(codigoProduto) {
  if (!codigoProduto) {
    renderQualidadeNfeList([]);
    return;
  }
  try {
    const resp = await fetch(`/api/qualidade/nfe-por-produto/${encodeURIComponent(codigoProduto)}`, { credentials: 'include' });
    if (!resp.ok) throw new Error(`HTTP ${resp.status}`);
    const data = await resp.json();
    const itens = Array.isArray(data?.itens) ? data.itens : [];
    renderQualidadeNfeList(itens);
  } catch (err) {
    console.error('[QUALIDADE] falha ao carregar NFe', err);
    renderQualidadeNfeList([]);
  }
}

// Qualidade: fecha listbox de NFe ao clicar fora
document.addEventListener('click', (e) => {
  if (!qualidadeNfeLista || !qualidadeNfe) return;
  if (qualidadeNfeLista.contains(e.target) || e.target === qualidadeNfe) return;
  qualidadeNfeLista.style.display = 'none';
});

// Qualidade: abre imagem do PIR em tela cheia
function openQualidadePirModal({ url, titulo, frequencia, oQue }) {
  const overlay = document.createElement('div');
  overlay.style.position = 'fixed';
  overlay.style.inset = '0';
  overlay.style.background = 'rgba(0,0,0,0.85)';
  overlay.style.display = 'flex';
  overlay.style.alignItems = 'center';
  overlay.style.justifyContent = 'center';
  overlay.style.zIndex = '9999';

  const wrap = document.createElement('div');
  wrap.style.maxWidth = '92vw';
  wrap.style.maxHeight = '92vh';
  wrap.style.display = 'flex';
  wrap.style.flexDirection = 'column';
  wrap.style.alignItems = 'center';
  wrap.style.gap = '12px';

  const img = document.createElement('img');
  img.src = url;
  img.alt = titulo || 'Imagem PIR';
  img.style.maxWidth = '92vw';
  img.style.maxHeight = '80vh';
  img.style.objectFit = 'contain';
  img.style.borderRadius = '10px';
  img.style.background = '#000';

  const caption = document.createElement('div');
  caption.style.color = '#e5e7eb';
  caption.style.textAlign = 'center';
  caption.style.fontSize = '14px';
  caption.innerHTML = `
    <div style="color:#cbd5f5;">Frequência: ${frequencia || '—'} | O que verificar: ${oQue || '—'}</div>
  `;

  wrap.appendChild(img);
  wrap.appendChild(caption);
  overlay.appendChild(wrap);
  overlay.addEventListener('click', () => document.body.removeChild(overlay));
  document.body.appendChild(overlay);
}

function renderQualidadeCarretelPir(itens = []) {
  // Qualidade: galeria responsiva com texto por foto
  if (!qualidadeCarretelImagemPlaceholder) return;
  const lista = Array.isArray(itens) ? itens : [];
  const itensComFoto = lista
    .map((item, index) => ({
      index,
      foto_url: String(item?.foto_url || '').trim(),
      frequencia: item?.frequencia ?? '',
      o_que_verificar: item?.o_que_verificar ?? ''
    }))
    .filter(item => item.foto_url);

  if (!itensComFoto.length) {
    qualidadeCarretelImagemPlaceholder.innerHTML = '<i class="fa-solid fa-film"></i><span>Sem imagens no carretel</span>';
    return;
  }

  const escapeHtml = (value) => String(value ?? '').replace(/[&<>"]/g, (ch) => ({
    '&': '&amp;',
    '<': '&lt;',
    '>': '&gt;',
    '"': '&quot;'
  }[ch]));
  const formatarFrequencia = (value) => {
    const raw = String(value ?? '').trim();
    if (!raw) return '';
    return raw.includes('%') ? raw : `${raw}%`;
  };

  qualidadeCarretelImagemPlaceholder.innerHTML = `
    <div class="qualidade-pir-galeria">
      ${itensComFoto.map((item, i) => {
        const freq = formatarFrequencia(item.frequencia) || '—';
        const oQue = String(item.o_que_verificar || '').trim() || 'Sem descrição';
        return `
          <div class="qualidade-pir-card" data-index="${i}">
            <div class="qualidade-pir-img-wrap" data-index="${i}">
              <img class="qualidade-pir-img" src="${escapeHtml(item.foto_url)}" alt="Foto PIR ${i + 1}" loading="lazy" />
              <div class="qualidade-pir-frequencia-badge">Freq: ${escapeHtml(freq)}</div>
            </div>
            <div class="qualidade-pir-oque-box">
              <div class="qualidade-pir-oque-title">O que verificar</div>
              <div class="qualidade-pir-oque-text">${escapeHtml(oQue)}</div>
            </div>
          </div>
        `;
      }).join('')}
    </div>
  `;

  const galeria = qualidadeCarretelImagemPlaceholder.querySelector('.qualidade-pir-galeria');
  if (!galeria) return;
  galeria.querySelectorAll('.qualidade-pir-img-wrap').forEach((opt) => {
    opt.addEventListener('click', () => {
      const idx = Number(opt.dataset.index || 0);
      const item = itensComFoto[idx];
      if (item?.foto_url) {
        const freq = formatarFrequencia(item.frequencia) || '—';
        const oQue = String(item.o_que_verificar || '').trim() || '—';
        openQualidadePirModal({
          url: item.foto_url,
          titulo: '',
          frequencia: freq,
          oQue
        });
      }
    });
  });
}

async function carregarQualidadeImagemProduto(codigoProduto) {
  if (!codigoProduto) {
    renderQualidadeImagemProduto('');
    return;
  }
  try {
    const resp = await fetch(`/api/produtos/imagem/${encodeURIComponent(codigoProduto)}`, { credentials: 'include' });
    if (!resp.ok) throw new Error(`HTTP ${resp.status}`);
    const data = await resp.json();
    renderQualidadeImagemProduto(data?.url_imagem || '');
  } catch (err) {
    console.error('[QUALIDADE] falha ao carregar imagem do produto', err);
    renderQualidadeImagemProduto('');
  }
}

async function carregarQualidadePirItens(idOmie) {
  if (!idOmie) {
    renderQualidadePirLista([]);
    renderQualidadeCarretelPir([]);
    return;
  }
  renderQualidadeCarretelLoading();
  try {
    const resp = await fetch(`/api/pir/${encodeURIComponent(idOmie)}`, { credentials: 'include' });
    if (!resp.ok) {
      throw new Error(`HTTP ${resp.status}`);
    }
    const data = await resp.json();
    renderQualidadePirLista(data);
    renderQualidadeCarretelPir(data);
  } catch (err) {
    console.error('[QUALIDADE] falha ao carregar PIR', err);
    if (qualidadeFrequencia) qualidadeFrequencia.value = '';
    renderQualidadeCarretelPir([]);
  }
}

function abrirFormularioInspecaoQualidade() {
  abrirModalInspecaoQualidade(null);
}

function fecharFormularioInspecaoQualidade() {
  fecharModalInspecaoQualidade();
}

// Qualidade: limpa campos do registro de inspeção
function resetFormularioInspecaoQualidade() {
  if (qualidadeProdutoBusca) qualidadeProdutoBusca.value = '';
  if (qualidadeCodProduto) qualidadeCodProduto.value = '';
  if (qualidadeDescricaoProduto) qualidadeDescricaoProduto.value = '';
  if (qualidadeNfe) qualidadeNfe.value = '';
  if (qualidadeQuantidadeOk) qualidadeQuantidadeOk.value = '';
  if (qualidadeQuantidadeNok) qualidadeQuantidadeNok.value = '';
  if (qualidadeCodigoProdutoReal) qualidadeCodigoProdutoReal.value = '';
  if (qualidadeFrequencia) qualidadeFrequencia.value = '';
  if (qualidadeProdutoCustomizadoCheck) {
    qualidadeProdutoCustomizadoCheck.checked = false;
    qualidadeProdutoCustomizadoCheck.disabled = false;
  }
  renderQualidadeImagemProduto('');
  renderQualidadeCarretelPir([]);
  renderQualidadeNfeList([]);
  if (qualidadeNfeLista) qualidadeNfeLista.style.display = 'none';
}

