function normalizeAtWhatsappPhone(value) {
  return String(value || '').replace(/\D/g, '');
}

function formatAtWhatsappTimestamp(value, options) {
  if (!value) return '-';
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return String(value);
  return date.toLocaleString('pt-BR', options || {
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit'
  });
}

function formatAtWhatsappConversationTime(value) {
  if (!value) return '-';
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return String(value);

  const now = new Date();
  const sameDay = date.toDateString() === now.toDateString();
  return sameDay
    ? date.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })
    : date.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' });
}

function formatAtWhatsappPhoneDisplay(value) {
  const digits = normalizeAtWhatsappPhone(value);
  if (!digits) return '';
  if (digits.length === 13 && digits.startsWith('55')) {
    return `+55 ${digits.slice(2, 4)} ${digits.slice(4, 9)}-${digits.slice(9)}`;
  }
  if (digits.length === 12 && digits.startsWith('55')) {
    return `+55 ${digits.slice(2, 4)} ${digits.slice(4, 8)}-${digits.slice(8)}`;
  }
  if (digits.length === 11) {
    return `(${digits.slice(0, 2)}) ${digits.slice(2, 7)}-${digits.slice(7)}`;
  }
  if (digits.length === 10) {
    return `(${digits.slice(0, 2)}) ${digits.slice(2, 6)}-${digits.slice(6)}`;
  }
  return String(value || digits);
}

function setAtWhatsappMessagesStatus(text = '', isError = false) {
  if (!atWhatsappMessagesStatus) return;
  atWhatsappMessagesStatus.style.color = isError ? '#f87171' : 'var(--inactive-color)';
  atWhatsappMessagesStatus.textContent = text || '';
}

function isAtWhatsappLightMode() {
  return document.documentElement.classList.contains('light-mode');
}

function setAtWhatsappReplyStatus(text = '', isError = false) {
  if (!atWhatsappReplyStatus) return;
  atWhatsappReplyStatus.style.color = isError ? '#f87171' : 'var(--inactive-color)';
  atWhatsappReplyStatus.textContent = text || '';
}

function shouldShowAtWhatsappFollowUps(row) {
  const text = String(row?.message_text || '').trim();
  if (!text) return false;
  if (String(row?.direction || '').trim() !== 'outbound') return false;
  if (!/chatbot/i.test(String(row?.profile_name || '').trim())) return false;
  if (/^⚠/.test(text)) return false;
  return /\bfonte:/i.test(text) || /\bmanual\b/i.test(text);
}

function buildAtWhatsappFollowUpChoices(row) {
  if (!shouldShowAtWhatsappFollowUps(row)) return [];
  const text = String(row?.message_text || '').trim().toLowerCase();
  const choices = [
    { label: 'Me envie o manual', message: 'Me envie o manual completo desse equipamento' },
    { label: 'Me envie a parte do manual', message: 'Me envie a parte do manual que fala disso' },
    { label: 'Me envie uma imagem', message: 'Me envie uma imagem da parte do manual que fala disso' }
  ];
  if (text.includes('pagina') || text.includes('página') || text.includes('fonte')) {
    choices.push({ label: 'Qual a página disso?', message: 'Qual a página do manual que fala disso?' });
  } else {
    choices.push({ label: 'Continuar no mesmo contexto', action: 'continue_context' });
  }
  return choices.slice(0, 4);
}

function renderAtWhatsappPreviewCards(row) {
  const isLight = isAtWhatsappLightMode();
  const payload = row?.payload_json && typeof row.payload_json === 'object' ? row.payload_json : {};
  const previewList = Array.isArray(payload?.manualPreviews)
    ? payload.manualPreviews.filter((item) => item && (item.openUrl || item.sourceUrl || item.imageUrl)).slice(0, 2)
    : [];

  const fallbackList = [];
  const requestBody = payload?.__meta?.request_body && typeof payload.__meta.request_body === 'object'
    ? payload.__meta.request_body
    : {};

  if (!previewList.length && requestBody?.document?.link) {
    fallbackList.push({
      manual: requestBody?.document?.filename || 'Manual Fromtherm',
      page: '',
      openUrl: requestBody.document.link
    });
  }
  if (!previewList.length && requestBody?.image?.link) {
    fallbackList.push({
      manual: requestBody?.image?.caption || 'Imagem do manual',
      page: '',
      imageUrl: requestBody.image.link
    });
  }

  const finalList = (previewList.length ? previewList : fallbackList).slice(0, 2);
  if (!finalList.length) return '';

  return `
    <div style="display:flex;flex-direction:column;gap:8px;margin-top:10px;">
      ${finalList.map((preview) => {
        const title = escapeAtHtml(String(preview.manual || 'Manual').trim() || 'Manual');
        const page = escapeAtHtml(String(preview.page || '').trim());
        const openUrl = escapeAtHtml(String(preview.openUrl || preview.sourceUrl || '').trim());
        const imageUrl = escapeAtHtml(String(preview.imageUrl || '').trim());
        return `
          <div style="padding:10px;border:1px solid ${isLight ? 'rgba(15,23,42,.12)' : 'rgba(255,255,255,.08)'};border-radius:10px;background:${isLight ? 'rgba(255,255,255,.82)' : 'rgba(255,255,255,.03)'};">
            <div style="font-size:12px;font-weight:700;color:${isLight ? '#0f172a' : '#e5e7eb'};">${title}</div>
            <div style="font-size:11px;color:${isLight ? '#64748b' : 'var(--inactive-color)'};margin-top:2px;">${page ? `Página ${page}` : 'Manual compartilhado pelo chatbot'}</div>
            <div style="display:flex;flex-wrap:wrap;gap:8px;margin-top:8px;">
              ${openUrl ? `<a href="${openUrl}" target="_blank" rel="noopener noreferrer" style="display:inline-flex;align-items:center;gap:6px;padding:6px 10px;border-radius:999px;border:1px solid rgba(14,165,233,.28);background:${isLight ? 'rgba(224,242,254,.95)' : 'rgba(14,165,233,.12)'};color:${isLight ? '#075985' : '#bae6fd'};font-size:11px;font-weight:600;text-decoration:none;">Abrir manual</a>` : ''}
              ${imageUrl ? `<a href="${imageUrl}" target="_blank" rel="noopener noreferrer" style="display:inline-flex;align-items:center;gap:6px;padding:6px 10px;border-radius:999px;border:1px solid rgba(16,185,129,.28);background:${isLight ? 'rgba(220,252,231,.95)' : 'rgba(16,185,129,.12)'};color:${isLight ? '#065f46' : '#d1fae5'};font-size:11px;font-weight:600;text-decoration:none;">Abrir imagem</a>` : ''}
            </div>
          </div>`;
      }).join('')}
    </div>
  `;
}

function renderAtWhatsappChoiceButtons(row) {
  const isLight = isAtWhatsappLightMode();
  const choices = buildAtWhatsappFollowUpChoices(row);
  if (!choices.length) return '';
  return `
    <div style="display:flex;flex-wrap:wrap;gap:8px;margin-top:10px;">
      ${choices.map((choice) => `
        <button
          type="button"
          class="at-wa-choice-btn"
          ${choice.message ? `data-at-wa-chat-msg="${escapeAtHtml(choice.message)}"` : ''}
          ${choice.action ? `data-at-wa-chat-action="${escapeAtHtml(choice.action)}"` : ''}
          style="padding:6px 10px;border-radius:999px;border:1px solid rgba(125,211,252,.24);background:${isLight ? 'rgba(224,242,254,.95)' : 'rgba(14,165,233,.12)'};color:${isLight ? '#075985' : '#dbeafe'};font-size:11px;font-weight:600;cursor:pointer;">
          ${escapeAtHtml(choice.label)}
        </button>
      `).join('')}
    </div>
  `;
}

function handleAtWhatsappConversationAction(action) {
  const acao = String(action || '').trim();
  if (acao !== 'continue_context') return;
  if (atWhatsappReplyInput) {
    atWhatsappReplyInput.placeholder = 'Continue perguntando sobre esse mesmo equipamento';
    atWhatsappReplyInput.focus();
  }
}

async function sendAtWhatsappChatbotPrompt(prompt) {
  const phone = atWhatsappSelectedPhone;
  const text = String(prompt || '').trim();
  if (!phone || !text) return;

  setAtWhatsappReplyStatus('Gerando resposta do chatbot...', false);
  if (atWhatsappReplyBtn) atWhatsappReplyBtn.disabled = true;

  try {
    const resp = await fetch('/api/sac/whatsapp/reply', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({
        phone,
        text,
        mode: 'chatbot'
      })
    });
    const data = await resp.json().catch(() => ({}));
    if (!resp.ok || data.ok === false) {
      throw new Error(data.error || 'Falha ao enviar resposta automática.');
    }
    setAtWhatsappReplyStatus('Resposta do chatbot enviada.', false);
    await carregarAtWhatsappConversations({ silent: true });
    await carregarAtWhatsappMessages({ phone, silent: true });
  } catch (err) {
    console.error('[SAC/WhatsApp] erro ao acionar resposta do chatbot', err);
    setAtWhatsappReplyStatus(err?.message || 'Erro ao acionar o chatbot.', true);
  } finally {
    syncAtWhatsappReplyBoxState();
  }
}

function syncAtWhatsappReplyBoxState() {
  const hasConversation = Boolean(atWhatsappSelectedPhone);
  const hasText = Boolean(String(atWhatsappReplyInput?.value || '').trim());

  if (atWhatsappReplyInput) {
    atWhatsappReplyInput.disabled = !hasConversation;
    atWhatsappReplyInput.placeholder = hasConversation
      ? 'Digite a resposta para este contato...'
      : 'Abra uma conversa para responder.';
  }

  if (atWhatsappReplyBtn) {
    atWhatsappReplyBtn.disabled = !hasConversation || !hasText;
    atWhatsappReplyBtn.style.opacity = (!hasConversation || !hasText) ? '.6' : '1';
    atWhatsappReplyBtn.style.cursor = (!hasConversation || !hasText) ? 'not-allowed' : 'pointer';
  }

  if (!hasConversation) {
    setAtWhatsappReplyStatus('Abra uma conversa para responder.', false);
  } else if (!hasText) {
    setAtWhatsappReplyStatus('Campo de resposta pronto para integrar o envio.', false);
  } else {
    setAtWhatsappReplyStatus('Resposta pronta para envio.', false);
  }
}

function setAtWhatsappInboxStatus(text = '', isError = false) {
  if (!atWhatsappInboxStatus) return;
  atWhatsappInboxStatus.style.color = isError ? '#f87171' : 'var(--inactive-color)';
  atWhatsappInboxStatus.textContent = text || '';
}

function syncAtWhatsappInboxCount(count = 0) {
  if (!atWhatsappInboxCount) return;
  const safeCount = Number.isFinite(Number(count)) ? Number(count) : 0;
  atWhatsappInboxCount.textContent = String(safeCount);
  atWhatsappInboxCount.style.opacity = safeCount > 0 ? '1' : '.55';
  if (atWhatsappTopBadge) {
    atWhatsappTopBadge.textContent = String(safeCount);
    atWhatsappTopBadge.style.display = safeCount > 0 ? 'flex' : 'none';
  }
}

function syncAtWhatsappConversationCount(count = 0) {
  if (!atWhatsappConversationCount) return;
  atWhatsappConversationCount.textContent = String(Number.isFinite(Number(count)) ? count : 0);
}

function getAtWhatsappConversationMeta(phone) {
  const phoneDigits = normalizeAtWhatsappPhone(phone);
  return atWhatsappConversationRows.find((row) => normalizeAtWhatsappPhone(row.from_phone_digits || row.from_phone) === phoneDigits) || null;
}

function isAtWhatsappConversationSeen(row) {
  const phoneDigits = normalizeAtWhatsappPhone(row?.from_phone_digits || row?.from_phone);
  if (!phoneDigits) return false;
  
  const lastReadAt = new Date(row?.last_read_at || 0).getTime();
  const lastReceivedAt = new Date(row?.last_received_at || 0).getTime();
  
  if (!Number.isFinite(lastReceivedAt) || lastReceivedAt <= 0) return lastReadAt > 0;
  return lastReadAt >= lastReceivedAt;
}

function getAtWhatsappFilteredRows() {
  if (!Array.isArray(atWhatsappConversationRows)) return [];
  if (atWhatsappConversationFilter === 'lidos') {
    return atWhatsappConversationRows.filter((row) => isAtWhatsappConversationSeen(row));
  }
  if (atWhatsappConversationFilter === 'nao_lidos') {
    return atWhatsappConversationRows.filter((row) => !isAtWhatsappConversationSeen(row));
  }
  return atWhatsappConversationRows;
}

function syncAtWhatsappFilterButtons() {
  const map = [
    [atWhatsappFilterTodosBtn, 'todos'],
    [atWhatsappFilterLidosBtn, 'lidos'],
    [atWhatsappFilterNaoLidosBtn, 'nao_lidos']
  ];
  map.forEach(([btn, value]) => {
    if (!btn) return;
    if (value === atWhatsappConversationFilter) btn.classList.add('active');
    else btn.classList.remove('active');
  });
}

function getAtWhatsappConversationDisplayName(meta = null) {
  const phoneLabel = formatAtWhatsappPhoneDisplay(meta?.from_phone_digits || meta?.from_phone);
  return String(meta?.contact_name || meta?.profile_name || '').trim() || phoneLabel || 'Contato';
}

function showAtWhatsappInboxListView() {
  if (atWhatsappInboxListView) atWhatsappInboxListView.style.display = 'block';
  if (atWhatsappConversationView) atWhatsappConversationView.style.display = 'none';
  atWhatsappSelectedPhone = '';
  syncAtWhatsappReplyBoxState();
}

function showAtWhatsappConversationView(meta = null, messageCount = null) {
  if (atWhatsappInboxListView) atWhatsappInboxListView.style.display = 'block';
  if (atWhatsappConversationView) atWhatsappConversationView.style.display = 'flex';

  const profileName = getAtWhatsappConversationDisplayName(meta);
  const subtitle = formatAtWhatsappPhoneDisplay(meta?.from_phone_digits || meta?.from_phone) || 'Sem número';

  if (atWhatsappConversationTitle) atWhatsappConversationTitle.textContent = profileName;
  if (atWhatsappConversationSubtitle) atWhatsappConversationSubtitle.textContent = subtitle;
  syncAtWhatsappConversationCount(messageCount ?? Number(meta?.total_messages || 0));
  syncAtWhatsappReplyBoxState();
}

function renderAtWhatsappConversationRows(rows = []) {
  if (!atWhatsappInboxList) return;
  const safeRows = Array.isArray(rows) ? rows : [];
  const filteredRows = getAtWhatsappFilteredRows();
  const isLight = isAtWhatsappLightMode();
  const unseenCount = safeRows.reduce((acc, row) => acc + (isAtWhatsappConversationSeen(row) ? 0 : 1), 0);

  syncAtWhatsappInboxCount(unseenCount);
  syncAtWhatsappFilterButtons();

  if (!filteredRows.length) {
    atWhatsappInboxList.innerHTML = `<div style="padding:12px;border:1px dashed ${isLight ? 'rgba(15,23,42,.14)' : 'rgba(255,255,255,.12)'};border-radius:12px;color:${isLight ? '#475569' : 'var(--inactive-color)'};background:${isLight ? 'rgba(255,255,255,.76)' : 'transparent'};font-size:12px;">Nenhuma conversa para este filtro.</div>`;
    const filtroLabel = atWhatsappConversationFilter === 'lidos'
      ? 'Lidos'
      : (atWhatsappConversationFilter === 'nao_lidos' ? 'Nao lidos' : 'Todos');
    setAtWhatsappInboxStatus(`Filtro: ${filtroLabel} · ${filteredRows.length} conversa(s).`, false);
    return;
  }

  atWhatsappInboxList.innerHTML = filteredRows.map((row) => {
    const phoneDigits = normalizeAtWhatsappPhone(row.from_phone_digits || row.from_phone);
    const profileName = escapeAtHtml(getAtWhatsappConversationDisplayName(row));
    const phoneLabel = escapeAtHtml(formatAtWhatsappPhoneDisplay(phoneDigits) || String(row.from_phone || '').trim() || 'Sem numero');
    const previewBase = String(row.last_message_text || '').trim() || `[mensagem do tipo ${String(row.last_message_type || 'message').trim() || 'message'}]`;
    const previewText = escapeAtHtml((String(row.last_direction || '').trim() === 'outbound' ? `Voce: ${previewBase}` : previewBase));
    const when = escapeAtHtml(formatAtWhatsappConversationTime(row.last_received_at));
    const activeClass = phoneDigits && phoneDigits === atWhatsappSelectedPhone ? ' active' : '';
    const seen = isAtWhatsappConversationSeen(row);
    return `
      <button type="button" class="at-wa-conversation-item${activeClass}" data-phone="${escapeAtHtml(phoneDigits)}">
        <div style="display:flex;justify-content:space-between;gap:10px;align-items:flex-start;margin-bottom:6px;">
          <div style="min-width:0;">
            <div style="font-size:13px;font-weight:700;color:${isLight ? '#0f172a' : '#e5e7eb'};white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${profileName}</div>
            <div style="font-size:11px;color:${isLight ? '#64748b' : 'var(--inactive-color)'};margin-top:2px;">${phoneLabel}</div>
          </div>
          <div style="display:flex;flex-direction:column;align-items:flex-end;gap:6px;flex-shrink:0;">
            <span style="font-size:11px;color:${isLight ? '#64748b' : 'var(--inactive-color)'};">${when}</span>
            ${seen ? '' : '<span style="width:8px;height:8px;border-radius:999px;background:#22c55e;display:inline-block;"></span>'}
          </div>
        </div>
        <div style="font-size:12px;color:${isLight ? '#334155' : '#cbd5e1'};white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${previewText}</div>
      </button>`;
  }).join('');

  atWhatsappInboxList.querySelectorAll('[data-phone]').forEach((btn) => {
    btn.addEventListener('click', () => {
      selecionarAtWhatsappConversation(btn.getAttribute('data-phone') || '', { syncField: true, silent: false });
    });
  });

  const filtroLabel = atWhatsappConversationFilter === 'lidos'
    ? 'Lidos'
    : (atWhatsappConversationFilter === 'nao_lidos' ? 'Nao lidos' : 'Todos');
  setAtWhatsappInboxStatus(`Filtro: ${filtroLabel} · ${filteredRows.length} conversa(s).`, false);
}

function renderAtWhatsappMessages(rows = []) {
  if (!atWhatsappMessagesList) return;
  const isLight = isAtWhatsappLightMode();
  if (!Array.isArray(rows) || !rows.length) {
    atWhatsappMessagesList.innerHTML = `<div style="padding:10px 12px;border:1px dashed ${isLight ? 'rgba(15,23,42,.14)' : 'rgba(255,255,255,.12)'};border-radius:10px;color:${isLight ? '#475569' : 'var(--inactive-color)'};background:${isLight ? 'rgba(255,255,255,.76)' : 'transparent'};font-size:12px;">Nenhuma mensagem recebida para esta conversa ainda.</div>`;
    return;
  }

  // Encontrar o índice da última mensagem outbound do chatbot para só mostrar botões nela
  let lastChatbotOutboundIdx = -1;
  for (let i = rows.length - 1; i >= 0; i--) {
    if (String(rows[i].direction || '').trim() === 'outbound' && /chatbot/i.test(String(rows[i].profile_name || '').trim())) {
      lastChatbotOutboundIdx = i;
      break;
    }
  }

  atWhatsappMessagesList.innerHTML = rows.map((row, idx) => {
    const isOutbound = String(row.direction || '').trim() === 'outbound';
    const profileName = escapeAtHtml(String(row.profile_name || '').trim() || (isOutbound ? 'Atendimento' : 'Contato'));
    const messageType = escapeAtHtml(String(row.message_type || '').trim() || 'message');
    const text = escapeAtHtml(String(row.message_text || '').trim() || `[mensagem do tipo ${messageType}]`);
    const when = escapeAtHtml(formatAtWhatsappTimestamp(row.received_at));
    const fromPhone = escapeAtHtml(formatAtWhatsappPhoneDisplay(row.from_phone || row.from_phone_digits) || String(row.from_phone || '').trim() || '');
    const borderColor = isOutbound ? 'rgba(14,165,233,.28)' : 'rgba(16,185,129,.18)';
    const bgColor = isLight
      ? (isOutbound ? 'linear-gradient(180deg, rgba(224,242,254,.95) 0%, rgba(240,249,255,.95) 100%)' : 'linear-gradient(180deg, rgba(236,253,245,.95) 0%, rgba(240,253,250,.95) 100%)')
      : (isOutbound ? 'rgba(14,165,233,.08)' : 'rgba(16,185,129,.05)');
    const titleColor = isLight ? (isOutbound ? '#0369a1' : '#047857') : (isOutbound ? '#7dd3fc' : '#d1fae5');
    const metaColor = isLight ? '#64748b' : 'var(--inactive-color)';
    const textColor = isLight ? '#0f172a' : 'var(--content-title-color)';
    const shadow = isLight ? 'box-shadow:0 6px 16px rgba(15,23,42,.05);' : '';
    const alignStyle = isOutbound ? 'margin-left:18px;' : 'margin-right:18px;';
    const originLabel = isOutbound ? 'saída' : (fromPhone || 'sem número');
    const previewCards = renderAtWhatsappPreviewCards(row);
    const choiceButtons = idx === lastChatbotOutboundIdx ? renderAtWhatsappChoiceButtons(row) : '';
    return `
      <div style="padding:10px 12px;border:1px solid ${borderColor};border-radius:10px;background:${bgColor};${alignStyle}${shadow}">
        <div style="display:flex;justify-content:space-between;gap:10px;align-items:center;margin-bottom:6px;">
          <strong style="font-size:12px;color:${titleColor};">${profileName}</strong>
          <span style="font-size:11px;color:${metaColor};">${when}</span>
        </div>
        <div style="font-size:11px;color:${metaColor};margin-bottom:6px;">${originLabel} · ${messageType}</div>
        <div style="font-size:13px;color:${textColor};white-space:pre-wrap;">${text}</div>
        ${previewCards}
        ${choiceButtons}
      </div>`;
  }).join('');

  atWhatsappMessagesList.scrollTop = atWhatsappMessagesList.scrollHeight;

  atWhatsappMessagesList.querySelectorAll('[data-at-wa-chat-msg]').forEach((btn) => {
    btn.addEventListener('click', () => {
      sendAtWhatsappChatbotPrompt(btn.getAttribute('data-at-wa-chat-msg') || '');
    });
  });
  atWhatsappMessagesList.querySelectorAll('[data-at-wa-chat-action]').forEach((btn) => {
    btn.addEventListener('click', () => {
      handleAtWhatsappConversationAction(btn.getAttribute('data-at-wa-chat-action') || '');
    });
  });
}

async function selecionarAtWhatsappConversation(phone, { syncField = true, silent = false } = {}) {
  const phoneDigits = normalizeAtWhatsappPhone(phone);
  if (!phoneDigits) return;
  const meta = getAtWhatsappConversationMeta(phoneDigits);
  atWhatsappSelectedPhone = phoneDigits;
  atWhatsappMessagesLastPhone = phoneDigits;
  
  try {
    await fetch('/api/sac/whatsapp/mark-read', {
      method: 'POST',
      credentials: 'include',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ phone_digits: phoneDigits })
    });
  } catch (err) {
    console.warn('[SAC/WhatsApp] erro ao marcar como lido:', err);
  }
  
  atWhatsappConversationState.set(phoneDigits, { last_read_at: new Date().toISOString() });

  if (syncField && atTelefoneInput) {
    atTelefoneInput.value = formatAtWhatsappPhoneDisplay(phoneDigits);
  }

  renderAtWhatsappConversationRows(atWhatsappConversationRows);
  showAtWhatsappConversationView(meta);
  carregarAtWhatsappMessages({ phone: phoneDigits, silent });
}

async function carregarAtWhatsappMessages({ phone = null, silent = false } = {}) {
  const phoneDigits = normalizeAtWhatsappPhone(phone ?? atTelefoneInput?.value);
  atWhatsappMessagesLastPhone = phoneDigits;
  if (phoneDigits) atWhatsappSelectedPhone = phoneDigits;
  if (atWhatsappConversationRows.length) renderAtWhatsappConversationRows(atWhatsappConversationRows);

  if (!silent) setAtWhatsappMessagesStatus('Consultando mensagens recebidas...', false);

  try {
    const url = phoneDigits
      ? `/api/sac/whatsapp/messages?phone=${encodeURIComponent(phoneDigits)}`
      : '/api/sac/whatsapp/messages';
    const resp = await fetch(url, { credentials: 'include' });
    const data = await resp.json().catch(() => ({}));
    if (!resp.ok || data.ok === false) {
      throw new Error(data.error || 'Falha ao consultar mensagens do WhatsApp.');
    }
    const rows = Array.isArray(data.messages) ? data.messages : [];
    renderAtWhatsappMessages(rows);
    if (phoneDigits) {
      showAtWhatsappConversationView(getAtWhatsappConversationMeta(phoneDigits), rows.length);
      setAtWhatsappMessagesStatus(
        rows.length
          ? `Exibindo ${rows.length} mensagem(ns) de ${formatAtWhatsappPhoneDisplay(phoneDigits) || phoneDigits}.`
          : `Nenhuma mensagem recebida ainda para ${formatAtWhatsappPhoneDisplay(phoneDigits) || phoneDigits}.`,
        false
      );
      return;
    }
    setAtWhatsappMessagesStatus(
      rows.length
        ? `Exibindo as ${rows.length} mensagem(ns) mais recentes recebidas no webhook.`
        : 'Nenhuma mensagem recebida no webhook ainda.',
      false
    );
  } catch (err) {
    console.error('[SAC/WhatsApp] erro ao carregar mensagens', err);
    renderAtWhatsappMessages([]);
    setAtWhatsappMessagesStatus(err?.message || 'Erro ao consultar mensagens do WhatsApp.', true);
  }
}

async function carregarAtWhatsappConversations({ silent = false } = {}) {
  // Sincronizar estado de leitura com dados do servidor
  if (!silent) setAtWhatsappInboxStatus('Consultando conversas recebidas...', false);

  try {
    const resp = await fetch('/api/sac/whatsapp/conversations', { credentials: 'include' });
    const data = await resp.json().catch(() => ({}));
    if (!resp.ok || data.ok === false) {
      throw new Error(data.error || 'Falha ao consultar conversas do WhatsApp.');
    }

    const rows = Array.isArray(data.conversations) ? data.conversations : [];
    atWhatsappConversationRows = rows;
    // Sincronizar estado de leitura do servidor com mapa local
    rows.forEach(row => {
      const phoneDigits = normalizeAtWhatsappPhone(row?.from_phone_digits || row?.from_phone);
      if (phoneDigits) {
        atWhatsappConversationState.set(phoneDigits, {
          last_read_at: row.last_read_at
        });
      }
    });
    
    renderAtWhatsappConversationRows(rows);

    if (!rows.length) {
      atWhatsappSelectedPhone = '';
      atWhatsappMessagesLastPhone = '';
      renderAtWhatsappMessages([]);
      setAtWhatsappInboxStatus('Nenhuma conversa recebida no webhook ainda.', false);
      setAtWhatsappMessagesStatus('Aguardando uma primeira conversa no WhatsApp.', false);
      showAtWhatsappInboxListView();
      return;
    }

    if (!atWhatsappSelectedPhone) {
      showAtWhatsappInboxListView();
      return;
    }

    const selectedExists = rows.some((row) => normalizeAtWhatsappPhone(row.from_phone_digits || row.from_phone) === atWhatsappSelectedPhone);
    if (!selectedExists) {
      atWhatsappSelectedPhone = '';
      atWhatsappMessagesLastPhone = '';
      renderAtWhatsappMessages([]);
      showAtWhatsappInboxListView();
      setAtWhatsappMessagesStatus('A conversa selecionada não está mais disponível.', false);
      return;
    }

    if (atWhatsappConversationView && atWhatsappConversationView.style.display !== 'none') {
      showAtWhatsappConversationView(getAtWhatsappConversationMeta(atWhatsappSelectedPhone));
      carregarAtWhatsappMessages({ phone: atWhatsappSelectedPhone, silent: true });
    }
  } catch (err) {
    console.error('[SAC/WhatsApp] erro ao carregar conversas', err);
    atWhatsappConversationRows = [];
    renderAtWhatsappConversationRows([]);
    setAtWhatsappInboxStatus(err?.message || 'Erro ao consultar conversas do WhatsApp.', true);
  }
}

function setAtWhatsappConversationFilter(filterValue = 'todos') {
  const allowed = new Set(['todos', 'lidos', 'nao_lidos']);
  atWhatsappConversationFilter = allowed.has(filterValue) ? filterValue : 'todos';
  renderAtWhatsappConversationRows(atWhatsappConversationRows);
}

function openAtWhatsappModal() {
  if (!atWhatsappModal) return;
  atWhatsappModal.style.display = 'flex';
  showAtWhatsappInboxListView();
  carregarAtWhatsappConversations({ silent: true });
}

function closeAtWhatsappModal() {
  if (!atWhatsappModal) return;
  atWhatsappModal.style.display = 'none';
}

function bindAtWhatsappRealtimeUpdates() {
  if (atWhatsappRealtimeBound || !window.EventSource || !atWhatsappInboxListView) return;
  atWhatsappRealtimeBound = true;

  try {
    if (!window.__appGlobalSse) {
      window.__appGlobalSse = new EventSource('/api/produtos/stream');
    }

    window.__appGlobalSse.addEventListener('message', (event) => {
      let payload = null;
      try {
        payload = JSON.parse(event.data || '{}');
      } catch (_) {
        return;
      }

      if (!payload || payload.type !== 'whatsapp_message_received') return;

      const incomingPhones = Array.isArray(payload.phones)
        ? payload.phones.map((item) => normalizeAtWhatsappPhone(item)).filter(Boolean)
        : [];

      carregarAtWhatsappConversations({ silent: true });

      if (atWhatsappSelectedPhone && (!incomingPhones.length || incomingPhones.includes(atWhatsappSelectedPhone))) {
        carregarAtWhatsappMessages({ phone: atWhatsappSelectedPhone, silent: true });
      }
    });
  } catch (err) {
    atWhatsappRealtimeBound = false;
    console.warn('[SAC/WhatsApp] falha ao conectar SSE em tempo real', err);
  }
}

if (atWhatsappConversationBackBtn) {
  atWhatsappConversationBackBtn.addEventListener('click', () => {
    showAtWhatsappInboxListView();
    renderAtWhatsappConversationRows(atWhatsappConversationRows);
    renderAtWhatsappMessages([]);
    setAtWhatsappMessagesStatus('Selecione um contato para abrir a conversa.', false);
  });
}

if (atWhatsappTopBtn) {
  atWhatsappTopBtn.addEventListener('click', () => {
    openAtWhatsappModal();
  });
}

if (atWhatsappModalClose) {
  atWhatsappModalClose.addEventListener('click', () => {
    closeAtWhatsappModal();
  });
}

if (atWhatsappModal) {
  atWhatsappModal.addEventListener('click', (event) => {
    if (event.target === atWhatsappModal) closeAtWhatsappModal();
  });
}

document.addEventListener('keydown', (event) => {
  if (event.key === 'Escape' && atWhatsappModal && atWhatsappModal.style.display === 'flex') {
    closeAtWhatsappModal();
  }
});

if (atWhatsappFilterTodosBtn) {
  atWhatsappFilterTodosBtn.addEventListener('click', () => setAtWhatsappConversationFilter('todos'));
}

if (atWhatsappFilterLidosBtn) {
  atWhatsappFilterLidosBtn.addEventListener('click', () => setAtWhatsappConversationFilter('lidos'));
}

if (atWhatsappFilterNaoLidosBtn) {
  atWhatsappFilterNaoLidosBtn.addEventListener('click', () => setAtWhatsappConversationFilter('nao_lidos'));
}

if (atWhatsappReplyInput) {
  atWhatsappReplyInput.addEventListener('input', syncAtWhatsappReplyBoxState);
}

if (atWhatsappReplyBtn) {
  atWhatsappReplyBtn.addEventListener('click', async () => {
    syncAtWhatsappReplyBoxState();
    const phone = atWhatsappSelectedPhone;
    const text = String(atWhatsappReplyInput?.value || '').trim();
    if (!phone || !text) return;

    atWhatsappReplyBtn.disabled = true;
    setAtWhatsappReplyStatus('Enviando resposta...', false);

    try {
      const resp = await fetch('/api/sac/whatsapp/reply', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({
          phone,
          text,
          mode: 'manual'
        })
      });
      const data = await resp.json().catch(() => ({}));
      if (!resp.ok || data.ok === false) {
        throw new Error(data.error || 'Falha ao enviar resposta.');
      }

      if (atWhatsappReplyInput) atWhatsappReplyInput.value = '';
      setAtWhatsappReplyStatus('Resposta enviada com sucesso.', false);
      syncAtWhatsappReplyBoxState();
      await carregarAtWhatsappConversations({ silent: true });
      await carregarAtWhatsappMessages({ phone, silent: true });
    } catch (err) {
      console.error('[SAC/WhatsApp] erro ao enviar resposta manual', err);
      setAtWhatsappReplyStatus(err?.message || 'Erro ao enviar resposta do WhatsApp.', true);
      syncAtWhatsappReplyBoxState();
    } finally {
      if (atWhatsappReplyBtn) atWhatsappReplyBtn.disabled = false;
    }
  });
}

if (atWhatsappInboxListView) {
  renderAtWhatsappConversationRows([]);
  showAtWhatsappInboxListView();
  bindAtWhatsappRealtimeUpdates();
  carregarAtWhatsappConversations({ silent: true });
}

if (atWhatsappMessagesList) {
  renderAtWhatsappMessages([]);
}

syncAtWhatsappReplyBoxState();

if (!atWhatsappMessagesPollTimer && (atWhatsappMessagesList || atWhatsappInboxListView)) {
  atWhatsappMessagesPollTimer = setInterval(() => {
    if (atWhatsappInboxListView) carregarAtWhatsappConversations({ silent: true });
  }, 15000);
}
