function envioRastreioStatusRaw(row) {
  return String(row?.rastreio_status || '').trim() || 'Pendente';
}

function envioWorkflowStatus(row) {
  const raw = envioRastreioStatusRaw(row);
  if (raw === 'Enviado' || raw === 'Excluído') return raw;
  if (raw === 'Entregue' || raw === 'Finalizado') return raw;
  return 'Pendente';
}

// Preenche status de rastreio nas células com data-rastreio
async function preencherStatusRastreio(container) {
  if (!container) return;
  const spans = container.querySelectorAll('[data-rastreio]');
  spans.forEach(async (el) => {
    const codigoRaw = (el.getAttribute('data-rastreio') || '').trim();
    const codigo = codigoRaw.replace(/\s+/g, '').toUpperCase();
    if (!codigo || !/^[A-Z]{2}\d{9}[A-Z]{2}$/.test(codigo)) {
      return; // não é código válido de rastreio
    }
    el.textContent = 'Consultando...';
    try {
      const resp = await fetch(`/api/sac/rastreio/${encodeURIComponent(codigo)}`);
      const data = await resp.json().catch(() => ({}));
      if (!resp.ok || data.ok === false) throw new Error(data.error || `Falha ao consultar (${resp.status})`);
      const partes = [];
      if (data.status) partes.push(data.status);
      if (data.detalhe) partes.push(data.detalhe);
      const local = [data.local, data.cidade, data.uf].filter(Boolean).join(' - ');
      if (local) partes.push(local);
      if (data.quando) partes.push(new Date(data.quando).toLocaleString('pt-BR'));
      el.textContent = partes.length ? partes.join(' | ') : 'Sem atualização';
    } catch (err) {
      console.error('[SAC] erro rastreio', err);
      el.textContent = err?.message || 'Erro ao consultar';
    }
  });
}

// Consulta status VIPP para envios com id_vipp (substitui "ok" por status real)
async function preencherStatusVipp(container) {
  if (!container) return;
  const spans = container.querySelectorAll('[data-id-vipp]');
  spans.forEach(async (el) => {
    const idVipp = (el.getAttribute('data-id-vipp') || '').trim();
    if (!idVipp) return;
    const envioId = (el.getAttribute('data-envio-id') || '').trim();
    const identificacaoAttr = (el.getAttribute('data-identificacao') || '').replace(/\s+/g, '').toUpperCase();
    el.textContent = 'Consultando VIPP...';
    try {
      const url = '/api/vipp/status?id=' + encodeURIComponent(idVipp) + (envioId ? '&envio_id=' + encodeURIComponent(envioId) : '');
      const resp = await fetch(url, { credentials: 'same-origin' });
      const data = await resp.json().catch(() => ({}));
      if (!resp.ok || data.ok === false) {
        el.textContent = data.error || 'Erro VIPP';
        return;
      }
      const statusVipp = data.statusVipp || '';
      const isStatusInutil = !statusVipp || statusVipp === 'Desconhecido' || statusVipp === 'Invalida';
      // ECT code: prefer what VIPP returned, fallback to card attribute
      const ectCode = data.etiquetaPostagem ||
        (/^[A-Z]{2}\d{9}[A-Z]{2}$/.test(identificacaoAttr) ? identificacaoAttr : '');

      // Quando VIPP não tem status útil e temos código ECT, tenta Correios
      if (isStatusInutil && ectCode) {
        el.textContent = 'Consultando Correios...';
        try {
          const rCorr = await fetch('/api/sac/rastreio/' + encodeURIComponent(ectCode), { credentials: 'same-origin' });
          const dCorr = await rCorr.json().catch(() => ({}));
          const STATUS_INVALIDOS_CORREIOS = ['Invalida', 'Desconhecido', 'ok'];
          if (rCorr.ok && dCorr.ok !== false && dCorr.status && !STATUS_INVALIDOS_CORREIOS.includes(dCorr.status)) {
            const partes = [];
            if (dCorr.status) partes.push(dCorr.status);
            if (dCorr.detalhe) partes.push(dCorr.detalhe);
            const local = [dCorr.local, dCorr.cidade, dCorr.uf].filter(Boolean).join(' - ');
            if (local) partes.push(local);
            if (dCorr.quando) partes.push(new Date(dCorr.quando).toLocaleString('pt-BR'));
            el.textContent = partes.join(' | ') || 'Aguardando movimentação nos Correios';
            return;
          }
        } catch (_) {}
        // Fallback: postagem criada no VIPP mas ainda sem movimentação nos Correios
        el.textContent = 'Aguardando movimentação';
        return;
      }

      const partes = [];
      if (statusVipp && !isStatusInutil) partes.push(statusVipp);
      if (data.statusSolicitacao) partes.push(data.statusSolicitacao);
      if (data.etiquetaPostagem) partes.push('ECT: ' + data.etiquetaPostagem);
      el.textContent = partes.length ? partes.join(' | ') : 'Aguardando VIPP';
    } catch (err) {
      console.error('[VIPP] erro status', err);
      el.textContent = 'Erro ao consultar VIPP';
    }
  });
}


const normalizeSacStatus = (val) => {
  const status = String(val || '').trim();
  const found = sacStatusOptions.find(opt => opt.toLowerCase() === status.toLowerCase());
  return found || sacStatusOptions[0];
};

const setAtEnvioStatus = (text, isError = false) => {
  if (!atEnvioStatus) return;
  atEnvioStatus.style.display = text ? 'inline' : 'none';
  atEnvioStatus.style.color = isError ? '#f87171' : 'var(--inactive-color)';
  atEnvioStatus.textContent = text || '';
};

function normalizarTextoEnvioMercadoria(value) {
  return String(value || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .trim();
}

function isRastreioEmTransitoOuPosterior(statusRaw) {
  const status = normalizarTextoEnvioMercadoria(statusRaw);
  if (!status) return false;

  return (
    status.includes('em transito') ||
    status.includes('saiu para entrega') ||
    status.includes('objeto entregue') ||
    status.includes('entregue ao destinatario') ||
    status.includes('objeto recebido pelo destinatario') ||
    status.includes('disponivel para retirada')
  );
}

function isCodigoRastreioEnvioMercadoria(value) {
  return /^[A-Z]{2}\d{9}[A-Z]{2}$/.test(String(value || '').replace(/\s+/g, '').toUpperCase());
}

function getClasseStatusEnvioMercadoria(statusRaw) {
  const s = normalizarTextoEnvioMercadoria(statusRaw || 'pendente');
  if (s === 'enviado') return 'envio-status-enviado';
  if (s === 'finalizado' || s === 'entregue') return 'envio-status-finalizado';
  if (s.includes('separacao')) return 'envio-status-separacao';
  if (s === 'valida' || s === 'processamento vipp' || s === 'ok') return 'envio-status-correios';
  if (isRastreioEmTransitoOuPosterior(statusRaw)) return 'envio-status-correios';
  return 'envio-status-pendente';
}

function getStatusTokenEnvioMercadoria(statusRaw) {
  return getClasseStatusEnvioMercadoria(statusRaw).replace('envio-status-', '');
}

function atualizarMetricasEnvioMercadoria(rows) {
  const ativos = Array.isArray(rows) ? rows : [];
  const total = ativos.length;
  const pendentes = ativos.filter(r => envioWorkflowStatus(r) === 'Pendente').length;
  const enviados = ativos.filter(r => envioWorkflowStatus(r) === 'Enviado').length;

  if (envioMetricPendente) envioMetricPendente.textContent = pendentes;
  if (envioMetricCorreios) envioMetricCorreios.textContent = '0';
  if (envioMetricEnviado) envioMetricEnviado.textContent = enviados;
  if (envioMetricTotal) envioMetricTotal.textContent = total;
}


function filtrarEnvioMercadoria(row) {
  const statusRaw = normalizarTextoEnvioMercadoria(envioRastreioStatusRaw(row));
  return !['excluido', 'enviado', 'entregue', 'finalizado'].includes(statusRaw);
}

function renderMetodoEnvioMercadoriaHtml(metodoEnvioRaw, idVipp) {
  const metodo = String(metodoEnvioRaw || (idVipp ? 'Envio via Correios' : '')).trim() || 'Envio via Correios';
  let iconHtml = '';
  if (metodo === 'Envio via Correios') {
    iconHtml = '<img src="https://vipp.visualset.com.br/vipp/img/logo-visualset5.png" alt="" class="envio-card-metodo-icon-correios">';
  } else if (metodo === 'Envio via Disktenha') {
    iconHtml = '<i class="fa-solid fa-motorcycle envio-card-metodo-icon envio-card-metodo-icon-moto"></i>';
  } else if (metodo === 'Envio via transportadora') {
    iconHtml = '<i class="fa-solid fa-truck envio-card-metodo-icon envio-card-metodo-icon-truck"></i>';
  } else {
    iconHtml = '<i class="fa-solid fa-paper-plane envio-card-metodo-icon"></i>';
  }
  return `<div class="envio-card-metodo">${iconHtml}<span>${escapeAtHtml(metodo)}</span></div>`;
}

function isEnvioSacCorreiosVipp(r) {
  const metodo = String(r?.metodo_envio || '').trim();
  return !!r?.id_vipp || metodo === 'Envio via Correios';
}

function isEnvioSacManualRastreio(r) {
  const metodo = String(r?.metodo_envio || '').trim();
  return metodo === 'Envio via Disktenha' || metodo === 'Envio via transportadora';
}

function renderSacAcoesRastreabilidadeHtml(r) {
  const temIdent = !!(r.identificacao && String(r.identificacao).trim().length > 0);
  const identRaw = temIdent ? String(r.identificacao).trim() : '';
  const btnStyle = 'padding:6px 8px;font-size:11px;display:inline-flex;align-items:center;gap:5px;justify-content:center;white-space:normal;line-height:1.25;text-align:center;';
  const parts = [];
  if (isEnvioSacCorreiosVipp(r)) {
    if (temIdent) {
      parts.push(
        `<button class="content-button btn-envio-ver-etiqueta" data-envio-id="${escapeAtHtml(String(r.id))}" data-identificacao="${escapeAtHtml(identRaw)}"` +
        ` style="${btnStyle}background:#0f766e;color:#ccfbf1;border:none;border-radius:8px;cursor:pointer;font-weight:700;" title="Abrir etiqueta e declaração em PDF">` +
        `<i class="fa-solid fa-file-pdf"></i><span>Ver etiqueta</span></button>`
      );
    } else {
      parts.push(
        `<button class="content-button btn-envio-gerar-etiqueta btn-sac-rastreabilidade" data-envio-id="${escapeAtHtml(String(r.id))}" data-n-solic="${escapeAtHtml(r.numero_sep || '')}"` +
        ` style="${btnStyle}background:#1d4ed8;color:#dbeafe;border:none;border-radius:8px;cursor:pointer;font-weight:700;">` +
        `<i class="fa-solid fa-barcode"></i><span>Gerar etiqueta</span></button>`
      );
    }
  } else if (isEnvioSacManualRastreio(r) && !temIdent) {
    parts.push(
      `<button class="content-button btn-sac-inserir-rastreabilidade" data-envio-id="${escapeAtHtml(String(r.id))}"` +
      ` style="${btnStyle}background:linear-gradient(135deg,#0ea5e9 0%,#0284c7 100%);color:white;border:none;border-radius:8px;cursor:pointer;font-weight:700;">` +
      `<i class="fa-solid fa-pen-to-square"></i><span>Inserir rastreabilidade</span></button>`
    );
  }
  return parts.join('');
}

/** Abre PDF da etiqueta postal + declaração de conteúdo (as duas etiquetas do envio). */
function _envioAbrirEtiquetasPdf(envioId, identificacao) {
  const ecLimpo = String(identificacao || '').trim().replace(/\s+/g, '');
  if (ecLimpo) {
    window.open(`/api/vipp/etiqueta?id=${encodeURIComponent(ecLimpo)}&saida=1`, '_blank');
  }
  if (envioId) {
    window.open(`/api/vipp/declaracao?id=${encodeURIComponent(envioId)}`, '_blank');
  }
  if (!ecLimpo && !envioId) {
    alert('Etiqueta ainda não disponível para este envio.');
  }
}

function montarConteudoEnvioMercadoria(conteudoRaw) {
  if (!conteudoRaw) {
    return '<div class="envio-card-text">Sem conteúdo informado.</div>';
  }

  try {
    const items = JSON.parse(conteudoRaw);
    if (Array.isArray(items) && items.length) {
      return `
        <div class="envio-content-list">
          ${items.map((item) => {
            const texto = escapeAtHtml(item?.conteudo || 'Item sem descrição');
            const qtd = escapeAtHtml(formatarQuantidadeExibicao(item?.quantidade));
            return `<div class="envio-content-item"><b>${texto}</b><span>Qtd. ${qtd}</span></div>`;
          }).join('')}
        </div>
      `;
    }
  } catch (_) {}

  return `<div class="envio-card-text" style="white-space:pre-wrap;">${escapeAtHtml(conteudoRaw)}</div>`;
}

function renderEnvioMercadoriaCard(r) {
  const dataFmt = r.created_at ? new Date(r.created_at).toLocaleString('pt-BR') : '-';
  const usuario = escapeAtHtml(r.usuario || '-');
  const obs = escapeAtHtml(r.observacao || 'Sem observação');
  const numeroSep = escapeAtHtml(r.numero_sep || '-');
  const status = envioRastreioStatusRaw(r);
  const statusNorm = normalizarTextoEnvioMercadoria(status);
  const etiqueta = r.etiqueta_url || r.etiqueta || '';
  const declaracao = r.declaracao_url || r.declaracao || '';
  const declaracaoHref = declaracao || (r.id_vipp ? '/api/vipp/declaracao?id=' + r.id : '');
  const temIdentificacao = r.identificacao && String(r.identificacao).trim().length > 0;
  const identRaw = r.identificacao ? String(r.identificacao).trim() : '-';
  const metodoEnvio = String(r.metodo_envio || '').trim();
  const isCorreios = !metodoEnvio || metodoEnvio === 'Envio via Correios';
  const isEnvioManual = metodoEnvio === 'Envio via Disktenha' || metodoEnvio === 'Envio via transportadora';
  const temVippPendente = isCorreios && !!(r.id_vipp && !etiqueta && !temIdentificacao);
  const podeMarcarEnviado = isEnvioManual && statusNorm !== 'enviado';
  const metodoHtml = renderMetodoEnvioMercadoriaHtml(metodoEnvio, r.id_vipp);
  let buttons = '';
  if (etiqueta || temIdentificacao) {
    buttons = `<button class="content-button btn-envio-imprimir" data-envio-id="${escapeAtHtml(String(r.id))}" data-identificacao="${escapeAtHtml(identRaw)}" style="padding:8px 10px;font-size:12px;display:inline-flex;align-items:center;gap:6px;"><i class="fa-solid fa-print"></i><span>Imprimir</span></button>`;
  } else if (temVippPendente) {
    buttons = `<button class="content-button btn-envio-gerar-etiqueta" data-envio-id="${escapeAtHtml(String(r.id))}" data-n-solic="${escapeAtHtml(r.numero_sep || '')}" style="padding:8px 10px;font-size:12px;display:inline-flex;align-items:center;gap:6px;background:#1d4ed8;color:#dbeafe;border:none;border-radius:8px;cursor:pointer;font-weight:700;"><i class="fa-solid fa-barcode"></i><span>Gerar etiqueta</span></button>`;
  } else if (podeMarcarEnviado) {
    buttons = `<button class="content-button btn-envio-marcar-enviado" data-envio-id="${escapeAtHtml(String(r.id))}" style="padding:8px 10px;font-size:12px;display:inline-flex;align-items:center;gap:6px;background:#15803d;color:#dcfce7;border:none;border-radius:8px;cursor:pointer;font-weight:700;"><i class="fa-solid fa-circle-check"></i><span>Enviado</span></button>`;
  }

  const statusToken = getStatusTokenEnvioMercadoria(status);
  const statusClasse = `envio-card-status-${statusToken}`;
  const statusPillClasse = `envio-status-${statusToken}`;

  return `
    <article class="envio-card ${statusClasse}">
      <div class="envio-card-rastreio">
        <div class="envio-card-heading">
          <div class="envio-card-id"><i class="fa-solid fa-box-open" style="color:#38bdf8;"></i> Envio #${escapeAtHtml(r.id || '-')}</div>
          <div class="envio-card-sep-block">
            <div class="envio-card-sep"><small>SEP</small><span>${numeroSep}</span></div>
            ${metodoHtml}
          </div>
        </div>
        <div class="envio-card-meta">${escapeAtHtml(dataFmt)}<br>Solicitado por <strong style="color:#e5e7eb;">${usuario}</strong></div>
        <div>
          <div class="envio-card-label">Observação</div>
          <div class="envio-card-text">${obs}</div>
        </div>
      </div>
      <div>
        <div class="envio-card-label">Conteúdo</div>
        ${montarConteudoEnvioMercadoria(r.conteudo || '')}
      </div>
      <div class="envio-card-main">
        <div>
          <div class="envio-card-label">Rastreio</div>
          <div class="envio-card-text" style="font-weight:800;color:#f8fafc;">${escapeAtHtml(identRaw)}</div>
        </div>
        <span class="envio-status-pill ${statusPillClasse}"><i class="fa-solid fa-circle"></i>${escapeAtHtml(status)}</span>
      </div>
      <div class="envio-card-actions">
        <div class="envio-card-label">Ações</div>
        ${buttons || (temVippPendente ? '<div class="envio-card-text">Etiqueta ainda não gerada — clique em Gerar etiqueta.</div>' : podeMarcarEnviado ? '<div class="envio-card-text">Confirme o envio clicando em Enviado.</div>' : '<div class="envio-card-text">Sem anexos.</div>')}
      </div>
    </article>`;
}

