function setSacAtModoVisual(mode = 'at') {
  const sacAtPane = document.getElementById('sacAtPane');
  const sacAtRelatorioPane = document.getElementById('sacAtRelatorioPane');
  const vendasGraficosPane = document.getElementById('vendasGraficosPane');
  const vendasControlePane = document.getElementById('vendasControlePane');
  const vendasMapaPane     = document.getElementById('vendasMapaPane');
  const vendasRelatorioPane = document.getElementById('vendasRelatorioPane');
  const wrapper = sacAtRelatorioPane?.parentElement || vendasGraficosPane?.parentElement || sacAtPane?.parentElement;
  if (!sacAtPane || !wrapper) return;

  if (mode === 'relatorio') {
    sacAtPane.style.display = 'flex';
    Array.from(wrapper.children).forEach((child) => {
      if (!(child instanceof HTMLElement)) return;
      if (child === sacAtRelatorioPane) {
        child.style.display = 'flex';
        return;
      }
      if (child.classList.contains('modal-overlay') || child.id === 'atLightbox' || child.id === 'atWhatsappModal') {
        return;
      }
      child.style.display = 'none';
    });
    return;
  }

  if (mode === 'vendas') {
    sacAtPane.style.display = 'flex';
    Array.from(wrapper.children).forEach((child) => {
      if (!(child instanceof HTMLElement)) return;
      if (child === vendasGraficosPane) {
        child.style.display = 'flex';
        return;
      }
      if (child.classList.contains('modal-overlay') || child.id === 'atLightbox' || child.id === 'atWhatsappModal') {
        return;
      }
      child.style.display = 'none';
    });
    return;
  }

  if (mode === 'vendas-controle') {
    sacAtPane.style.display = 'flex';
    Array.from(wrapper.children).forEach((child) => {
      if (!(child instanceof HTMLElement)) return;
      if (child === vendasControlePane) {
        child.style.display = 'flex';
        return;
      }
      if (child.classList.contains('modal-overlay') || child.id === 'atLightbox' || child.id === 'atWhatsappModal') {
        return;
      }
      child.style.display = 'none';
    });
    return;
  }

  if (mode === 'vendas-mapa') {
    sacAtPane.style.display = 'flex';
    Array.from(wrapper.children).forEach((child) => {
      if (!(child instanceof HTMLElement)) return;
      if (child === vendasMapaPane) {
        child.style.display = 'flex';
        return;
      }
      if (child.classList.contains('modal-overlay') || child.id === 'atLightbox' || child.id === 'atWhatsappModal') {
        return;
      }
      child.style.display = 'none';
    });
    return;
  }

  if (mode === 'vendas-relatorio') {
    sacAtPane.style.display = 'flex';
    Array.from(wrapper.children).forEach((child) => {
      if (!(child instanceof HTMLElement)) return;
      if (child === vendasRelatorioPane) {
        child.style.display = 'flex';
        return;
      }
      if (child.classList.contains('modal-overlay') || child.id === 'atLightbox' || child.id === 'atWhatsappModal') {
        return;
      }
      child.style.display = 'none';
    });
    return;
  }

  Array.from(wrapper.children).forEach((child) => {
    if (!(child instanceof HTMLElement)) return;
    if (child === sacAtRelatorioPane || child === vendasGraficosPane || child === vendasControlePane || child === vendasMapaPane || child === vendasRelatorioPane || child.id === 'atGraficosView') {
      child.style.display = 'none';
      return;
    }
    if (child.classList.contains('modal-overlay') || child.id === 'atLightbox' || child.id === 'atWhatsappModal') {
      return;
    }
    child.style.display = '';
  });
}

function mergeAtSerieRows(rows) {
  if (!Array.isArray(rows) || !rows.length) return [];

  const isFilled = (v) => {
    const txt = String(v || '').trim();
    return txt && txt !== '-';
  };

  const normalizeKeyPart = (v) => String(v || '').trim().toUpperCase();
  const mergedMap = new Map();

  rows.forEach((row, idx) => {
    const op = String(row?.ordem_producao || '').trim();
    const modelo = String(row?.modelo || '').trim();
    const canMerge = !!op && !!modelo;
    const key = canMerge
      ? `${normalizeKeyPart(op)}|${normalizeKeyPart(modelo)}`
      : `__idx__${idx}`;

    if (!mergedMap.has(key)) {
      mergedMap.set(key, {
        ...row,
        pedido_list: isFilled(row?.pedido) ? [String(row.pedido).trim()] : []
      });
      return;
    }

    const current = mergedMap.get(key);
    const pedidoAtual = String(row?.pedido || '').trim();
    if (isFilled(pedidoAtual) && !current.pedido_list.includes(pedidoAtual)) {
      current.pedido_list.push(pedidoAtual);
    }

    if (!isFilled(current.cliente) && isFilled(row?.cliente)) current.cliente = String(row.cliente).trim();
    if (!isFilled(current.nota_fiscal) && isFilled(row?.nota_fiscal)) current.nota_fiscal = String(row.nota_fiscal).trim();
    if (!isFilled(current.chave_nfe) && isFilled(row?.chave_nfe)) current.chave_nfe = String(row.chave_nfe).trim();
    if (!isFilled(current.data_entrega) && isFilled(row?.data_entrega)) current.data_entrega = String(row.data_entrega).trim();
    if (!isFilled(current.teste_tipo_gas) && isFilled(row?.teste_tipo_gas)) current.teste_tipo_gas = String(row.teste_tipo_gas).trim();
  });

  return Array.from(mergedMap.values()).map((row) => ({
    ...row,
    pedido: Array.isArray(row.pedido_list) && row.pedido_list.length ? row.pedido_list.join(' / ') : row.pedido,
  }));
}

function renderAtSerieRows(rows) {
  if (!atSerieModalTbody) return;
  const mergedRows = mergeAtSerieRows(rows);
  atSerieRenderedRows = mergedRows;
  if (!Array.isArray(mergedRows) || !mergedRows.length) {
    limparAtSerieSelecionada();
    atSerieModalTbody.innerHTML = '<tr><td colspan="7" style="text-align:center;padding:16px;color:var(--inactive-color);">Nenhum registro encontrado.</td></tr>';
    return;
  }

  atSerieModalTbody.innerHTML = mergedRows.map((row, idx) => {
    const jaExiste = !!row.ja_existe;
    const rowStyle = jaExiste
      ? 'cursor:pointer;color:#f87171;background:rgba(239,68,68,.10);'
      : 'cursor:pointer;';
    const titleAttr = jaExiste ? ' title="Este número de série já possui atendimento registrado. Clique para reabrir."' : '';
    return `
    <tr data-at-row-index="${idx}" style="${rowStyle}"${titleAttr}>
      <td>${jaExiste ? '<i class="fa-solid fa-circle-exclamation" style="color:#f87171;margin-right:4px;"></i>' : ''}${escapeAtHtml(row.pedido || '-')}</td>
      <td>${escapeAtHtml(row.ordem_producao || '-')}</td>
      <td>${escapeAtHtml(row.modelo || '-')}</td>
      <td>${escapeAtHtml(row.cliente || '-')}</td>
      <td>${String(row.nota_fiscal || '').trim()
        ? `<a href="#" class="at-nfe-link" data-num="${escapeAtHtml(row.nota_fiscal || '')}" data-chave="${escapeAtHtml(row.chave_nfe || '')}" style="color:#0ea5e9;text-decoration:underline;font-weight:600;" title="Abrir detalhes da NF-e">${escapeAtHtml(row.nota_fiscal || '')}</a>`
        : '-'}</td>
      <td>${escapeAtHtml(row.data_entrega || '-')}</td>
      <td>${escapeAtHtml(row.teste_tipo_gas || '-')}</td>
    </tr>
  `;
  }).join('');
}

let atSerieLastRows = [];
let atSerieRenderedRows = [];
let atSerieSelectedRow = null;
let atIdExistente = null; // ID do AT já existente ao clicar em linha vermelha
let atSerieSelectionContext = { mode: 'create', idAt: null };
const atBuscaSpinner = document.getElementById('atBuscaSpinner');

function setAtSerieSelectionContext(mode = 'create', idAt = null) {
  atSerieSelectionContext = { mode, idAt: idAt ? String(idAt) : null };
}

function _atEditBuscaSetFeedback(text, isError = false) {
  const okEl = document.getElementById('atEmSavedMsg');
  const errEl = document.getElementById('atEmErrMsg');
  if (isError) {
    if (okEl) okEl.style.display = 'none';
    if (errEl) {
      errEl.textContent = text || 'Erro ao atualizar Dados da Busca.';
      errEl.style.display = text ? 'inline' : 'none';
    }
    return;
  }
  if (errEl) errEl.style.display = 'none';
  if (okEl) {
    okEl.textContent = text || '';
    okEl.style.display = text ? 'inline' : 'none';
  }
}

function _atSetEditBuscaFieldValue(elId, value) {
  const el = document.getElementById(elId);
  if (!el) return;
  el.value = value ?? '';
  el.dataset.lastBuscaValue = String(value ?? '').trim();
}

function _atAtualizarBuscaSelecionadaNoCache(idStr, rowData) {
  const idx = _atAllRows.findIndex(r => String(r.id) === String(idStr));
  if (idx === -1) return;
  _atAllRows[idx] = {
    ..._atAllRows[idx],
    pedido: String(rowData.pedido || '').trim() || null,
    ordem_producao: String(rowData.ordem_producao || '').trim() || null,
    modelo: String(rowData.modelo || '').trim() || _atAllRows[idx].modelo,
    cliente: String(rowData.cliente || '').trim() || null,
    nota_fiscal: String(rowData.nota_fiscal || '').trim() || null,
    data_entrega: String(rowData.data_entrega || '').trim() || null,
    teste_tipo_gas: String(rowData.teste_tipo_gas || '').trim() || null,
  };
}

async function _atAplicarBuscaSelecionadaNoEditModal(rowData) {
  const id = _atEditModalCurrentId;
  if (!id || !rowData) return;

  _atEditBuscaSetFeedback('Associando Dados da Busca...', false);

  const payload = {
    selected_item: {
      pedido: String(rowData.pedido || '').trim() || null,
      ordem_producao: String(rowData.ordem_producao || '').trim() || null,
      modelo: String(rowData.modelo || '').trim() || null,
      cliente: String(rowData.cliente || '').trim() || null,
      nota_fiscal: String(rowData.nota_fiscal || '').trim() || null,
      data_entrega: String(rowData.data_entrega || '').trim() || null,
      teste_tipo_gas: String(rowData.teste_tipo_gas || '').trim() || null,
    }
  };

  const resp = await fetch(`/api/sac/at/atendimentos/${id}`, {
    method: 'PATCH',
    credentials: 'include',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(payload)
  });
  const data = await resp.json().catch(() => ({}));
  if (!resp.ok || data.ok === false) {
    throw new Error(data.error || 'Falha ao associar Dados da Busca.');
  }

  _atSetEditBuscaFieldValue('atEmPedido', rowData.pedido);
  _atSetEditBuscaFieldValue('atEmOrdemProducao', rowData.ordem_producao);
  _atSetEditBuscaFieldValue('atEmNotaFiscal', rowData.nota_fiscal);
  _atSetEditBuscaFieldValue('atEmDataEntrega', rowData.data_entrega);
  _atAtualizarBuscaSelecionadaNoCache(String(id), rowData);
  _atRenderCurrent();
  _atEditBuscaSetFeedback('Dados da Busca associados com sucesso.', false);
}

async function buscarSerieAtComTermo(termoBruto, options = {}) {
  const termo = String(termoBruto || '').trim();
  const isEditMode = options.contextMode === 'edit';
  if (!termo || termo.length < 2) {
    if (isEditMode) _atEditBuscaSetFeedback('Digite ao menos 2 caracteres para pesquisar.', true);
    else setAtSerieBuscaStatus('Digite ao menos 2 caracteres para pesquisar.', true);
    return;
  }

  setAtSerieSelectionContext(options.contextMode || 'create', options.idAt || null);

  if (atSerieBuscaBtn) atSerieBuscaBtn.disabled = true;
  if (atBuscaSpinner) atBuscaSpinner.style.display = 'block';
  if (isEditMode) {
    _atEditBuscaSetFeedback('', false);
    const _sp = document.getElementById('atEmBuscaSpinner');
    const _spTxt = document.getElementById('atEmBuscaSpinnerTxt');
    const _fPed = document.getElementById('atEmPedido');
    const _fOp  = document.getElementById('atEmOrdemProducao');
    if (_sp) _sp.style.display = 'inline-block';
    if (_spTxt) _spTxt.style.display = 'inline';
    if (_fPed) _fPed.disabled = true;
    if (_fOp)  _fOp.disabled  = true;
  } else setAtSerieBuscaStatus('Pesquisando número de série...', false);

  try {
    const resp = await fetch(`/api/sac/at/busca-serie?termo=${encodeURIComponent(termo)}`);
    const data = await resp.json().catch(() => ({}));
    if (!resp.ok || data.ok === false) {
      throw new Error(data.error || 'Falha ao buscar número de série.');
    }

    const rows = Array.isArray(data.rows) ? data.rows : [];
    atSerieLastRows = rows;
    renderAtSerieRows(rows);
    const isRapido = atTipoAtendimentoInput?.value === 'Atendimento rápido';
    if (rows.length) {
      if (isEditMode) _atEditBuscaSetFeedback(`${rows.length} registro(s) encontrado(s). Escolha um item.`, false);
      else setAtSerieBuscaStatus(`${rows.length} registro(s) encontrado(s).`, false);
      if (atSerieReabrirBtn && !isRapido) atSerieReabrirBtn.style.display = 'inline-flex';
      openAtSerieModal();
    } else {
      if (isEditMode) _atEditBuscaSetFeedback('Nenhum registro encontrado para este valor.', true);
      else setAtSerieBuscaStatus('Nenhum registro encontrado para este número de série.', false);
      if (atSerieReabrirBtn) atSerieReabrirBtn.style.display = 'none';
      closeAtSerieModal();
    }
  } catch (err) {
    console.error('[SAC/AT] erro na busca de serie', err);
    if (isEditMode) _atEditBuscaSetFeedback(err?.message || 'Erro ao buscar Dados da Busca.', true);
    else setAtSerieBuscaStatus(err?.message || 'Erro ao buscar número de série.', true);
  } finally {
    if (atSerieBuscaBtn) atSerieBuscaBtn.disabled = false;
    if (atBuscaSpinner) atBuscaSpinner.style.display = 'none';
    if (isEditMode) {
      const _sp = document.getElementById('atEmBuscaSpinner');
      const _spTxt = document.getElementById('atEmBuscaSpinnerTxt');
      const _fPed = document.getElementById('atEmPedido');
      const _fOp  = document.getElementById('atEmOrdemProducao');
      if (_sp) _sp.style.display = 'none';
      if (_spTxt) _spTxt.style.display = 'none';
      if (_fPed) _fPed.disabled = false;
      if (_fOp)  _fOp.disabled  = false;
    }
  }
}

async function buscarSerieAt() {
  return buscarSerieAtComTermo(atSerieBuscaInput?.value?.trim() || '', { contextMode: 'create' });
}

function _atBuscarDadosBuscaEditModal(term) {
  return buscarSerieAtComTermo(term, { contextMode: 'edit', idAt: _atEditModalCurrentId });
}

function _atBindBuscaEditField(elId) {
  const el = document.getElementById(elId);
  if (!el) return;

  el.addEventListener('focus', () => {
    el.dataset.lastBuscaValue = String(el.value || '').trim();
  });

  el.addEventListener('keydown', (e) => {
    if (e.key !== 'Enter') return;
    e.preventDefault();
    const term = String(el.value || '').trim();
    if (!term || term === String(el.dataset.lastBuscaValue || '').trim()) return;
    el.dataset.lastBuscaValue = term;
    _atBuscarDadosBuscaEditModal(term);
  });

  el.addEventListener('blur', () => {
    const term = String(el.value || '').trim();
    if (!term || term === String(el.dataset.lastBuscaValue || '').trim()) return;
    el.dataset.lastBuscaValue = term;
    _atBuscarDadosBuscaEditModal(term);
  });
}

async function preencherEnderecoPorCepAt() {
  const cepRaw = atCepInput?.value || '';
  const cep = cepRaw.replace(/\D/g, '');
  if (cep.length !== 8) {
    setAtEnvioStatus('CEP inválido. Digite 8 números e pressione Enter.', true);
    return;
  }

  setAtEnvioStatus('Consultando CEP...', false);

  try {
    const resp = await fetch(`/api/sac/at/cep/${encodeURIComponent(cep)}`);
    const data = await resp.json().catch(() => ({}));
    if (!resp.ok || data.ok === false) {
      if (atRuaInput) atRuaInput.value = '';
      if (atBairroInput) atBairroInput.value = '';
      if (atCidadeInput) atCidadeInput.value = '';
      if (atEstadoInput) atEstadoInput.value = '';
      setAtEnvioStatus('CEP não encontrado. Preencha o endereço manualmente.', true);
      return;
    }

    if (atRuaInput)    atRuaInput.value    = String(data.rua      || '').trim();
    if (atBairroInput)  atBairroInput.value  = String(data.bairro   || '').trim();
    if (atCidadeInput)  atCidadeInput.value  = String(data.municipio|| '').trim();
    if (atEstadoInput)  atEstadoInput.value  = String(data.uf       || '').trim();
    setAtEnvioStatus('Endereço preenchido pelo CEP.', false);
  } catch (err) {
    console.error('[SAC/AT] erro ao consultar CEP', err);
    setAtEnvioStatus('Erro ao consultar CEP. Tente novamente.', true);
  }
}

// ── Modal: Envio de Peça (OS) ──────────────────────────────────────────────
(function () {
  const modal       = document.getElementById('osEnviarPecaModal');
  const closeBtn    = document.getElementById('osEnviarPecaModalClose');
  const openBtn     = document.getElementById('atEnviarPecaBtn');

  const attachEtBtn = document.getElementById('osAttachEtiquetaBtn');
  const attachDcBtn = document.getElementById('osAttachDeclaracaoBtn');
  const inputEt     = document.getElementById('osFileInputEtiqueta');
  const inputDc     = document.getElementById('osFileInputDeclaracao');
  const infoEt      = document.getElementById('osFileInfoEtiqueta');
  const infoDc      = document.getElementById('osFileInfoDeclaracao');
  const obsEl       = document.getElementById('osObservacao');
  const sepEl       = document.getElementById('osNumeroSep');
  const statusEl    = document.getElementById('osEnvioStatus');
  const sendBtn     = document.getElementById('osSendBtn');

  if (!modal) return;

  function openModal() {
    modal.style.display = 'flex';
    document.body.style.overflow = 'hidden';
  }

  function closeModal() {
    modal.style.display = 'none';
    document.body.style.overflow = '';
  }

  if (openBtn)  openBtn.addEventListener('click', openModal);
  if (closeBtn) closeBtn.addEventListener('click', closeModal);
  modal.addEventListener('click', (e) => { if (e.target === modal) closeModal(); });
  document.addEventListener('keydown', (e) => { if (e.key === 'Escape' && modal.style.display === 'flex') closeModal(); });

  function formatFile(f) {
    if (!f) return 'Nenhum arquivo.';
    const kb = (f.size / 1024).toFixed(1);
    return f.name + ' (' + kb + ' KB)';
  }

  if (attachEtBtn && inputEt) {
    attachEtBtn.addEventListener('click', () => { inputEt.value = ''; inputEt.click(); });
    inputEt.addEventListener('change', () => {
      const f = inputEt.files?.[0];
      if (f) {
        const name = f.name.toLowerCase();
        if (!name.includes('etiqueta')) {
          alert('Selecione o arquivo de ETIQUETA (nome deve conter "etiqueta").');
          inputEt.value = '';
          infoEt.textContent = 'Nenhum arquivo.';
          return;
        }
      }
      infoEt.textContent = f ? formatFile(f) : 'Nenhum arquivo.';
    });
  }

  if (attachDcBtn && inputDc) {
    attachDcBtn.addEventListener('click', () => { inputDc.value = ''; inputDc.click(); });
    inputDc.addEventListener('change', () => {
      const f = inputDc.files?.[0];
      infoDc.textContent = f ? formatFile(f) : 'Nenhum arquivo.';
    });
  }

  function setStatus(text, isError = false) {
    if (!statusEl) return;
    statusEl.style.display = text ? 'inline' : 'none';
    statusEl.style.color = isError ? '#f87171' : 'var(--inactive-color)';
    statusEl.textContent = text || '';
  }

  if (sendBtn) {
    sendBtn.addEventListener('click', async () => {
      const userName = document.getElementById('userNameDisplay')?.textContent?.trim() || '';
      const observacao = obsEl?.value?.trim() || '';
      const numeroSep  = sepEl?.value?.trim() || '';
      const etiqueta   = inputEt?.files?.[0] || null;
      const declaracao = inputDc?.files?.[0] || null;

      if (!userName) { alert('Usuário não identificado. Faça login novamente.'); return; }
      if (!etiqueta || !declaracao) {
        alert('Selecione exatamente 2 arquivos: Etiqueta e Declaração de conteúdo.');
        return;
      }

      sendBtn.disabled = true;
      setStatus('Enviando...', false);

      try {
        const formData = new FormData();
        formData.append('usuario', userName);
        formData.append('observacao', observacao);
        formData.append('numero_sep', numeroSep);
        formData.append('anexos', etiqueta);
        formData.append('anexos', declaracao);

        const resp = await fetch('/api/sac/solicitacoes', { method: 'POST', body: formData });
        const data = await resp.json().catch(() => ({}));
        const ok   = resp.ok && data.ok !== false;

        if (ok) {
          setStatus('Solicitação registrada com sucesso!', false);
          if (inputEt) inputEt.value = '';
          if (inputDc) inputDc.value = '';
          if (infoEt)  infoEt.textContent  = 'Nenhum arquivo.';
          if (infoDc)  infoDc.textContent  = 'Nenhum arquivo.';
          if (obsEl)   obsEl.value  = '';
          if (sepEl)   sepEl.value  = '';
          setTimeout(closeModal, 1800);
        } else {
          setStatus(data.error || 'Falha ao registrar.', true);
        }
      } catch (err) {
        console.error('[OS-EnviarPeca] erro ao registrar envio', err);
        setStatus(err?.message || 'Erro ao registrar.', true);
      } finally {
        sendBtn.disabled = false;
      }
    });
  }
})();
// ── Fim Modal: Envio de Peça (OS) ───────────────────────────────────────────

if (atEnviarBtn) {
  atEnviarBtn.addEventListener('click', async () => {
    // Tipo de atendimento é obrigatório
    if (!atTipoAtendimentoInput?.value?.trim()) {
      setAtEnvioStatus('Selecione o Tipo de atendimento antes de enviar.', true);
      atTipoAtendimentoInput?.focus();
      return;
    }

    atEnviarBtn.disabled = true;
    setAtEnvioStatus('Salvando atendimento...', false);

    try {
      const payload = {
        tipo: atTipoAtendimentoInput?.value?.trim() || null,
        nome_revenda_cliente: atNomeRevendaClienteInput?.value?.trim() || null,
        numero_telefone: atTelefoneInput?.value?.trim() || null,
        data: atDataInput?.value || null,
        cpf_cnpj: atCpfCnpjInput?.value?.trim() || null,
        cep: atCepInput?.value?.trim() || null,
        bairro: atBairroInput?.value?.trim() || null,
        cidade: atCidadeInput?.value?.trim() || null,
        estado: atEstadoInput?.value?.trim() || null,
        numero: atNumeroInput?.value?.trim() || null,
        rua: atRuaInput?.value?.trim() || null,
        agendar_atendimento_com: atAgendarComInput?.value?.trim() || null,
        descreva_reclamacao: atDescricaoInput?.value?.trim() || null,
        motivo_solicitacao: (atTipoAtendimentoInput?.value === 'Atendimento rápido'
          ? document.getElementById('atRapidoMotivo')?.value?.trim()
          : document.getElementById('atMotivoSolicitacao')?.value?.trim()) || null,
        acao_tomada: (atTipoAtendimentoInput?.value === 'Atendimento rápido'
          ? document.getElementById('atRapidoAcao')?.value?.trim()
          : null) || null,
        atendimento_inicial: document.getElementById('atAtendimentoInicial')?.value?.trim() || null,
        modelo: atModeloInput?.value?.trim() || null,
        tag_problema: atTagProblemaInput?.value?.trim() || null,
        subtag: (atTipoAtendimentoInput?.value === 'Atendimento rápido'
          ? document.getElementById('atSubtag')?.value?.trim()
          : null) || null,
        plataforma_atendimento: atPlataformaInput?.value?.trim() || null,
        selected_item: atSerieSelectedRow || null,
        id_at_existente: atIdExistente || null,
      };

      const resp = await fetch('/api/sac/at', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload),
      });

      const data = await resp.json().catch(() => ({}));
      if (!resp.ok || data.ok === false) {
        throw new Error(data.error || 'Falha ao salvar atendimento AT.');
      }

      // Upload de anexos pendentes após obter o id_at
      const idAtSalvo = data?.row?.id;
      if (idAtSalvo && _atAnexosPendentes.length) {
        setAtEnvioStatus('Enviando anexos...', false);
        await _atFazerUploadAnexos(idAtSalvo);
      }

      // Se for Atendimento rápido, registra também em sac.mencoes
      if (payload.tipo === 'Atendimento rápido' && idAtSalvo) {
        try {
          await fetch('/api/sac/at/mencoes', {
            method: 'POST',
            credentials: 'include',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
              id_at: idAtSalvo,
              telefone: payload.numero_telefone || null,
              nome_revenda_cliente: payload.nome_revenda_cliente || null,
              plataforma: payload.plataforma_atendimento || null,
              motivo_solicitacao: payload.motivo_solicitacao || null,
              acao_tomada: payload.acao_tomada || null,
            }),
          });
        } catch (mErr) {
          console.warn('[SAC/AT] falha ao registrar menção automática:', mErr);
        }
      }

      setAtEnvioStatus(`Atendimento salvo com sucesso (ID ${idAtSalvo || 'n/a'}).`, false);

      // Auto-registra tag no catálogo sac.tag (fire-and-forget)
      const _tagPrinc = payload.tag_problema;
      if (_tagPrinc) {
        fetch('/api/sac/at/tags', {
          method: 'POST', credentials: 'include',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ nome: _tagPrinc.trim() })
        }).catch(() => null);
      }

      resetAtFormulario();
      fecharModalAtFormulario();
      abrirTelaAtAtendimentos();
      await carregarAtAtendimentos();
    } catch (err) {
      console.error('[SAC/AT] erro ao salvar atendimento', err);
      setAtEnvioStatus(err?.message || 'Erro ao salvar atendimento.', true);
    } finally {
      atEnviarBtn.disabled = false;
    }
  });
}

let _atCepDebounce = null;
if (atCepInput) {
  atCepInput.addEventListener('input', () => {
    // Formata como 00000-000
    let v = atCepInput.value.replace(/\D/g, '');
    if (v.length > 5) v = v.slice(0, 5) + '-' + v.slice(5, 8);
    atCepInput.value = v;
    const clean = v.replace(/\D/g, '');
    clearTimeout(_atCepDebounce);
    if (clean.length === 8) _atCepDebounce = setTimeout(preencherEnderecoPorCepAt, 500);
  });
  atCepInput.addEventListener('blur', () => {
    const clean = atCepInput.value.replace(/\D/g, '');
    if (clean.length === 8) preencherEnderecoPorCepAt();
  });
  atCepInput.addEventListener('keydown', (e) => {
    if (e.key !== 'Enter') return;
    e.preventDefault();
    preencherEnderecoPorCepAt();
  });
}

