if (atSerieModalTbody) {
  atSerieModalTbody.addEventListener('click', async (e) => {
    const nfeLink = e.target.closest('.at-nfe-link');
    if (nfeLink) {
      e.preventDefault();
      e.stopPropagation();
      abrirDetalhesNfeAt(nfeLink.dataset?.chave || '', nfeLink.dataset?.num || '');
      return;
    }

    const rowEl = e.target.closest('tr[data-at-row-index]');
    if (!rowEl) return;
    const idx = Number(rowEl.getAttribute('data-at-row-index'));
    if (!Number.isFinite(idx) || idx < 0) return;
    const rowData = atSerieRenderedRows[idx];
    if (!rowData) return;

    // Se o modal de edição está aberto, SEMPRE aplica na OS em edição (não abre Nova OS)
    if (_atEditModalCurrentId) {
      // Spinner na linha clicada
      const _origHtml = rowEl.innerHTML;
      rowEl.innerHTML = `<td colspan="7" style="text-align:center;padding:8px;">
        <span style="display:inline-flex;align-items:center;gap:8px;color:#a78bfa;font-size:13px;">
          <span style="width:14px;height:14px;border:2px solid rgba(167,139,250,.3);border-top-color:#a78bfa;border-radius:50%;animation:atSpinAnim .7s linear infinite;display:inline-block;"></span>
          Associando...
        </span></td>`;
      try {
        await _atAplicarBuscaSelecionadaNoEditModal(rowData);
        closeAtSerieModal();
      } catch (err) {
        console.error('[SAC/AT] erro ao aplicar Dados da Busca no modal de edição', err);
        rowEl.innerHTML = _origHtml;
        _atEditBuscaSetFeedback(err?.message || 'Erro ao associar Dados da Busca.', true);
      } finally {
        setAtSerieSelectionContext('create', null);
      }
      return;
    }

    preencherAtSerieSelecionada(rowData);

    // Se a linha já tem atendimento registrado, preenche todos os campos do formulário
    if (rowData.ja_existe && rowData.at_data) {
      const d = rowData.at_data;
      atIdExistente = d.id || null;
      const modalTitle = document.getElementById('atFormModalTitle');
      if (modalTitle) modalTitle.textContent = 'Registrar nova reclamação';
      if (atTipoAtendimentoInput) atTipoAtendimentoInput.value = d.tipo || '';
      if (atNomeRevendaClienteInput) atNomeRevendaClienteInput.value = d.nome_revenda_cliente || '';
      if (atTelefoneInput) atTelefoneInput.value = d.numero_telefone || '';
      if (atCpfCnpjInput) atCpfCnpjInput.value = d.cpf_cnpj || '';
      if (atCepInput) atCepInput.value = d.cep || '';
      if (atBairroInput) atBairroInput.value = d.bairro || '';
      if (atCidadeInput) atCidadeInput.value = d.cidade || '';
      if (atEstadoInput) atEstadoInput.value = d.estado || '';
      if (atNumeroInput) atNumeroInput.value = d.numero || '';
      if (atRuaInput) atRuaInput.value = d.rua || '';
      if (atAgendarComInput) atAgendarComInput.value = d.agendar_atendimento_com || '';
      if (atModeloInput) atModeloInput.value = d.at_modelo || '';
      if (atTagProblemaInput) atTagProblemaInput.value = d.tag_problema || '';
      if (atPlataformaInput) atPlataformaInput.value = d.plataforma_atendimento || '';
      if (atDescricaoInput) atDescricaoInput.value = ''; // deixa vazio para nova inserção
      const motEl = document.getElementById('atMotivoSolicitacao'); if (motEl) motEl.value = '';
      const iniEl = document.getElementById('atAtendimentoInicial'); if (iniEl) iniEl.value = '';
      showAtWhatsappInboxListView();
      carregarAtWhatsappConversations({ silent: true });
      aplicarVisibilidadeAtCampos();
      carregarHistoricoReclamacao(rowData.ordem_producao || '', rowData.modelo || '');
      setAtSerieBuscaStatus('OS existente carregada. Preencha a nova reclamação e envie.', false);
    } else {
      const modalTitle = document.getElementById('atFormModalTitle');
      if (modalTitle) modalTitle.textContent = 'Nova OS';
      setAtSerieBuscaStatus('Item selecionado e preenchido abaixo da pesquisa.', false);
    }

    closeAtSerieModal();
    abrirTelaAtFormulario();
  });
}

