// ── Modal Inserir rastreabilidade (SAC) ─────────────────────────────────────
(function initSacIdentificacaoModal() {
  const modal = document.getElementById('sacIdentificacaoModal');
  const input = document.getElementById('sacIdentificacaoInput');
  const hiddenId = document.getElementById('sacIdentificacaoEnvioId');
  const statusEl = document.getElementById('sacIdentificacaoModalStatus');
  const btnClose = document.getElementById('sacIdentificacaoModalClose');
  const btnCancel = document.getElementById('sacIdentificacaoCancelarBtn');
  const btnSave = document.getElementById('sacIdentificacaoSalvarBtn');
  if (!modal || !input || !hiddenId || !btnSave) return;
  if (modal.parentElement !== document.body) document.body.appendChild(modal);

  function fecharModalSacIdentificacao() {
    modal.style.display = 'none';
    document.body.style.overflow = '';
    if (statusEl) { statusEl.style.display = 'none'; statusEl.textContent = ''; }
  }

  window.abrirModalSacIdentificacao = function (envioId, valorAtual) {
    hiddenId.value = String(envioId || '');
    input.value = (valorAtual && valorAtual !== '—') ? String(valorAtual).trim() : '';
    if (statusEl) { statusEl.style.display = 'none'; statusEl.textContent = ''; }
    modal.style.display = 'flex';
    document.body.style.overflow = 'hidden';
    setTimeout(function () { input.focus(); }, 50);
  };

  btnClose?.addEventListener('click', fecharModalSacIdentificacao);
  btnCancel?.addEventListener('click', fecharModalSacIdentificacao);
  modal.addEventListener('click', function (e) { if (e.target === modal) fecharModalSacIdentificacao(); });
  document.addEventListener('keydown', function (e) {
    if (e.key === 'Escape' && modal.style.display === 'flex') fecharModalSacIdentificacao();
  });

  btnSave.addEventListener('click', async function () {
    const envioId = hiddenId.value;
    const identificacao = input.value.trim();
    if (!envioId) return;
    if (!identificacao) {
      if (statusEl) {
        statusEl.style.display = 'block';
        statusEl.textContent = 'Informe o código de rastreabilidade.';
      }
      return;
    }
    btnSave.disabled = true;
    try {
      const resp = await fetch('/api/sac/solicitacoes/' + encodeURIComponent(envioId) + '/identificacao', {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({ identificacao: identificacao })
      });
      const data = await resp.json().catch(function () { return {}; });
      if (!resp.ok || data.ok === false) throw new Error(data.error || 'Falha ao salvar');
      fecharModalSacIdentificacao();
      if (typeof carregarSacSolicitacoes === 'function' && sacTabelaBody) {
        await carregarSacSolicitacoes(sacTabelaBody, { hideDone: false, filterByUser: true });
      }
    } catch (err) {
      if (statusEl) {
        statusEl.style.display = 'block';
        statusEl.textContent = err.message || 'Erro ao salvar rastreabilidade.';
      }
    } finally {
      btnSave.disabled = false;
    }
  });

  document.addEventListener('click', function (ev) {
    const btn = ev.target.closest('.btn-sac-inserir-rastreabilidade');
    if (!btn) return;
    ev.preventDefault();
    const envioId = btn.getAttribute('data-envio-id');
    if (!envioId) return;
    const row = btn.closest('tr');
    const identCell = row ? row.querySelector('td:nth-child(4)') : null;
    const valorAtual = identCell ? identCell.textContent.split('\n')[0].trim() : '';
    window.abrirModalSacIdentificacao(envioId, valorAtual);
  });
})();

// ── Helper compartilhado: parse de preferência de agente "__AGENT__:pc:imp" ──
// Definido no escopo global para ser acessível pelas funções de envio e pelo modal de etiquetas
function _etqParseAgentPref(pref) {
  if (!pref || !pref.startsWith('__AGENT__:')) return null;
  const s   = pref.slice('__AGENT__:'.length);
  const idx = s.indexOf(':');
  if (idx === -1) return null;
  return { pcName: s.slice(0, idx), impressora: s.slice(idx + 1) };
}

// ── Envio de Mercadoria: impressora configurável (separada da etiquetas de ID) ──
let _envioImprPref = null;

function _envioImprPrefKey() {
  const u = (document.getElementById('userNameDisplay')?.textContent || 'user').trim().replace(/\s+/g, '_');
  return `envio_printer_pref_${u}`;
}
function _envioCarregarPref() {
  // Carrega localStorage imediatamente (UX responsivo)
  _envioImprPref = localStorage.getItem(_envioImprPrefKey()) || null;
  _envioAtualizarGearBtn();
  // Sincroniza com banco em background
  fetch('/api/usuario/preferencias/impressora_envio')
    .then(r => r.ok ? r.json() : null)
    .then(d => {
      if (d && d.valor) {
        _envioImprPref = d.valor;
        localStorage.setItem(_envioImprPrefKey(), d.valor);
        _envioAtualizarGearBtn();
      }
    })
    .catch(() => {});
}
function _envioSalvarPref(p) {
  _envioImprPref = p || null;
  if (p) localStorage.setItem(_envioImprPrefKey(), p);
  else localStorage.removeItem(_envioImprPrefKey());
  _envioAtualizarGearBtn();
  // Persiste no banco
  fetch('/api/usuario/preferencias', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ chave: 'impressora_envio', valor: p || null })
  }).catch(() => {});
}
function _envioAtualizarGearBtn() {
  const btn = document.getElementById('envioImprGearBtn');
  if (!btn) return;
  if (_envioImprPref) {
    const ag = _etqParseAgentPref(_envioImprPref);
    const label = ag ? `${ag.impressora}` : (_envioImprPref === '__PDF__' ? 'PDF' : _envioImprPref === '__BP__' ? 'Agente' : _envioImprPref);
    btn.title = `Impressora envios: ${label} — clique para trocar`;
    btn.classList.add('etq-pref-set');
  } else {
    btn.title = 'Impressora envios não definida — clique para configurar';
    btn.classList.remove('etq-pref-set');
  }
}

async function _envioMostrarSeletor(container) {
  if (!container) return;
  container.style.display = 'block';
  container.innerHTML = '<div style="padding:12px 14px;color:#facc15;font-size:.85rem;"><i class="fa-solid fa-spinner fa-spin"></i> Buscando impressoras...</div>';
  let agentOpts = '';
  let cupOpts = '';
  try {
    const ar = await fetch('/api/etiquetas/agentes-disponiveis', { credentials: 'include' });
    const ad = await ar.json();
    const agentes = ad.agentes || [];
    if (agentes.length > 0) {
      agentOpts += '<optgroup label="🖨️ Agentes online">';
      for (const ag of agentes) {
        for (const imp of (ag.printers || [])) {
          const val = `__AGENT__:${ag.pcName}:${imp}`;
          agentOpts += `<option value="${escapeHtml(val)}">${escapeHtml(ag.pcName)} → ${escapeHtml(imp)}</option>`;
        }
      }
      agentOpts += '</optgroup>';
    } else {
      agentOpts = '<option value="__BP__">🖨️ Agente local (qualquer)</option>';
    }
  } catch (_) { agentOpts = '<option value="__BP__">🖨️ Agente local (qualquer)</option>'; }
  try {
    const r = await fetch('/api/etiquetas/impressoras', { credentials: 'include' });
    const d = await r.json();
    if (d.impressoras?.length) {
      cupOpts = '<optgroup label="Impressoras servidor">' + d.impressoras.map(p => `<option value="${escapeHtml(p)}">${escapeHtml(p)}</option>`).join('') + '</optgroup>';
    }
  } catch (_) {}
  const prefAtual = _envioImprPref || '';
  container.innerHTML = `
    <div style="padding:12px 14px;">
      <div style="color:#f1f5f9;font-size:.85rem;font-weight:600;margin-bottom:8px;"><i class="fa-solid fa-print" style="color:#7c3aed;margin-right:6px;"></i>Impressora de envios</div>
      <div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;">
        <select id="_envioSelImp" style="background:#0f172a;color:#f1f5f9;border:1px solid #334155;border-radius:6px;padding:5px 8px;font-size:.85rem;flex:1;min-width:140px;">
          <option value="__PDF__">📄 PDF (abrir no navegador)</option>
          ${agentOpts}${cupOpts}
        </select>
        <button id="_envioBtnSalv" style="background:#7c3aed;color:#fff;border:none;border-radius:6px;padding:5px 12px;font-size:.82rem;cursor:pointer;white-space:nowrap;">
          <i class="fa-solid fa-floppy-disk"></i> Salvar
        </button>
        <button id="_envioBtnCanc" style="background:#374151;color:#94a3b8;border:none;border-radius:6px;padding:5px 10px;font-size:.82rem;cursor:pointer;">Cancelar</button>
      </div>
    </div>`;
  if (prefAtual) { const sel = document.getElementById('_envioSelImp'); if (sel) sel.value = prefAtual; }
  document.getElementById('_envioBtnSalv')?.addEventListener('click', () => {
    const printer = document.getElementById('_envioSelImp')?.value || '';
    container.style.display = 'none'; container.innerHTML = '';
    if (printer) _envioSalvarPref(printer);
  });
  document.getElementById('_envioBtnCanc')?.addEventListener('click', () => {
    container.style.display = 'none'; container.innerHTML = '';
  });
}

async function _envioMarcarComoEnviado(envioId) {
  const resp = await fetch(`/api/sac/solicitacoes/${encodeURIComponent(envioId)}/status`, {
    method: 'PATCH',
    headers: { 'Content-Type': 'application/json' },
    credentials: 'include',
    body: JSON.stringify({ status: 'Enviado' }),
  });
  const data = await resp.json().catch(() => ({}));
  if (!resp.ok || data.ok === false) {
    throw new Error(data.error || 'Falha ao marcar envio como Enviado');
  }
}

async function _envioImprimirEtiqueta(envioId, identificacao, btnRef) {
  if (btnRef) btnRef.disabled = true;
  try {
    const pref = _envioImprPref || '__PDF__';
    const ecLimpo = String(identificacao || '').trim().replace(/\s+/g, '');
    // PDF: abre direto no navegador. Caso contrário, enfileira ZPL via backend
    // (independente de ter código ECT — backend resolve via envio_id).
    if (pref === '__PDF__') {
      if (!ecLimpo) throw new Error('Código ECT não disponível para este envio');
      window.open(`/api/vipp/etiqueta?id=${encodeURIComponent(ecLimpo)}&saida=1`, '_blank');
      return;
    }
    // Modo agente/impressora: enfileira ZPL via backend (POST /api/vipp/imprimir-envio)
    const agentDest = _etqParseAgentPref(pref);
    const body = { envio_id: envioId };
    if (agentDest) { body.destino_agente = agentDest.pcName; body.impressora = agentDest.impressora; }
    else if (pref !== '__BP__') { body.impressora = pref; }
    const resp = await fetch('/api/vipp/imprimir-envio', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify(body),
    });
    const data = await resp.json();
    if (!data.ok) throw new Error(data.error || 'Falha ao enfileirar impressão');
    if (btnRef) {
      const orig = btnRef.innerHTML;
      btnRef.innerHTML = '<i class="fa-solid fa-check" style="color:#4ade80;"></i> Enviado!';
      setTimeout(() => { btnRef.innerHTML = orig; }, 3000);
    }
  } catch (err) {
    alert('Erro ao imprimir etiqueta de envio: ' + err.message);
  } finally {
    if (btnRef) btnRef.disabled = false;
  }
}

function setupEnvioPrintButtons(container) {
  if (!container) return;
  _envioCarregarPref();
  container.addEventListener('click', async (ev) => {
    const btnMarcarEnviado = ev.target.closest('.btn-envio-marcar-enviado');
    if (btnMarcarEnviado && !btnMarcarEnviado.disabled) {
      ev.preventDefault();
      const envioId = btnMarcarEnviado.getAttribute('data-envio-id');
      if (!envioId) return;
      btnMarcarEnviado.disabled = true;
      const origHtmlMarcar = btnMarcarEnviado.innerHTML;
      btnMarcarEnviado.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i><span>Salvando...</span>';
      try {
        await _envioMarcarComoEnviado(envioId);
        if (typeof carregarSacSolicitacoes === 'function' && envioMercadoriaTabelaBodyPane) {
          await carregarSacSolicitacoes(envioMercadoriaTabelaBodyPane, { filaLogistica: true });
        }
      } catch (err) {
        alert('Erro ao marcar como Enviado: ' + (err.message || err));
        btnMarcarEnviado.disabled = false;
        btnMarcarEnviado.innerHTML = origHtmlMarcar;
      }
      return;
    }

    const btnVerEtiqueta = ev.target.closest('.btn-envio-ver-etiqueta');
    if (btnVerEtiqueta) {
      ev.preventDefault();
      const envioId = btnVerEtiqueta.getAttribute('data-envio-id');
      const identificacao = btnVerEtiqueta.getAttribute('data-identificacao') || '';
      _envioAbrirEtiquetasPdf(envioId, identificacao);
      return;
    }

    const btnGerar = ev.target.closest('.btn-envio-gerar-etiqueta');
    if (btnGerar && !btnGerar.disabled) {
      ev.preventDefault();
      const envioId = btnGerar.getAttribute('data-envio-id');
      const nSolic = btnGerar.getAttribute('data-n-solic') || '';
      btnGerar.disabled = true;
      const origHtml = btnGerar.innerHTML;
      btnGerar.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i><span>Gerando...</span>';
      try {
        const r = await fetch('/api/vipp/gerar-etiqueta', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          credentials: 'include',
          body: JSON.stringify({ envio_id: envioId, n_solic: nSolic || undefined })
        });
        const d = await r.json().catch(() => ({}));
        if (!r.ok || !d.ok) throw new Error(_vippMsgErroUsuario(d.error || 'Falha ao gerar etiqueta', d));
        if (btnGerar.closest('#sacTabelaBody')) {
          if (typeof carregarSacSolicitacoes === 'function' && sacTabelaBody) {
            await carregarSacSolicitacoes(sacTabelaBody, { hideDone: false, filterByUser: true });
          }
        } else if (typeof carregarSacSolicitacoes === 'function' && envioMercadoriaTabelaBodyPane) {
          carregarSacSolicitacoes(envioMercadoriaTabelaBodyPane, { filaLogistica: true });
        }
      } catch (err) {
        alert(_vippMsgErroUsuario(err));
        btnGerar.disabled = false;
        btnGerar.innerHTML = origHtml;
      }
      return;
    }

    const btn = ev.target.closest('.btn-envio-imprimir');
    if (!btn) return;
    ev.preventDefault();
    const envioId = btn.getAttribute('data-envio-id');
    const identificacao = btn.getAttribute('data-identificacao') || '';
    if (!envioId) return;
    // Se não tem impressora configurada, abre seletor antes de imprimir
    if (!_envioImprPref) {
      const drop = document.getElementById('envioImprGearDropdown');
      if (drop) { await _envioMostrarSeletor(drop); return; }
    }
    const pref = _envioImprPref || '__PDF__';
    btn.disabled = true;
    const origHtml = btn.innerHTML;
    btn.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i><span>Imprimindo...</span>';
    try {
      if (pref === '__PDF__') {
        // PDF: abre etiqueta + declaração HTML em abas separadas
        const ecLimpo = String(identificacao).trim().replace(/\s+/g, '');
        if (ecLimpo) window.open(`/api/vipp/etiqueta?id=${encodeURIComponent(ecLimpo)}&saida=1`, '_blank');
        window.open(`/api/vipp/declaracao?id=${encodeURIComponent(envioId)}`, '_blank');
      } else {
        // Agente/impressora: enfileira etiqueta e declaração em paralelo
        const agentDest = _etqParseAgentPref(pref);
        const base = { envio_id: Number(envioId) };
        if (agentDest) { base.destino_agente = agentDest.pcName; base.impressora = agentDest.impressora; }
        else if (pref !== '__BP__') { base.impressora = pref; }
        const [rEtq, rDec] = await Promise.all([
          fetch('/api/vipp/imprimir-envio', { method: 'POST', headers: { 'Content-Type': 'application/json' }, credentials: 'include', body: JSON.stringify(base) }).then(r => r.json()),
          fetch('/api/vipp/imprimir-declaracao', { method: 'POST', headers: { 'Content-Type': 'application/json' }, credentials: 'include', body: JSON.stringify(base) }).then(r => r.json()),
        ]);
        const erros = [!rEtq.ok && ('Etiqueta: ' + (rEtq.error || 'Erro')), !rDec.ok && ('Declaração: ' + (rDec.error || 'Erro'))].filter(Boolean);
        if (erros.length) throw new Error(erros.join(' | '));
      }
      await _envioMarcarComoEnviado(envioId);
      if (typeof carregarSacSolicitacoes === 'function' && envioMercadoriaTabelaBodyPane) {
        await carregarSacSolicitacoes(envioMercadoriaTabelaBodyPane, { filaLogistica: true });
      } else {
        btn.innerHTML = '<i class="fa-solid fa-check" style="color:#4ade80;"></i><span>Enviado!</span>';
        setTimeout(() => { btn.innerHTML = origHtml; btn.disabled = false; }, 3000);
      }
    } catch (err) {
      alert('Erro ao imprimir: ' + err.message);
      btn.innerHTML = origHtml;
      btn.disabled = false;
    }
  });
}

