  'tecnologia da informacao': ['2.04.77', 'INFORMATICA PERIFERICOS'],
  'suprimentos administrativos': ['2.04.06', 'MATERIAL ESCRITORIO'],
  'eventos comerciais': ['2.02.94', 'Feiras e Eventos'],
