// Registra item do carrinho no banco com status "carrinho"
async function registrarItemCarrinhoNoBanco(item) {
  try {
    const resp = await fetch('/api/compras/carrinho', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify(item)
    });
    const data = await resp.json().catch(() => ({}));
    if (!resp.ok || !data.ok || !data.id) {
      throw new Error(data.error || `Erro ao registrar carrinho (${resp.status})`);
    }
    return { id: data.id, grupo_requisicao: data.grupo_requisicao || null };
  } catch (err) {
    console.error('[CARRINHO] Falha ao registrar item no banco:', err);
    return null;
  }
}

// Atualiza item do carrinho no banco
async function atualizarItemCarrinhoNoBanco(item) {
  const idDb = Number(item?.id_db);
  if (!Number.isFinite(idDb) || idDb <= 0) return;
  try {
    await fetch(`/api/compras/carrinho/${idDb}`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify(item)
    });
  } catch (err) {
    console.warn('[CARRINHO] Falha ao atualizar item no banco:', err);
  }
}

// Remove item do carrinho no banco
async function removerItemCarrinhoNoBanco(item) {
  const idDb = Number(item?.id_db);
  if (!Number.isFinite(idDb) || idDb <= 0) return;
  try {
    await fetch(`/api/compras/carrinho/${idDb}`, {
      method: 'DELETE',
      credentials: 'include'
    });
  } catch (err) {
    console.warn('[CARRINHO] Falha ao remover item no banco:', err);
  }
}

// Carrega itens do carrinho do banco (apenas do solicitante logado)
async function carregarCarrinhoComprasDoBanco() {
  try {
    const resp = await fetch('/api/compras/carrinho', {
      credentials: 'include',
      cache: 'no-store'
    });

    if (resp.status === 304) {
      console.warn('[CARRINHO] Resposta 304 (Not Modified) em /api/compras/carrinho; mantendo estado atual em memória.');
      return;
    }

    const data = await resp.json().catch(() => ({}));
    if (!resp.ok || !data.ok) {
      throw new Error(data.error || 'Erro ao carregar carrinho');
    }

    const itens = Array.isArray(data.itens) ? data.itens : [];
    window.carrinhoCompras = itens.map(item => {
      // Comentário: Busca url_imagem do cache de produtos usando produto_codigo
      let urlImagem = '';
      if (item.produto_codigo && window.produtosCatalogoOmie) {
        const produtoComImagem = window.produtosCatalogoOmie.find(p => 
          String(p.codigo).trim() === String(item.produto_codigo).trim()
        );
        urlImagem = produtoComImagem?.url_imagem || '';
      }
      
      return {
        id_db: item.id,
        produto_codigo: item.produto_codigo,
        produto_descricao: item.produto_descricao,
        quantidade: item.quantidade ?? '',
        prazo_solicitado: item.prazo_solicitado,
        familia_nome: item.familia_produto,
        observacao: item.observacao,
        observacao_reprovacao: item.observacao_reprovacao,
        solicitante: item.solicitante,
        departamento: item.departamento,
        centro_custo: item.centro_custo,
        objetivo_compra: item.objetivo_compra,
        resp_inspecao_recebimento: item.resp_inspecao_recebimento,
        responsavel_pela_compra: item.responsavel_pela_compra,
        retorno_cotacao: item.retorno_cotacao,
        codigo_produto_omie: item.codigo_produto_omie,
        categoria_compra: item.categoria_compra_codigo,
        categoria_compra_codigo: item.categoria_compra_codigo,
        categoria_compra_nome: item.categoria_compra_nome,
        codigo_omie: item.codigo_omie,
        requisicao_direta: item.requisicao_direta,
        anexo_url: item.anexo_url || null,
        grupo_requisicao: item.grupo_requisicao || null,
        np: item.grupo_requisicao || item.np || null,
        anexo: item.anexos || null,
        anexos: item.anexos || null,
        url_imagem: urlImagem  // Adiciona URL da imagem do cache
      };
    });

    renderCarrinhoCompras();
    renderModalCarrinhoCompras();
    renderModalCarrinhoLista();
  } catch (err) {
    console.warn('[CARRINHO] Falha ao carregar itens do banco:', err);
  }
}

// Função global para configurar event listeners de expandir/colapsar nas tabelas de compras
function setupComprasExpandListeners() {
  document.querySelectorAll('.compras-pedido-header').forEach(header => {
    // Remove listener antigo se existir
    const newHeader = header.cloneNode(true);
    header.parentNode.replaceChild(newHeader, header);
    
    // Adiciona novo listener
    newHeader.addEventListener('click', () => {
      const expandId = newHeader.getAttribute('data-expand-id');
      const icon = newHeader.querySelector('.compras-expand-icon');
      const itens = document.querySelectorAll(`.compras-pedido-item[data-pedido="${expandId}"]`);
      
      const isExpanded = itens[0]?.style.display !== 'none';
      
      itens.forEach(item => {
        item.style.display = isExpanded ? 'none' : 'table-row';
      });
      
      if (icon) {
        icon.style.transform = isExpanded ? 'rotate(0deg)' : 'rotate(90deg)';
      }
    });
  });
}

// Renderiza a lista do carrinho
function renderCarrinhoCompras() {
  const tbody = document.getElementById('comprasCarrinhoTbody');
  const countEl = document.getElementById('comprasCarrinhoCount');
  const badgeEl = document.getElementById('carrinhoCountBadge');
  const btnLimpar = document.getElementById('comprasLimparCarrinhoBtn');
  const btnEnviar = document.getElementById('comprasEnviarPedidoBtn');
  const tituloCarrinho = document.getElementById('comprasTituloCarrinho');
  const containerCarrinho = document.getElementById('comprasCarrinhoContainer');
  
  if (!tbody) return;
  
  const carrinho = window.carrinhoCompras || [];
  
  if (countEl) countEl.textContent = carrinho.length;
  
  // Atualiza o badge do botão Abrir Carrinho
  if (badgeEl) {
    badgeEl.textContent = carrinho.length;
    badgeEl.style.display = carrinho.length > 0 ? 'flex' : 'none';
  }
  
  // Atualiza também o badge da Lista de Produtos (página Compras)
  const badgeListaProdutos = document.getElementById('listaProdutosCarrinhoCount');
  if (badgeListaProdutos) {
    badgeListaProdutos.textContent = carrinho.length;
    badgeListaProdutos.style.display = carrinho.length > 0 ? 'flex' : 'none';
  }
  
  // Atualiza também o contador do catálogo Omie se existir
  if (typeof atualizarContadorCatalogo === 'function') {
    atualizarContadorCatalogo();
  }
  
  if (carrinho.length === 0) {
    // Oculta título e container quando vazio
    if (tituloCarrinho) tituloCarrinho.style.display = 'none';
    if (containerCarrinho) containerCarrinho.style.display = 'none';
    if (btnLimpar) btnLimpar.style.display = 'none';
    if (btnEnviar) btnEnviar.style.display = 'none';
    return;
  }
  
  // Mostra título e container quando tem itens
  if (tituloCarrinho) tituloCarrinho.style.display = 'flex';
  if (containerCarrinho) containerCarrinho.style.display = 'block';

  const formatarQtdSeguro = (valor) => {
    if (typeof formatarQuantidadeExibicao === 'function') {
      return formatarQuantidadeExibicao(valor);
    }
    if (typeof window.formatarQuantidadeExibicao === 'function') {
      return window.formatarQuantidadeExibicao(valor);
    }
    if (valor === null || valor === undefined || String(valor).trim() === '') {
      return '-';
    }
    const numero = Number(String(valor).replace(',', '.'));
    if (!Number.isFinite(numero)) {
      return String(valor);
    }
    if (Math.abs(numero - Math.round(numero)) < 1e-9) {
      return String(Math.round(numero));
    }
    return numero.toLocaleString('pt-BR', { minimumFractionDigits: 0, maximumFractionDigits: 4 });
  };
  
  tbody.innerHTML = carrinho.map((item, idx) => {
    const prazoFmt = item.prazo_solicitado || '—';
    const badgeRequisicaoDireta = item.requisicao_direta 
      ? `<span style="display:inline-block;background:#0ea5e9;color:white;padding:2px 6px;border-radius:4px;font-size:11px;font-weight:600;margin-left:6px;" title="Este item será aprovado automaticamente após o envio">
          <i class="fa-solid fa-bolt"></i> REQUISIÇÃO DIRETA
         </span>`
      : '';
    
    return `
      <tr>
        <td>${window.escapeHtml(item.produto_codigo)}</td>
        <td style="max-width:300px;">
          ${window.escapeHtml(item.produto_descricao || '')}
          ${badgeRequisicaoDireta}
        </td>
        <td>${formatarQtdSeguro(item.quantidade)}</td>
        <td>${prazoFmt}</td>
        <td style="max-width:200px;">${window.escapeHtml(item.observacao || '')}</td>
        <td>
          <button class="content-button" data-idx="${idx}" style="padding:4px 8px;background:#ef4444;color:white;font-size:12px;">
            <i class="fa-solid fa-trash"></i>
          </button>
        </td>
      </tr>`;
  }).join('');
  
  if (btnLimpar) btnLimpar.style.display = 'inline-flex';
  if (btnEnviar) btnEnviar.style.display = 'inline-flex';
  
  // Bind botões de remover
  tbody.querySelectorAll('[data-idx]').forEach(btn => {
    btn.addEventListener('click', async () => {
      const idx = parseInt(btn.getAttribute('data-idx'), 10);
      const item = window.carrinhoCompras[idx];
      await removerItemCarrinhoNoBanco(item);
      window.carrinhoCompras.splice(idx, 1);
      renderCarrinhoCompras();
    });
  });
}

