// Variável global para controlar modo de visualização (cards ou lista)
window.carrinhoViewMode = 'grade'; // 'grade' ou 'lista'

// Variável global para armazenar usuários ativos
window.usuariosAtivos = [];

// Obtém o nome do usuário logado
function obterUsuarioLogado() {
  return (document.getElementById('userNameDisplay')?.textContent || '').trim() || 
         window.__sessionUser?.username || 
         '';
}

function garantirCategoriasPadraoProducao(map = window.categoriasPorDepartamento) {
  if (!map) return map;

  const chaveProducao = Object.keys(map).find(key =>
    String(key || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase() === 'producao'
  ) || 'Produção';

  const categorias = Array.isArray(map[chaveProducao]) ? map[chaveProducao] : [];
  const temEmbalagem = categorias.some(cat =>
    String(cat || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase() === 'embalagem dos produtos'
  );

  if (!temEmbalagem) {
    const idxMateriaPrima = categorias.findIndex(cat =>
      String(cat || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase() === 'materia prima'
    );
    if (idxMateriaPrima >= 0) {
      categorias.splice(idxMateriaPrima, 0, 'Embalagem dos produtos');
    } else {
      categorias.push('Embalagem dos produtos');
    }
  }

  map[chaveProducao] = categorias;
  return map;
}

// Carrega departamentos e categorias do backend
async function carregarCategoriasPorDepartamento() {
  try {
    console.log('[CONFIG] Buscando departamentos/categorias...');
    const resp = await fetch('/api/compras/departamentos-categorias', { credentials: 'include' });
    const data = await resp.json().catch(() => ({}));
    console.log('[CONFIG] Resposta departamentos/categorias:', {
      okHttp: resp.ok,
      status: resp.status,
      body: data
    });

    if (!resp.ok || !data.ok) {
      throw new Error(data?.error || 'Erro ao carregar departamentos e categorias');
    }

    const departamentos = Array.isArray(data.departamentos) ? data.departamentos : [];
    window.departamentosConfig = departamentos;
    console.log('[CONFIG] Departamentos carregados:', departamentos.length);

    const map = {};
    departamentos.forEach((dept) => {
      const categorias = Array.isArray(dept.categorias) ? dept.categorias : [];
      map[dept.nome] = categorias.map(cat => cat.nome);
    });
    window.categoriasPorDepartamento = garantirCategoriasPadraoProducao(map);

    return departamentos;
  } catch (err) {
    console.error('[Config] Erro ao carregar departamentos/categorias:', err);
    window.departamentosConfig = [];
    window.categoriasPorDepartamento = {};
    return [];
  }
}

window.carregarCategoriasPorDepartamento = carregarCategoriasPorDepartamento;

// Carrega opções de Departamento no carrinho a partir de configuracoes.departamento
async function carregarDepartamentosCarrinho() {
  const select = document.getElementById('carrinhoDepartamentoGlobal');
  if (!select) return;

  try {
    const resp = await fetch('/api/compras/departamentos', { credentials: 'include' });
    if (!resp.ok) throw new Error('Erro ao buscar departamentos');
    const data = await resp.json();
    const departamentos = Array.isArray(data.departamentos) ? data.departamentos : [];

    const nomes = departamentos
      .map(d => String(d.nome || '').trim())
      .filter(Boolean)
      .sort((a, b) => a.localeCompare(b, 'pt-BR', { sensitivity: 'base' }));

    select.innerHTML = '<option value="">Selecione...</option>' +
      nomes.map(nome => `<option value="${window.escapeHtml(nome)}">${window.escapeHtml(nome)}</option>`).join('');

    const itemBase = (window.carrinhoCompras || []).find(item => item?.departamento || item?.centro_custo);
    const departamentoSalvo = nomes.find(nome =>
      normalizarCategoriaCarrinho(nome) === normalizarCategoriaCarrinho(itemBase?.departamento)
    );
    const padrao = nomes.find(nome => normalizarCategoriaCarrinho(nome) === 'producao');
    select.value = departamentoSalvo || padrao || '';

    // Atualiza categorias do carrinho ao selecionar departamento
    select.onchange = async () => {
      atualizarCategoriasPorDepartamento(select.value, 'carrinhoCentroCustoGlobal');
      await aplicarCategoriaPadraoCarrinho();
    };

    // Inicializa categorias com o departamento atual (se houver)
    atualizarCategoriasPorDepartamento(select.value, 'carrinhoCentroCustoGlobal');
    const categoriaGlobal = document.getElementById('carrinhoCentroCustoGlobal');
    const categoriaSalva = Array.from(categoriaGlobal?.options || []).find(option =>
      normalizarCategoriaCarrinho(option.value) === normalizarCategoriaCarrinho(itemBase?.centro_custo)
    );
    if (categoriaSalva && categoriaGlobal) categoriaGlobal.value = categoriaSalva.value;
    await aplicarCategoriaPadraoCarrinho({ render: false });
  } catch (err) {
    console.error('[CARRINHO] Erro ao carregar departamentos:', err);
    select.innerHTML = '<option value="">Selecione...</option>';
    atualizarCategoriasPorDepartamento('', 'carrinhoCentroCustoGlobal');
  }
}

// Define "Materia prima" como padrão no carrinho quando disponível
async function aplicarCategoriaPadraoCarrinho(options = {}) {
  const opts = options || {};
  const select = document.getElementById('carrinhoCentroCustoGlobal');
  if (!select) return;

  if (!select.value) {
    const option = Array.from(select.options).find(opt =>
      (opt.value || '').toLowerCase() === 'materia prima' ||
      (opt.textContent || '').toLowerCase() === 'materia prima'
    );

    if (option) {
      select.value = option.value;
    }
  }

  const centroCusto = (select.value || '').trim();
  atualizarResumoCategoriaVinculadaCarrinho(centroCusto);
  if (!centroCusto) return;

  const carrinho = window.carrinhoCompras || [];
  let alterouAlgumItem = false;
  await Promise.all(carrinho.map(async (item) => {
    item.centro_custo = centroCusto || item.centro_custo || '';
    const alterouCategoria = aplicarCategoriaCompraOmieOperacionalNoItem(item, centroCusto);
    if (alterouCategoria) {
      alterouAlgumItem = true;
      await atualizarItemCarrinhoNoBanco(item);
    }
  }));

  if (alterouAlgumItem && opts.render !== false) {
    renderCarrinhoCompras();
    renderModalCarrinhoCompras();
  }
}

function atualizarResumoCategoriaVinculadaCarrinho(centroCusto) {
  const hint = document.getElementById('carrinhoCategoriaVinculadaHint');
  if (!hint) return;
  const categoria = obterCategoriaCompraOmieOperacionalCarrinho(centroCusto);
  hint.classList.toggle('is-manual', !categoria);
  hint.innerHTML = categoria
    ? `<i class="fa-solid fa-link"></i><span>Categoria da Compra: <strong>${window.escapeHtml(categoria.nome)}</strong></span>`
    : '<i class="fa-solid fa-circle-info"></i><span>Sem vínculo automático. Escolha a Categoria da Compra nos itens.</span>';
}

function obterCategoriaCompraOmieOperacionalCarrinho(centroCusto) {
  const mapeada = CATEGORIAS_COMPRA_AUTOMATICAS_CARRINHO[normalizarCategoriaCarrinho(centroCusto)];
  if (!mapeada) return null;
  return { codigo: mapeada[0], descricao: mapeada[1], nome: `${mapeada[0]} - ${mapeada[1]}` };
}

function aplicarCategoriaCompraOmieOperacionalNoItem(item, centroCusto) {
  const categoriaOmie = obterCategoriaCompraOmieOperacionalCarrinho(centroCusto);
  if (!item || !categoriaOmie) return false;

  item.categoria_compra = categoriaOmie.codigo;
  item.categoria_compra_codigo = categoriaOmie.codigo;
  item.categoria_compra_nome = categoriaOmie.nome;
  return true;
}

function configurarCategoriaGlobalCarrinho() {
  const select = document.getElementById('carrinhoCentroCustoGlobal');
  if (!select || select.dataset.boundCategoriaGlobal) return;

  select.addEventListener('change', async () => {
    const centroCusto = (select.value || '').trim();
    const carrinho = window.carrinhoCompras || [];

    await Promise.all(carrinho.map(async (item) => {
      item.centro_custo = centroCusto || item.centro_custo || '';
      aplicarCategoriaCompraOmieOperacionalNoItem(item, centroCusto);
      await atualizarItemCarrinhoNoBanco(item);
    }));

    renderCarrinhoCompras();
    renderModalCarrinhoCompras();
  });

  select.dataset.boundCategoriaGlobal = '1';
}

