async function abrirModalCarrinhoComprasLegado() {
  const modal = document.getElementById('modalCarrinhoCompras');
  if (!modal) return;
  
  // Carrega usuários ativos se ainda não foram carregados
  if (window.usuariosAtivos.length === 0) {
    await carregarUsuariosAtivos();
  }
  
  // Sincroniza os dados do carrinho no modal
  await carregarCarrinhoComprasDoBanco();
  configurarPrazoSolicitadoGlobal();
  configurarObjetivoCompraGlobalCarrinho();
  configurarAnexoUrlGlobalCarrinho();
  configurarAnexoArquivoGlobalCarrinho();
  configurarRetornoCotacaoGlobalCarrinho();
  configurarCompraRealizadaGlobalCarrinho();
  await carregarCategoriasPorDepartamento();
  await carregarDepartamentosCarrinho();
  configurarCategoriaGlobalCarrinho();
  await carregarCategoriaCompraDropdown();
  await carregarGruposRequisicaoDisponiveis();
  atualizarBlocoCompraOmieModal();
  renderModalCarrinhoCompras();
  
  // Exibe o modal
  modal.style.display = 'flex';
  setTimeout(() => modal.classList.add('active'), 10);
}

window.abrirModalCarrinhoCompras = async function() {
  const modal = document.getElementById('modalCarrinhoCompras');
  if (!modal) return;

  prepararPadroesAberturaCarrinhoCompras();
  configurarPrazoSolicitadoGlobal();
  configurarObjetivoCompraGlobalCarrinho();
  configurarAnexoUrlGlobalCarrinho();
  configurarAnexoArquivoGlobalCarrinho();
  configurarRetornoCotacaoGlobalCarrinho();
  configurarCompraRealizadaGlobalCarrinho();
  atualizarBlocoCompraOmieModal();

  modal.style.display = 'flex';
  setTimeout(() => modal.classList.add('active'), 10);

  renderCarrinhoCompras();
  renderModalCarrinhoCompras();
  renderModalCarrinhoLista();

  const cargaCarrinho = carregarCarrinhoComprasDoBanco();
  const cargas = [
    window.usuariosAtivos.length === 0 ? carregarUsuariosAtivos() : Promise.resolve(),
    cargaCarrinho,
    (async () => {
      await cargaCarrinho;
      await carregarCategoriasPorDepartamento();
      await carregarDepartamentosCarrinho();
      configurarCategoriaGlobalCarrinho();
      await carregarCategoriaCompraDropdown();
    })(),
    carregarGruposRequisicaoDisponiveis()
  ];

  const resultados = await Promise.allSettled(cargas);
  resultados.forEach((resultado, idx) => {
    if (resultado.status === 'rejected') {
      console.warn(`[CARRINHO] Falha ao carregar recurso do modal (${idx}):`, resultado.reason);
    }
  });

  prepararPadroesAberturaCarrinhoCompras();
  configurarCompraRealizadaGlobalCarrinho();
  renderCarrinhoCompras();
  renderModalCarrinhoCompras();
  renderModalCarrinhoLista();
}

// Fecha o modal do carrinho
function fecharModalCarrinhoCompras() {
  const modal = document.getElementById('modalCarrinhoCompras');
  if (!modal) return;
  
  modal.classList.remove('active');
  setTimeout(() => {
    modal.style.display = 'none';
    // Dispara evento para resetar o botão do carrinho
    window.dispatchEvent(new CustomEvent('carrinhoModalFechado'));
  }, 300);
}

// Carrega lista de usuários ativos
async function carregarUsuariosAtivos() {
  try {
    const response = await fetch('/api/compras/usuarios');
    if (!response.ok) throw new Error('Erro ao carregar usuários');
    const data = await response.json();
    window.usuariosAtivos = data.usuarios || [];
  } catch (err) {
    console.error('[CARRINHO] Erro ao carregar usuários:', err);
    window.usuariosAtivos = [];
  }
}

// Obtém lista de grupos de NP no carrinho
function obterGruposNP() {
  const carrinho = window.carrinhoCompras || [];
  const grupos = new Set();
  carrinho.forEach(item => {
    if (item.np) {
      grupos.add(item.np);
    }
  });
  return Array.from(grupos).sort();
}

// Filtra itens do carrinho por NP
function filtrarCarrinhoPorNP(npSelecionado) {
  const carrinho = window.carrinhoCompras || [];
  if (!npSelecionado) {
    return carrinho;
  }
  return carrinho.filter(item => item.np === npSelecionado);
}

// Atualiza select de filtro de NP
function atualizarSelectFiltroNP() {
  const selectFiltro = document.getElementById('filtroCarrinhoNP');
  if (!selectFiltro) return;
  
  const grupos = obterGruposNP();
  const valorAtual = selectFiltro.value;
  
  selectFiltro.innerHTML = '<option value="">Todos</option>' + 
    grupos.map(np => `<option value="${np}">${np}</option>`).join('');
  
  // Mantém seleção anterior se ainda existir
  if (valorAtual && grupos.includes(valorAtual)) {
    selectFiltro.value = valorAtual;
  } else {
    selectFiltro.value = '';
  }
}

// Renderiza a tabela do carrinho dentro do modal
async function renderModalCarrinhoCompras() {
  const cardsContainer = document.getElementById('modalCarrinhoCards');
  const countEl = document.getElementById('modalCarrinhoCount');
  const btnLimpar = document.getElementById('modalComprasLimparCarrinhoBtn');
  const btnEnviar = document.getElementById('modalComprasEnviarPedidoBtn');
  
  if (!cardsContainer) return;
  
  const carrinho = window.carrinhoCompras || [];
  const selectFiltro = document.getElementById('filtroCarrinhoNP');
  const npSelecionado = selectFiltro ? selectFiltro.value : '';
  const carrinhoFiltrado = filtrarCarrinhoPorNP(npSelecionado);
  const solicitante = (document.getElementById('userNameDisplay')?.textContent || '').trim() 
    || window.__sessionUser?.username || 'Usuário';
  
  if (countEl) countEl.textContent = carrinho.length;
  
  // Atualiza select de NP
  atualizarSelectFiltroNP();
  
  if (carrinhoFiltrado.length === 0) {
    cardsContainer.innerHTML = `
      <div style="grid-column:1/-1;text-align:center;padding:40px 20px;color:var(--inactive-color);">
        <i class="fa-solid fa-cart-shopping" style="font-size:40px;opacity:0.2;display:block;margin-bottom:12px;"></i>
        <div style="font-size:14px;font-weight:500;">${carrinho.length === 0 ? 'Carrinho vazio' : 'Nenhum item neste grupo'}</div>
        <div style="font-size:12px;margin-top:6px;">${carrinho.length === 0 ? 'Clique em "Abrir Catálogo" para adicionar produtos' : ''}</div>
      </div>`;
    if (btnLimpar) btnLimpar.style.display = 'none';
    if (btnEnviar) btnEnviar.style.display = 'none';
    return;
  }
  
  // Agrupa por NP e renderiza em grupos separados
  const obterIdxCarrinho = (item, fallbackIdx) => {
    const idxGlobal = (window.carrinhoCompras || []).indexOf(item);
    return idxGlobal >= 0 ? idxGlobal : fallbackIdx;
  };
  
  const renderItemCarrinhoCard = (item, fallbackIdx) => {
    const idx = obterIdxCarrinho(item, fallbackIdx);
    const itemSolicitante = item.solicitante || solicitante;
    const temAnexo = item.anexo ? true : false;
    
    // Verifica se tem imagem do produto
    const temImagem = item.url_imagem && 
                      item.url_imagem.trim() && 
                      (item.url_imagem.startsWith('http://') || item.url_imagem.startsWith('https://'));
    
    // Verifica se URL está expirada (parâmetro Expires)
    let urlExpirada = false;
    if (temImagem && item.url_imagem.includes('Expires=')) {
      const match = item.url_imagem.match(/Expires=(\d+)/);
      if (match) {
        const expiresTimestamp = parseInt(match[1]);
        const agora = Math.floor(Date.now() / 1000);
        urlExpirada = expiresTimestamp < agora;
      }
    }
    
    // Prepara strings para onclick ANTES de stringify
    const infoProdutoTexto = `${window.escapeHtml(item.produto_codigo)} - ${window.escapeHtml(item.produto_descricao)}`;
    
    // HTML da imagem do produto
    const imgHtml = temImagem && !urlExpirada ? 
      `<img 
        src="${item.url_imagem}" 
        alt="${window.escapeHtml(item.produto_descricao)}"
        style="width:100%;height:100%;object-fit:cover;border-radius:6px;cursor:zoom-in;"
        onclick='if(typeof ampliarImagemProduto === "function") ampliarImagemProduto(${JSON.stringify(item.url_imagem)}, ${JSON.stringify(infoProdutoTexto)});event.stopPropagation();'
        onerror="this.style.display='none';this.nextElementSibling.style.display='flex'"
      />
      <div style="display:none;width:100%;height:100%;align-items:center;justify-content:center;color:#d1d5db;border-radius:6px;background:#f9fafb;">
        <i class="fa-solid fa-image" style="font-size:24px;"></i>
      </div>` :
      `<div style="display:flex;width:100%;height:100%;align-items:center;justify-content:center;color:#d1d5db;border-radius:6px;background:#f9fafb;">
        <i class="fa-solid fa-image" style="font-size:24px;"></i>
      </div>`;
    
    const npExibicao = item.grupo_requisicao || item.np || '';
    const gruposDisponiveis = Array.isArray(window.gruposRequisicaoDisponiveis)
      ? window.gruposRequisicaoDisponiveis
      : [];
    const gruposUnicos = Array.from(new Set([
      npExibicao,
      ...gruposDisponiveis
    ].filter(Boolean)));
    const opcoesGrupo = (gruposUnicos.length ? gruposUnicos : ['']);
    const opcoesGrupoHtml = [
      // Opção para criar novo grupo
      `<option value="__NOVO__" style="color:#10b981;font-weight:600;">+ Criar Novo NP</option>`,
      // Opções existentes
      ...opcoesGrupo.map(grupo => {
        const label = grupo || 'Sem grupo';
        const selected = grupo === npExibicao ? 'selected' : '';
        return `<option value="${grupo}" ${selected}>${label}</option>`;
      })
    ].join('');
    return `
      <div class="carrinho-product-card" style="background:white;border:1px solid #e5e7eb;border-radius:8px;padding:12px;box-shadow:0 1px 2px rgba(0,0,0,0.05);transition:all 0.2s;display:flex;flex-direction:column;gap:12px;"
           onmouseover="this.style.boxShadow='0 2px 8px rgba(0,0,0,0.1)';" 
           onmouseout="this.style.boxShadow='0 1px 2px rgba(0,0,0,0.05)';">
        
        <!-- Linha superior: informações e controles -->
        <div class="carrinho-item-top-row" style="display:flex;gap:12px;align-items:flex-start;">
          
          <!-- Lado Esquerdo: Foto e Info -->
          <div style="flex:1;min-width:0;display:flex;flex-direction:column;gap:8px;">
          
          <!-- Cabeçalho com Foto e Descrição -->
          <div style="display:flex;gap:10px;">
            
            <!-- Foto do Produto -->
            <div style="width:60px;height:60px;flex-shrink:0;border:1px solid #e5e7eb;border-radius:6px;overflow:hidden;background:#f9fafb;">
              ${imgHtml}
            </div>
            
            <!-- Informações do Produto -->
            <div style="flex:1;min-width:0;">
              <div style="display:flex;align-items:center;gap:6px;margin-bottom:4px;flex-wrap:wrap;">
                <span style="background:#3b82f6;color:white;padding:1px 6px;border-radius:3px;font-size:10px;font-weight:700;">
                  NP: ${window.escapeHtml(npExibicao || 'N/A')}
                </span>
                <span style="font-size:11px;font-weight:600;color:#6b7280;">
                  ${window.escapeHtml(item.produto_codigo)}
                </span>
                ${item.requisicao_direta ? `<span style="background:#0ea5e9;color:white;padding:1px 4px;border-radius:3px;font-size:9px;font-weight:600;"><i class="fa-solid fa-bolt"></i> DIRETA</span>` : ''}
              </div>
              <!-- Descrição com quebra de linha -->
              <div style="font-size:11px;font-weight:600;color:#111827;line-height:1.3;word-break:break-word;">
                ${window.escapeHtml(item.produto_descricao || 'Sem descrição')}
              </div>
            </div>
          </div>
          
          </div><!-- fim lado esquerdo -->
          
          <!-- Lado Direito: Quantidade e Botões na MESMA LINHA -->
          <div class="carrinho-item-controles" style="display:flex;gap:6px;align-items:flex-end;">
          
          <!-- Campo Quantidade -->
          <div class="carrinho-item-qtd" style="width:90px;">
            <label style="color:#6b7280;font-weight:500;display:block;margin-bottom:2px;font-size:11px;">
              <i class="fa-solid fa-boxes-stacked" style="margin-right:3px;font-size:10px;"></i>Qtd
            </label>
            <input type="number" class="carrinho-input-quantidade" data-idx="${idx}" 
                   value="${item.quantidade}" min="1"
                   style="width:100%;padding:4px 6px;border:1px solid #d1d5db;border-radius:4px;font-size:11px;font-weight:600;text-align:center;">
          </div>
          
          <!-- Botões de Ação na MESMA LINHA -->
          <div class="carrinho-item-botoes" style="display:flex;gap:6px;align-items:flex-end;">
          <button class="modal-remover-item-btn carrinho-item-acao-remover" data-idx="${idx}" 
                  style="background:#ef4444;color:white;border:none;width:32px;height:32px;border-radius:6px;cursor:pointer;display:flex;align-items:center;justify-content:center;flex-shrink:0;transition:all 0.2s;"
                  onmouseover="this.style.background='#dc2626';" onmouseout="this.style.background='#ef4444';"
                  title="Remover item">
            <i class="fa-solid fa-trash" style="font-size:12px;"></i>
          </button>
          <div class="carrinho-item-confirmar-wrap" style="display:flex;flex-direction:column;align-items:center;gap:4px;">
            ${item.observacao_reprovacao ? `
              <div
                class="carrinho-item-alerta"
                title="${window.escapeHtml(item.observacao_reprovacao)}"
                style="font-size:14px;color:#f59e0b;cursor:help;line-height:1;"
              >
                <i class="fa-solid fa-triangle-exclamation"></i>
              </div>
            ` : ''}
            <button class="carrinho-toggle-detalhes-btn carrinho-item-acao-confirmar" data-idx="${idx}"
                    style="background:#3b82f6;color:white;border:none;width:32px;height:32px;border-radius:6px;cursor:pointer;display:flex;align-items:center;justify-content:center;flex-shrink:0;transition:all 0.2s;"
                    onmouseover="this.style.background='#2563eb';" onmouseout="this.style.background='#3b82f6';"
                    title="Expandir/Recolher detalhes">
              <i class="fa-solid fa-chevron-down" style="font-size:12px;"></i>
            </button>
          </div>
          </div>
          
          </div><!-- fim lado direito -->
        </div><!-- fim linha superior -->
        
        <!-- Campos Expandíveis (sempre em coluna única) -->
        <div class="carrinho-detalhes-expandiveis" data-idx="${idx}" style="display:none;flex-direction:column;gap:4px;font-size:11px;padding-top:8px;border-top:1px solid #f3f4f6;">
        
        <div>
          <label style="color:#6b7280;font-weight:500;display:flex;align-items:center;gap:6px;margin-bottom:2px;">
            <i class="fa-solid fa-tags" style="color:#ec4899;width:12px;font-size:10px;"></i>Categoria da Compra *
          </label>
          <div class="carrinho-item-categoria-wrapper" data-idx="${idx}" style="position:relative;">
            <button type="button" class="carrinho-item-categoria-btn" data-idx="${idx}"
                    style="width:100%;padding:4px 6px;border:1px solid #d1d5db;border-radius:4px;font-size:11px;background:white;font-weight:600;text-align:left;display:flex;align-items:center;justify-content:space-between;gap:8px;">
              <span id="carrinhoItemCategoriaCompraBtnText-${idx}">Selecione...</span>
              <i class="fa-solid fa-chevron-down" style="color:#64748b;"></i>
            </button>
            <input type="hidden" id="carrinhoItemCategoriaCompra-${idx}" data-idx="${idx}" value="${window.escapeHtml(item.categoria_compra || '')}" data-label="" />
            <div id="carrinhoItemCategoriaCompraDropdown-${idx}" class="carrinho-item-categoria-dropdown"
                 style="display:none;position:absolute;top:100%;left:0;right:0;background:white;border:1px solid #d1d5db;border-top:none;border-radius:0 0 6px 6px;max-height:260px;overflow-y:auto;z-index:1200;box-shadow:0 6px 12px rgba(0,0,0,0.12);padding:8px;"></div>
          </div>
        </div>
        
        <div>
          <label style="color:#6b7280;font-weight:500;display:flex;align-items:center;gap:6px;margin-bottom:2px;">
            <i class="fa-solid fa-sort-alpha-down" style="color:#8b5cf6;width:12px;font-size:10px;"></i>NP
          </label>
            <select class="carrinho-input-np" data-idx="${idx}"
                    style="width:100%;padding:4px 6px;border:1px solid #d1d5db;border-radius:4px;font-size:11px;">
              ${opcoesGrupoHtml}
            </select>
        </div>
        
        
        ${temAnexo ? `
        <div style="background:#dbeafe;padding:4px 8px;border-radius:4px;margin-top:2px;">
          <i class="fa-solid fa-paperclip" style="color:#2563eb;font-size:10px;margin-right:4px;"></i>
          <span style="color:#1e40af;font-weight:600;font-size:10px;">
            ${window.escapeHtml(item.anexo.nome)}
          </span>
        </div>
        ` : ''}
        
        </div><!-- fim carrinho-detalhes-expandiveis -->
      
      </div>`;
  };
  
  const gruposNP = carrinhoFiltrado.reduce((acc, item, idx) => {
    const chave = item.grupo_requisicao || item.np || 'Sem NP';
    if (!acc[chave]) acc[chave] = [];
    acc[chave].push({ item, idx });
    return acc;
  }, {});
  
  const ordemGrupos = Object.keys(gruposNP).sort((a, b) => {
    if (a === 'Sem NP') return 1;
    if (b === 'Sem NP') return -1;
    return a.localeCompare(b);
  });
  
  cardsContainer.innerHTML = ordemGrupos.map((np) => {
    const itensGrupo = gruposNP[np] || [];
    const cardsHtml = itensGrupo.map(({ item, idx }) => renderItemCarrinhoCard(item, idx)).join('');
    return `
      <div class="carrinho-np-group" style="grid-column:1/-1;border:1px solid #e5e7eb;border-radius:10px;padding:12px;background:#f9fafb;">
        <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:8px;">
          <div style="font-size:12px;font-weight:700;color:#111827;">Grupo NP: ${window.escapeHtml(np)}</div>
          <div style="font-size:11px;color:#6b7280;">${itensGrupo.length} item(ns)</div>
        </div>
        <div style="display:flex;flex-direction:column;gap:12px;">
          ${cardsHtml}
        </div>
      </div>`;
  }).join('');
  
  if (btnLimpar) btnLimpar.style.display = 'inline-flex';
  if (btnEnviar) btnEnviar.style.display = 'inline-flex';
  
  // Bind botões de expandir/recolher
  cardsContainer.querySelectorAll('.carrinho-toggle-detalhes-btn').forEach(btn => {
    btn.addEventListener('click', async () => {
      const idx = btn.getAttribute('data-idx');
      const detalhesDiv = cardsContainer.querySelector(`.carrinho-detalhes-expandiveis[data-idx="${idx}"]`);
      const icon = btn.querySelector('i');
      
      console.log('[DEBUG CATEGORIA] Botão expandir clicado', { 
        idx, 
        detalhesDiv_existe: !!detalhesDiv 
      });
      
      if (detalhesDiv) {
        if (detalhesDiv.style.display === 'none' || !detalhesDiv.style.display) {
          detalhesDiv.style.display = 'flex';
          icon.className = 'fa-solid fa-chevron-up';
          btn.style.background = '#10b981';
          
          // Busca e aplica categoria da última compra deste produto
          const itemIdx = parseInt(idx, 10);
          const item = window.carrinhoCompras[itemIdx];
          
          console.log('[DEBUG CATEGORIA] Item do carrinho:', { 
            itemIdx, 
            item_existe: !!item,
            produto_codigo: item?.produto_codigo,
            codigo_omie: item?.codigo_omie,
            categoria_atual: item?.categoria_compra,
            item_completo: item
          });
          
          if (item && item.produto_codigo) {
            console.log('[DEBUG CATEGORIA] Chamando aplicarCategoriaCompraPorProdutoCarrinho');
            await aplicarCategoriaCompraPorProdutoCarrinho(item.produto_codigo, itemIdx);
          } else if (item && !item.produto_codigo) {
            console.warn('[DEBUG CATEGORIA] Item não tem produto_codigo!');
          }
        } else {
          detalhesDiv.style.display = 'none';
          icon.className = 'fa-solid fa-chevron-down';
          btn.style.background = '#3b82f6';
        }
      }
    });
  });
  
  // Bind botões de remover no modal
  cardsContainer.querySelectorAll('.modal-remover-item-btn').forEach(btn => {
    btn.addEventListener('click', async () => {
      const idx = parseInt(btn.getAttribute('data-idx'), 10);
      if (confirm('Deseja remover este item do carrinho?')) {
        const item = window.carrinhoCompras[idx];
        await removerItemCarrinhoNoBanco(item);
        window.carrinhoCompras.splice(idx, 1);
        renderModalCarrinhoCompras();
        renderCarrinhoCompras();
      }
    });
  });
  
  // Bind inputs editáveis - atualiza carrinho em tempo real
  cardsContainer.querySelectorAll('.carrinho-input-quantidade').forEach(input => {
    input.addEventListener('change', async (e) => {
      const idx = parseInt(e.target.getAttribute('data-idx'), 10);
      const valor = parseFloat(e.target.value) || 1;
      if (window.carrinhoCompras[idx]) {
        window.carrinhoCompras[idx].quantidade = valor;
        await atualizarItemCarrinhoNoBanco(window.carrinhoCompras[idx]);
        renderCarrinhoCompras();
      }
    });
  });
  
  cardsContainer.querySelectorAll('.carrinho-input-prazo').forEach(input => {
    input.addEventListener('change', async (e) => {
      const idx = parseInt(e.target.getAttribute('data-idx'), 10);
      if (window.carrinhoCompras[idx]) {
        window.carrinhoCompras[idx].prazo_solicitado = e.target.value;
        await atualizarItemCarrinhoNoBanco(window.carrinhoCompras[idx]);
        renderCarrinhoCompras();
      }
    });
  });
  
  cardsContainer.querySelectorAll('.carrinho-input-departamento').forEach(input => {
    input.addEventListener('change', async (e) => {
      const idx = parseInt(e.target.getAttribute('data-idx'), 10);
      if (window.carrinhoCompras[idx]) {
        window.carrinhoCompras[idx].departamento = e.target.value;
        await atualizarItemCarrinhoNoBanco(window.carrinhoCompras[idx]);
        renderCarrinhoCompras();
      }
    });
  });
  
  cardsContainer.querySelectorAll('.carrinho-input-objetivo').forEach(input => {
    input.addEventListener('blur', async (e) => {
      const idx = parseInt(e.target.getAttribute('data-idx'), 10);
      if (window.carrinhoCompras[idx]) {
        window.carrinhoCompras[idx].objetivo_compra = e.target.value.trim();
        await atualizarItemCarrinhoNoBanco(window.carrinhoCompras[idx]);
        renderCarrinhoCompras();
      }
    });
  });
  
  cardsContainer.querySelectorAll('.carrinho-input-categoria').forEach(input => {
    input.addEventListener('change', async (e) => {
      const idx = parseInt(e.target.getAttribute('data-idx'), 10);
      if (window.carrinhoCompras[idx]) {
        window.carrinhoCompras[idx].categoria_compra = e.target.value.trim();
        await atualizarItemCarrinhoNoBanco(window.carrinhoCompras[idx]);
        renderCarrinhoCompras();
      }
    });
  });
  
  cardsContainer.querySelectorAll('.carrinho-input-np').forEach(input => {
    input.addEventListener('change', async (e) => {
      const idx = parseInt(e.target.getAttribute('data-idx'), 10);
      const valorSelecionado = e.target.value;
      
      if (window.carrinhoCompras[idx]) {
        // Se selecionou "Criar Novo NP", gera um novo grupo_requisicao
        if (valorSelecionado === '__NOVO__') {
          try {
            // Chama API para gerar novo grupo_requisicao
            const resp = await fetch('/api/compras/gerar-novo-grupo', {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              credentials: 'include'
            });
            
            if (!resp.ok) {
              throw new Error('Erro ao gerar novo grupo');
            }
            
            const data = await resp.json();
            const novoGrupo = data.grupo_requisicao;
            
            console.log(`[Carrinho] Novo grupo_requisicao criado: ${novoGrupo}`);
            
            // Atualiza o item com o novo grupo
            window.carrinhoCompras[idx].grupo_requisicao = novoGrupo;
            window.carrinhoCompras[idx].np = novoGrupo;
            await atualizarItemCarrinhoNoBanco(window.carrinhoCompras[idx]);
            await carregarGruposRequisicaoDisponiveis();
            atualizarSelectFiltroNP();
            renderModalCarrinhoCompras();
          } catch (err) {
            console.error('[Carrinho] Erro ao criar novo NP:', err);
            alert('Erro ao criar novo NP. Tente novamente.');
            // Reverte para o valor anterior
            e.target.value = window.carrinhoCompras[idx].grupo_requisicao || '';
          }
        } else {
          // Atualização normal de grupo
          window.carrinhoCompras[idx].grupo_requisicao = valorSelecionado || null;
          window.carrinhoCompras[idx].np = valorSelecionado || null;
          await atualizarItemCarrinhoNoBanco(window.carrinhoCompras[idx]);
          await carregarGruposRequisicaoDisponiveis();
          atualizarSelectFiltroNP();
          renderModalCarrinhoCompras();
        }
      }
    });
  });
  
  cardsContainer.querySelectorAll('.carrinho-input-responsavel').forEach(input => {
    input.addEventListener('change', async (e) => {
      const idx = parseInt(e.target.getAttribute('data-idx'), 10);
      if (window.carrinhoCompras[idx]) {
        window.carrinhoCompras[idx].responsavel_pela_compra = e.target.value;
        await atualizarItemCarrinhoNoBanco(window.carrinhoCompras[idx]);
        renderCarrinhoCompras();
      }
    });
  });
  
  cardsContainer.querySelectorAll('.carrinho-input-retorno').forEach(input => {
    input.addEventListener('change', async (e) => {
      const idx = parseInt(e.target.getAttribute('data-idx'), 10);
      if (window.carrinhoCompras[idx]) {
        window.carrinhoCompras[idx].retorno_cotacao = e.target.value;
        await atualizarItemCarrinhoNoBanco(window.carrinhoCompras[idx]);
        renderCarrinhoCompras();
      }
    });
  });
  
  cardsContainer.querySelectorAll('.carrinho-input-requisicao').forEach(input => {
    input.addEventListener('change', async (e) => {
      const idx = parseInt(e.target.getAttribute('data-idx'), 10);
      if (window.carrinhoCompras[idx]) {
        window.carrinhoCompras[idx].requisicao_direta = e.target.value === 'true';
        await atualizarItemCarrinhoNoBanco(window.carrinhoCompras[idx]);
        renderModalCarrinhoCompras(); // Re-renderiza para atualizar o badge
        renderCarrinhoCompras();
      }
    });
  });
  
  // Popula e bind dropdown de Categoria da Compra
  await popularDropdownCategoriaCompraCarrinho(cardsContainer);
}

// Popula dropdown de Categoria da Compra no carrinho com categorias filtradas
async function popularDropdownCategoriaCompraCarrinho(container) {
  try {
    // Busca categorias da API
    const resp = await fetch('/api/compras/categorias-listar', { credentials: 'include' });
    if (!resp.ok) {
      console.error('[CARRINHO] Erro ao buscar categorias:', resp.status);
      return;
    }
    
    const data = await resp.json();
    const categorias = data.categorias || [];
    
    // Filtra apenas categorias com formato x.xx.xx (3 níveis)
    const categoriasFiltradas = categorias.filter(cat => {
      const codigo = String(cat.codigo || '').trim();
      const partes = codigo.split('.');
      return partes.length === 3 && partes.every(p => p.length > 0);
    });
    
    console.log('[CARRINHO] Categorias carregadas:', {
      total: categorias.length,
      filtradas: categoriasFiltradas.length
    });
    
    // Popula todos os dropdowns
    container.querySelectorAll('.carrinho-item-categoria-wrapper').forEach(wrapper => {
      const idx = wrapper.getAttribute('data-idx');
      const dropdown = document.getElementById(`carrinhoItemCategoriaCompraDropdown-${idx}`);
      const btnText = document.getElementById(`carrinhoItemCategoriaCompraBtnText-${idx}`);
      const hiddenInput = document.getElementById(`carrinhoItemCategoriaCompra-${idx}`);
      const btn = wrapper.querySelector('.carrinho-item-categoria-btn');
      
      if (!dropdown || !btn) return;
      
      // Popula dropdown com opções
      dropdown.innerHTML = categoriasFiltradas.map(cat => `
        <div class="carrinho-categoria-option" data-codigo="${window.escapeHtml(cat.codigo)}" 
             data-descricao="${window.escapeHtml(cat.descricao)}" data-idx="${idx}"
             style="padding:6px 10px;cursor:pointer;font-size:11px;border-radius:4px;transition:background 0.15s;color:#111827;">
          <strong style="color:var(--active-color);">${window.escapeHtml(cat.codigo)}</strong> - <span style="color:#111827;">${window.escapeHtml(cat.descricao)}</span>
        </div>
      `).join('');
      
      // Atualiza texto do botão se já tiver valor
      const item = window.carrinhoCompras[parseInt(idx, 10)];
      if (item && item.categoria_compra_nome) {
        btnText.textContent = item.categoria_compra_nome;
        btnText.style.color = 'var(--active-color)';
      } else if (item && item.categoria_compra_codigo) {
        const cat = categoriasFiltradas.find(c => c.codigo === item.categoria_compra_codigo);
        if (cat) {
          btnText.textContent = `${cat.codigo} - ${cat.descricao}`;
          btnText.style.color = 'var(--active-color)';
        }
      }
      
      // Toggle dropdown ao clicar no botão
      btn.addEventListener('click', (e) => {
        e.stopPropagation();
        const isVisible = dropdown.style.display === 'block';
        
        // Fecha todos os outros dropdowns
        document.querySelectorAll('.carrinho-item-categoria-dropdown').forEach(d => {
          d.style.display = 'none';
        });
        
        // Toggle este dropdown
        dropdown.style.display = isVisible ? 'none' : 'block';
      });
      
      // Selecionar opção
      dropdown.querySelectorAll('.carrinho-categoria-option').forEach(option => {
        option.addEventListener('click', async (e) => {
          e.stopPropagation();
          
          const codigo = option.getAttribute('data-codigo');
          const descricao = option.getAttribute('data-descricao');
          const itemIdx = parseInt(option.getAttribute('data-idx'), 10);
          
          console.log('[CARRINHO] Categoria selecionada:', { codigo, descricao, itemIdx });
          
          // Atualiza no carrinho
          if (window.carrinhoCompras[itemIdx]) {
            window.carrinhoCompras[itemIdx].categoria_compra_codigo = codigo;
            window.carrinhoCompras[itemIdx].categoria_compra = codigo;
            window.carrinhoCompras[itemIdx].categoria_compra_nome = `${codigo} - ${descricao}`;
            
            // Salva no banco
            await atualizarItemCarrinhoNoBanco(window.carrinhoCompras[itemIdx]);
            
            // Atualiza UI
            btnText.textContent = `${codigo} - ${descricao}`;
            btnText.style.color = 'var(--active-color)';
            if (hiddenInput) hiddenInput.value = codigo;
            
            console.log('[CARRINHO] Categoria atualizada no item', itemIdx);
          }
          
          // Fecha dropdown
          dropdown.style.display = 'none';
        });
        
        // Hover effect
        option.addEventListener('mouseenter', () => {
          option.style.background = 'var(--bg-hover)';
        });
        option.addEventListener('mouseleave', () => {
          option.style.background = 'transparent';
        });
      });
    });
    
    // Fecha dropdown ao clicar fora
    document.addEventListener('click', (e) => {
      if (!e.target.closest('.carrinho-item-categoria-wrapper')) {
        document.querySelectorAll('.carrinho-item-categoria-dropdown').forEach(d => {
          d.style.display = 'none';
        });
      }
    });
    
  } catch (err) {
    console.error('[CARRINHO] Erro ao popular dropdown de categorias:', err);
  }
}

// Limpar carrinho do modal
function limparCarrinhoModal() {
  if (!confirm('Deseja realmente limpar todo o carrinho?')) return;
  const itens = window.carrinhoCompras || [];
  itens.forEach(item => removerItemCarrinhoNoBanco(item));
  window.carrinhoCompras = [];
  renderModalCarrinhoCompras();
  renderModalCarrinhoLista();
  renderCarrinhoCompras();
}

// Renderiza visualização em lista (tabela) do carrinho
function renderModalCarrinhoLista() {
  const tbody = document.getElementById('modalCarrinhoListaTbody');
  if (!tbody) return;
  
  const carrinho = window.carrinhoCompras || [];
  const selectFiltro = document.getElementById('filtroCarrinhoNP');
  const npSelecionado = selectFiltro ? selectFiltro.value : '';
  const carrinhoFiltrado = filtrarCarrinhoPorNP(npSelecionado);
  
  // Atualiza select de NP
  atualizarSelectFiltroNP();
  
  if (carrinho.length === 0) {
    tbody.innerHTML = `
      <tr>
        <td colspan="12" style="text-align:center;padding:40px;color:var(--inactive-color);">
          <i class="fa-solid fa-cart-shopping" style="font-size:32px;opacity:0.3;display:block;margin-bottom:12px;"></i>
          Carrinho vazio
        </td>
      </tr>`;
    return;
  }
  
  if (carrinhoFiltrado.length === 0) {
    tbody.innerHTML = `
      <tr>
        <td colspan="12" style="text-align:center;padding:40px;color:var(--inactive-color);">
          <i class="fa-solid fa-filter" style="font-size:32px;opacity:0.3;display:block;margin-bottom:12px;"></i>
          Nenhum item neste grupo
        </td>
      </tr>`;
    return;
  }
  
  tbody.innerHTML = carrinhoFiltrado.map((item, filterIdx) => {
    // Encontra o índice real do item no carrinho completo
    const idx = window.carrinhoCompras.indexOf(item);
    // Verifica se tem imagem
    const temImagem = item.url_imagem && 
                      item.url_imagem.trim() && 
                      (item.url_imagem.startsWith('http://') || item.url_imagem.startsWith('https://'));
    
    // Prepara string para onclick ANTES de stringify
    const infoProdutoTexto = window.escapeHtml(item.produto_codigo);
    
    const imgHtml = temImagem ? 
      `<img src="${item.url_imagem}" alt="${window.escapeHtml(item.produto_descricao)}" 
            style="width:40px;height:40px;object-fit:cover;border-radius:4px;cursor:zoom-in;"
            onclick='if(typeof ampliarImagemProduto === "function") ampliarImagemProduto(${JSON.stringify(item.url_imagem)}, ${JSON.stringify(infoProdutoTexto)});event.stopPropagation();'
            onerror="this.style.display='none';">` :
      `<div style="width:40px;height:40px;display:flex;align-items:center;justify-content:center;background:#f3f4f6;border-radius:4px;">
        <i class="fa-solid fa-image" style="color:#d1d5db;font-size:16px;"></i>
      </div>`;
    
    return `
      <tr>
        <td style="position:sticky;left:0;z-index:9;background:#1f2937;text-align:center;padding:8px;">${imgHtml}</td>
        <td style="position:sticky;left:50px;z-index:9;background:#374151;font-weight:600;color:#ffffff;padding:8px;">${window.escapeHtml(item.produto_codigo)}</td>
        <td style="position:sticky;left:130px;z-index:9;background:#374151;padding:8px;max-width:150px;">
          <div style="font-weight:600;color:#ffffff;margin-bottom:2px;font-size:11px;overflow:hidden;text-overflow:ellipsis;display:-webkit-box;-webkit-line-clamp:1;-webkit-box-orient:vertical;word-break:break-word;">${window.escapeHtml(item.produto_descricao || '')}</div>
          ${item.requisicao_direta ? '<span style="background:#0ea5e9;color:white;padding:1px 4px;border-radius:3px;font-size:9px;font-weight:600;"><i class="fa-solid fa-bolt"></i> DIRETA</span>' : ''}
        </td>
        <td>
          <input type="number" class="lista-input-quantidade" data-idx="${idx}" value="${item.quantidade}" min="1"
                 style="width:60px;padding:4px;border:1px solid #d1d5db;border-radius:4px;font-size:11px;">
        </td>
        <td>
          <input type="date" class="lista-input-prazo" data-idx="${idx}" value="${item.prazo_solicitado || ''}"
                 style="width:100%;padding:4px;border:1px solid #d1d5db;border-radius:4px;font-size:11px;">
        </td>
        <td>
          <select class="lista-input-departamento" data-idx="${idx}"
                  style="width:100%;padding:4px;border:1px solid #d1d5db;border-radius:4px;font-size:11px;">
            <option value="Produção" ${item.departamento === 'Produção' ? 'selected' : ''}>Produção</option>
            <option value="Qualidade" ${item.departamento === 'Qualidade' ? 'selected' : ''}>Qualidade</option>
            <option value="Manutenção" ${item.departamento === 'Manutenção' ? 'selected' : ''}>Manutenção</option>
            <option value="Compras" ${item.departamento === 'Compras' ? 'selected' : ''}>Compras</option>
            <option value="Administrativo" ${item.departamento === 'Administrativo' ? 'selected' : ''}>Administrativo</option>
            <option value="Comercial" ${item.departamento === 'Comercial' ? 'selected' : ''}>Comercial</option>
            <option value="Financeiro" ${item.departamento === 'Financeiro' ? 'selected' : ''}>Financeiro</option>
            <option value="Logística" ${item.departamento === 'Logística' ? 'selected' : ''}>Logística</option>
          </select>
        </td>
        <td>
          <input type="text" class="lista-input-objetivo" data-idx="${idx}" 
                 value="${window.escapeHtml(item.objetivo_compra || '')}" placeholder="Objetivo"
                 style="width:100%;padding:4px;border:1px solid #d1d5db;border-radius:4px;font-size:11px;">
        </td>
        <td>
          <select class="lista-input-categoria" data-idx="${idx}"
                  style="width:100%;padding:4px;border:1px solid #d1d5db;border-radius:4px;font-size:11px;">
            <option value="">Selecione...</option>
            ${(window.categoriasCompra || []).map(cat => 
              `<option value="${cat.codigo}" ${item.categoria_compra === cat.codigo ? 'selected' : ''}>${window.escapeHtml(cat.descricao)}</option>`
            ).join('')}
          </select>
        </td>
        <td>
          <select class="lista-input-np" data-idx="${idx}"
                  style="width:100%;padding:4px;border:1px solid #d1d5db;border-radius:4px;font-size:11px;">
            ${(() => {
              const alfabeto = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ'.split('');
              return alfabeto.map(letra => `<option value="${letra}" ${item.np === letra ? 'selected' : ''}>${letra}</option>`).join('');
            })()}
          </select>
        </td>
        <td>
          <select class="lista-input-retorno" data-idx="${idx}"
                  style="width:100%;padding:4px;border:1px solid #d1d5db;border-radius:4px;font-size:11px;">
            <option value="Sim" ${item.retorno_cotacao === 'Sim' ? 'selected' : ''}>Sim</option>
            <option value="Não" ${item.retorno_cotacao === 'Não' ? 'selected' : ''}>Não</option>
          </select>
        </td>
        <td>
          <select class="lista-input-requisicao" data-idx="${idx}"
                  style="width:100%;padding:4px;border:1px solid #d1d5db;border-radius:4px;font-size:11px;">
            <option value="true" ${item.requisicao_direta ? 'selected' : ''}>Sim</option>
            <option value="false" ${!item.requisicao_direta ? 'selected' : ''}>Não</option>
          </select>
        </td>
        <td>
          <select class="lista-input-responsavel" data-idx="${idx}"
                  style="width:100%;padding:4px;border:1px solid #d1d5db;border-radius:4px;font-size:11px;">
            <option value="">Selecione...</option>
            ${window.usuariosAtivos.map(u => {
              const usuarioLogado = obterUsuarioLogado();
              const responsavelAtual = item.responsavel_pela_compra || usuarioLogado;
              return `<option value="${window.escapeHtml(u.username)}" ${responsavelAtual === u.username ? 'selected' : ''}>${window.escapeHtml(u.username)}</option>`;
            }).join('')}
          </select>
        </td>
        <td style="text-align:center;">
          <button class="lista-remover-item-btn" data-idx="${idx}" 
                  style="background:#ef4444;color:white;border:none;padding:6px 8px;border-radius:4px;cursor:pointer;"
                  title="Remover">
            <i class="fa-solid fa-trash" style="font-size:11px;"></i>
          </button>
        </td>
      </tr>`;
  }).join('');
  
  // Event listeners para os inputs da lista
  tbody.querySelectorAll('.lista-input-quantidade').forEach(input => {
    input.addEventListener('change', async (e) => {
      const idx = parseInt(e.target.getAttribute('data-idx'), 10);
      const valor = parseFloat(e.target.value) || 1;
      if (window.carrinhoCompras[idx]) {
        window.carrinhoCompras[idx].quantidade = valor;
        await atualizarItemCarrinhoNoBanco(window.carrinhoCompras[idx]);
        renderCarrinhoCompras();
      }
    });
  });
  
  tbody.querySelectorAll('.lista-input-prazo').forEach(input => {
    input.addEventListener('change', async (e) => {
      const idx = parseInt(e.target.getAttribute('data-idx'), 10);
      if (window.carrinhoCompras[idx]) {
        window.carrinhoCompras[idx].prazo_solicitado = e.target.value;
        await atualizarItemCarrinhoNoBanco(window.carrinhoCompras[idx]);
        renderCarrinhoCompras();
      }
    });
  });
  
  tbody.querySelectorAll('.lista-input-departamento').forEach(input => {
    input.addEventListener('change', async (e) => {
      const idx = parseInt(e.target.getAttribute('data-idx'), 10);
      if (window.carrinhoCompras[idx]) {
        window.carrinhoCompras[idx].departamento = e.target.value;
        await atualizarItemCarrinhoNoBanco(window.carrinhoCompras[idx]);
        renderCarrinhoCompras();
      }
    });
  });

  tbody.querySelectorAll('.lista-input-objetivo').forEach(input => {
    const selecionarTextoObjetivoItem = () => {
      input.select();
    };
    input.addEventListener('focus', selecionarTextoObjetivoItem);
    input.addEventListener('click', selecionarTextoObjetivoItem);
  });
  
  tbody.querySelectorAll('.lista-input-objetivo').forEach(input => {
    input.addEventListener('change', async (e) => {
      const idx = parseInt(e.target.getAttribute('data-idx'), 10);
      if (window.carrinhoCompras[idx]) {
        window.carrinhoCompras[idx].objetivo_compra_nome = e.target.value;
        await atualizarItemCarrinhoNoBanco(window.carrinhoCompras[idx]);
        renderCarrinhoCompras();
      }
    });
  });
  
  tbody.querySelectorAll('.lista-input-objetivo').forEach(input => {
    input.addEventListener('change', async (e) => {
      const idx = parseInt(e.target.getAttribute('data-idx'), 10);
      if (window.carrinhoCompras[idx]) {
        window.carrinhoCompras[idx].objetivo_compra_nome = e.target.value;
        await atualizarItemCarrinhoNoBanco(window.carrinhoCompras[idx]);
        renderCarrinhoCompras();
      }
    });
  });
  
  tbody.querySelectorAll('.lista-input-categoria').forEach(input => {
    input.addEventListener('change', async (e) => {
      const idx = parseInt(e.target.getAttribute('data-idx'), 10);
      if (window.carrinhoCompras[idx]) {
        window.carrinhoCompras[idx].categoria_compra = e.target.value;
        await atualizarItemCarrinhoNoBanco(window.carrinhoCompras[idx]);
        renderCarrinhoCompras();
      }
    });
  });
  
  tbody.querySelectorAll('.lista-input-np').forEach(input => {
    input.addEventListener('change', async (e) => {
      const idx = parseInt(e.target.getAttribute('data-idx'), 10);
      if (window.carrinhoCompras[idx]) {
        window.carrinhoCompras[idx].np = e.target.value;
        await atualizarItemCarrinhoNoBanco(window.carrinhoCompras[idx]);
        atualizarSelectFiltroNP();
        renderModalCarrinhoLista();
      }
    });
  });
  
  tbody.querySelectorAll('.lista-input-retorno').forEach(input => {
    input.addEventListener('change', async (e) => {
      const idx = parseInt(e.target.getAttribute('data-idx'), 10);
      if (window.carrinhoCompras[idx]) {
        window.carrinhoCompras[idx].retorno_cotacao = e.target.value;
        await atualizarItemCarrinhoNoBanco(window.carrinhoCompras[idx]);
        renderCarrinhoCompras();
      }
    });
  });
  
  tbody.querySelectorAll('.lista-input-requisicao').forEach(input => {
    input.addEventListener('change', async (e) => {
      const idx = parseInt(e.target.getAttribute('data-idx'), 10);
      if (window.carrinhoCompras[idx]) {
        window.carrinhoCompras[idx].requisicao_direta = e.target.value === 'true';
        await atualizarItemCarrinhoNoBanco(window.carrinhoCompras[idx]);
        renderCarrinhoCompras();
      }
    });
  });
  
  tbody.querySelectorAll('.lista-input-responsavel').forEach(input => {
    input.addEventListener('change', async (e) => {
      const idx = parseInt(e.target.getAttribute('data-idx'), 10);
      if (window.carrinhoCompras[idx]) {
        window.carrinhoCompras[idx].responsavel_pela_compra = e.target.value;
        await atualizarItemCarrinhoNoBanco(window.carrinhoCompras[idx]);
        renderCarrinhoCompras();
      }
    });
  });
  
  tbody.querySelectorAll('.lista-remover-item-btn').forEach(btn => {
    btn.addEventListener('click', async () => {
      const idx = parseInt(btn.getAttribute('data-idx'), 10);
      if (confirm('Deseja remover este item do carrinho?')) {
        const item = window.carrinhoCompras[idx];
        await removerItemCarrinhoNoBanco(item);
        window.carrinhoCompras.splice(idx, 1);
        renderModalCarrinhoLista();
        renderModalCarrinhoCompras();
        renderCarrinhoCompras();
      }
    });
  });
}

// Enviar pedido do modal
async function enviarPedidoModal() {
  const carrinho = window.carrinhoCompras || [];
  if (carrinho.length === 0) {
    alert('Carrinho vazio!');
    return;
  }

  const solicitanteAtual = (document.getElementById('userNameDisplay')?.textContent || '').trim()
    || window.__sessionUser?.username
    || 'Usuário';
  
  // Captura valores dos campos globais do modal
  const departamentoGlobal = document.getElementById('carrinhoDepartamentoGlobal')?.value?.trim() || null;
  const centroCustoGlobal = document.getElementById('carrinhoCentroCustoGlobal')?.value?.trim() || null;
  const prazoSolicitadoGlobalBruto = document.getElementById('carrinhoPrazoSolicitadoGlobal')?.value || null;
  const objetivoCompraGlobal = document.getElementById('carrinhoObjetivoCompraGlobal')?.value?.trim() || null;
  const anexoUrlGlobal = document.getElementById('carrinhoAnexoUrlGlobal')?.value?.trim() || null;
  const retornoCotacaoGlobalBruto = document.getElementById('carrinhoRetornoCotacaoGlobal')?.value?.trim() || 'Não';
  const anexoArquivoGlobal = document.getElementById('carrinhoAnexosGlobal')?.files?.[0]
    || window.__carrinhoAnexoArquivoGlobal
    || null;
  const compraRealizada = document.getElementById('carrinhoCompraRealizada')?.checked === true;
  const compraAutorizada = (document.getElementById('carrinhoCompraAutorizada')?.checked === true) && !compraRealizada;
  const prazoSolicitadoGlobal = compraRealizada ? null : prazoSolicitadoGlobalBruto;
  const retornoCotacaoGlobal = compraRealizada ? 'Não' : retornoCotacaoGlobalBruto;
  const notaFiscalGlobal = document.getElementById('carrinhoNfeGlobal')?.value?.trim() || '';

  if (compraRealizada && !notaFiscalGlobal) {
    alert('Campo N nota fiscal é obrigatório quando Compra já realizada estiver marcado.');
    const inputNfe = document.getElementById('carrinhoNfeGlobal');
    if (inputNfe) inputNfe.focus();
    return;
  }

  let anexoDataGlobal = null;
  if (anexoArquivoGlobal) {
    try {
      const base64 = await converterArquivoParaBase64(anexoArquivoGlobal);
      anexoDataGlobal = {
        nome: anexoArquivoGlobal.name,
        tipo: anexoArquivoGlobal.type,
        tamanho: anexoArquivoGlobal.size,
        base64
      };
    } catch (errAnexo) {
      alert('Erro ao processar anexo global do carrinho.');
      throw errAnexo;
    }
  }
  
  console.log('[Enviar Pedido] Valores globais capturados:', {
    departamento: departamentoGlobal,
    centro_custo: centroCustoGlobal,
    prazo_solicitado: prazoSolicitadoGlobal,
    objetivo_compra: objetivoCompraGlobal,
    anexo_url: anexoUrlGlobal,
    retorno_cotacao: retornoCotacaoGlobal,
    compra_realizada: compraRealizada,
    n_nota_fiscal: notaFiscalGlobal
  });
  
  // Aplica os valores globais a TODOS os itens do carrinho
  carrinho.forEach((item, idx) => {
    if (departamentoGlobal) {
      item.departamento = departamentoGlobal;
      console.log(`[Enviar Pedido] Item ${idx}: departamento aplicado = ${departamentoGlobal}`);
    }
    if (centroCustoGlobal) {
      item.centro_custo = centroCustoGlobal;
      aplicarCategoriaCompraOmieOperacionalNoItem(item, centroCustoGlobal);
      console.log(`[Enviar Pedido] Item ${idx}: centro_custo aplicado = ${centroCustoGlobal}`);
    }
    if (prazoSolicitadoGlobal) {
      item.prazo_solicitado = prazoSolicitadoGlobal;
      console.log(`[Enviar Pedido] Item ${idx}: prazo_solicitado aplicado = ${prazoSolicitadoGlobal}`);
    }
    if (objetivoCompraGlobal) {
      item.objetivo_compra = objetivoCompraGlobal;
    }

    if (compraRealizada) {
      const objetivoBase = String(item.objetivo_compra || '').replace(/^\s*nfe\s*:\s*/i, '').trim();
      item.nota_fiscal = notaFiscalGlobal;
      item.objetivo_compra = objetivoBase
        ? `NFe: ${notaFiscalGlobal} - ${objetivoBase}`
        : `NFe: ${notaFiscalGlobal}`;
    }

    if (anexoUrlGlobal) {
      item.anexo_url = anexoUrlGlobal;
    }
    item.retorno_cotacao = retornoCotacaoGlobal || 'Não';
    if (anexoDataGlobal) {
      item.anexo = anexoDataGlobal;
      item.anexos = [{
        nome: anexoDataGlobal.nome,
        tipo: anexoDataGlobal.tipo,
        tamanho: anexoDataGlobal.tamanho,
        url: anexoUrlGlobal || null
      }];
    }
    if (compraAutorizada || compraRealizada) {
      item.requisicao_direta = true;
    }
  });
  
  const statusEl = document.getElementById('modalComprasFormStatus');
  const btnEnviar = document.getElementById('modalComprasEnviarPedidoBtn');
  const originalBtnHtml = btnEnviar ? btnEnviar.innerHTML : '';
  let respostasErro = 0;
  
  try {
    // Comentário: segue o mesmo fluxo do botão "Enviar requisição" do modal Cotado
    if (btnEnviar) {
      btnEnviar.disabled = true;
      btnEnviar.style.cursor = 'not-allowed';
      btnEnviar.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i><span>Processando...</span>';
    }
    if (statusEl) {
      statusEl.style.display = 'block';
      statusEl.style.background = '#fef3c7';
      statusEl.style.color = '#92400e';
      statusEl.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> Enviando solicitação...';
    }
    atualizarBlocoCompraOmieModal();
    
    // Separar itens: com requisição direta e sem requisição direta
    const itensComRequisicao = carrinho.filter(item => item.requisicao_direta === true);
    const itensSemRequisicao = carrinho.filter(item => item.requisicao_direta !== true);
    
    // Se há itens com requisição direta, agrupá-los por NP
    const gruposNP = {};
    itensComRequisicao.forEach(item => {
      const np = item.np || 'A';
      if (!gruposNP[np]) {
        gruposNP[np] = [];
      }
      gruposNP[np].push(item);
    });
    
    // Criar lista de solicitações: uma por grupo de NP (requisição direta) + uma para os demais
    const solicitacoes = [];
    
    // Adicionar grupos de NP com requisição direta
    Object.entries(gruposNP).forEach(([np, itens]) => {
      solicitacoes.push({ itens, np, requisicaoDireta: true });
    });
    
    // Adicionar itens sem requisição direta como uma solicitação única
    if (itensSemRequisicao.length > 0) {
      solicitacoes.push({ itens: itensSemRequisicao, np: null, requisicaoDireta: false });
    }
    
    console.log(`[Compras] Enviando ${solicitacoes.length} solicitação(ões):`, solicitacoes);
    
    // Enviar todas as solicitações
    let respostasOk = 0;
    respostasErro = 0;
    const erros = [];
    const numerosCompraOmieGerados = [];
    
    for (let i = 0; i < solicitacoes.length; i++) {
      const sol = solicitacoes[i];
      const descricao = sol.requisicaoDireta 
        ? `Solicitação ${i+1} (NP: ${sol.np}, ${sol.itens.length} itens com Requisição Direta)`
        : `Solicitação ${i+1} (${sol.itens.length} itens sem Requisição Direta)`;
      
      try {
        const itensPayload = (sol.itens || []).map((item) => {
          const itemSolicitante = String(item.solicitante || solicitanteAtual || '').trim();
          const objetivoBase = String(item.objetivo_compra || '').trim();
          const respBase = String(item.resp_inspecao_recebimento || '').trim();
          
          // Objetivo: usa o que foi digitado, ou padrão
          const objetivoFinal = objetivoBase || 'Compra via catálogo Omie';
          // Inspeção: usa o que foi digitado, ou padrão
          const respFinal = respBase || `a pedido de: ${itemSolicitante}`;
          
          // obsItem: formatação limpa com os dados
          const obsItem = `Solicitante: ${itemSolicitante}\nObjetivo: ${objetivoFinal}\nA pedido de: ${respFinal}`;

          return {
            ...item,
            objetivo_compra: objetivoFinal,
            resp_inspecao_recebimento: respFinal,
            obsItem: obsItem
          };
        });

        const response = await fetch('/api/compras/solicitacao', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            itens: itensPayload,
            compra_autorizada: compraAutorizada,
            compra_realizada: compraRealizada,
            n_nota_fiscal: notaFiscalGlobal
          })
        });
        
        const result = await response.json();
        
        if (result.ok) {
          respostasOk++;
          const numerosRetornados = Array.isArray(result.numeros_compra_omie) ? result.numeros_compra_omie : [];
          numerosRetornados.forEach((numero) => {
            const numeroTexto = String(numero || '').trim();
            if (numeroTexto) numerosCompraOmieGerados.push(numeroTexto);
          });
          console.log(`[Compras] ✓ ${descricao} enviada com sucesso`);
        } else {
          respostasErro++;
          const msgErro = result.error || 'Erro desconhecido';
          erros.push(`${descricao}: ${msgErro}`);
          console.error(`[Compras] ✗ ${descricao}: ${msgErro}`);
        }
      } catch (err) {
        respostasErro++;
        erros.push(`${descricao}: ${err.message}`);
        console.error(`[Compras] ✗ ${descricao}:`, err);
      }
    }
    
    // Atualizar status
    if (statusEl) {
      if (respostasErro === 0) {
        const numerosUnicos = Array.from(new Set(numerosCompraOmieGerados));
        statusEl.style.background = '#d1fae5';
        statusEl.style.color = '#065f46';
        statusEl.innerHTML = `<i class="fa-solid fa-check-circle"></i> ${respostasOk} solicitação(ões) enviada(s) com sucesso!`;
        if (numerosUnicos.length > 0) {
          statusEl.innerHTML += `<br><small>Compra(s) gerada(s) na Omie: <strong>${numerosUnicos.join(', ')}</strong></small>`;
          atualizarBlocoCompraOmieModal(numerosUnicos);
          const numerosHtml = numerosUnicos
            .map(numero => `<span style="display:inline-flex;align-items:center;justify-content:center;margin:6px 6px 0 0;padding:7px 12px;border-radius:9px;background:#047857;color:white;font-size:17px;font-weight:900;">${window.escapeHtml ? window.escapeHtml(numero) : numero}</span>`)
            .join('');
          statusEl.innerHTML = `<div style="font-weight:800;font-size:14px;margin-bottom:4px;"><i class="fa-solid fa-check-circle"></i> Pedido de compra enviado com sucesso</div><div style="font-size:12px;">Numero do pedido:</div><div>${numerosHtml}</div>`;
        }
      } else {
        statusEl.style.background = '#fee2e2';
        statusEl.style.color = '#991b1b';
        const erroTexto = erros.length > 0 ? `<br><small>${erros.join('<br>')}</small>` : '';
        statusEl.innerHTML = `<i class="fa-solid fa-exclamation-circle"></i> ${respostasOk} de ${solicitacoes.length} solicitação(ões) enviada(s)${erroTexto}`;
        atualizarBlocoCompraOmieModal();
      }
    }

    // Comentário: restaura o botão após concluir o envio
    if (btnEnviar) {
      btnEnviar.disabled = false;
      btnEnviar.style.cursor = 'pointer';
      btnEnviar.innerHTML = originalBtnHtml;
    }
    
    // Sucesso total retorna ao catalogo sem interromper o fluxo com alert nativo.
    if (respostasErro === 0) {
      window.carrinhoCompras = [];

      const numerosUnicos = Array.from(new Set(numerosCompraOmieGerados));
      renderModalCarrinhoCompras();
      renderCarrinhoCompras();
      voltarParaListaProdutosAposCompra();
      mostrarConfirmacaoLogistica(
        'Solicitacao enviada com sucesso',
        numerosUnicos.length > 0 ? `Pedido Omie: ${numerosUnicos.join(', ')}` : ''
      );
      if (typeof recarregarKanbanMinhasCompras === 'function') {
        recarregarKanbanMinhasCompras();
      }
    }
  } catch (err) {
    console.error('Erro ao enviar pedido:', err);
    if (statusEl) {
      statusEl.style.background = '#fee2e2';
      statusEl.style.color = '#991b1b';
      statusEl.innerHTML = `<i class="fa-solid fa-exclamation-circle"></i> Erro: ${err.message}`;
    }
    if (btnEnviar) {
      btnEnviar.disabled = false;
      btnEnviar.style.cursor = 'pointer';
      btnEnviar.innerHTML = originalBtnHtml;
    }
  }
}

// ========== FIM DO MODAL DO CARRINHO ==========

