// Modal específico para "Kanban de compras" (visualização do usuário solicitante)
async function abrirModalDetalhesPedidoMinhas(numeroPedido, statusColuna, itemIds = null) {
  const modal = document.getElementById('modalDetalhesPedidoCompras');
  const modalBody = document.getElementById('modalPedidoBody');
  const modalTitulo = document.getElementById('modalPedidoTitulo');
  
  if (!modal || !modalBody || !modalTitulo) return;
  
  modalBody.innerHTML = '<div style="text-align:center;padding:40px;"><i class="fa-solid fa-spinner fa-spin" style="font-size:32px;color:#3b82f6;"></i><br><br>Carregando...</div>';
  modal.style.display = 'flex';

  const itemIdAtualNavegacao = String(itemIds || '')
    .split(',')
    .map(v => String(v || '').trim())
    .filter(Boolean)[0] || '';
  renderizarNavegacaoModalKanban({
    modalId: 'modalDetalhesPedidoCompras',
    status: statusColuna,
    currentItemId: itemIdAtualNavegacao,
    openType: 'detalhes-pedido'
  });
  
  const currentUser = (document.getElementById('userNameDisplay')?.textContent || '').trim();
  
  try {
    const fmtQtdModal = (v) => {
      try {
        if (typeof formatarQuantidadeExibicao === 'function') return formatarQuantidadeExibicao(v);
      } catch (_) {}
      if (v === null || v === undefined || v === '') return '-';
      const n = Number(String(v).replace(',', '.'));
      if (!Number.isFinite(n)) return String(v);
      return Math.abs(n - Math.round(n)) < 1e-9
        ? String(Math.round(n))
        : n.toLocaleString('pt-BR', { minimumFractionDigits: 0, maximumFractionDigits: 4 });
    };

    // Comentário: tenta usar o cache do kanban para evitar lista vazia
    let listaCompleta = Array.isArray(window.kanbanMinhasItens) ? window.kanbanMinhasItens : [];

    if (!listaCompleta.length) {
      // Busca apenas os itens do usuário logado
      const resp = await fetch(`/api/compras/minhas?solicitante=${encodeURIComponent(currentUser)}`, { credentials: 'include' });
      if (!resp.ok) throw new Error('Não foi possível carregar as solicitações');
      const data = await resp.json();
      listaCompleta = Array.isArray(data.solicitacoes) ? data.solicitacoes : [];
    }
    
    // Busca itens por diferentes critérios
    let itensPedido;
    
    // Se tiver itemIds específicos, busca por todos eles
    if (itemIds) {
      // Converte para array de IDs (mantém strings como "req_"/"ped_" e números)
      const idsArray = (typeof itemIds === 'string'
        ? itemIds.split(',')
        : [String(itemIds)]
      )
        .map(id => String(id).trim())
        .filter(id => id && id !== 'undefined' && id !== 'null');
      
      itensPedido = listaCompleta.filter(item => idsArray.includes(String(item.id)));
      
      // Fallback: se não encontrou no cache/minhas, busca em /api/compras/todas
      if (itensPedido.length === 0) {
        const respAll = await fetch('/api/compras/todas', { credentials: 'include' });
        if (respAll.ok) {
          const dataAll = await respAll.json();
          const todosItens = Array.isArray(dataAll.solicitacoes) ? dataAll.solicitacoes : [];
          itensPedido = todosItens.filter(item => idsArray.includes(String(item.id)));
        }
      }
    }
    // Se numero_pedido for válido, busca por ele
    else if (numeroPedido && numeroPedido !== 'undefined' && numeroPedido !== 'null' && numeroPedido !== '') {
      itensPedido = listaCompleta.filter(item => item.numero_pedido === numeroPedido);
    }
    // Senão, busca todos os itens com aquele status
    else {
      itensPedido = listaCompleta.filter(item => {
        const itemStatus = (item.status || '').toLowerCase().trim();
        const colunaStatus = statusColuna.toLowerCase().trim();
        return itemStatus === colunaStatus || 
               (colunaStatus === 'cotado aguardando escolha' && itemStatus === 'cotado') ||
               (colunaStatus === 'solicitado revisão' && itemStatus === 'retificar');
      });
    }
    
    if (itensPedido.length === 0) {
      modalBody.innerHTML = '<div style="text-align:center;padding:40px;color:#ef4444;">Nenhum item encontrado.</div>';
      return;
    }

    const primeiroItemPedido = itensPedido[0] || null;
    const grupoRequisicaoModal = String(primeiroItemPedido?.grupo_requisicao || '').trim();
    const tableSourceModal = String(primeiroItemPedido?.table_source || 'solicitacao_compras').trim() || 'solicitacao_compras';
    if (grupoRequisicaoModal && ['solicitacao_compras', 'compras_sem_cadastro'].includes(tableSourceModal)) {
      try {
        const respGrupo = await fetch(
          `/api/compras/grupo-itens?grupo_requisicao=${encodeURIComponent(grupoRequisicaoModal)}&table_source=${encodeURIComponent(tableSourceModal)}`,
          { credentials: 'include' }
        );
        if (respGrupo.ok) {
          const dataGrupo = await respGrupo.json();
          const itensGrupo = Array.isArray(dataGrupo.itens) ? dataGrupo.itens : [];
          if (itensGrupo.length > 0) {
            itensPedido = [{
              ...primeiroItemPedido,
              table_source: tableSourceModal,
              itens: itensGrupo
            }];
          }
        }
      } catch (erroGrupo) {
        console.error('[MODAL MINHAS] Erro ao carregar itens do grupo:', erroGrupo);
      }
    }
    
    modalTitulo.textContent = numeroPedido && numeroPedido !== 'undefined' && numeroPedido !== 'null' 
      ? `Meu Pedido ${numeroPedido}` 
      : `Meus Itens - ${statusColuna}`;

    const fmtDate = (iso) => {
      if (!iso) return '-';
      const d = new Date(iso);
      return Number.isNaN(d.getTime()) ? '-' : d.toLocaleDateString('pt-BR');
    };

    const statusColunaLower = (statusColuna || '').toLowerCase().trim();
    if (
      statusColunaLower === 'aguardando aprovação da requisição' ||
      statusColunaLower === 'aguardando compra preparação' ||
      statusColunaLower === 'aguardando compra' ||
      statusColunaLower === 'compra realizada' ||
      statusColunaLower === 'faturada pelo fornecedor' ||
      statusColunaLower === 'recebido' ||
      statusColunaLower === 'concluído' ||
      statusColunaLower === 'concluido'
    ) {
      
      // Comentário: Para etapas Omie, busca dados especiais do backend
      if (
        statusColunaLower === 'aguardando compra' ||
        statusColunaLower === 'compra realizada' ||
        statusColunaLower === 'faturada pelo fornecedor' ||
        statusColunaLower === 'recebido' ||
        statusColunaLower === 'concluído' ||
        statusColunaLower === 'concluido'
      ) {
        // Busca detalhes especiais do pedido
        const primeiroItemPedido = itensPedido[0];
        if (primeiroItemPedido) {
          try {
            const respDetalhes = await fetch(`/api/compras/pedido-detalhes/${primeiroItemPedido.n_cod_ped || primeiroItemPedido.id}`, { credentials: 'include' });
            if (respDetalhes.ok) {
              const detalhes = await respDetalhes.json();
              
              // Usa os itens do backend se disponível, caso contrário usa os do frontend
              const itensParaMostrar = detalhes.itens && Array.isArray(detalhes.itens) && detalhes.itens.length > 0 
                ? detalhes.itens 
                : (primeiroItemPedido.itens || []);
              
              const linhasItens = itensParaMostrar.map(item => {
                const codigo = escapeHtml(item.produto_codigo || '-');
                const descricao = escapeHtml(item.produto_descricao || 'Sem descrição');
                const quantidade = fmtQtdModal(item.quantidade);
                return `
                  <tr>
                    <td style="padding:10px;border-bottom:1px solid #e5e7eb;">${codigo}</td>
                    <td style="padding:10px;border-bottom:1px solid #e5e7eb;">${descricao}</td>
                    <td style="padding:10px;border-bottom:1px solid #e5e7eb;text-align:center;">${quantidade}</td>
                  </tr>
                `;
              }).join('');

              const createdAt = fmtDate(detalhes.createdAt);
              const previsao = fmtDate(detalhes.d_dt_previsao);
              const dataInclusao = fmtDate(detalhes.d_inc_data);

              modalBody.innerHTML = `
                <div style="display:flex;flex-direction:column;gap:16px;">
                  <div style="padding:16px;background:#f9fafb;border-radius:8px;border:1px solid #e5e7eb;">
                    <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:12px;">
                      <div>
                        <div style="font-size:11px;color:#6b7280;text-transform:uppercase;margin-bottom:4px;">Solicitante</div>
                        <div style="font-weight:600;color:#374151;">${escapeHtml(detalhes.solicitante)}</div>
                      </div>
                      <div>
                        <div style="font-size:11px;color:#6b7280;text-transform:uppercase;margin-bottom:4px;">Data de Inclusão</div>
                        <div style="font-weight:600;color:#374151;">${dataInclusao}</div>
                      </div>
                      <div>
                        <div style="font-size:11px;color:#6b7280;text-transform:uppercase;margin-bottom:4px;">Data de Previsão</div>
                        <div style="font-weight:600;color:#059669;">${previsao}</div>
                      </div>
                      <div>
                        <div style="font-size:11px;color:#6b7280;text-transform:uppercase;margin-bottom:4px;">Departamento</div>
                        <div style="font-weight:600;color:#374151;">${escapeHtml(detalhes.departamento)}</div>
                      </div>
                      <div>
                        <div style="font-size:11px;color:#6b7280;text-transform:uppercase;margin-bottom:4px;">Centro de custo</div>
                        <div style="font-weight:600;color:#374151;">${escapeHtml(detalhes.centroCusto)}</div>
                      </div>
                      <div>
                        <div style="font-size:11px;color:#6b7280;text-transform:uppercase;margin-bottom:4px;">Fornecedor</div>
                        <div style="font-weight:600;color:#374151;display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical;overflow:hidden;word-break:break-word;">${escapeHtml(detalhes.fornecedorNome)}</div>
                      </div>
                      </div>
                      <div style="grid-column:1/-1;">
                        <div style="font-size:11px;color:#6b7280;text-transform:uppercase;margin-bottom:4px;">Objetivo da compra</div>
                        <div style="font-weight:600;color:#374151;">${escapeHtml(detalhes.objetivoCompra)}</div>
                      </div>
                    </div>
                  </div>

                  <div style="padding:16px;background:#ffffff;border-radius:8px;border:1px solid #e5e7eb;">
                    <div style="font-weight:700;color:#1f2937;margin-bottom:10px;">Itens</div>
                    <div style="overflow-x:auto;">
                      <table style="width:100%;border-collapse:collapse;font-size:13px;">
                        <thead>
                          <tr>
                            <th style="text-align:left;padding:10px;border-bottom:2px solid #e5e7eb;">produto_codigo</th>
                            <th style="text-align:left;padding:10px;border-bottom:2px solid #e5e7eb;">produto_descricao</th>
                            <th style="text-align:center;padding:10px;border-bottom:2px solid #e5e7eb;">quantidade</th>
                          </tr>
                        </thead>
                        <tbody>
                          ${linhasItens || '<tr><td colspan="3" style="padding:10px;text-align:center;color:#9ca3af;">Sem produtos</td></tr>'}
                        </tbody>
                      </table>
                    </div>
                  </div>
                </div>
              `;
              return;
            }
          } catch (err) {
            console.error('[Modal] Erro ao buscar detalhes do pedido:', err);
          }
        }
      }
      
      // Comentário: suporta itens agrupados (com array itens) e prioriza dados de compras_sem_cadastro
      const itensDetalhe = itensPedido.flatMap((item) => {
        if (Array.isArray(item.itens) && item.itens.length > 0) {
          return item.itens.map(i => ({
            ...i,
            table_source: i.table_source || item.table_source,
            link: i.link ?? item.link,
            links: i.links ?? item.links
          }));
        }
        return [item];
      });

      const itemSemCadastro = itensDetalhe.find(i => i.table_source === 'compras_sem_cadastro')
        || itensPedido.find(i => i.table_source === 'compras_sem_cadastro')
        || itensDetalhe.find(i => i && (i.link || i.links))
        || itensPedido.find(i => i && (i.link || i.links));
      const primeiro = itemSemCadastro || itensDetalhe[0] || itensPedido[0] || {};

      const normalizarListaLinks = (raw) => {
        if (!raw) return [];
        if (Array.isArray(raw)) return raw.filter(Boolean).map(v => String(v).trim()).filter(Boolean);
        if (typeof raw === 'string') {
          const texto = raw.trim();
          if (!texto) return [];
          try {
            const parsed = JSON.parse(texto);
            if (Array.isArray(parsed)) return parsed.filter(Boolean).map(v => String(v).trim()).filter(Boolean);
          } catch (_) {}
          return [texto];
        }
        return [];
      };

      const montarHtmlLinks = (links) => {
        if (!Array.isArray(links) || links.length === 0) return '-';
        return links.map((link, idx) => {
          const href = /^https?:\/\//i.test(link) ? link : `https://${link}`;
          let nome = `Link ${idx + 1}`;
          try {
            const semQuery = link.split('?')[0];
            nome = decodeURIComponent(semQuery.substring(semQuery.lastIndexOf('/') + 1)) || nome;
          } catch (_) {
            nome = link;
          }
          return `<a href="${escapeHtml(href)}" target="_blank" rel="noopener" style="color:#1d4ed8;text-decoration:underline;">${escapeHtml(nome)}</a>`;
        }).join(' • ');
      };

      const linksSemCadastro = Array.from(new Set(
        itensDetalhe
          .filter(i => i.table_source === 'compras_sem_cadastro' || i.link || i.links)
          .flatMap(i => normalizarListaLinks(i.link || i.links))
      ));

      const campoLinkSemCadastroHtml = itemSemCadastro
        ? `
              <div style="grid-column:1/-1;">
                <div style="font-size:11px;color:#6b7280;text-transform:uppercase;margin-bottom:4px;">Link</div>
                <div style="font-weight:600;color:#374151;word-break:break-word;">${montarHtmlLinks(linksSemCadastro)}</div>
              </div>
            `
        : '';

      const solicitante = escapeHtml(primeiro.solicitante || primeiro.fornecedor_nome || '-');
      const departamento = escapeHtml(primeiro.departamento || '-');
      const centroCusto = escapeHtml(primeiro.centro_custo || '-');
      const objetivoCompra = escapeHtml(primeiro.objetivo_compra || '-');
      const createdAt = fmtDate(primeiro.created_at || primeiro.createdAt || primeiro.data_criacao);

      const expandirItensTabelaModal = (item) => {
        const tableSource = String(item?.table_source || '').trim().toLowerCase();
        const descricaoBruta = String(item?.produto_descricao || item?.descricao || '').trim();
        const codigoBase = String(item?.produto_codigo || '-').trim() || '-';
        const quantidadeBase = obterQuantidadeConfiavel(item, item?.quantidade);

        if (tableSource !== 'compras_sem_cadastro' || !descricaoBruta) {
          return [{
            produto_codigo: codigoBase,
            produto_descricao: descricaoBruta || '-',
            quantidade: quantidadeBase
          }];
        }

        return [{
          produto_codigo: codigoBase,
          produto_descricao: descricaoBruta || '-',
          quantidade: quantidadeBase
        }];
      };

      const itensTabela = itensDetalhe.flatMap(expandirItensTabelaModal);

      const linhasItens = itensTabela.map(item => {
        const codigo = escapeHtml(item.produto_codigo || '-');
        const descricao = escapeHtml(item.produto_descricao || item.descricao || '-');
        const quantidade = fmtQtdModal(obterQuantidadeConfiavel(item, item.quantidade));
        return `
          <tr>
            <td style="padding:10px;border-bottom:1px solid #e5e7eb;">${codigo}</td>
            <td style="padding:10px;border-bottom:1px solid #e5e7eb;">${descricao}</td>
            <td style="padding:10px;border-bottom:1px solid #e5e7eb;text-align:center;">${quantidade}</td>
          </tr>
        `;
      }).join('');

      modalBody.innerHTML = `
        <div style="display:flex;flex-direction:column;gap:16px;">
          <div style="padding:16px;background:#f9fafb;border-radius:8px;border:1px solid #e5e7eb;">
            <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:12px;">
              <div>
                <div style="font-size:11px;color:#6b7280;text-transform:uppercase;margin-bottom:4px;">Solicitante</div>
                <div style="font-weight:600;color:#374151;">${solicitante}</div>
              </div>
              <div>
                <div style="font-size:11px;color:#6b7280;text-transform:uppercase;margin-bottom:4px;">Created at</div>
                <div style="font-weight:600;color:#374151;">${createdAt}</div>
              </div>
              <div>
                <div style="font-size:11px;color:#6b7280;text-transform:uppercase;margin-bottom:4px;">Departamento</div>
                <div style="font-weight:600;color:#374151;">${departamento}</div>
              </div>
              <div>
                <div style="font-size:11px;color:#6b7280;text-transform:uppercase;margin-bottom:4px;">Centro de custo</div>
                <div style="font-weight:600;color:#374151;">${centroCusto}</div>
              </div>
              <div style="grid-column:1/-1;">
                <div style="font-size:11px;color:#6b7280;text-transform:uppercase;margin-bottom:4px;">Objetivo da compra</div>
                <div style="font-weight:600;color:#374151;">${objetivoCompra}</div>
              </div>
              ${campoLinkSemCadastroHtml}
            </div>
          </div>

          <div style="padding:16px;background:#ffffff;border-radius:8px;border:1px solid #e5e7eb;">
            <div style="font-weight:700;color:#1f2937;margin-bottom:10px;">Itens</div>
            <div style="overflow-x:auto;">
              <table style="width:100%;border-collapse:collapse;font-size:13px;">
                <thead>
                  <tr>
                    <th style="text-align:left;padding:10px;border-bottom:2px solid #e5e7eb;">produto_codigo</th>
                    <th style="text-align:left;padding:10px;border-bottom:2px solid #e5e7eb;">produto_descricao</th>
                    <th style="text-align:center;padding:10px;border-bottom:2px solid #e5e7eb;">quantidade</th>
                  </tr>
                </thead>
                <tbody>
                  ${linhasItens}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      `;
      return;
    }

    // Busca cotações apenas para itens cotados
    const cotacoesMap = new Map();
    if (statusColuna === 'cotado aguardando escolha') {
      await Promise.all(itensPedido.map(async (item) => {
        try {
          const cotacoesResp = await fetch(`/api/compras/cotacoes/${item.id}`);
          if (cotacoesResp.ok) {
            const cotacoes = await cotacoesResp.json();
            cotacoesMap.set(item.id, Array.isArray(cotacoes) ? cotacoes : []);
          }
        } catch (e) {
          console.error(`Erro ao buscar cotações do item ${item.id}:`, e);
        }
      }));
    }

    const cotacoesParaAprovacao = statusColuna === 'cotado aguardando escolha'
      ? Array.from(cotacoesMap.values()).flat()
      : [];
    const possuiCotacaoUsdParaAprovacao = cotacoesParaAprovacao.some((cotacao) =>
      String(cotacao?.moeda || 'BRL').toUpperCase() === 'USD'
    );
    const taxaUsdBrlParaAprovacao = possuiCotacaoUsdParaAprovacao
      ? await obterTaxaUsdBrlCotacaoKanban()
      : null;
    
    let html = '<div style="display:flex;flex-direction:column;gap:20px;">';
    
    itensPedido.forEach((item, idx) => {
      const prazo = fmtDate(item.prazo_solicitado);
      const cotacoes = cotacoesMap.get(item.id) || [];
      
      // Escapar strings antes de usar no template
      const codigoEscaped = escapeHtml(item.produto_codigo || '-');
      const statusEscaped = escapeHtml(item.status || 'pendente');
      const descricaoEscaped = escapeHtml(item.produto_descricao || item.descricao || '-');
      
      html += `
        <div style="padding:16px;background:#f9fafb;border-radius:8px;border-left:4px solid #3b82f6;">
          <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(200px,1fr));gap:12px;margin-bottom:12px;">
            <div>
              <div style="font-size:11px;color:#6b7280;text-transform:uppercase;margin-bottom:4px;">ID</div>
              <div style="font-weight:600;color:#374151;">${item.id}</div>
            </div>
            <div>
              <div style="font-size:11px;color:#6b7280;text-transform:uppercase;margin-bottom:4px;">Código</div>
              <div style="font-weight:600;color:#1f2937;">${codigoEscaped}</div>
            </div>
            <div>
              <div style="font-size:11px;color:#6b7280;text-transform:uppercase;margin-bottom:4px;">Quantidade</div>
              <div style="font-weight:600;color:#1f2937;">${fmtQtdModal(item.quantidade)}</div>
            </div>
            <div>
              <div style="font-size:11px;color:#6b7280;text-transform:uppercase;margin-bottom:4px;">Status</div>
              <div><span style="padding:4px 10px;border-radius:6px;background:#3b82f6;color:white;font-size:11px;font-weight:600;">${statusEscaped}</span></div>
            </div>
            <div>
              <div style="font-size:11px;color:#6b7280;text-transform:uppercase;margin-bottom:4px;">Prazo solicitado</div>
              <div style="color:#374151;">${prazo}</div>
            </div>
          </div>
          <div style="grid-column:1/-1;">
            <div style="font-size:11px;color:#6b7280;text-transform:uppercase;margin-bottom:4px;">Descrição</div>
            <div style="color:#374151;">${descricaoEscaped}</div>
          </div>
          
          ${statusColuna === 'solicitado revisão' ? `
          <!-- Histórico de comentários (read-only) -->
          ${item.observacao_retificacao ? `
          <div style="margin-top:12px;padding:12px;background:#fef3c7;border:1px solid #fbbf24;border-radius:6px;">
            <div style="font-weight:600;color:#92400e;margin-bottom:6px;display:flex;align-items:center;gap:6px;">
              <i class="fa-solid fa-comment-dots"></i> Histórico de Comentários
            </div>
            <div style="color:#78350f;font-size:13px;line-height:1.5;white-space:pre-wrap;">
              ${escapeHtml(item.observacao_retificacao)}
            </div>
          </div>
          ` : ''}
          
          <!-- Campo para adicionar novo comentário -->
          <div style="margin-top:12px;padding:12px;background:#e0f2fe;border:1px solid #0ea5e9;border-radius:6px;">
            <div style="font-weight:600;color:#075985;margin-bottom:6px;display:flex;align-items:center;gap:6px;">
              <i class="fa-solid fa-plus-circle"></i> Adicionar Novo Comentário (Obrigatório)
            </div>
            <textarea 
              id="novo-comentario-retificacao-${item.id}" 
              placeholder="Digite seu comentário para voltar este item para Aguardando Compra..."
              style="width:100%;min-height:80px;padding:10px;border:1px solid #0ea5e9;border-radius:6px;font-size:13px;resize:vertical;font-family:inherit;"
            ></textarea>
          </div>
          ` : ''}
          
          ${(statusColuna === 'cotado aguardando escolha' && cotacoes.length > 0) ? `
          <div style="margin-top:16px;padding-top:16px;border-top:2px solid #e5e7eb;">
            <div style="font-weight:600;color:#1f2937;margin-bottom:12px;display:flex;align-items:center;gap:8px;">
              <i class="fa-solid fa-list"></i> Cotações Disponíveis para Aprovação
            </div>
            <div style="display:flex;flex-direction:column;gap:8px;">
              ${cotacoes.map((cotacao, cotIdx) => {
                // Escapar strings da cotação antes de inserir no template
                const fornecedorEscaped = escapeHtml(cotacao.fornecedor_nome || '-');
                const observacaoEscaped = cotacao.observacao ? escapeHtml(cotacao.observacao) : '';
                const valorCotado = Number(cotacao.valor_cotado) || 0;
                const moedaCotada = String(cotacao.moeda || 'BRL').toUpperCase() === 'USD' ? 'USD' : 'BRL';
                const valorCotadoHtml = `${formatarValorCotacaoKanban(valorCotado, moedaCotada)}${formatarConversaoUsdParaBrlCotacaoKanban(valorCotado, moedaCotada, taxaUsdBrlParaAprovacao)}`;
                
                return `
                <div style="background:white;padding:12px;border-radius:6px;border:1px solid #e5e7eb;">
                  <div style="display:grid;grid-template-columns:2fr 1fr auto;gap:12px;align-items:center;">
                    <div>
                      <div style="font-size:11px;color:#6b7280;">Fornecedor</div>
                      <div style="font-weight:600;color:#1f2937;">${fornecedorEscaped}</div>
                    </div>
                    <div>
                      <div style="font-size:11px;color:#6b7280;">Valor Cotado</div>
                      <div style="font-weight:600;color:#059669;">${valorCotadoHtml}</div>
                    </div>
                    <button 
                      id="btn-aprovar-cotacao-${item.id}-${cotacao.id}"
                      onclick="toggleAprovarCotacaoMinhas('${item.id}', ${cotacao.id})"
                      data-aprovado="false"
                      style="background:#10b981;color:white;border:none;padding:8px 16px;border-radius:6px;cursor:pointer;font-size:12px;font-weight:600;display:flex;align-items:center;gap:6px;"
                      title="Aprovar esta cotação">
                      <i class="fa-solid fa-check"></i>
                      Aprovar
                    </button>
                  </div>
                  ${cotacao.observacao ? `
                    <div style="margin-top:8px;padding-top:8px;border-top:1px solid #f3f4f6;">
                      <div style="font-size:11px;color:#6b7280;">Observações</div>
                      <div style="font-size:12px;color:#374151;">${observacaoEscaped}</div>
                    </div>
                  ` : ''}
                  ${(cotacao.anexos && Array.isArray(cotacao.anexos) && cotacao.anexos.length > 0) ? `
                    <div style="margin-top:8px;padding-top:8px;border-top:1px solid #f3f4f6;">
                      <div style="font-size:11px;color:#6b7280;margin-bottom:6px;">Anexos</div>
                      <div style="display:flex;flex-wrap:wrap;gap:6px;">
                        ${cotacao.anexos.map((anexo, anexoIdx) => {
                          const nomeAnexo = anexo.nome || `Anexo ${anexoIdx + 1}`;
                          return `
                          <a 
                            href="${anexo.url || anexo.path || '#'}" 
                            target="_blank"
                            style="display:flex;align-items:center;gap:6px;background:#f3f4f6;padding:6px 10px;border-radius:6px;text-decoration:none;color:#1f2937;font-size:11px;transition:background 0.2s;"
                            onmouseover="this.style.background='#e5e7eb'"
                            onmouseout="this.style.background='#f3f4f6'"
                            title="${nomeAnexo}">
                            <i class="fa-solid fa-paperclip" style="color:#3b82f6;"></i>
                            <span>${nomeAnexo}</span>
                          </a>
                          `;
                        }).join('')}
                      </div>
                    </div>
                  ` : ''}
                </div>
                `;
              }).join('')}
            </div>
          </div>
          ` : ''}
          
          <!-- Botões de Ação conforme status -->
          ${statusColuna === 'aguardando cotação' ? `
          <div style="margin-top:12px;display:flex;gap:8px;">
            <button 
              onclick="editarItemMinhas('${item.id}')"
              style="display:flex;align-items:center;gap:6px;background:#f59e0b;color:white;border:none;padding:8px 14px;border-radius:6px;cursor:pointer;font-size:12px;font-weight:600;"
              title="Editar este item">
              <i class="fa-solid fa-edit"></i>
              Editar
            </button>
            <button 
              onclick="excluirItemMinhas('${item.id}')"
              style="display:flex;align-items:center;gap:6px;background:#ef4444;color:white;border:none;padding:8px 14px;border-radius:6px;cursor:pointer;font-size:12px;font-weight:600;"
              title="Excluir este item">
              <i class="fa-solid fa-trash"></i>
              Excluir
            </button>
          </div>
          ` : ''}
          
          ${statusColuna === 'solicitado revisão' ? `
          <div style="margin-top:12px;display:flex;flex-direction:column;gap:8px;">
            <button 
              onclick="voltarParaAguardandoCompra('${item.id}', '${item.table_source || 'solicitacao_compras'}')"
              style="display:flex;align-items:center;justify-content:center;gap:8px;background:linear-gradient(135deg,#10b981 0%,#059669 100%);color:white;border:none;padding:10px 16px;border-radius:6px;cursor:pointer;font-size:13px;font-weight:600;"
              title="Retificar">
              <i class="fa-solid fa-check-circle"></i>
              Retificar
            </button>
            <button 
              onclick="excluirItemMinhas('${item.id}', '${item.table_source || 'solicitacao_compras'}')"
              style="width:100%;display:flex;align-items:center;justify-content:center;gap:6px;background:#ef4444;color:white;border:none;padding:8px 14px;border-radius:6px;cursor:pointer;font-size:12px;font-weight:600;"
              title="Excluir este item">
              <i class="fa-solid fa-trash"></i>
              Excluir
            </button>
          </div>
          ` : ''}
          
          ${statusColuna === 'cotado aguardando escolha' ? `
          <div style="margin-top:12px;">
            <button 
              onclick="enviarEscolhaMinhas('${item.id}')"
              style="width:100%;display:flex;align-items:center;justify-content:center;gap:8px;background:linear-gradient(135deg,#0ea5e9 0%,#0284c7 100%);color:white;border:none;padding:12px;border-radius:6px;cursor:pointer;font-size:13px;font-weight:700;"
              title="Aprovar cotação e criar requisição na Omie">
              <i class="fa-solid fa-paper-plane"></i>
              Aprovar e Criar Requisição
            </button>
          </div>
          ` : ''}
        </div>
      `;
    });
    
    html += '</div>';
    modalBody.innerHTML = html;
    
  } catch (err) {
    console.error('[MODAL MINHAS] Erro:', err);
    modalBody.innerHTML = '<div style="text-align:center;padding:40px;color:#ef4444;">Erro ao carregar detalhes do pedido.</div>';
  }
}

// Comentário: modal específico para o kanban "Analise de cadastro" (aceita dados vindos do histórico)
async function abrirModalAnaliseCadastro(itemId) {
  const modal = document.getElementById('modalAnaliseCadastro');
  const modalBody = document.getElementById('modalAnaliseCadastroBody');
  const modalTitulo = document.getElementById('modalAnaliseCadastroTitulo');
  if (!modal || !modalBody || !modalTitulo) return;

  modalBody.innerHTML = '<div style="text-align:center;padding:40px;"><i class="fa-solid fa-spinner fa-spin" style="font-size:32px;color:#3b82f6;"></i><br><br>Carregando...</div>';
  modal.style.display = 'flex';
  renderizarNavegacaoModalKanban({
    modalId: 'modalAnaliseCadastro',
    status: 'analise de cadastro',
    currentItemId: itemId,
    openType: 'analise-cadastro'
  });

  const currentUser = (document.getElementById('userNameDisplay')?.textContent || '').trim();

  try {
    const alvoId = String(itemId || '').trim();
    const isItemAnaliseCadastro = (cand) => {
      if (!cand) return false;
      const status = String(cand.statusNormalizado || cand.status || '').toLowerCase().trim();
      return status === 'analise de cadastro';
    };

    const localizarItemAnalise = (lista) => {
      if (!Array.isArray(lista) || !alvoId) return null;
      return lista.find((cand) => {
        if (!isItemAnaliseCadastro(cand)) return false;
        const candId = String(cand.id || '').trim();
        const candHistoricoId = String(cand.historico_id || '').trim();
        const candIdSolicitante = String(cand.id_solicitante || '').trim();
        return candId === alvoId || candHistoricoId === alvoId || candIdSolicitante === alvoId;
      }) || null;
    };

    // Comentário: tenta localizar primeiro no cache do kanban
    const cacheItens = Array.isArray(window.kanbanMinhasItens) ? window.kanbanMinhasItens : [];
    let item = localizarItemAnalise(cacheItens);

    // Fallback 1: endpoint "minhas" (quando existir solicitante na tela)
    if (!item && currentUser) {
      try {
        const resp = await fetch(`/api/compras/minhas?solicitante=${encodeURIComponent(currentUser)}`, { credentials: 'include' });
        if (resp.ok) {
          const data = await resp.json();
          const listaCompleta = Array.isArray(data.solicitacoes) ? data.solicitacoes : [];
          item = localizarItemAnalise(listaCompleta);
        }
      } catch (_err) {
        // segue para próximo fallback
      }
    }

    // Fallback 2: endpoint "todas" para não travar o modal por ausência de solicitante
    if (!item) {
      try {
        const resp = await fetch('/api/compras/todas', { credentials: 'include' });
        if (resp.ok) {
          const data = await resp.json();
          const listaCompleta = Array.isArray(data.solicitacoes) ? data.solicitacoes : [];
          item = localizarItemAnalise(listaCompleta);
        }
      } catch (_err) {
        // mantém fluxo para mensagem de item não encontrado
      }
    }

    if (!item) {
      modalBody.innerHTML = '<div style="text-align:center;padding:40px;color:#ef4444;">Item não encontrado.</div>';
      return;
    }

    modalTitulo.textContent = `Item ${item.id} - Organizando requisição`;

    const fmtDate = (iso) => {
      if (!iso) return '-';
      const d = new Date(iso);
      return Number.isNaN(d.getTime()) ? '-' : d.toLocaleDateString('pt-BR');
    };

    // Comentário: cada registro representa 1 item por linha; não extrair quantidade da descrição
    const processarItensDescricao = (descricao) => {
      if (!descricao || typeof descricao !== 'string') return [];

      return [{
        descricao: String(descricao || '').trim(),
        quantidade: obterQuantidadeConfiavel(item, item?.quantidade)
      }].filter((it) => it.descricao);
    };

    const tableSourceAnalise = String(item.table_source || 'solicitacao_compras').trim() || 'solicitacao_compras';
    const grupoRequisicaoAnalise = String(item.grupo_requisicao || '').trim();
    let itensGrupoAnalise = [];

    if (grupoRequisicaoAnalise) {
      try {
        const respGrupo = await fetch(
          `/api/compras/grupo-itens?grupo_requisicao=${encodeURIComponent(grupoRequisicaoAnalise)}&table_source=${encodeURIComponent(tableSourceAnalise)}`,
          { credentials: 'include' }
        );
        if (respGrupo.ok) {
          const dataGrupo = await respGrupo.json();
          itensGrupoAnalise = Array.isArray(dataGrupo.itens) ? dataGrupo.itens : [];
        }
      } catch (erroGrupo) {
        console.error('[ANALISE CADASTRO] Erro ao carregar itens do grupo:', erroGrupo);
      }
    }

    const itensAnaliseNormalizados = (Array.isArray(itensGrupoAnalise) && itensGrupoAnalise.length > 0)
      ? itensGrupoAnalise.map((it) => ({
          descricao: String(it?.produto_descricao || '').trim(),
          quantidade: it?.quantidade,
          produto_codigo: String(it?.produto_codigo || '').trim(),
          item_origem_id: it?.id
        })).filter((it) => it.descricao || it.produto_codigo)
      : processarItensDescricao(item.produto_descricao);

    window.analiseCadastroCodprovBase = item.produto_codigo || '';
    window.analiseCadastroItens = itensAnaliseNormalizados;
    window.analiseCadastroItemId = item.id;
    window.analiseCadastroTableSource = tableSourceAnalise;
    window.analiseCadastroDirty = false;

    // Comentário: renderiza detalhes do item de compras_sem_cadastro
    let anexosItem = item.anexos;
    if (typeof anexosItem === 'string') {
      try {
        anexosItem = JSON.parse(anexosItem);
      } catch (e) {
        anexosItem = [];
      }
    }
    if (!Array.isArray(anexosItem)) anexosItem = [];
    
    const anexosItemHtml = anexosItem.length > 0 ? `
      <div style="margin-top:12px;">
        <div style="font-size:12px;color:#6b7280;font-weight:600;margin-bottom:8px;">
          <i class="fa-solid fa-paperclip"></i> Anexos do Item:
        </div>
        <div style="display:flex;flex-wrap:wrap;gap:8px;">
          ${anexosItem.map((anexo, idx) => {
            const nome = anexo?.nome || `Anexo ${idx + 1}`;
            const url = anexo?.url || anexo?.path || '#';
            return `
              <a 
                href="${url}" 
                target="_blank" 
                style="display:flex;align-items:center;gap:6px;background:#f3f4f6;padding:8px 12px;border-radius:6px;text-decoration:none;color:#1f2937;font-size:12px;border:1px solid #d1d5db;">
                <i class="fa-solid fa-file" style="color:#3b82f6;"></i>
                <span>${escapeHtml(nome)}</span>
              </a>
            `;
          }).join('')}
        </div>
      </div>
    ` : '';

    const html = `
      <div style="background:#eff6ff;border:2px solid #3b82f6;border-radius:8px;padding:20px;">
        <h4 style="margin:0 0 16px 0;font-size:15px;font-weight:700;color:#1e40af;">
          <i class="fa-solid fa-clipboard-list"></i>
          Detalhes da Solicitação
        </h4>
        <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(250px,1fr));gap:12px;font-size:13px;color:#1f2937;">
          <div><strong>ID:</strong> ${item.id}</div>
          <div><strong>Unidade:</strong> ${escapeHtml(item.unidade || '-')}</div>
          <div><strong>Status:</strong> <span style="background:#dbeafe;color:#1e40af;padding:4px 8px;border-radius:4px;font-weight:600;">${escapeHtml(item.status || '-')}</span></div>
          <div><strong>Solicitante:</strong> ${escapeHtml(item.solicitante || '-')}</div>
          <div><strong>Departamento:</strong> ${escapeHtml(item.departamento || '-')}</div>
          <div><strong>Grupo Requisição:</strong> ${escapeHtml(item.grupo_requisicao || '-')}</div>
          <div><strong>Data Solicitação:</strong> ${fmtDate(item.data_solicitacao)}</div>
          <div><strong>Prazo Solicitado:</strong> ${fmtDate(item.prazo_solicitado)}</div>
          <div><strong>Observações:</strong> ${escapeHtml(item.observacao || '-')}</div>
        </div>
        ${anexosItemHtml}
      </div>
      <div style="margin-top:20px;">
        <h4 style="margin:0 0 12px 0;font-size:14px;font-weight:700;color:#1e40af;">
          <i class="fa-solid fa-list"></i>
          Itens da Solicitação
        </h4>
        <div id="listaItensAnaliseCadastro" style="display:grid;gap:8px;"></div>
        <div style="display:flex;justify-content:flex-end;gap:10px;margin-top:12px;">
          <button id="btnCriarItensOmieAnaliseCadastro" onclick="criarItensOmieAnaliseCadastro()" style="background:#2563eb;color:white;border:none;padding:8px 14px;border-radius:6px;font-size:12px;font-weight:700;cursor:pointer;opacity:1;display:inline-flex;align-items:center;gap:6px;" title="Criar itens na Omie">
            <i class="fa-solid fa-cloud-arrow-up"></i>
            Criar itens na Omie
          </button>
          <button id="btnCriarRequisicaoCompraAnaliseCadastro" onclick="criarRequisicaoCompraAnaliseCadastro()" style="background:#7c3aed;color:white;border:none;padding:8px 14px;border-radius:6px;font-size:12px;font-weight:700;cursor:pointer;opacity:1;display:inline-flex;align-items:center;gap:6px;" title="Criar requisição de compra">
            <i class="fa-solid fa-cart-shopping"></i>
            Criar requisição de compra
          </button>
          <button id="btnSalvarItensAnaliseCadastro" onclick="salvarItensAnaliseCadastro()" style="background:#22c55e;color:white;border:none;padding:8px 14px;border-radius:6px;font-size:12px;font-weight:700;cursor:pointer;opacity:1;display:inline-flex;align-items:center;gap:6px;" title="Salvar alterações">
            <i class="fa-solid fa-floppy-disk"></i>
            Salvar alterações
          </button>
        </div>
      </div>
    `;

    modalBody.innerHTML = html;
    renderizarListaItensAnaliseCadastro();

  } catch (err) {
    console.error('[MODAL ANALISE CADASTRO] Erro:', err);
    const msg = (err && err.message) ? err.message : 'Erro desconhecido ao carregar detalhes do item.';
    modalBody.innerHTML = `<div style="text-align:center;padding:40px;color:#ef4444;">Erro ao carregar detalhes do item.<br><small style="display:block;margin-top:8px;color:#b91c1c;">${escapeHtml(msg)}</small></div>`;
  }
}

// Comentário: fecha o modal de analise de cadastro
function fecharModalAnaliseCadastro() {
  const modal = document.getElementById('modalAnaliseCadastro');
  if (modal) modal.style.display = 'none';
  window.analiseCadastroTableSource = null;
}

// Comentário: formatador local de quantidade exclusivo do modal de Análise de Cadastro
function formatarQuantidadeAnaliseCadastro(valor) {
  if (valor === null || valor === undefined) return '-';
  const bruto = String(valor).trim();
  if (!bruto) return '-';

  let normalizado = bruto;
  const temVirgula = normalizado.includes(',');
  const temPonto = normalizado.includes('.');
  if (temVirgula && temPonto) {
    if (normalizado.lastIndexOf(',') > normalizado.lastIndexOf('.')) {
      normalizado = normalizado.replace(/\./g, '').replace(',', '.');
    } else {
      normalizado = normalizado.replace(/,/g, '');
    }
  } else if (temVirgula) {
    normalizado = normalizado.replace(',', '.');
  }

  const numero = Number(normalizado);
  if (!Number.isFinite(numero)) return bruto;
  if (Math.abs(numero - Math.round(numero)) < 1e-9) return String(Math.round(numero));
  return numero.toLocaleString('pt-BR', { minimumFractionDigits: 0, maximumFractionDigits: 4 });
}

// Comentário: renderiza lista de itens do modal de análise de cadastro
function renderizarListaItensAnaliseCadastro() {
  const container = document.getElementById('listaItensAnaliseCadastro');
  if (!container) return;

  const itens = Array.isArray(window.analiseCadastroItens) ? window.analiseCadastroItens : [];
  const codprovBase = String(window.analiseCadastroCodprovBase || '').trim();

  if (!itens.length) {
    container.innerHTML = '<div style="text-align:center;padding:12px;color:#9ca3af;font-size:12px;">Nenhum item encontrado</div>';
    return;
  }

  const codBaseMatch = codprovBase.match(/(\d+)$/);
  const codBaseNumero = codBaseMatch ? codBaseMatch[1] : '00001';

  container.innerHTML = itens.map((item, idx) => {
    const subIndice = (idx + 1).toString();
    const codprov = `CODPROV - ${codBaseNumero}.${subIndice}`;
    const codigoExibicao = String(item.produto_codigo || '').trim() || codprov;
    const descricao = item.descricao ? escapeHtml(item.descricao) : '';
    const quantidade = escapeHtml(formatarQuantidadeAnaliseCadastro(item.quantidade));

    const codigoOmie = item.codigo_omie ? escapeHtml(item.codigo_omie) : '';
    const jaExiste = !!item.ja_existe_omie;

    return `
      <div style="background:white;border:1px solid #bfdbfe;border-radius:6px;padding:12px;display:grid;grid-template-columns:170px 1fr 110px 150px;gap:12px;align-items:center;">
        <div style="font-weight:600;color:#1e40af;font-size:13px;display:flex;flex-direction:column;gap:6px;">
          <span>${escapeHtml(codigoExibicao)}</span>
          ${codigoOmie ? `
            <span style="font-size:11px;background:#ecfdf5;color:#047857;border:1px solid #a7f3d0;padding:2px 6px;border-radius:6px;width:max-content;">
              Omie: ${codigoOmie}
            </span>
          ` : ''}
          ${jaExiste ? `
            <span style="font-size:11px;background:#fef3c7;color:#92400e;border:1px solid #fde68a;padding:2px 6px;border-radius:6px;width:max-content;">
              Já existe
            </span>
          ` : ''}
        </div>
        <div>
          <input
            type="text"
            value="${descricao}"
            placeholder="Descrição"
            maxlength="120"
            oninput="atualizarItemAnaliseCadastroComContador(${idx}, this)"
            style="width:100%;padding:6px 8px;border:1px solid #d1d5db;border-radius:6px;font-size:12px;"
            id="inputDescAnaliseCadastro_${idx}" />
          <div style="text-align:right;font-size:11px;margin-top:3px;" id="contadorDescAnaliseCadastro_${idx}">
            <span id="contadorNumDesc_${idx}" style="color:${descricao.length > 100 ? (descricao.length >= 120 ? '#dc2626' : '#d97706') : '#6b7280'};">${
              // escapa a expressão para o template literal do servidor
              descricao.length
            }</span><span style="color:#9ca3af;">/120</span>
          </div>
        </div>
        <div>
          <input
            type="text"
            value="${quantidade}"
            placeholder="Quantidade"
            oninput="atualizarItemAnaliseCadastro(${idx}, 'quantidade', this.value)"
            style="width:100%;padding:6px 8px;border:1px solid #d1d5db;border-radius:6px;font-size:12px;text-align:center;" />
        </div>
        <div style="display:flex;gap:8px;justify-content:flex-end;">
          <button onclick="duplicarItemAnaliseCadastro(${idx})" title="Duplicar item" style="background:#e0f2fe;color:#0369a1;border:1px solid #bae6fd;padding:6px 8px;border-radius:6px;font-size:12px;font-weight:700;cursor:pointer;">
            <i class="fa-solid fa-copy"></i>
          </button>
          <button onclick="inserirNovoItemAnaliseCadastro(${idx})" title="Novo abaixo" style="background:#ecfccb;color:#3f6212;border:1px solid #d9f99d;padding:6px 8px;border-radius:6px;font-size:12px;font-weight:700;cursor:pointer;">
            <i class="fa-solid fa-plus"></i>
          </button>
          <button onclick="removerItemAnaliseCadastro(${idx})" title="Excluir item" style="background:#fee2e2;color:#991b1b;border:1px solid #fecaca;padding:6px 8px;border-radius:6px;font-size:12px;font-weight:700;cursor:pointer;">
            <i class="fa-solid fa-trash"></i>
          </button>
        </div>
      </div>
    `;
  }).join('');

  atualizarBotaoSalvarAnaliseCadastro();
}

// Comentário: atualiza o campo descrição E atualiza o contador de caracteres em tempo real
window.atualizarItemAnaliseCadastroComContador = function(index, inputEl) {
  const valor = inputEl.value;
  const len = valor.length;
  const spanNum = document.getElementById(`contadorNumDesc_${index}`);
  if (spanNum) {
    spanNum.textContent = len;
    spanNum.style.color = len >= 120 ? '#dc2626' : len > 100 ? '#d97706' : '#6b7280';
  }
  const itens = Array.isArray(window.analiseCadastroItens) ? window.analiseCadastroItens : [];
  const alvo = itens[index];
  if (!alvo) return;
  alvo['descricao'] = valor.trim();
  window.analiseCadastroDirty = true;
  atualizarBotaoSalvarAnaliseCadastro();
};

// Comentário: atualiza item editado e habilita salvar
window.atualizarItemAnaliseCadastro = function(index, campo, valor) {
  const itens = Array.isArray(window.analiseCadastroItens) ? window.analiseCadastroItens : [];
  const alvo = itens[index];
  if (!alvo) return;
  alvo[campo] = String(valor ?? '').trim();
  window.analiseCadastroDirty = true;
  atualizarBotaoSalvarAnaliseCadastro();
};

function atualizarBotaoSalvarAnaliseCadastro() {
  const btn = document.getElementById('btnSalvarItensAnaliseCadastro');
  if (!btn) return;
  btn.disabled = false;
  btn.style.opacity = '1';
  btn.style.cursor = 'pointer';
}

// Comentário: duplica o item mantendo o sequencial do CODPROV
window.duplicarItemAnaliseCadastro = function(index) {
  const itens = Array.isArray(window.analiseCadastroItens) ? window.analiseCadastroItens : [];
  const alvo = itens[index];
  if (!alvo) return;

  const duplicado = { descricao: alvo.descricao || '', quantidade: alvo.quantidade || '' };
  itens.splice(index + 1, 0, duplicado);
  window.analiseCadastroItens = itens;
  window.analiseCadastroDirty = true;
  renderizarListaItensAnaliseCadastro();
};

// Comentário: insere novo item vazio abaixo do atual
window.inserirNovoItemAnaliseCadastro = function(index) {
  const itens = Array.isArray(window.analiseCadastroItens) ? window.analiseCadastroItens : [];
  itens.splice(index + 1, 0, { descricao: '', quantidade: '' });
  window.analiseCadastroItens = itens;
  window.analiseCadastroDirty = true;
  renderizarListaItensAnaliseCadastro();
};

// Comentário: remove item da lista
window.removerItemAnaliseCadastro = function(index) {
  const itens = Array.isArray(window.analiseCadastroItens) ? window.analiseCadastroItens : [];
  if (!itens[index]) return;
  itens.splice(index, 1);
  window.analiseCadastroItens = itens;
  window.analiseCadastroDirty = true;
  renderizarListaItensAnaliseCadastro();
  if (typeof window.salvarItensAnaliseCadastro === 'function') {
    window.salvarItensAnaliseCadastro();
  }
};

// Comentário: salva alterações na coluna produto_descricao
window.salvarItensAnaliseCadastro = async function() {
  const itemId = window.analiseCadastroItemId;
  if (!itemId) return;
  const tableSource = String(window.analiseCadastroTableSource || 'solicitacao_compras').trim();

  const itens = Array.isArray(window.analiseCadastroItens) ? window.analiseCadastroItens : [];
  if (!itens.length) return;

  try {
    // Salvar cada item individualmente no banco usando seu próprio ID
    for (const item of itens) {
      const rowId = item.item_origem_id || itemId;
      const endpoint = tableSource === 'compras_sem_cadastro'
        ? `/api/compras/sem-cadastro/${rowId}`
        : `/api/compras/solicitacoes/${rowId}`;

      const payload = {};
      if (typeof item.descricao !== 'undefined') {
        payload.produto_descricao = String(item.descricao || '').trim();
      }
      if (typeof item.quantidade !== 'undefined' && item.quantidade !== null && item.quantidade !== '') {
        payload.quantidade = item.quantidade;
      }

      const resp = await fetch(endpoint, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify(payload)
      });

      if (!resp.ok) {
        const errData = await resp.json().catch(() => ({}));
        throw new Error(errData.error || `Erro ao salvar item "${item.descricao}"`);
      }
    }

    window.analiseCadastroDirty = false;
    atualizarBotaoSalvarAnaliseCadastro();
    alert('Itens atualizados com sucesso.');
  } catch (err) {
    console.error('[ANALISE CADASTRO] Erro ao salvar itens:', err);
    alert('Erro ao salvar itens: ' + err.message);
  }
};

// Comentário: cadastra os itens do modal na Omie e retorna os códigos criados
window.criarItensOmieAnaliseCadastro = async function() {
  const itemId = window.analiseCadastroItemId;
  if (!itemId) return;
  const tableSource = String(window.analiseCadastroTableSource || 'solicitacao_compras').trim();

  const itens = Array.isArray(window.analiseCadastroItens) ? window.analiseCadastroItens : [];
  if (!itens.length) {
    alert('Nenhum item para cadastrar na Omie.');
    return;
  }

  const indicesOriginaisCodprov = [];
  const itensCodprov = itens
    .map((item, indexOriginal) => ({ item, indexOriginal }))
    .filter(({ item }) => /^CODPROV\s*-/i.test(String(item?.produto_codigo || '').trim()))
    .map(({ item, indexOriginal }) => {
      indicesOriginaisCodprov.push(indexOriginal);
      return {
        descricao: item?.descricao,
        quantidade: item?.quantidade,
        codigo_omie: item?.codigo_omie || null
      };
    });

  if (!itensCodprov.length) {
    alert('Não há itens com código CODPROV na lista para cadastrar na Omie.');
    return;
  }

  const btn = document.getElementById('btnCriarItensOmieAnaliseCadastro');
  const originalHtml = btn ? btn.innerHTML : '';

  try {
    if (btn) {
      btn.disabled = true;
      btn.style.cursor = 'not-allowed';
      btn.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> Cadastrando...';
    }

    const endpoint = tableSource === 'compras_sem_cadastro'
      ? `/api/compras/sem-cadastro/${itemId}/cadastrar-omie`
      : `/api/compras/solicitacoes/${itemId}/cadastrar-omie`;

    const resp = await fetch(endpoint, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({ itens: itensCodprov })
    });

    if (!resp.ok) {
      const errData = await resp.json().catch(() => ({}));

      throw new Error(errData.error || 'Erro ao cadastrar itens na Omie');
    }

    const data = await resp.json();
    const resultados = Array.isArray(data.itens) ? data.itens : [];

    resultados.forEach((r) => {
      const indexOriginal = Number(indicesOriginaisCodprov[r.index]);
      const alvo = itens[indexOriginal];
      if (alvo) {
        alvo.codigo_omie = r.codigo_produto || '';
        alvo.ja_existe_omie = !!r.ja_existe;
      }
    });

    if (data.base_codigo) {
      window.analiseCadastroCodprovBase = data.base_codigo;
    }

    window.analiseCadastroItens = itens;
    renderizarListaItensAnaliseCadastro();
    alert('Itens cadastrados na Omie com sucesso.');
  } catch (err) {
    console.error('[ANALISE CADASTRO] Erro ao cadastrar itens na Omie:', err);
    alert('Erro ao cadastrar itens na Omie: ' + err.message);
  } finally {
    if (btn) {
      btn.disabled = false;
      btn.style.cursor = 'pointer';
      btn.innerHTML = originalHtml;
    }
  }
};

// Comentário: cria requisição de compra na Omie sem validar retorno de cotação (fluxo compras_sem_cadastro)
window.criarRequisicaoCompraAnaliseCadastro = async function() {
  const itemId = window.analiseCadastroItemId;
  if (!itemId) return;
  const tableSource = String(window.analiseCadastroTableSource || 'solicitacao_compras').trim();

  const itens = Array.isArray(window.analiseCadastroItens) ? window.analiseCadastroItens : [];
  if (!itens.length) {
    alert('Nenhum item para criar requisição.');
    return;
  }

  // Para sem-cadastro: varredura automática — resolve codigo_omie para itens que ainda não têm
  if (tableSource === 'compras_sem_cadastro') {
    const itensSemOmie = itens.filter((i) => !i.codigo_omie && i.produto_codigo);
    if (itensSemOmie.length) {
      try {
        const respResolver = await fetch('/api/compras/resolver-codigos-omie', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          credentials: 'include',
          body: JSON.stringify({ codigos: itensSemOmie.map((i) => i.produto_codigo) })
        });
        if (respResolver.ok) {
          const { resultado } = await respResolver.json();
          // Popula codigo_omie nos itens encontrados
          for (const item of itens) {
            if (!item.codigo_omie && item.produto_codigo && resultado[item.produto_codigo]) {
              item.codigo_omie = resultado[item.produto_codigo];
            }
          }
          window.analiseCadastroItens = itens;
        }
      } catch (e) {
        console.warn('[ANALISE CADASTRO] Erro na varredura de códigos Omie:', e);
      }
    }

    // Após varredura, verifica se ainda há itens sem codigo_omie
    const aindaSemOmie = itens.filter((i) => !i.codigo_omie);
    if (aindaSemOmie.length) {
      const nomes = aindaSemOmie.map((i) => `"${i.descricao || i.produto_codigo || '?'}"`).join(', ');
      alert(`Os seguintes itens não foram encontrados na Omie e precisam ser cadastrados antes:\n${nomes}`);
      return;
    }
  }

  const btn = document.getElementById('btnCriarRequisicaoCompraAnaliseCadastro');
  const originalHtml = btn ? btn.innerHTML : '';

  try {
    if (btn) {
      btn.disabled = true;
      btn.style.cursor = 'not-allowed';
      btn.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> Criando...';
    }

    const resp = tableSource === 'compras_sem_cadastro'
      ? await fetch(`/api/compras/sem-cadastro/${itemId}/criar-requisicao-omie`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          credentials: 'include',
          body: JSON.stringify({ itens })
        })
      : await (async () => {
          const ids = Array.from(new Set(
            itens
              .map((item) => Number(item?.item_origem_id || item?.id))
              .filter((id) => Number.isInteger(id) && id > 0)
          ));

          const idsPayload = ids.length ? ids : [Number(itemId)].filter((id) => Number.isInteger(id) && id > 0);

          return fetch('/api/compras/aprovar-grupo', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            credentials: 'include',
            body: JSON.stringify({ ids: idsPayload })
          });
        })();

    if (!resp.ok) {
      const errData = await resp.json();
      throw new Error(errData.error || 'Erro ao criar requisição na Omie');
    }

    const data = await resp.json();
    const codigoInterno = data.codIntReqCompra || data.numero_pedido || '-';
    const codigoOmie = data.codReqCompra || data.ncodped || '-';
    alert(`Requisição criada com sucesso!\nCódigo interno: ${codigoInterno}\nCódigo Omie: ${codigoOmie}`);
    fecharModalAnaliseCadastro();
    if (typeof loadMinhasSolicitacoes === 'function') {
      loadMinhasSolicitacoes();
    }
  } catch (err) {
    console.error('[ANALISE CADASTRO] Erro ao criar requisição:', err);
    alert('Erro ao criar requisição: ' + err.message);
  } finally {
    if (btn) {
      btn.disabled = false;
      btn.style.cursor = 'pointer';
      btn.innerHTML = originalHtml;
    }
  }
};

// Comentário: modal específico para o kanban "Cotado aguardando escolha" (detalhes do item)
async function abrirModalCotadoEscolhaItem(itemId) {
  const modal = document.getElementById('modalCotadoEscolhaItem');
  const modalBody = document.getElementById('modalCotadoEscolhaBody');
  const modalTitulo = document.getElementById('modalCotadoEscolhaTitulo');
  if (!modal || !modalBody || !modalTitulo) return;

  modalBody.innerHTML = '<div style="text-align:center;padding:40px;"><i class="fa-solid fa-spinner fa-spin" style="font-size:32px;color:#8b5cf6;"></i><br><br>Carregando...</div>';
  modal.style.display = 'flex';
  renderizarNavegacaoModalKanban({
    modalId: 'modalCotadoEscolhaItem',
    status: 'cotado aguardando escolha',
    currentItemId: itemId,
    openType: 'cotado-escolha'
  });

  const currentUser = (document.getElementById('userNameDisplay')?.textContent || '').trim();

  try {
    const idAlvo = String(itemId || '').trim();
    const localizarItemCotado = (itens = []) => {
      if (!Array.isArray(itens) || !idAlvo) return null;
      const normalizados = itens
        .filter(i => i && typeof i === 'object')
        .map(i => ({
          ...i,
          __statusNorm: String(i?.statusNormalizado || i?.status || '').toLowerCase().trim()
        }));

      // 1) Preferência: item cotado com ID exato
      let encontrado = normalizados.find(i => String(i.id || '').trim() === idAlvo && i.__statusNorm === 'cotado');
      if (encontrado) return encontrado;

      // 2) Fallback: qualquer item com ID exato
      encontrado = normalizados.find(i => String(i.id || '').trim() === idAlvo);
      if (encontrado) return encontrado;

      // 3) Fallback: alguns fluxos exibem ID no formato "<id_usuario>.<sequencia>"
      encontrado = normalizados.find(i => String(i.id_solicitante || '').trim() === idAlvo && i.__statusNorm === 'cotado');
      if (encontrado) return encontrado;

      return null;
    };

    // Comentário: tenta localizar primeiro no cache do kanban
    const cacheItens = Array.isArray(window.kanbanMinhasItens) ? window.kanbanMinhasItens : [];
    let item = localizarItemCotado(cacheItens);

    // Fallback 1: endpoint "minhas" (quando existir solicitante na tela)
    if (!item && currentUser) {
      try {
        const resp = await fetch(`/api/compras/minhas?solicitante=${encodeURIComponent(currentUser)}`, { credentials: 'include' });
        if (resp.ok) {
          const data = await resp.json();
          const listaCompleta = Array.isArray(data.solicitacoes) ? data.solicitacoes : [];
          item = localizarItemCotado(listaCompleta);
        }
      } catch (_err) {
        // segue para próximo fallback
      }
    }

    // Fallback 2: endpoint "todas" para não travar o modal por ausência de solicitante
    if (!item) {
      try {
        const resp = await fetch('/api/compras/todas', { credentials: 'include' });
        if (resp.ok) {
          const data = await resp.json();
          const listaCompleta = Array.isArray(data.solicitacoes) ? data.solicitacoes : [];
          item = localizarItemCotado(listaCompleta);
        }
      } catch (_err) {
        // mantém fluxo para mensagem de item não encontrado
      }
    }

    if (!item) {
      modalBody.innerHTML = '<div style="text-align:center;padding:40px;color:#ef4444;">Item não encontrado.</div>';
      return;
    }

    // Comentário: armazena table_source para uso posterior
    const tableSource = item.table_source === 'compras_sem_cadastro' ? 'compras_sem_cadastro' : 'solicitacao_compras';
    window.cotadoEscolhaTableSource = tableSource;

    const statusAtual = (item.status || 'cotado').toString().toLowerCase().trim();
    const statusTitulo = statusAtual === 'aguardando cotação'
      ? 'Aguardando cotação'
      : 'Cotado aguardando escolha';
    modalTitulo.textContent = `Item ${item.id} - ${statusTitulo}`;

    // Comentário: inicializa estado do modal do item cotado
    window.cotadoEscolhaItem = item;
    window.cotadoEscolhaItemId = item.id;
    window.cotadoEscolhaCotacoesDb = [];

    // Comentário: renderiza apenas detalhes do item + cotações registradas
    const normalizarListaLinks = (raw) => {
      if (!raw) return [];
      if (Array.isArray(raw)) return raw.filter(Boolean).map(v => String(v).trim()).filter(Boolean);
      if (typeof raw === 'string') {
        const texto = raw.trim();
        if (!texto) return [];
        try {
          const parsed = JSON.parse(texto);
          if (Array.isArray(parsed)) return parsed.filter(Boolean).map(v => String(v).trim()).filter(Boolean);
        } catch (err) {
          // mantém fluxo para string simples
        }
        return [texto];
      }
      return [];
    };

    const montarHtmlLinks = (links) => {
      if (!Array.isArray(links) || links.length === 0) return '-';
      return links.map((link, idx) => {
        const href = /^https?:\/\//i.test(link) ? link : `https://${link}`;
        let nome = `Link ${idx + 1}`;
        try {
          const semQuery = link.split('?')[0];
          nome = decodeURIComponent(semQuery.substring(semQuery.lastIndexOf('/') + 1)) || nome;
        } catch (err) {
          nome = link;
        }
        return `<a href="${escapeHtml(href)}" target="_blank" rel="noopener" style="color:#1d4ed8;text-decoration:underline;">${escapeHtml(nome)}</a>`;
      }).join(' • ');
    };

    const linksSemCadastro = normalizarListaLinks(item.link || item.links);
    const linksAnexoUrlSolicitacao = normalizarListaLinks(item.anexo_url);
    const linksDetalhesItem = Array.from(new Set([
      ...linksSemCadastro,
      ...linksAnexoUrlSolicitacao
    ]));
    const linksDetalhesItemHtml = montarHtmlLinks(linksDetalhesItem);
    const grupoRequisicao = String(item.grupo_requisicao || '').trim();

    let itensGrupoCotado = [item];
    if (grupoRequisicao) {
      try {
        const respGrupo = await fetch(
          `/api/compras/grupo-itens?grupo_requisicao=${encodeURIComponent(grupoRequisicao)}&table_source=${encodeURIComponent(tableSource)}`,
          { credentials: 'include' }
        );
        if (respGrupo.ok) {
          const dataGrupo = await respGrupo.json();
          const itensApi = Array.isArray(dataGrupo.itens) ? dataGrupo.itens : [];
          if (itensApi.length > 0) itensGrupoCotado = itensApi;
        }
      } catch (erroGrupo) {
        console.error('[COTADO ESCOLHA] Erro ao carregar itens do grupo:', erroGrupo);
      }
    }

    const formatarQtdGrupoCotado = (valor) => {
      try {
        if (typeof formatarQuantidadeExibicao === 'function') return formatarQuantidadeExibicao(valor);
      } catch (_) {}
      if (valor === null || valor === undefined || String(valor).trim() === '') return '-';
      return String(valor);
    };

    const itensGrupoHtml = (Array.isArray(itensGrupoCotado) && itensGrupoCotado.length > 0)
      ? `
        <div style="margin-top:10px;">
          <div style="display:flex;justify-content:space-between;align-items:center;gap:8px;flex-wrap:wrap;">
            <div style="font-size:11px;color:#6b7280;"><strong>Itens do Grupo:</strong> <span style="color:#374151;">${itensGrupoCotado.length}</span></div>
          </div>
          <div style="margin-top:8px;display:grid;gap:4px;max-height:180px;overflow-y:auto;">
            ${itensGrupoCotado.map((grupoItem, idx) => {
              const descricao = grupoItem?.produto_descricao || grupoItem?.descricao || '-';
              const codigo = grupoItem?.produto_codigo || '-';
              const quantidade = formatarQtdGrupoCotado(grupoItem?.quantidade);
              return `
                <div style="display:grid;gap:2px;background:#ffffff;border:1px solid #d1d5db;border-radius:6px;padding:6px 8px;">
                  <div style="font-size:11px;font-weight:700;color:#1f2937;">#${escapeHtml(String(grupoItem?.id || idx + 1))} • ${escapeHtml(String(codigo))}</div>
                  <div style="font-size:11px;color:#374151;">${escapeHtml(String(descricao))}</div>
                  <div style="font-size:10px;color:#6b7280;"><strong>Qtd:</strong> ${escapeHtml(String(quantidade))}</div>
                </div>
              `;
            }).join('')}
          </div>
        </div>
      `
      : '';

    let anexosItem = item.anexos;
    if (typeof anexosItem === 'string') {
      try {
        anexosItem = JSON.parse(anexosItem);
      } catch (e) {
        anexosItem = [];
      }
    }
    if (!Array.isArray(anexosItem)) anexosItem = [];
    const anexosItemHtml = anexosItem.length > 0 ? `
      <div style="margin-top:8px;">
        <div style="font-size:11px;color:#6b7280;"><strong>Anexos do Item:</strong></div>
        <div style="display:flex;flex-wrap:wrap;gap:6px;margin-top:6px;">
          ${anexosItem.map((anexo, idx) => {
            const anexoRaw = typeof anexo === 'string' ? anexo : '';
            const url = anexoRaw || anexo?.url || anexo?.path || '';
            let nome = anexo?.nome || '';
            if (!nome && url) {
              try {
                const semQuery = url.split('?')[0];
                nome = decodeURIComponent(semQuery.substring(semQuery.lastIndexOf('/') + 1)) || '';
              } catch (err) {
                nome = url;
              }
            }
            if (!nome) nome = `Anexo ${idx + 1}`;
            return `
              <a 
                href="${escapeHtml(url || 'javascript:void(0)')}" 
                target="_blank" 
                rel="noopener"
                style="display:flex;align-items:center;gap:6px;background:#f3f4f6;padding:6px 10px;border-radius:6px;text-decoration:none;color:#1f2937;font-size:11px;border:1px solid #d1d5db;">
                <i class=\"fa-solid fa-paperclip\" style=\"color:#3b82f6;\"></i>
                <span>${escapeHtml(nome)}</span>
              </a>
            `;
          }).join('')}
        </div>
      </div>
    ` : '';
    const grupoModal = String(item.grupo_requisicao || '-').trim() || '-';
    const objetivoCompra = String(item.objetivo_compra || '-').trim() || '-';
    const html = `
      <!-- Detalhes do Item -->
      <div style="background:#ede9fe;border:2px solid #8b5cf6;border-radius:8px;padding:16px;margin-bottom:16px;">
        <h4 style="margin:0 0 12px 0;font-size:14px;font-weight:700;color:#5b21b6;display:flex;align-items:center;justify-content:space-between;gap:12px;flex-wrap:wrap;">
          <span style="display:inline-flex;align-items:center;gap:8px;">
            <i class="fa-solid fa-clipboard-check"></i>
            <span>Detalhes do Item</span>
          </span>
          <span id="totalCotacoesKanbanResumo" style="display:inline-flex;align-items:center;gap:6px;background:#ffffff;border:1px solid #c4b5fd;border-radius:999px;padding:4px 10px;font-size:12px;color:#5b21b6;">
            <i class="fa-solid fa-calculator"></i>
            <strong>Total das cotações:</strong>
            <span>R$ 0,00</span>
          </span>
        </h4>
        <div style="display:grid;gap:10px;font-size:12px;color:#1f2937;">
          <div><strong>ID de referência:</strong> ${escapeHtml(String(item.id || '-'))}</div>
          <div><strong>Grupo:</strong> ${escapeHtml(grupoModal)}</div>
          <div><strong>Objetivo da Compra/Observações:</strong> ${linkifyText(objetivoCompra)}</div>
          <div><strong>Link:</strong> ${linksDetalhesItemHtml}</div>
          ${anexosItemHtml}
          ${itensGrupoHtml}
        </div>
      </div>

      <!-- Cotações Registradas -->
      <h4 style="margin:0 0 12px 0;font-size:13px;font-weight:700;color:#6b7280;text-transform:uppercase;">
        <i class="fa-solid fa-check-circle" style="color:#10b981;"></i>
        Cotações Registradas
      </h4>
      <div id="listaCotacoesRegistradasCotadoEscolha" style="display:grid;gap:12px;">
        <div style="text-align:center;padding:30px;color:#9ca3af;font-size:13px;background:#f9fafb;border-radius:6px;border:2px dashed #d1d5db;">
          Nenhuma cotação registrada ainda
        </div>
      </div>

      <div style="display:flex;justify-content:space-between;align-items:center;padding-top:16px;border-top:1px solid #e5e7eb;margin-top:16px;gap:8px;flex-wrap:wrap;">
        <button class="btn-secondary" onclick="fecharModalCotadoEscolhaItem()">
          <i class="fa-solid fa-times"></i>
          Fechar
        </button>
        <div style="display:flex;gap:8px;flex-wrap:wrap;">
          <button 
            onclick="retificarCotadoEscolha()"
            style="background:linear-gradient(135deg,#fbbf24 0%,#f59e0b 100%);color:#000;padding:12px 20px;border:none;border-radius:6px;font-size:13px;font-weight:700;cursor:pointer;display:flex;align-items:center;gap:8px;">
            <i class="fa-solid fa-rotate-left"></i>
            <span>Retificar</span>
          </button>
          <button 
            onclick="cancelarCotadoEscolha()"
            style="background:linear-gradient(135deg,#ef4444 0%,#dc2626 100%);color:white;padding:12px 20px;border:none;border-radius:6px;font-size:13px;font-weight:700;cursor:pointer;display:flex;align-items:center;gap:8px;">
            <i class="fa-solid fa-ban"></i>
            <span>Excluir</span>
          </button>
        </div>
      </div>
    `;

    modalBody.innerHTML = html;

    // Comentário: carrega cotações do banco para TODOS os itens do grupo.
    // Em alguns fluxos o item exibido no kanban pode ser histórico/representante do grupo,
    // então consultar apenas item.id pode retornar vazio mesmo com cotações já registradas.
    const idsSolicitacaoGrupo = Array.from(new Set(
      (Array.isArray(itensGrupoCotado) ? itensGrupoCotado : [])
        .map((grupoItem) => Number(grupoItem?.id))
        .filter((id) => Number.isInteger(id) && id > 0)
    ));
    const idFallback = Number(item?.id);
    if (idsSolicitacaoGrupo.length === 0 && Number.isInteger(idFallback) && idFallback > 0) {
      idsSolicitacaoGrupo.push(idFallback);
    }

    if (idsSolicitacaoGrupo.length > 0) {
      try {
        const fontesBusca = tableSource === 'compras_sem_cadastro'
          ? ['compras_sem_cadastro', 'solicitacao_compras']
          : ['solicitacao_compras', 'compras_sem_cadastro'];

        const respostasCotacoes = await Promise.all(
          idsSolicitacaoGrupo.map(async (solicitacaoIdGrupo) => {
            const acumulado = [];
            for (const fonte of fontesBusca) {
              const respCot = await fetch(
                `/api/compras/cotacoes/${solicitacaoIdGrupo}?table_source=${encodeURIComponent(fonte)}`,
                { credentials: 'include' }
              );
              if (!respCot.ok) continue;
              const data = await respCot.json();
              const cotacoesFonte = Array.isArray(data?.cotacoes)
                ? data.cotacoes
                : (Array.isArray(data) ? data : []);
              if (cotacoesFonte.length > 0) acumulado.push(...cotacoesFonte);
            }
            return acumulado;
          })
        );

        const mapaCotacoes = new Map();
        respostasCotacoes.flat().forEach((cotacao) => {
          if (!cotacao || typeof cotacao !== 'object') return;
          const chave = Number(cotacao.id);
          if (!Number.isInteger(chave) || chave <= 0) return;
          if (!mapaCotacoes.has(chave)) {
            mapaCotacoes.set(chave, cotacao);
          }
        });
        window.cotadoEscolhaCotacoesDb = Array.from(mapaCotacoes.values());
      } catch (e) {
        console.error('[COTADO ESCOLHA] Erro ao buscar cotações do grupo:', e);
      }
    }

    try {
      await renderizarCotacoesRegistradasCotadoEscolha();
    } catch (errRender) {
      const containerCot = document.getElementById('listaCotacoesRegistradasCotadoEscolha');
      if (containerCot) {
        containerCot.innerHTML = '<div style="text-align:center;padding:20px;color:#ef4444;font-size:13px;">Falha ao renderizar cotações.</div>';
      }
    }
  } catch (err) {
    const msg = (err && err.message) ? err.message : 'Erro desconhecido ao carregar detalhes do item.';
    modalBody.innerHTML = `<div style="text-align:center;padding:40px;color:#ef4444;">Erro ao carregar detalhes do item.<br><small style="display:block;margin-top:8px;color:#b91c1c;">${escapeHtml(msg)}</small></div>`;
  }
}

// Comentário: fecha o modal de item cotado aguardando escolha
function fecharModalCotadoEscolhaItem() {
  const modal = document.getElementById('modalCotadoEscolhaItem');
  if (modal) modal.style.display = 'none';
  window.cotadoEscolhaItem = null;
  window.cotadoEscolhaItemId = null;
  window.cotadoEscolhaCotacoesDb = [];
}

// Comentário: modal específico do kanban "Cotação"
async function abrirModalCotacaoKanban(itemId, grupoRequisicaoEncoded = '', tableSourceArg = '') {
  const modal = document.getElementById('modalCotacaoKanban');
  const modalBody = document.getElementById('modalCotacaoKanbanBody');
  const modalTitulo = document.getElementById('modalCotacaoKanbanTitulo');
  if (!modal || !modalBody || !modalTitulo) return;

  modalBody.innerHTML = '<div style="text-align:center;padding:40px;"><i class="fa-solid fa-spinner fa-spin" style="font-size:32px;color:#fbbf24;"></i><br><br>Carregando...</div>';
  modal.style.display = 'flex';
  renderizarNavegacaoModalKanban({
    modalId: 'modalCotacaoKanban',
    status: 'aguardando cotação',
    currentItemId: itemId,
    openType: 'cotacao'
  });

  const currentUser = (document.getElementById('userNameDisplay')?.textContent || '').trim();

  try {
    const grupoRequisicao = decodeURIComponent(String(grupoRequisicaoEncoded || '').trim());
    const tableSourceRecebido = String(tableSourceArg || '').trim();
    const cacheItens = Array.isArray(window.kanbanMinhasItens) ? window.kanbanMinhasItens : [];
    console.log('[DEBUG Modal Cotação] itemId recebido:', itemId);
    console.log('[DEBUG Modal Cotação] Total de itens no cache:', cacheItens.length);
    console.log('[DEBUG Modal Cotação] IDs no cache:', cacheItens.map(i => i.id).slice(0, 20));
    
    let item = cacheItens.find(i => String(i.id) === String(itemId));
    if (!item && grupoRequisicao && tableSourceRecebido) {
      item = cacheItens.find(i =>
        String(i.grupo_requisicao || '').trim() === grupoRequisicao
        && String(i.table_source || '').trim() === tableSourceRecebido
      );
    }

    if (!item) {
      console.log('[DEBUG Modal Cotação] Item não encontrado no cache, buscando na API...');
      const resp = await fetch(`/api/compras/minhas?solicitante=${encodeURIComponent(currentUser)}`, { credentials: 'include' });
      if (!resp.ok) throw new Error('Não foi possível carregar as solicitações');
      const data = await resp.json();
      const listaCompleta = Array.isArray(data.solicitacoes) ? data.solicitacoes : [];
      item = listaCompleta.find(i => String(i.id) === String(itemId));
      if (!item && grupoRequisicao && tableSourceRecebido) {
        item = listaCompleta.find(i =>
          String(i.grupo_requisicao || '').trim() === grupoRequisicao
          && String(i.table_source || '').trim() === tableSourceRecebido
        );
      }
    } else {
      console.log('[DEBUG Modal Cotação] Item encontrado no cache!');
    }

    const grupoModal = grupoRequisicao || String(item?.grupo_requisicao || '').trim();
    const tableSourceModal = String(tableSourceRecebido || item?.table_source || 'solicitacao_compras').trim() || 'solicitacao_compras';

    if (!item && !grupoModal) {
      modalBody.innerHTML = '<div style="text-align:center;padding:40px;color:#ef4444;">Item não encontrado.</div>';
      return;
    }

    let itensGrupo = [];
    let itemReferenciaId = item?.id || null;
    if (grupoModal) {
      try {
        const respGrupo = await fetch(
          `/api/compras/grupo-itens?grupo_requisicao=${encodeURIComponent(grupoModal)}&table_source=${encodeURIComponent(tableSourceModal)}`,
          { credentials: 'include' }
        );
        if (respGrupo.ok) {
          const dataGrupo = await respGrupo.json();
          itensGrupo = Array.isArray(dataGrupo.itens) ? dataGrupo.itens : [];
          itemReferenciaId = dataGrupo.referencia_id || itemReferenciaId;
        }
      } catch (erroGrupo) {
        console.error('[COTACAO KANBAN] Erro ao carregar itens do grupo:', erroGrupo);
      }
    }

    const itemExibicao = itensGrupo[0] || item;
    if (!itemExibicao) {
      modalBody.innerHTML = '<div style="text-align:center;padding:40px;color:#ef4444;">Não foi possível carregar os itens do grupo.</div>';
      return;
    }

    window.cotacaoKanbanItem = itemExibicao;
    window.cotacaoKanbanItemId = itemReferenciaId || itemExibicao.id;
    window.cotacaoKanbanGrupoRequisicao = grupoModal || null;
    window.cotacaoKanbanTableSource = tableSourceModal;
    window.cotacaoKanbanItensGrupo = (Array.isArray(itensGrupo) && itensGrupo.length > 0) ? itensGrupo : [itemExibicao];
    window.cotacaoKanbanAnexos = [];
    window.cotacaoKanbanLinks = [];
    window.cotacaoKanbanCotacoes = [];
    window.cotacaoKanbanItensSelecionados = [];
    window.cotacaoKanbanItensUsados = new Set();
    window.cotacaoKanbanFiltroItensGrupo = 'pendentes';
    window.cotacaoKanbanMoeda = 'BRL';
    window.cotacaoKanbanEdicaoId = null;
    window.cotacaoKanbanEditandoDetalhes = false;
    window.cotacaoKanbanEditQtdItemId = null;
    window.cotacaoKanbanBuscaResultados = [];
    window.cotacaoKanbanNovoItemPendente = null;
    window.cotacaoKanbanBuscaReqSeq = 0;

    modalTitulo.textContent = grupoModal
      ? `Cotação - Grupo ${grupoModal}`
      : `Cotação - Item ${itemExibicao.id}`;

    const fmtDate = (iso) => {
      if (!iso) return '-';
      const d = new Date(iso);
      return Number.isNaN(d.getTime()) ? '-' : d.toLocaleDateString('pt-BR');
    };

    const normalizarLinksCotacao = (raw) => {
      if (!raw) return [];
      if (Array.isArray(raw)) return raw;
      if (typeof raw === 'string') {
        try {
          const parsed = JSON.parse(raw);
          return Array.isArray(parsed) ? parsed : [raw];
        } catch (err) {
          return [raw];
        }
      }
      return [];
    };

    const formatarLinkPrincipal = (url) => {
      try {
        const parsed = new URL(url);
        return parsed.hostname;
      } catch (err) {
        return url;
      }
    };

    const normalizarAnexosCotacao = (raw) => {
      if (!raw) return [];
      if (Array.isArray(raw)) return raw;
      if (typeof raw === 'string') {
        try {
          const parsed = JSON.parse(raw);
          if (Array.isArray(parsed)) return parsed;
        } catch (err) {
          return [raw];
        }
      }
      return [];
    };

    console.log('[DEBUG Modal Cotação] Item completo:', itemExibicao);
    console.log('[DEBUG Modal Cotação] Todas as propriedades do item:', Object.keys(itemExibicao));
    console.log('[DEBUG Modal Cotação] item.link:', itemExibicao.link);
    console.log('[DEBUG Modal Cotação] item.links:', itemExibicao.links);
    console.log('[DEBUG Modal Cotação] item.isSemCadastro:', itemExibicao.isSemCadastro);
    
    const origemParaAgregacao = (Array.isArray(itensGrupo) && itensGrupo.length > 0)
      ? itensGrupo
      : [itemExibicao];

    const linksCotacao = Array.from(new Set(
      origemParaAgregacao.flatMap((grupoItem) =>
        normalizarLinksCotacao(grupoItem?.link || grupoItem?.links)
          .map((link) => String(link || '').trim())
          .filter(Boolean)
      )
    ));
    console.log('[DEBUG Modal Cotação] linksCotacao normalizado:', linksCotacao);
    
    const linksCotacaoHtml = linksCotacao.length
      ? linksCotacao.map((link) => {
          const href = /^https?:\/\//i.test(link) ? link : `https://${link}`;
          const label = formatarLinkPrincipal(link);
          return `<a href="${escapeHtml(href)}" target="_blank" rel="noopener" style="color:#1d4ed8;text-decoration:underline;">${escapeHtml(label)}</a>`;
        }).join(' • ')
      : '-';

    const anexosVistos = new Set();
    const anexosItem = [];
    origemParaAgregacao.forEach((grupoItem) => {
      const anexosNormalizados = normalizarAnexosCotacao(grupoItem?.anexos);
      anexosNormalizados.forEach((anexo, idx) => {
        const anexoRaw = typeof anexo === 'string' ? anexo : '';
        const url = anexoRaw || anexo?.url || anexo?.path || '';
        const nome = anexo?.nome || '';
        const chave = `${nome}::${url}::${idx}`;
        if (anexosVistos.has(chave)) return;
        anexosVistos.add(chave);
        anexosItem.push(anexo);
      });
    });

    const anexosItemHtml = anexosItem.length > 0
      ? `
        <div style="margin-top:8px;">
          <div style="font-size:11px;color:#6b7280;"><strong>Anexos do Item:</strong></div>
          <div style="display:flex;flex-wrap:wrap;gap:6px;margin-top:6px;">
            ${anexosItem.map((anexo, idx) => {
              const anexoRaw = typeof anexo === 'string' ? anexo : '';
              const url = anexoRaw || anexo?.url || anexo?.path || '';
              const tipo = anexo?.tipo || 'application/octet-stream';
              const base64 = anexo?.base64 || '';
              const href = url || (base64 ? `data:${tipo};base64,${base64}` : 'javascript:void(0)');
              let nome = anexo?.nome || '';
              if (!nome && url) {
                try {
                  const semQuery = url.split('?')[0];
                  nome = decodeURIComponent(semQuery.substring(semQuery.lastIndexOf('/') + 1)) || '';
                } catch (err) {
                  nome = url;
                }
              }
              if (!nome) nome = `Anexo ${idx + 1}`;
              return `
                <a
                  href="${escapeHtml(href)}"
                  target="_blank"
                  rel="noopener"
                  style="display:flex;align-items:center;gap:6px;background:#f3f4f6;padding:6px 10px;border-radius:6px;text-decoration:none;color:#1f2937;font-size:11px;border:1px solid #d1d5db;">
                  <i class="fa-solid fa-paperclip" style="color:#3b82f6;"></i>
                  <span>${escapeHtml(nome)}</span>
                </a>
              `;
            }).join('')}
          </div>
        </div>
      `
      : `
        <div style="margin-top:8px;">
          <div style="font-size:11px;color:#6b7280;"><strong>Anexos do Item:</strong> -</div>
        </div>
      `;

    const itensGrupoHtml = (Array.isArray(window.cotacaoKanbanItensGrupo) && window.cotacaoKanbanItensGrupo.length > 0)
      ? `
        <div style="margin-top:10px;">
          <div style="display:flex;justify-content:space-between;align-items:center;gap:8px;flex-wrap:wrap;">
            <div style="font-size:11px;color:#6b7280;"><strong>Itens do Grupo:</strong> <span id="qtdItensGrupoCotacaoKanban" style="color:#374151;">0</span></div>
            <span style="display:inline-flex;align-items:center;gap:6px;flex-wrap:wrap;">
              <button
                type="button"
                id="btnFiltroItensGrupoCotacaoKanban"
                onclick="alternarFiltroItensGrupoCotacaoKanban()"
                style="background:#f3f4f6;color:#374151;border:1px solid #d1d5db;padding:4px 8px;border-radius:6px;font-size:11px;font-weight:600;cursor:pointer;">
                Mostrar tudo
              </button>
            </span>
          </div>
          <div style="margin-top:8px;display:grid;gap:6px;">
            <input
              id="novoItemGrupoBuscaCotacaoKanban"
              type="text"
              placeholder="Digite código ou descrição para buscar produto..."
              oninput="buscarProdutosNovoItemGrupoCotacaoKanban()"
              onkeydown="atalhoBuscaNovoItemGrupoCotacaoKanban(event)"
              style="padding:6px 8px;border:1px solid #d1d5db;border-radius:6px;font-size:11px;" />
            <div id="listaBuscaNovoItemGrupoCotacaoKanban" style="display:none;max-height:140px;overflow-y:auto;border:1px solid #d1d5db;border-radius:6px;background:#fff;"></div>
          </div>
          <div id="listaItensGrupoCotacaoKanban" style="margin-top:6px;display:grid;gap:4px;max-height:160px;overflow-y:auto;"></div>
        </div>
      `
      : '';

    const html = `
      <div id="detalhesItemCotacaoKanbanContainer"></div>

      <div style="background:#f9fafb;border:2px solid #e5e7eb;border-radius:8px;padding:20px;margin-bottom:20px;">
        <h4 style="margin:0 0 16px 0;font-size:14px;font-weight:700;color:#1f2937;">
          <i class="fa-solid fa-edit" style="color:#fbbf24;"></i>
          Registrar Nova Cotação
        </h4>
        <div style="margin-bottom:12px;">
          <label style="display:block;font-size:12px;color:#6b7280;font-weight:600;margin-bottom:6px;">Fornecedor *</label>
          <input 
            type="text" 
            id="cotacaoKanbanFornecedor"
            placeholder="Nome do fornecedor..."
            style="width:100%;padding:10px;border:1px solid #d1d5db;border-radius:6px;font-size:13px;"
          />
        </div>
        <div style="margin-bottom:12px;">
          <label style="display:flex;align-items:center;gap:6px;font-size:12px;color:#6b7280;font-weight:600;margin-bottom:6px;">
            <span>Valor Unitário *</span>
            <button
              type="button"
              id="btnMoedaCotacaoKanban"
              onclick="alternarMoedaCotacaoKanban()"
              style="background:#f3f4f6;color:#111827;border:1px solid #d1d5db;padding:2px 8px;border-radius:999px;font-size:11px;font-weight:700;cursor:pointer;">
              R$
            </button>
          </label>
          <input 
            type="text" 
            id="cotacaoKanbanValor"
            placeholder="0,00"
            inputmode="decimal"
            oninput="mascararValorCotacaoKanban(this)"
            onblur="mascararValorCotacaoKanban(this)"
            style="width:100%;padding:10px;border:1px solid #d1d5db;border-radius:6px;font-size:13px;"
          />
        </div>
        <div style="margin-bottom:16px;">
          <label style="display:block;font-size:12px;color:#6b7280;font-weight:600;margin-bottom:6px;">Itens nesta cotação *</label>
          <div
            id="areaDropItensCotacaoKanban"
            ondragover="dragOverItemCotacaoKanban(event)"
            ondrop="dropItemCotacaoKanban(event)"
            style="min-height:56px;border:2px dashed #d1d5db;border-radius:8px;background:#ffffff;padding:10px;display:grid;gap:6px;align-content:start;">
            <div style="font-size:12px;color:#9ca3af;">Arraste itens do grupo para registrar nesta cotação</div>
          </div>
          <div id="listaItensSelecionadosCotacaoKanban" style="margin-top:8px;display:grid;gap:6px;"></div>
        </div>
        <div style="margin-bottom:16px;">
          <label style="display:block;font-size:12px;color:#6b7280;font-weight:600;margin-bottom:6px;">Anexos (opcional)</label>
          <input 
            type="file" 
            id="cotacaoKanbanAnexo"
            accept=".pdf,.jpg,.jpeg,.png,.xlsx,.xls,.doc,.docx"
            onchange="adicionarAnexoCotacaoKanban()"
            style="width:100%;padding:8px;border:1px solid #d1d5db;border-radius:6px;font-size:13px;"
          />
          <div id="listaAnexosCotacaoKanban" style="margin-top:10px;display:grid;gap:6px;"></div>
        </div>
        <div style="margin-bottom:16px;">
          <label style="display:block;font-size:12px;color:#6b7280;font-weight:600;margin-bottom:6px;">Link (opcional)</label>
          <input
            type="text"
            id="cotacaoKanbanLink"
            placeholder="Cole o link e pressione Enter"
            onkeydown="adicionarLinkCotacaoKanban(event)"
            style="width:100%;padding:10px;border:1px solid #d1d5db;border-radius:6px;font-size:13px;"
          />
          <div id="listaLinksCotacaoKanban" style="margin-top:10px;display:grid;gap:6px;"></div>
        </div>
        <div id="cotacaoKanbanModoEdicaoInfo" style="display:none;margin:0 0 10px 0;padding:8px 10px;background:#fffbeb;border:1px solid #fde68a;border-radius:6px;font-size:12px;color:#92400e;font-weight:600;"></div>
        <div style="display:flex;gap:8px;align-items:center;">
          <button
            id="cotacaoKanbanSalvarBtn"
            onclick="registrarCotacaoKanban()"
            style="flex:1;background:linear-gradient(135deg,#10b981 0%,#059669 100%);color:white;border:none;padding:12px 20px;border-radius:6px;font-size:14px;font-weight:600;cursor:pointer;">
            <i class="fa-solid fa-plus"></i>
            Registrar Cotação
          </button>
          <button
            type="button"
            id="cotacaoKanbanCancelarEdicaoBtn"
            onclick="cancelarEdicaoCotacaoKanban()"
            style="display:none;background:#e5e7eb;color:#111827;border:none;padding:12px 14px;border-radius:6px;font-size:13px;font-weight:700;cursor:pointer;">
            Cancelar edição
          </button>
        </div>
      </div>

      <h4 style="margin:0 0 12px 0;font-size:13px;font-weight:700;color:#6b7280;text-transform:uppercase;">
        <i class="fa-solid fa-check-circle" style="color:#10b981;"></i>
        Cotações Registradas
      </h4>
      <div id="listaCotacoesRegistradasKanban" style="display:grid;gap:12px;margin-bottom:16px;">
        <div style="text-align:center;padding:20px;color:#9ca3af;font-size:13px;">Nenhuma cotação registrada ainda</div>
      </div>

      <div style="display:flex;justify-content:flex-end;align-items:center;padding-top:16px;border-top:1px solid #e5e7eb;">
        <button 
          onclick="enviarCotacoesKanban()"
          style="background:linear-gradient(135deg,#fbbf24 0%,#f59e0b 100%);color:#000;padding:12px 28px;border:none;border-radius:6px;font-size:14px;font-weight:700;cursor:pointer;display:flex;align-items:center;gap:8px;">
          <i class="fa-solid fa-paper-plane"></i>
          <span>Enviar Cotações</span>
        </button>
      </div>
    `;

    modalBody.innerHTML = html;
    window.cotacaoKanbanDetalhesContexto = {
      grupoModal,
      linksCotacaoHtml,
      anexosItemHtml,
      itensGrupoHtml
    };
    renderizarDetalhesItemCotacaoKanban();
    atualizarEstadoFormularioCotacaoKanban();
    renderizarItensGrupoCotacaoKanban();
    renderizarItensSelecionadosCotacaoKanban();
    await carregarCotacoesKanban();
  } catch (err) {
    console.error('[COTACAO KANBAN] Erro:', err);
    modalBody.innerHTML = '<div style="text-align:center;padding:40px;color:#ef4444;">Erro ao carregar detalhes do item.</div>';
  }
}

function fecharModalCotacaoKanban() {
  const modal = document.getElementById('modalCotacaoKanban');
  if (modal) modal.style.display = 'none';
  window.cotacaoKanbanItem = null;
  window.cotacaoKanbanItemId = null;
  window.cotacaoKanbanGrupoRequisicao = null;
  window.cotacaoKanbanTableSource = null;
  window.cotacaoKanbanItensGrupo = [];
  window.cotacaoKanbanAnexos = [];
  window.cotacaoKanbanLinks = [];
  window.cotacaoKanbanCotacoes = [];
  window.cotacaoKanbanItensSelecionados = [];
  window.cotacaoKanbanItensUsados = new Set();
  window.cotacaoKanbanFiltroItensGrupo = 'pendentes';
  window.cotacaoKanbanMoeda = 'BRL';
  window.cotacaoKanbanEdicaoId = null;
  window.cotacaoKanbanEditandoDetalhes = false;
  window.cotacaoKanbanEditQtdItemId = null;
  window.cotacaoKanbanBuscaResultados = [];
  window.cotacaoKanbanNovoItemPendente = null;
  window.cotacaoKanbanBuscaReqSeq = 0;
  window.cotacaoKanbanDetalhesContexto = null;
}

// Comentário: abre janela de impressão do Pedido de Compra com base nos dados da cotação atual
function abrirPedidoCompraCotacaoKanban() {
  const grupo = window.cotacaoKanbanGrupoRequisicao || '-';
  const item = window.cotacaoKanbanItem || {};
  const itemId = window.cotacaoKanbanItemId || '-';
  const itensGrupo = Array.isArray(window.cotacaoKanbanItensGrupo) ? window.cotacaoKanbanItensGrupo : [];
  const cotacoes = Array.isArray(window.cotacaoKanbanCotacoes) ? window.cotacaoKanbanCotacoes : [];
  const agora = new Date();
  const dataHora = agora.toLocaleDateString('pt-BR') + ' às ' + agora.toLocaleTimeString('pt-BR');
  const userNome = (document.getElementById('userNameDisplay')?.textContent || '').trim() || '';

  const fmtBRL = (v) => Number(v || 0).toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });

  // Determina fornecedor vencedor (menor valor BRL)
  const cotacoesBrl = cotacoes.filter(c => String(c.moeda || 'BRL').toUpperCase() !== 'USD');
  const fornecedorVencedor = cotacoesBrl.length > 0
    ? cotacoesBrl.reduce((a, b) => Number(a.valor_cotado || 0) <= Number(b.valor_cotado || 0) ? a : b)
    : cotacoes[0] || null;

  // Monta linhas de itens do grupo
  const itensHtml = itensGrupo.length > 0
    ? itensGrupo.map((it, idx) => {
        const qtd = Number(it.quantidade || 1);
        const codigo = String(it.produto_codigo || '-');
        const descricao = String(it.produto_descricao || it.descricao || '-');
        return `<tr>
          <td style="padding:8px 10px;border:1px solid #d1d5db;text-align:center;">${idx + 1}</td>
          <td style="padding:8px 10px;border:1px solid #d1d5db;font-family:monospace;font-size:12px;">${codigo}</td>
          <td style="padding:8px 10px;border:1px solid #d1d5db;">${descricao}</td>
          <td style="padding:8px 10px;border:1px solid #d1d5db;text-align:center;">${qtd}</td>
        </tr>`;
      }).join('')
    : `<tr><td colspan="4" style="padding:16px;text-align:center;color:#9ca3af;border:1px solid #d1d5db;">Sem itens</td></tr>`;

  const html = `<!DOCTYPE html>
<html lang="pt-BR">
<head>
  <meta charset="UTF-8">
  <title>PDF - ID ${itemId}</title>
  <style>
    * { box-sizing: border-box; margin: 0; padding: 0; }
    body { font-family: Arial, sans-serif; font-size: 13px; color: #111; padding: 30px; max-width: 900px; margin: 0 auto; }
    .header { display: flex; justify-content: space-between; align-items: flex-start; border-bottom: 3px solid #1e3a5f; padding-bottom: 16px; margin-bottom: 24px; gap: 20px; }
    .header-logo { flex-shrink: 0; }
    .header-logo img { height: 60px; width: auto; display: block; }
    .header-empresa { flex: 1; }
    .header-empresa h1 { font-size: 16px; font-weight: 700; color: #1e3a5f; margin-bottom: 4px; }
    .header-empresa p { font-size: 11px; color: #555; line-height: 1.6; }
    .header-titulo { text-align: right; flex-shrink: 0; }
    .header-titulo h2 { font-size: 20px; font-weight: 700; color: #1e3a5f; }
    .header-titulo p { font-size: 11px; color: #888; margin-top: 4px; }
    .section-title { font-size: 13px; font-weight: 700; color: #1e3a5f; background: #f0f4ff; padding: 8px 12px; margin: 20px 0 10px; border-left: 4px solid #1e3a5f; }
    table { width: 100%; border-collapse: collapse; margin-bottom: 8px; }
    th { background: #1e3a5f; color: #fff; padding: 8px 10px; font-size: 12px; text-align: left; }
    td { font-size: 12px; }
    tr:nth-child(even) td { background: #f9fafb; }
    .info-box { background: #f9fafb; border: 1px solid #e5e7eb; border-radius: 6px; padding: 12px 16px; font-size: 12px; line-height: 1.8; }
    .footer { margin-top: 40px; padding-top: 12px; border-top: 1px solid #d1d5db; font-size: 11px; color: #888; text-align: center; }
    @media print {
      body { padding: 15px; }
      @page { margin: 15mm; }
    }
  </style>
</head>
<body>
  <div class="header">
    <div class="header-logo">
      <img src="${window.storagePublicUrl('produtos/assets/Logo_OS.png')}" alt="Logo" />
    </div>
    <div class="header-empresa">
      <h1>FROMTHERM SISTEMAS TERMICOS LTDA</h1>
      <p>
        CNPJ: 12.659.566/0001-09 &nbsp;|&nbsp; Inscrição Estadual: 256.225.389<br>
        RUA EDGARD HOFFMANN, 699 - LOTE CICOB, BEIRA RIO<br>
        Biguaçu - SC - CEP: 88164-275<br>
        Telefone: (48) 99652-4210
      </p>
    </div>
    <div class="header-titulo">
      <h2>Pedido de Compra</h2>
      <p>ID de referência: <strong>${itemId}</strong></p>
    </div>
  </div>

  ${fornecedorVencedor ? `
  <div class="section-title">Fornecedor Selecionado (Menor Valor)</div>
  <div class="info-box">
    <strong>${fornecedorVencedor.fornecedor_nome || '-'}</strong>
    ${fornecedorVencedor.cnpj ? `<br>CNPJ: ${fornecedorVencedor.cnpj}` : ''}
    ${fornecedorVencedor.observacao ? `<br>Obs: ${fornecedorVencedor.observacao}` : ''}
  </div>
  ` : ''}

  <div class="section-title">Itens do Pedido</div>
  <table>
    <thead>
      <tr>
        <th style="width:40px;">Item</th>
        <th style="width:160px;">Código</th>
        <th>Descrição</th>
        <th style="width:70px;text-align:center;">Qtd</th>
      </tr>
    </thead>
    <tbody>${itensHtml}</tbody>
  </table>

  <div class="footer">
    Gerado em ${dataHora}${userNome ? ' por ' + userNome : ''} &nbsp;|&nbsp; ID de referência: ${itemId}
  </div>
</body>
</html>`;

  const janela = window.open('', '_blank', 'width=960,height=700,scrollbars=yes');
  if (!janela) { alert('Permita pop-ups para abrir o PDF.'); return; }
  janela.document.write(html);
  janela.document.close();
  janela.focus();
  setTimeout(() => janela.print(), 600);
}

function renderizarDetalhesItemCotacaoKanban(contexto = {}) {
  const container = document.getElementById('detalhesItemCotacaoKanbanContainer');
  if (!container) return;

  const contextoFinal = {
    ...(window.cotacaoKanbanDetalhesContexto || {}),
    ...(contexto || {})
  };

  const item = window.cotacaoKanbanItem || {};
  const itemId = window.cotacaoKanbanItemId || '-';
  const grupoModal = contextoFinal.grupoModal || window.cotacaoKanbanGrupoRequisicao || '-';
  const linksCotacaoHtml = contextoFinal.linksCotacaoHtml || '-';
  const anexosItemHtml = contextoFinal.anexosItemHtml || '<div style="margin-top:8px;"><div style="font-size:11px;color:#6b7280;"><strong>Anexos do Item:</strong> -</div></div>';
  const itensGrupoHtml = contextoFinal.itensGrupoHtml || '';
  const editando = window.cotacaoKanbanEditandoDetalhes === true;

  const objetivoAtual = String(item.objetivo_compra || '').trim();
  const linkAtual = (() => {
    if (window.cotacaoKanbanTableSource === 'compras_sem_cadastro') {
      const base = item.link || item.links;
      if (Array.isArray(base)) return String(base[0] || '').trim();
      return String(base || '').trim();
    }
    const base = item.anexo_url;
    if (Array.isArray(base)) return String(base[0] || '').trim();
    return String(base || '').trim();
  })();

  if (!editando) {
    container.innerHTML = `
      <div style="background:#ede9fe;border:2px solid #8b5cf6;border-radius:8px;padding:16px;margin-bottom:16px;">
        <h4 style="margin:0 0 12px 0;font-size:14px;font-weight:700;color:#5b21b6;display:flex;align-items:center;justify-content:space-between;gap:12px;flex-wrap:wrap;">
          <span style="display:inline-flex;align-items:center;gap:8px;">
            <i class="fa-solid fa-clipboard-check"></i>
            <span>Detalhes do Item</span>
          </span>
          <span style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;">
            <span id="totalCotacoesKanbanResumo" style="display:inline-flex;align-items:center;gap:6px;background:#ffffff;border:1px solid #c4b5fd;border-radius:999px;padding:4px 10px;font-size:12px;color:#5b21b6;">
              <i class="fa-solid fa-calculator"></i>
              <strong>Total das cotações:</strong>
              <span>R$ 0,00</span>
            </span>
            <button
              type="button"
              onclick="abrirPedidoCompraCotacaoKanban()"
              title="Gerar PDF"
              style="background:#059669;color:#ffffff;border:none;padding:8px 12px;border-radius:6px;font-size:12px;font-weight:700;cursor:pointer;display:inline-flex;align-items:center;gap:6px;">
              <i class="fa-solid fa-file-pdf"></i>
              PDF
            </button>
            <button
              type="button"
              onclick="iniciarEdicaoDetalhesCotacaoKanban()"
              style="background:#2563eb;color:#ffffff;border:none;padding:8px 12px;border-radius:6px;font-size:12px;font-weight:700;cursor:pointer;display:inline-flex;align-items:center;gap:6px;">
              <i class="fa-solid fa-pen"></i>
              Editar
            </button>
          </span>
        </h4>
        <div style="display:grid;gap:10px;font-size:12px;color:#1f2937;">
          <div><strong>ID de referência:</strong> ${escapeHtml(String(itemId))}</div>
          <div><strong>Grupo:</strong> ${escapeHtml(String(grupoModal || '-'))}</div>
          <div><strong>Objetivo da Compra/Observações:</strong> ${linkifyText(item.objetivo_compra || '-')}</div>
          <div><strong>Link:</strong> ${linksCotacaoHtml}</div>
          ${anexosItemHtml}
          ${itensGrupoHtml}
        </div>
      </div>
    `;
    return;
  }

  // Monta HTML dos anexos existentes para o modo edição
  const _anexosEdicaoLista = (() => {
    const raw = item ? item.anexos : null;
    if (!raw) return [];
    if (Array.isArray(raw)) return raw;
    if (typeof raw === 'string') { try { return JSON.parse(raw); } catch (e) { return []; } }
    return [];
  })();
  const _anexosEdicaoHtml = _anexosEdicaoLista.length ? `
    <div style="display:grid;gap:6px;">
      <span style="font-weight:600;font-size:12px;color:#1f2937;">Anexos existentes</span>
      <div style="display:flex;flex-wrap:wrap;gap:6px;">
        ${_anexosEdicaoLista.map((anexo, idx) => {
          const url = typeof anexo === 'string' ? anexo : (anexo?.url || anexo?.path || '');
          const tipo = anexo?.tipo || 'application/octet-stream';
          const base64 = anexo?.base64 || '';
          const href = url || (base64 ? `data:${tipo};base64,${base64}` : 'javascript:void(0)');
          let nome = typeof anexo === 'string' ? '' : (anexo?.nome || '');
          if (!nome && url) { try { const s = url.split('?')[0]; nome = decodeURIComponent(s.substring(s.lastIndexOf('/') + 1)) || ''; } catch(e){ nome = url; } }
          if (!nome) nome = `Anexo ${idx + 1}`;
          return `<div style="display:inline-flex;align-items:center;gap:4px;background:#f3f4f6;padding:5px 10px;border-radius:6px;border:1px solid #d1d5db;">
            <a href="${escapeHtml(href)}" target="_blank" rel="noopener" style="display:inline-flex;align-items:center;gap:5px;text-decoration:none;color:#1f2937;font-size:11px;">
              <i class="fa-solid fa-paperclip" style="color:#3b82f6;"></i>
              <span>${escapeHtml(nome)}</span>
            </a>
            <button type="button" onclick="excluirAnexoCotacaoKanban(${idx})" title="Excluir anexo" style="background:none;border:none;cursor:pointer;padding:0 0 0 6px;color:#ef4444;display:inline-flex;align-items:center;font-size:12px;">
              <i class="fa-solid fa-xmark"></i>
            </button>
          </div>`;
        }).join('')}
      </div>
    </div>` : '';

  container.innerHTML = `
    <div style="background:#ede9fe;border:2px solid #8b5cf6;border-radius:8px;padding:16px;margin-bottom:16px;">
      <h4 style="margin:0 0 12px 0;font-size:14px;font-weight:700;color:#5b21b6;display:flex;align-items:center;justify-content:space-between;gap:12px;flex-wrap:wrap;">
        <span style="display:inline-flex;align-items:center;gap:8px;">
          <i class="fa-solid fa-clipboard-check"></i>
          <span>Detalhes do Item (Edição)</span>
        </span>
        <span id="totalCotacoesKanbanResumo" style="display:inline-flex;align-items:center;gap:6px;background:#ffffff;border:1px solid #c4b5fd;border-radius:999px;padding:4px 10px;font-size:12px;color:#5b21b6;">
          <i class="fa-solid fa-calculator"></i>
          <strong>Total das cotações:</strong>
          <span>R$ 0,00</span>
        </span>
      </h4>
      <div style="display:grid;gap:10px;font-size:12px;color:#1f2937;">
        <div><strong>ID de referência:</strong> ${escapeHtml(String(itemId))}</div>
        <div><strong>Grupo:</strong> ${escapeHtml(String(grupoModal || '-'))}</div>
        <label style="display:grid;gap:6px;">
          <span style="font-weight:600;">Objetivo da Compra/Observações</span>
          <textarea id="cotacaoKanbanDetalhesObjetivo" style="padding:8px;border:1px solid #d1d5db;border-radius:6px;min-height:72px;resize:vertical;">${escapeHtml(objetivoAtual)}</textarea>
        </label>
        <label style="display:grid;gap:6px;">
          <span style="font-weight:600;">Link</span>
          <input id="cotacaoKanbanDetalhesLink" type="text" value="${escapeHtml(linkAtual)}" placeholder="https://..." style="padding:8px;border:1px solid #d1d5db;border-radius:6px;">
        </label>
        ${_anexosEdicaoHtml}
        <div style="display:grid;gap:6px;">
          <span style="font-weight:600;font-size:12px;color:#1f2937;">Anexar arquivo (opcional)</span>
          <div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;">
            <input type="file" id="cotacaoKanbanDetalhesAnexoInput" accept=".pdf,.jpg,.jpeg,.png,.xlsx,.xls,.doc,.docx" style="display:none;" onchange="onCotacaoKanbanDetalhesAnexoChange()">
            <button type="button" onclick="document.getElementById('cotacaoKanbanDetalhesAnexoInput').click()" style="background:#2563eb;color:#fff;border:none;padding:8px 12px;border-radius:6px;font-size:12px;font-weight:600;cursor:pointer;display:inline-flex;align-items:center;gap:6px;">
              <i class="fa-solid fa-paperclip"></i>
              Selecionar arquivo
            </button>
            <span id="cotacaoKanbanDetalhesAnexoNome" style="font-size:11px;color:#6b7280;">Nenhum arquivo selecionado</span>
          </div>
        </div>
      </div>
      <div style="display:flex;justify-content:flex-end;gap:8px;margin-top:12px;">
        <button type="button" onclick="cancelarEdicaoDetalhesCotacaoKanban()" style="background:#6b7280;color:#fff;border:none;padding:8px 12px;border-radius:6px;font-size:12px;font-weight:700;cursor:pointer;display:inline-flex;align-items:center;gap:6px;">
          <i class="fa-solid fa-times"></i>
          Cancelar
        </button>
        <button type="button" id="btnSalvarDetalhesCotacaoKanban" onclick="salvarDetalhesCotacaoKanban()" style="background:#10b981;color:#fff;border:none;padding:8px 12px;border-radius:6px;font-size:12px;font-weight:700;cursor:pointer;display:inline-flex;align-items:center;gap:6px;">
          <i class="fa-solid fa-floppy-disk"></i>
          Salvar alterações
        </button>
      </div>
      ${itensGrupoHtml}
    </div>
  `;
}

window.onCotacaoKanbanDetalhesAnexoChange = function() {
  const input = document.getElementById('cotacaoKanbanDetalhesAnexoInput');
  const nomeSpan = document.getElementById('cotacaoKanbanDetalhesAnexoNome');
  if (input && nomeSpan) {
    nomeSpan.textContent = input.files && input.files[0] ? input.files[0].name : 'Nenhum arquivo selecionado';
  }
};

function construirAnexosItemHtmlCotacaoKanban(item) {  const raw = item ? item.anexos : null;
  let lista = [];
  if (raw) {
    if (Array.isArray(raw)) {
      lista = raw;
    } else if (typeof raw === 'string') {
      try { lista = JSON.parse(raw); } catch (e) { lista = []; }
    }
  }
  if (!lista.length) {
    return '<div style="margin-top:8px;"><div style="font-size:11px;color:#6b7280;"><strong>Anexos do Item:</strong> -</div></div>';
  }
  const itensHtml = lista.map((anexo, idx) => {
    const anexoRaw = typeof anexo === 'string' ? anexo : '';
    const url = anexoRaw || anexo?.url || anexo?.path || '';
    const tipo = anexo?.tipo || 'application/octet-stream';
    const base64 = anexo?.base64 || '';
    const href = url || (base64 ? `data:${tipo};base64,${base64}` : 'javascript:void(0)');
    let nome = anexo?.nome || '';
    if (!nome && url) {
      try {
        const semQuery = url.split('?')[0];
        nome = decodeURIComponent(semQuery.substring(semQuery.lastIndexOf('/') + 1)) || '';
      } catch (e) { nome = url; }
    }
    if (!nome) nome = `Anexo ${idx + 1}`;
    return `<div style="display:inline-flex;align-items:center;gap:4px;background:#f3f4f6;padding:6px 10px;border-radius:6px;border:1px solid #d1d5db;"><a href="${escapeHtml(href)}" target="_blank" rel="noopener" style="display:inline-flex;align-items:center;gap:6px;text-decoration:none;color:#1f2937;font-size:11px;"><i class="fa-solid fa-paperclip" style="color:#3b82f6;"></i><span>${escapeHtml(nome)}</span></a><button onclick="excluirAnexoCotacaoKanban(${idx})" title="Excluir anexo" style="background:none;border:none;cursor:pointer;padding:0 0 0 6px;color:#ef4444;display:inline-flex;align-items:center;font-size:11px;"><i class="fa-solid fa-trash-can"></i></button></div>`;
  }).join('');
  return `<div style="margin-top:8px;"><div style="font-size:11px;color:#6b7280;"><strong>Anexos do Item:</strong></div><div style="display:flex;flex-wrap:wrap;gap:6px;margin-top:6px;">${itensHtml}</div></div>`;
}

async function excluirAnexoCotacaoKanban(index) {
  const itemId = Number(window.cotacaoKanbanItemId);
  if (!Number.isInteger(itemId)) return;
  if (!confirm('Deseja remover este anexo?')) return;

  const tableSource = window.cotacaoKanbanTableSource === 'compras_sem_cadastro'
    ? 'compras_sem_cadastro'
    : 'solicitacao_compras';

  try {
    const resp = await fetch(`/api/compras/itens/${itemId}`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({ table_source: tableSource, remover_anexo_index: index })
    });
    const data = await resp.json().catch(() => ({}));
    if (!resp.ok) throw new Error(data.error || 'Erro ao remover anexo');

    window.cotacaoKanbanItem = {
      ...(window.cotacaoKanbanItem || {}),
      ...(data.item || {})
    };

    const novoAnexosHtml = construirAnexosItemHtmlCotacaoKanban(window.cotacaoKanbanItem);
    window.cotacaoKanbanDetalhesContexto = {
      ...(window.cotacaoKanbanDetalhesContexto || {}),
      anexosItemHtml: novoAnexosHtml
    };

    renderizarDetalhesItemCotacaoKanban();
    renderizarItensGrupoCotacaoKanban();
  } catch (err) {
    console.error('[COTACAO KANBAN] Erro ao remover anexo:', err);
    alert('Erro ao remover anexo: ' + err.message);
  }
}

function iniciarEdicaoDetalhesCotacaoKanban() {
  window.cotacaoKanbanEditandoDetalhes = true;
  renderizarDetalhesItemCotacaoKanban();
  renderizarItensGrupoCotacaoKanban();
}

function cancelarEdicaoDetalhesCotacaoKanban() {
  window.cotacaoKanbanEditandoDetalhes = false;
  renderizarDetalhesItemCotacaoKanban();
  renderizarItensGrupoCotacaoKanban();
}

async function salvarDetalhesCotacaoKanban() {
  const itemId = Number(window.cotacaoKanbanItemId);
  if (!Number.isInteger(itemId)) return;

  const objetivoCompra = (document.getElementById('cotacaoKanbanDetalhesObjetivo')?.value || '').trim();
  const link = (document.getElementById('cotacaoKanbanDetalhesLink')?.value || '').trim();
  const tableSource = window.cotacaoKanbanTableSource === 'compras_sem_cadastro'
    ? 'compras_sem_cadastro'
    : 'solicitacao_compras';

  const payload = {
    table_source: tableSource,
    objetivo_compra: objetivoCompra || null
  };

  if (tableSource === 'compras_sem_cadastro') {
    payload.link = link || null;
  } else {
    payload.anexo_url = link || null;
  }

  // Upload de arquivo (se selecionado)
  const inputAnexo = document.getElementById('cotacaoKanbanDetalhesAnexoInput');
  const arquivoSelecionado = inputAnexo && inputAnexo.files && inputAnexo.files[0] ? inputAnexo.files[0] : null;
  if (arquivoSelecionado) {
    try {
      const formData = new FormData();
      const timestamp = Date.now();
      const filePath = `compras/item-detalhes/${itemId}/${timestamp}_${arquivoSelecionado.name}`;
      formData.append('file', arquivoSelecionado);
      formData.append('path', filePath);
      const uploadResp = await fetch('/api/upload/supabase', {
        method: 'POST',
        credentials: 'include',
        body: formData
      });
      if (uploadResp.ok) {
        const uploadData = await uploadResp.json();
        const fileUrl = uploadData.url || uploadData.path || '';
        if (fileUrl) {
          payload.novo_anexo = { nome: arquivoSelecionado.name, url: fileUrl, tipo: arquivoSelecionado.type };
        }
      }
    } catch (uploadErr) {
      console.error('[Cotacao Kanban] Erro no upload do anexo:', uploadErr);
    }
  }

  const btnSalvar = document.getElementById('btnSalvarDetalhesCotacaoKanban');
  const originalHtml = btnSalvar ? btnSalvar.innerHTML : '';
  if (btnSalvar) {
    btnSalvar.disabled = true;
    btnSalvar.style.cursor = 'not-allowed';
    btnSalvar.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> Salvando...';
  }

  try {
    const resp = await fetch(`/api/compras/itens/${itemId}`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify(payload)
    });

    const data = await resp.json().catch(() => ({}));
    if (!resp.ok) {
      throw new Error(data.error || 'Erro ao salvar detalhes do item');
    }

    window.cotacaoKanbanItem = {
      ...(window.cotacaoKanbanItem || {}),
      ...(data.item || {})
    };

    const linkExibicao = link
      ? (() => {
        const href = /^https?:\/\//i.test(link) ? link : `https://${link}`;
        return `<a href="${escapeHtml(href)}" target="_blank" rel="noopener" style="color:#1d4ed8;text-decoration:underline;">${escapeHtml(link)}</a>`;
      })()
      : '-';
    const novoAnexosHtml = construirAnexosItemHtmlCotacaoKanban(window.cotacaoKanbanItem);
    window.cotacaoKanbanDetalhesContexto = {
      ...(window.cotacaoKanbanDetalhesContexto || {}),
      linksCotacaoHtml: linkExibicao,
      anexosItemHtml: novoAnexosHtml
    };

    window.cotacaoKanbanEditandoDetalhes = false;
    renderizarDetalhesItemCotacaoKanban();
    renderizarItensGrupoCotacaoKanban();
    if (typeof loadMinhasSolicitacoes === 'function') {
      loadMinhasSolicitacoes();
    }
    alert('Detalhes do item atualizados com sucesso.');
  } catch (err) {
    console.error('[COTACAO KANBAN] Erro ao salvar detalhes do item:', err);
    alert('Erro ao salvar detalhes do item: ' + err.message);
    if (btnSalvar) {
      btnSalvar.disabled = false;
      btnSalvar.style.cursor = 'pointer';
      btnSalvar.innerHTML = originalHtml;
    }
  }
}

function atualizarEstadoFormularioCotacaoKanban() {
  const idEdicao = Number(window.cotacaoKanbanEdicaoId);
  const emEdicao = Number.isInteger(idEdicao) && idEdicao > 0;
  const info = document.getElementById('cotacaoKanbanModoEdicaoInfo');
  const btnSalvar = document.getElementById('cotacaoKanbanSalvarBtn');
  const btnCancelar = document.getElementById('cotacaoKanbanCancelarEdicaoBtn');

  if (info) {
    info.style.display = emEdicao ? 'block' : 'none';
    info.innerHTML = emEdicao
      ? `<i class="fa-solid fa-pen-to-square"></i> Editando cotação #${escapeHtml(String(window.cotacaoKanbanEdicaoId))}`
      : '';
  }

  if (btnSalvar) {
    btnSalvar.innerHTML = emEdicao
      ? '<i class="fa-solid fa-floppy-disk"></i> Salvar alterações'
      : '<i class="fa-solid fa-plus"></i> Registrar Cotação';
    btnSalvar.style.background = emEdicao
      ? 'linear-gradient(135deg,#2563eb 0%,#1d4ed8 100%)'
      : 'linear-gradient(135deg,#10b981 0%,#059669 100%)';
  }

  if (btnCancelar) {
    btnCancelar.style.display = emEdicao ? 'inline-flex' : 'none';
  }
}

window.adicionarAnexoCotacaoKanban = function() {
  const anexoInput = document.getElementById('cotacaoKanbanAnexo');
  if (!anexoInput || !anexoInput.files[0]) return;

  const file = anexoInput.files[0];
  const anexoId = Date.now() + '_' + Math.random().toString(36).substr(2, 9);

  if (!window.cotacaoKanbanAnexos) window.cotacaoKanbanAnexos = [];
  window.cotacaoKanbanAnexos.push({
    id: anexoId,
    file: file,
    nome: file.name,
    tipo: file.type,
    tamanho: file.size
  });

  renderizarListaAnexosCotacaoKanban();
  anexoInput.value = '';
};

function renderizarListaAnexosCotacaoKanban() {
  const listaContainer = document.getElementById('listaAnexosCotacaoKanban');
  if (!listaContainer) return;

  if (!window.cotacaoKanbanAnexos || window.cotacaoKanbanAnexos.length === 0) {
    listaContainer.innerHTML = '';
    return;
  }

  const html = window.cotacaoKanbanAnexos.map(anexo => {
    const tamanhoKB = (anexo.tamanho / 1024).toFixed(1);
    return `
      <div style="display:flex;align-items:center;gap:8px;background:#f0f9ff;border:1px solid #bae6fd;border-radius:6px;padding:8px 10px;">
        <i class="fa-solid fa-paperclip" style="color:#0284c7;font-size:12px;"></i>
        <span style="flex:1;font-size:12px;color:#0c4a6e;font-weight:500;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;" title="${escapeHtml(anexo.nome)}">
          ${escapeHtml(anexo.nome)}
        </span>
        <span style="font-size:11px;color:#0369a1;">${tamanhoKB} KB</span>
        <button 
          onclick="removerAnexoCotacaoKanban('${anexo.id}')"
          style="background:transparent;color:#ef4444;border:none;padding:4px;border-radius:4px;font-size:14px;cursor:pointer;line-height:1;width:20px;height:20px;display:flex;align-items:center;justify-content:center;"
          title="Remover anexo"
          onmouseover="this.style.background='#fee2e2'"
          onmouseout="this.style.background='transparent'">
          <i class="fa-solid fa-times"></i>
        </button>
      </div>
    `;
  }).join('');

  listaContainer.innerHTML = html;
}

window.removerAnexoCotacaoKanban = function(anexoId) {
  if (!window.cotacaoKanbanAnexos) return;
  window.cotacaoKanbanAnexos = window.cotacaoKanbanAnexos.filter(a => a.id !== anexoId);
  renderizarListaAnexosCotacaoKanban();
};

window.adicionarLinkCotacaoKanban = function(event) {
  if (!event || event.key !== 'Enter') return;
  event.preventDefault();

  const input = document.getElementById('cotacaoKanbanLink');
  if (!input) return;

  const valor = String(input.value || '').trim();
  if (!valor) return;

  const href = /^https?:\/\//i.test(valor) ? valor : `https://${valor}`;
  try {
    new URL(href);
  } catch (err) {
    alert('Link inválido. Verifique a URL e tente novamente.');
    return;
  }

  if (!window.cotacaoKanbanLinks) window.cotacaoKanbanLinks = [];
  const jaExiste = window.cotacaoKanbanLinks.some(link => String(link).toLowerCase() === href.toLowerCase());
  if (jaExiste) {
    input.value = '';
    return;
  }

  window.cotacaoKanbanLinks.push(href);
  input.value = '';
  renderizarListaLinksCotacaoKanban();
};

function renderizarListaLinksCotacaoKanban() {
  const listaContainer = document.getElementById('listaLinksCotacaoKanban');
  if (!listaContainer) return;

  if (!window.cotacaoKanbanLinks || window.cotacaoKanbanLinks.length === 0) {
    listaContainer.innerHTML = '';
    return;
  }

  const html = window.cotacaoKanbanLinks.map((link, idx) => {
    let nome = `Link ${idx + 1}`;
    try {
      const semQuery = link.split('?')[0];
      nome = decodeURIComponent(semQuery.substring(semQuery.lastIndexOf('/') + 1)) || nome;
    } catch (err) {
      nome = link;
    }

    return `
      <div style="display:flex;align-items:center;gap:8px;background:#ecfeff;border:1px solid #a5f3fc;border-radius:6px;padding:8px 10px;">
        <i class="fa-solid fa-link" style="color:#0891b2;font-size:12px;"></i>
        <a href="${escapeHtml(link)}" target="_blank" rel="noopener" style="flex:1;font-size:12px;color:#0c4a6e;font-weight:500;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;text-decoration:underline;" title="${escapeHtml(link)}">${escapeHtml(nome)}</a>
        <button
          onclick="removerLinkCotacaoKanban(${idx})"
          style="background:transparent;color:#ef4444;border:none;padding:4px;border-radius:4px;font-size:14px;cursor:pointer;line-height:1;width:20px;height:20px;display:flex;align-items:center;justify-content:center;"
          title="Remover link"
          onmouseover="this.style.background='#fee2e2'"
          onmouseout="this.style.background='transparent'">
          <i class="fa-solid fa-times"></i>
        </button>
      </div>
    `;
  }).join('');

  listaContainer.innerHTML = html;
}

window.removerLinkCotacaoKanban = function(index) {
  if (!window.cotacaoKanbanLinks) return;
  window.cotacaoKanbanLinks.splice(index, 1);
  renderizarListaLinksCotacaoKanban();
};

function renderizarItensGrupoCotacaoKanban() {
  const lista = document.getElementById('listaItensGrupoCotacaoKanban');
  const btnFiltro = document.getElementById('btnFiltroItensGrupoCotacaoKanban');
  const qtdItensEl = document.getElementById('qtdItensGrupoCotacaoKanban');
  if (!lista) return;

  const todosItens = Array.isArray(window.cotacaoKanbanItensGrupo) ? window.cotacaoKanbanItensGrupo : [];
  const usados = window.cotacaoKanbanItensUsados instanceof Set ? window.cotacaoKanbanItensUsados : new Set();
  const modoFiltro = window.cotacaoKanbanFiltroItensGrupo === 'todos' ? 'todos' : 'pendentes';
  const itemEmEdicaoQtd = Number(window.cotacaoKanbanEditQtdItemId || 0);

  if (btnFiltro) {
    btnFiltro.textContent = modoFiltro === 'todos' ? 'Mostrar pendentes' : 'Mostrar tudo';
    btnFiltro.style.background = modoFiltro === 'todos' ? '#ede9fe' : '#f3f4f6';
    btnFiltro.style.borderColor = modoFiltro === 'todos' ? '#c4b5fd' : '#d1d5db';
    btnFiltro.style.color = modoFiltro === 'todos' ? '#5b21b6' : '#374151';
  }

  const itensFiltrados = modoFiltro === 'todos'
    ? todosItens
    : todosItens.filter(item => !usados.has(Number(item?.id)));

  if (qtdItensEl) {
    const total = todosItens.length;
    const exibidos = itensFiltrados.length;
    qtdItensEl.textContent = modoFiltro === 'todos' ? `${total}` : `${exibidos}/${total}`;
    qtdItensEl.title = modoFiltro === 'todos'
      ? `Mostrando ${total} item(ns)`
      : `Mostrando ${exibidos} pendente(s) de ${total} item(ns)`;
  }

  const itemPendente = window.cotacaoKanbanNovoItemPendente;
  const blocoPendente = itemPendente
    ? `
      <div style="font-size:11px;color:#1f2937;background:#fffbeb;border:1px solid #fde68a;border-radius:4px;padding:6px 8px;display:flex;justify-content:space-between;gap:8px;align-items:center;">
        <span style="font-weight:700;color:#92400e;">${escapeHtml(itemPendente.codigo || '-')}</span>
        <span style="flex:1;color:#78350f;">${escapeHtml(itemPendente.descricao || '-')}</span>
        <span style="display:inline-flex;align-items:center;gap:6px;white-space:nowrap;">
          <input id="inputQtdNovoItemPendenteCotacaoKanban" type="number" min="0.0001" step="0.0001" value="${escapeHtml(String(itemPendente.quantidade || '1'))}" style="width:86px;padding:4px 6px;border:1px solid #d1d5db;border-radius:4px;font-size:11px;" />
          <button type="button" onclick="salvarNovoItemPendenteCotacaoKanban()" style="background:#10b981;color:#fff;border:none;border-radius:4px;padding:4px 6px;font-size:11px;cursor:pointer;" title="Salvar novo item"><i class=\"fa-solid fa-check\"></i></button>
          <button type="button" onclick="cancelarNovoItemPendenteCotacaoKanban()" style="background:#6b7280;color:#fff;border:none;border-radius:4px;padding:4px 6px;font-size:11px;cursor:pointer;" title="Cancelar"><i class=\"fa-solid fa-times\"></i></button>
        </span>
      </div>
    `
    : '';

  if (itensFiltrados.length === 0 && !blocoPendente) {
    lista.innerHTML = '<div style="font-size:12px;color:#9ca3af;text-align:center;padding:10px;border:1px dashed #d1d5db;border-radius:6px;background:#fafafa;">Nenhum item disponível neste filtro</div>';
    return;
  }

  const listaItensHtml = itensFiltrados.map((grupoItem) => {
    const idItem = Number(grupoItem?.id);
    const quantidadeValor = grupoItem?.quantidade;
    const quantidadeTexto = (quantidadeValor === null || quantidadeValor === undefined || String(quantidadeValor).trim() === '')
      ? '-'
      : String(quantidadeValor);
    const jaSelecionado = (window.cotacaoKanbanItensSelecionados || []).some(item => Number(item?.id) === idItem);
    const editandoQtd = itemEmEdicaoQtd === idItem;
    return `
      <div
        draggable="${editandoQtd ? 'false' : 'true'}"
        ondragstart="iniciarDragItemCotacaoKanban(event, ${Number.isInteger(idItem) ? idItem : 0})"
        style="font-size:11px;color:#1f2937;background:${jaSelecionado ? '#dcfce7' : '#f8fafc'};border:1px solid ${jaSelecionado ? '#86efac' : '#e5e7eb'};border-radius:4px;padding:6px 8px;display:flex;justify-content:space-between;gap:8px;cursor:grab;align-items:center;">
        <span style="font-weight:600;">${escapeHtml(grupoItem.produto_codigo || '-')}</span>
        <span style="flex:1;">${escapeHtml(grupoItem.produto_descricao || '-')}</span>
        ${editandoQtd
          ? `<span style="display:inline-flex;align-items:center;gap:6px;white-space:nowrap;">
               <input id="inputQtdEditItemGrupoCotacaoKanban-${idItem}" type="number" min="0.0001" step="0.0001" value="${escapeHtml(quantidadeTexto === '-' ? '' : quantidadeTexto)}" style="width:86px;padding:4px 6px;border:1px solid #d1d5db;border-radius:4px;font-size:11px;" />
               <button type="button" onclick="event.stopPropagation(); salvarQuantidadeItemGrupoCotacaoKanban(${idItem})" style="background:#10b981;color:#fff;border:none;border-radius:4px;padding:4px 6px;font-size:11px;cursor:pointer;" title="Salvar quantidade"><i class=\"fa-solid fa-check\"></i></button>
               <button type="button" onclick="event.stopPropagation(); cancelarEdicaoQuantidadeItemGrupoCotacaoKanban()" style="background:#6b7280;color:#fff;border:none;border-radius:4px;padding:4px 6px;font-size:11px;cursor:pointer;" title="Cancelar"><i class=\"fa-solid fa-times\"></i></button>
             </span>`
           : `<span style="color:#1f2937;white-space:nowrap;font-weight:700;">Qtd: ${escapeHtml(quantidadeTexto)}</span>
             <span style="display:inline-flex;align-items:center;gap:6px;">
               <button
                 type="button"
                 onclick="event.stopPropagation(); editarQuantidadeItemGrupoCotacaoKanban(${Number.isInteger(idItem) ? idItem : 0})"
                 title="Editar quantidade"
                 style="background:#2563eb;color:#fff;border:none;border-radius:4px;padding:4px 6px;font-size:11px;cursor:pointer;">
                 <i class="fa-solid fa-pen"></i>
               </button>
               <button
                 type="button"
                 onclick="event.stopPropagation(); excluirItemGrupoCotacaoKanban(${Number.isInteger(idItem) ? idItem : 0})"
                 title="Excluir item"
                 style="background:#dc2626;color:#fff;border:none;border-radius:4px;padding:4px 6px;font-size:11px;cursor:pointer;">
                 <i class="fa-solid fa-trash"></i>
               </button>
             </span>`}
      </div>
    `;
  }).join('');

  lista.innerHTML = `${blocoPendente}${listaItensHtml}`;
}

async function recarregarItensGrupoCotacaoKanban() {
  const grupo = String(window.cotacaoKanbanGrupoRequisicao || '').trim();
  const tableSource = String(window.cotacaoKanbanTableSource || '').trim();
  if (!grupo || !tableSource) return;

  const selecionadosAtuais = Array.isArray(window.cotacaoKanbanItensSelecionados)
    ? window.cotacaoKanbanItensSelecionados
    : [];

  const resp = await fetch(
    `/api/compras/grupo-itens?grupo_requisicao=${encodeURIComponent(grupo)}&table_source=${encodeURIComponent(tableSource)}`,
    { credentials: 'include' }
  );
  const data = await resp.json().catch(() => ({}));
  if (!resp.ok) {
    throw new Error(data.error || 'Erro ao recarregar itens do grupo');
  }

  const itensGrupo = Array.isArray(data.itens) ? data.itens : [];
  window.cotacaoKanbanItensGrupo = itensGrupo;
  window.cotacaoKanbanEditQtdItemId = null;
  window.cotacaoKanbanNovoItemPendente = null;

  const mapaGrupo = new Map(itensGrupo.map(it => [Number(it?.id), it]));
  window.cotacaoKanbanItensSelecionados = selecionadosAtuais
    .map((sel) => {
      const id = Number(sel?.id);
      const atualizado = mapaGrupo.get(id);
      if (!atualizado) return null;
      return {
        ...sel,
        produto_codigo: atualizado.produto_codigo || sel.produto_codigo,
        produto_descricao: atualizado.produto_descricao || sel.produto_descricao,
        quantidade: atualizado.quantidade ?? sel.quantidade,
        grupo_requisicao: atualizado.grupo_requisicao || sel.grupo_requisicao,
        table_source: atualizado.table_source || sel.table_source
      };
    })
    .filter(Boolean);

  renderizarItensSelecionadosCotacaoKanban();
  renderizarItensGrupoCotacaoKanban();
}

window.adicionarItemGrupoCotacaoKanban = async function() {
  await salvarNovoItemPendenteCotacaoKanban();
};

window.buscarProdutosNovoItemGrupoCotacaoKanban = async function() {
  const input = document.getElementById('novoItemGrupoBuscaCotacaoKanban');
  const termo = (input?.value || '').trim();
  const seq = (window.cotacaoKanbanBuscaReqSeq || 0) + 1;
  window.cotacaoKanbanBuscaReqSeq = seq;
  window.cotacaoKanbanBuscaTermoAtual = termo;

  if (termo.length < 2) {
    window.cotacaoKanbanBuscaResultados = [];
    renderizarBuscaNovoItemGrupoCotacaoKanban();
    return;
  }

  try {
    const resp = await fetch(`/api/produtos/search?q=${encodeURIComponent(termo)}&limit=20`, { credentials: 'include' });
    const data = await resp.json().catch(() => ({}));
    if (seq !== window.cotacaoKanbanBuscaReqSeq) return;
    if (!resp.ok) throw new Error(data.error || 'Erro ao buscar produtos');

    const produtos = Array.isArray(data.produtos) ? data.produtos : [];
    window.cotacaoKanbanBuscaResultados = produtos.map((p) => ({
      codigo: String(p?.codigo || '').trim(),
      descricao: String(p?.descricao || '').trim(),
      codigo_produto_omie: (p?.codigo_produto ?? null)
    })).filter((p) => p.codigo || p.descricao);
    renderizarBuscaNovoItemGrupoCotacaoKanban();
  } catch (err) {
    console.error('[COTACAO KANBAN] Erro na busca de produtos:', err);
    window.cotacaoKanbanBuscaResultados = [];
    renderizarBuscaNovoItemGrupoCotacaoKanban('Falha ao buscar produtos');
  }
};

function renderizarBuscaNovoItemGrupoCotacaoKanban(mensagemErro = '') {
  const container = document.getElementById('listaBuscaNovoItemGrupoCotacaoKanban');
  if (!container) return;

  if (mensagemErro) {
    container.style.display = 'block';
    container.innerHTML = `<div style="padding:8px;font-size:11px;color:#b91c1c;">${escapeHtml(mensagemErro)}</div>`;
    return;
  }

  const resultados = Array.isArray(window.cotacaoKanbanBuscaResultados) ? window.cotacaoKanbanBuscaResultados : [];
  const termoAtual = String(window.cotacaoKanbanBuscaTermoAtual || '').trim();
  if (resultados.length === 0) {
    if (termoAtual.length >= 2) {
      container.style.display = 'block';
      container.innerHTML = `
        <button
          type="button"
          onclick="adicionarProdutoSemCadastroDaBuscaCotacaoKanban()"
          style="width:100%;text-align:left;border:none;background:#fffbeb;padding:8px;cursor:pointer;font-size:11px;display:flex;align-items:center;gap:8px;">
          <span style="display:inline-flex;align-items:center;justify-content:center;width:18px;height:18px;border-radius:999px;background:#10b981;color:#fff;font-weight:700;">+</span>
          <span style="color:#92400e;">Não encontrado. Adicionar sem cadastro: <strong>${escapeHtml(termoAtual)}</strong> (Enter)</span>
        </button>
      `;
    } else {
      container.style.display = 'none';
      container.innerHTML = '';
    }
    return;
  }

  container.style.display = 'block';
  container.innerHTML = resultados.map((produto, idx) => `
    <button
      type="button"
      onclick="selecionarProdutoBuscaNovoItemGrupoCotacaoKanban(${idx})"
      style="width:100%;text-align:left;border:none;border-bottom:1px solid #eef2f7;background:#fff;padding:7px 8px;cursor:pointer;font-size:11px;display:grid;gap:2px;">
      <span style="font-weight:700;color:#1f2937;">${escapeHtml(produto.codigo || '-')}</span>
      <span style="color:#4b5563;">${escapeHtml(produto.descricao || '-')}</span>
    </button>
  `).join('');
}

window.atalhoBuscaNovoItemGrupoCotacaoKanban = async function(event) {
  if (!event || event.key !== 'Enter') return;
  const resultados = Array.isArray(window.cotacaoKanbanBuscaResultados) ? window.cotacaoKanbanBuscaResultados : [];
  const termoAtual = String(window.cotacaoKanbanBuscaTermoAtual || '').trim();
  if (resultados.length === 0 && termoAtual.length >= 2) {
    event.preventDefault();
    await adicionarProdutoSemCadastroDaBuscaCotacaoKanban();
  }
};

async function obterCodigoProvisorioCotacaoKanban() {
  const resp = await fetch('/api/compras/proximo-codigo-provisorio', { credentials: 'include' });
  const data = await resp.json().catch(() => ({}));
  if (!resp.ok || !data?.ok || !data?.codigo) {
    throw new Error(data?.erro || data?.error || 'Erro ao gerar código provisório');
  }
  return String(data.codigo || '').trim();
}

window.adicionarProdutoSemCadastroDaBuscaCotacaoKanban = async function() {
  const termo = String(window.cotacaoKanbanBuscaTermoAtual || '').trim();
  if (termo.length < 2) {
    alert('Digite ao menos 2 caracteres para adicionar sem cadastro.');
    return;
  }

  try {
    const codigoProvisorio = await obterCodigoProvisorioCotacaoKanban();
    window.cotacaoKanbanNovoItemPendente = {
      codigo: codigoProvisorio,
      descricao: termo,
      codigo_produto_omie: null,
      quantidade: 1,
      sem_cadastro: true
    };

    window.cotacaoKanbanBuscaResultados = [];
    window.cotacaoKanbanBuscaTermoAtual = '';
    const input = document.getElementById('novoItemGrupoBuscaCotacaoKanban');
    if (input) input.value = '';

    renderizarBuscaNovoItemGrupoCotacaoKanban();
    renderizarItensGrupoCotacaoKanban();
  } catch (err) {
    console.error('[COTACAO KANBAN] Erro ao criar item sem cadastro:', err);
    alert('Erro ao criar item sem cadastro: ' + err.message);
  }
};

window.selecionarProdutoBuscaNovoItemGrupoCotacaoKanban = function(index) {
  const idx = Number(index);
  const resultados = Array.isArray(window.cotacaoKanbanBuscaResultados) ? window.cotacaoKanbanBuscaResultados : [];
  const escolhido = resultados[idx];
  if (!escolhido) return;

  window.cotacaoKanbanNovoItemPendente = {
    codigo: escolhido.codigo,
    descricao: escolhido.descricao,
    codigo_produto_omie: escolhido.codigo_produto_omie ?? null,
    quantidade: 1
  };

  window.cotacaoKanbanBuscaResultados = [];
  const input = document.getElementById('novoItemGrupoBuscaCotacaoKanban');
  if (input) input.value = '';
  renderizarBuscaNovoItemGrupoCotacaoKanban();
  renderizarItensGrupoCotacaoKanban();
};

window.cancelarNovoItemPendenteCotacaoKanban = function() {
  window.cotacaoKanbanNovoItemPendente = null;
  renderizarItensGrupoCotacaoKanban();
};

window.salvarNovoItemPendenteCotacaoKanban = async function() {
  const grupo = String(window.cotacaoKanbanGrupoRequisicao || '').trim();
  const tableSource = String(window.cotacaoKanbanTableSource || '').trim();
  if (!grupo || !tableSource) {
    alert('Grupo não identificado para adicionar item.');
    return;
  }

  const pendente = window.cotacaoKanbanNovoItemPendente;
  if (!pendente) {
    alert('Selecione um produto na lista de busca antes de salvar.');
    return;
  }

  const codigo = String(pendente.codigo || '').trim();
  const descricao = String(pendente.descricao || '').trim();
  const codigoProdutoOmie = pendente.codigo_produto_omie ?? null;
  const qtdInput = document.getElementById('inputQtdNovoItemPendenteCotacaoKanban');
  const quantidadeTxt = (qtdInput?.value || '').trim();

  const quantidade = Number(String(quantidadeTxt).replace(',', '.'));
  if (!codigo || !descricao) {
    alert('Código e descrição são obrigatórios.');
    return;
  }
  if (!Number.isFinite(quantidade) || quantidade <= 0) {
    alert('Quantidade inválida.');
    return;
  }

  try {
    const resp = await fetch('/api/compras/grupo-itens', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({
        grupo_requisicao: grupo,
        table_source: tableSource,
        produto_codigo: String(codigo).trim(),
        produto_descricao: String(descricao).trim(),
        codigo_produto_omie: codigoProdutoOmie,
        quantidade
      })
    });
    const data = await resp.json().catch(() => ({}));
    if (!resp.ok) throw new Error(data.error || 'Erro ao adicionar item no grupo');

    await recarregarItensGrupoCotacaoKanban();
    if (typeof loadMinhasSolicitacoes === 'function') loadMinhasSolicitacoes();
    alert('Item adicionado ao grupo com sucesso.');
  } catch (err) {
    console.error('[COTACAO KANBAN] Erro ao adicionar item no grupo:', err);
    alert('Erro ao adicionar item no grupo: ' + err.message);
  }
};

window.editarQuantidadeItemGrupoCotacaoKanban = function(itemId) {
  const id = Number(itemId);
  if (!Number.isInteger(id) || id <= 0) return;

  window.cotacaoKanbanEditQtdItemId = id;
  renderizarItensGrupoCotacaoKanban();
};

window.cancelarEdicaoQuantidadeItemGrupoCotacaoKanban = function() {
  window.cotacaoKanbanEditQtdItemId = null;
  renderizarItensGrupoCotacaoKanban();
};

window.salvarQuantidadeItemGrupoCotacaoKanban = async function(itemId) {
  const id = Number(itemId);
  if (!Number.isInteger(id) || id <= 0) return;

  const tableSource = String(window.cotacaoKanbanTableSource || '').trim();
  const inputQtd = document.getElementById(`inputQtdEditItemGrupoCotacaoKanban-${id}`);
  const novaQtdTxt = (inputQtd?.value || '').trim();

  const novaQtd = Number(String(novaQtdTxt).replace(',', '.'));
  if (!Number.isFinite(novaQtd) || novaQtd <= 0) {
    alert('Quantidade inválida.');
    return;
  }

  try {
    const resp = await fetch(`/api/compras/itens/${id}`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({ table_source: tableSource, quantidade: novaQtd })
    });
    const data = await resp.json().catch(() => ({}));
    if (!resp.ok) throw new Error(data.error || 'Erro ao atualizar quantidade');

    window.cotacaoKanbanEditQtdItemId = null;
    await recarregarItensGrupoCotacaoKanban();
    if (typeof loadMinhasSolicitacoes === 'function') loadMinhasSolicitacoes();
  } catch (err) {
    console.error('[COTACAO KANBAN] Erro ao editar quantidade do item:', err);
    alert('Erro ao editar quantidade: ' + err.message);
  }
};

window.excluirItemGrupoCotacaoKanban = async function(itemId) {
  const id = Number(itemId);
  if (!Number.isInteger(id) || id <= 0) return;
  const tableSource = String(window.cotacaoKanbanTableSource || '').trim();

  if (!confirm('Deseja excluir este item do grupo?')) return;

  try {
    const resp = await fetch(`/api/compras/itens/${id}`, {
      method: 'DELETE',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({ table_source: tableSource })
    });
    const data = await resp.json().catch(() => ({}));
    if (!resp.ok) throw new Error(data.error || 'Erro ao excluir item');

    window.cotacaoKanbanEditQtdItemId = null;
    await recarregarItensGrupoCotacaoKanban();
    if (typeof loadMinhasSolicitacoes === 'function') loadMinhasSolicitacoes();
  } catch (err) {
    console.error('[COTACAO KANBAN] Erro ao excluir item do grupo:', err);
    alert('Erro ao excluir item: ' + err.message);
  }
};

function renderizarItensSelecionadosCotacaoKanban() {
  const lista = document.getElementById('listaItensSelecionadosCotacaoKanban');
  if (!lista) return;

  const itensSelecionados = Array.isArray(window.cotacaoKanbanItensSelecionados) ? window.cotacaoKanbanItensSelecionados : [];
  if (itensSelecionados.length === 0) {
    lista.innerHTML = '<div style="font-size:11px;color:#9ca3af;">Nenhum item arrastado ainda.</div>';
    return;
  }

  lista.innerHTML = itensSelecionados.map(item => `
    <div style="display:flex;align-items:center;gap:8px;background:#ecfdf5;border:1px solid #a7f3d0;border-radius:6px;padding:8px 10px;">
      <i class="fa-solid fa-box" style="color:#059669;font-size:11px;"></i>
      <span style="flex:1;font-size:11px;color:#065f46;font-weight:600;">${escapeHtml(item.produto_codigo || '-')} - ${escapeHtml(item.produto_descricao || '-')}</span>
      <span style="font-size:10px;color:#047857;">Qtd: ${escapeHtml(String(item.quantidade ?? '-'))}</span>
      <button
        type="button"
        onclick="removerItemSelecionadoCotacaoKanban(${Number(item.id)})"
        style="background:transparent;color:#ef4444;border:none;cursor:pointer;font-size:12px;padding:2px 4px;">
        <i class="fa-solid fa-times"></i>
      </button>
    </div>
  `).join('');
}

window.alternarFiltroItensGrupoCotacaoKanban = function() {
  window.cotacaoKanbanFiltroItensGrupo = window.cotacaoKanbanFiltroItensGrupo === 'todos' ? 'pendentes' : 'todos';
  renderizarItensGrupoCotacaoKanban();
};

window.iniciarDragItemCotacaoKanban = function(event, itemId) {
  if (!event?.dataTransfer) return;
  event.dataTransfer.setData('text/plain', String(itemId));
  event.dataTransfer.effectAllowed = 'copy';
};

window.dragOverItemCotacaoKanban = function(event) {
  event.preventDefault();
  if (event?.dataTransfer) event.dataTransfer.dropEffect = 'copy';
};

window.dropItemCotacaoKanban = function(event) {
  event.preventDefault();
  const itemId = Number(event?.dataTransfer?.getData('text/plain') || 0);
  if (!Number.isInteger(itemId) || itemId <= 0) return;

  const todosItens = Array.isArray(window.cotacaoKanbanItensGrupo) ? window.cotacaoKanbanItensGrupo : [];
  const item = todosItens.find(it => Number(it?.id) === itemId);
  if (!item) return;

  if (!Array.isArray(window.cotacaoKanbanItensSelecionados)) {
    window.cotacaoKanbanItensSelecionados = [];
  }

  const jaSelecionado = window.cotacaoKanbanItensSelecionados.some(it => Number(it?.id) === itemId);
  if (jaSelecionado) return;

  window.cotacaoKanbanItensSelecionados.push({
    id: item.id,
    grupo_requisicao: item.grupo_requisicao || window.cotacaoKanbanGrupoRequisicao || null,
    produto_codigo: item.produto_codigo || null,
    produto_descricao: item.produto_descricao || item.descricao || null,
    quantidade: item.quantidade ?? null,
    table_source: item.table_source || window.cotacaoKanbanTableSource || 'solicitacao_compras'
  });

  renderizarItensSelecionadosCotacaoKanban();
  renderizarItensGrupoCotacaoKanban();
};

window.removerItemSelecionadoCotacaoKanban = function(itemId) {
  const idNormalizado = Number(itemId);
  if (!Array.isArray(window.cotacaoKanbanItensSelecionados)) return;
  window.cotacaoKanbanItensSelecionados = window.cotacaoKanbanItensSelecionados.filter(item => Number(item?.id) !== idNormalizado);
  renderizarItensSelecionadosCotacaoKanban();
  renderizarItensGrupoCotacaoKanban();
};

window.alternarMoedaCotacaoKanban = function() {
  window.cotacaoKanbanMoeda = window.cotacaoKanbanMoeda === 'USD' ? 'BRL' : 'USD';
  const btnMoeda = document.getElementById('btnMoedaCotacaoKanban');
  if (btnMoeda) btnMoeda.textContent = window.cotacaoKanbanMoeda === 'USD' ? '$' : 'R$';
};

window.mascararValorCotacaoKanban = function(input) {
  if (!input) return;
  const apenasDigitos = String(input.value || '').replace(/\D/g, '');
  if (!apenasDigitos) {
    input.value = '';
    return;
  }

  const valorNumerico = Number(apenasDigitos) / 100;
  input.value = valorNumerico.toLocaleString('pt-BR', {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2
  });
};

function parseValorCotacaoKanban(valorTexto) {
  const texto = String(valorTexto || '').trim();
  if (!texto) return 0;

  const normalizado = texto
    .replace(/\./g, '')
    .replace(',', '.')
    .replace(/[^\d.]/g, '');

  const valor = Number.parseFloat(normalizado);
  return Number.isFinite(valor) ? valor : 0;
}

function simboloMoedaCotacaoKanban(moeda) {
  return String(moeda || 'BRL').toUpperCase() === 'USD' ? '$' : 'R$';
}

function formatarValorCotacaoKanban(valor, moeda) {
  const numero = Number(valor || 0);
  const simbolo = simboloMoedaCotacaoKanban(moeda);
  const valorFormatado = Number.isFinite(numero)
    ? numero.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 })
    : '0,00';
  return `${simbolo} ${valorFormatado}`;
}

const COTACAO_KANBAN_CAMBIO_CACHE_MS = 5 * 60 * 1000;

async function obterTaxaUsdBrlCotacaoKanban() {
  const cache = window.cotacaoKanbanCambioUsdBrl;
  const agora = Date.now();
  if (
    cache
    && Number.isFinite(Number(cache.valor))
    && Number(cache.valor) > 0
    && Number(cache.expiraEm || 0) > agora
  ) {
    return Number(cache.valor);
  }

  try {
    const resp = await _origFetch('https://economia.awesomeapi.com.br/json/last/USD-BRL', {
      method: 'GET',
      mode: 'cors',
      credentials: 'omit',
      cache: 'no-store'
    });
    if (!resp.ok) throw new Error(`HTTP ${resp.status}`);
    const data = await resp.json();
    const taxa = Number(data?.USDBRL?.bid || 0);
    if (!Number.isFinite(taxa) || taxa <= 0) {
      throw new Error('Taxa inválida');
    }

    window.cotacaoKanbanCambioUsdBrl = {
      valor: taxa,
      expiraEm: agora + COTACAO_KANBAN_CAMBIO_CACHE_MS
    };
    return taxa;
  } catch (err) {
    console.error('[COTACAO KANBAN] Falha ao consultar câmbio USD/BRL:', err);
    return null;
  }
}

function formatarConversaoUsdParaBrlCotacaoKanban(valor, moeda, taxaUsdBrl) {
  const moedaNormalizada = String(moeda || 'BRL').toUpperCase();
  if (moedaNormalizada !== 'USD') return '';

  const valorNumero = Number(valor || 0);
  const taxaNumero = Number(taxaUsdBrl || 0);
  if (!Number.isFinite(valorNumero) || valorNumero <= 0) return '';
  if (!Number.isFinite(taxaNumero) || taxaNumero <= 0) return '';

  const valorConvertido = valorNumero * taxaNumero;
  return ` <span style="color:#2563eb;">(≈ ${formatarValorCotacaoKanban(valorConvertido, 'BRL')})</span>`;
}

function montarResumoTotalCotacoesKanban(cotacoes = [], taxaUsdBrl = null, obterValor = null) {
  const lista = Array.isArray(cotacoes) ? cotacoes : [];
  const getValor = typeof obterValor === 'function'
    ? obterValor
    : (cotacao) => Number(cotacao?.valor_cotado || 0) || 0;

  let somaBrl = 0;
  let somaUsd = 0;

  lista.forEach((cotacao) => {
    const moeda = String(cotacao?.moeda || 'BRL').toUpperCase() === 'USD' ? 'USD' : 'BRL';
    const valor = Number(getValor(cotacao));
    if (!Number.isFinite(valor) || valor <= 0) return;

    if (moeda === 'USD') {
      somaUsd += valor;
    } else {
      somaBrl += valor;
    }
  });

  const temBrl = somaBrl > 0;
  const temUsd = somaUsd > 0;
  const taxaValida = Number.isFinite(Number(taxaUsdBrl || 0)) && Number(taxaUsdBrl || 0) > 0;

  if (temBrl && temUsd) {
    const totalConvertidoBrl = somaBrl + (taxaValida ? somaUsd * Number(taxaUsdBrl) : 0);
    return `${formatarValorCotacaoKanban(somaBrl, 'BRL')} + ${formatarValorCotacaoKanban(somaUsd, 'USD')}`
      + (taxaValida ? ` <span style="color:#2563eb;">(≈ ${formatarValorCotacaoKanban(totalConvertidoBrl, 'BRL')})</span>` : '');
  }

  if (temUsd) {
    return `${formatarValorCotacaoKanban(somaUsd, 'USD')}${formatarConversaoUsdParaBrlCotacaoKanban(somaUsd, 'USD', taxaUsdBrl)}`;
  }

  return formatarValorCotacaoKanban(somaBrl, 'BRL');
}

async function registrarCotacaoKanban() {
  if (!window.cotacaoKanbanItemId) return;
  const fornecedor = document.getElementById('cotacaoKanbanFornecedor').value.trim();
  const valor = parseValorCotacaoKanban(document.getElementById('cotacaoKanbanValor')?.value || '0');
  const cotacaoEdicaoId = Number(window.cotacaoKanbanEdicaoId);
  const emEdicao = Number.isInteger(cotacaoEdicaoId) && cotacaoEdicaoId > 0;

  if (!fornecedor) {
    alert('Preencha o fornecedor');
    return;
  }
  if (!valor || valor <= 0) {
    alert('Preencha um valor válido');
    return;
  }
  if (!Array.isArray(window.cotacaoKanbanItensSelecionados) || window.cotacaoKanbanItensSelecionados.length === 0) {
    alert('Arraste pelo menos 1 item do grupo para esta cotação.');
    return;
  }

  try {
    let anexosArray = null;
    if (window.cotacaoKanbanAnexos && window.cotacaoKanbanAnexos.length > 0) {
      anexosArray = [];
      for (const anexo of window.cotacaoKanbanAnexos) {
        const base64 = await new Promise((resolve, reject) => {
          const reader = new FileReader();
          reader.onload = () => resolve(reader.result.split(',')[1]);
          reader.onerror = reject;
          reader.readAsDataURL(anexo.file);
        });
        anexosArray.push({
          nome: anexo.nome,
          tipo: anexo.tipo,
          tamanho: anexo.tamanho,
          base64: base64
        });
      }
    }

    // Objetivo: Passar table_source para identificar se é de compras_sem_cadastro ou solicitacao_compras
    const tableSource = window.cotacaoKanbanTableSource || window.cotacaoKanbanItem?.table_source || 'solicitacao_compras';
    const linksCotacao = Array.isArray(window.cotacaoKanbanLinks) ? window.cotacaoKanbanLinks : [];
    const itensCotacao = Array.isArray(window.cotacaoKanbanItensSelecionados) ? window.cotacaoKanbanItensSelecionados : [];
    const moeda = window.cotacaoKanbanMoeda === 'USD' ? 'USD' : 'BRL';

    const payload = {
      fornecedor_nome: fornecedor,
      valor_cotado: valor,
      moeda,
      link: linksCotacao,
      itens_cotacao: itensCotacao,
      table_source: tableSource
    };

    if (!emEdicao) {
      payload.solicitacao_id = window.cotacaoKanbanItemId;
    }
    if (Array.isArray(anexosArray) && anexosArray.length > 0) {
      payload.anexos = anexosArray;
    }

    const endpoint = emEdicao
      ? `/api/compras/cotacoes/${cotacaoEdicaoId}`
      : '/api/compras/cotacoes';
    const method = emEdicao ? 'PUT' : 'POST';

    const resp = await fetch(endpoint, {
      method,
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify(payload)
    });

    if (!resp.ok) {
      const errData = await resp.json();
      throw new Error(errData.error || 'Erro ao salvar cotação');
    }

    document.getElementById('cotacaoKanbanFornecedor').value = '';
    document.getElementById('cotacaoKanbanValor').value = '';
    const inputLink = document.getElementById('cotacaoKanbanLink');
    if (inputLink) inputLink.value = '';
    window.cotacaoKanbanAnexos = [];
    window.cotacaoKanbanLinks = [];
    window.cotacaoKanbanItensSelecionados = [];
    window.cotacaoKanbanMoeda = 'BRL';
    window.cotacaoKanbanEdicaoId = null;
    const btnMoeda = document.getElementById('btnMoedaCotacaoKanban');
    if (btnMoeda) btnMoeda.textContent = 'R$';
    atualizarEstadoFormularioCotacaoKanban();
    renderizarListaAnexosCotacaoKanban();
    renderizarListaLinksCotacaoKanban();
    renderizarItensSelecionadosCotacaoKanban();
    await carregarCotacoesKanban();
  } catch (err) {
    console.error('[COTACAO KANBAN] Erro ao registrar:', err);
    alert('Erro ao registrar cotação: ' + err.message);
  }
}

async function carregarCotacoesKanban() {
  if (!window.cotacaoKanbanItemId) return;
  const container = document.getElementById('listaCotacoesRegistradasKanban');
  const totalCotacoesResumo = document.getElementById('totalCotacoesKanbanResumo');
  if (!container) return;

  try {
    // Comentário: determina table_source a partir do item (compras_sem_cadastro ou solicitacao_compras)
    const item = window.cotacaoKanbanItem || {};
    const tableSource = window.cotacaoKanbanTableSource || item.table_source || 'solicitacao_compras';
    
    const resp = await fetch(`/api/compras/cotacoes/${window.cotacaoKanbanItemId}?table_source=${encodeURIComponent(tableSource)}`, { credentials: 'include' });
    if (!resp.ok) throw new Error('Erro ao carregar cotações');
    const data = await resp.json();
    window.cotacaoKanbanCotacoes = Array.isArray(data.cotacoes) ? data.cotacoes : [];

    const possuiCotacaoUsd = window.cotacaoKanbanCotacoes.some((cotacao) =>
      String(cotacao?.moeda || 'BRL').toUpperCase() === 'USD'
    );
    const taxaUsdBrl = possuiCotacaoUsd ? await obterTaxaUsdBrlCotacaoKanban() : null;

    const itensUsados = new Set();
    window.cotacaoKanbanCotacoes.forEach((cotacao) => {
      const itens = Array.isArray(cotacao?.itens_cotacao) ? cotacao.itens_cotacao : [];
      itens.forEach((item) => {
        const idItem = Number(item?.item_origem_id || item?.id);
        if (Number.isInteger(idItem)) itensUsados.add(idItem);
      });
    });
    window.cotacaoKanbanItensUsados = itensUsados;
    renderizarItensGrupoCotacaoKanban();

    const resumoTotalHtml = montarResumoTotalCotacoesKanban(
      window.cotacaoKanbanCotacoes,
      taxaUsdBrl,
      (cotacao) => Number(cotacao?.valor_cotado || 0) || 0
    );
    if (totalCotacoesResumo) {
      totalCotacoesResumo.innerHTML = `
        <i class="fa-solid fa-calculator"></i>
        <strong>Total das cotações:</strong>
        <span>${resumoTotalHtml}</span>
      `;
    }

    if (window.cotacaoKanbanCotacoes.length === 0) {
      container.innerHTML = '<div style="text-align:center;padding:20px;color:#9ca3af;font-size:13px;">Nenhuma cotação registrada ainda</div>';
      return;
    }

    const html = window.cotacaoKanbanCotacoes.map(cotacao => {
      const moedaCotacao = String(cotacao.moeda || 'BRL').toUpperCase() === 'USD' ? 'USD' : 'BRL';
      const valorCotacao = Number(cotacao.valor_cotado || 0) || 0;
      const valorCotacaoHtml = `${formatarValorCotacaoKanban(valorCotacao, moedaCotacao)}${formatarConversaoUsdParaBrlCotacaoKanban(valorCotacao, moedaCotacao, taxaUsdBrl)}`;
      const observacaoTexto = cotacao.observacao || '';
      let linksHtml = '';
      const linksArray = (() => {
        const bruto = cotacao.link;
        if (!bruto) return [];
        if (Array.isArray(bruto)) return bruto.map(v => String(v || '').trim()).filter(Boolean);
        if (typeof bruto === 'string') {
          const texto = bruto.trim();
          if (!texto) return [];
          try {
            const parsed = JSON.parse(texto);
            if (Array.isArray(parsed)) return parsed.map(v => String(v || '').trim()).filter(Boolean);
          } catch (err) {
            // mantém fluxo de string simples
          }
          return [texto];
        }
        return [];
      })();

      if (linksArray.length > 0) {
        linksHtml = `
          <div style="font-size:11px;color:#6b7280;margin-top:4px;">
            <strong><i class="fa-solid fa-link"></i> Links:</strong>
            <div style="margin-top:4px;padding-left:8px;display:flex;flex-direction:column;gap:4px;">
              ${linksArray.map((link, idx) => {
                const href = /^https?:\/\//i.test(link) ? link : `https://${link}`;
                let nome = `Link ${idx + 1}`;
                try {
                  const semQuery = link.split('?')[0];
                  nome = decodeURIComponent(semQuery.substring(semQuery.lastIndexOf('/') + 1)) || nome;
                } catch (err) {
                  nome = link;
                }
                return `<a href="${escapeHtml(href)}" target="_blank" rel="noopener" style="color:#0284c7;text-decoration:underline;">• ${escapeHtml(nome)}</a>`;
              }).join('')}
            </div>
          </div>
        `;
      }

      let anexosHtml = '';
      if (cotacao.anexos) {
        const anexosArray = Array.isArray(cotacao.anexos) ? cotacao.anexos : [];
        const listaAnexos = anexosArray.map(a => a?.nome).filter(a => a);
        if (listaAnexos.length > 0) {
          anexosHtml = `
            <div style="font-size:11px;color:#6b7280;margin-top:4px;">
              <strong><i class="fa-solid fa-paperclip"></i> Anexos:</strong>
              <div style="margin-top:4px;padding-left:8px;display:flex;flex-direction:column;gap:4px;">
                ${anexosArray.map((anexo, idx) => {
                  const nome = anexo?.nome || `Anexo ${idx + 1}`;
                  const url = anexo?.url || '';
                  const tipo = anexo?.tipo || 'application/octet-stream';
                  const base64 = anexo?.base64 || '';
                  const href = url || (base64 ? `data:${tipo};base64,${base64}` : '#');
                  return `
                    <a href="${href}" target="_blank" style="color:#0284c7;text-decoration:underline;">• ${escapeHtml(nome)}</a>
                  `;
                }).join('')}
              </div>
            </div>
          `;
        }
      }

      return `
        <div style="background:white;border:2px solid #10b981;border-radius:8px;padding:12px;display:grid;grid-template-columns:1fr auto;gap:12px;align-items:start;">
          <div>
            <div style="display:flex;align-items:center;gap:8px;margin-bottom:6px;">
              <i class="fa-solid fa-check-circle" style="color:#10b981;"></i>
              <span style="font-size:12px;font-weight:600;color:#1f2937;">${escapeHtml(cotacao.fornecedor_nome || '-')}</span>
            </div>
            <div style="font-size:11px;color:#6b7280;">
              <strong>Valor:</strong> ${valorCotacaoHtml}
            </div>
            <div style="font-size:11px;color:#6b7280;margin-top:4px;">
              <strong>Itens da cotação:</strong>
              <div style="margin-top:4px;padding-left:8px;display:flex;flex-direction:column;gap:3px;">
                ${(Array.isArray(cotacao.itens_cotacao) && cotacao.itens_cotacao.length > 0)
                  ? cotacao.itens_cotacao.map((itemCotado) => {
                      const codigo = itemCotado?.produto_codigo || '-';
                      const descricao = itemCotado?.produto_descricao || '-';
                      const qtd = itemCotado?.quantidade ?? '-';
                      return `<span style="color:#374151;">• ${escapeHtml(String(codigo))} - ${escapeHtml(String(descricao))} (Qtd: ${escapeHtml(String(qtd))})</span>`;
                    }).join('')
                  : '<span style="color:#9ca3af;">Sem itens vinculados</span>'
                }
              </div>
            </div>
            ${linksHtml}
            ${anexosHtml}

            <div style="margin-top:10px;background:#f9fafb;border:1px solid #e5e7eb;border-radius:6px;padding:10px;">
              <div style="font-size:11px;color:#6b7280;font-weight:600;margin-bottom:6px;">Observações</div>
              <div style="font-size:12px;color:#374151;white-space:pre-wrap;">${escapeHtml(observacaoTexto || 'Sem observações.')}</div>
            </div>

            <div style="margin-top:8px;">
              <textarea
                id="obs-cotacao-${cotacao.id}"
                placeholder="Adicionar nova observação..."
                style="width:100%;min-height:60px;padding:8px;border:1px solid #d1d5db;border-radius:6px;font-size:12px;resize:vertical;"></textarea>
              <button
                onclick="adicionarObservacaoCotacaoKanban(${cotacao.id})"
                style="margin-top:6px;background:#3b82f6;color:white;border:none;padding:6px 10px;border-radius:6px;font-size:12px;font-weight:700;cursor:pointer;display:inline-flex;align-items:center;gap:6px;">
                <i class="fa-solid fa-plus"></i>
                Adicionar observação
              </button>
            </div>
          </div>
          <div style="display:grid;gap:6px;">
            <button
              onclick="editarCotacaoKanban(${cotacao.id})"
              title="Editar cotação"
              style="background:#2563eb;color:white;border:none;padding:8px;border-radius:6px;cursor:pointer;width:36px;height:36px;display:flex;align-items:center;justify-content:center;">
              <i class="fa-solid fa-pen"></i>
            </button>
            <button
              onclick="excluirCotacaoKanban(${cotacao.id})"
              title="Excluir cotação"
              style="background:#ef4444;color:white;border:none;padding:8px;border-radius:6px;cursor:pointer;width:36px;height:36px;display:flex;align-items:center;justify-content:center;">
              <i class="fa-solid fa-trash"></i>
            </button>
          </div>
        </div>
      `;
    }).join('');

    container.innerHTML = html;
  } catch (err) {
    console.error('[COTACAO KANBAN] Erro ao listar:', err);
    container.innerHTML = '<div style="text-align:center;padding:20px;color:#ef4444;font-size:13px;">Erro ao carregar cotações.</div>';
  }
}

window.editarCotacaoKanban = function(cotacaoId) {
  const id = Number(cotacaoId);
  if (!Number.isInteger(id)) return;

  const cotacao = (Array.isArray(window.cotacaoKanbanCotacoes) ? window.cotacaoKanbanCotacoes : []).find(c => Number(c?.id) === id);
  if (!cotacao) {
    alert('Cotação não encontrada para edição.');
    return;
  }

  const inputFornecedor = document.getElementById('cotacaoKanbanFornecedor');
  const inputValor = document.getElementById('cotacaoKanbanValor');
  if (inputFornecedor) inputFornecedor.value = cotacao.fornecedor_nome || '';
  if (inputValor) {
    const valor = Number(cotacao.valor_cotado || 0);
    inputValor.value = Number.isFinite(valor)
      ? valor.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 })
      : '';
  }

  const moedaCotacao = String(cotacao.moeda || 'BRL').toUpperCase() === 'USD' ? 'USD' : 'BRL';
  window.cotacaoKanbanMoeda = moedaCotacao;
  const btnMoeda = document.getElementById('btnMoedaCotacaoKanban');
  if (btnMoeda) btnMoeda.textContent = moedaCotacao === 'USD' ? '$' : 'R$';

  const linksArray = (() => {
    const bruto = cotacao.link;
    if (!bruto) return [];
    if (Array.isArray(bruto)) return bruto.map(v => String(v || '').trim()).filter(Boolean);
    if (typeof bruto === 'string') {
      const texto = bruto.trim();
      if (!texto) return [];
      try {
        const parsed = JSON.parse(texto);
        if (Array.isArray(parsed)) return parsed.map(v => String(v || '').trim()).filter(Boolean);
      } catch (err) {
      }
      return [texto];
    }
    return [];
  })();

  window.cotacaoKanbanLinks = linksArray;
  window.cotacaoKanbanAnexos = [];
  window.cotacaoKanbanItensSelecionados = Array.isArray(cotacao.itens_cotacao)
    ? cotacao.itens_cotacao.map((item) => ({
        id: Number(item?.item_origem_id || item?.id),
        item_origem_id: Number(item?.item_origem_id || item?.id),
        grupo_requisicao: item?.grupo_requisicao || window.cotacaoKanbanGrupoRequisicao || null,
        produto_codigo: item?.produto_codigo || null,
        produto_descricao: item?.produto_descricao || null,
        quantidade: item?.quantidade ?? null,
        table_source: item?.table_source || window.cotacaoKanbanTableSource || 'solicitacao_compras'
      })).filter((item) => Number.isInteger(Number(item.id)))
    : [];
  window.cotacaoKanbanEdicaoId = id;

  atualizarEstadoFormularioCotacaoKanban();
  renderizarListaAnexosCotacaoKanban();
  renderizarListaLinksCotacaoKanban();
  renderizarItensSelecionadosCotacaoKanban();
  renderizarItensGrupoCotacaoKanban();

  const boxInfo = document.getElementById('cotacaoKanbanModoEdicaoInfo');
  if (boxInfo) {
    boxInfo.scrollIntoView({ behavior: 'smooth', block: 'center' });
  }
};

window.cancelarEdicaoCotacaoKanban = function() {
  window.cotacaoKanbanEdicaoId = null;
  const inputFornecedor = document.getElementById('cotacaoKanbanFornecedor');
  const inputValor = document.getElementById('cotacaoKanbanValor');
  const inputLink = document.getElementById('cotacaoKanbanLink');
  if (inputFornecedor) inputFornecedor.value = '';
  if (inputValor) inputValor.value = '';
  if (inputLink) inputLink.value = '';
  window.cotacaoKanbanAnexos = [];
  window.cotacaoKanbanLinks = [];
  window.cotacaoKanbanItensSelecionados = [];
  window.cotacaoKanbanMoeda = 'BRL';
  const btnMoeda = document.getElementById('btnMoedaCotacaoKanban');
  if (btnMoeda) btnMoeda.textContent = 'R$';

  atualizarEstadoFormularioCotacaoKanban();
  renderizarListaAnexosCotacaoKanban();
  renderizarListaLinksCotacaoKanban();
  renderizarItensSelecionadosCotacaoKanban();
  renderizarItensGrupoCotacaoKanban();
};

async function adicionarObservacaoCotacaoKanban(cotacaoId) {
  const textarea = document.getElementById(`obs-cotacao-${cotacaoId}`);
  const novoTexto = (textarea?.value || '').trim();
  if (!novoTexto) {
    alert('Digite uma observação.');
    return;
  }

  const user = (document.getElementById('userNameDisplay')?.textContent || '').trim();
  const agora = new Date().toLocaleString('pt-BR');
  const cotacaoAtual = window.cotacaoKanbanCotacoes.find(c => c.id === cotacaoId);
  const historicoAtual = (cotacaoAtual?.observacao || '').trim();
  const novaEntrada = `[${agora} - ${user || 'Usuário'}] ${novoTexto}`;
  const observacaoAtualizada = historicoAtual ? `${historicoAtual}\n${novaEntrada}` : novaEntrada;

  try {
    const resp = await fetch(`/api/compras/cotacoes/${cotacaoId}`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({ observacao: observacaoAtualizada })
    });
    if (!resp.ok) {
      const errData = await resp.json();
      throw new Error(errData.error || 'Erro ao atualizar observação');
    }
    await carregarCotacoesKanban();
  } catch (err) {
    console.error('[COTACAO KANBAN] Erro ao adicionar observação:', err);
    alert('Erro ao adicionar observação: ' + err.message);
  }
}

async function excluirCotacaoKanban(cotacaoId) {
  if (!confirm('Excluir esta cotação?')) return;
  try {
    const resp = await fetch(`/api/compras/cotacoes/${cotacaoId}`, {
      method: 'DELETE',
      credentials: 'include'
    });
    if (!resp.ok) {
      const errData = await resp.json();
      throw new Error(errData.error || 'Erro ao excluir cotação');
    }
    await carregarCotacoesKanban();
  } catch (err) {
    console.error('[COTACAO KANBAN] Erro ao excluir:', err);
    alert('Erro ao excluir cotação: ' + err.message);
  }
}

async function enviarCotacoesKanban() {
  if (!window.cotacaoKanbanItemId) return;
  try {
    // Objetivo: Mudar status para "cotado" de todos os itens do grupo na tabela correta
    const tableSource = window.cotacaoKanbanTableSource || window.cotacaoKanbanItem?.table_source || 'solicitacao_compras';
    const itensGrupo = Array.isArray(window.cotacaoKanbanItensGrupo) ? window.cotacaoKanbanItensGrupo : [];
    const idsGrupo = itensGrupo
      .map(item => Number(item?.id))
      .filter(id => Number.isInteger(id) && id > 0);

    const idsParaAtualizar = idsGrupo.length > 0
      ? Array.from(new Set(idsGrupo))
      : [Number(window.cotacaoKanbanItemId)].filter(id => Number.isInteger(id) && id > 0);

    if (idsParaAtualizar.length === 0) {
      throw new Error('Nenhum item válido encontrado para atualizar status.');
    }

    let totalAtualizados = 0;
    for (const itemId of idsParaAtualizar) {
      let endpoint = '';
      if (tableSource === 'compras_sem_cadastro') {
        endpoint = `/api/compras/sem-cadastro/${itemId}`;
      } else {
        endpoint = `/api/compras/solicitacoes/${itemId}`;
      }

      const resp = await fetch(endpoint, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({ status: 'cotado' })
      });

      if (!resp.ok) {
        const errData = await resp.json().catch(() => ({}));
        throw new Error(errData.error || `Erro ao atualizar status do item ${itemId}`);
      }

      totalAtualizados += 1;
    }

    alert(`Cotações enviadas com sucesso! ${totalAtualizados} item(ns) atualizado(s) para "cotado".`);
    fecharModalCotacaoKanban();
    if (typeof loadMinhasSolicitacoes === 'function') {
      loadMinhasSolicitacoes();
    }
  } catch (err) {
    console.error('[COTACAO KANBAN] Erro ao enviar:', err);
    alert('Erro ao enviar cotações: ' + err.message);
  }
}
async function renderizarCotacoesRegistradasCotadoEscolha() {
  const container = document.getElementById('listaCotacoesRegistradasCotadoEscolha');
  const totalCotacoesResumo = document.getElementById('totalCotacoesKanbanResumo');
  if (!container) return;

  const cotacoesRaw = Array.isArray(window.cotadoEscolhaCotacoesDb) ? window.cotadoEscolhaCotacoesDb : [];
  const cotacoes = cotacoesRaw.filter(c => c && typeof c === 'object');

  const possuiCotacaoUsd = cotacoes.some((cotacao) =>
    String(cotacao?.moeda || 'BRL').toUpperCase() === 'USD'
  );
  const taxaUsdBrl = possuiCotacaoUsd ? await obterTaxaUsdBrlCotacaoKanban() : null;
  const resumoTotalHtml = montarResumoTotalCotacoesKanban(
    cotacoes,
    taxaUsdBrl,
    (cotacao) => Number(cotacao?.valor_cotado || cotacao?.valor_unitario || 0) || 0
  );
  if (totalCotacoesResumo) {
    totalCotacoesResumo.innerHTML = `
      <i class="fa-solid fa-calculator"></i>
      <strong>Total das cotações:</strong>
      <span>${resumoTotalHtml}</span>
    `;
  }

  if (cotacoes.length === 0) {
    container.innerHTML = '<div style="text-align:center;padding:20px;color:#9ca3af;font-size:13px;">Nenhuma cotação registrada ainda</div>';
    return;
  }

  const item = window.cotadoEscolhaItem || {};
  const html = cotacoes.map((cotacao) => {
    const moedaCotacao = String(cotacao.moeda || 'BRL').toUpperCase() === 'USD' ? 'USD' : 'BRL';
    const valorCotacao = Number(cotacao.valor_cotado || cotacao.valor_unitario || 0) || 0;
    const valorCotacaoHtml = `${formatarValorCotacaoKanban(valorCotacao, moedaCotacao)}${formatarConversaoUsdParaBrlCotacaoKanban(valorCotacao, moedaCotacao, taxaUsdBrl)}`;
    const statusAprovacao = (cotacao.status_aprovacao || 'pendente').toString().toLowerCase();
    const aprovado = statusAprovacao === 'aprovado';
    const observacaoTexto = cotacao.observacao || '';
    let linksHtml = '';
    const linksArray = (() => {
      const bruto = cotacao.link;
      if (!bruto) return [];
      if (Array.isArray(bruto)) return bruto.map(v => String(v || '').trim()).filter(Boolean);
      if (typeof bruto === 'string') {
        const texto = bruto.trim();
        if (!texto) return [];
        try {
          const parsed = JSON.parse(texto);
          if (Array.isArray(parsed)) return parsed.map(v => String(v || '').trim()).filter(Boolean);
        } catch (err) {
          // mantém fluxo para string simples
        }
        return [texto];
      }
      return [];
    })();

    if (linksArray.length > 0) {
      linksHtml = `
        <div style="font-size:11px;color:#6b7280;margin-top:4px;">
          <strong><i class="fa-solid fa-link"></i> Links:</strong>
          <div style="margin-top:4px;padding-left:8px;display:flex;flex-direction:column;gap:4px;">
            ${linksArray.map((link, idx) => {
              const href = /^https?:\/\//i.test(link) ? link : `https://${link}`;
              let nome = `Link ${idx + 1}`;
              try {
                const semQuery = link.split('?')[0];
                nome = decodeURIComponent(semQuery.substring(semQuery.lastIndexOf('/') + 1)) || nome;
              } catch (err) {
                nome = link;
              }
              return `<a href="${escapeHtml(href)}" target="_blank" rel="noopener" style="color:#0284c7;text-decoration:underline;">• ${escapeHtml(nome)}</a>`;
            }).join('')}
          </div>
        </div>
      `;
    }

    let anexosHtml = '';
    if (cotacao.anexos) {
      let anexosArray = [];
      if (Array.isArray(cotacao.anexos)) {
        anexosArray = cotacao.anexos;
      } else if (typeof cotacao.anexos === 'string') {
        try {
          const parsed = JSON.parse(cotacao.anexos);
          anexosArray = Array.isArray(parsed) ? parsed : [];
        } catch (_e) {
          anexosArray = [];
        }
      }
      const listaAnexos = anexosArray.map(a => a?.nome).filter(a => a);
      if (listaAnexos.length > 0) {
        anexosHtml = `
          <div style="font-size:11px;color:#6b7280;margin-top:4px;">
            <strong><i class="fa-solid fa-paperclip"></i> Anexos:</strong>
            <div style="margin-top:4px;padding-left:8px;display:flex;flex-direction:column;gap:4px;">
                ${anexosArray.map((anexo, idx) => {
                  const nome = anexo?.nome || `Anexo ${idx + 1}`;
                  const url = anexo?.url || '';
                  const tipo = anexo?.tipo || 'application/octet-stream';
                  const base64 = anexo?.base64 || '';
                  const href = url || (base64 ? `data:${tipo};base64,${base64}` : '#');
                  return `
                    <a href="${href}" target="_blank" style="color:#0284c7;text-decoration:underline;">• ${escapeHtml(nome)}</a>
                  `;
                }).join('')}
            </div>
          </div>
        `;
      }
    }

    return `
      <div style="background:white;border:2px solid #10b981;border-radius:8px;padding:12px;display:grid;grid-template-columns:1fr auto;gap:12px;align-items:center;">
        <div>
          <div style="display:flex;align-items:center;gap:8px;margin-bottom:6px;">
            <i class="fa-solid fa-check-circle" style="color:#10b981;"></i>
            <span style="font-size:12px;font-weight:600;color:#1f2937;">${escapeHtml(item.produto_codigo || `Item ${cotacao.item_id}`)}</span>
            <span style="font-size:10px;padding:2px 6px;border-radius:10px;background:${aprovado ? '#dcfce7' : '#fef3c7'};color:${aprovado ? '#166534' : '#92400e'};font-weight:700;text-transform:uppercase;">
              ${escapeHtml(statusAprovacao)}
            </span>
          </div>
          <div style="font-size:11px;color:#6b7280;margin-bottom:4px;">
            <strong>Fornecedor:</strong> ${escapeHtml(cotacao.fornecedor_nome || cotacao.fornecedor || '-')}
          </div>
          <div style="font-size:11px;color:#6b7280;">
            <strong>Valor:</strong> ${valorCotacaoHtml}
          </div>
          <div style="font-size:11px;color:#6b7280;margin-top:4px;">
            <strong>Itens da cotação:</strong>
            <div style="margin-top:4px;padding-left:8px;display:flex;flex-direction:column;gap:3px;">
              ${(Array.isArray(cotacao.itens_cotacao) && cotacao.itens_cotacao.length > 0)
                ? cotacao.itens_cotacao.map((itemCotado) => {
                    const codigo = itemCotado?.produto_codigo || '-';
                    const descricao = itemCotado?.produto_descricao || '-';
                    const qtd = itemCotado?.quantidade ?? '-';
                    return `<span style="color:#374151;">• ${escapeHtml(String(codigo))} - ${escapeHtml(String(descricao))} (Qtd: ${escapeHtml(String(qtd))})</span>`;
                  }).join('')
                : '<span style="color:#9ca3af;">Sem itens vinculados</span>'
              }
            </div>
          </div>
          ${linksHtml}
          ${anexosHtml}

          <div style="margin-top:10px;background:#f9fafb;border:1px solid #e5e7eb;border-radius:6px;padding:10px;">
            <div style="font-size:11px;color:#6b7280;font-weight:600;margin-bottom:6px;">Observações</div>
            <div style="font-size:12px;color:#374151;white-space:pre-wrap;">${escapeHtml(observacaoTexto || 'Sem observações.')}</div>
          </div>

          <div style="margin-top:8px;">
            <textarea
              id="obs-cotado-${cotacao.id}"
              placeholder="Adicionar nova observação..."
              style="width:100%;min-height:60px;padding:8px;border:1px solid #d1d5db;border-radius:6px;font-size:12px;resize:vertical;"></textarea>
            <button
              onclick="adicionarObservacaoCotadoEscolha(${cotacao.id})"
              style="margin-top:6px;background:#3b82f6;color:white;border:none;padding:6px 10px;border-radius:6px;font-size:12px;font-weight:700;cursor:pointer;display:inline-flex;align-items:center;gap:6px;">
              <i class="fa-solid fa-plus"></i>
              Adicionar observação
            </button>
          </div>
        </div>
        <button 
          id="btn-aprovar-cotacao-${cotacao.id}"
          onclick="realizarRequisicaoCotadoEscolha(${cotacao.id})"
          title="${aprovado ? 'Requisição já realizada para esta cotação' : 'Realizar requisição desta cotação'}"
          ${aprovado ? 'disabled' : ''}
          style="background:${aprovado ? '#9ca3af' : '#10b981'};color:#ffffff;border:none;padding:8px 12px;border-radius:6px;cursor:${aprovado ? 'not-allowed' : 'pointer'};font-size:12px;font-weight:700;display:flex;align-items:center;gap:6px;opacity:${aprovado ? '0.9' : '1'};">
          <i class="fa-solid fa-check"></i>
          ${aprovado ? 'Requisição realizada' : 'Realizar requisição'}
        </button>
      </div>
    `;
  }).join('');

  container.innerHTML = html;
}

// Comentário: realiza requisição de uma cotação no modal "Cotado aguardando escolha"
async function realizarRequisicaoCotadoEscolha(cotacaoId) {
  if (!cotacaoId) return;
  const btn = document.getElementById(`btn-aprovar-cotacao-${cotacaoId}`);
  const originalHtml = btn ? btn.innerHTML : null;
  if (btn) {
    btn.disabled = true;
    btn.style.cursor = 'not-allowed';
    btn.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> Processando...';
  }
  try {
    const resp = await fetch(`/api/compras/cotacoes/${cotacaoId}/realizar-requisicao`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include'
    });
    if (!resp.ok) {
      const errData = await resp.json();
      throw new Error(errData.error || 'Erro ao realizar requisição');
    }

    const data = await resp.json();
    const novoGrupo = String(data?.novo_grupo_requisicao || '').trim();
    alert(`Requisição realizada com sucesso. Novo grupo do(s) item(ns): ${novoGrupo || '-'}.`);
    fecharModalCotadoEscolhaItem();
    if (typeof loadMinhasSolicitacoes === 'function') {
      loadMinhasSolicitacoes();
    }
  } catch (err) {
    console.error('[COTADO ESCOLHA] Erro ao realizar requisição da cotação:', err);
    alert('Erro ao realizar requisição: ' + err.message);
    if (btn && originalHtml) {
      btn.disabled = false;
      btn.style.cursor = 'pointer';
      btn.innerHTML = originalHtml;
    }
  }
}

async function adicionarObservacaoCotadoEscolha(cotacaoId) {
  const textarea = document.getElementById(`obs-cotado-${cotacaoId}`);
  const novoTexto = (textarea?.value || '').trim();
  if (!novoTexto) {
    alert('Digite uma observação.');
    return;
  }

  const user = (document.getElementById('userNameDisplay')?.textContent || '').trim();
  const agora = new Date().toLocaleString('pt-BR');
  const cotacaoAtual = window.cotadoEscolhaCotacoesDb.find(c => c.id === cotacaoId);
  const historicoAtual = (cotacaoAtual?.observacao || '').trim();
  const novaEntrada = `[${agora} - ${user || 'Usuário'}] ${novoTexto}`;
  const observacaoAtualizada = historicoAtual ? `${historicoAtual}\n${novaEntrada}` : novaEntrada;

  try {
    const resp = await fetch(`/api/compras/cotacoes/${cotacaoId}`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({ observacao: observacaoAtualizada })
    });
    if (!resp.ok) {
      const errData = await resp.json();
      throw new Error(errData.error || 'Erro ao atualizar observação');
    }

    const idx = window.cotadoEscolhaCotacoesDb.findIndex(c => c.id === cotacaoId);
    if (idx !== -1) {
      window.cotadoEscolhaCotacoesDb[idx].observacao = observacaoAtualizada;
    }
    await renderizarCotacoesRegistradasCotadoEscolha();
  } catch (err) {
    console.error('[COTADO ESCOLHA] Erro ao adicionar observação:', err);
    alert('Erro ao adicionar observação: ' + err.message);
  }
}

// Comentário: retifica item para aguardando cotação
async function retificarCotadoEscolha() {
  if (!window.cotadoEscolhaItemId) return;
  const tableSource = window.cotadoEscolhaTableSource || 'solicitacao_compras';
  try {
    let endpoint;
    if (tableSource === 'compras_sem_cadastro') {
      endpoint = `/api/compras/sem-cadastro/${window.cotadoEscolhaItemId}`;
    } else {
      endpoint = `/api/compras/solicitacoes/${window.cotadoEscolhaItemId}`;
    }
    
    const resp = await fetch(endpoint, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({ status: 'aguardando cotação' })
    });
    if (!resp.ok) {
      const errData = await resp.json();
      throw new Error(errData.error || 'Erro ao atualizar status');
    }
    alert('Status atualizado para "aguardando cotação".');
    fecharModalCotadoEscolhaItem();
    if (typeof loadMinhasSolicitacoes === 'function') {
      loadMinhasSolicitacoes();
    }
  } catch (err) {
    console.error('[COTADO ESCOLHA] Erro ao retificar:', err);
    alert('Erro ao retificar: ' + err.message);
  }
}

