function atualizarLayoutModeloCompraCatalogo() {
  const selectRetorno = document.getElementById('catalogoRetornoCotacoesGlobal');
  const gridConfig = document.getElementById('catalogoGridConfiguracoes');
  const coluna3 = document.getElementById('catalogoColuna3');
  const modalContent = document.getElementById('modalCatalogoOmieContent');
  if (!selectRetorno || !gridConfig || !coluna3 || !modalContent) return;

  const retornoTexto = String(selectRetorno.value || '').trim().toLowerCase();
  const ocultarColuna3 = retornoTexto === 'compra ja realizada' || retornoTexto === 'registro rapido de compra';

  coluna3.style.display = ocultarColuna3 ? 'none' : 'flex';
  gridConfig.style.gridTemplateColumns = ocultarColuna3 ? 'repeat(2, 1fr)' : 'repeat(3, 1fr)';
  modalContent.style.maxWidth = ocultarColuna3 ? '1400px' : '1800px';
}

function atualizarTooltipModeloCompraCatalogo() {
  const selectRetorno = document.getElementById('catalogoRetornoCotacoesGlobal');
  const tooltip = document.getElementById('catalogoRetornoModeloTooltip');
  if (!selectRetorno || !tooltip) return;

  const mensagensPorModelo = {
    '': 'Selecione um modelo para ver como a solicitação será tratada no fluxo de compras.',
    'Apenas realizar compra sem retorno de valores ou caracteristica': 'Compra direta sem retorno de cotação; o fluxo segue para análise/cadastro normalmente.',
    'Compra ja realizada': 'Use quando a compra já foi concluída; pode solicitar informações complementares como NFe.',
    'Compra com retorno de valores e caracteristica tecnica': 'Solicita retorno completo da cotação com valores e características técnicas no kanban.',
    'Registro rapido de compra': 'Registro rápido para compras que não seguem fluxo de kanban, apenas para registro.'
  };

  const valorAtual = String(selectRetorno.value || '');
  tooltip.textContent = mensagensPorModelo[valorAtual] || mensagensPorModelo[''];
  atualizarLayoutModeloCompraCatalogo();
}

function inicializarTooltipModeloCompraCatalogo() {
  const selectRetorno = document.getElementById('catalogoRetornoCotacoesGlobal');
  if (!selectRetorno) return;

  if (!selectRetorno.dataset.tooltipModeloBound) {
    selectRetorno.addEventListener('change', atualizarTooltipModeloCompraCatalogo);
    selectRetorno.dataset.tooltipModeloBound = '1';
  }

  atualizarTooltipModeloCompraCatalogo();
}

// Carrega responsáveis para inspeção no painel de compra
async function carregarResponsaveisCatalogoInspecao() {
  const select = document.getElementById('catalogoRespInspecaoRecebimento');
  if (!select) return;

  try {
    const resp = await fetch('/api/compras/usuarios', { credentials: 'include' });
    const data = await resp.json();
    if (data.ok && Array.isArray(data.usuarios)) {
      select.innerHTML = '<option value="">Selecione o responsável...</option>' +
        data.usuarios.map(u =>
          `<option value="${window.escapeHtml(u.username)}">${window.escapeHtml(u.username)}</option>`
        ).join('');
    }
  } catch (err) {
    console.error('[Catálogo] Erro ao carregar responsáveis:', err);
    select.innerHTML = '<option value="">Erro ao carregar</option>';
  }

  const currentUser = (document.getElementById('userNameDisplay')?.textContent || '').trim() || window.__sessionUser?.username || '';
  if (currentUser) {
    const option = Array.from(select.options).find(o => String(o.value || '').toLowerCase() === currentUser.toLowerCase());
    if (option) select.value = option.value;
  }
}

// Abre modal do catálogo Omie
async function abrirModalCatalogoOmie() {
  const modal = document.getElementById('modalCatalogoOmie');
  if (!modal) return;

  inicializarTooltipModeloCompraCatalogo();
  
  const lista = document.getElementById('listaProdutosCatalogo');
  if (lista) {
    lista.innerHTML = '';
  }
  
  modal.style.display = 'flex';
  
  // Inicializa contador de carrinho
  atualizarContadorCatalogo();
  
  // Atualiza opções de NP baseado no carrinho
  await carregarGruposRequisicaoDisponiveis();
  atualizarOpcoesNP();
  
  // Define valor padrão como "Não"
  const selectCadastro = document.getElementById('catalogoPossuiCadastroOmie');
  if (selectCadastro) {
    selectCadastro.value = 'nao';
  }
  
  // Garante que campo descrição está visível
  const campoDescricao = document.getElementById('catalogoCampoDescricao');
  if (campoDescricao) {
    campoDescricao.style.display = 'block';
  }
  
  // Garante que campo quantidade está visível (padrão "Não")
  const campoQuantidade = document.getElementById('catalogoCampoQuantidade');
  if (campoQuantidade) {
    campoQuantidade.style.display = 'block';
  }
  
  // Garante que botão adicionar está visível (padrão "Não")
  const botaoAdicionar = document.getElementById('catalogoBotaoAdicionarNaoCadastrado');
  if (botaoAdicionar) {
    botaoAdicionar.style.display = 'block';
  }
  
  // Define valor padrão de Etapas do Pedido
  const selectEtapas = document.getElementById('catalogoEtapasPedido');
  if (selectEtapas) {
    selectEtapas.value = 'aguardando aprovação da requisição';
  }
  
  // Oculta seção de filtros inicialmente (só aparece quando Sim)
  const secaoFiltros = document.getElementById('catalogoSecaoFiltros');
  if (secaoFiltros) {
    secaoFiltros.style.display = 'none';
  }
  
  try {
    // Carrega departamentos e categorias de compra
    await Promise.all([
      carregarDepartamentosCatalogo(),
      loadModalComprasCategoriasCompra(),
      carregarResponsaveisCatalogoInspecao()
    ]);
    
    // Define "Produção" como padrão após carregar departamentos
    const selectDept = document.getElementById('catalogoDepartamentoGlobal');
    if (selectDept) {
      const opcaoProd = Array.from(selectDept.options).find(o => 
        (o.value || '').toLowerCase() === 'produção' || (o.value || '').toLowerCase() === 'producao'
      );
      if (opcaoProd) {
        selectDept.value = opcaoProd.value;
        // Dispara evento change para carregar categorias
        selectDept.dispatchEvent(new Event('change'));
      }
    }
    
    console.log('[Catálogo] Modal aberto. Produtos não carregados (aguardando seleção Sim).');
    
  } catch (err) {
    console.error('[CATÁLOGO OMIE] Erro:', err);
    if (lista) {
      lista.innerHTML = '<div style="text-align:center;padding:40px;color:#ef4444;">Erro ao carregar configurações</div>';
    }
  }
  
  // Adiciona event listeners para validar interação entre Requisição Direta e Não incluir quantidade
  inicializarValidacaoCatalogoCheckboxes();
  
  // Inicializa sistema de keywords/tags para descrição
  inicializarDescricaoKeywords();
}

// ========== FUNÇÕES PARA GERENCIAR KEYWORDS/TAGS DE DESCRIÇÃO ==========
// Objetivo: Permitir adicionar palavras-chave ao pressionar Enter e remover ao clicar no X

function abrirDialogoEntradaCatalogo({ titulo, label, placeholder = '', valorInicial = '', tipo = 'text' }) {
  return new Promise((resolve) => {
    const overlay = document.createElement('div');
    overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.45);z-index:100100;display:flex;align-items:center;justify-content:center;padding:16px;';

    const modal = document.createElement('div');
    modal.style.cssText = 'width:100%;max-width:420px;background:#ffffff;border-radius:10px;box-shadow:0 18px 40px rgba(0,0,0,0.28);padding:16px;display:flex;flex-direction:column;gap:10px;';

    const h = document.createElement('div');
    h.textContent = titulo || 'Informação necessária';
    h.style.cssText = 'font-size:15px;font-weight:700;color:#0f172a;';

    const l = document.createElement('label');
    l.textContent = label || 'Digite o valor';
    l.style.cssText = 'font-size:12px;font-weight:600;color:#334155;';

    const input = document.createElement('input');
    input.type = tipo;
    input.placeholder = placeholder;
    input.value = valorInicial;
    input.style.cssText = 'width:100%;padding:10px;border:2px solid #3b82f6;border-radius:8px;font-size:14px;font-weight:600;color:#0f172a;';

    const footer = document.createElement('div');
    footer.style.cssText = 'display:flex;justify-content:flex-end;gap:8px;margin-top:4px;';

    const btnCancelar = document.createElement('button');
    btnCancelar.type = 'button';
    btnCancelar.textContent = 'Cancelar';
    btnCancelar.style.cssText = 'padding:8px 12px;border:1px solid #cbd5e1;background:#ffffff;color:#334155;border-radius:8px;cursor:pointer;font-weight:600;';

    const btnConfirmar = document.createElement('button');
    btnConfirmar.type = 'button';
    btnConfirmar.textContent = 'Confirmar';
    btnConfirmar.style.cssText = 'padding:8px 12px;border:none;background:#2563eb;color:#ffffff;border-radius:8px;cursor:pointer;font-weight:700;';

    const finalizar = (valor) => {
      document.removeEventListener('keydown', onKeydown);
      overlay.remove();
      resolve(valor);
    };

    const onKeydown = (event) => {
      if (event.key === 'Escape') {
        event.preventDefault();
        finalizar(null);
      }
      if (event.key === 'Enter') {
        event.preventDefault();
        finalizar(String(input.value || '').trim());
      }
    };

    btnCancelar.addEventListener('click', () => finalizar(null));
    btnConfirmar.addEventListener('click', () => finalizar(String(input.value || '').trim()));
    overlay.addEventListener('click', (event) => {
      if (event.target === overlay) finalizar(null);
    });
    document.addEventListener('keydown', onKeydown);

    footer.appendChild(btnCancelar);
    footer.appendChild(btnConfirmar);

    modal.appendChild(h);
    modal.appendChild(l);
    modal.appendChild(input);
    modal.appendChild(footer);
    overlay.appendChild(modal);
    document.body.appendChild(overlay);

    setTimeout(() => {
      input.focus();
      input.select();
    }, 0);
  });
}

function atualizarDescricaoKeywordsHidden() {
  const tagsContainer = document.getElementById('catalogoDescricaoTags');
  const hidden = document.getElementById('catalogoDescricaoKeywords');
  if (!tagsContainer || !hidden) return '';
  // Comentário: hidden guarda apenas as descrições separadas por ; (quantidade fica no data-quantidade do DOM)
  const keywords = Array.from(tagsContainer.querySelectorAll('[data-keyword]'))
    .map(tag => (tag.getAttribute('data-keyword') || '').trim())
    .filter(Boolean);
  hidden.value = keywords.join(';');
  return hidden.value;
}

// Retorna array de {descricao, quantidade} lendo direto do DOM
function obterItensSemCadastroDoDom() {
  const tagsContainer = document.getElementById('catalogoDescricaoTags');
  if (!tagsContainer) return [];
  return Array.from(tagsContainer.querySelectorAll('[data-keyword]'))
    .map(row => ({
      descricao: (row.getAttribute('data-keyword') || '').trim(),
      quantidade: parseInt(row.getAttribute('data-quantidade'), 10) || 1
    }))
    .filter(it => it.descricao);
}

async function adicionarDescricaoKeyword(valor, quantidadeParam) {
  const input = document.getElementById('catalogoDescricaoNaoCadastrado');
  const inputQtd = document.getElementById('catalogoDescricaoQtd');
  const tagsContainer = document.getElementById('catalogoDescricaoTags');
  const hidden = document.getElementById('catalogoDescricaoKeywords');
  if (!input || !tagsContainer || !hidden) return;

  const refocarCampoDescricao = () => {
    setTimeout(() => {
      input.focus();
    }, 0);
  };

  const keyword = String(valor || '').trim();
  if (!keyword) {
    refocarCampoDescricao();
    return;
  }

  const existente = Array.from(tagsContainer.querySelectorAll('[data-keyword]'))
    .some(tag => (tag.getAttribute('data-keyword') || '').toLowerCase() === keyword.toLowerCase());
  if (existente) {
    input.value = '';
    refocarCampoDescricao();
    return;
  }

  const quantidade = parseInt(quantidadeParam, 10);
  if (!Number.isFinite(quantidade) || quantidade < 1) {
    alert('Quantidade inválida. Deve ser um número maior que zero.');
    if (inputQtd) inputQtd.focus();
    return;
  }

  // Cria uma LINHA visual (row) com descrição preenchida, quantidade e botão de remover
  const row = document.createElement('div');
  row.setAttribute('data-keyword', keyword);
  row.setAttribute('data-quantidade', String(quantidade));
  row.style.display = 'flex';
  row.style.gap = '6px';
  row.style.alignItems = 'center';

  const inputDesc = document.createElement('input');
  inputDesc.type = 'text';
  inputDesc.value = keyword;
  inputDesc.readOnly = true;
  inputDesc.style.cssText = 'flex:1;padding:8px 10px;border:1px solid #bfdbfe;border-radius:6px;font-size:13px;background:#eff6ff;font-weight:500;color:#1e40af;cursor:default;';

  const inputQtdRow = document.createElement('input');
  inputQtdRow.type = 'number';
  inputQtdRow.value = String(quantidade);
  inputQtdRow.min = '1';
  inputQtdRow.readOnly = true;
  inputQtdRow.style.cssText = 'width:80px;padding:8px 10px;border:1px solid #bfdbfe;border-radius:6px;font-size:13px;background:#eff6ff;font-weight:600;text-align:center;color:#1e40af;cursor:default;';

  const btnRemover = document.createElement('button');
  btnRemover.type = 'button';
  btnRemover.title = 'Remover item';
  btnRemover.innerHTML = '<i class="fa-solid fa-trash-can"></i>';
  btnRemover.style.cssText = 'width:36px;height:36px;border:none;background:#fee2e2;color:#dc2626;border-radius:6px;font-size:14px;cursor:pointer;display:flex;align-items:center;justify-content:center;flex-shrink:0;';

  row.appendChild(inputDesc);
  row.appendChild(inputQtdRow);
  row.appendChild(btnRemover);
  tagsContainer.appendChild(row);

  input.value = '';
  if (inputQtd) inputQtd.value = '1';
  atualizarDescricaoKeywordsHidden();
  refocarCampoDescricao();
}

function limparDescricaoKeywords() {
  const tagsContainer = document.getElementById('catalogoDescricaoTags');
  const hidden = document.getElementById('catalogoDescricaoKeywords');
  const input = document.getElementById('catalogoDescricaoNaoCadastrado');
  const inputQtd = document.getElementById('catalogoDescricaoQtd');
  if (tagsContainer) tagsContainer.innerHTML = '';
  if (hidden) hidden.value = '';
  if (input) input.value = '';
  if (inputQtd) inputQtd.value = '1';
}

function inicializarDescricaoKeywords() {
  const input = document.getElementById('catalogoDescricaoNaoCadastrado');
  const inputQtd = document.getElementById('catalogoDescricaoQtd');
  const addBtn = document.getElementById('catalogoDescricaoAddBtn');
  const tagsContainer = document.getElementById('catalogoDescricaoTags');
  if (!input || !tagsContainer || input.dataset.keywordsInit === '1') return;

  input.dataset.keywordsInit = '1';

  function adicionarItemAtual() {
    const qtd = inputQtd ? parseInt(inputQtd.value, 10) || 1 : 1;
    void adicionarDescricaoKeyword(input.value, qtd);
  }

  // Enter no campo de descrição adiciona o item
  input.addEventListener('keydown', (event) => {
    if (event.key !== 'Enter') return;
    event.preventDefault();
    adicionarItemAtual();
  });

  // Enter no campo de quantidade também adiciona
  if (inputQtd) {
    inputQtd.addEventListener('keydown', (event) => {
      if (event.key !== 'Enter') return;
      event.preventDefault();
      adicionarItemAtual();
    });
  }

  // Botão "+" adiciona o item
  if (addBtn) {
    addBtn.addEventListener('click', () => {
      adicionarItemAtual();
    });
  }

  tagsContainer.addEventListener('click', (event) => {
    const target = event.target;
    if (!(target instanceof HTMLElement)) return;
    const btn = target.closest('button');
    if (!btn) return;
    const row = btn.closest('[data-keyword]');
    if (row) {
      row.remove();
      atualizarDescricaoKeywordsHidden();
    }
  });

  if (!window.__catalogoDescricaoEnterDelegado) {
    window.__catalogoDescricaoEnterDelegado = true;
    document.addEventListener('keydown', async (event) => {
      const target = event.target;
      if (!(target instanceof HTMLInputElement)) return;
      if (target.id !== 'catalogoDescricaoNaoCadastrado' && target.id !== 'catalogoDescricaoQtd') return;
      if (event.key !== 'Enter') return;
      if (event.isComposing) return;

      event.preventDefault();
      event.stopPropagation();

      if (input.dataset.keywordDialogOpen === '1') return;
      input.dataset.keywordDialogOpen = '1';
      try {
        const qtd = inputQtd ? parseInt(inputQtd.value, 10) || 1 : 1;
        await adicionarDescricaoKeyword(input.value, qtd);
      } finally {
        input.dataset.keywordDialogOpen = '0';
      }
    }, true);
  }
}

