// Carrega produtos do catálogo Omie (chamada quando usuário seleciona "Sim")
async function carregarProdutosCatalogoOmie() {
  const lista = document.getElementById('listaProdutosCatalogo');
  if (!lista) return;
  
  lista.innerHTML = '<div style="text-align:center;padding:40px;"><i class="fa-solid fa-spinner fa-spin" style="font-size:32px;color:#3b82f6;"></i><br><br>Carregando catálogo...</div>';
  
  try {
    const respProdutos = await fetch('/api/compras/catalogo-omie', { credentials: 'include' });
    
    if (!respProdutos.ok) throw new Error('Erro ao carregar catálogo');
    
    const data = await respProdutos.json();
    window.produtosCatalogoOmie = data.produtos || [];
    
    // Popula select de famílias
    const selectFamilia = document.getElementById('catalogoFamilia');
    if (selectFamilia) {
      const familias = [...new Set(window.produtosCatalogoOmie.map(p => p.descricao_familia).filter(f => f))].sort();
      selectFamilia.innerHTML = '<option value="">Todas as Famílias</option>' + 
        familias.map(f => `<option value="${escapeHtml(f)}">${escapeHtml(f)}</option>`).join('');
    }
    
    // Renderiza produtos
    renderizarCatalogoOmie(window.produtosCatalogoOmie);
    
    console.log('[Catálogo] Produtos carregados:', window.produtosCatalogoOmie.length);
    
  } catch (err) {
    console.error('[Catálogo] Erro ao carregar produtos:', err);
    lista.innerHTML = '<div style="text-align:center;padding:40px;color:#ef4444;">Erro ao carregar catálogo de produtos</div>';
  }
}

// Gerencia mudança de anexo no catálogo (acumula múltiplos arquivos)
function handleCatalogoAnexoChange(input) {
  if (!input || !input.files || input.files.length === 0) return;
  
  const preview = document.getElementById('catalogoAnexoPreview');
  const label = document.getElementById('catalogoAnexoLabel');
  
  if (!preview || !label) return;
  
  // Inicializa array se não existir
  if (!window.catalogoAnexosAcumulados) {
    window.catalogoAnexosAcumulados = [];
  }
  
  // Valida e ACUMULA cada arquivo novo
  let novosAdicionados = 0;
  for (let i = 0; i < input.files.length; i++) {
    const file = input.files[i];
    
    // Valida tamanho (máximo 5MB por arquivo)
    if (file.size > 5 * 1024 * 1024) {
      alert(`Arquivo "${file.name}" muito grande! Tamanho máximo: 5MB por arquivo.`);
      continue;
    }
    
    // Verifica se arquivo já existe na lista (por nome e tamanho)
    const jaExiste = window.catalogoAnexosAcumulados.some(
      f => f.name === file.name && f.size === file.size
    );
    
    if (jaExiste) {
      console.log(`[Catálogo] Arquivo "${file.name}" já está na lista, ignorando...`);
      continue;
    }
    
    // ACUMULA o arquivo
    window.catalogoAnexosAcumulados.push(file);
    novosAdicionados++;
  }
  
  // Limpa o input (para permitir selecionar o mesmo arquivo novamente se necessário)
  input.value = '';
  
  if (novosAdicionados === 0 && window.catalogoAnexosAcumulados.length === 0) {
    return;
  }
  
  // Monta HTML da lista de arquivos ACUMULADOS
  const listaHTML = window.catalogoAnexosAcumulados.map((file, index) => {
    // Define ícone baseado no tipo
    let iconClass = 'fa-file';
    let iconColor = '#10b981';
    if (file.type.startsWith('image/')) {
      iconClass = 'fa-file-image';
      iconColor = '#3b82f6';
    } else if (file.type === 'application/pdf') {
      iconClass = 'fa-file-pdf';
      iconColor = '#ef4444';
    } else if (file.type.includes('excel') || file.type.includes('spreadsheet')) {
      iconClass = 'fa-file-excel';
      iconColor = '#10b981';
    }
    
    const tamanhoMB = (file.size / 1024 / 1024).toFixed(2);
    
    return `
      <div style="display:flex;align-items:center;justify-content:space-between;padding:8px;background:white;border:2px solid ${iconColor};border-radius:6px;margin-bottom:6px;">
        <div style="display:flex;align-items:center;gap:8px;flex:1;">
          <i class="fa-solid ${iconClass}" style="color:${iconColor};font-size:16px;"></i>
          <div style="flex:1;">
            <div style="font-size:12px;font-weight:600;color:#065f46;">${escapeHtml(file.name)}</div>
            <div style="font-size:10px;color:#6b7280;">${tamanhoMB} MB</div>
          </div>
        </div>
        <button 
          type="button"
          onclick="removerCatalogoAnexoIndividual(${index})"
          style="background:#ef4444;color:white;border:none;padding:4px 8px;border-radius:4px;cursor:pointer;font-size:11px;">
          <i class="fa-solid fa-trash"></i>
        </button>
      </div>
    `;
  }).join('');
  
  preview.innerHTML = listaHTML + `
    <button 
      type="button"
      onclick="removerCatalogoAnexo()"
      style="width:100%;padding:8px;background:#ef4444;color:white;border:none;border-radius:6px;cursor:pointer;font-size:12px;font-weight:600;margin-top:4px;">
      <i class="fa-solid fa-trash"></i> Remover Todos
    </button>
  `;
  
  preview.style.display = 'block';
  label.textContent = `${window.catalogoAnexosAcumulados.length} arquivo(s) selecionado(s)`;
  
  if (novosAdicionados > 0) {
    console.log(`[Catálogo] ${novosAdicionados} novo(s) arquivo(s) adicionado(s). Total: ${window.catalogoAnexosAcumulados.length}`);
  }
}

// Gerencia links no catálogo (cache em memória e renderização)
function handleCatalogoLinkKeydown(event) {
  if (event.key !== 'Enter') return;
  event.preventDefault();

  const input = event.target;
  if (!input) return;

  const valor = String(input.value || '').trim();
  if (!valor) return;

  if (!window.catalogoLinksAcumulados) {
    window.catalogoLinksAcumulados = [];
  }

  // Evita duplicidade
  if (window.catalogoLinksAcumulados.includes(valor)) {
    input.value = '';
    return;
  }

  window.catalogoLinksAcumulados.push(valor);
  input.value = '';
  renderizarCatalogoLinks();
}

function removerCatalogoLink(index) {
  if (!window.catalogoLinksAcumulados || index < 0 || index >= window.catalogoLinksAcumulados.length) return;
  window.catalogoLinksAcumulados.splice(index, 1);
  renderizarCatalogoLinks();
}

function renderizarCatalogoLinks() {
  const preview = document.getElementById('catalogoLinkPreview');
  if (!preview) return;

  const links = window.catalogoLinksAcumulados || [];
  if (links.length === 0) {
    preview.style.display = 'none';
    preview.innerHTML = '';
    return;
  }

  const listaHTML = links.map((link, index) => {
    const linkSeguro = escapeHtml(link);
    return `
      <div style="display:flex;align-items:center;justify-content:space-between;padding:8px;background:white;border:2px solid #3b82f6;border-radius:6px;margin-bottom:6px;">
        <div style="display:flex;align-items:center;gap:8px;flex:1;min-width:0;">
          <i class="fa-solid fa-link" style="color:#3b82f6;font-size:16px;"></i>
          <div style="flex:1;min-width:0;">
            <div style="font-size:12px;font-weight:600;color:#1e3a8a;word-break:break-all;">${linkSeguro}</div>
          </div>
        </div>
        <button 
          type="button"
          onclick="removerCatalogoLink(${index})"
          style="background:#ef4444;color:white;border:none;padding:4px 8px;border-radius:4px;cursor:pointer;font-size:11px;">
          <i class="fa-solid fa-trash"></i>
        </button>
      </div>
    `;
  }).join('');

  preview.innerHTML = listaHTML;
  preview.style.display = 'block';
}

// Remove todos os anexos do catálogo
function removerCatalogoAnexo() {
  const input = document.getElementById('catalogoAnexo');
  const preview = document.getElementById('catalogoAnexoPreview');
  const label = document.getElementById('catalogoAnexoLabel');
  
  // Limpa array acumulado
  window.catalogoAnexosAcumulados = [];
  
  if (input) input.value = '';
  if (preview) {
    preview.style.display = 'none';
    preview.innerHTML = '';
  }
  if (label) label.textContent = 'Clique para selecionar arquivos';
  
  console.log('[Catálogo] Todos os anexos removidos');
}

// Remove anexo individual do catálogo (do array acumulado)
function removerCatalogoAnexoIndividual(index) {
  if (!window.catalogoAnexosAcumulados || index < 0 || index >= window.catalogoAnexosAcumulados.length) {
    return;
  }
  
  const arquivoRemovido = window.catalogoAnexosAcumulados[index].name;
  
  // Remove do array
  window.catalogoAnexosAcumulados.splice(index, 1);
  
  console.log(`[Catálogo] Anexo "${arquivoRemovido}" removido. Restam: ${window.catalogoAnexosAcumulados.length}`);
  
  // Atualiza preview
  if (window.catalogoAnexosAcumulados.length > 0) {
    // Re-renderiza a lista
    const input = document.getElementById('catalogoAnexo');
    if (input) {
      // Força atualização do preview sem adicionar novos arquivos
      const preview = document.getElementById('catalogoAnexoPreview');
      const label = document.getElementById('catalogoAnexoLabel');
      
      if (preview && label) {
        const listaHTML = window.catalogoAnexosAcumulados.map((file, idx) => {
          let iconClass = 'fa-file';
          let iconColor = '#10b981';
          if (file.type.startsWith('image/')) {
            iconClass = 'fa-file-image';
            iconColor = '#3b82f6';
          } else if (file.type === 'application/pdf') {
            iconClass = 'fa-file-pdf';
            iconColor = '#ef4444';
          } else if (file.type.includes('excel') || file.type.includes('spreadsheet')) {
            iconClass = 'fa-file-excel';
            iconColor = '#10b981';
          }
          
          const tamanhoMB = (file.size / 1024 / 1024).toFixed(2);
          
          return `
            <div style="display:flex;align-items:center;justify-content:space-between;padding:8px;background:white;border:2px solid ${iconColor};border-radius:6px;margin-bottom:6px;">
              <div style="display:flex;align-items:center;gap:8px;flex:1;">
                <i class="fa-solid ${iconClass}" style="color:${iconColor};font-size:16px;"></i>
                <div style="flex:1;">
                  <div style="font-size:12px;font-weight:600;color:#065f46;">${escapeHtml(file.name)}</div>
                  <div style="font-size:10px;color:#6b7280;">${tamanhoMB} MB</div>
                </div>
              </div>
              <button 
                type="button"
                onclick="removerCatalogoAnexoIndividual(${idx})"
                style="background:#ef4444;color:white;border:none;padding:4px 8px;border-radius:4px;cursor:pointer;font-size:11px;">
                <i class="fa-solid fa-trash"></i>
              </button>
            </div>
          `;
        }).join('');
        
        preview.innerHTML = listaHTML + `
          <button 
            type="button"
            onclick="removerCatalogoAnexo()"
            style="width:100%;padding:8px;background:#ef4444;color:white;border:none;border-radius:6px;cursor:pointer;font-size:12px;font-weight:600;margin-top:4px;">
            <i class="fa-solid fa-trash"></i> Remover Todos
          </button>
        `;
        
        label.textContent = `${window.catalogoAnexosAcumulados.length} arquivo(s) selecionado(s)`;
      }
    }
  } else {
    removerCatalogoAnexo();
  }
}

// Função para validar interação entre Requisição Direta e Não incluir quantidade
function inicializarValidacaoCatalogoCheckboxes() {
  const checkboxRequisicaoDireta = document.getElementById('catalogoRequisicaoDiretaGlobal');
  const checkboxNaoIncluirQuantidade = document.getElementById('catalogoNaoIncluirQuantidade');
  const labelNaoIncluirQuantidade = document.getElementById('labelNaoIncluirQuantidade');
  
  if (!checkboxRequisicaoDireta || !checkboxNaoIncluirQuantidade) return;
  
  // Event listener para Requisição Direta
  checkboxRequisicaoDireta.addEventListener('change', function() {
    if (this.checked) {
      // Se marcar Requisição Direta, desabilita e desmarca Não incluir quantidade
      checkboxNaoIncluirQuantidade.disabled = true;
      checkboxNaoIncluirQuantidade.checked = false;
      labelNaoIncluirQuantidade.style.opacity = '0.5';
      labelNaoIncluirQuantidade.style.cursor = 'not-allowed';
      labelNaoIncluirQuantidade.style.pointerEvents = 'none';
      console.log('[Catálogo] Requisição Direta ativada - Não incluir quantidade desabilitada');
    } else {
      // Se desmarcar Requisição Direta, habilita Não incluir quantidade
      checkboxNaoIncluirQuantidade.disabled = false;
      labelNaoIncluirQuantidade.style.opacity = '1';
      labelNaoIncluirQuantidade.style.cursor = 'pointer';
      labelNaoIncluirQuantidade.style.pointerEvents = 'auto';
      console.log('[Catálogo] Requisição Direta desativada - Não incluir quantidade habilitada');
    }
  });
  
  // Inicializa estado inicial baseado em Requisição Direta
  if (checkboxRequisicaoDireta.checked) {
    checkboxNaoIncluirQuantidade.disabled = true;
    checkboxNaoIncluirQuantidade.checked = false;
    labelNaoIncluirQuantidade.style.opacity = '0.5';
    labelNaoIncluirQuantidade.style.cursor = 'not-allowed';
    labelNaoIncluirQuantidade.style.pointerEvents = 'none';
  }
}

// Renderiza produtos do catálogo
function renderizarCatalogoOmie(produtos, options = {}) {
  const {
    containerId = 'listaProdutosCatalogo',
    atualizarContador = true,
    append = false
  } = options;

  const lista = document.getElementById(containerId);
  if (!lista) return;
  
  // Atualiza contador de produtos exibidos (apenas no modal)
  if (atualizarContador) {
    const contadorProdutos = document.getElementById('catalogoTotalProdutos');
    if (contadorProdutos) {
      contadorProdutos.textContent = produtos.length;
    }
  }
  
  if (produtos.length === 0) {
    if (!append) {
      lista.innerHTML = '<div style="text-align:center;padding:40px;color:#9ca3af;grid-column:1/-1;">Nenhum produto encontrado</div>';
    }
    return;
  }
  
  const html = produtos.map(produto => {
    // Valida se a URL da imagem é válida
    const temImagem = produto.url_imagem && 
                      produto.url_imagem.trim() && 
                      (produto.url_imagem.startsWith('http://') || produto.url_imagem.startsWith('https://'));
    
    // Verifica se URL está expirada (parâmetro Expires)
    let urlExpirada = false;
    if (temImagem && produto.url_imagem.includes('Expires=')) {
      const match = produto.url_imagem.match(/Expires=(\d+)/);
      if (match) {
        const expiresTimestamp = parseInt(match[1]);
        const agora = Math.floor(Date.now() / 1000);
        urlExpirada = expiresTimestamp < agora;
      }
    }
    
    // Prepara string para onclick ANTES de stringify
    const infoProdutoTexto = `${produto.codigo} - ${produto.descricao || ''}`;
    
    const imgHtml = temImagem && !urlExpirada ? 
      `<img 
        src="${produto.url_imagem}" 
        alt="${escapeHtml(produto.descricao)}"
        style="max-width:100%;max-height:100%;object-fit:contain;cursor:zoom-in;transition:transform 0.2s;"
        onclick='ampliarImagemProduto(${JSON.stringify(produto.url_imagem || '')}, ${JSON.stringify(infoProdutoTexto)}, ${JSON.stringify(produto.codigo || '')});event.stopPropagation();'
        onmouseover="this.style.transform='scale(1.05)'"
        onmouseout="this.style.transform='scale(1)'"
        onerror="this.style.display='none';this.nextElementSibling.style.display='flex'"
      />
      <div style="display:none;width:100%;height:100%;align-items:center;justify-content:center;color:#9ca3af;">
        <i class="fa-solid fa-image" style="font-size:48px;"></i>
      </div>` :
      urlExpirada ? 
      `<div 
        id="img-expirada-${produto.codigo_produto}" 
        data-codigo-produto="${produto.codigo_produto}"
        data-codigo="${escapeHtml(produto.codigo)}"
        data-descricao="${escapeHtml(produto.descricao)}"
        style="display:flex;width:100%;height:100%;align-items:center;justify-content:center;color:#f59e0b;flex-direction:column;gap:8px;" 
        title="Atualizando imagem...">
        <i class="fa-solid fa-rotate fa-spin" style="font-size:32px;"></i>
        <span style="font-size:10px;text-align:center;">Atualizando...</span>
      </div>` :
      `<div style="display:flex;width:100%;height:100%;align-items:center;justify-content:center;color:#9ca3af;">
        <i class="fa-solid fa-image" style="font-size:48px;"></i>
      </div>`;
    
    return `
      <div class="produto-catalogo-card" data-product-code="${escapeHtml(produto.codigo)}" style="
        background:white;
        border:1px solid #e5e7eb;
        border-radius:8px;
        overflow:hidden;
        transition:all 0.2s;
        cursor:default;
        display:flex;
        flex-direction:column;
      " 
      onmouseover="this.style.boxShadow='0 4px 12px rgba(0,0,0,0.1)';this.style.transform='translateY(-2px)'"
      onmouseout="this.style.boxShadow='none';this.style.transform='translateY(0)'">
        
        <!-- Imagem -->
        <div style="
          width:100%;
          height:140px;
          background:#f9fafb;
          display:flex;
          align-items:center;
          justify-content:center;
          overflow:hidden;
          position:relative;
          border-bottom:1px solid #111827;
          box-shadow:inset 0 0 0 1px #111827;
        ">
          ${imgHtml}
        </div>
        
        <!-- Informações -->
        <div style="padding:10px;flex:1;display:flex;flex-direction:column;">
          <div style="font-size:12px;font-weight:700;color:#1f2937;margin-bottom:3px;">
            ${escapeHtml(produto.codigo)}
          </div>
          <div class="produto-card-descricao" style="font-size:10px;font-weight:400;color:#4b5563;margin-bottom:6px;line-height:1.3;min-height:32px;">
            ${escapeHtml(produto.descricao)}
          </div>
          <div id="estoque-card-${escapeHtml(produto.codigo)}" data-codigo="${escapeHtml(produto.codigo)}" style="margin-bottom:6px;min-height:14px;"></div>
          
          <!-- Badges: Família e Estoque -->
          <div style="display:flex;flex-wrap:wrap;gap:4px;margin-bottom:8px;">
            <span id="min-badge-${escapeHtml(produto.codigo)}" data-codigo="${escapeHtml(produto.codigo)}"></span>
            <span id="compra-badge-${escapeHtml(produto.codigo)}" data-codigo="${escapeHtml(produto.codigo)}"></span>
            ${produto.abaixo_minimo ? `
            <span style="background:#fef3c7;color:#92400e;padding:3px 6px;border-radius:4px;font-size:9px;font-weight:600;display:flex;align-items:center;gap:3px;" title="Estoque: ${produto.saldo_estoque} | Mínimo: ${produto.estoque_minimo}">
              <i class="fa-solid fa-triangle-exclamation" style="font-size:8px;"></i>
              Est. ${Math.round(produto.saldo_estoque)}/${Math.round(produto.estoque_minimo)}
            </span>
            ` : ''}
          </div>
          
          <!-- Botão Ações -->
          <div style="margin-top:auto;display:flex;gap:6px;align-items:stretch;">
            <button 
              onclick="event.stopPropagation();abrirModalAcoesProduto('${produto.codigo}', '${produto.codigo_produto}', '${escapeHtml(produto.descricao.replace(/'/g, "\\'"))}', '${escapeHtml((produto.unidade || 'UN').replace(/'/g, "\\'"))}')"
              title="Ações do produto"
              style="
                flex:1;
                background:linear-gradient(135deg,#3b82f6 0%,#2563eb 100%);
                color:white;
                border:none;
                padding:8px;
                border-radius:6px;
                cursor:pointer;
                font-size:13px;
                font-weight:600;
                display:flex;
                align-items:center;
                justify-content:center;
                gap:6px;
              "
              onmouseover="this.style.transform='scale(1.02)'"
              onmouseout="this.style.transform='scale(1)'">
              <i class="fa-solid fa-ellipsis"></i> Ações
            </button>
          </div>
        </div>
      </div>
    `;
  }).join('');

  if (append) {
    lista.insertAdjacentHTML('beforeend', html);
  } else {
    lista.innerHTML = html;
  }

  // A busca recria os cards; restaura os dados já carregados sem aguardar nova rede.
  aplicarCacheEstoqueCards();
  
  // Atualiza automaticamente todas as imagens expiradas em lote
  setTimeout(() => atualizarImagensExpiradasEmLote(), 100);

  // Agrupa renderizações sucessivas da pesquisa em uma única consulta.
  clearTimeout(window.__estoqueCardsLoadTimer);
  window.__estoqueCardsLoadTimer = setTimeout(() => carregarEstoqueCards(), 200);

  // Marca produtos com compra em andamento (badge "Em compra")
  setTimeout(() => carregarComprasBadges(), 250);
}

// ----- Badge "Em compra" nos cards (produtos com solicitação de compra ativa) -----
let __produtosEmCompraCache = null;
let __produtosEmCompraCacheTs = 0;

async function getProdutosEmCompra() {
  const agora = Date.now();
  if (__produtosEmCompraCache && (agora - __produtosEmCompraCacheTs) < 2 * 60 * 1000) {
    return __produtosEmCompraCache;
  }
  try {
    const resp = await fetch('/api/compras/produtos-em-compra', { credentials: 'include' });
    if (resp.ok) {
      const data = await resp.json();
      const mapa = new Map();
      (Array.isArray(data.itens) ? data.itens : []).forEach(it => {
        const cod = String(it.codigo || '').trim().toUpperCase();
        if (cod) mapa.set(cod, String(it.status || '').trim());
      });
      __produtosEmCompraCache = mapa;
      __produtosEmCompraCacheTs = agora;
    }
  } catch (_) {
    // silencia erros de rede — badge é informativo
  }
  return __produtosEmCompraCache || new Map();
}

async function carregarComprasBadges() {
  const badges = document.querySelectorAll('[id^="compra-badge-"]');
  if (!badges.length) return;

  const emCompra = await getProdutosEmCompra();
  badges.forEach(badge => {
    const cod = String(badge.dataset.codigo || '').trim().toUpperCase();
    const status = emCompra.get(cod);
    if (!status) {
      badge.innerHTML = '';
      return;
    }
    badge.innerHTML = `<button type="button"
      onclick="event.stopPropagation();abrirModalEmCompra('${escapeHtml(cod)}')"
      style="display:inline-flex;align-items:center;gap:4px;background:#dbeafe;color:#1e40af;padding:5px 8px;border:1px solid #1e40af;border-radius:5px;font-size:11px;font-weight:800;cursor:pointer;"
      title="Clique para ver os dados da compra — status: ${escapeHtml(status)}"
      onmouseover="this.style.background='#bfdbfe'"
      onmouseout="this.style.background='#dbeafe'">
      <i class="fa-solid fa-cart-shopping" style="font-size:10px;"></i>
      Em compra
    </button>`;
  });
}

function _fmtDataEmCompra(iso) {
  if (!iso) return '—';
  const d = new Date(iso);
  if (Number.isNaN(d.getTime())) return '—';
  return d.toLocaleDateString('pt-BR');
}

function _fmtQtdEmCompra(v) {
  if (v === null || v === undefined || v === '') return '—';
  const n = Number(String(v).replace(',', '.'));
  if (!Number.isFinite(n)) return String(v);
  return Math.abs(n - Math.round(n)) < 1e-9
    ? String(Math.round(n))
    : n.toLocaleString('pt-BR', { minimumFractionDigits: 0, maximumFractionDigits: 4 });
}

window.abrirModalEmCompra = async function abrirModalEmCompra(codigo) {
  const cod = String(codigo || '').trim();
  if (!cod) return;

  document.getElementById('modalEmCompraProduto')?.remove();

  const modal = document.createElement('div');
  modal.id = 'modalEmCompraProduto';
  modal.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,.55);z-index:10050;display:flex;align-items:center;justify-content:center;padding:16px;';
  modal.innerHTML = `
    <div style="background:#fff;border-radius:12px;width:min(560px,100%);max-height:85vh;display:flex;flex-direction:column;box-shadow:0 20px 50px rgba(0,0,0,.35);">
      <div style="padding:14px 16px;border-bottom:1px solid #e5e7eb;display:flex;align-items:center;gap:10px;">
        <i class="fa-solid fa-cart-shopping" style="color:#1e40af;font-size:16px;"></i>
        <div style="flex:1;min-width:0;">
          <div style="font-weight:800;font-size:15px;color:#111827;">Compras em andamento</div>
          <div style="font-size:12px;color:#6b7280;margin-top:2px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${escapeHtml(cod)}</div>
        </div>
        <button type="button" id="modalEmCompraFechar" style="border:none;background:#f3f4f6;width:32px;height:32px;border-radius:8px;cursor:pointer;color:#374151;">
          <i class="fa-solid fa-xmark"></i>
        </button>
      </div>
      <div id="modalEmCompraBody" style="padding:16px;overflow:auto;flex:1;">
        <div style="text-align:center;padding:28px;color:#6b7280;">
          <i class="fa-solid fa-spinner fa-spin" style="font-size:28px;color:#3b82f6;"></i>
          <div style="margin-top:10px;font-size:13px;">Carregando...</div>
        </div>
      </div>
    </div>`;
  document.body.appendChild(modal);

  const fechar = () => modal.remove();
  document.getElementById('modalEmCompraFechar')?.addEventListener('click', fechar);
  modal.addEventListener('click', (e) => { if (e.target === modal) fechar(); });

  const body = document.getElementById('modalEmCompraBody');
  try {
    const resp = await fetch('/api/compras/produtos-em-compra/' + encodeURIComponent(cod), { credentials: 'include' });
    const data = await resp.json().catch(() => ({}));
    if (!resp.ok || !data.ok) throw new Error(data.error || `HTTP ${resp.status}`);

    const compras = Array.isArray(data.compras) ? data.compras : [];
    if (!compras.length) {
      body.innerHTML = '<div style="text-align:center;padding:28px;color:#6b7280;font-size:13px;">Nenhuma compra em andamento para este produto.</div>';
      return;
    }

    const descricao = compras[0].produto_descricao || '';
    body.innerHTML = `
      ${descricao ? `<div style="font-size:12px;color:#4b5563;margin-bottom:14px;line-height:1.4;">${escapeHtml(descricao)}</div>` : ''}
      <div style="display:flex;flex-direction:column;gap:12px;">
        ${compras.map((c, idx) => `
          <div style="border:1px solid #e5e7eb;border-radius:10px;padding:12px 14px;background:#f8fafc;">
            ${compras.length > 1 ? `<div style="font-size:11px;font-weight:700;color:#6b7280;margin-bottom:8px;">Compra ${idx + 1} de ${compras.length}</div>` : ''}
            <div style="display:flex;flex-wrap:wrap;gap:6px;margin-bottom:10px;">
              <span style="display:inline-flex;align-items:center;gap:4px;background:#dbeafe;color:#1e40af;padding:3px 8px;border-radius:999px;font-size:11px;font-weight:700;">
                <i class="fa-solid fa-tag" style="font-size:9px;"></i>${escapeHtml(c.status || '—')}
              </span>
              <span style="display:inline-flex;align-items:center;gap:4px;background:#ecfdf5;color:#065f46;padding:3px 8px;border-radius:999px;font-size:11px;font-weight:700;">
                Qtd: ${_fmtQtdEmCompra(c.quantidade)}
              </span>
            </div>
            <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px 12px;font-size:12px;">
              <div><div style="color:#9ca3af;font-size:10px;font-weight:700;text-transform:uppercase;">Solicitante</div><div style="color:#111827;font-weight:600;">${escapeHtml(c.solicitante || '—')}</div></div>
              <div><div style="color:#9ca3af;font-size:10px;font-weight:700;text-transform:uppercase;">Responsável compra</div><div style="color:#111827;font-weight:600;">${escapeHtml(c.responsavel_pela_compra || '—')}</div></div>
              <div style="grid-column:1/-1;"><div style="color:#9ca3af;font-size:10px;font-weight:700;text-transform:uppercase;">Fornecedor</div><div style="color:#111827;font-weight:600;">${escapeHtml(c.fornecedor_nome || '—')}</div></div>
              <div><div style="color:#9ca3af;font-size:10px;font-weight:700;text-transform:uppercase;">Pedido Omie</div><div style="color:#111827;font-weight:600;">${escapeHtml(c.c_numero || '—')}</div></div>
              <div><div style="color:#9ca3af;font-size:10px;font-weight:700;text-transform:uppercase;">Nº pedido interno</div><div style="color:#111827;font-weight:600;word-break:break-all;">${escapeHtml(c.numero_pedido || '—')}</div></div>
              <div><div style="color:#9ca3af;font-size:10px;font-weight:700;text-transform:uppercase;">Departamento</div><div style="color:#111827;font-weight:600;">${escapeHtml(c.departamento || '—')}</div></div>
              <div><div style="color:#9ca3af;font-size:10px;font-weight:700;text-transform:uppercase;">Prazo solicitado</div><div style="color:#111827;font-weight:600;">${_fmtDataEmCompra(c.prazo_solicitado)}</div></div>
              <div><div style="color:#9ca3af;font-size:10px;font-weight:700;text-transform:uppercase;">Previsão chegada</div><div style="color:#111827;font-weight:600;">${_fmtDataEmCompra(c.previsao_chegada)}</div></div>
              <div><div style="color:#9ca3af;font-size:10px;font-weight:700;text-transform:uppercase;">Criado em</div><div style="color:#111827;font-weight:600;">${_fmtDataEmCompra(c.created_at)}</div></div>
              ${c.objetivo_compra ? `<div style="grid-column:1/-1;"><div style="color:#9ca3af;font-size:10px;font-weight:700;text-transform:uppercase;">Objetivo</div><div style="color:#111827;">${escapeHtml(c.objetivo_compra)}</div></div>` : ''}
              ${c.observacao ? `<div style="grid-column:1/-1;"><div style="color:#9ca3af;font-size:10px;font-weight:700;text-transform:uppercase;">Observação</div><div style="color:#111827;">${escapeHtml(c.observacao)}</div></div>` : ''}
            </div>
          </div>
        `).join('')}
      </div>`;
  } catch (err) {
    body.innerHTML = `<div style="text-align:center;padding:28px;color:#ef4444;font-size:13px;">Erro ao carregar: ${escapeHtml(err.message || String(err))}</div>`;
  }
};

// Carrega estoque por local para todos os cards visíveis
window.__estoqueCardCache = window.__estoqueCardCache || {};
window.__estoqueMinimoCache = window.__estoqueMinimoCache || {};
window.__estoqueCardCacheMeta = window.__estoqueCardCacheMeta || {};
const ESTOQUE_CARD_CACHE_TTL_MS = 60_000;

function formatarQtdEstoque(saldo, unidade) {
  const qtd = Number(saldo).toLocaleString('pt-BR', { minimumFractionDigits: 0, maximumFractionDigits: 2 });
  return unidade ? `${qtd} ${unidade}` : qtd;
}

function aplicarDeltaListaLocais(locais, deltas) {
  const lista = (locais || []).map(l => ({ ...l }));
  for (const d of deltas || []) {
    const cod = String(d.local_codigo || '').trim();
    if (!cod) continue;
    let item = lista.find(l => String(l.local_codigo) === cod);
    if (item) {
      item.saldo = Math.max(0, (Number(item.saldo) || 0) + (Number(d.delta) || 0));
    } else if ((Number(d.delta) || 0) > 0) {
      lista.push({
        local_codigo: d.local_codigo,
        local_nome: d.local_nome || d.local_codigo,
        saldo: Number(d.delta) || 0,
        unidade: d.unidade || 'UN'
      });
    }
  }
  return lista;
}

function renderHtmlEstoquePorLocal(locais, tema) {
  if (!locais || locais.length === 0) {
    if (tema === 'modal') return '<span class="movim-estoque-vazio">Sem estoque registrado</span>';
    return '<span style="font-size:9px;color:#9ca3af;">Sem estoque</span>';
  }
  const locaisOrdenados = [...locais].sort((a, b) => {
    const aAlmox = String(a.local_codigo || '') === '10717096386' || /PORTA PALLET/i.test(a.local_nome || '');
    const bAlmox = String(b.local_codigo || '') === '10717096386' || /PORTA PALLET/i.test(b.local_nome || '');
    return Number(bAlmox) - Number(aAlmox);
  });
  return locaisOrdenados.map(l => {
    const isAlmox = String(l.local_codigo || '') === '10717096386' || /PORTA PALLET/i.test(l.local_nome || '');
    const nome = escapeHtml(l.local_nome || l.local_codigo || '—');
    const nomeExibicao = isAlmox ? 'ESTOQUE ALMOX.' : nome;
    const qtd = formatarQtdEstoque(l.saldo, l.unidade);
    if (tema === 'modal') {
      return `<div class="movim-est-linha" data-local-codigo="${escapeHtml(String(l.local_codigo || ''))}">
        <span class="movim-est-nome">${nomeExibicao}</span>
        <span class="movim-est-qtd">${escapeHtml(qtd)}</span>
      </div>`;
    }
    return `<div style="display:flex;justify-content:space-between;font-size:${isAlmox ? '11px' : '9px'};color:#374151;line-height:1.5;${isAlmox ? 'padding:3px 5px;background:#f3f4f6;border-radius:4px;margin-bottom:3px;' : ''}">
      <span style="color:${isAlmox ? '#111827' : '#6b7280'};font-weight:${isAlmox ? '800' : '400'};overflow:hidden;text-overflow:ellipsis;white-space:nowrap;max-width:70%;">${nomeExibicao}</span>
      <span style="font-weight:${isAlmox ? '800' : '600'};white-space:nowrap;">${escapeHtml(qtd)}</span>
    </div>`;
  }).join('');
}

function atualizarCardEstoqueVisual(codigo) {
  const el = document.getElementById('estoque-card-' + codigo);
  if (!el) return;
  const locais = window.__estoqueCardCache[codigo] || [];
  el.innerHTML = renderHtmlEstoquePorLocal(locais, 'card');
}

function renderizarBadgeMinimo(badge, info) {
  if (!badge) return;
  badge.innerHTML = '';
  if (!info || Number(info.min) <= 0) return;
  const cor = info.abaixo ? '#dc2626' : '#16a34a';
  const bg = info.abaixo ? '#fee2e2' : '#dcfce7';
  badge.innerHTML = `<span style="display:inline-flex;align-items:center;background:${bg};color:${cor};padding:5px 8px;border:1px solid ${cor};border-radius:5px;font-size:12px;font-weight:800;">Mínimo: ${Number(info.min).toLocaleString('pt-BR', {minimumFractionDigits:0, maximumFractionDigits:2})}</span>`;
}

function aplicarCacheEstoqueCards(codigos = null) {
  const filtro = Array.isArray(codigos) && codigos.length ? new Set(codigos) : null;
  document.querySelectorAll('[id^="estoque-card-"]').forEach(el => {
    const cod = el.dataset.codigo;
    if (!cod || (filtro && !filtro.has(cod))) return;
    if (Object.prototype.hasOwnProperty.call(window.__estoqueCardCache, cod)) {
      el.innerHTML = renderHtmlEstoquePorLocal(window.__estoqueCardCache[cod], 'card');
    }
  });
  document.querySelectorAll('[id^="min-badge-"]').forEach(badge => {
    const cod = badge.dataset.codigo;
    if (!cod || (filtro && !filtro.has(cod))) return;
    if (Object.prototype.hasOwnProperty.call(window.__estoqueMinimoCache, cod)) {
      renderizarBadgeMinimo(badge, window.__estoqueMinimoCache[cod]);
    }
  });
}

window.aplicarDeltaEstoqueOtimista = function aplicarDeltaEstoqueOtimista(codigo, deltas) {
  if (!codigo || !Array.isArray(deltas) || !deltas.length) return;
  const atual = window.__estoqueCardCache[codigo] || [];
  window.__estoqueCardCache[codigo] = aplicarDeltaListaLocais(atual, deltas);
  window.__estoqueCardCacheMeta[codigo] = Date.now();
  atualizarCardEstoqueVisual(codigo);
  if (typeof window.__atualizarMovimEstoqueLocais === 'function') {
    window.__atualizarMovimEstoqueLocais(codigo, deltas);
  }
};

async function carregarEstoqueCards(options = {}) {
  const { force = false, codigos: codigosForcados = null } = options;
  const placeholders = document.querySelectorAll('[id^="estoque-card-"]');
  if (!placeholders.length) return;

  const codigosVisiveis = [...new Set(Array.from(placeholders).map(el => el.dataset.codigo).filter(Boolean))];
  const codigosAlvo = Array.isArray(codigosForcados) && codigosForcados.length
    ? [...new Set(codigosForcados.filter(Boolean))]
    : codigosVisiveis;
  aplicarCacheEstoqueCards(codigosVisiveis);

  const codigos = force
    ? codigosAlvo
    : codigosAlvo.filter(cod => {
        const atualizadoEm = Number(window.__estoqueCardCacheMeta[cod]) || 0;
        const cacheExpirou = Date.now() - atualizadoEm >= ESTOQUE_CARD_CACHE_TTL_MS;
        return cacheExpirou ||
          !Object.prototype.hasOwnProperty.call(window.__estoqueCardCache, cod) ||
          !Object.prototype.hasOwnProperty.call(window.__estoqueMinimoCache, cod);
      });
  if (!codigos.length) return;

  try {
    const resp = await fetch('/api/logistica/estoque/batch?codigos=' + encodeURIComponent(codigos.join(',')));
    if (!resp.ok) return;
    const { dados, minimos } = await resp.json();

    codigos.forEach(cod => {
      const locais = dados?.[cod];
      if (!locais || locais.length === 0) {
        window.__estoqueCardCache[cod] = [];
      } else {
        window.__estoqueCardCache[cod] = locais.map(l => ({ ...l }));
      }
      window.__estoqueMinimoCache[cod] = minimos?.[cod] || { min: 0, saldoAlmox: 0, abaixo: false };
      window.__estoqueCardCacheMeta[cod] = Date.now();
    });
    aplicarCacheEstoqueCards(codigos);
  } catch (e) {
    // silencia erros de rede
  }
}

// Disponibiliza para uso externo (ex.: lista de produtos)
window.renderizarCatalogoOmie = renderizarCatalogoOmie;

// ===================== MODAL SEPARAÇÃO =====================
(function() {
  let _sepCtx = null;

  // Cria o modal diretamente como filho de <body> para position:fixed funcionar
  // independente de transforms/backdrop-filter em containers pais
  const ov = document.createElement('div');
  ov.id = 'modalSeparacaoQtd';
  ov.style.cssText = 'display:none;position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,.75);z-index:99999;align-items:center;justify-content:center;padding:16px;';
  ov.innerHTML = `
    <div style="width:min(420px,95%);background:#1c1c1c;border-radius:16px;padding:20px;box-shadow:0 18px 48px rgba(0,0,0,.55);display:flex;flex-direction:column;gap:14px;">
      <h3 id="sepQtyTitle" style="margin:0;font-size:1.05rem;color:#f0f0f0;">Quantidade para separação</h3>
      <div id="sepQtyProd" style="font-weight:700;font-size:.95rem;color:#e5e7eb;"></div>
      <div id="sepQtyUnit" style="display:inline-block;padding:10px 12px;border-radius:12px;background:#2a1b00;border:1px solid #ffb400;color:#ffda7a;font-weight:800;font-size:1.05rem;letter-spacing:.03em;"></div>
      <input id="sepQtyInput" type="number" min="0.001" step="0.001" value="1" style="width:100%;padding:12px;border:none;border-radius:12px;background:#2a2a2a;color:#fff;font-size:1rem;box-sizing:border-box;" />
      <div style="display:flex;gap:10px;">
        <button id="sepQtyCancel" type="button" style="flex:1;border:none;border-radius:12px;padding:12px;font-weight:700;cursor:pointer;background:#2a2a2a;color:#fff;font-size:14px;">Cancelar</button>
        <button id="sepQtyOk" type="button" style="flex:1;border:none;border-radius:12px;padding:12px;font-weight:700;cursor:pointer;background:#f59e0b;color:#1a1200;font-size:14px;">Confirmar</button>
      </div>
    </div>
  `;
  document.body.appendChild(ov);

  function fechar() {
    ov.style.display = 'none';
    _sepCtx = null;
  }

  async function confirmar() {
    if (!_sepCtx) return;
    const input = document.getElementById('sepQtyInput');
    let qty = Number(String(input?.value || '').replace(',', '.'));
    if (!Number.isFinite(qty) || qty <= 0) { input?.focus({ preventScroll: true }); return; }
    if (_sepCtx.unidade === 'UN') {
      qty = Math.max(1, Math.round(qty));
    }
    const { codigo, descricao, unidade } = _sepCtx;
    fechar();
    try {
      const resp = await fetch('/api/logistica/separacao', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({ codigo, descricao, quantidade: qty, unidade })
      });
      const data = await resp.json();
      if (!data.ok) {
        alert('Erro ao registrar separação: ' + (data.error || 'tente novamente.'));
      } else {
        // Atualiza badge do botão de separações
        const badge = document.getElementById('listaSeparacaoCount');
        if (badge) {
          const atual = parseInt(badge.textContent) || 0;
          const incremento = data.merged ? 0 : 1;
          const total = atual + incremento;
          badge.textContent = total;
          badge.style.display = total > 0 ? '' : 'none';
        }
      }
    } catch (err) {
      console.error('[Separação] Erro:', err);
      alert('Erro ao conectar ao servidor.');
    }
  }

  // eventos do overlay
  ov.addEventListener('click', e => { if (e.target === ov) fechar(); });
  document.getElementById('sepQtyCancel').addEventListener('click', fechar);
  document.getElementById('sepQtyOk').addEventListener('click', confirmar);
  document.getElementById('sepQtyInput').addEventListener('keydown', e => {
    if (e.key === 'Enter') confirmar();
    if (e.key === 'Escape') fechar();
  });

  window.abrirModalSeparacaoQtd = function(codigo, descricao, unidade) {
    _sepCtx = { codigo, descricao, unidade: (unidade || 'UN').toUpperCase() };
    const el = id => document.getElementById(id);
    el('sepQtyTitle').textContent = 'Quantidade para separação';
    el('sepQtyProd').textContent  = descricao || codigo;
    el('sepQtyUnit').textContent  = 'SOLICITAR COMO: ' + _sepCtx.unidade;
    const inp = el('sepQtyInput');
    if (inp) {
      inp.value = 1;
      if (_sepCtx.unidade === 'UN') {
        inp.min = '1';
        inp.step = '1';
      } else {
        inp.min = '0.001';
        inp.step = '0.001';
      }
    }
    ov.style.display = 'flex';
    try { inp?.focus({ preventScroll: true }); } catch {}
  };
})();

