// Carrega categorias da tabela ListarCategorias para o dropdown recolhível
async function carregarCategoriaCompraDropdown(options = {}) {
  const dropdownId = options.dropdownId || 'catalogoCategoriaCompraDropdown';
  const btnTextId = options.btnTextId || 'catalogoCategoriaCompraBtnText';
  const hiddenInputId = options.hiddenInputId || 'catalogoCategoriaCompraGlobal';
  const logPrefix = options.logPrefix || 'Catálogo';
  const categoriasOverride = Array.isArray(options.categorias) ? options.categorias : null;
  const onSelect = typeof options.onSelect === 'function' ? options.onSelect : null;

  const dropdown = document.getElementById(dropdownId);
  const btnText = document.getElementById(btnTextId);
  const hiddenInput = document.getElementById(hiddenInputId);
  if (!dropdown || !btnText || !hiddenInput) return;

  dropdown.innerHTML = '<div style="padding:8px;color:#64748b;font-size:12px;">Carregando...</div>';

  let categorias = categoriasOverride || [];
  if (!categoriasOverride) {
    const respCat = await fetch('/api/compras/categorias-listar', { credentials: 'include' });
    if (!respCat.ok) throw new Error('Erro ao buscar categorias');
    const dataCat = await respCat.json();
    categorias = Array.isArray(dataCat.categorias) ? dataCat.categorias : [];
    window.categoriasCompra = categorias;
  }
  console.log(`[${logPrefix}] categorias-listar total:`, categorias.length);

  if (categorias.length === 0) {
    dropdown.innerHTML = '<div style="padding:8px;color:#9ca3af;font-size:12px;">Nenhuma categoria encontrada</div>';
    return;
  }

  const map = new Map();
  categorias.forEach(c => map.set(String(c.codigo), c));
  window.categoriasCompraMap = map;
  const filhosPorPai = new Map();
  categorias.forEach(c => {
    const pai = c.categoria_superior ? String(c.categoria_superior) : null;
    if (!filhosPorPai.has(pai)) filhosPorPai.set(pai, []);
    filhosPorPai.get(pai).push(c);
  });

  const topLevel = categorias.filter(c => {
    const pai = c.categoria_superior ? String(c.categoria_superior) : null;
    return !pai || !map.has(pai);
  });

  const ordenar = (a, b) => String(a.descricao || '').localeCompare(String(b.descricao || ''), 'pt-BR', { sensitivity: 'base' });
  dropdown.innerHTML = '';

  const criarItem = (cat, nivel = 0) => {
    const btn = document.createElement('button');
    btn.type = 'button';
    btn.style.cssText = `width:100%;text-align:left;padding:6px 8px;border:none;background:transparent;font-size:12px;cursor:pointer;border-radius:4px;margin-left:${nivel * 12}px;`;
    btn.onmouseover = () => { btn.style.background = '#f1f5f9'; };
    btn.onmouseout = () => { btn.style.background = 'transparent'; };
    btn.textContent = `${cat.codigo} - ${cat.descricao}`;
    btn.addEventListener('click', () => {
      hiddenInput.value = String(cat.codigo);
      hiddenInput.setAttribute('data-label', `${cat.codigo} - ${cat.descricao}`);
      btnText.textContent = `${cat.codigo} - ${cat.descricao}`;
      dropdown.style.display = 'none';
      if (onSelect) {
        Promise.resolve(onSelect(cat, { hiddenInput, btnText })).catch(err => {
          console.warn('[Categoria Compra] Falha ao aplicar seleção:', err);
        });
      }
    });
    return btn;
  };

  const renderGrupo = (grupo) => {
    const grupoOrdenado = [...grupo].sort(ordenar);
    grupoOrdenado.forEach(nivel1 => {
      const nivel2List = (filhosPorPai.get(String(nivel1.codigo)) || []).sort(ordenar);
      const detailsNivel1 = document.createElement('details');
      detailsNivel1.style.cssText = 'padding:4px 0;';
      const summaryNivel1 = document.createElement('summary');
      summaryNivel1.textContent = `${nivel1.codigo} - ${nivel1.descricao}`;
      summaryNivel1.style.cssText = 'cursor:pointer;list-style:none;padding:6px 8px;font-size:12px;font-weight:700;color:#1f2937;border-radius:4px;text-transform:uppercase;';
      summaryNivel1.onmouseover = () => { summaryNivel1.style.background = '#f1f5f9'; };
      summaryNivel1.onmouseout = () => { summaryNivel1.style.background = 'transparent'; };
      detailsNivel1.appendChild(summaryNivel1);

      const groupNivel1 = document.createElement('div');
      groupNivel1.style.cssText = 'padding-left:8px;display:grid;gap:2px;';

      if (nivel2List.length === 0) {
        groupNivel1.appendChild(criarItem(nivel1, 0));
      } else {
        nivel2List.forEach(nivel2 => {
          const nivel3List = (filhosPorPai.get(String(nivel2.codigo)) || []).sort(ordenar);
          if (nivel3List.length > 0) {
            const details = document.createElement('details');
            details.style.cssText = 'padding:4px 0;';
            const summary = document.createElement('summary');
            summary.textContent = `${nivel2.codigo} - ${nivel2.descricao}`;
            summary.style.cssText = 'cursor:pointer;list-style:none;padding:6px 8px;font-size:12px;font-weight:600;color:#1f2937;border-radius:4px;';
            summary.onmouseover = () => { summary.style.background = '#f8fafc'; };
            summary.onmouseout = () => { summary.style.background = 'transparent'; };
            details.appendChild(summary);
            const group = document.createElement('div');
            group.style.cssText = 'padding-left:8px;display:grid;gap:2px;';
            nivel3List.forEach(nivel3 => group.appendChild(criarItem(nivel3, 1)));
            details.appendChild(group);
            groupNivel1.appendChild(details);
          } else {
            groupNivel1.appendChild(criarItem(nivel2, 0));
          }
        });
      }

      detailsNivel1.appendChild(groupNivel1);
      dropdown.appendChild(detailsNivel1);
    });
  };

  if (topLevel.length > 0) {
    renderGrupo(topLevel);
  } else {
    const nivel2List = (filhosPorPai.get(null) || categorias).sort(ordenar);
    nivel2List.forEach(nivel2 => dropdown.appendChild(criarItem(nivel2, 0)));
  }

  const categoriaPadraoCodigo = '2.14.94';
  if (!hiddenInput.value) {
    const categoriaPadrao = map.get(categoriaPadraoCodigo);
    if (categoriaPadrao) {
      hiddenInput.value = String(categoriaPadrao.codigo);
      hiddenInput.setAttribute('data-label', `${categoriaPadrao.codigo} - ${categoriaPadrao.descricao}`);
      btnText.textContent = `${categoriaPadrao.codigo} - ${categoriaPadrao.descricao}`;
    }
  }
}

// Aplica categoria da compra baseada no último pedido do produto
async function aplicarCategoriaCompraPorProdutoCarrinho(codigoProdutoOmie, itemIdx) {
  console.log('[DEBUG CATEGORIA] Função chamada com:', { codigoProdutoOmie, itemIdx });
  
  const codigo = String(codigoProdutoOmie || '').trim();
  console.log('[DEBUG CATEGORIA] Código após trim:', codigo);
  
  if (!codigo || !Number.isFinite(itemIdx)) {
    console.warn('[DEBUG CATEGORIA] Validação falhou:', { 
      codigo_valido: !!codigo, 
      idx_valido: Number.isFinite(itemIdx) 
    });
    return null;
  }

  const itemAntesDaConsulta = window.carrinhoCompras[itemIdx];
  const categoriaOperacionalAtual = obterCategoriaCompraOmieOperacionalCarrinho(itemAntesDaConsulta?.centro_custo);
  if (categoriaOperacionalAtual) {
    console.log('[DEBUG CATEGORIA] Mantendo categoria operacional escolhida no carrinho:', categoriaOperacionalAtual);
    return categoriaOperacionalAtual;
  }

  try {
    const url = `/api/compras/categoria-por-produto/${encodeURIComponent(codigo)}`;
    console.log('[DEBUG CATEGORIA] Fazendo fetch para:', url);

    const resp = await fetch(url, { credentials: 'include' });
    console.log('[DEBUG CATEGORIA] Resposta recebida:', { 
      status: resp.status, 
      ok: resp.ok 
    });
    
    if (!resp.ok) {
      console.warn('[DEBUG CATEGORIA] Resposta não OK:', resp.status);
      return null;
    }

    const data = await resp.json();
    console.log('[DEBUG CATEGORIA] Dados da API:', data);
    
    const categoriaCodigo = String(data?.categoria_codigo || data?.categoria || '').trim();
    const categoriaDescricao = String(data?.categoria_descricao || '').trim();
    const categoriaNome = String(data?.categoria_nome || '').trim();
    
    console.log('[DEBUG CATEGORIA] Categoria extraída:', {
      codigo: categoriaCodigo,
      descricao: categoriaDescricao,
      nome: categoriaNome
    });
    
    if (!categoriaCodigo) {
      console.warn('[DEBUG CATEGORIA] Nenhuma categoria na resposta');
      return null;
    }

    if (window.carrinhoCompras[itemIdx]) {
      const itemAtual = window.carrinhoCompras[itemIdx];
      const categoriaOperacionalDepoisDaConsulta = obterCategoriaCompraOmieOperacionalCarrinho(itemAtual?.centro_custo);
      if (categoriaOperacionalDepoisDaConsulta) {
        console.log('[DEBUG CATEGORIA] Consulta atrasada ignorada para preservar categoria operacional:', categoriaOperacionalDepoisDaConsulta);
        return categoriaOperacionalDepoisDaConsulta;
      }

      // Atualiza o item do carrinho
      console.log('[DEBUG CATEGORIA] Atualizando item no índice:', itemIdx);
      
      itemAtual.categoria_compra_codigo = categoriaCodigo;
      itemAtual.categoria_compra = categoriaDescricao;
      itemAtual.categoria_compra_nome = categoriaNome;

      // Atualiza no banco
      console.log('[DEBUG CATEGORIA] Salvando no banco...');
      await atualizarItemCarrinhoNoBanco(itemAtual);
      console.log('[DEBUG CATEGORIA] Salvo no banco!');
      
      // Atualiza a UI
      const btnText = document.getElementById(`carrinhoItemCategoriaCompraBtnText-${itemIdx}`);
      const hiddenInput = document.getElementById(`carrinhoItemCategoriaCompra-${itemIdx}`);
      
      console.log('[DEBUG CATEGORIA] Elementos DOM:', { 
        btnText_existe: !!btnText, 
        hiddenInput_existe: !!hiddenInput,
        btnText_id: `carrinhoItemCategoriaCompraBtnText-${itemIdx}`,
        hiddenInput_id: `carrinhoItemCategoriaCompra-${itemIdx}`
      });
      
      if (btnText && categoriaNome) {
        console.log('[DEBUG CATEGORIA] Atualizando btnText para:', categoriaNome);
        btnText.textContent = categoriaNome;
        btnText.style.color = 'var(--active-color)';
      }
      
      if (hiddenInput) {
        console.log('[DEBUG CATEGORIA] Atualizando hiddenInput.value para:', categoriaCodigo);
        hiddenInput.value = categoriaCodigo;
      }

      console.log('[DEBUG CATEGORIA] ✅ Categoria aplicada com sucesso!', { 
        codigo: categoriaCodigo,
        descricao: categoriaDescricao,
        nome: categoriaNome,
        item_idx: itemIdx 
      });
      
      return { 
        codigo: categoriaCodigo, 
        descricao: categoriaDescricao,
        nome: categoriaNome
      };
    }
    
    return null;
  } catch (err) {
    console.warn('[CARRINHO] Falha ao aplicar categoria por produto:', err);
    return null;
  }
}

