// Abre modal de edição de item de compra
async function abrirModalEditarCompra(item) {
  if (!item) {
    alert('Item não encontrado.');
    return;
  }

  // Verifica se o status permite edição
  const status = (item.status || '').toLowerCase();
  if (status !== 'aguardando compra' && status !== 'aguardando cotação' && status !== 'aguardando_compra' && status !== 'aguardando_cotacao') {
    alert('Este item não pode ser editado. Apenas itens com status "aguardando compra" ou "aguardando cotação" podem ser editados.');
    return;
  }

  const modal = document.getElementById('comprasModalOverlay');
  if (!modal) {
    alert('Modal não encontrado.');
    return;
  }

  // Mostra o modal
  modal.style.display = 'flex';

  // Mostra spinner
  const spinner = document.getElementById('comprasModalSpinner');
  const form = document.getElementById('comprasModalForm');
  if (spinner) spinner.style.display = 'block';
  if (form) form.style.display = 'none';

  try {
    // Carrega dados necessários para os selects
    await Promise.all([
      loadModalComprasDepartamentos(),
      loadModalComprasCentrosCusto(),
      loadModalComprasResponsaveis(),
      loadModalComprasCategoriasCompra()
    ]);

    // Preenche os campos do formulário com os dados do item
    const camposCodigo = document.getElementById('modalComprasCodigo');
    const camposDescricao = document.getElementById('modalComprasDescricao');
    const camposQuantidade = document.getElementById('modalComprasQuantidade');
    const camposDepartamento = document.getElementById('modalComprasDepartamento');
    const camposCentroCusto = document.getElementById('modalComprasCentroCusto');
    const camposRetornoCotacao = document.getElementById('modalComprasRetornoCotacao');
    const camposPrazo = document.getElementById('modalComprasPrazo');
    const camposResponsavel = document.getElementById('modalComprasResponsavel');
    const camposObjetivo = document.getElementById('modalComprasObjetivo');
    const camposObservacao = document.getElementById('modalComprasObservacao');

    if (camposCodigo) camposCodigo.value = item.produto_codigo || '';
    if (camposDescricao) camposDescricao.value = item.descricao || '';
    if (camposQuantidade) camposQuantidade.value = item.quantidade || 1;
    if (camposDepartamento) camposDepartamento.value = item.departamento || '';
    if (camposCentroCusto) camposCentroCusto.value = item.centro_custo || '';
    if (camposRetornoCotacao) camposRetornoCotacao.value = item.retorno_cotacao || '';
    if (camposPrazo && item.prazo_solicitado) {
      const prazoDate = new Date(item.prazo_solicitado);
      if (!isNaN(prazoDate.getTime())) {
        camposPrazo.value = prazoDate.toISOString().slice(0, 10);
      }
    }
    if (camposResponsavel) camposResponsavel.value = item.resp_inspecao_recebimento || '';
    if (camposObjetivo) camposObjetivo.value = item.objetivo_compra || '';
    if (camposObservacao) camposObservacao.value = item.observacao || '';

    // Altera o título do modal
    const modalTitulo = modal.querySelector('.modal-header h3');
    if (modalTitulo) {
      modalTitulo.innerHTML = '<i class="fa-solid fa-edit" style="color:#f59e0b;"></i> Editar item de compra';
    }

    // Altera o botão de submit
    const btnSalvar = document.getElementById('modalComprasAdicionarBtn');
    if (btnSalvar) {
      btnSalvar.textContent = 'Atualizar';
      btnSalvar.style.background = '#f59e0b';
      
      // Remove listeners antigos e adiciona novo para edição
      const novoBtnSalvar = btnSalvar.cloneNode(true);
      btnSalvar.parentNode.replaceChild(novoBtnSalvar, btnSalvar);
      
      novoBtnSalvar.addEventListener('click', async (e) => {
        e.preventDefault();
        await salvarEdicaoCompra(item.id);
      });
    }

    // Oculta spinner e mostra form
    if (spinner) spinner.style.display = 'none';
    if (form) form.style.display = 'block';

  } catch (err) {
    console.error('[COMPRAS] Erro ao abrir modal de edição:', err);
    alert('Erro ao carregar dados para edição.');
    modal.style.display = 'none';
  }
}

// Salva a edição de um item de compra
async function salvarEdicaoCompra(itemId) {
  const camposCodigo = document.getElementById('modalComprasCodigo');
  const camposDescricao = document.getElementById('modalComprasDescricao');
  const camposQuantidade = document.getElementById('modalComprasQuantidade');
  const camposDepartamento = document.getElementById('modalComprasDepartamento');
  const camposCentroCusto = document.getElementById('modalComprasCentroCusto');
  const camposRetornoCotacao = document.getElementById('modalComprasRetornoCotacao');
  const camposPrazo = document.getElementById('modalComprasPrazo');
  const camposResponsavel = document.getElementById('modalComprasResponsavel');
  const camposResponsavelCompra = document.getElementById('modalComprasResponsavelCompra');
  const camposObjetivo = document.getElementById('modalComprasObjetivo');
  const camposObservacao = document.getElementById('modalComprasObservacao');

  // Validações básicas
  if (!camposCodigo?.value?.trim()) {
    alert('O código do produto é obrigatório.');
    return;
  }
  if (!camposQuantidade?.value || camposQuantidade.value < 1) {
    alert('A quantidade deve ser maior que zero.');
    return;
  }
  if (!camposDepartamento?.value) {
    alert('Selecione um departamento.');
    return;
  }
  if (!camposCentroCusto?.value) {
    alert('Selecione uma categoria.');
    return;
  }
  if (!camposRetornoCotacao?.value) {
    alert('Selecione se necessário retorno de cotação.');
    return;
  }
  if (!camposResponsavel?.value) {
    alert('Selecione um responsável pela inspeção de recebimento.');
    return;
  }
  if (!camposResponsavelCompra?.value) {
    alert('Selecione um responsável pela compra.');
    return;
  }
  if (!camposObjetivo?.value?.trim()) {
    alert('O objetivo da compra é obrigatório.');
    return;
  }

  const payload = {
    produto_codigo: camposCodigo.value.trim(),
    descricao: camposDescricao.value.trim(),
    quantidade: parseInt(camposQuantidade.value),
    departamento: camposDepartamento.value,
    centro_custo: camposCentroCusto.value,
    retorno_cotacao: camposRetornoCotacao.value,
    prazo_solicitado: camposPrazo?.value || null,
    resp_inspecao_recebimento: camposResponsavel.value,
    responsavel_pela_compra: camposResponsavelCompra.value,
    objetivo_compra: camposObjetivo.value.trim(),
    observacao: camposObservacao?.value?.trim() || null
  };

  const btnSalvar = document.getElementById('modalComprasAdicionarBtn');
  if (btnSalvar) {
    btnSalvar.disabled = true;
    btnSalvar.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> Salvando...';
  }

  try {
    const resp = await fetch(`/api/compras/item/${itemId}`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify(payload)
    });

    if (!resp.ok) {
      const errData = await resp.json().catch(() => ({}));
      throw new Error(errData.error || 'Erro ao atualizar item');
    }

    // Feedback visual
    if (btnSalvar) {
      btnSalvar.style.background = '#10b981';
      btnSalvar.innerHTML = '<i class="fa-solid fa-check"></i> Salvo!';
    }

    // Fecha o modal e recarrega a lista
    setTimeout(() => {
      const modal = document.getElementById('comprasModalOverlay');
      if (modal) modal.style.display = 'none';
      loadComprasSolicitacoes();
    }, 1000);

  } catch (err) {
    console.error('[COMPRAS] Erro ao salvar edição:', err);
    alert('Erro ao salvar: ' + err.message);
    
    if (btnSalvar) {
      btnSalvar.disabled = false;
      btnSalvar.innerHTML = '<i class="fa-solid fa-edit"></i> Atualizar';
      btnSalvar.style.background = '#f59e0b';
    }
  }
}

// Carrega itens cotados do usuário logado
async function loadComprasCotadas() {
  const tbody = document.getElementById('comprasCotadasTbody');
  if (!tbody) return;
  
  tbody.innerHTML = '<tr><td colspan="6" style="text-align:center;padding:16px;color:var(--inactive-color);">Carregando...</td></tr>';
  
  // Garante que os fornecedores estão carregados antes de renderizar
  if (!window.fornecedoresCache || window.fornecedoresCache.length === 0) {
    await loadFornecedores();
  }
  
  try {
    const resp = await fetch('/api/compras/todas', { credentials: 'include' });
    if (!resp.ok) throw new Error('Não foi possível carregar as solicitações');
    const data = await resp.json();
    const listaCompleta = Array.isArray(data.solicitacoes) ? data.solicitacoes : [];
    
    // Pega usuário logado
    const usuario = window.__sessionUser?.username || document.getElementById('userNameDisplay')?.textContent?.trim() || '';
    
    // Filtra apenas itens com status "cotado" do usuário logado
    const lista = listaCompleta.filter(item => {
      const status = (item.status || '').toLowerCase();
      const solicitante = (item.solicitante || '').toLowerCase();
      return (status === 'cotado') && (solicitante === usuario.toLowerCase());
    });
    
    // Atualiza contador da aba de Cotações
    const contadorCotacoes = document.getElementById('contadorMinhasCotacoes');
    if (contadorCotacoes) {
      contadorCotacoes.textContent = lista.length;
    }
    
    if (!lista.length) {
      tbody.innerHTML = '<tr><td colspan="6" style="text-align:center;padding:16px;color:var(--inactive-color);">Nenhum item cotado.</td></tr>';
      return;
    }

    // Agrupa itens por numero_pedido
    const pedidosMap = new Map();
    lista.forEach(item => {
      const numPedido = item.numero_pedido || 'sem-numero';
      if (!pedidosMap.has(numPedido)) {
        pedidosMap.set(numPedido, []);
      }
      pedidosMap.get(numPedido).push(item);
    });

    const fmtInputDate = (iso) => {
      if (!iso) return '';
      try {
        const d = new Date(iso);
        if (Number.isNaN(d.getTime())) return '';
        return d.toISOString().slice(0, 10);
      } catch (_) {
        return '';
      }
    };

    const fmtDate = (iso) => {
      if (!iso) return '-';
      const d = new Date(iso);
      return Number.isNaN(d.getTime()) ? '-' : d.toLocaleDateString('pt-BR');
    };

    const fmtDateTime = (iso) => {
      if (!iso) return '-';
      const d = new Date(iso);
      return Number.isNaN(d.getTime()) ? '-' : d.toLocaleString('pt-BR');
    };

    let html = '';
    let pedidoIndex = 0;

    pedidosMap.forEach((itens, numeroPedido) => {
      const primeiroItem = itens[0];
      const totalItens = itens.length;
      const dataCriacao = fmtDateTime(primeiroItem.created_at);
      const solicitante = escapeHtml(primeiroItem.solicitante || '-');
      const expandId = `compras-cotado-expand-${pedidoIndex}`;

      // Linha principal do pedido (colapsada)
      html += `
        <tr class="compras-pedido-header" data-expand-id="${expandId}" style="cursor:pointer;background:#f9fafb;">
          <td style="text-align:center;">
            <i class="fa-solid fa-chevron-right compras-expand-icon" style="color:#6b7280;transition:transform 0.2s;"></i>
          </td>
          <td><strong style="color:#8b5cf6;">${escapeHtml(numeroPedido)}</strong></td>
          <td><span style="background:#ddd6fe;color:#5b21b6;padding:4px 10px;border-radius:12px;font-size:12px;font-weight:600;">${totalItens} ${totalItens === 1 ? 'item' : 'itens'}</span></td>
          <td style="color:#1f2937;font-weight:500;">${solicitante}</td>
          <td style="color:#1f2937;font-weight:500;">${dataCriacao}</td>
          <td></td>
        </tr>
      `;

      // Linhas dos itens (inicialmente ocultas) - usando mesma estrutura da outra tabela
      itens.forEach((item) => {
        const previsaoValue = fmtInputDate(item.previsao_chegada);
        const obs = item.observacao ? escapeHtml(item.observacao) : '-';
        
        // Processa anexos existentes
        let anexosExistentesHtml = '';
        try {
          const anexosExistentes = item.anexos ? (typeof item.anexos === 'string' ? JSON.parse(item.anexos) : item.anexos) : [];
          if (Array.isArray(anexosExistentes) && anexosExistentes.length > 0) {
            anexosExistentesHtml = anexosExistentes.map(anexoRaw => {
              const aUrl = typeof anexoRaw === 'string' ? anexoRaw : (anexoRaw?.url || '#');
              const aNome = typeof anexoRaw === 'string'
                ? (decodeURIComponent((anexoRaw.split('/').pop() || '').split('?')[0]).replace(/^\d+_/, '') || 'Arquivo')
                : (anexoRaw?.nome || 'Arquivo');
              return `
                <a href="${aUrl}" target="_blank" style="display:flex;align-items:center;gap:4px;background:#dbeafe;padding:4px 8px;border-radius:4px;font-size:11px;text-decoration:none;color:#1e40af;">
                  <i class="fa-solid fa-file" style="color:#3b82f6;"></i>
                  <span style="max-width:150px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;" title="${escapeHtml(aNome)}">${escapeHtml(aNome)}</span>
                  <i class="fa-solid fa-external-link-alt" style="font-size:9px;color:#60a5fa;"></i>
                </a>
              `;
            }).join('');
          }
        } catch (e) {
          console.error('[Anexos] Erro ao processar anexos:', e);
        }
        
        html += `
          <tr class="compras-pedido-item" data-pedido="${expandId}" style="display:none;background:#fefefe;">
            <td></td>
            <td colspan="5" style="padding:12px 20px;">
              <div style="display:grid;grid-template-columns:auto 1fr;gap:16px;align-items:start;border-left:3px solid #8b5cf6;padding-left:16px;">
                <div style="min-width:60px;">
                  <div style="font-size:11px;color:#6b7280;text-transform:uppercase;margin-bottom:4px;">ID</div>
                  <div style="font-weight:600;color:#374151;">${item.id}</div>
                </div>
                <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:12px;">
                  <!-- Primeira linha: Código - Descrição -->
                  <div>
                    <div style="font-size:11px;color:#6b7280;text-transform:uppercase;margin-bottom:4px;">Código</div>
                    <div style="font-weight:600;color:#1f2937;">${escapeHtml(item.produto_codigo || '-')}</div>
                  </div>
                  <div style="grid-column:span 2;">
                    <div style="font-size:11px;color:#6b7280;text-transform:uppercase;margin-bottom:4px;">Descrição</div>
                    <div style="color:#374151;">${escapeHtml(item.produto_descricao || '-')}</div>
                  </div>
                  
                  <!-- Segunda linha: Quantidade - Observação -->
                  <div>
                    <div style="font-size:11px;color:#6b7280;text-transform:uppercase;margin-bottom:4px;">Quantidade</div>
                    <div style="font-weight:600;color:#1f2937;">${formatarQuantidadeExibicao(item.quantidade)}</div>
                  </div>
                  <div style="grid-column:span 2;">
                    <div style="font-size:11px;color:#6b7280;text-transform:uppercase;margin-bottom:4px;">Observação</div>
                    <div style="color:#374151;">${obs}</div>
                  </div>
                  
                  <!-- Terceira linha: Prazo - Previsão - Fornecedor -->
                  <div>
                    <div style="font-size:11px;color:#6b7280;text-transform:uppercase;margin-bottom:4px;">Prazo solicitado</div>
                    <div style="color:#374151;">${fmtDate(item.prazo_solicitado)}</div>
                  </div>
                  <div>
                    <div style="font-size:11px;color:#6b7280;text-transform:uppercase;margin-bottom:4px;">Previsão chegada</div>
                    <div style="color:#374151;">${item.previsao_chegada ? fmtDate(item.previsao_chegada) : '-'}</div>
                  </div>
                  <div>
                    <div style="font-size:11px;color:#6b7280;text-transform:uppercase;margin-bottom:4px;">Fornecedor</div>
                    <div style="color:#374151;">${escapeHtml(item.fornecedor_nome || '-')}</div>
                  </div>
                  
                  <!-- Quarta linha: Status -->
                  <div style="grid-column:span 3;">
                    <div style="font-size:11px;color:#6b7280;text-transform:uppercase;margin-bottom:4px;">Status</div>
                    <div>
                      <span style="padding:6px 12px;border-radius:6px;font-size:12px;font-weight:600;background:#8b5cf6;color:#ffffff;">
                        ${item.status || 'cotado'}
                      </span>
                    </div>
                  </div>
                  
                  <!-- Quinta linha: Anexos -->
                  ${anexosExistentesHtml ? `
                    <div style="grid-column:span 3;">
                      <div style="font-size:11px;color:#6b7280;text-transform:uppercase;margin-bottom:4px;">Anexos</div>
                      <div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;">
                        ${anexosExistentesHtml}
                      </div>
                    </div>
                  ` : ''}
                  
                  <!-- Sexta linha: Cotações recebidas -->
                  <div style="grid-column:span 3;margin-top:12px;">
                    <div style="font-size:11px;color:#6b7280;text-transform:uppercase;margin-bottom:8px;display:flex;align-items:center;gap:6px;">
                      <i class="fa-solid fa-file-invoice-dollar" style="color:#8b5cf6;"></i>
                      Cotações Recebidas
                    </div>
                    <div class="compras-cotacoes-list-cotados" data-item-id="${item.id}" style="display:flex;flex-direction:column;gap:8px;">
                      <!-- Será preenchido via JS -->
                      <div style="color:#9ca3af;font-size:12px;font-style:italic;">Carregando cotações...</div>
                    </div>
                  </div>
                </div>
              </div>
            </td>
          </tr>
        `;
      });

      pedidoIndex++;
    });

    tbody.innerHTML = html;

    // Adiciona event listeners para expandir/colapsar usando função global
    setupComprasExpandListeners();
    
    // Carrega cotações de cada item
    const cotacoesContainers = tbody.querySelectorAll('.compras-cotacoes-list-cotados');
    cotacoesContainers.forEach(container => {
      const itemId = container.getAttribute('data-item-id');
      loadCotacoesItemCotados(itemId);
    });

  } catch (err) {
    console.error('[COMPRAS] Falha ao listar cotados:', err);
    tbody.innerHTML = '<tr><td colspan="6" style="text-align:center;padding:16px;color:#b91c1c;">Erro ao carregar itens cotados.</td></tr>';
  }
}

// Carrega e renderiza cotações para itens cotados (visualização simplificada)
async function loadCotacoesItemCotados(solicitacaoId) {
  const container = document.querySelector(`.compras-cotacoes-list-cotados[data-item-id="${solicitacaoId}"]`);
  if (!container) return;
  
  try {
    const response = await fetch(`/api/compras/cotacoes/${solicitacaoId}`);
    if (!response.ok) throw new Error('Erro ao carregar cotações');
    const cotacoes = await response.json();
    
    if (!Array.isArray(cotacoes)) {
      container.innerHTML = '<div style="color:#9ca3af;font-size:12px;font-style:italic;">Nenhuma cotação encontrada</div>';
      return;
    }
    
    if (cotacoes.length === 0) {
      container.innerHTML = '<div style="color:#9ca3af;font-size:12px;font-style:italic;">Nenhuma cotação adicionada</div>';
      return;
    }
    
    container.innerHTML = cotacoes.map(cotacao => {
      // Parse anexos
      let anexosArray = [];
      if (cotacao.anexos) {
        try {
          anexosArray = typeof cotacao.anexos === 'string' ? JSON.parse(cotacao.anexos) : cotacao.anexos;
          if (!Array.isArray(anexosArray)) anexosArray = [];
        } catch (e) {
          anexosArray = [];
        }
      }
      
      // Define cor e texto baseado no status
      const statusAprovacao = cotacao.status_aprovacao || 'pendente';
      let statusColor, statusBg, statusText;
      
      if (statusAprovacao === 'aprovado') {
        statusColor = '#059669';
        statusBg = '#d1fae5';
        statusText = 'Aprovado';
      } else if (statusAprovacao === 'reprovado') {
        statusColor = '#dc2626';
        statusBg = '#fee2e2';
        statusText = 'Reprovado';
      } else {
        statusColor = '#6b7280';
        statusBg = '#f3f4f6';
        statusText = 'Pendente';
      }
      
      return `
        <div class="cotacao-card" data-cotacao-id="${cotacao.id}" data-status="${statusAprovacao}" style="background:#f9fafb;padding:12px;border:2px solid ${statusAprovacao === 'aprovado' ? '#10b981' : statusAprovacao === 'reprovado' ? '#ef4444' : '#e5e7eb'};border-radius:8px;position:relative;">
          
          <!-- Badge de Status -->
          <div style="position:absolute;top:8px;right:8px;background:${statusBg};color:${statusColor};padding:4px 10px;border-radius:12px;font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:0.5px;">
            ${statusText}
          </div>
          
          <!-- Grid de informações -->
          <div style="display:grid;grid-template-columns:2fr 1fr auto;gap:12px;align-items:center;margin-bottom:${cotacao.observacao ? '8px' : '0'};padding-right:90px;">
            <!-- Fornecedor -->
            <div>
              <div style="font-size:10px;color:#6b7280;text-transform:uppercase;margin-bottom:2px;">Fornecedor</div>
              <div style="font-weight:600;color:#1f2937;font-size:13px;">${escapeHtml(cotacao.fornecedor_nome)}</div>
            </div>
            
            <!-- Valor -->
            <div>
              <div style="font-size:10px;color:#6b7280;text-transform:uppercase;margin-bottom:2px;">Valor</div>
              <div style="font-weight:600;color:#059669;font-size:14px;">R$ ${(parseFloat(cotacao.valor_cotado) || 0).toFixed(2)}</div>
            </div>
            
            <!-- Anexos -->
            <div>
              ${anexosArray.length > 0 ? `
                <div style="display:flex;gap:4px;flex-wrap:wrap;">
                  ${anexosArray.map(anexo => `
                    <a href="${anexo.base64 || anexo.url}" download="${escapeHtml(anexo.nome)}" style="display:flex;align-items:center;gap:4px;background:#dbeafe;padding:4px 8px;border-radius:4px;text-decoration:none;font-size:11px;color:#1e40af;cursor:pointer;" title="${escapeHtml(anexo.nome)}">
                      <i class="fa-solid fa-file"></i>
                      <span style="max-width:60px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${escapeHtml(anexo.nome)}</span>
                    </a>
                  `).join('')}
                </div>
              ` : '<div style="font-size:11px;color:#9ca3af;font-style:italic;">Sem anexos</div>'}
            </div>
          </div>
          
          <!-- Observação (se existir) -->
          ${cotacao.observacao ? `
            <div style="padding-top:8px;border-top:1px solid #e5e7eb;margin-bottom:10px;">
              <div style="font-size:10px;color:#6b7280;text-transform:uppercase;margin-bottom:4px;">Observação</div>
              <div style="font-size:12px;color:#374151;line-height:1.4;">${escapeHtml(cotacao.observacao)}</div>
            </div>
          ` : ''}
          
          <!-- Botões de Ação -->
          <div style="display:flex;gap:8px;margin-top:10px;">
            <button 
              class="btn-aprovar-cotacao" 
              data-cotacao-id="${cotacao.id}"
              style="flex:1;padding:8px 16px;background:${statusAprovacao === 'aprovado' ? '#10b981' : '#fff'};color:${statusAprovacao === 'aprovado' ? '#fff' : '#10b981'};border:2px solid #10b981;border-radius:6px;font-weight:600;font-size:12px;cursor:pointer;transition:all 0.2s;display:flex;align-items:center;justify-content:center;gap:6px;"
              ${statusAprovacao === 'aprovado' ? 'disabled' : ''}
            >
              <i class="fa-solid fa-check-circle"></i>
              <span>Aprovar</span>
            </button>
            <button 
              class="btn-reprovar-cotacao" 
              data-cotacao-id="${cotacao.id}"
              style="flex:1;padding:8px 16px;background:${statusAprovacao === 'reprovado' ? '#ef4444' : '#fff'};color:${statusAprovacao === 'reprovado' ? '#fff' : '#ef4444'};border:2px solid #ef4444;border-radius:6px;font-weight:600;font-size:12px;cursor:pointer;transition:all 0.2s;display:flex;align-items:center;justify-content:center;gap:6px;"
              ${statusAprovacao === 'reprovado' ? 'disabled' : ''}
            >
              <i class="fa-solid fa-times-circle"></i>
              <span>Reprovar</span>
            </button>
          </div>
        </div>
      `;
    }).join('');
    
    // Adiciona event listeners para os botões de aprovar/reprovar
    setTimeout(() => {
      container.querySelectorAll('.btn-aprovar-cotacao').forEach(btn => {
        btn.addEventListener('click', () => atualizarStatusCotacao(btn.dataset.cotacaoId, 'aprovado', solicitacaoId));
      });
      
      container.querySelectorAll('.btn-reprovar-cotacao').forEach(btn => {
        btn.addEventListener('click', () => atualizarStatusCotacao(btn.dataset.cotacaoId, 'reprovado', solicitacaoId));
      });
    }, 100);
    
  } catch (err) {
    console.error('[COTACOES] Erro ao carregar para item cotado:', err);
    container.innerHTML = '<div style="color:#ef4444;font-size:12px;">Erro ao carregar cotações</div>';
  }
}

// Atualiza status de aprovação de uma cotação
async function atualizarStatusCotacao(cotacaoId, status, solicitacaoId) {
  try {
    const response = await fetch(`/api/compras/cotacoes/${cotacaoId}/status`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({ status })
    });
    
    if (!response.ok) throw new Error('Erro ao atualizar status');
    
    // Recarrega as cotações para atualizar a UI
    await loadCotacoesItemCotados(solicitacaoId);
    
    // Verifica se todas as cotações foram marcadas
    verificarCotacoesCompletas(solicitacaoId);
    
  } catch (err) {
    console.error('[COTACOES] Erro ao atualizar status:', err);
    alert('Erro ao atualizar status da cotação');
  }
}

// Verifica se todas as cotações de um item foram marcadas
async function verificarCotacoesCompletas(solicitacaoId) {
  try {
    console.log('[VERIFICACAO] Verificando cotações para item:', solicitacaoId);
    
    const response = await fetch(`/api/compras/cotacoes/${solicitacaoId}`);
    if (!response.ok) return;
    
    const cotacoes = await response.json();
    console.log('[VERIFICACAO] Cotações recebidas:', cotacoes);
    
    if (!Array.isArray(cotacoes) || cotacoes.length === 0) {
      console.log('[VERIFICACAO] Nenhuma cotação encontrada');
      return;
    }
    
    // Verifica se todas as cotações foram marcadas (aprovado ou reprovado)
    const todasMarcadas = cotacoes.every(c => c.status_aprovacao === 'aprovado' || c.status_aprovacao === 'reprovado');
    console.log('[VERIFICACAO] Todas marcadas?', todasMarcadas);
    
    // Verifica se tem pelo menos uma cotação aprovada
    const temAprovada = cotacoes.some(c => c.status_aprovacao === 'aprovado');
    console.log('[VERIFICACAO] Tem aprovada?', temAprovada);
    
    // Busca o container de cotações deste item
    const cotacoesContainer = document.querySelector(`.compras-cotacoes-list-cotados[data-item-id="${solicitacaoId}"]`);
    if (!cotacoesContainer) {
      console.log('[VERIFICACAO] Container de cotações não encontrado');
      return;
    }
    
    console.log('[VERIFICACAO] Container encontrado:', cotacoesContainer);
    
    // Remove QUALQUER container de ações anterior (pode haver múltiplos se houver bug)
    const oldContainers = document.querySelectorAll(`.cotacoes-actions-container[data-solicitacao="${solicitacaoId}"]`);
    oldContainers.forEach(old => old.remove());
    
    if (todasMarcadas) {
      console.log('[VERIFICACAO] Mostrando botões de ação');
      
      // Cria NOVO container de ações
      const actionsContainer = document.createElement('div');
      actionsContainer.className = 'cotacoes-actions-container';
      actionsContainer.dataset.solicitacao = solicitacaoId; // Identificador único
      actionsContainer.style.cssText = 'margin-top:16px;padding:16px;background:#f0fdf4;border:2px solid #10b981;border-radius:8px;display:flex;gap:12px;align-items:center;';
      
      // Verifica se tem pelo menos uma cotação aprovada
      const temAprovada = cotacoes.some(c => c.status_aprovacao === 'aprovado');
      
      actionsContainer.innerHTML = `
        <div style="flex:1;">
          <div style="font-weight:600;color:#059669;margin-bottom:4px;display:flex;align-items:center;gap:8px;">
            <i class="fa-solid fa-check-circle" style="font-size:18px;"></i>
            <span>Todas as cotações foram avaliadas!</span>
          </div>
          <div style="font-size:13px;color:#047857;">
            ${temAprovada ? 'Você pode enviar para compra ou excluir este item.' : 'Todas foram reprovadas. Você pode excluir este item.'}
          </div>
        </div>
        ${temAprovada ? `
          <button 
            class="btn-enviar-compra" 
            data-item-id="${solicitacaoId}"
            style="padding:10px 20px;background:#10b981;color:white;border:none;border-radius:6px;font-weight:600;font-size:13px;cursor:pointer;display:flex;align-items:center;gap:8px;box-shadow:0 2px 4px rgba(16,185,129,0.3);"
          >
            <i class="fa-solid fa-paper-plane"></i>
            <span>Enviar para Compra</span>
          </button>
        ` : ''}
        <button 
          class="btn-excluir-item" 
          data-item-id="${solicitacaoId}"
          style="padding:10px 20px;background:#ef4444;color:white;border:none;border-radius:6px;font-weight:600;font-size:13px;cursor:pointer;display:flex;align-items:center;gap:8px;box-shadow:0 2px 4px rgba(239,68,68,0.3);"
        >
          <i class="fa-solid fa-trash"></i>
          <span>Excluir Item</span>
        </button>
      `;
      
      // Adiciona após o container de cotações
      cotacoesContainer.parentElement.appendChild(actionsContainer);
      
      // Event listeners para os novos botões
      const btnEnviar = actionsContainer.querySelector('.btn-enviar-compra');
      if (btnEnviar) {
        btnEnviar.addEventListener('click', () => enviarParaCompra(solicitacaoId));
      }
      
      const btnExcluir = actionsContainer.querySelector('.btn-excluir-item');
      if (btnExcluir) {
        btnExcluir.addEventListener('click', () => excluirItemCompra(solicitacaoId));
      }
      
      console.log('[VERIFICACAO] Container de ações criado e inserido');
    }
    
  } catch (err) {
    console.error('[COTACOES] Erro ao verificar completude:', err);
  }
}

// Envia item para compra (muda status para "aguardando compra")
async function enviarParaCompra(itemId) {
  if (!confirm('Deseja enviar este item para compra?')) return;
  
  try {
    const response = await fetch(`/api/compras/itens/${itemId}/status`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({ status: 'aguardando compra' })
    });
    
    if (!response.ok) throw new Error('Erro ao enviar para compra');
    
    alert('Item enviado para compra com sucesso!');
    
    // Recarrega a lista de itens cotados
    loadComprasCotadas();
    
  } catch (err) {
    console.error('[COMPRAS] Erro ao enviar para compra:', err);
    alert('Erro ao enviar item para compra');
  }
}

// Exclui um item da solicitação de compra
async function excluirItemCompra(itemId) {
  if (!confirm('Deseja realmente excluir este item? Esta ação não pode ser desfeita.')) return;
  
  try {
    const response = await fetch(`/api/compras/itens/${itemId}`, {
      method: 'DELETE',
      credentials: 'include'
    });
    
    if (!response.ok) throw new Error('Erro ao excluir item');
    
    alert('Item excluído com sucesso!');
    
    // Recarrega a lista de itens cotados
    loadComprasCotadas();
    
  } catch (err) {
    console.error('[COMPRAS] Erro ao excluir item:', err);
    alert('Erro ao excluir item');
  }
}

async function loadComprasRecebimentoLegacy() {
  const tbody = document.getElementById('recebimentoTbody');
  if (!tbody) return;
  tbody.innerHTML = '<tr><td colspan="12" style="text-align:center;padding:16px;color:var(--inactive-color);">Carregando...</td></tr>';
  try {
    const resp = await fetch('/api/compras/todas', { credentials: 'include' });
    if (!resp.ok) throw new Error('Não foi possível carregar as solicitações');
    const data = await resp.json();
    const lista = (Array.isArray(data.solicitacoes) ? data.solicitacoes : [])
      .filter(item => (item.status || '').toLowerCase() === 'compra realizada');

    if (!lista.length) {
      tbody.innerHTML = '<tr><td colspan="12" style="text-align:center;padding:16px;color:var(--inactive-color);">Nenhuma solicitação encontrada com status "compra realizada".</td></tr>';
      return;
    }

    const fmtInputDate = (iso) => {
      if (!iso) return '';
      try {
        const d = new Date(iso);
        if (Number.isNaN(d.getTime())) return '';
        return d.toISOString().slice(0, 10);
      } catch (_) {
        return '';
      }
    };

    tbody.innerHTML = lista.map(item => {
      const prazo = item.prazo_solicitado ? new Date(item.prazo_solicitado).toLocaleDateString('pt-BR') : '-';
      const criado = item.created_at ? new Date(item.created_at).toLocaleString('pt-BR') : '-';
      const previsao = fmtInputDate(item.previsao_chegada);
      const obs = item.observacao ? escapeHtml(item.observacao) : '-';
      const responsavel = item.responsavel ? escapeHtml(item.responsavel) : '-';
      return `
        <tr>
          <td><strong>${escapeHtml(item.numero_pedido || '')}</strong></td>
          <td>${item.id}</td>
          <td>${escapeHtml(item.produto_codigo || '')}</td>
          <td style="max-width:300px;">${escapeHtml(item.produto_descricao || '-')}</td>
          <td>${formatarQuantidadeExibicao(item.quantidade)}</td>
          <td>${escapeHtml(item.solicitante || '-')}</td>
          <td>${prazo}</td>
          <td>${previsao ? new Date(previsao).toLocaleDateString('pt-BR') : ''}</td>
          <td>${responsavel}</td>
          <td><span style="padding:4px 8px;border-radius:6px;background:#3b82f6;color:white;font-size:12px;">${escapeHtml(item.status || 'pendente')}</span></td>
          <td>${obs}</td>
          <td>${criado}</td>
        </tr>
      `;
    }).join('');
  } catch (err) {
    console.error('[recebimento] carregar', err);
    tbody.innerHTML = '<tr><td colspan="12" style="text-align:center;padding:16px;color:var(--inactive-color);">Erro ao carregar dados.</td></tr>';
  }
}

const RECEBIMENTO_FILTER_FIELDS = [
  { key: 'produto', inputId: 'recebimentoFilterProduto' },
  { key: 'pedido', inputId: 'recebimentoFilterPedido' },
  { key: 'etapa', inputId: 'recebimentoFilterEtapa' },
  { key: 'solicitante', inputId: 'recebimentoFilterSolicitante' },
  { key: 'previsao', inputId: 'recebimentoFilterPrevisao' },
  { key: 'responsavel', inputId: 'recebimentoFilterResponsavel' },
  { key: 'fornecedor', inputId: 'recebimentoFilterFornecedor' },
  { key: 'observacao', inputId: 'recebimentoFilterObservacao' },
  { key: 'criadoEm', inputId: 'recebimentoFilterCriadoEm' },
  { key: 'valor', inputId: 'recebimentoFilterValor' },
  { key: 'acoes', inputId: 'recebimentoFilterAcoes' }
];

setTimeout(() => {
  try {
    vincularFiltrosRecebimento();
  } catch (err) {
    console.warn('[recebimento] nao foi possivel vincular filtros no bootstrap:', err);
  }
}, 0);

function obterEstadoRecebimentoCompras() {
  if (!window.__recebimentoComprasState) {
    window.__recebimentoComprasState = {
      rows: [],
      filtrosVinculados: false
    };
  }
  return window.__recebimentoComprasState;
}

function normalizarTextoRecebimento(valor) {
  return String(valor ?? '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .trim();
}

function formatarDataRecebimento(valor, incluirHora = false) {
  if (!valor) return '-';
  const data = new Date(valor);
  if (Number.isNaN(data.getTime())) return String(valor);
  if (incluirHora) {
    return data.toLocaleString('pt-BR', { dateStyle: 'short', timeStyle: 'short' });
  }
  return data.toLocaleDateString('pt-BR');
}

function formatarValorRecebimento(valor) {
  const numero = Number(valor);
  if (!Number.isFinite(numero)) return '-';
  return numero.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
}

function obterFornecedorRecebimento(item) {
  return item?.fornecedor_nome_fantasia || item?.fornecedor_razao_social || '-';
}

function obterFornecedorComplementoRecebimento(item) {
  const partes = [
    item?.fornecedor_razao_social,
    item?.fornecedor_cnpj_cpf,
    item?.fornecedor_cidade
      ? `${item.fornecedor_cidade}${item?.fornecedor_estado ? ` / ${item.fornecedor_estado}` : ''}`
      : item?.fornecedor_estado
  ].filter(Boolean);
  return partes.join(' | ');
}

function obterNfsRecebimento(item) {
  if (Array.isArray(item?.fornecedor_lista_nfes)) return item.fornecedor_lista_nfes;
  return [];
}

function obterTextoAcoesRecebimento(item) {
  const listaNfs = obterNfsRecebimento(item);
  if (listaNfs.length) {
    return listaNfs
      .map(nf => [nf?.numero_nfe, nf?.chave_nfe].filter(Boolean).join(' '))
      .join(' ');
  }
  return item?.fornecedor_lista_numeros_nfe || '';
}

function obterChavePedidoRecebimento(item) {
  const chavePrincipal = item?.n_cod_ped || item?.cnumero;
  if (chavePrincipal !== null && chavePrincipal !== undefined && String(chavePrincipal).trim()) {
    return String(chavePrincipal).trim();
  }

  return [
    item?.fornecedor_cnpj_cpf || 'sem-cnpj',
    item?.d_inc_data || 'sem-data',
    item?.produto_codigo || 'sem-produto'
  ].join('|');
}

function listarItensPedidoRecebimento(itemOuChave) {
  const state = obterEstadoRecebimentoCompras();
  const chave = typeof itemOuChave === 'string'
    ? String(itemOuChave)
    : obterChavePedidoRecebimento(itemOuChave);

  return state.rows.filter((row) => obterChavePedidoRecebimento(row) === chave);
}

function montarContextoPedidoRecebimento(itemOuChave) {
  const itensPedido = listarItensPedidoRecebimento(itemOuChave);
  const base = itensPedido[0] || (typeof itemOuChave === 'object' && itemOuChave ? itemOuChave : {});
  const observacoes = [...new Set(
    itensPedido
      .map((row) => String(row?.observacao || '').trim())
      .filter(Boolean)
  )];

  return {
    cnumero: base?.cnumero || '',
    n_cod_ped: base?.n_cod_ped || '',
    observacao: observacoes.join(' | ') || base?.observacao || '',
    d_inc_data: base?.d_inc_data || '',
    itens: itensPedido.map((row) => ({
      produto_codigo: row?.produto_codigo || '',
      produto_descricao: row?.produto_descricao || '',
      quantidade: row?.quantidade || '',
      unidade: row?.unidade || '',
      valor_item: row?.valor_item || row?.valor_total_pedido || ''
    }))
  };
}

window.obterContextoPedidoRecebimento = montarContextoPedidoRecebimento;

function agruparRecebimentoPorPedido(lista) {
  const mapa = new Map();

  lista.forEach((item) => {
    const chavePedido = obterChavePedidoRecebimento(item);
    if (!mapa.has(chavePedido)) {
      mapa.set(chavePedido, {
        ...item,
        __pedidoKey: chavePedido,
        __pedidoItens: []
      });
    }

    mapa.get(chavePedido).__pedidoItens.push(item);
  });

  return Array.from(mapa.values()).map((grupo) => {
    const observacoes = [...new Set(
      grupo.__pedidoItens
        .map((row) => String(row?.observacao || '').trim())
        .filter(Boolean)
    )];

    const mapaNfs = new Map();
    grupo.__pedidoItens.forEach((row) => {
      obterNfsRecebimento(row).forEach((nf) => {
        const chaveNf = [nf?.chave_nfe || '', nf?.numero_nfe || ''].join('|');
        if (!mapaNfs.has(chaveNf)) mapaNfs.set(chaveNf, nf);
      });
    });

    return {
      ...grupo,
      observacao: observacoes.join(' | ') || grupo.observacao || '',
      fornecedor_lista_nfes: Array.from(mapaNfs.values())
    };
  });
}

function montarIndiceRecebimento(item) {
  const campos = {
    produto: `${item?.produto_codigo || ''} ${item?.produto_descricao || ''} ${item?.quantidade || ''} ${item?.unidade || ''}`,
    pedido: `${item?.cnumero || ''} ${item?.n_cod_ped || ''} ${item?.produto_codigo || ''} ${item?.produto_descricao || ''}`,
    etapa: `${item?.etapa_nf || ''} ${item?.etapa_nf_descricao || ''}`,
    solicitante: item?.solicitante || '',
    previsao: formatarDataRecebimento(item?.previsao_chegada),
    responsavel: item?.resp_inspecao_recebimento || '',
    fornecedor: `${obterFornecedorRecebimento(item)} ${obterFornecedorComplementoRecebimento(item)}`,
    observacao: item?.observacao || '',
    criadoEm: formatarDataRecebimento(item?.d_inc_data),
    valor: `${item?.valor_total_pedido || ''} ${formatarValorRecebimento(item?.valor_total_pedido)}`,
    acoes: obterTextoAcoesRecebimento(item)
  };

  item.__recebimentoCampos = Object.fromEntries(
    Object.entries(campos).map(([chave, valor]) => [chave, normalizarTextoRecebimento(valor)])
  );
  item.__recebimentoSearch = normalizarTextoRecebimento(Object.values(campos).join(' '));
  return item;
}

function coletarFiltrosRecebimento() {
  const filtros = {
    global: normalizarTextoRecebimento(document.getElementById('recebimentoGlobalSearch')?.value || '')
  };

  RECEBIMENTO_FILTER_FIELDS.forEach(({ key, inputId }) => {
    filtros[key] = normalizarTextoRecebimento(document.getElementById(inputId)?.value || '');
  });

  return filtros;
}

function atualizarResumoFiltrosRecebimento(filtros, filtrados, total) {
  const resumo = document.getElementById('recebimentoFilterSummary');
  if (!resumo) return;

  const ativos = [
    filtros.global,
    ...RECEBIMENTO_FILTER_FIELDS.map(({ key }) => filtros[key])
  ].filter(Boolean).length;

  if (!ativos) {
    resumo.textContent = `Sem filtros ativos | ${filtrados} pedido(s)`;
    resumo.style.background = '#eff6ff';
    resumo.style.color = '#1d4ed8';
    return;
  }

  resumo.textContent = `${ativos} filtro(s) ativo(s) | ${filtrados} de ${total} pedido(s)`;
  resumo.style.background = '#fff7ed';
  resumo.style.color = '#c2410c';
}

function renderAcoesRecebimento(item) {
  const listaNfs = obterNfsRecebimento(item);
  if (!listaNfs.length) {
    const textoFallback = item?.fornecedor_lista_numeros_nfe
      ? `NF ${escapeHtml(String(item.fornecedor_lista_numeros_nfe))}`
      : 'Sem NF vinculada';
    return `<span style="display:inline-flex;align-items:center;justify-content:center;padding:6px 10px;border-radius:999px;background:#f1f5f9;color:#475569;font-size:11px;font-weight:600;">${textoFallback}</span>`;
  }

  return listaNfs.map((nf) => {
    const numero = escapeHtml(String(nf?.numero_nfe || '-'));
    const chave = escapeHtml(String(nf?.chave_nfe || ''));
    const pedidoKey = escapeHtml(obterChavePedidoRecebimento(item));
    const valorNf = formatarValorRecebimento(
      nf?.valor_nfe ?? nf?.valor_total ?? nf?.valor ?? null
    );
    const valorNfTexto = escapeHtml(valorNf && valorNf !== '-' ? valorNf : 'sem valor');
    return `
      <button
        type="button"
        data-chave="${chave}"
        data-num="${numero}"
        data-pedidokey="${pedidoKey}"
        onclick="event.stopPropagation();if(window.abrirModalNfeOmieDetalhes&&this.dataset.chave){const contexto=window.obterContextoPedidoRecebimento?window.obterContextoPedidoRecebimento(this.dataset.pedidokey):{};window.abrirModalNfeOmieDetalhes(this.dataset.chave,this.dataset.num,contexto);}"
        style="display:inline-flex;align-items:center;justify-content:flex-start;gap:6px;padding:7px 10px;border:1px solid #bae6fd;border-radius:999px;background:#f0f9ff;color:#0369a1;font-size:11px;font-weight:700;cursor:pointer;max-width:100%;width:100%;text-align:left;white-space:nowrap;"
      >
        <i class="fa-solid fa-file-invoice"></i>
        <span>NF ${numero} - ${valorNfTexto}</span>
      </button>
    `;
  }).join('');
}

function renderRecebimentoTabela(listaFiltrada, totalOriginal) {
  const tbody = document.getElementById('recebimentoTbody');
  const countBadge = document.getElementById('recebimentoCount');
  if (!tbody) return;

  const grupos = agruparRecebimentoPorPedido(listaFiltrada);

  if (countBadge) {
    countBadge.textContent = totalOriginal === grupos.length
      ? `${totalOriginal} pedidos`
      : `${grupos.length} de ${totalOriginal} pedidos`;
  }

  if (!grupos.length) {
    tbody.innerHTML = `
      <tr>
        <td colspan="10" style="text-align:center;padding:32px 16px;color:#64748b;">
          <i class="fa-solid fa-filter-circle-xmark" style="font-size:22px;margin-bottom:10px;display:block;color:#94a3b8;"></i>
          Nenhum pedido encontrado com os filtros atuais.
        </td>
      </tr>
    `;
    return;
  }

  tbody.innerHTML = grupos.map((item) => {
    const pedidoNumero = escapeHtml(String(item?.cnumero || item?.n_cod_ped || '-'));
    const etapaCor = item?.etapa_nf_cor || '#f59e0b';
    const etapaTexto = escapeHtml(item?.etapa_nf_descricao || item?.etapa_nf || '-');
    const solicitante = escapeHtml(item?.solicitante || '-');
    const previsao = escapeHtml(formatarDataRecebimento(item?.previsao_chegada));
    const responsavel = escapeHtml(item?.resp_inspecao_recebimento || '-');
    const fornecedorNome = escapeHtml(obterFornecedorRecebimento(item));
    const fornecedorComplemento = obterFornecedorComplementoRecebimento(item);
    const observacaoCompleta = escapeHtml(item?.observacao || '-');
    const criadoEm = escapeHtml(formatarDataRecebimento(item?.d_inc_data));
    const valor = escapeHtml(formatarValorRecebimento(item?.valor_total_pedido));
    const itensDoPedido = listarItensPedidoRecebimento(item.__pedidoKey);
    const itensVisiveis = Array.isArray(item.__pedidoItens) && item.__pedidoItens.length ? item.__pedidoItens : itensDoPedido;
    const totalItensPedido = itensDoPedido.length || itensVisiveis.length || 0;
    const produtosHtml = itensVisiveis.map((produto) => {
      const produtoCodigo = escapeHtml(produto?.produto_codigo || '-');
      const produtoDescricao = escapeHtml(produto?.produto_descricao || '-');
      const quantidade = produto?.quantidade ? formatarQuantidadeExibicao(produto.quantidade) : '-';
      const unidade = escapeHtml(produto?.unidade || '');

      return `
        <div style="padding:8px 10px;border-radius:8px;background:#fff;border:1px solid #dbeafe;">
          <div style="font-weight:700;color:#1e3a8a;">${produtoCodigo}</div>
          <div style="font-size:12px;color:#475569;margin-top:4px;line-height:1.45;">${produtoDescricao}</div>
          <div style="display:inline-flex;align-items:center;gap:6px;margin-top:8px;padding:4px 8px;border-radius:999px;background:#eff6ff;color:#1d4ed8;font-size:11px;font-weight:700;">
            <i class="fa-solid fa-boxes-stacked"></i>
            <span>${escapeHtml(String(quantidade))}${unidade ? ` ${unidade}` : ''}</span>
          </div>
        </div>
      `;
    }).join('');
    const notaFiltroItens = itensVisiveis.length && totalItensPedido > itensVisiveis.length
      ? `<div style="font-size:11px;color:#64748b;margin:0 0 8px;">Mostrando ${itensVisiveis.length} item(ns) filtrado(s) deste pedido.</div>`
      : '';
    const botaoVerItens = totalItensPedido
      ? `
        <details class="recebimento-detalhes-inline" style="display:inline-block;position:relative;">
          <summary style="cursor:pointer;display:inline-flex;align-items:center;gap:6px;padding:4px 9px;border-radius:999px;background:#f8fafc;color:#334155;font-size:11px;font-weight:700;border:1px solid #cbd5e1;list-style:none;">
            <i class="fa-solid fa-eye" style="color:#64748b;"></i>
            <span>Ver</span>
          </summary>
          <div class="recebimento-popover-itens" style="position:absolute;top:calc(100% + 8px);left:0;z-index:30;width:min(420px,70vw);padding:10px;border-radius:12px;background:#f8fafc;border:1px solid #cbd5e1;box-shadow:0 12px 28px rgba(15,23,42,.16);">
            ${notaFiltroItens}
            <div style="display:flex;flex-direction:column;gap:8px;">
              ${produtosHtml}
            </div>
          </div>
        </details>
      `
      : '';

    return `
      <tr style="border-bottom:1px solid #e2e8f0;">
        <td style="padding:14px 16px;vertical-align:top;border-bottom:1px solid #e2e8f0;min-width:260px;">
          <div style="font-weight:700;color:#1d4ed8;display:flex;align-items:center;gap:8px;flex-wrap:wrap;">
            <span>${pedidoNumero}</span>
            <span style="display:inline-flex;align-items:center;gap:6px;padding:4px 9px;border-radius:999px;background:#dbeafe;color:#1d4ed8;font-size:11px;font-weight:700;">
              <i class="fa-solid fa-boxes-stacked"></i>
              <span>${totalItensPedido}</span>
            </span>
            ${botaoVerItens}
          </div>
        </td>
        <td style="padding:14px 16px;vertical-align:top;border-bottom:1px solid #e2e8f0;">
          <span style="display:inline-flex;align-items:center;padding:6px 10px;border-radius:999px;background:${escapeHtml(etapaCor)}18;color:${escapeHtml(etapaCor)};font-size:11px;font-weight:700;border:1px solid ${escapeHtml(etapaCor)}40;">
            ${etapaTexto}
          </span>
        </td>
        <td class="recebimento-coluna-texto" style="padding:14px 16px;vertical-align:top;border-bottom:1px solid #e2e8f0;">${solicitante}</td>
        <td class="recebimento-coluna-texto" style="padding:14px 16px;vertical-align:top;border-bottom:1px solid #e2e8f0;">${previsao}</td>
        <td class="recebimento-coluna-texto" style="padding:14px 16px;vertical-align:top;border-bottom:1px solid #e2e8f0;">${responsavel}</td>
        <td style="padding:14px 16px;vertical-align:top;border-bottom:1px solid #e2e8f0;min-width:230px;">
          <div class="recebimento-fornecedor-nome" style="font-weight:700;color:#0f172a;">${fornecedorNome}</div>
          ${fornecedorComplemento ? `<div class="recebimento-coluna-texto" style="font-size:11px;color:#64748b;line-height:1.45;margin-top:4px;">${escapeHtml(fornecedorComplemento)}</div>` : ''}
        </td>
        <td style="padding:14px 16px;vertical-align:top;max-width:220px;border-bottom:1px solid #e2e8f0;">
          <div class="recebimento-observacao-texto" title="${observacaoCompleta}" style="font-size:12px;color:#334155;line-height:1.45;word-break:break-word;display:-webkit-box;-webkit-line-clamp:4;-webkit-box-orient:vertical;overflow:hidden;text-overflow:ellipsis;cursor:help;max-width:220px;">
            ${observacaoCompleta}
          </div>
        </td>
        <td style="padding:14px 16px;vertical-align:top;border-bottom:1px solid #e2e8f0;">${criadoEm}</td>
        <td style="padding:14px 16px;vertical-align:top;text-align:right;border-bottom:1px solid #e2e8f0;font-weight:700;color:#047857;white-space:nowrap;">${valor}</td>
        <td style="padding:14px 16px;vertical-align:top;text-align:center;border-bottom:1px solid #e2e8f0;min-width:220px;">
          <div style="display:flex;flex-direction:column;align-items:stretch;gap:6px;">
            ${renderAcoesRecebimento(item)}
          </div>
        </td>
      </tr>
    `;
  }).join('');
}

function aplicarFiltrosRecebimento() {
  const state = obterEstadoRecebimentoCompras();
  const filtros = coletarFiltrosRecebimento();
  const listaFiltrada = state.rows.filter((item) => {
    if (filtros.global && !item.__recebimentoSearch.includes(filtros.global)) return false;
    return RECEBIMENTO_FILTER_FIELDS.every(({ key }) => {
      const valorFiltro = filtros[key];
      if (!valorFiltro) return true;
      return (item.__recebimentoCampos?.[key] || '').includes(valorFiltro);
    });
  });

  const totalPedidos = agruparRecebimentoPorPedido(state.rows).length;
  const pedidosFiltrados = agruparRecebimentoPorPedido(listaFiltrada).length;

  renderRecebimentoTabela(listaFiltrada, totalPedidos);
  atualizarResumoFiltrosRecebimento(filtros, pedidosFiltrados, totalPedidos);
}

function vincularFiltrosRecebimento() {
  const state = obterEstadoRecebimentoCompras();
  if (state.filtrosVinculados) return;

  const elementos = [
    document.getElementById('recebimentoGlobalSearch'),
    ...RECEBIMENTO_FILTER_FIELDS.map(({ inputId }) => document.getElementById(inputId))
  ].filter(Boolean);

  elementos.forEach((el) => {
    el.addEventListener('input', aplicarFiltrosRecebimento);
  });

  document.getElementById('recebimentoClearFiltersBtn')?.addEventListener('click', () => {
    elementos.forEach((el) => {
      el.value = '';
    });
    aplicarFiltrosRecebimento();
    document.getElementById('recebimentoGlobalSearch')?.focus();
  });

  document.getElementById('menu-recebimento')?.addEventListener('click', async (event) => {
    event.preventDefault();
    event.stopImmediatePropagation();
    abrirLocalizarNfePeloMenuRecebimento();
  });

  document.getElementById('recebimentoRefreshBtn')?.addEventListener('click', async () => {
    await loadComprasRecebimento(true);
  });

  state.filtrosVinculados = true;
}

async function loadComprasRecebimento(forceReload = false) {
  const state = obterEstadoRecebimentoCompras();
  const tbody = document.getElementById('recebimentoTbody');
  const btnRecarregar = document.getElementById('recebimentoRefreshBtn');
  if (!tbody) return;

  vincularFiltrosRecebimento();

  if (!forceReload && state.rows.length) {
    aplicarFiltrosRecebimento();
    return;
  }

  if (btnRecarregar) btnRecarregar.disabled = true;
  tbody.innerHTML = '<tr><td colspan="10" style="text-align:center;padding:24px;color:var(--inactive-color);">Carregando recebimentos...</td></tr>';

  try {
    const resp = await fetch('/api/compras/solicitacoes-recebimento', { credentials: 'include' });
    if (!resp.ok) throw new Error('Nao foi possivel carregar os recebimentos.');

    const data = await resp.json();
    const listaBruta = Array.isArray(data)
      ? data
      : Array.isArray(data?.solicitacoes)
        ? data.solicitacoes
        : Array.isArray(data?.items)
          ? data.items
          : [];

    state.rows = listaBruta.map((item) => montarIndiceRecebimento({ ...item }));
    aplicarFiltrosRecebimento();
  } catch (err) {
    console.error('[recebimento] carregar', err);
    state.rows = [];
    tbody.innerHTML = '<tr><td colspan="10" style="text-align:center;padding:24px;color:#b91c1c;">Erro ao carregar os dados de recebimento.</td></tr>';
    atualizarResumoFiltrosRecebimento({ global: '', produto: '', pedido: '', etapa: '', solicitante: '', previsao: '', responsavel: '', fornecedor: '', observacao: '', criadoEm: '', valor: '', acoes: '' }, 0, 0);
  } finally {
    if (btnRecarregar) btnRecarregar.disabled = false;
  }
}

// ========== Modal de Ações do Kanban (Hamburger) ==========
function abrirModalComprasAcoes() {
  const modal = document.getElementById('modalComprasAcoes');
  if (modal) {
    modal.style.display = 'flex';
  }
}

function fecharModalComprasAcoes() {
  const modal = document.getElementById('modalComprasAcoes');
  if (modal) {
    modal.style.display = 'none';
  }
}

/**
 * Varredura leve da coluna Faturada: atualiza SQL com o que está na Omie
 * (etapa 40 + órfãos locais), sem varrer os milhares de NF-e históricas.
 */
async function varrerFaturadasOmieKanban() {
  const btn = document.getElementById('comprasVarrerFaturadasBtn');
  if (btn?.disabled) return;

  const okConfirm = window.confirm(
    'Varrer a coluna "Faturada pelo fornecedor" com a Omie?\n\n' +
    'Isso atualiza só essa coluna (leve, sem sobrecarregar a Omie) e remove NF-e que já não existem lá.'
  );
  if (!okConfirm) return;

  const textoOriginal = btn ? btn.innerHTML : '';
  if (btn) {
    btn.disabled = true;
    btn.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i><span class="compras-acao-text">Varrendo…</span>';
  }

  try {
    const resp = await fetch('/api/compras/kanban/varrer-faturadas', {
      method: 'POST',
      credentials: 'include',
      headers: { 'Content-Type': 'application/json' },
      body: '{}'
    });
    const data = await resp.json().catch(() => ({}));

    if (resp.status === 409) {
      alert(data.error || 'Já existe uma varredura em andamento.');
      return;
    }
    if (!resp.ok || !data.ok) {
      throw new Error(data.error || data.erro || `Falha HTTP ${resp.status}`);
    }

    const tempo = data.tempo_formatado || `${Math.round((data.duracao_ms || 0) / 1000)}s`;
    alert(
      'Varredura concluída (' + tempo + ').\n\n' +
      'Atualizados na lista Omie: ' + (data.upsertados || 0) + '\n' +
      'Órfãos atualizados: ' + (data.atualizados_orfaos || 0) + '\n' +
      'Removidos (excluídos na Omie): ' + (data.removidos || 0) + '\n' +
      'Erros: ' + (data.erros || 0) + '\n\n' +
      'O kanban será recarregado.'
    );

    if (typeof loadMinhasSolicitacoes === 'function') {
      loadMinhasSolicitacoes();
    }
  } catch (err) {
    console.error('[Compras] Varredura Faturadas:', err);
    alert('Erro na varredura: ' + (err.message || err));
  } finally {
    if (btn) {
      btn.disabled = false;
      btn.innerHTML = textoOriginal ||
        '<i class="fa-solid fa-magnifying-glass-chart"></i><span class="compras-acao-text">Varrer Faturadas (Omie)</span>';
    }
  }
}
window.varrerFaturadasOmieKanban = varrerFaturadasOmieKanban;

// ========== Funções de Filtro de Kanbans ==========

// Variável global para armazenar kanbans visíveis do usuário
let kanbansVisiveis = [];
let estadoInicialFiltroKanbans = null;
const DATA_LIMITE_PADRAO = '2026-02-01';

// Variável global para controlar filtro por solicitante (padrão: todas as solicitações)
window.kanbanFiltroSolicitante = 'todas';

function formatarDataLimite(valor) {
  if (!valor) return '';
  const texto = String(valor).trim();
  if (/^\d{4}-\d{2}-\d{2}$/.test(texto)) {
    const [y, m, d] = texto.split('-');
    return `${d}/${m}/${y.slice(-2)}`;
  }
  return texto;
}

function normalizarDataLimite(valor) {
  const texto = String(valor || '').trim();
  if (!texto) return '';
  if (/^\d{4}-\d{2}-\d{2}$/.test(texto)) return texto;
  const match = texto.match(/^(\d{2})\/(\d{2})\/(\d{2}|\d{4})$/);
  if (!match) return '';
  const dia = match[1];
  const mes = match[2];
  const ano = match[3].length === 2 ? `20${match[3]}` : match[3];
  return `${ano}-${mes}-${dia}`;
}

function obterDatasLimiteKanban() {
  try {
    const raw = localStorage.getItem('kanbanDatasLimite');
    const data = raw ? JSON.parse(raw) : {};
    return data && typeof data === 'object' ? data : {};
  } catch {
    return {};
  }
}

function salvarDatasLimiteKanban(map) {
  localStorage.setItem('kanbanDatasLimite', JSON.stringify(map || {}));
}

// Lê do localStorage quais kanbans podem aparecer mesmo com zero itens
function obterKanbansVaziosVisiveis() {
  const raw = localStorage.getItem('kanbansVaziosVisiveis');
  if (!raw) return [];
  try {
    const arr = JSON.parse(raw);
    return Array.isArray(arr) ? arr.filter(Boolean) : [];
  } catch (err) {
    console.warn('[FILTRO] Erro ao ler kanbans vazios:', err);
    return [];
  }
}

// Lista de todos os kanbans disponíveis (deve corresponder aos statusColunas)
const todosKanbans = [
  'aguardando aprovação da requisição',
  'solicitado revisão',
  'aguardando cotação',
  'cotado aguardando escolha',
  'analise de cadastro',
  'aguardando compra preparação',
  'compra realizada',
  'faturada pelo fornecedor',
  'recebido',
  'concluído'
];

function normalizarListaKanbans(lista = []) {
  return Array.from(new Set((Array.isArray(lista) ? lista : []).filter(Boolean)))
    .sort((a, b) => a.localeCompare(b, 'pt-BR', { sensitivity: 'base' }));
}

function listasKanbansIguais(a = [], b = []) {
  if (a.length !== b.length) return false;
  return a.every((valor, idx) => valor === b[idx]);
}

function normalizarMapaDatasLimite(map = {}) {
  const normalizado = {};
  todosKanbans.forEach(kanban => {
    normalizado[kanban] = normalizarDataLimite(map[kanban]) || DATA_LIMITE_PADRAO;
  });
  return normalizado;
}

function mapasDataLimiteIguais(a = {}, b = {}) {
  return todosKanbans.every(kanban => {
    const valorA = normalizarDataLimite(a[kanban]) || DATA_LIMITE_PADRAO;
    const valorB = normalizarDataLimite(b[kanban]) || DATA_LIMITE_PADRAO;
    return valorA === valorB;
  });
}

function coletarEstadoFiltroKanbansModal() {
  const checkboxesVisivel = document.querySelectorAll('#listaFiltroKanbans .kanban-visivel-checkbox');
  const checkboxesVazio = document.querySelectorAll('#listaFiltroKanbans .kanban-vazio-checkbox');
  const inputsDataLimite = document.querySelectorAll('#listaFiltroKanbans .kanban-data-limite');

  if (!checkboxesVisivel.length) return null;

  let visiveis = Array.from(checkboxesVisivel)
    .filter(cb => cb.checked)
    .map(cb => cb.value);

  let vazios = Array.from(checkboxesVazio)
    .filter(cb => cb.checked)
    .map(cb => cb.value);

  // Mantém a consistência: "mesmo vazio" implica "visível".
  const visiveisSet = new Set(visiveis);
  vazios.forEach(kanban => visiveisSet.add(kanban));
  visiveis = Array.from(visiveisSet);
  vazios = vazios.filter(kanban => visiveisSet.has(kanban));

  const datasLimite = {};
  inputsDataLimite.forEach(input => {
    const kanban = input.getAttribute('data-kanban');
    if (!kanban) return;
    datasLimite[kanban] = normalizarDataLimite(input.value) || DATA_LIMITE_PADRAO;
  });

  return {
    visiveis: normalizarListaKanbans(visiveis),
    vazios: normalizarListaKanbans(vazios),
    datasLimite: normalizarMapaDatasLimite(datasLimite)
  };
}

// Abre o modal de filtro de kanbans
async function abrirModalFiltroKanbans() {
  const modal = document.getElementById('modalFiltroKanbans');
  if (!modal) return;
  
  // Carrega preferências do usuário
  await carregarPreferenciasKanbans();
  
  // Carrega preferência de kanbans que podem aparecer vazios
  const kanbansVaziosVisiveis = obterKanbansVaziosVisiveis();
  
  // Popula checkboxes
  const checkboxContainer = document.getElementById('listaFiltroKanbans');
  if (!checkboxContainer) return;

  const datasLimite = obterDatasLimiteKanban();
  
  // Títulos personalizados
  const titulosPersonalizados = {
    'aguardando cotação': 'Cotação com compras',
    'aguardando compra preparação': 'Requisições',
    'analise de cadastro': 'Organizando requisição'
  };
  
  // Badges identificadores para cada kanban
  const badgesKanban = {
    'aguardando aprovação da requisição': { texto: 'Operação Aprovador', cor: '#2563eb' },
    'aguardando cotação': { texto: 'Operação Comprador', cor: '#059669' },
    'cotado aguardando escolha': { texto: 'Ação Requisitante', cor: '#dc2626' },
    'solicitado revisão': { texto: 'Ação Requisitante', cor: '#dc2626' },
    'analise de cadastro': { texto: 'Operação Comprador', cor: '#059669' },
    'aguardando compra preparação': { texto: 'Operação Comprador', cor: '#059669' },
    'compra realizada': { texto: 'Ação Recebimento', cor: '#d97706' },
    'faturada pelo fornecedor': { texto: 'Ação Recebimento', cor: '#d97706' },
    'recebido': { texto: 'Setores de Liberação', cor: '#7c3aed' },
    'concluído': { texto: '', cor: '' }
  };
  
  checkboxContainer.innerHTML = todosKanbans.map(kanban => {
    const tituloExibir = titulosPersonalizados[kanban] || (kanban.charAt(0).toUpperCase() + kanban.slice(1));
    const checkedVazio = kanbansVaziosVisiveis.includes(kanban) ? 'checked' : '';
    const checkedVisivel = (kanbansVisiveis.includes(kanban) || checkedVazio) ? 'checked' : '';
    const badge = badgesKanban[kanban] || { texto: '', cor: '' };

    const dataLimite = datasLimite[kanban] || DATA_LIMITE_PADRAO;
    const dataLimiteExibir = formatarDataLimite(dataLimite);

    return `
      <div data-kanban="${kanban}" style="display:grid;grid-template-columns:1fr 110px 160px 120px;gap:10px;align-items:center;padding:10px;border-radius:6px;transition:all 0.2s;border:1px solid transparent;background:transparent;" 
           onmouseover="this.style.borderColor='#3b82f6';this.style.background='transparent'" 
           onmouseout="this.style.borderColor='transparent';this.style.background='transparent'">
        <div style="display:flex;flex-direction:column;gap:4px;">
          <span style="font-size:14px;color:#ffffff;font-weight:500;">${tituloExibir}</span>
          ${badge.texto ? `<span style="background:${badge.cor};color:white;padding:2px 8px;border-radius:4px;font-size:10px;font-weight:600;text-transform:uppercase;letter-spacing:0.3px;width:fit-content;">${badge.texto}</span>` : ''}
        </div>
        <label style="display:flex;align-items:center;justify-content:center;gap:8px;cursor:pointer;">
          <input type="checkbox" class="kanban-visivel-checkbox" value="${kanban}" ${checkedVisivel} style="width:18px;height:18px;cursor:pointer;">
          <span style="font-size:12px;color:#e5e7eb;">Visível</span>
        </label>
        <label style="display:flex;align-items:center;justify-content:center;gap:8px;cursor:pointer;">
          <input type="checkbox" class="kanban-vazio-checkbox" value="${kanban}" ${checkedVazio} style="width:18px;height:18px;cursor:pointer;">
          <span style="font-size:12px;color:#e5e7eb;">Mesmo vazio</span>
        </label>
        <div style="display:flex;justify-content:center;">
          <div style="position:relative;width:100%;max-width:120px;">
            <input type="text" class="kanban-data-limite" data-kanban="${kanban}" value="${dataLimiteExibir}" placeholder="dd/mm/aa" style="width:100%;padding:6px 28px 6px 8px;border:1px solid #1e293b;border-radius:6px;background:#0f172a;color:#e5e7eb;font-size:12px;box-sizing:border-box;">
            <button type="button" class="kanban-data-limite-btn" data-kanban="${kanban}" style="position:absolute;right:4px;top:50%;transform:translateY(-50%);background:transparent;border:none;color:#93c5fd;cursor:pointer;padding:2px;">
              <i class="fa-solid fa-calendar"></i>
            </button>
            <input type="date" class="kanban-data-limite-picker" data-kanban="${kanban}" value="${dataLimite}" style="position:absolute;opacity:0;pointer-events:none;width:0;height:0;">
          </div>
        </div>
      </div>
    `;
  }).join('');

  // Bind do ícone de calendário e sincronização com input de texto
  const botoesData = checkboxContainer.querySelectorAll('.kanban-data-limite-btn');
  const pickersData = checkboxContainer.querySelectorAll('.kanban-data-limite-picker');
  const inputsTexto = checkboxContainer.querySelectorAll('.kanban-data-limite');
  const inputGlobal = document.getElementById('kanbanDataLimiteGlobal');
  const inputGlobalBtn = document.getElementById('kanbanDataLimiteGlobalBtn');
  const inputGlobalPicker = document.getElementById('kanbanDataLimiteGlobalPicker');

  const abrirPicker = (picker) => {
    if (!picker) return;
    try {
      if (typeof picker.showPicker === 'function') {
        picker.showPicker();
        return;
      }
    } catch (_) {
      // fallback abaixo
    }
    picker.focus();
    picker.click();
  };

  botoesData.forEach(btn => {
    btn.addEventListener('click', () => {
      const kanban = btn.getAttribute('data-kanban');
      const picker = checkboxContainer.querySelector(`.kanban-data-limite-picker[data-kanban="${kanban}"]`);
      abrirPicker(picker);
    });
  });

  pickersData.forEach(picker => {
    picker.addEventListener('change', () => {
      const kanban = picker.getAttribute('data-kanban');
      const input = checkboxContainer.querySelector(`.kanban-data-limite[data-kanban="${kanban}"]`);
      if (!input) return;
      input.value = formatarDataLimite(picker.value);
    });
  });

  inputsTexto.forEach(input => {
    input.addEventListener('change', () => {
      const kanban = input.getAttribute('data-kanban');
      const picker = checkboxContainer.querySelector(`.kanban-data-limite-picker[data-kanban="${kanban}"]`);
      if (!picker) return;
      const normalizada = normalizarDataLimite(input.value);
      picker.value = normalizada || '';
    });
  });

  const aplicarDataGlobal = (valor) => {
    const normalizada = normalizarDataLimite(valor);
    const valorExibir = formatarDataLimite(normalizada || DATA_LIMITE_PADRAO);

    if (inputGlobal) inputGlobal.value = valorExibir;
    if (inputGlobalPicker) inputGlobalPicker.value = normalizada || '';

    inputsTexto.forEach(input => {
      input.value = valorExibir;
      const kanban = input.getAttribute('data-kanban');
      const picker = checkboxContainer.querySelector(`.kanban-data-limite-picker[data-kanban="${kanban}"]`);
      if (picker) picker.value = normalizada || '';
    });
  };

  if (inputGlobal) {
    inputGlobal.value = formatarDataLimite(DATA_LIMITE_PADRAO);
    inputGlobal.addEventListener('change', () => aplicarDataGlobal(inputGlobal.value));
  }

  if (inputGlobalBtn && inputGlobalPicker) {
    inputGlobalBtn.addEventListener('click', () => {
      abrirPicker(inputGlobalPicker);
    });

    inputGlobalPicker.addEventListener('change', () => {
      aplicarDataGlobal(inputGlobalPicker.value);
    });
  }

  // Regras de consistência entre visível e vazio
  const visivelCheckboxes = checkboxContainer.querySelectorAll('.kanban-visivel-checkbox');
  const vazioCheckboxes = checkboxContainer.querySelectorAll('.kanban-vazio-checkbox');

  vazioCheckboxes.forEach(cb => {
    cb.addEventListener('change', () => {
      if (cb.checked) {
        const row = cb.closest('[data-kanban]');
        const visivel = row?.querySelector('.kanban-visivel-checkbox');
        if (visivel) visivel.checked = true;
      }
    });
  });

  visivelCheckboxes.forEach(cb => {
    cb.addEventListener('change', () => {
      if (!cb.checked) {
        const row = cb.closest('[data-kanban]');
        const vazio = row?.querySelector('.kanban-vazio-checkbox');
        if (vazio) vazio.checked = false;
      }
    });
  });

  estadoInicialFiltroKanbans = coletarEstadoFiltroKanbansModal();
  modal.style.display = 'flex';
}

// Fecha o modal de filtro
function fecharModalFiltroKanbans() {
  const modal = document.getElementById('modalFiltroKanbans');
  if (modal) modal.style.display = 'none';
  estadoInicialFiltroKanbans = null;
}

// Carrega preferências de kanbans visíveis do servidor
async function carregarPreferenciasKanbans() {
  try {
    const resp = await fetch('/api/compras/filtro-kanbans', {
      credentials: 'include'
    });
    
    if (!resp.ok) {
      console.warn('[FILTRO] Erro ao carregar preferências, usando padrão');
      kanbansVisiveis = [...todosKanbans]; // Todos visíveis por padrão
      return;
    }
    
    const data = await resp.json();
    kanbansVisiveis = data.kanbans_visiveis || [...todosKanbans];
    
  } catch (err) {
    console.error('[FILTRO] Erro ao carregar preferências:', err);
    kanbansVisiveis = [...todosKanbans]; // Fallback: todos visíveis
  }
}

// Salva preferências de kanbans visíveis no servidor
async function salvarPreferenciasKanbans() {
  try {
    const estadoAtual = coletarEstadoFiltroKanbansModal();
    if (!estadoAtual) {
      fecharModalFiltroKanbans();
      return;
    }

    const estadoBase = estadoInicialFiltroKanbans || {
      visiveis: normalizarListaKanbans(kanbansVisiveis),
      vazios: normalizarListaKanbans(obterKanbansVaziosVisiveis()),
      datasLimite: normalizarMapaDatasLimite(obterDatasLimiteKanban())
    };

    const alterouVisiveis = !listasKanbansIguais(estadoAtual.visiveis, estadoBase.visiveis);
    const alterouVazios = !listasKanbansIguais(estadoAtual.vazios, estadoBase.vazios);
    const alterouDatas = !mapasDataLimiteIguais(estadoAtual.datasLimite, estadoBase.datasLimite);
    const houveAlteracao = alterouVisiveis || alterouVazios || alterouDatas;

    // Sem alterações: apenas fecha, sem POST e sem recarregar kanban/lista.
    if (!houveAlteracao) {
      fecharModalFiltroKanbans();
      return;
    }

    // Salva preferência de kanbans que podem aparecer vazios no localStorage
    localStorage.setItem('kanbansVaziosVisiveis', JSON.stringify(estadoAtual.vazios));

    // Salva datas limite por kanban no localStorage
    salvarDatasLimiteKanban(estadoAtual.datasLimite);

    // Só grava no banco se o conjunto de kanbans visíveis realmente mudou.
    if (alterouVisiveis) {
      const resp = await fetch('/api/compras/filtro-kanbans', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({ kanbans_visiveis: estadoAtual.visiveis })
      });

      if (!resp.ok) {
        throw new Error('Falha ao salvar preferências');
      }
    }

    // Atualiza variável global
    kanbansVisiveis = estadoAtual.visiveis;

    // Aplica filtro visualmente
    aplicarFiltroKanbans();

    // Recarrega os kanbans apenas quando houve alteração salva/aplicada.
    await loadMinhasSolicitacoes();

    // Fecha modal
    fecharModalFiltroKanbans();
    
    // Feedback visual
    const btn = document.querySelector('[onclick="abrirModalFiltroKanbans()"]');
    if (btn) {
      const originalBg = btn.style.background;
      btn.style.background = '#10b981';
      btn.style.color = 'white';
      setTimeout(() => {
        btn.style.background = originalBg;
        btn.style.color = '';
      }, 800);
    }
    
  } catch (err) {
    console.error('[FILTRO] Erro ao salvar preferências:', err);
    alert('Erro ao salvar preferências de filtro. Tente novamente.');
  }
}

// Aplica o filtro de kanbans (oculta/mostra colunas)
function deveExibirKanbanPorFiltro(statusNormalizado, count = 0) {
  if (!statusNormalizado) return false;
  if (!kanbansVisiveis.includes(statusNormalizado)) return false;

  if (count <= 0) {
    const kanbansVaziosVisiveis = obterKanbansVaziosVisiveis();
    if (!kanbansVaziosVisiveis.includes(statusNormalizado)) return false;
  }

  return true;
}

function aplicarFiltroKanbans() {
  const kanbanContainer = document.getElementById('kanbanMinhasSolicitacoes');
  if (!kanbanContainer) return;

  // Pega todas as colunas do kanban
  const colunas = kanbanContainer.querySelectorAll('.kanban-column-minhas');
  
  colunas.forEach(coluna => {
    // Pega o status normalizado diretamente do atributo data-status
    const statusNormalizado = coluna.getAttribute('data-status');
    if (!statusNormalizado) return;
    
    // Pega a quantidade de itens no kanban
    const countElement = coluna.querySelector('.kanban-count-minhas');
    const count = countElement ? parseInt(countElement.textContent) || 0 : 0;
    
    // Lógica de exibição:
    // 1. Se o kanban não está na lista de visíveis: oculta
    // 2. Se está na lista de visíveis mas tem 0 itens e "mostrarVazios" está desativado: oculta
    // 3. Caso contrário: mostra
    coluna.style.display = deveExibirKanbanPorFiltro(statusNormalizado, count) ? '' : 'none';
  });
}

function filtrarItensPorDataLimite(status, itens) {
  const statusNormalizado = String(status || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .trim();

  // Para etapas da NF, exibe todos os pedidos independentemente da data de inclusão.
  if (['faturada pelo fornecedor', 'recebido', 'concluido'].includes(statusNormalizado)) {
    return itens;
  }

  const datasLimite = obterDatasLimiteKanban();
  const limite = datasLimite[status] || DATA_LIMITE_PADRAO;
  if (!limite) return itens;

  const limiteNormalizado = normalizarDataLimite(limite) || DATA_LIMITE_PADRAO;
  const limiteDate = new Date(`${limiteNormalizado}T00:00:00`);
  if (Number.isNaN(limiteDate.getTime())) return itens;

  return itens.filter(item => {
    if (!item.d_inc_data) return true;
    const dataItem = new Date(item.d_inc_data);
    if (Number.isNaN(dataItem.getTime())) return true;
    return dataItem >= limiteDate;
  });
}

// Seleciona/desmarca todos os checkboxes
function toggleSelecionarTodosKanbans() {
  const checkboxesVisivel = document.querySelectorAll('#listaFiltroKanbans .kanban-visivel-checkbox');
  const checkboxesVazio = document.querySelectorAll('#listaFiltroKanbans .kanban-vazio-checkbox');
  const todosMarcados = Array.from(checkboxesVisivel).every(cb => cb.checked);
  
  checkboxesVisivel.forEach(cb => {
    cb.checked = !todosMarcados;
  });

  if (todosMarcados) {
    checkboxesVazio.forEach(cb => {
      cb.checked = false;
    });
  }
}

// Seleciona/desmarca todos os checkboxes da coluna "Visível mesmo vazio"
function toggleSelecionarTodosKanbansVazios() {
  const checkboxesVisivel = document.querySelectorAll('#listaFiltroKanbans .kanban-visivel-checkbox');
  const checkboxesVazio = document.querySelectorAll('#listaFiltroKanbans .kanban-vazio-checkbox');
  const todosMarcados = Array.from(checkboxesVazio).every(cb => cb.checked);

  checkboxesVazio.forEach(cb => {
    cb.checked = !todosMarcados;
  });

  // Regra de consistência: se "mesmo vazio" estiver marcado, o kanban precisa estar visível.
  if (!todosMarcados) {
    checkboxesVisivel.forEach(cb => {
      cb.checked = true;
    });
  }
}

// ========== Variável global para permissões de acesso ==========
let permissoesAcessoCache = [];

// Função para verificar se o usuário tem permissão para aprovar itens de um departamento
function usuarioPodeAprovarDepartamento(departamento) {
  // Pega username do usuário logado
  const username = window.__sessionUser?.username || 
                   document.getElementById('userNameDisplay')?.textContent?.trim() || '';
  
  if (!username) {
    console.warn('[Permissões] Usuário não identificado');
    return false;
  }
  
  // Verifica se existe permissão para tipo_botao='aprovacao', username e departamento
  const temPermissao = permissoesAcessoCache.some(p => 
    p.tipo_botao === 'aprovacao' && 
    p.responsavel_username === username && 
    p.departamento_nome === departamento
  );
  
  console.log(`[Permissões] User: ${username}, Depto: ${departamento}, Permissão: ${temPermissao}`);
  return temPermissao;
}

// Carrega permissões de acesso do servidor
async function carregarPermissoesAcessoParaAprovacao() {
  try {
    const resp = await fetch('/api/compras/config-acesso-botoes', { credentials: 'include' });
    if (!resp.ok) throw new Error('Erro ao carregar permissões');
    
    const data = await resp.json();
    permissoesAcessoCache = data.permissoes || [];
    console.log('[Permissões] Permissões carregadas:', permissoesAcessoCache.length);
  } catch (err) {
    console.error('[Permissões] Erro ao carregar permissões:', err);
    permissoesAcessoCache = [];
  }
}

// ========== Modal de Aprovação de Requisições ==========
async function abrirModalAprovacaoRequisicao() {
  try {
    // Carrega permissões de acesso antes de renderizar o modal
    await carregarPermissoesAcessoParaAprovacao();
    
    // Busca todas as solicitações aguardando aprovação (não apenas do usuário logado)
    const resp = await fetch(`/api/compras/todas`, { credentials: 'include' });
    if (!resp.ok) throw new Error('Erro ao carregar solicitações');
    
    const data = await resp.json();
    const todasSolicitacoes = data.solicitacoes || [];

    const fmtQtdModal = (valor) => {
      if (valor === null || valor === undefined || String(valor).trim() === '') return '-';
      const bruto = String(valor).trim();
      let normalizado = bruto;
      const temVirgula = normalizado.includes(',');
      const temPonto = normalizado.includes('.');
      if (temVirgula && temPonto) {
        if (normalizado.lastIndexOf(',') > normalizado.lastIndexOf('.')) {
          normalizado = normalizado.replace(/\./g, '').replace(',', '.');
        } else {
          normalizado = normalizado.replace(/,/g, '');
        }
      } else if (temVirgula) {
        normalizado = normalizado.replace(',', '.');
      }
      const n = Number(normalizado);
      if (!Number.isFinite(n)) return bruto;
      if (Math.abs(n - Math.round(n)) < 1e-9) return String(Math.round(n));
      return n.toLocaleString('pt-BR', { minimumFractionDigits: 0, maximumFractionDigits: 4 });
    };
    
    // Filtra apenas as que estão aguardando aprovação
    const itensAprovacaoResumo = todasSolicitacoes.filter(item => 
      (item.status || '').toLowerCase().trim() === 'aguardando aprovação da requisição'
    );

    // Expande por grupo_requisicao para garantir que o modal mostre todos os itens do pedido
    const cacheGrupoItens = new Map();
    const itensAprovacaoExpandidos = [];

    for (const itemResumo of itensAprovacaoResumo) {
      const grupoRequisicao = String(itemResumo?.grupo_requisicao || '').trim();
      const tableSource = String(itemResumo?.table_source || 'solicitacao_compras').trim() || 'solicitacao_compras';
      const podeExpandir = grupoRequisicao && ['solicitacao_compras', 'compras_sem_cadastro'].includes(tableSource);

      if (!podeExpandir) {
        itensAprovacaoExpandidos.push(itemResumo);
        continue;
      }

      const chaveCache = `${tableSource}::${grupoRequisicao.toLowerCase()}`;
      if (!cacheGrupoItens.has(chaveCache)) {
        try {
          const respGrupo = await fetch(
            `/api/compras/grupo-itens?grupo_requisicao=${encodeURIComponent(grupoRequisicao)}&table_source=${encodeURIComponent(tableSource)}`,
            { credentials: 'include' }
          );

          if (respGrupo.ok) {
            const dataGrupo = await respGrupo.json();
            const itensGrupo = Array.isArray(dataGrupo.itens) ? dataGrupo.itens : [];
            const itensNormalizados = itensGrupo.length > 0
              ? itensGrupo.map((it) => ({
                  ...itemResumo,
                  ...it,
                  grupo_requisicao: String(it?.grupo_requisicao || itemResumo?.grupo_requisicao || '').trim(),
                  table_source: String(it?.table_source || tableSource).trim() || tableSource
                }))
              : [itemResumo];
            cacheGrupoItens.set(chaveCache, itensNormalizados);
          } else {
            cacheGrupoItens.set(chaveCache, [itemResumo]);
          }
        } catch (erroGrupo) {
          console.error('[Modal Aprovação] Erro ao expandir grupo:', erroGrupo);
          cacheGrupoItens.set(chaveCache, [itemResumo]);
        }
      }

      itensAprovacaoExpandidos.push(...(cacheGrupoItens.get(chaveCache) || [itemResumo]));
    }

    const itensAprovacao = itensAprovacaoExpandidos
      .filter(item => (item.status || '').toLowerCase().trim() === 'aguardando aprovação da requisição')
      .filter((item, idx, arr) => {
        const chave = `${String(item?.table_source || '').trim()}::${String(item?.id || '').trim()}`;
        return arr.findIndex((cand) => `${String(cand?.table_source || '').trim()}::${String(cand?.id || '').trim()}` === chave) === idx;
      });
    
    if (itensAprovacao.length === 0) {
      alert('Nenhuma solicitação aguardando aprovação');
      return;
    }
    
    // Debug: verifica estrutura dos dados
    console.log('[Modal Aprovação] Exemplo de item:', itensAprovacao[0]);
    console.log('[Modal Aprovação] Total de itens:', itensAprovacao.length);
    console.log('[Modal Aprovação] Itens com anexos:', itensAprovacao.filter(i => i.anexos && i.anexos.length > 0).length);
    
    // Lista de grupos disponíveis (aguardando aprovação)
    const gruposDisponiveis = Array.from(new Set(
      itensAprovacao
        .map(item => String(item.grupo_requisicao || '').trim())
        .filter(Boolean)
    )).sort((a, b) => a.localeCompare(b, 'pt-BR', { sensitivity: 'base' }));
    window.gruposRequisicaoDisponiveisAprovacao = gruposDisponiveis;

    // Agrupa por grupo_requisicao
    const itensPorGrupoRequisicao = {};
    itensAprovacao.forEach(item => {
      const grupoRequisicao = item.grupo_requisicao || 'Sem grupo';
      if (!itensPorGrupoRequisicao[grupoRequisicao]) {
        itensPorGrupoRequisicao[grupoRequisicao] = [];
      }
      itensPorGrupoRequisicao[grupoRequisicao].push(item);
    });
    
    // Monta HTML da tabela agrupada por grupo_requisicao
    let tabelaHtml = '';
    Object.keys(itensPorGrupoRequisicao).sort().forEach((grupoRequisicao, grupoIdx) => {
      const itensGrupo = itensPorGrupoRequisicao[grupoRequisicao];
      const totalQtd = itensGrupo.reduce((sum, i) => sum + (parseFloat(i.quantidade) || 0), 0);
      const itensPermitidos = itensGrupo.filter(i => usuarioPodeAprovarDepartamento(i.departamento || ''));
      const idsPermitidos = itensPermitidos.map(i => i.id).join(',');
      const itensSolicitacaoGrupo = itensGrupo.filter(i => i.table_source === 'solicitacao_compras');
      const idsSolicitacaoGrupo = itensSolicitacaoGrupo
        .map(i => Number(i.id))
        .filter(id => Number.isInteger(id) && id > 0);
      const idsSolicitacaoGrupoCsv = idsSolicitacaoGrupo.join(',');
      const retornoCotacaoGrupoValores = itensSolicitacaoGrupo.map((item) => {
        const valor = String(item.retorno_cotacao || '').trim().toLowerCase();
        return ['s', 'sim', 'yes', 'true', '1'].includes(valor) ? 'Sim' : 'Não';
      });
      const retornoGrupoUnico = retornoCotacaoGrupoValores.length > 0
        && retornoCotacaoGrupoValores.every(v => v === retornoCotacaoGrupoValores[0])
        ? retornoCotacaoGrupoValores[0]
        : '__misto__';
      const totalSemPermissao = itensGrupo.length - itensPermitidos.length;
      const grupoRequisicaoEncoded = encodeURIComponent(grupoRequisicao);
      const itensGrupoParaRecusa = itensGrupo.map(i => ({ id: i.id, ts: String(i.table_source || 'solicitacao_compras') }));
      const itensGrupoJsonEncoded = encodeURIComponent(JSON.stringify(itensGrupoParaRecusa));
      
      tabelaHtml += `
        <div data-grupo-aprovacao="${escapeHtml(grupoRequisicao)}" style="margin-bottom:24px;border:2px solid #3b82f6;border-radius:8px;overflow:hidden;">
          <div style="background:linear-gradient(135deg,#3b82f6 0%,#2563eb 100%);color:white;padding:12px 16px;display:flex;justify-content:space-between;align-items:center;">
            <div style="display:flex;align-items:center;gap:10px;">
              <i class="fa-solid fa-layer-group" style="font-size:18px;"></i>
              <span style="font-weight:700;font-size:15px;">${escapeHtml(grupoRequisicao)}</span>
            </div>
            <div style="display:flex;gap:16px;">
              ${idsPermitidos ? `
              <button
                type="button"
                title="Comprar requisição ${escapeHtml(grupoRequisicao)}"
                onclick="aprovarGrupoRequisicao('${idsPermitidos}', '${grupoRequisicaoEncoded}', ${totalSemPermissao})"
                style="background:rgba(255,255,255,0.2);border:1px solid rgba(255,255,255,0.4);color:white;padding:4px 10px;border-radius:10px;font-size:11px;font-weight:700;cursor:pointer;display:flex;align-items:center;gap:6px;"
              >
                <i class="fa-solid fa-cart-shopping"></i>
                <span>Comprar requisição ${escapeHtml(grupoRequisicao)}</span>
              </button>
              ` : '<span style="font-size:11px;opacity:0.8;">Sem permissão</span>'}
              <button
                type="button"
                title="Recusar tudo — devolver todos os itens ao carrinho"
                onclick="abrirModalRecusarTudoGrupo('${grupoRequisicaoEncoded}', '${itensGrupoJsonEncoded}')"
                style="background:rgba(239,68,68,0.35);border:1px solid rgba(239,68,68,0.7);color:white;padding:4px 10px;border-radius:10px;font-size:11px;font-weight:700;cursor:pointer;display:flex;align-items:center;gap:6px;"
              >
                <i class="fa-solid fa-ban"></i>
                <span>Recusar tudo</span>
              </button>
              ${idsSolicitacaoGrupo.length > 0 ? `
              <div style="background:rgba(255,255,255,0.2);padding:4px 10px;border-radius:12px;display:flex;align-items:center;gap:8px;">
                <span style="font-size:11px;opacity:0.9;">Retorno Cotação:</span>
                <select
                  data-valor-original="${escapeHtml(retornoGrupoUnico)}"
                  onchange="atualizarRetornoCotacaoGrupoAprovacao('${grupoRequisicaoEncoded}', '${idsSolicitacaoGrupoCsv}', this)"
                  style="padding:4px 8px;border-radius:10px;border:1px solid rgba(255,255,255,0.4);background:rgba(255,255,255,0.9);color:#1f2937;font-size:11px;font-weight:700;"
                >
                  ${retornoGrupoUnico === '__misto__' ? '<option value="__misto__" selected disabled>Misto</option>' : ''}
                  <option value="Sim" ${retornoGrupoUnico === 'Sim' ? 'selected' : ''}>Sim</option>
                  <option value="Não" ${retornoGrupoUnico === 'Não' ? 'selected' : ''}>Não</option>
                </select>
              </div>
              ` : ''}
              <div style="background:rgba(255,255,255,0.2);padding:4px 12px;border-radius:12px;">
                <span style="font-size:11px;opacity:0.9;">Itens:</span>
                <span style="font-weight:700;margin-left:4px;">${itensGrupo.length}</span>
              </div>
            </div>
          </div>
          <div style="overflow-x:auto;">
            <table style="width:100%;border-collapse:collapse;font-size:12px;">
              <thead>
                <tr style="background:#f3f4f6;border-bottom:2px solid #e5e7eb;">
                  <th style="padding:10px;text-align:left;font-weight:600;color:#374151;width:60px;">ID</th>
                  <th style="padding:10px;text-align:left;font-weight:600;color:#374151;">Código</th>
                  <th style="padding:10px;text-align:left;font-weight:600;color:#374151;">Descrição</th>
                  <th style="padding:10px;text-align:center;font-weight:600;color:#374151;width:80px;">Qtd</th>
                  <th style="padding:10px;text-align:left;font-weight:600;color:#374151;width:90px;">Unidade</th>
                  <th style="padding:10px;text-align:left;font-weight:600;color:#374151;width:120px;">Solicitante</th>
                  <th style="padding:10px;text-align:center;font-weight:600;color:#374151;width:120px;">Retorno Cotação</th>
                  <th style="padding:10px;text-align:left;font-weight:600;color:#374151;width:120px;">Departamento</th>
                  <th style="padding:10px;text-align:left;font-weight:600;color:#374151;width:150px;">Objetivo Compra</th>
                  <th style="padding:10px;text-align:left;font-weight:600;color:#374151;width:180px;">Número da requisição</th>
                  <th style="padding:10px;text-align:center;font-weight:600;color:#374151;width:80px;">Anexos</th>
                  <th style="padding:10px;text-align:center;font-weight:600;color:#374151;width:120px;">Ações</th>
                </tr>
              </thead>
              <tbody>
                ${itensGrupo.map((item, idx) => {
                  const isSemCadastro = item.table_source === 'compras_sem_cadastro';
                  const retornoCotacaoRaw = String(item.retorno_cotacao || '').trim();
                  const retornoCotacaoEhSim = retornoCotacaoIndicaCotacao(retornoCotacaoRaw, item.table_source || 'solicitacao_compras');
                  const retornoTexto = retornoCotacaoEhSim ? 'SIM' : 'NÃO';
                  const retornoCor = retornoCotacaoEhSim ? '#10b981' : '#ef4444';
                  const grupoAtual = item.grupo_requisicao || 'Sem grupo';
	                  
	                  // Processa anexos
                  let anexosHtml = '-';
                  if (item.anexos && Array.isArray(item.anexos) && item.anexos.length > 0) {
                    const anexosJson = JSON.stringify(item.anexos).replace(/"/g, '&quot;');
                    anexosHtml = `
                      <button 
                        onclick="exibirAnexosAprovacao(${item.id}, '${anexosJson}')" 
                        title="Ver anexos (${item.anexos.length})"
                        style="background:#3b82f6;color:white;border:none;padding:6px 10px;border-radius:6px;cursor:pointer;font-size:12px;font-weight:600;display:flex;align-items:center;gap:4px;transition:all 0.2s;"
                        onmouseover="this.style.background='#2563eb';this.style.transform='scale(1.05)'"
                        onmouseout="this.style.background='#3b82f6';this.style.transform='scale(1)'">
                        <i class="fa-solid fa-paperclip"></i>
                        <span>${item.anexos.length}</span>
                      </button>
                    `;
                  }
                  
                  const grupoAtualValor = String(item.grupo_requisicao || '').trim();
                  const grupoAtualLabel = grupoAtualValor || 'Sem grupo';
                  const gruposAlternativos = gruposDisponiveis.filter(g => g !== grupoAtualValor);
                  const opcoesGrupoHtml = [
                    `<option value="${escapeHtml(grupoAtualValor)}" selected>${escapeHtml(grupoAtualLabel)}</option>`,
                    `<option value="__novo__">Novo grupo de requisição</option>`,
                    ...gruposAlternativos.map(g => `<option value="${escapeHtml(g)}">${escapeHtml(g)}</option>`)
                  ].join('');

                  const itensExpandirSemCadastro = (() => {
                    if (!isSemCadastro) {
                      return [{
                        codigo: item.produto_codigo || '-',
                        descricao: item.produto_descricao || '-',
                        quantidade: obterQuantidadeConfiavel(item, item.quantidade)
                      }];
                    }

                    return [{
                      codigo: String(item.produto_codigo || '-').trim() || '-',
                      descricao: String(item.produto_descricao || '').trim() || '-',
                      quantidade: obterQuantidadeConfiavel(item, item.quantidade) ?? '1'
                    }];
                  })();

                  const numeroRequisicaoHtml = isSemCadastro
                    ? `<span style="display:inline-flex;align-items:center;padding:6px 8px;border:1px solid #cbd5e1;border-radius:6px;background:#f8fafc;font-size:11px;color:#475569;">${escapeHtml(grupoAtualLabel)}</span>`
                    : `
                        <select
                          id="grupo-requisicao-select-${item.id}"
                          data-valor-original="${escapeHtml(grupoAtualValor)}"
                          onchange="atualizarGrupoRequisicaoItem(${item.id}, this)"
                          style="width:100%;padding:6px;border:1px solid #cbd5e1;border-radius:6px;font-size:11px;background:white;">
                          ${opcoesGrupoHtml}
                        </select>
                      `;

                  const acoesHtml = isSemCadastro
                    ? '<span style="color:#64748b;font-size:11px;font-style:italic;">Use Comprar requisição</span>'
                    : `
                        <div style="display:flex;gap:6px;justify-content:center;">
                          ${usuarioPodeAprovarDepartamento(item.departamento || '') ? `
                          <button onclick="aprovarItemRequisicao(${item.id}, '${escapeHtml(item.table_source || '')}', '${escapeHtml(retornoCotacaoRaw)}')" title="Aprovar item${retornoCotacaoEhSim ? ' (enviar para cotação)' : ' (criar requisição direto)'}" style="background:#10b981;color:white;border:none;padding:6px 10px;border-radius:6px;cursor:pointer;font-size:13px;font-weight:600;display:flex;align-items:center;gap:4px;transition:all 0.2s;" onmouseover="this.style.background='#059669';this.style.transform='translateY(-1px)'" onmouseout="this.style.background='#10b981';this.style.transform='translateY(0)'">
                            <i class="fa-solid fa-check"></i>
                          </button>
                          ` : '<span style="color:#9ca3af;font-size:11px;font-style:italic;">Sem permissão</span>'}
                          <button onclick="abrirModalReprovacao(${item.id}, '${escapeHtml(item.table_source || '')}')" title="Reprovar (voltar para carrinho)" style="background:#ef4444;color:white;border:none;padding:6px 10px;border-radius:6px;cursor:pointer;font-size:13px;font-weight:600;display:flex;align-items:center;gap:4px;transition:all 0.2s;" onmouseover="this.style.background='#dc2626';this.style.transform='translateY(-1px)'" onmouseout="this.style.background='#ef4444';this.style.transform='translateY(0)'">
                            <i class="fa-solid fa-rotate-left"></i>
                          </button>
                        </div>
                      `;

                  return itensExpandirSemCadastro.map((itemExpandido, idxExpandido) => `
                    <tr data-aprovacao-item-id="${item.id}" style="border-bottom:1px solid #f3f4f6;${idx % 2 === 0 ? 'background:#f9fafb;' : ''}transition:background 0.2s;" onmouseover="this.style.background='#eff6ff'" onmouseout="this.style.background='${idx % 2 === 0 ? '#f9fafb' : 'white'}'">
                      <td style="padding:10px;color:#6b7280;font-weight:600;">${item.id}</td>
                      <td style="padding:10px;font-weight:600;color:#1f2937;">${escapeHtml(itemExpandido.codigo || '-')}</td>
                      <td style="padding:10px;color:#374151;max-width:250px;line-height:1.4;">${escapeHtml((itemExpandido.descricao || '-').substring(0, 120))}${(itemExpandido.descricao || '').length > 120 ? '...' : ''}</td>
                      <td style="padding:10px;text-align:center;">
                        ${isSemCadastro
                          ? `<span style="font-weight:700;color:#1f2937;">${fmtQtdModal(itemExpandido.quantidade)}</span>`
                          : `<input
                              type="number"
                              min="1"
                              step="1"
                              value="${obterQuantidadeConfiavel(item, item.quantidade) ?? ''}"
                              style="width:70px;padding:6px;border:1px solid #cbd5e1;border-radius:6px;text-align:center;font-weight:700;color:#1f2937;font-size:14px;"
                              onkeydown="if(event.key==='Enter'){this.blur();}"
                              onblur="atualizarQuantidadeItemAprovacao(${item.id}, this)"
                            />`
                        }
                      </td>
                      <td style="padding:10px;color:#374151;font-size:11px;">${escapeHtml(item.unidade || '-')}</td>
                      <td style="padding:10px;color:#374151;font-size:11px;">${escapeHtml(item.solicitante || '-')}</td>
                      <td style="padding:10px;text-align:center;">
                        <span style="background:${retornoCor};color:white;padding:4px 10px;border-radius:12px;font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:0.5px;">${retornoTexto}</span>
                      </td>
                      <td style="padding:10px;color:#374151;font-size:11px;">${escapeHtml(item.departamento || '-')}</td>
                      <td style="padding:10px;color:#374151;font-size:11px;max-width:150px;">${escapeHtml((item.objetivo_compra || '-').substring(0, 50))}${(item.objetivo_compra || '').length > 50 ? '...' : ''}</td>
                      <td style="padding:10px;color:#374151;font-size:11px;">${numeroRequisicaoHtml}</td>
                      <td style="padding:10px;text-align:center;">${idxExpandido === 0 ? anexosHtml : '-'}</td>
                      <td style="padding:10px;text-align:center;">${acoesHtml}</td>
                    </tr>
                  `).join('');
                }).join('')}
              </tbody>
            </table>
          </div>
        </div>
      `;
    });
    
    // Cria e abre modal
    const modalId = 'modalAprovacaoRequisicao';
    let modal = document.getElementById(modalId);
    
    if (!modal) {
      modal = document.createElement('div');
      modal.id = modalId;
      modal.className = 'modal';
      modal.style.display = 'none';
      modal.style.setProperty('z-index', '10002', 'important');
      document.body.appendChild(modal);
    }
    
    modal.innerHTML = `
      <div class="modal-content" style="max-width:1400px;width:95%;max-height:90vh;overflow-y:auto;">
        <div class="modal-header" style="background:linear-gradient(135deg,#3b82f6 0%,#2563eb 100%);color:white;padding:20px;border-radius:8px 8px 0 0;">
          <h3 style="margin:0;display:flex;align-items:center;gap:10px;font-size:18px;">
            <i class="fa-solid fa-shield-check" style="font-size:22px;"></i>
            <span>Aprovação de Requisições de Compra</span>
          </h3>
          <button class="modal-close" onclick="document.getElementById('${modalId}').style.display='none'" style="color:white;opacity:0.9;">&times;</button>
        </div>
        <div class="modal-body" style="padding:24px;background:#f9fafb;">
          
          <div style="background:#eff6ff;border:2px solid #3b82f6;border-radius:8px;padding:16px;margin-bottom:24px;">
            <div style="display:flex;align-items:start;gap:12px;">
              <i class="fa-solid fa-info-circle" style="color:#3b82f6;font-size:20px;margin-top:2px;"></i>
              <div style="flex:1;">
                <div style="font-weight:700;color:#1e40af;margin-bottom:6px;font-size:14px;">Instruções</div>
                <div style="color:#1e40af;font-size:13px;line-height:1.6;">
                  • Use o botão <i class="fa-solid fa-check" style="color:#10b981;"></i> para aprovar o item individualmente<br>
                  • Use o botão <i class="fa-solid fa-rotate-left" style="color:#ef4444;"></i> para reprovar e voltar o item ao carrinho
                </div>
              </div>
            </div>
          </div>
          
          ${tabelaHtml}
          
        </div>
      </div>
    `;
    
    modal.style.display = 'flex';
    modal.style.setProperty('z-index', '10002', 'important');
    
  } catch (err) {
    console.error('[Modal Aprovação] Erro:', err);
    alert('Erro ao carregar solicitações para aprovação: ' + err.message);
  }
}

// Função para aprovar um item individualmente
async function aprovarItemRequisicao(itemId, tableSource, retornoCotacaoRawOriginal) {
  const retornoCotacaoRaw = String(retornoCotacaoRawOriginal || '').trim();
  const isSemCadastro = tableSource === 'compras_sem_cadastro';
  const retornoCotacaoEhSim = retornoCotacaoIndicaCotacao(retornoCotacaoRaw, tableSource || 'solicitacao_compras');

  const retornoCotacaoEhSimSolicitacao = ['s', 'sim', 'yes', 'true', '1'].includes(retornoCotacaoRaw.toLowerCase());
  const novoStatusSolicitacao = retornoCotacaoEhSimSolicitacao ? 'aguardando cotação' : 'Requisição';

  const mensagemConfirmacao = isSemCadastro
    ? `Deseja aprovar este item? O status será atualizado para ${retornoCotacaoEhSim ? 'aguardando cotação' : 'Organizando requisição'}.`
    : 'Deseja aprovar este item? Será criada uma requisição na Omie e o item será movido para "Pedido de compra".';

  if (!confirm(mensagemConfirmacao)) return;
  
  try {
    if (isSemCadastro) {
      const novoStatus = retornoCotacaoEhSim ? 'aguardando cotação' : 'Analise de cadastro';
      const resp = await fetch(`/api/compras/sem-cadastro/${itemId}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({ status: novoStatus })
      });

      if (!resp.ok) {
        const error = await resp.json();
        throw new Error(error.error || 'Falha ao atualizar status');
      }

      alert(`Item aprovado e status atualizado para ${novoStatus}.`);
      removerItemModalAprovacao(itemId);
      atualizarKanbanMinhasAposMudanca(itemId, novoStatus);
      return;
    }

    // Chama o endpoint que aprova o item e cria requisição na Omie
    const resp = await fetch(`/api/compras/aprovar-item/${itemId}`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include'
    });
    
    if (!resp.ok) {
      const error = await resp.json();
      throw new Error(error.error || 'Falha ao aprovar item');
    }
    
    const resultado = await resp.json();
    console.log('[Aprovação] Resultado:', resultado);
    
    // Feedback visual
    alert(`Item aprovado com sucesso!\nNúmero do Pedido: ${resultado.numero_pedido}\nRequisição criada na Omie.`);

    removerItemModalAprovacao(itemId);
    atualizarKanbanMinhasAposMudanca(itemId, novoStatusSolicitacao);
    
  } catch (err) {
    console.error('[Aprovação] Erro ao aprovar item:', err);
    alert('Erro ao aprovar item: ' + err.message);
  }
}

// Atualiza retorno_cotacao (Sim/Não) em massa no grupo da requisição
async function atualizarRetornoCotacaoGrupoAprovacao(grupoRequisicaoEncoded, idsCsv, selectEl) {
  if (!selectEl) return;
  const originalValue = String(selectEl.getAttribute('data-valor-original') || 'Não').trim() || 'Não';

  const valorSelecionado = String(selectEl.value || '').trim();
  if (!valorSelecionado || valorSelecionado === '__misto__') {
    selectEl.value = originalValue;
    return;
  }
  const valorNormalizado = ['s', 'sim', 'yes', 'true', '1'].includes(valorSelecionado.toLowerCase()) ? 'Sim' : 'Não';
  const ids = String(idsCsv || '')
    .split(',')
    .map(v => Number(v.trim()))
    .filter(v => Number.isInteger(v) && v > 0);

  if (!ids.length) {
    selectEl.value = originalValue;
    return;
  }

  const grupoRequisicao = decodeURIComponent(String(grupoRequisicaoEncoded || ''));
  const confirma = confirm(
    `Deseja alterar Retorno Cotação para "${valorNormalizado}" em ${ids.length} item(ns) do grupo "${grupoRequisicao}"?`
  );
  if (!confirma) {
    selectEl.value = originalValue;
    return;
  }

  selectEl.disabled = true;
  try {
    const resp = await fetch('/api/compras/solicitacoes/retorno-cotacao/lote', {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({ ids, retorno_cotacao: valorNormalizado })
    });

    const data = await resp.json().catch(() => ({}));
    if (!resp.ok || !data.success) {
      throw new Error(data.error || 'Falha ao atualizar retorno de cotação em lote');
    }

    selectEl.setAttribute('data-valor-original', valorNormalizado);
    await abrirModalAprovacaoRequisicao();
  } catch (err) {
    console.error('[Aprovação] Erro ao atualizar retorno de cotação em lote:', err);
    alert('Erro ao atualizar retorno de cotação em lote: ' + err.message);
    selectEl.value = originalValue;
  } finally {
    selectEl.disabled = false;
  }
}

// Atualiza grupo_requisicao do item no modal de aprovação
async function atualizarGrupoRequisicaoItem(itemId, selectEl) {
  if (!selectEl) return;
  const valorSelecionado = String(selectEl.value || '').trim();

  selectEl.disabled = true;
  const originalText = selectEl.options[selectEl.selectedIndex]?.text || '';

  try {
    const resp = await fetch(`/api/compras/solicitacoes/${itemId}`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({ grupo_requisicao: valorSelecionado || null })
    });

    const data = await resp.json().catch(() => ({}));
    if (!resp.ok || !data.success) {
      throw new Error(data.error || 'Falha ao atualizar grupo de requisição');
    }

    const novoGrupo = String(data.solicitacao?.grupo_requisicao || valorSelecionado || '').trim();
    const labelGrupo = novoGrupo || 'Sem grupo';

    const span = document.getElementById(`grupo-requisicao-text-${itemId}`);
    if (span) span.textContent = labelGrupo;

    if (novoGrupo) {
      atualizarOpcoesGrupoRequisicaoTodos(novoGrupo, itemId);
    }

    rebuildSelectGrupoRequisicao(selectEl, novoGrupo, itemId);

    await abrirModalAprovacaoRequisicao();
  } catch (err) {
    console.error('[Aprovação] Erro ao atualizar grupo de requisição:', err);
    alert('Erro ao atualizar grupo de requisição: ' + err.message);
    selectEl.value = selectEl.getAttribute('data-valor-original') || '';
  } finally {
    selectEl.disabled = false;
  }
}

function rebuildSelectGrupoRequisicao(selectEl, grupoAtual, itemId) {
  if (!selectEl) return;
  const valorAtual = String(grupoAtual || '').trim();
  const labelAtual = valorAtual || 'Sem grupo';
  const grupos = Array.isArray(window.gruposRequisicaoDisponiveisAprovacao)
    ? window.gruposRequisicaoDisponiveisAprovacao
    : [];
  const gruposAlternativos = grupos.filter(g => g !== valorAtual);

  selectEl.innerHTML = [
    `<option value="${escapeHtml(valorAtual)}" selected>${escapeHtml(labelAtual)}</option>`,
    `<option value="__novo__">Novo grupo de requisição</option>`,
    ...gruposAlternativos.map(g => `<option value="${escapeHtml(g)}">${escapeHtml(g)}</option>`)
  ].join('');

  selectEl.setAttribute('data-valor-original', valorAtual);
}

function atualizarOpcoesGrupoRequisicaoTodos(novoGrupo, itemIdAtual) {
  const grupo = String(novoGrupo || '').trim();
  if (!grupo) return;

  const lista = Array.isArray(window.gruposRequisicaoDisponiveisAprovacao)
    ? window.gruposRequisicaoDisponiveisAprovacao
    : [];
  if (!lista.includes(grupo)) {
    lista.push(grupo);
    lista.sort((a, b) => a.localeCompare(b, 'pt-BR', { sensitivity: 'base' }));
    window.gruposRequisicaoDisponiveisAprovacao = lista;
  }

  document.querySelectorAll('[id^="grupo-requisicao-select-"]').forEach(selectEl => {
    const itemId = Number(String(selectEl.id).replace('grupo-requisicao-select-', ''));
    if (itemId === Number(itemIdAtual)) return;
    const valorAtual = String(selectEl.value || '').trim();
    const labelAtual = valorAtual || 'Sem grupo';
    const gruposAlternativos = window.gruposRequisicaoDisponiveisAprovacao.filter(g => g !== valorAtual);
    selectEl.innerHTML = [
      `<option value="${escapeHtml(valorAtual)}" selected>${escapeHtml(labelAtual)}</option>`,
      `<option value="__novo__">Novo grupo de requisição</option>`,
      ...gruposAlternativos.map(g => `<option value="${escapeHtml(g)}">${escapeHtml(g)}</option>`)
    ].join('');
    selectEl.setAttribute('data-valor-original', valorAtual);
  });
}

// Função para aprovar todos os itens de um grupo (comprar requisição)
async function aprovarGrupoRequisicao(itemIdsCsv, grupoRequisicaoEncoded = '', totalSemPermissao = 0) {
  const grupoRequisicao = grupoRequisicaoEncoded ? decodeURIComponent(grupoRequisicaoEncoded) : 'Grupo';
  const ids = (itemIdsCsv || '')
    .split(',')
    .map(id => String(id).trim())
    .filter(id => id && id !== 'undefined' && id !== 'null');
  
  if (!ids.length) {
    alert('Nenhum item com permissão para aprovação neste grupo.');
    return;
  }
  
  const avisoSemPermissao = totalSemPermissao > 0
    ? `\n\n${totalSemPermissao} item(ns) sem permissão não serão aprovados.`
    : '';
  
  const confirma = confirm(
    `Deseja aprovar todos os itens do grupo "${grupoRequisicao}"?` +
    '\nIsso criará requisições na Omie e moverá os itens para "Pedido de compra".' +
    avisoSemPermissao
  );
  if (!confirma) return;
  
  try {
    const respBase = await fetch('/api/compras/todas', { credentials: 'include' });
    if (!respBase.ok) throw new Error('Falha ao carregar itens do grupo para aprovação');
    const dataBase = await respBase.json();
    const todasSolicitacoes = Array.isArray(dataBase.solicitacoes) ? dataBase.solicitacoes : [];

    const itensGrupo = todasSolicitacoes.filter(item => {
      const status = String(item?.status || '').toLowerCase().trim();
      const grupo = String(item?.grupo_requisicao || '').trim();
      return status === 'aguardando aprovação da requisição' && grupo === grupoRequisicao;
    });

    const itensPermitidos = itensGrupo.filter(item => usuarioPodeAprovarDepartamento(item?.departamento || ''));
    const itensSolicitacao = itensPermitidos.filter(item => String(item?.table_source || 'solicitacao_compras') !== 'compras_sem_cadastro');
    const itensSemCadastro = itensPermitidos.filter(item => String(item?.table_source || '') === 'compras_sem_cadastro');

    let resultadoSolicitacao = { numero_pedido: null, itens_requisicao: [], itens_aguardando_cotacao: [] };
    if (itensSolicitacao.length > 0) {
      const idsSolicitacao = itensSolicitacao
        .map(item => String(item.id).trim())
        .filter(id => ids.includes(id));

      if (idsSolicitacao.length > 0) {
        const resp = await fetch('/api/compras/aprovar-grupo', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          credentials: 'include',
          body: JSON.stringify({ ids: idsSolicitacao })
        });

        if (!resp.ok) {
          const error = await resp.json().catch(() => ({}));
          throw new Error(error.error || 'Falha ao aprovar itens de solicitação no grupo');
        }
        resultadoSolicitacao = await resp.json();
      }
    }

    let totalSemCadastroCotacao = 0;
    let totalSemCadastroAnalise = 0;
    for (const item of itensSemCadastro) {
      const retornoCotacaoRaw = String(item?.retorno_cotacao || '').trim();
      const vaiCotacao = retornoCotacaoIndicaCotacao(retornoCotacaoRaw, 'compras_sem_cadastro');
      const novoStatus = vaiCotacao ? 'aguardando cotação' : 'Analise de cadastro';

      const respSemCadastro = await fetch(`/api/compras/sem-cadastro/${item.id}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({ status: novoStatus })
      });

      if (!respSemCadastro.ok) {
        const errorSemCadastro = await respSemCadastro.json().catch(() => ({}));
        throw new Error(errorSemCadastro.error || `Falha ao aprovar item sem cadastro ${item.id}`);
      }

      if (vaiCotacao) totalSemCadastroCotacao += 1;
      else totalSemCadastroAnalise += 1;
    }

    const itensRequisicao = resultadoSolicitacao.itens_requisicao || [];
    const itensCotacao = resultadoSolicitacao.itens_aguardando_cotacao || [];
    
    let mensagem = `Aprovação do grupo "${grupoRequisicao}" concluída.`;
    if (resultadoSolicitacao.numero_pedido) {
      mensagem += `\n\nRequisição criada: ${resultadoSolicitacao.numero_pedido}`;
    }
    mensagem += `\n\nItens em requisição: ${itensRequisicao.length}`;
    if (itensCotacao.length > 0) {
      mensagem += `\nItens aguardando cotação: ${itensCotacao.length}`;
    }
    if (totalSemCadastroCotacao > 0 || totalSemCadastroAnalise > 0) {
      mensagem += `\n\nItens sem cadastro aprovados via grupo:`;
      if (totalSemCadastroCotacao > 0) mensagem += `\n- Aguardando cotação: ${totalSemCadastroCotacao}`;
      if (totalSemCadastroAnalise > 0) mensagem += `\n- Organizando requisição: ${totalSemCadastroAnalise}`;
    }
    
    alert(mensagem);
  } catch (err) {
    console.error('[Aprovar Grupo] Erro:', err);
    alert('Erro ao aprovar itens do grupo: ' + err.message);
  }
  await abrirModalAprovacaoRequisicao();
}

// ========== Recusar Tudo — modal de motivo e reprovação em lote ==========

function abrirModalRecusarTudoGrupo(grupoRequisicaoEncoded, itensJsonEncoded) {
  const grupoRequisicao = decodeURIComponent(grupoRequisicaoEncoded);
  let itens = [];
  try { itens = JSON.parse(decodeURIComponent(itensJsonEncoded)); } catch (e) { itens = []; }

  if (!itens.length) {
    alert('Nenhum item para recusar neste grupo.');
    return;
  }

  window._recusarTudoGrupoRequisicao = grupoRequisicao;
  window._recusarTudoItens = itens;

  const modalId = 'modalRecusarTudoGrupo';
  let modal = document.getElementById(modalId);
  if (!modal) {
    modal = document.createElement('div');
    modal.id = modalId;
    modal.className = 'modal';
    modal.style.display = 'none';
    modal.style.setProperty('z-index', '10004', 'important');
    document.body.appendChild(modal);
  }

  modal.innerHTML = `
    <div class="modal-content" style="max-width:600px;width:90%;">
      <div class="modal-header" style="background:linear-gradient(135deg,#ef4444 0%,#dc2626 100%);color:white;padding:16px;border-radius:8px 8px 0 0;">
        <h3 style="margin:0;display:flex;align-items:center;gap:10px;font-size:16px;">
          <i class="fa-solid fa-ban"></i>
          <span>Recusar Tudo — ${escapeHtml(grupoRequisicao)}</span>
        </h3>
        <button id="recusarTudoBtnFechar" class="modal-close" onclick="fecharModalRecusarTudoGrupo()" style="color:white;opacity:0.9;">&times;</button>
      </div>
      <div id="recusarTudoModalBody" class="modal-body" style="padding:20px;background:#f9fafb;">
        <div style="font-size:13px;color:#374151;margin-bottom:6px;">
          Todos os <strong>${itens.length} item(ns)</strong> da requisição <strong>${escapeHtml(grupoRequisicao)}</strong> serão devolvidos ao carrinho.
        </div>
        <div style="font-size:13px;color:#374151;margin-bottom:10px;">Informe o motivo (obrigatório):</div>
        <textarea id="recusarTudoTexto" rows="4" style="width:100%;padding:10px;border:1px solid #e5e7eb;border-radius:8px;resize:vertical;font-size:13px;" placeholder="Descreva o motivo..."></textarea>
        <div id="recusarTudoError" style="color:#ef4444;font-size:12px;margin-top:8px;display:none;">Motivo é obrigatório.</div>
        <div style="display:flex;justify-content:flex-end;gap:10px;margin-top:16px;">
          <button onclick="fecharModalRecusarTudoGrupo()" style="background:#e5e7eb;color:#374151;border:none;padding:10px 16px;border-radius:6px;cursor:pointer;font-size:13px;font-weight:600;">Cancelar</button>
          <button onclick="confirmarRecusarTudoGrupo()" style="background:#ef4444;color:white;border:none;padding:10px 16px;border-radius:6px;cursor:pointer;font-size:13px;font-weight:700;">Recusar Tudo</button>
        </div>
      </div>
    </div>
  `;

  modal.style.display = 'flex';
}

function fecharModalRecusarTudoGrupo() {
  const modal = document.getElementById('modalRecusarTudoGrupo');
  if (modal) modal.style.display = 'none';
  const textarea = document.getElementById('recusarTudoTexto');
  const errorDiv = document.getElementById('recusarTudoError');
  if (textarea) textarea.value = '';
  if (errorDiv) errorDiv.style.display = 'none';
  window._recusarTudoGrupoRequisicao = null;
  window._recusarTudoItens = null;
}

async function confirmarRecusarTudoGrupo() {
  const textarea = document.getElementById('recusarTudoTexto');
  const errorDiv = document.getElementById('recusarTudoError');
  if (!textarea) return;
  const motivo = textarea.value.trim();
  if (!motivo) {
    if (errorDiv) errorDiv.style.display = 'block';
    textarea.focus();
    return;
  }

  const itens = Array.isArray(window._recusarTudoItens) ? window._recusarTudoItens : [];
  if (!itens.length) { fecharModalRecusarTudoGrupo(); return; }

  // Troca o corpo do modal para spinner de progresso
  const modalBody = document.getElementById('recusarTudoModalBody');
  const btnFechar = document.getElementById('recusarTudoBtnFechar');
  if (btnFechar) btnFechar.style.display = 'none'; // impede fechar durante operação

  if (modalBody) {
    modalBody.innerHTML = `
      <div style="display:flex;flex-direction:column;align-items:center;justify-content:center;padding:36px 20px;gap:20px;">
        <div style="width:56px;height:56px;border:5px solid #fecaca;border-top-color:#ef4444;border-radius:50%;animation:recusarTudoSpin 0.8s linear infinite;"></div>
        <div style="text-align:center;">
          <div style="font-weight:700;color:#1f2937;font-size:15px;margin-bottom:6px;">Recusando itens...</div>
          <div id="recusarTudoProgresso" style="color:#6b7280;font-size:13px;">0 de ${itens.length}</div>
        </div>
        <div style="width:100%;background:#f3f4f6;border-radius:8px;height:8px;overflow:hidden;">
          <div id="recusarTudoBarraProgresso" style="height:8px;background:linear-gradient(90deg,#ef4444,#dc2626);border-radius:8px;width:0%;transition:width 0.3s ease;"></div>
        </div>
        <div id="recusarTudoItemAtual" style="color:#9ca3af;font-size:11px;font-style:italic;text-align:center;"></div>
      </div>
      <style>
        @keyframes recusarTudoSpin { to { transform: rotate(360deg); } }
      </style>
    `;
  }

  let processados = 0;
  let erros = 0;
  const total = itens.length;

  for (const item of itens) {
    // Atualiza progresso visual
    const elProgresso = document.getElementById('recusarTudoProgresso');
    const elBarra = document.getElementById('recusarTudoBarraProgresso');
    const elItem = document.getElementById('recusarTudoItemAtual');
    if (elProgresso) elProgresso.textContent = `${processados} de ${total}`;
    if (elBarra) elBarra.style.width = `${Math.round((processados / total) * 100)}%`;
    if (elItem) elItem.textContent = `Processando item #${item.id}...`;

    try {
      await reprovarItemAprovacao(item.id, motivo, item.ts || 'solicitacao_compras');
    } catch (err) {
      console.error('[Recusar Tudo] Erro ao reprovar item', item.id, err);
      erros++;
    }
    processados++;
  }

  // Barra 100%
  const elProgresso = document.getElementById('recusarTudoProgresso');
  const elBarra = document.getElementById('recusarTudoBarraProgresso');
  const elItem = document.getElementById('recusarTudoItemAtual');
  if (elProgresso) elProgresso.textContent = `${total} de ${total}`;
  if (elBarra) elBarra.style.width = '100%';
  if (elItem) elItem.textContent = erros > 0 ? `Concluído com ${erros} erro(s).` : 'Todos os itens recusados com sucesso!';

  // Pequena pausa para o usuário ver o 100%
  await new Promise(resolve => setTimeout(resolve, 700));

  fecharModalRecusarTudoGrupo();
  if (erros > 0) {
    alert(`${total - erros} item(ns) recusado(s). ${erros} erro(s) ocorreram.`);
  }

  await abrirModalAprovacaoRequisicao();
}

// Atualiza a quantidade de um item direto no modal de aprovação
async function atualizarQuantidadeItemAprovacao(itemId, input) {
  try {
    const valor = input?.value;
    const quantidade = Number(valor);
    if (!Number.isFinite(quantidade) || quantidade <= 0) {
      alert('Quantidade inválida. Use um valor maior que zero.');
      await abrirModalAprovacaoRequisicao();
      return;
    }
    
    const resp = await fetch(`/api/compras/solicitacoes/${itemId}`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({ quantidade })
    });
    
    if (!resp.ok) {
      const error = await resp.json().catch(() => ({}));
      throw new Error(error.error || 'Falha ao atualizar quantidade');
    }
    
    // Recarrega o modal para atualizar totais e agrupamentos
    await abrirModalAprovacaoRequisicao();
  } catch (err) {
    console.error('[Aprovação] Erro ao atualizar quantidade:', err);
    alert('Erro ao atualizar quantidade: ' + err.message);
  }
}

