function obterUnidadePedidoPreviewAssociacao(item) {
  const unidadeDireta = String(item?.pedido_unidade || '').trim();
  if (unidadeDireta) return unidadeDireta;

  const itensContexto = Array.isArray(window.__associarNfeContextoAtual?.itens)
    ? window.__associarNfeContextoAtual.itens
    : [];

  if (!itensContexto.length) return '-';

  const codigoPedido = normalizarTextoRecebimento(item?.pedido_codigo_produto || '');
  const descricaoPedido = normalizarTextoRecebimento(item?.pedido_descricao_produto || '');

  const encontrado = itensContexto.find((ctx) => {
    const codigoCtx = normalizarTextoRecebimento(ctx?.produto_codigo || '');
    const descricaoCtx = normalizarTextoRecebimento(ctx?.produto_descricao || '');
    return (codigoPedido && codigoCtx === codigoPedido)
      || (descricaoPedido && descricaoCtx === descricaoPedido);
  });

  return String(encontrado?.unidade || '-').trim() || '-';
}

const DICIONARIO_EQUIVALENCIA_UNIDADE_PREVIEW = {
  UN: ['UN', 'UND', 'UNID', 'UNIDADE', 'UNIDAD', 'UNIT', 'PC', 'PÇ', 'PECA', 'PEÇA', 'PCS', 'PÇS', 'PECAS', 'PEÇAS'],
  PAR: ['PAR', 'PARES', 'PR'],
  CX: ['CX', 'CAIXA', 'CXS', 'CAIXAS'],
  PCT: ['PCT', 'PAC', 'PACOTE', 'PACOTES', 'EMB', 'EMBALAGEM', 'EMBALAGENS'],
  RL: ['RL', 'RLO', 'ROLO', 'ROLOS'],
  M: ['M', 'MT', 'MTS', 'METRO', 'METROS'],
  CM: ['CM', 'CENTIMETRO', 'CENTÍMETRO', 'CENTIMETROS', 'CENTÍMETROS'],
  MM: ['MM', 'MILIMETRO', 'MILÍMETRO', 'MILIMETROS', 'MILÍMETROS'],
  KG: ['KG', 'KILO', 'QUILO', 'QUILOGRAMA', 'QUILOGRAMAS'],
  G: ['G', 'GR', 'GRAMA', 'GRAMAS'],
  TON: ['TON', 'T', 'TONELADA', 'TONELADAS'],
  L: ['L', 'LT', 'LTS', 'LITRO', 'LITROS'],
  ML: ['ML', 'MILILITRO', 'MILILITROS'],
  M2: ['M2', 'M²', 'MT2', 'METRO2', 'METRO QUADRADO', 'METROS QUADRADOS'],
  M3: ['M3', 'M³', 'MT3', 'METRO3', 'METRO CUBICO', 'METRO CÚBICO', 'METROS CUBICOS', 'METROS CÚBICOS']
};

function normalizarTokenUnidadePreview(valor) {
  return String(valor || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/²/g, '2')
    .replace(/³/g, '3')
    .toUpperCase()
    .replace(/[^A-Z0-9]+/g, '');
}

const MAPA_CANONICO_UNIDADE_PREVIEW = (() => {
  const mapa = new Map();

  Object.entries(DICIONARIO_EQUIVALENCIA_UNIDADE_PREVIEW).forEach(([canonico, aliases]) => {
    const chaveCanonica = normalizarTokenUnidadePreview(canonico);
    if (chaveCanonica) mapa.set(chaveCanonica, canonico);

    aliases.forEach((alias) => {
      const chaveAlias = normalizarTokenUnidadePreview(alias);
      if (chaveAlias) mapa.set(chaveAlias, canonico);
    });
  });

  return mapa;
})();

function unidadeCanonicaPreview(valor) {
  const token = normalizarTokenUnidadePreview(valor);
  if (!token) return '';
  return MAPA_CANONICO_UNIDADE_PREVIEW.get(token) || token;
}

function unidadesEquivalentesPreview(unidadeA, unidadeB) {
  const canonicaA = unidadeCanonicaPreview(unidadeA);
  const canonicaB = unidadeCanonicaPreview(unidadeB);
  if (!canonicaA || !canonicaB) return false;
  return canonicaA === canonicaB;
}

function snapshotEdicoesQtdUnidAssociacaoNfe() {
  const previewConteudo = document.getElementById('modalAssociarPedidoNfePreviewConteudo');
  if (!previewConteudo) return;

  if (!window.__associarNfeCamposEditados || typeof window.__associarNfeCamposEditados !== 'object') {
    window.__associarNfeCamposEditados = {};
  }

  previewConteudo.querySelectorAll('.assoc-override-qtd, .assoc-override-unid, .assoc-override-valor').forEach((input) => {
    const seq = Number(input.dataset.seq || 0);
    if (!seq) return;

    if (!window.__associarNfeCamposEditados[seq]) {
      window.__associarNfeCamposEditados[seq] = {};
    }

    if (input.classList.contains('assoc-override-qtd')) {
      const textoQtd = String(input.value || '').trim();
      const qtd = textoQtd
        ? Number(textoQtd.includes(',') ? textoQtd.replace(/\./g, '').replace(',', '.') : textoQtd)
        : null;
      window.__associarNfeCamposEditados[seq].nQtde = Number.isFinite(qtd) ? qtd : null;
    }

    if (input.classList.contains('assoc-override-unid')) {
      window.__associarNfeCamposEditados[seq].cUnidade = String(input.value || '').trim().toUpperCase() || null;
    }

    if (input.classList.contains('assoc-override-valor')) {
      const valor = parseFloat(String(input.value || '').replace(/\./g, '').replace(',', '.'));
      window.__associarNfeCamposEditados[seq].nValTot = Number.isFinite(valor) ? valor : null;
    }
  });
}

function trocarVinculoPedidoEntreSequenciasAssociacaoNfe(seqOrigem, seqDestino) {
  if (!Array.isArray(window.__associarNfePreviewEstadoItens)) return false;
  if (!seqOrigem || !seqDestino || seqOrigem === seqDestino) return false;

  snapshotEdicoesQtdUnidAssociacaoNfe();

  const itensEstado = window.__associarNfePreviewEstadoItens;
  const idxOrigem = itensEstado.findIndex((it) => Number(it?.n_sequencia || 0) === Number(seqOrigem));
  const idxDestino = itensEstado.findIndex((it) => Number(it?.n_sequencia || 0) === Number(seqDestino));
  if (idxOrigem < 0 || idxDestino < 0) return false;

  const camposPedido = [
    'pedido_item_encontrado',
    'pedido_n_cod_ped',
    'pedido_numero',
    'pedido_n_cod_item',
    'pedido_codigo_produto',
    'pedido_descricao_produto',
    'pedido_qtde',
    'pedido_unidade',
    'pedido_valor_total',
    'criterio_match',
    'score_match'
  ];

  const origem = itensEstado[idxOrigem];
  const destino = itensEstado[idxDestino];
  const snapshotOrigem = {};
  const snapshotDestino = {};

  camposPedido.forEach((campo) => {
    snapshotOrigem[campo] = origem?.[campo];
    snapshotDestino[campo] = destino?.[campo];
  });

  camposPedido.forEach((campo) => {
    origem[campo] = snapshotDestino[campo];
    destino[campo] = snapshotOrigem[campo];
  });

  [origem, destino].forEach((item) => {
    const codItem = Number(item?.pedido_n_cod_item || 0);
    item.pedido_item_encontrado = Number.isFinite(codItem) && codItem > 0;
    item.criterio_match = 'ajuste_manual_arrastar';
    item.score_match = 9999;
  });

  return true;
}

function habilitarDragDropAssociacaoPedidoNfe(preview) {
  const previewConteudo = document.getElementById('modalAssociarPedidoNfePreviewConteudo');
  if (!previewConteudo) return;

  const linhas = previewConteudo.querySelectorAll('tr[data-seq]');
  linhas.forEach((linha) => {
    linha.addEventListener('dragover', (event) => {
      event.preventDefault();
      linha.style.outline = '2px dashed #0ea5e9';
      linha.style.outlineOffset = '-2px';
    });

    linha.addEventListener('dragleave', () => {
      linha.style.outline = 'none';
    });

    linha.addEventListener('drop', (event) => {
      event.preventDefault();
      linha.style.outline = 'none';

      const origemSeq = Number(event.dataTransfer?.getData('text/plain') || 0);
      const destinoSeq = Number(linha.dataset.seq || 0);
      if (!origemSeq || !destinoSeq || origemSeq === destinoSeq) return;

      const trocou = trocarVinculoPedidoEntreSequenciasAssociacaoNfe(origemSeq, destinoSeq);
      if (!trocou) return;

      renderPreviewAssociacaoPedidoNfe(preview || window.__associarNfePreviewAtual?.preview || {});
      setStatusModalAssociarPedidoNfe(
        `Vínculo do pedido ajustado manualmente: Seq ${origemSeq} ↔ Seq ${destinoSeq}.`,
        'info'
      );

      const btnAssociar = document.getElementById('modalAssociarPedidoBtnConfirmar');
      if (btnAssociar) btnAssociar.disabled = false;
    });
  });

  previewConteudo.querySelectorAll('.assoc-pedido-draggable').forEach((el) => {
    el.addEventListener('dragstart', (event) => {
      const seq = Number(el.dataset.seq || 0);
      if (!seq) return;
      event.dataTransfer?.setData('text/plain', String(seq));
      event.dataTransfer.effectAllowed = 'move';
      el.style.opacity = '0.55';
    });

    el.addEventListener('dragend', () => {
      el.style.opacity = '1';
      linhas.forEach((linha) => {
        linha.style.outline = 'none';
      });
    });
  });
}

function renderPreviewAssociacaoPedidoNfe(preview) {
  const previewWrap = document.getElementById('modalAssociarPedidoNfePreviewWrap');
  const previewConteudo = document.getElementById('modalAssociarPedidoNfePreviewConteudo');
  if (!previewWrap || !previewConteudo) return;

  if (!Array.isArray(window.__associarNfePreviewEstadoItens)) {
    window.__associarNfePreviewEstadoItens = Array.isArray(preview?.itens)
      ? preview.itens.map((item) => ({ ...item }))
      : [];
  }

  const itens = [...window.__associarNfePreviewEstadoItens].sort(
    (a, b) => Number(a?.n_sequencia || 0) - Number(b?.n_sequencia || 0)
  );
  const itensInformativosPedido = Array.isArray(preview?.itens_pedido_informativos)
    ? preview.itens_pedido_informativos
    : [];
  const pedidoBaseNumero = String(preview?.c_numero_pedido || '').trim();
  const obterResumoSugestoesPedido = (item) => {
    const sugestoes = Array.isArray(item?.pedido_sugestoes) ? item.pedido_sugestoes : [];
    if (!sugestoes.length) return '';
    const primeira = sugestoes[0] || {};
    const pedidoNumero = String(primeira?.pedido_numero || primeira?.pedido_n_cod_ped || '').trim();
    if (!pedidoNumero) return `${sugestoes.length} sugestao(oes) automatica(s) encontrada(s)`;
    return sugestoes.length === 1
      ? `Sugestao automatica: pedido ${pedidoNumero}`
      : `Sugestao automatica: pedido ${pedidoNumero} + ${sugestoes.length - 1}`;
  };
  const pedidosEnvolvidos = Array.from(new Map(
    itens
      .map((item) => {
        const numero = String(item?.pedido_numero || '').trim();
        const nCodPed = Number(item?.pedido_n_cod_ped || 0);
        if (!numero && !(Number.isFinite(nCodPed) && nCodPed > 0)) return null;
        const chave = numero || String(nCodPed);
        return [
          chave,
          {
            numero: numero || String(nCodPed),
            n_cod_ped: Number.isFinite(nCodPed) && nCodPed > 0 ? nCodPed : null
          }
        ];
      })
      .filter(Boolean)
  ).values());

  if (!window.__associarNfeCamposEditados || typeof window.__associarNfeCamposEditados !== 'object') {
    window.__associarNfeCamposEditados = {};
  }
  const compararQuantidadePreview = (item) => {
    const nfQtd = Number(item?.nf_qtde);
    const pedidoQtd = Number(item?.pedido_qtde);
    if (Number.isFinite(nfQtd) && Number.isFinite(pedidoQtd)) {
      return Math.abs(nfQtd - pedidoQtd) > 0.0001;
    }
    return String(item?.nf_qtde ?? '').trim() !== String(item?.pedido_qtde ?? '').trim();
  };
  const compararUnidadePreview = (item, unidadePedido) => {
    const nfUnidade = String(item?.nf_unidade || '').trim();
    const pedidoUnidade = String(unidadePedido || '').trim();
    if (!nfUnidade && !pedidoUnidade) return false;
    if (!nfUnidade || !pedidoUnidade) return true;
    return !unidadesEquivalentesPreview(nfUnidade, pedidoUnidade);
  };

  const itensComMatch = itens.filter((item) => !!item?.pedido_item_encontrado).length;
  const itensSemMatch = itens.length - itensComMatch;

  const divergenciasValor = itens.filter((item) => {
    if (item?.criterio_match === 'agrupamento_mesmo_item_pedido') return false;
    const nfValor = Number(item?.nf_valor_total || 0);
    const pedidoValor = Number(item?.pedido_valor_total || 0);
    return Number.isFinite(nfValor) && Number.isFinite(pedidoValor) && Math.abs(nfValor - pedidoValor) > 0.01;
  }).length;
  const divergenciasQtdUnid = itens.filter((item) => {
    if (item?.criterio_match === 'agrupamento_mesmo_item_pedido') return false;
    const unidadePedido = obterUnidadePedidoPreviewAssociacao(item);
    return compararQuantidadePreview(item) || compararUnidadePreview(item, unidadePedido);
  }).length;
  const gruposMesmoItem = itens.filter((item) => item?.criterio_match === 'agrupamento_mesmo_item_pedido').length;
  const itensInformativosTotal = itensInformativosPedido.length;

  const totalValorNfPreview = itens.reduce((acc, item) => acc + (Number(item?.nf_valor_total || 0) || 0), 0);
  const totalValorPedidoPreview = itens.reduce((acc, item) => {
    const seq = Number(item?.n_sequencia || 0);
    const overrideCampos = window.__associarNfeCamposEditados?.[seq] || {};
    const valorOverride = Number(overrideCampos?.nValTot);
    return acc + (Number.isFinite(valorOverride) ? valorOverride : (Number(item?.pedido_valor_total || 0) || 0));
  }, 0);

  const resumoHtml = `
    <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:8px;margin-bottom:10px;">
      <div style="background:#f8fafc;border:1px solid #e2e8f0;border-radius:10px;padding:10px;">
        <div style="font-size:11px;color:#64748b;">NF-e</div>
        <div style="font-size:13px;font-weight:700;color:#0f172a;">${escapeHtml(String(preview?.numero_nfe || '-'))}</div>
      </div>
      <div style="background:#f8fafc;border:1px solid #e2e8f0;border-radius:10px;padding:10px;">
        <div style="font-size:11px;color:#64748b;">Pedido</div>
        <div style="font-size:13px;font-weight:700;color:#0f172a;">${escapeHtml(String(preview?.c_numero_pedido || preview?.n_cod_ped || '-'))}</div>
      </div>
      <div style="background:#ecfdf5;border:1px solid #bbf7d0;border-radius:10px;padding:10px;">
        <div style="font-size:11px;color:#166534;">Itens com match</div>
        <div style="font-size:13px;font-weight:700;color:#166534;">${itensComMatch}</div>
      </div>
      <div style="background:#fef2f2;border:1px solid #fecaca;border-radius:10px;padding:10px;">
        <div style="font-size:11px;color:#991b1b;">Sem match</div>
        <div style="font-size:13px;font-weight:700;color:#991b1b;">${itensSemMatch}</div>
      </div>
      <div style="background:${divergenciasValor > 0 ? '#fef2f2' : '#eff6ff'};border:1px solid ${divergenciasValor > 0 ? '#fecaca' : '#bfdbfe'};border-radius:10px;padding:10px;">
        <div style="font-size:11px;color:${divergenciasValor > 0 ? '#991b1b' : '#1d4ed8'};">Divergências de valor</div>
        <div style="font-size:13px;font-weight:700;color:${divergenciasValor > 0 ? '#991b1b' : '#1d4ed8'};">${divergenciasValor}</div>
      </div>
      <div style="background:${divergenciasQtdUnid > 0 ? '#fef2f2' : '#eff6ff'};border:1px solid ${divergenciasQtdUnid > 0 ? '#fecaca' : '#bfdbfe'};border-radius:10px;padding:10px;">
        <div style="font-size:11px;color:${divergenciasQtdUnid > 0 ? '#991b1b' : '#1d4ed8'};">Qtd/Unid. divergentes</div>
        <div style="font-size:13px;font-weight:700;color:${divergenciasQtdUnid > 0 ? '#991b1b' : '#1d4ed8'};">${divergenciasQtdUnid}</div>
      </div>
      <div style="background:${itensInformativosTotal > 0 ? '#fff7ed' : '#f8fafc'};border:1px solid ${itensInformativosTotal > 0 ? '#fed7aa' : '#e2e8f0'};border-radius:10px;padding:10px;">
        <div style="font-size:11px;color:${itensInformativosTotal > 0 ? '#9a3412' : '#64748b'};">Itens informativos</div>
        <div style="font-size:13px;font-weight:700;color:${itensInformativosTotal > 0 ? '#9a3412' : '#0f172a'};">${itensInformativosTotal}</div>
      </div>
    </div>
  `;

  const linhasHtml = itens.length
    ? itens.map((item) => {
        const isServico = !!item?.item_servico;
        const encontrou = !!item?.pedido_item_encontrado;
        const criterio = isServico
          ? 'Servico por CFOP'
          : item?.criterio_match === 'id_produto'
          ? 'ID produto'
          : item?.criterio_match === 'codigo_produto'
            ? 'Código produto'
            : item?.criterio_match === 'ajuste_manual_arrastar'
              ? 'Ajuste manual'
            : item?.criterio_match === 'fallback_item_unico_pedido'
              ? 'Item único do pedido'
            : item?.criterio_match === 'agrupamento_mesmo_item_pedido'
              ? 'Item agrupado'
              : (encontrou ? 'Match identificado' : 'Sem match');
        const nfValor = Number(item?.nf_valor_total || 0);
        const pedidoValor = Number((isServico ? item?.nf_valor_total : item?.pedido_valor_total) || 0);
        const agrupadoMesmoItem = item?.criterio_match === 'agrupamento_mesmo_item_pedido';
        const divergiuValor = Number.isFinite(nfValor) && Number.isFinite(pedidoValor) && Math.abs(nfValor - pedidoValor) > 0.01;
        const seq = Number(item?.n_sequencia || 0);
        const overrideCampos = window.__associarNfeCamposEditados?.[seq] || {};
        const qtdPedidoBase = item?.pedido_qtde ?? '-';
        const qtdPedido = isServico ? (item?.nf_qtde ?? '-') : (overrideCampos?.nQtde ?? qtdPedidoBase);
        const valorPedidoEditado = isServico ? item?.nf_valor_total : (overrideCampos?.nValTot ?? item?.pedido_valor_total);
        const unidadePedidoBase = obterUnidadePedidoPreviewAssociacao(item);
        const unidadePedido = isServico ? (item?.nf_unidade || '-') : (overrideCampos?.cUnidade || unidadePedidoBase);
        const divergiuQtd = !isServico && !agrupadoMesmoItem && compararQuantidadePreview({ ...item, pedido_qtde: qtdPedido });
        const divergiuUnidade = !isServico && !agrupadoMesmoItem && compararUnidadePreview(item, unidadePedido);
        const pedidoValorComparacao = Number(valorPedidoEditado || 0);
        const divergiuValorEditado = !isServico && !agrupadoMesmoItem && Number.isFinite(nfValor) && Number.isFinite(pedidoValorComparacao) && Math.abs(nfValor - pedidoValorComparacao) > 0.01;
        const temDivergencia = divergiuValorEditado || divergiuQtd || divergiuUnidade;
        const qtdNf = item?.nf_qtde ?? '-';
        const corQtd = divergiuQtd ? '#b91c1c' : '#0f172a';
        const bgQtd = divergiuQtd ? '#fee2e2' : 'transparent';
        const corUnid = divergiuUnidade ? '#b91c1c' : '#0f172a';
        const bgUnid = divergiuUnidade ? '#fee2e2' : 'transparent';
        const possuiSugestaoPedido = !encontrou && !isServico && Array.isArray(item?.pedido_sugestoes) && item.pedido_sugestoes.length > 0;
        const resumoSugestoesPedido = possuiSugestaoPedido ? obterResumoSugestoesPedido(item) : '';
        const pedidoItemNumero = String(item?.pedido_numero || '').trim();
        const pedidoEhComplementar = !!pedidoItemNumero && !!pedidoBaseNumero && pedidoItemNumero !== pedidoBaseNumero;
        const badgePedidoItem = pedidoItemNumero
          ? `<div style="display:inline-flex;align-items:center;gap:6px;font-size:10px;font-weight:800;color:${pedidoEhComplementar ? '#1d4ed8' : '#166534'};background:${pedidoEhComplementar ? '#dbeafe' : '#dcfce7'};border:1px solid ${pedidoEhComplementar ? '#93c5fd' : '#86efac'};border-radius:999px;padding:3px 8px;margin-bottom:4px;">Pedido ${escapeHtml(pedidoItemNumero)}${pedidoEhComplementar ? ' - complementar' : ''}</div>`
          : '';

        return `
          <tr style="border-bottom:1px solid #e2e8f0;background:${!encontrou ? '#fff7ed' : (temDivergencia ? '#fff7f7' : '#f8fafc')};" data-seq="${Number(item?.n_sequencia || 0)}">
            <td style="padding:7px 8px;font-size:11px;color:#0f172a;text-align:center;">${Number(item?.n_sequencia || 0) || '-'}</td>
            <td style="padding:7px 8px;font-size:11px;color:#0f172a;">${escapeHtml(String(item?.nf_codigo_produto || '-'))}</td>
            <td style="padding:7px 8px;font-size:11px;color:#0f172a;max-width:220px;line-height:1.35;" title="${escapeHtml(String(item?.nf_descricao_produto || '-'))}">${escapeHtml(String(item?.nf_descricao_produto || '-'))}</td>
            <td style="padding:7px 8px;font-size:11px;color:${corQtd};background:${bgQtd};text-align:right;white-space:nowrap;font-weight:${divergiuQtd ? '700' : '400'};">${escapeHtml(String(qtdNf))}</td>
            <td style="padding:7px 8px;font-size:11px;color:${corUnid};background:${bgUnid};text-align:center;white-space:nowrap;font-weight:${divergiuUnidade ? '700' : '400'};">${escapeHtml(String(item?.nf_unidade || '-'))}</td>
            <td style="padding:7px 8px;font-size:11px;text-align:right;font-weight:700;color:${divergiuValor ? '#b91c1c' : '#0f172a'};background:${divergiuValor ? '#fee2e2' : 'transparent'};border-right:3px solid #cbd5e1;">${escapeHtml(formatarValorRecebimento(item?.nf_valor_total))}</td>
            <td colspan="2" style="padding:7px 8px;font-size:11px;color:#0f172a;max-width:380px;line-height:1.35;">
              ${isServico ? `
              <div style="display:flex;align-items:center;gap:8px;padding:6px 8px;border:1px solid #bae6fd;border-radius:8px;background:#f0f9ff;">
                <i class="fa-solid fa-screwdriver-wrench" style="color:#0369a1;"></i>
                <div style="min-width:0;flex:1;">
                  <div style="font-size:11px;font-weight:800;color:#075985;">${escapeHtml(String(item?.servico_produto_codigo || item?.nf_codigo_produto || 'Servico'))}</div>
                  <div style="font-size:11px;color:#334155;line-height:1.35;">${escapeHtml(String(item?.servico_produto_descricao || item?.nf_descricao_produto || ''))}</div>
                </div>
                <button type="button" class="assoc-servico-produto-btn" data-seq="${seq}" style="border:1px solid #38bdf8;background:#0284c7;color:#fff;border-radius:7px;padding:5px 8px;font-size:11px;font-weight:700;cursor:pointer;">Selecionar</button>
              </div>` : encontrou ? `
              <div class="assoc-pedido-draggable" data-seq="${seq}" draggable="true" style="display:flex;align-items:flex-start;gap:8px;padding:6px 8px;border:1px dashed #cbd5e1;border-radius:8px;background:#ffffff;cursor:grab;">
                <i class="fa-solid fa-grip-vertical" style="margin-top:1px;color:#64748b;"></i>
                <div style="display:flex;flex-direction:column;gap:2px;min-width:0;">
                  ${badgePedidoItem}
                  <div style="font-size:11px;font-weight:700;color:#0f172a;">${escapeHtml(String(item?.pedido_codigo_produto || '-'))}</div>
                  <div style="font-size:11px;color:#334155;line-height:1.35;max-width:320px;" title="${escapeHtml(String(item?.pedido_descricao_produto || '-'))}">${escapeHtml(String(item?.pedido_descricao_produto || '-'))}</div>
                </div>
              </div>` : `
              <div style="display:flex;align-items:center;gap:8px;padding:6px 8px;border:1px dashed #fed7aa;border-radius:8px;background:#fff7ed;flex-wrap:wrap;">
                ${item?.produto_override && Number(item?.servico_produto_codigo_produto || 0) > 0 ? `
                <div style="min-width:0;flex:1;">
                  <div style="font-size:11px;font-weight:800;color:#9a3412;">${escapeHtml(String(item?.servico_produto_codigo || '-'))}</div>
                  <div style="font-size:11px;color:#7c2d12;line-height:1.35;max-width:240px;" title="${escapeHtml(String(item?.servico_produto_descricao || ''))}">${escapeHtml(String(item?.servico_produto_descricao || ''))}</div>
                </div>` : `
                <i class="fa-solid fa-triangle-exclamation" style="color:#ea580c;font-size:12px;flex-shrink:0;"></i>
                <span style="font-size:11px;color:#9a3412;flex:1;">Sem match — selecione o produto</span>`}
                <button type="button" class="assoc-produto-override-btn" data-seq="${seq}" style="border:1px solid #fb923c;background:#ea580c;color:#fff;border-radius:7px;padding:5px 8px;font-size:11px;font-weight:700;cursor:pointer;white-space:nowrap;flex-shrink:0;">${item?.produto_override && Number(item?.servico_produto_codigo_produto || 0) > 0 ? 'Alterar' : 'Selecionar produto'}</button>
                ${possuiSugestaoPedido ? `<button type="button" class="assoc-sugestao-pedido-btn" data-seq="${seq}" title="Usar a melhor sugestão automática encontrada" style="border:1px solid #60a5fa;background:#2563eb;color:#fff;border-radius:7px;padding:5px 8px;font-size:11px;font-weight:700;cursor:pointer;white-space:nowrap;flex-shrink:0;">Usar sugestão</button>` : ''}
                <button type="button" class="assoc-item-pedido-btn" data-seq="${seq}" title="Vincular a um item do pedido atual ou de um pedido complementar sugerido" style="border:1px solid #16a34a;background:#15803d;color:#fff;border-radius:7px;padding:5px 8px;font-size:11px;font-weight:700;cursor:pointer;white-space:nowrap;flex-shrink:0;">Escolher item</button>
              </div>`}
            </td>
            <td style="padding:7px 8px;font-size:11px;color:${corQtd};background:${bgQtd};text-align:right;white-space:nowrap;">${
              (!isServico && divergiuQtd)
                ? `<input type="text" class="assoc-override-qtd" data-seq="${seq}" value="${escapeHtml(fmtQtdBR(qtdPedido))}" style="width:72px;padding:2px 4px;font-size:11px;font-weight:700;color:#b91c1c;border:1px solid #fca5a5;border-radius:4px;text-align:right;background:#fff5f5;" title="Edite a quantidade do item do pedido">`
                : escapeHtml(String(qtdPedido))
            }</td>
            <td style="padding:7px 8px;font-size:11px;color:${corUnid};background:${bgUnid};text-align:center;white-space:nowrap;">${
              (!isServico && (divergiuQtd || divergiuUnidade))
                ? `<input type="text" class="assoc-override-unid" data-seq="${seq}" value="${escapeHtml(String(unidadePedido || ''))}" style="width:50px;padding:2px 4px;font-size:11px;font-weight:700;color:#b91c1c;border:1px solid #fca5a5;border-radius:4px;text-align:center;background:#fff5f5;text-transform:uppercase;" title="Edite a unidade para associação">`
                : escapeHtml(String(unidadePedido || '-'))
            }</td>
            <td style="padding:7px 8px;font-size:11px;text-align:right;font-weight:700;color:${divergiuValorEditado ? '#b91c1c' : '#0f172a'};background:${divergiuValorEditado ? '#fee2e2' : 'transparent'};">${
              divergiuValorEditado
                ? `<input type="text" class="assoc-override-valor" data-seq="${seq}" value="${escapeHtml(Number(valorPedidoEditado || 0).toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 }))}" style="width:82px;padding:2px 4px;font-size:11px;font-weight:700;color:#b91c1c;border:1px solid #fca5a5;border-radius:4px;text-align:right;background:#fff5f5;" title="Edite o valor total do item do pedido">`
                : escapeHtml(formatarValorRecebimento(valorPedidoEditado))
            }</td>
            <td style="padding:7px 8px;font-size:11px;text-align:center;color:${temDivergencia ? '#b91c1c' : (encontrou ? '#166534' : '#9a3412')};font-weight:700;">${escapeHtml(criterio)}</td>
          </tr>
        `;
      }).join('')
    : '<tr><td colspan="12" style="padding:10px;font-size:11px;color:#64748b;text-align:center;">Sem itens para pré-visualização.</td></tr>';

  const itensInformativosHtml = itensInformativosPedido.length
    ? `
      <div style="margin:0 0 10px;padding:10px 12px;border:1px solid #fed7aa;background:#fff7ed;color:#9a3412;border-radius:8px;font-size:12px;">
        <div style="display:flex;align-items:center;gap:8px;font-weight:800;margin-bottom:8px;">
          <i class="fa-solid fa-circle-info"></i>
          <span>${itensInformativosPedido.length} item(ns) do pedido foram tratados como informativos</span>
        </div>
        <div style="font-size:11px;line-height:1.45;margin-bottom:8px;">Eles existem no pedido apenas como referencia interna e nao serao associados a NF-e. A associacao segue somente com os itens que vieram na nota.</div>
        <div style="display:grid;gap:6px;">
          ${itensInformativosPedido.map((itemInfo) => `
            <div style="display:grid;grid-template-columns:minmax(90px,.7fr) minmax(220px,2fr) minmax(80px,.5fr) minmax(90px,.7fr);gap:8px;align-items:center;background:#ffffff;border:1px solid #fed7aa;border-radius:8px;padding:8px;">
              <div style="font-weight:800;color:#7c2d12;font-size:11px;">${escapeHtml(String(itemInfo?.pedido_codigo_produto || '-'))}</div>
              <div style="color:#431407;font-size:11px;line-height:1.35;">${escapeHtml(String(itemInfo?.pedido_descricao_produto || '-'))}</div>
              <div style="text-align:right;color:#7c2d12;font-size:11px;">${escapeHtml(String(itemInfo?.pedido_qtde ?? '-'))} ${escapeHtml(String(itemInfo?.pedido_unidade || ''))}</div>
              <div style="text-align:right;font-weight:800;color:#7c2d12;font-size:11px;">${escapeHtml(formatarValorRecebimento(itemInfo?.pedido_valor_total))}</div>
            </div>
          `).join('')}
        </div>
      </div>
    `
    : '';
  const pedidosEnvolvidosHtml = pedidosEnvolvidos.length > 1
    ? `
      <div style="margin:0 0 10px;padding:10px 12px;border:1px solid #93c5fd;background:#eff6ff;color:#1d4ed8;border-radius:8px;font-size:12px;">
        <div style="font-weight:800;margin-bottom:4px;">Esta NF-e sera vinculada a mais de um pedido.</div>
        <div>Pedidos envolvidos: ${escapeHtml(pedidosEnvolvidos.map((pedido) => pedido.numero).join(', '))}.</div>
        <div style="margin-top:4px;">Ao concluir a NF, o sistema atualiza cada pedido individualmente conforme o valor realmente recebido em cada um.</div>
      </div>
    `
    : '';

  previewConteudo.innerHTML = `
    ${resumoHtml}
    ${pedidosEnvolvidosHtml}
    ${itensInformativosHtml}
    ${gruposMesmoItem > 0 ? `<div style="margin:0 0 10px;padding:10px 12px;border:1px solid #bbf7d0;background:#ecfdf5;color:#166534;border-radius:8px;font-size:12px;font-weight:700;"><i class="fa-solid fa-layer-group" style="margin-right:6px;"></i>${gruposMesmoItem} linha(s) da NF-e foram agrupadas no mesmo item do pedido. A conferência usa a soma das linhas, não cada linha isolada.</div>` : ''}
    <div style="margin:0 0 10px;padding:9px 12px;border:1px solid #bae6fd;background:#f0f9ff;color:#0c4a6e;border-radius:8px;font-size:12px;font-weight:700;">Arraste o bloco do item do Pedido (coluna azul com ícone <i class="fa-solid fa-grip-vertical"></i>) para outra linha da NF-e para trocar a associação.</div>
    ${(divergenciasValor > 0 || divergenciasQtdUnid > 0) ? `<div style="margin:0 0 10px;padding:10px 12px;border:1px solid #fecaca;background:#fff1f2;color:#b91c1c;border-radius:8px;font-size:12px;font-weight:700;">Existem divergências de valor, quantidade ou unidade entre a NF-e e o pedido.${divergenciasQtdUnid > 0 ? ' Edite os campos de Qtd/Unid. do Pedido (em vermelho) antes de associar.' : ' Os campos divergentes estão destacados em vermelho.'}</div>` : ''}
    <div style="max-height:340px;overflow:auto;border:1px solid #e2e8f0;border-radius:10px;">
      <table style="width:100%;border-collapse:collapse;min-width:1220px;">
        <thead>
          <tr style="position:sticky;top:0;background:#f8fafc;border-bottom:1px solid #e2e8f0;">
            <th style="padding:7px 8px;font-size:11px;color:#334155;text-align:center;">Seq</th>
            <th style="padding:7px 8px;font-size:11px;color:#334155;text-align:left;">Código NF</th>
            <th style="padding:7px 8px;font-size:11px;color:#334155;text-align:left;">Descrição NF</th>
            <th style="padding:7px 8px;font-size:11px;color:#334155;text-align:right;">Qtd NF</th>
            <th style="padding:7px 8px;font-size:11px;color:#334155;text-align:center;">Unid. NF</th>
            <th style="padding:7px 8px;font-size:11px;color:#334155;text-align:right;border-right:3px solid #cbd5e1;">Valor NF</th>
            <th style="padding:7px 8px;font-size:11px;color:#334155;text-align:left;">Código Pedido</th>
            <th style="padding:7px 8px;font-size:11px;color:#334155;text-align:left;">Descrição Pedido</th>
            <th style="padding:7px 8px;font-size:11px;color:#334155;text-align:right;">Qtd Pedido</th>
            <th style="padding:7px 8px;font-size:11px;color:#334155;text-align:center;">Unid. Pedido</th>
            <th style="padding:7px 8px;font-size:11px;color:#334155;text-align:right;">Valor Pedido</th>
            <th style="padding:7px 8px;font-size:11px;color:#334155;text-align:center;">Match</th>
          </tr>
        </thead>
        <tbody>${linhasHtml}
          <tr style="background:#eef2ff;border-top:2px solid #cbd5e1;">
            <td colspan="5" style="padding:8px;font-size:11px;font-weight:700;color:#1e3a8a;text-align:right;">Total</td>
            <td style="padding:8px;font-size:11px;font-weight:700;color:#1e3a8a;text-align:right;border-right:3px solid #cbd5e1;">${escapeHtml(formatarValorRecebimento(totalValorNfPreview))}</td>
            <td colspan="4" style="padding:8px;font-size:11px;font-weight:700;color:#166534;text-align:right;">Total</td>
            <td style="padding:8px;font-size:11px;font-weight:700;color:#166534;text-align:right;">${escapeHtml(formatarValorRecebimento(totalValorPedidoPreview))}</td>
            <td style="padding:8px;font-size:11px;color:#334155;text-align:center;">&nbsp;</td>
          </tr>
        </tbody>
      </table>
    </div>
  `;

  previewWrap.style.display = 'block';
  habilitarDragDropAssociacaoPedidoNfe(preview);
  previewConteudo.querySelectorAll('.assoc-override-qtd, .assoc-override-unid, .assoc-override-valor').forEach((input) => {
    input.addEventListener('input', snapshotEdicoesQtdUnidAssociacaoNfe);
    input.addEventListener('change', snapshotEdicoesQtdUnidAssociacaoNfe);
  });
  previewConteudo.querySelectorAll('.assoc-servico-produto-btn').forEach((btn) => {
    btn.addEventListener('click', () => abrirModalProdutoServicoAssociacaoNfe(Number(btn.dataset.seq || 0)));
  });
  previewConteudo.querySelectorAll('.assoc-produto-override-btn').forEach((btn) => {
    btn.addEventListener('click', () => abrirModalProdutoServicoAssociacaoNfe(Number(btn.dataset.seq || 0)));
  });
  previewConteudo.querySelectorAll('.assoc-sugestao-pedido-btn').forEach((btn) => {
    btn.addEventListener('click', () => aplicarSugestaoPedidoAssociacao(Number(btn.dataset.seq || 0), 0));
  });
  previewConteudo.querySelectorAll('.assoc-item-pedido-btn').forEach((btn) => {
    btn.addEventListener('click', () => abrirPickerItemPedidoAssociacaoAvancado(Number(btn.dataset.seq || 0)));
  });
}

function aplicarVinculoItemPedidoAssociacao(seq, dadosItem = {}) {
  if (!seq) return false;
  const item = (window.__associarNfePreviewEstadoItens || []).find(i => Number(i?.n_sequencia || 0) === seq);
  if (!item) return false;

  const nCodItem = Number(dadosItem?.pedido_n_cod_item || dadosItem?.nCodItem || 0);
  if (!Number.isFinite(nCodItem) || nCodItem <= 0) return false;

  const nCodPed = Number(dadosItem?.pedido_n_cod_ped || dadosItem?.nCodPed || 0);
  const numeroPedido = String(dadosItem?.pedido_numero || dadosItem?.numeroPedido || '').trim();
  const numeroPedidoBase = String(window.__associarNfePreviewAtual?.preview?.c_numero_pedido || '').trim();

  item.pedido_item_encontrado = true;
  item.pedido_item_override = true;
  item.pedido_n_cod_ped = Number.isFinite(nCodPed) && nCodPed > 0
    ? nCodPed
    : (Number(window.__associarNfePreviewAtual?.preview?.n_cod_ped || 0) || null);
  item.pedido_numero = numeroPedido || numeroPedidoBase || null;
  item.pedido_n_cod_item = nCodItem;
  item.pedido_codigo_produto = dadosItem?.pedido_codigo_produto || dadosItem?.codigo || '';
  item.pedido_descricao_produto = dadosItem?.pedido_descricao_produto || dadosItem?.descricao || '';
  item.pedido_qtde = (dadosItem?.pedido_qtde ?? dadosItem?.qtde ?? '') !== '' ? Number(dadosItem?.pedido_qtde ?? dadosItem?.qtde) : null;
  item.pedido_unidade = dadosItem?.pedido_unidade || dadosItem?.unidade || '';
  item.pedido_valor_total = (dadosItem?.pedido_valor_total ?? dadosItem?.valor ?? '') !== '' ? Number(dadosItem?.pedido_valor_total ?? dadosItem?.valor) : null;
  item.criterio_match = item.pedido_numero && numeroPedidoBase && item.pedido_numero !== numeroPedidoBase
    ? 'ajuste_manual_pedido_complementar'
    : 'ajuste_manual_item_pedido';
  item.score_match = 9999;
  delete item.produto_override;

  renderPreviewAssociacaoPedidoNfe(window.__associarNfePreviewAtual?.preview || {});
  const btnAssociarMain = document.getElementById('modalAssociarPedidoBtnConfirmar');
  if (btnAssociarMain) btnAssociarMain.disabled = false;
  return true;
}

function aplicarSugestaoPedidoAssociacao(seq, indiceSugestao = 0) {
  const item = (window.__associarNfePreviewEstadoItens || []).find(i => Number(i?.n_sequencia || 0) === seq);
  if (!item) return false;
  const sugestoes = Array.isArray(item?.pedido_sugestoes) ? item.pedido_sugestoes : [];
  const sugestao = sugestoes[Number(indiceSugestao) || 0];
  if (!sugestao) return false;
  return aplicarVinculoItemPedidoAssociacao(seq, sugestao);
}

function abrirPickerItemPedidoAssociacao(seq) {
  if (!seq) return;
  const preview = window.__associarNfePreviewAtual?.preview || {};
  const numeroPedido = String(preview?.c_numero_pedido || '').trim();
  const itemAtual = (window.__associarNfePreviewEstadoItens || []).find(i => Number(i?.n_sequencia || 0) === seq);
  const itensComplementares = Array.isArray(itemAtual?.pedido_sugestoes)
    ? itemAtual.pedido_sugestoes.map((itemSugestao) => ({ ...itemSugestao, origem_lista: 'pedido_complementar' }))
    : [];

  // Coleta todos os itens do pedido: informativos + matched
  let itensPedido = [
    ...itensComplementares,
    ...(preview.itens_pedido_informativos || []),
    ...(preview.itens_preview || [])
      .filter(i => i.pedido_item_encontrado && Number(i.pedido_n_cod_item || 0) > 0)
      .map(i => ({
        pedido_n_cod_ped: i.pedido_n_cod_ped || preview?.n_cod_ped || null,
        pedido_numero: i.pedido_numero || preview?.c_numero_pedido || null,
        pedido_n_cod_item: i.pedido_n_cod_item,
        pedido_codigo_produto: i.pedido_codigo_produto,
        pedido_descricao_produto: i.pedido_descricao_produto,
        pedido_qtde: i.pedido_qtde,
        pedido_unidade: i.pedido_unidade,
        pedido_valor_total: i.pedido_valor_total,
      }))
  ];
  // Remove duplicatas por n_cod_item
  const seen = new Set();
  itensPedido = itensPedido.filter(i => {
    const k = Number(i.pedido_n_cod_item || 0);
    if (!k || seen.has(k)) return false;
    seen.add(k); return true;
  });
  const itensComplementaresFiltrados = itensComplementares.filter(i => {
    const k = Number(i.pedido_n_cod_item || 0);
    if (!k || seen.has(k)) return false;
    seen.add(k); return true;
  });

  let modal = document.getElementById('modalItemPedidoAssociacao');
  if (modal) modal.remove();
  modal = document.createElement('div');
  modal.id = 'modalItemPedidoAssociacao';
  modal.style.cssText = 'position:fixed;inset:0;z-index:2147483647;background:rgba(15,23,42,.70);display:flex;align-items:center;justify-content:center;padding:20px;';

  const renderItensHtml = (items) => {
    if (!items.length) return '<div style="font-size:12px;color:#64748b;padding:12px;">Nenhum item encontrado para o pedido.</div>';
    return items.map(it => `
      <button type="button"
        data-n-cod-ped="${Number(it.pedido_n_cod_ped || 0)}"
        data-numero-pedido="${escapeHtml(String(it.pedido_numero || numeroPedido || ''))}"
        data-n-cod-item="${Number(it.pedido_n_cod_item || 0)}"
        data-codigo="${escapeHtml(String(it.pedido_codigo_produto || ''))}"
        data-descricao="${escapeHtml(String(it.pedido_descricao_produto || ''))}"
        data-qtde="${escapeHtml(String(it.pedido_qtde ?? ''))}"
        data-unidade="${escapeHtml(String(it.pedido_unidade || ''))}"
        data-valor="${escapeHtml(String(it.pedido_valor_total ?? ''))}"
        style="display:flex;align-items:center;justify-content:space-between;gap:14px;text-align:left;border:1px solid #bbf7d0;background:#f0fdf4;border-radius:10px;padding:10px;cursor:pointer;width:100%;">
        <span style="min-width:0;">
          <div style="font-size:10px;font-weight:800;color:${it.origem_lista === 'pedido_complementar' ? '#1d4ed8' : '#166534'};margin-bottom:3px;">Pedido ${escapeHtml(String(it.pedido_numero || numeroPedido || it.pedido_n_cod_ped || '-'))}${it.origem_lista === 'pedido_complementar' ? ' - sugestão automática' : ''}</div>
          <div style="font-weight:800;color:#0f172a;">${escapeHtml(String(it.pedido_codigo_produto || '-'))}</div>
          <div style="font-size:12px;color:#475569;">${escapeHtml(String(it.pedido_descricao_produto || '-'))}</div>
          <div style="font-size:11px;color:#64748b;margin-top:2px;">Qtd: ${escapeHtml(String(it.pedido_qtde ?? '-'))} ${escapeHtml(String(it.pedido_unidade || ''))} · R$ ${escapeHtml(Number(it.pedido_valor_total || 0).toLocaleString('pt-BR', { minimumFractionDigits: 2 }))}</div>
        </span>
        <span style="white-space:nowrap;background:#15803d;color:white;border-radius:8px;padding:7px 10px;font-size:12px;font-weight:800;">Usar este item</span>
      </button>`).join('');
  };

  modal.innerHTML = `
    <div style="width:min(820px,95vw);max-height:85vh;overflow:auto;background:#fff;border:2px solid #16a34a;border-radius:16px;box-shadow:0 24px 80px rgba(0,0,0,.35);padding:18px;">
      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:8px;">
        <strong style="font-size:18px;color:#0f172a;">Itens do Pedido ${escapeHtml(String(numeroPedido || ''))}</strong>
        <button type="button" id="modalItemPedidoFechar" style="border:0;background:transparent;font-size:26px;cursor:pointer;color:#334155;">&times;</button>
      </div>
      <div style="font-size:12px;color:#475569;margin-bottom:12px;">Clique em <strong>Usar este item</strong> para vincular o item do pedido à linha da NF-e não mapeada.</div>
      <div id="modalItemPedidoLista" style="display:flex;flex-direction:column;gap:8px;">
        ${itensPedido.length ? renderItensHtml(itensPedido) : '<div style="font-size:12px;color:#64748b;">Carregando itens...</div>'}
      </div>
    </div>`;

  document.body.appendChild(modal);
  modal.querySelector('#modalItemPedidoFechar').onclick = () => modal.remove();

  function attachSelectHandlers() {
    modal.querySelectorAll('button[data-n-cod-item]').forEach(btn => {
      btn.onclick = () => {
        const aplicado = aplicarVinculoItemPedidoAssociacao(seq, {
          pedido_n_cod_ped: Number(btn.dataset.nCodPed || 0) || null,
          pedido_numero: btn.dataset.numeroPedido || '',
          pedido_n_cod_item: Number(btn.dataset.nCodItem || 0) || null,
          pedido_codigo_produto: btn.dataset.codigo || '',
          pedido_descricao_produto: btn.dataset.descricao || '',
          pedido_qtde: btn.dataset.qtde !== '' ? Number(btn.dataset.qtde) : null,
          pedido_unidade: btn.dataset.unidade || '',
          pedido_valor_total: btn.dataset.valor !== '' ? Number(btn.dataset.valor) : null
        });
        if (!aplicado) return;
        modal.remove();
      };
    });
  }

  // Se sem itens no preview, busca via API
  if (!itensPedido.length && numeroPedido) {
    const lista = modal.querySelector('#modalItemPedidoLista');
    fetch(`/api/compras/buscar-pedido-compra?numero=${encodeURIComponent(numeroPedido)}`, { credentials: 'include', cache: 'no-store' })
      .then(r => r.json())
      .then(data => {
        const itensApi = (data?.pedido?.itens || []).filter(i => Number(i.n_cod_item || 0) > 0);
        lista.innerHTML = itensApi.length
          ? renderItensHtml(itensApi.map(i => ({
              pedido_n_cod_ped: preview?.n_cod_ped || null,
              pedido_numero: numeroPedido || null,
              pedido_n_cod_item: i.n_cod_item,
              pedido_codigo_produto: i.c_produto || i.produto_codigo,
              pedido_descricao_produto: i.c_descricao || i.produto_descricao,
              pedido_qtde: i.n_qtde !== undefined ? i.n_qtde : i.quantidade,
              pedido_unidade: i.c_unidade || i.unidade,
              pedido_valor_total: i.n_val_tot !== undefined ? i.n_val_tot : i.valor_item,
            })))
          : '<div style="font-size:12px;color:#64748b;">Nenhum item encontrado.</div>';
        attachSelectHandlers();
      })
      .catch(() => {
        lista.innerHTML = '<div style="font-size:12px;color:#b91c1c;">Erro ao carregar itens do pedido.</div>';
      });
  } else {
    attachSelectHandlers();
  }
}

function abrirPickerItemPedidoAssociacaoAvancado(seq) {
  if (!seq) return;
  const preview = window.__associarNfePreviewAtual?.preview || {};
  const numeroPedidoBase = String(preview?.c_numero_pedido || '').trim();
  const itemAtual = (window.__associarNfePreviewEstadoItens || []).find((i) => Number(i?.n_sequencia || 0) === seq);
  const sugestoesComplementares = Array.isArray(itemAtual?.pedido_sugestoes)
    ? itemAtual.pedido_sugestoes.map((itemSugestao) => ({ ...itemSugestao, origem_lista: 'pedido_complementar' }))
    : [];

  const dedupeItens = (items, seen = new Set()) => items.filter((item) => {
    const codItem = Number(item?.pedido_n_cod_item || 0);
    if (!codItem || seen.has(codItem)) return false;
    seen.add(codItem);
    return true;
  });

  const itensPedidoBase = [
    ...(preview.itens_pedido_informativos || []),
    ...(preview.itens_preview || [])
      .filter((i) => i.pedido_item_encontrado && Number(i.pedido_n_cod_item || 0) > 0)
      .map((i) => ({
        pedido_n_cod_ped: i.pedido_n_cod_ped || preview?.n_cod_ped || null,
        pedido_numero: i.pedido_numero || preview?.c_numero_pedido || null,
        pedido_n_cod_item: i.pedido_n_cod_item,
        pedido_codigo_produto: i.pedido_codigo_produto,
        pedido_descricao_produto: i.pedido_descricao_produto,
        pedido_qtde: i.pedido_qtde,
        pedido_unidade: i.pedido_unidade,
        pedido_valor_total: i.pedido_valor_total,
        origem_lista: 'pedido_base'
      }))
  ];

  const seen = new Set();
  const sugestoesFiltradas = dedupeItens(sugestoesComplementares, seen);
  const itensBaseFiltrados = dedupeItens(itensPedidoBase, seen);

  let modal = document.getElementById('modalItemPedidoAssociacaoAvancado');
  if (modal) modal.remove();
  modal = document.createElement('div');
  modal.id = 'modalItemPedidoAssociacaoAvancado';
  modal.style.cssText = 'position:fixed;inset:0;z-index:2147483647;background:rgba(15,23,42,.70);display:flex;align-items:center;justify-content:center;padding:20px;';

  const renderItensHtml = (items, tituloSecao = '', emptyText = 'Nenhum item encontrado.') => {
    if (!items.length) {
      return `
        ${tituloSecao ? `<div style="font-size:12px;font-weight:800;color:#0f172a;margin:10px 0 6px;">${escapeHtml(tituloSecao)}</div>` : ''}
        <div style="font-size:12px;color:#64748b;padding:12px;">${escapeHtml(emptyText)}</div>
      `;
    }
    return `
      ${tituloSecao ? `<div style="font-size:12px;font-weight:800;color:#0f172a;margin:10px 0 6px;">${escapeHtml(tituloSecao)}</div>` : ''}
      ${items.map((it) => `
        <button type="button"
          data-n-cod-ped="${Number(it.pedido_n_cod_ped || 0)}"
          data-numero-pedido="${escapeHtml(String(it.pedido_numero || numeroPedidoBase || ''))}"
          data-n-cod-item="${Number(it.pedido_n_cod_item || 0)}"
          data-codigo="${escapeHtml(String(it.pedido_codigo_produto || ''))}"
          data-descricao="${escapeHtml(String(it.pedido_descricao_produto || ''))}"
          data-qtde="${escapeHtml(String(it.pedido_qtde ?? ''))}"
          data-unidade="${escapeHtml(String(it.pedido_unidade || ''))}"
          data-valor="${escapeHtml(String(it.pedido_valor_total ?? ''))}"
          style="display:flex;align-items:center;justify-content:space-between;gap:14px;text-align:left;border:1px solid #bbf7d0;background:#f0fdf4;border-radius:10px;padding:10px;cursor:pointer;width:100%;">
          <span style="min-width:0;">
            <div style="font-size:10px;font-weight:800;color:${it.origem_lista === 'pedido_complementar' ? '#1d4ed8' : (it.origem_lista === 'pedido_manual' ? '#7c3aed' : '#166534')};margin-bottom:3px;">Pedido ${escapeHtml(String(it.pedido_numero || numeroPedidoBase || it.pedido_n_cod_ped || '-'))}${it.origem_lista === 'pedido_complementar' ? ' - sugestão automática' : ''}${it.origem_lista === 'pedido_manual' ? ' - carregado manualmente' : ''}</div>
            <div style="font-weight:800;color:#0f172a;">${escapeHtml(String(it.pedido_codigo_produto || '-'))}</div>
            <div style="font-size:12px;color:#475569;">${escapeHtml(String(it.pedido_descricao_produto || '-'))}</div>
            <div style="font-size:11px;color:#64748b;margin-top:2px;">Qtd: ${escapeHtml(String(it.pedido_qtde ?? '-'))} ${escapeHtml(String(it.pedido_unidade || ''))} · R$ ${escapeHtml(Number(it.pedido_valor_total || 0).toLocaleString('pt-BR', { minimumFractionDigits: 2 }))}</div>
          </span>
          <span style="white-space:nowrap;background:#15803d;color:white;border-radius:8px;padding:7px 10px;font-size:12px;font-weight:800;">Usar este item</span>
        </button>
      `).join('')}
    `;
  };

  modal.innerHTML = `
    <div style="width:min(860px,95vw);max-height:85vh;overflow:auto;background:#fff;border:2px solid #16a34a;border-radius:16px;box-shadow:0 24px 80px rgba(0,0,0,.35);padding:18px;">
      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:8px;">
        <strong style="font-size:18px;color:#0f172a;">Escolher item para a linha ${escapeHtml(String(seq))} da NF-e</strong>
        <button type="button" id="modalItemPedidoAvancadoFechar" style="border:0;background:transparent;font-size:26px;cursor:pointer;color:#334155;">&times;</button>
      </div>
      <div style="font-size:12px;color:#475569;margin-bottom:12px;">Use a melhor sugestão, escolha outra sugestão listada abaixo ou carregue manualmente outro pedido pelo número.</div>
      <div id="modalItemPedidoAvancadoLista" style="display:flex;flex-direction:column;gap:8px;">
        ${sugestoesFiltradas.length > 0 ? renderItensHtml(sugestoesFiltradas, 'Sugestões automáticas de outros pedidos', 'Nenhuma sugestão automática encontrada.') : ''}
        ${renderItensHtml(itensBaseFiltrados, `Itens do pedido ${numeroPedidoBase || ''}`, 'Nenhum item encontrado no pedido base.')}
      </div>
      <div style="margin-top:14px;padding-top:12px;border-top:1px solid #e2e8f0;">
        <div style="font-size:12px;font-weight:800;color:#0f172a;margin-bottom:8px;">Carregar outro pedido manualmente</div>
        <div style="display:flex;gap:8px;flex-wrap:wrap;align-items:center;">
          <input id="modalItemPedidoAvancadoNumeroManual" type="text" placeholder="Digite o número do outro pedido" style="flex:1;min-width:240px;padding:10px 12px;border:1px solid #cbd5e1;border-radius:8px;font-size:14px;color:#0f172a;" />
          <button type="button" id="modalItemPedidoAvancadoBuscarManual" style="border:1px solid #0ea5e9;background:#0284c7;color:#fff;border-radius:8px;padding:9px 12px;font-size:12px;font-weight:800;cursor:pointer;">Carregar pedido</button>
        </div>
        <div id="modalItemPedidoAvancadoManualStatus" style="font-size:12px;color:#64748b;margin-top:8px;">Se souber o pedido correto, digite o número e carregue os itens dele.</div>
        <div id="modalItemPedidoAvancadoListaManual" style="display:flex;flex-direction:column;gap:8px;margin-top:8px;"></div>
      </div>
    </div>`;

  document.body.appendChild(modal);
  modal.querySelector('#modalItemPedidoAvancadoFechar').onclick = () => modal.remove();

  const aplicarSelecao = (btn) => {
    const aplicado = aplicarVinculoItemPedidoAssociacao(seq, {
      pedido_n_cod_ped: Number(btn.dataset.nCodPed || 0) || null,
      pedido_numero: btn.dataset.numeroPedido || '',
      pedido_n_cod_item: Number(btn.dataset.nCodItem || 0) || null,
      pedido_codigo_produto: btn.dataset.codigo || '',
      pedido_descricao_produto: btn.dataset.descricao || '',
      pedido_qtde: btn.dataset.qtde !== '' ? Number(btn.dataset.qtde) : null,
      pedido_unidade: btn.dataset.unidade || '',
      pedido_valor_total: btn.dataset.valor !== '' ? Number(btn.dataset.valor) : null
    });
    if (!aplicado) return;
    modal.remove();
  };

  const attachSelectHandlers = () => {
    modal.querySelectorAll('button[data-n-cod-item]').forEach((btn) => {
      btn.onclick = () => aplicarSelecao(btn);
    });
  };

  const listaManual = modal.querySelector('#modalItemPedidoAvancadoListaManual');
  const statusManual = modal.querySelector('#modalItemPedidoAvancadoManualStatus');
  const inputManual = modal.querySelector('#modalItemPedidoAvancadoNumeroManual');
  const btnManual = modal.querySelector('#modalItemPedidoAvancadoBuscarManual');

  const carregarItensPedidoManual = async (numeroPedidoManual) => {
    const numeroManual = String(numeroPedidoManual || '').trim();
    if (!numeroManual) {
      if (statusManual) statusManual.textContent = 'Digite um número de pedido para carregar os itens.';
      if (listaManual) listaManual.innerHTML = '';
      return;
    }

    if (statusManual) statusManual.textContent = `Carregando itens do pedido ${numeroManual}...`;
    if (listaManual) listaManual.innerHTML = '<div style="font-size:12px;color:#64748b;padding:12px;">Buscando pedido informado...</div>';
    if (btnManual) btnManual.disabled = true;

    try {
      const resp = await fetch(`/api/compras/buscar-pedido-compra?numero=${encodeURIComponent(numeroManual)}`, { credentials: 'include', cache: 'no-store' });
      const data = await resp.json().catch(() => ({}));
      if (!resp.ok || !data?.pedido) {
        throw new Error(data?.error || `Falha ao carregar pedido ${numeroManual}.`);
      }

      const numeroPedidoCarregado = String(data?.pedido?.c_numero || data?.pedido?.numero || numeroManual).trim() || numeroManual;
      const itensApi = (data?.pedido?.itens || [])
        .filter((i) => Number(i.n_cod_item || 0) > 0)
        .map((i) => ({
          pedido_n_cod_ped: data?.pedido?.n_cod_ped || data?.pedido?.nCodPed || null,
          pedido_numero: numeroPedidoCarregado,
          pedido_n_cod_item: i.n_cod_item,
          pedido_codigo_produto: i.c_produto || i.produto_codigo,
          pedido_descricao_produto: i.c_descricao || i.produto_descricao,
          pedido_qtde: i.n_qtde !== undefined ? i.n_qtde : i.quantidade,
          pedido_unidade: i.c_unidade || i.unidade,
          pedido_valor_total: i.n_val_tot !== undefined ? i.n_val_tot : i.valor_item,
          origem_lista: 'pedido_manual'
        }));

      if (listaManual) {
        listaManual.innerHTML = renderItensHtml(
          itensApi,
          `Itens do pedido ${numeroPedidoCarregado}`,
          'Nenhum item encontrado no pedido informado.'
        );
      }
      if (statusManual) {
        statusManual.textContent = itensApi.length > 0
          ? `Pedido ${numeroPedidoCarregado} carregado. Escolha um item abaixo.`
          : `Pedido ${numeroPedidoCarregado} encontrado, mas sem itens utilizáveis.`;
      }
      attachSelectHandlers();
    } catch (err) {
      if (listaManual) listaManual.innerHTML = '';
      if (statusManual) statusManual.textContent = err?.message || `Erro ao carregar o pedido ${numeroManual}.`;
    } finally {
      if (btnManual) btnManual.disabled = false;
    }
  };

  btnManual?.addEventListener('click', () => carregarItensPedidoManual(inputManual?.value || ''));
  inputManual?.addEventListener('keydown', (event) => {
    if (event.key === 'Enter') {
      event.preventDefault();
      carregarItensPedidoManual(inputManual?.value || '');
    }
  });

  attachSelectHandlers();
}

function abrirModalProdutoServicoAssociacaoNfe(seq) {
  if (!seq) return;
  let modal = document.getElementById('modalProdutoServicoAssociacaoNfe');
  if (modal) modal.remove();
  modal = document.createElement('div');
  modal.id = 'modalProdutoServicoAssociacaoNfe';
  modal.style.cssText = 'position:fixed;inset:0;z-index:2147483647;background:rgba(15,23,42,.70);display:flex;align-items:center;justify-content:center;padding:20px;';
  modal.innerHTML = `
    <div style="width:min(820px,95vw);max-height:85vh;overflow:auto;background:#fff;border:2px solid #0284c7;border-radius:16px;box-shadow:0 24px 80px rgba(0,0,0,.35);padding:18px;">
      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:8px;">
        <strong style="font-size:18px;color:#0f172a;">Escolha o produto/servico cadastrado</strong>
        <button type="button" id="modalServicoProdutoFechar" style="border:0;background:transparent;font-size:26px;cursor:pointer;color:#334155;">&times;</button>
      </div>
      <div style="font-size:12px;color:#475569;margin-bottom:12px;">Pesquise e clique em <strong>Usar este produto</strong> para vincular ao item de servico da NF-e.</div>
      <input id="modalServicoProdutoBusca" placeholder="Pesquisar por codigo, nome ou descricao" style="width:100%;padding:11px;border:1px solid #cbd5e1;border-radius:9px;margin-bottom:12px;font-size:14px;">
      <div id="modalServicoProdutoResultados" style="display:grid;gap:8px;"></div>
    </div>`;
  document.body.appendChild(modal);
  modal.querySelector('#modalServicoProdutoFechar').onclick = () => modal.remove();
  const input = modal.querySelector('#modalServicoProdutoBusca');
  const resultados = modal.querySelector('#modalServicoProdutoResultados');
  const itemAtual = (window.__associarNfePreviewEstadoItens || []).find(i => Number(i?.n_sequencia || 0) === seq);

  async function buscarProdutosServicoAssociacao(q) {
    q = String(q || '').trim();
    if (q.length < 2) {
      resultados.innerHTML = '<div style="font-size:12px;color:#64748b;">Digite ao menos 2 caracteres para buscar.</div>';
      return;
    }
    resultados.innerHTML = '<div style="font-size:12px;color:#64748b;">Buscando...</div>';
    try {
      const resp = await fetch('/api/produtos/busca', { method:'POST', headers:{'Content-Type':'application/json'}, credentials:'include', body: JSON.stringify({ q }) });
      const data = await resp.json().catch(() => ({}));
      const itens = Array.isArray(data?.itens) ? data.itens.slice(0, 40) : [];
      resultados.innerHTML = itens.length ? itens.map(p => `
        <button type="button" data-cp="${escapeHtml(String(p.codigo_produto || ''))}" data-codigo="${escapeHtml(String(p.codigo || ''))}" data-desc="${escapeHtml(String(p.descricao || ''))}" style="display:flex;align-items:center;justify-content:space-between;gap:14px;text-align:left;border:1px solid #bae6fd;background:#f0f9ff;border-radius:10px;padding:10px;cursor:pointer;">
          <span style="min-width:0;">
            <div style="font-weight:800;color:#0f172a;">${escapeHtml(String(p.codigo || '-'))}</div>
            <div style="font-size:12px;color:#475569;">${escapeHtml(String(p.descricao || '-'))}</div>
          </span>
          <span style="white-space:nowrap;background:#0284c7;color:white;border-radius:8px;padding:7px 10px;font-size:12px;font-weight:800;">Usar este produto</span>
        </button>`).join('') : '<div style="font-size:12px;color:#b91c1c;">Nenhum produto encontrado.</div>';
      resultados.querySelectorAll('button[data-cp]').forEach(btn => {
        btn.onclick = () => {
          const item = (window.__associarNfePreviewEstadoItens || []).find(i => Number(i?.n_sequencia || 0) === seq);
          if (item) {
            item.servico_produto_codigo_produto = Number(btn.dataset.cp || 0) || null;
            item.servico_produto_codigo = btn.dataset.codigo || '';
            item.servico_produto_descricao = btn.dataset.desc || '';
            if (!item.item_servico) item.produto_override = true;
          }
          modal.remove();
          renderPreviewAssociacaoPedidoNfe(window.__associarNfePreviewAtual?.preview || {});
        };
      });
    } catch (err) {
      resultados.innerHTML = `<div style="font-size:12px;color:#b91c1c;">Falha ao buscar produtos: ${escapeHtml(String(err?.message || err))}</div>`;
    }
  }

  input.value = String(itemAtual?.servico_produto_codigo || itemAtual?.nf_codigo_produto || itemAtual?.nf_descricao_produto || '').trim();
  resultados.innerHTML = '<div style="font-size:12px;color:#64748b;">Buscando sugestoes...</div>';
  input.oninput = () => buscarProdutosServicoAssociacao(input.value);
  buscarProdutosServicoAssociacao(input.value);
  setTimeout(() => input.focus(), 50);
}

async function previsualizarAssociacaoPedidoNfeOmie() {
  const nfeInput = document.getElementById('modalAssociarNfeNumeroInput');
  const pedidoInput = document.getElementById('modalAssociarPedidoNumeroInput');
  const btnPreview = document.getElementById('modalAssociarPedidoBtnPreview');
  const btnAssociar = document.getElementById('modalAssociarPedidoBtnConfirmar');

  if (!nfeInput || !pedidoInput || !btnPreview || !btnAssociar) return;

  const numeroNfe = String(nfeInput.value || '').trim();
  const numeroPedido = String(pedidoInput.value || '').trim();

  if (!numeroNfe) {
    setStatusModalAssociarPedidoNfe('Informe o número da NF-e.', 'erro');
    return;
  }
  if (!numeroPedido) {
    setStatusModalAssociarPedidoNfe('Informe o número do pedido para gerar a prévia.', 'erro');
    return;
  }

  const textoOriginal = btnPreview.innerHTML;
  btnPreview.disabled = true;
  btnAssociar.disabled = true;
  btnPreview.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i>';
  setStatusModalAssociarPedidoNfe('Gerando prévia dos itens da NF-e e do pedido...', 'info');

  try {
    const contextoAtual = window.__associarNfeContextoAtual || {};

    const resp = await fetch('/api/compras/pedidos-omie/nfe-associar-pedido/preview', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({
        numero_nfe: numeroNfe,
        chave_nfe: String(contextoAtual?.chave_nfe || '').trim(),
        numero_pedido: numeroPedido,
        n_cod_ped: Number(contextoAtual?.n_cod_ped || 0) || null
      })
    });

    const data = await resp.json().catch(() => ({}));
    if (!resp.ok || !data?.ok) {
      throw new Error(data?.error || `Falha ao gerar prévia (HTTP ${resp.status})`);
    }

    window.__associarNfePreviewAtual = {
      numeroNfe,
      numeroPedido,
      preview: data.preview
    };
    window.__associarNfePreviewEstadoItens = Array.isArray(data?.preview?.itens)
      ? data.preview.itens.map((item) => ({ ...item }))
      : [];
    window.__associarNfeCamposEditados = {};

    if (window.__associarNfeRecebimentoAtual && data?.preview?.categoria) {
      window.__associarNfeRecebimentoAtual = {
        ...window.__associarNfeRecebimentoAtual,
        categoria: data.preview.categoria
      };
    }

    const categoriaInfo = data?.preview?.categoria || window.__associarNfeRecebimentoAtual?.categoria || null;
    if (categoriaInfo?.inativa) {
      await carregarSeletorCategoriasAssociarNfe(categoriaInfo.codigo || '', categoriaInfo.descricao || '');
    } else {
      const pickerCategoria = document.getElementById('modalAssociarCategoriaPicker');
      if (pickerCategoria) pickerCategoria.style.display = 'none';
    }

    renderPreviewAssociacaoPedidoNfe(data.preview);

    const qtdSemMatch = Number(data?.preview?.itens_sem_match_total || 0);
    if (qtdSemMatch > 0) {
      setStatusModalAssociarPedidoNfe(
        `Prévia gerada. ${qtdSemMatch} item(ns) da NF-e não foram mapeados ao pedido — revise antes de confirmar.`,
        'erro'
      );
      resetBotaoAssociarPedidoNfe(true);
    } else {
      setStatusModalAssociarPedidoNfe('Prévia gerada. Itens prontos para associação.', 'sucesso');
      resetBotaoAssociarPedidoNfe(false);
    }
  } catch (err) {
    setStatusModalAssociarPedidoNfe(err?.message || 'Erro ao gerar prévia de associação.', 'erro');
  } finally {
    btnPreview.disabled = false;
    btnPreview.innerHTML = textoOriginal;
  }
}

async function localizarNfeParaAssociacaoOmie() {
  const nfeInput = document.getElementById('modalAssociarNfeNumeroInput');
  const btnLocalizar = document.getElementById('modalAssociarNfeBtnLocalizar');
  const blocoPedido = document.getElementById('modalAssociarPedidoNfeBlocoPedido');

  if (!nfeInput || !btnLocalizar || !blocoPedido) return;

  const numeroNfe = String(nfeInput.value || '').trim();
  if (!numeroNfe) {
    setStatusModalAssociarPedidoNfe('Informe o número da NF-e para localizar.', 'erro');
    return;
  }

  limparEtapaPedidoModalAssociarNfe();
  setStatusModalAssociarPedidoNfe('Localizando NF-e na Omie...', 'info');

  const textoOriginal = btnLocalizar.innerHTML;
  btnLocalizar.disabled = true;
  btnLocalizar.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i>';

  try {
    const resp = await fetch('/api/compras/pedidos-omie/nfe-associar-pedido/consultar', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({ numero_nfe: numeroNfe })
    });

    const data = await resp.json().catch(() => ({}));
    if (!resp.ok || !data?.ok) {
      throw new Error(data?.error || `Falha ao consultar NF-e (HTTP ${resp.status})`);
    }

    window.__associarNfeRecebimentoAtual = data?.recebimento || null;
    blocoPedido.style.display = 'block';

    const numeroNfeEncontrada = data?.recebimento?.c_numero_nfe || numeroNfe;
    const pedidosJaVinculados = Array.isArray(data?.recebimento?.pedidos_vinculados)
      ? data.recebimento.pedidos_vinculados.filter(Boolean)
      : [];

    // Exibe picker de categoria se a categoria atual estiver inativa
    const categoriaInfo = data?.recebimento?.categoria || null;
    if (categoriaInfo?.inativa) {
      await carregarSeletorCategoriasAssociarNfe(categoriaInfo.codigo || '', categoriaInfo.descricao || '');
    } else {
      const pickerCategoria = document.getElementById('modalAssociarCategoriaPicker');
      if (pickerCategoria) pickerCategoria.style.display = 'none';
    }

    if (pedidosJaVinculados.length > 0) {
      setStatusModalAssociarPedidoNfe(
        `NF-e ${numeroNfeEncontrada} localizada. Já vinculada aos pedidos: ${pedidosJaVinculados.join(', ')}.`,
        'info'
      );
    } else if (categoriaInfo?.inativa) {
      setStatusModalAssociarPedidoNfe(`NF-e ${numeroNfeEncontrada} localizada. Categoria inativa detectada — selecione uma substituta acima.`, 'erro');
    } else {
      setStatusModalAssociarPedidoNfe(`NF-e ${numeroNfeEncontrada} localizada. Informe o pedido para associar.`, 'sucesso');
    }

    const pedidoInput = document.getElementById('modalAssociarPedidoNumeroInput');
    if (pedidoInput) pedidoInput.focus();
  } catch (err) {
    setStatusModalAssociarPedidoNfe(err?.message || 'Erro ao localizar NF-e na Omie.', 'erro');
  } finally {
    btnLocalizar.disabled = false;
    btnLocalizar.innerHTML = textoOriginal;
  }
}

// ── Pré-visualização de etiqueta de recebimento (ZPL → PDF via backend) ──
async function imprimirEtiquetaRecebimentoPreview() {
  const nfe    = String(document.getElementById('modalAssociarNfeNumeroInput')?.value || '').trim();
  const pedido = String(document.getElementById('modalAssociarPedidoNumeroInput')?.value || '').trim();

  if (!nfe) {
    setStatusModalAssociarPedidoNfe('Informe o número da NF-e antes de imprimir.', 'erro');
    return;
  }
  if (!pedido) {
    setStatusModalAssociarPedidoNfe('Informe o número do pedido antes de imprimir.', 'erro');
    return;
  }

  const preview = window.__associarNfePreviewAtual?.preview || {};
  const itensPreview = Array.isArray(preview.itens) ? preview.itens : [];

  // Quantidade da etiqueta/PIR = sempre a da NF-e (recebimento parcial é normal)
  const itensParaImprimir = itensPreview
    .filter(it => it?.pedido_codigo_produto)
    .map(it => ({
      codigo_produto:    String(it.pedido_codigo_produto  || '').trim(),
      descricao_produto: String(it.pedido_descricao_produto || '').trim(),
      qtd:     String(it.nf_qtde ?? it.pedido_qtde ?? ''),
      unidade: String(it.nf_unidade ?? it.pedido_unidade ?? '').trim(),
    }));

  if (itensParaImprimir.length === 0) {
    setStatusModalAssociarPedidoNfe('Nenhum item com código de produto identificado. Gere a prévia antes de imprimir.', 'erro');
    return;
  }

  const payload = { nfe, pedido, itens: itensParaImprimir, usuario: (document.getElementById('userNameDisplay')?.textContent || '').trim() };

  const btn = document.getElementById('modalAssociarPedidoBtnImprimir');
  const textoOriginal = btn ? btn.innerHTML : '';
  if (btn) { btn.disabled = true; btn.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i>'; }

  try {
    const resp = await fetch('/api/etiquetas/recebimento/preview', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify(payload),
    });

    // 409 = todas as etiquetas já existem no banco
    if (resp.status === 409) {
      const err = await resp.json().catch(() => ({}));
      setStatusModalAssociarPedidoNfe(err?.error || 'Etiquetas já geradas anteriormente para esta NF-e/Pedido.', 'info');
      return;
    }

    if (!resp.ok) {
      const err = await resp.json().catch(() => ({}));
      throw new Error(err?.error || `Erro ${resp.status}`);
    }

    const geradas  = resp.headers.get('X-Etiquetas-Geradas')  || itensParaImprimir.length;
    const ignoradas = resp.headers.get('X-Etiquetas-Ignoradas') || '0';

    const blob = await resp.blob();
    const url  = URL.createObjectURL(blob);
    window.open(url, '_blank');
    setTimeout(() => URL.revokeObjectURL(url), 5 * 60 * 1000);

    const msg = Number(ignoradas) > 0
      ? `${geradas} etiqueta(s) gerada(s). ${ignoradas} já existia(m) e foram ignoradas.`
      : `${geradas} etiqueta(s) gerada(s) com sucesso.`;
    setStatusModalAssociarPedidoNfe(msg, 'sucesso');
  } catch (err) {
    setStatusModalAssociarPedidoNfe('Erro ao gerar etiquetas: ' + (err?.message || err), 'erro');
  } finally {
    if (btn) { btn.disabled = false; btn.innerHTML = textoOriginal || '<i class="fa-solid fa-print"></i> Imprimir'; }
  }
}

async function confirmarAssociacaoPedidoNfeOmie() {
  const nfeInput = document.getElementById('modalAssociarNfeNumeroInput');
  const pedidoInput = document.getElementById('modalAssociarPedidoNumeroInput');
  const btnAssociar = document.getElementById('modalAssociarPedidoBtnConfirmar');

  if (!nfeInput || !pedidoInput || !btnAssociar) return;

  const numeroNfe = String(nfeInput.value || '').trim();
  const numeroPedido = String(pedidoInput.value || '').trim();

  if (!numeroNfe) {
    setStatusModalAssociarPedidoNfe('Informe o número da NF-e.', 'erro');
    return;
  }
  if (!numeroPedido) {
    setStatusModalAssociarPedidoNfe('Informe o número do pedido para associar.', 'erro');
    return;
  }

  const previewAtual = window.__associarNfePreviewAtual;
  const previewValida = !!previewAtual
    && String(previewAtual.numeroNfe || '').trim() === numeroNfe
    && String(previewAtual.numeroPedido || '').trim() === numeroPedido;

  if (!previewValida) {
    setStatusModalAssociarPedidoNfe('Gere a prévia atualizada antes de confirmar a associação.', 'erro');
    await previsualizarAssociacaoPedidoNfeOmie();
    return;
  }

  const pickerCategoria = document.getElementById('modalAssociarCategoriaPicker');
  const selectCategoria = document.getElementById('modalAssociarCategoriaSelect');
  const pickerVisivel = pickerCategoria && pickerCategoria.style.display !== 'none';
  const categoriaSelecionada = String(selectCategoria?.value || '').trim();

  if (pickerVisivel && !categoriaSelecionada) {
    setStatusModalAssociarPedidoNfe('Selecione uma categoria ativa antes de associar a NF-e ao pedido.', 'erro');
    selectCategoria?.focus();
    return;
  }

  let associacaoConcluida = false;
  btnAssociar.disabled = true;
  btnAssociar.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i>';
  setStatusModalAssociarPedidoNfe('Associando NF-e ao pedido na Omie...', 'info');

  try {
    const contextoAtual = window.__associarNfeContextoAtual || {};
    const pedidosEnvolvidosPreview = Array.from(new Set(
      (Array.isArray(window.__associarNfePreviewEstadoItens) ? window.__associarNfePreviewEstadoItens : [])
        .map((item) => String(item?.pedido_numero || '').trim())
        .filter(Boolean)
    ));

    // Coleta overrides de vínculo/Qtd/Unid editados pelo usuário na prévia
    const itensOverrideMap = new Map();
    const itensEstado = Array.isArray(window.__associarNfePreviewEstadoItens)
      ? window.__associarNfePreviewEstadoItens
      : [];

    itensEstado.forEach((item) => {
      const seq = Number(item?.n_sequencia || 0);
      if (item?.item_servico) {
        itensOverrideMap.set(seq, {
          n_sequencia: seq,
          item_servico: true,
          nIdProdutoServico: Number(item?.servico_produto_codigo_produto || 0) || null,
          codigoProdutoServico: String(item?.servico_produto_codigo || item?.nf_codigo_produto || '').trim(),
          descricaoProdutoServico: String(item?.servico_produto_descricao || item?.nf_descricao_produto || '').trim(),
          nQtde: Number(item?.nf_qtde || 0) || null,
          cUnidade: String(item?.nf_unidade || '').trim().toUpperCase() || null
        });
        return;
      }
      if (item?.produto_override && Number(item?.servico_produto_codigo_produto || 0) > 0) {
        itensOverrideMap.set(seq, {
          n_sequencia: seq,
          nIdProdutoServico: Number(item?.servico_produto_codigo_produto || 0) || null,
          codigoProdutoServico: String(item?.servico_produto_codigo || '').trim(),
          descricaoProdutoServico: String(item?.servico_produto_descricao || '').trim(),
          nQtde: Number(item?.nf_qtde || 0) || null,
          cUnidade: String(item?.nf_unidade || '').trim().toUpperCase() || null
        });
        return;
      }
      const nIdItPedidoExistente = Number(item?.pedido_n_cod_item || 0);
      if (!seq || !Number.isFinite(nIdItPedidoExistente) || nIdItPedidoExistente <= 0) return;
      const nIdPedidoExistente = Number(item?.pedido_n_cod_ped || 0);
      itensOverrideMap.set(seq, {
        n_sequencia: seq,
        nIdPedidoExistente: Number.isFinite(nIdPedidoExistente) && nIdPedidoExistente > 0 ? nIdPedidoExistente : null,
        nIdItPedidoExistente
      });
    });

    const previewConteudo = document.getElementById('modalAssociarPedidoNfePreviewConteudo');
    if (previewConteudo) {
      previewConteudo.querySelectorAll('.assoc-override-qtd, .assoc-override-unid, .assoc-override-valor').forEach(input => {
        const seq = Number(input.dataset.seq || 0);
        if (!seq) return;
        let entry = itensOverrideMap.get(seq);
        if (!entry) {
          entry = { n_sequencia: seq };
          itensOverrideMap.set(seq, entry);
        }
        if (input.classList.contains('assoc-override-qtd')) {
          const textoQtd = String(input.value || '').trim();
          const qtd = textoQtd
            ? Number(textoQtd.includes(',') ? textoQtd.replace(/\./g, '').replace(',', '.') : textoQtd)
            : null;
          entry.nQtde = Number.isFinite(qtd) ? qtd : null;
        }
        if (input.classList.contains('assoc-override-unid')) {
          entry.cUnidade = String(input.value || '').trim().toUpperCase() || null;
        }
        if (input.classList.contains('assoc-override-valor')) {
          const valor = parseFloat(String(input.value || '').replace(/\./g, '').replace(',', '.'));
          entry.nValTot = Number.isFinite(valor) ? valor : null;
        }
      });
    }

    const itensOverride = Array.from(itensOverrideMap.values());

    const resp = await fetch('/api/compras/pedidos-omie/nfe-associar-pedido', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({
        numero_nfe: numeroNfe,
        chave_nfe: String(contextoAtual?.chave_nfe || '').trim(),
        numero_pedido: numeroPedido,
        n_cod_ped: Number(contextoAtual?.n_cod_ped || 0) || null,
        itens_override: itensOverride.length > 0 ? itensOverride : undefined,
        nova_categoria_compra: (() => {
          const sel = document.getElementById('modalAssociarCategoriaSelect');
          return sel?.value?.trim() || undefined;
        })()
      })
    });

    const data = await resp.json().catch(() => ({}));
    if (!resp.ok || !data?.ok) {
      throw new Error(data?.error || `Falha ao associar NF-e (HTTP ${resp.status})`);
    }
    associacaoConcluida = true;

    // ── Registra etiquetas automaticamente após associar ─────────────────
    try {
      const _previewEtq = window.__associarNfePreviewAtual?.preview || {};
      const _itensEtq   = Array.isArray(_previewEtq.itens) ? _previewEtq.itens : [];
      const _itensParaEtq = _itensEtq
        .filter(it => it?.pedido_codigo_produto)
        .map(it => ({
          codigo_produto:    String(it.pedido_codigo_produto  || '').trim(),
          descricao_produto: String(it.pedido_descricao_produto || '').trim(),
          // Sempre quantidade da NF-e (pedido pode ser maior; outra NF completa depois)
          qtd:     String(it.nf_qtde ?? it.pedido_qtde ?? ''),
          unidade: String(it.nf_unidade ?? it.pedido_unidade ?? '').trim(),
        }));
      if (_itensParaEtq.length > 0) {
        fetch('/api/etiquetas/recebimento/preview', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          credentials: 'include',
          body: JSON.stringify({ nfe: numeroNfe, pedido: numeroPedido, itens: _itensParaEtq, usuario: (document.getElementById('userNameDisplay')?.textContent || '').trim() }),
        }).then(async r => {
          if (r.ok) {
            const geradas = r.headers.get('X-Etiquetas-Geradas') || _itensParaEtq.length;
            console.log(`[etiquetas] ${geradas} etiqueta(s) registrada(s) para NF-e ${numeroNfe} / pedido ${numeroPedido}`);
          }
          // descarta o PDF — apenas registra no banco
        }).catch(e => console.warn('[etiquetas] falha ao registrar etiquetas:', e?.message));
      }
    } catch (_etqErr) {
      console.warn('[etiquetas] falha ao preparar etiquetas:', _etqErr?.message);
    }
    // ─────────────────────────────────────────────────────────────────────

    const pedidosAssociadosRetorno = Array.isArray(data?.dados?.pedidos_associados)
      ? data.dados.pedidos_associados
        .map((pedido) => String(pedido?.c_numero_pedido || pedido?.n_cod_ped || '').trim())
        .filter(Boolean)
      : [];
    const pedidosAssociadosExibir = pedidosAssociadosRetorno.length > 0
      ? pedidosAssociadosRetorno
      : pedidosEnvolvidosPreview;
    const resumoPedidosAssociados = pedidosAssociadosExibir.length > 0
      ? `<div style="margin-top:8px;font-size:12px;color:#166534;font-weight:700;">Pedidos afetados: ${escapeHtml(pedidosAssociadosExibir.join(', '))}</div>`
      : '';

    setStatusModalAssociarPedidoNfe(
      `<div style="display:flex;align-items:flex-start;gap:12px;">
        <i class="fa-solid fa-circle-check" style="font-size:26px;color:#16a34a;margin-top:2px;"></i>
        <div style="flex:1;">
          <div style="font-size:17px;font-weight:800;line-height:1.2;">NF-e associada com sucesso</div>
          <div style="font-size:13px;margin-top:5px;">${escapeHtml(data?.message || `NF-e ${numeroNfe} associada ao pedido ${numeroPedido}.`)}</div>
          ${resumoPedidosAssociados}
          <div style="display:flex;gap:8px;flex-wrap:wrap;margin-top:12px;">
            <button type="button" id="modalAssociarNovaBuscaBtn" style="border:none;border-radius:8px;background:#7c3aed;color:#fff;font-weight:700;padding:9px 13px;cursor:pointer;display:inline-flex;align-items:center;gap:6px;">
              <i class="fa-solid fa-magnifying-glass"></i> Buscar outra NF-e
            </button>
            <button type="button" id="modalAssociarFecharSucessoBtn" style="border:1px solid #86efac;border-radius:8px;background:#ffffff;color:#166534;font-weight:700;padding:9px 13px;cursor:pointer;">
              Fechar
            </button>
            <button type="button" id="modalAssociarTransformacaoMpBtn" style="border:none;border-radius:8px;background:linear-gradient(135deg,#ea580c 0%,#c2410c 100%);color:#fff;font-weight:700;padding:9px 13px;cursor:pointer;display:inline-flex;align-items:center;gap:6px;">
              <i class="fa-solid fa-arrows-rotate"></i> Transformação de MP
            </button>
          </div>
        </div>
      </div>`,
      'sucesso'
    );

    // Guarda dados da associação para o modal de transformação
    window.__transformacaoMpDados = {
      n_id_receb: data?.dados?.n_id_receb || null,
      numero_nfe: data?.dados?.c_numero_nfe || null,
      fornecedor_nome: data?.dados?.fornecedor_nome || window.__associarNfePreviewAtual?.preview?.fornecedor_nome || null,
      valor_total: data?.dados?.valor_total_nfe
        || window.__associarNfePreviewAtual?.preview?.valor_total_nfe
        || (Array.isArray(window.__associarNfePreviewEstadoItens)
            ? +(window.__associarNfePreviewEstadoItens.reduce((a, it) => a + (Number(it.nf_valor_total) || 0), 0)).toFixed(2) || null
            : null)
        || null,
      solicitante: (document.getElementById('userNameDisplay')?.textContent || '').trim() || null,
    };

    document.getElementById('modalAssociarTransformacaoMpBtn')?.addEventListener('click', () => {
      abrirModalTransformacaoMp(window.__transformacaoMpDados);
    });

    document.getElementById('modalAssociarNovaBuscaBtn')?.addEventListener('click', () => {
      fecharModalAssociarPedidoNfe();
      if (typeof window.abrirModalLocalizarNfe === 'function') {
        window.abrirModalLocalizarNfe();
      }
      const inputLocalizar = document.getElementById('modalLocalizarNfeInput');
      if (inputLocalizar) {
        inputLocalizar.value = '';
        inputLocalizar.focus();
      }
      const conteudoLocalizar = document.getElementById('modalLocalizarNfeConteudo');
      if (conteudoLocalizar) {
        conteudoLocalizar.innerHTML = '<div style="display:flex;align-items:center;justify-content:center;color:#94a3b8;font-size:13px;padding:24px 0;gap:8px;"><i class="fa-solid fa-file-invoice"></i><span>Digite o numero da NF-e e clique em Buscar.</span></div>';
      }
    });
    document.getElementById('modalAssociarFecharSucessoBtn')?.addEventListener('click', fecharModalAssociarPedidoNfe);

    if (typeof loadComprasRecebimento === 'function') {
      loadComprasRecebimento(true).catch(() => {});
    }
    if (window.atualizarListaNfesOmie) {
      atualizarListaNfesOmie().catch(() => {});
    }
  } catch (err) {
    setStatusModalAssociarPedidoNfe(err?.message || 'Erro ao associar NF-e ao pedido.', 'erro');
  } finally {
    if (associacaoConcluida) {
      btnAssociar.disabled = true;
      btnAssociar.innerHTML = '<i class="fa-solid fa-circle-check"></i> Associado';
    } else {
      resetBotaoAssociarPedidoNfe(false);
    }
  }
}

// ═══════════════════════════════════════════════════════════════════════════════
// TRANSFORMAÇÃO DE MATÉRIA-PRIMA
// Modal para registrar SAI + ENT de peças após processamento externo (ex: zincagem)
// Custo é rateado proporcionalmente à área (largura × altura) de cada peça
// ═══════════════════════════════════════════════════════════════════════════════

function criarModalTransformacaoMpSeNecessario() {
  if (document.getElementById('modalTransformacaoMp')) return;
  const el = document.createElement('div');
  el.id = 'modalTransformacaoMp';
  el.style.cssText = 'display:none;position:fixed;inset:0;background:rgba(15,23,42,.72);z-index:100200;align-items:center;justify-content:center;padding:18px;';
  el.innerHTML = `
    <div style="width:min(980px,100%);max-height:92vh;background:#fff;border-radius:14px;box-shadow:0 24px 60px rgba(2,6,23,.38);border:1px solid #d1d5db;overflow:hidden;display:flex;flex-direction:column;">
      <div style="display:flex;align-items:center;justify-content:space-between;padding:14px 18px;border-bottom:1px solid #e5e7eb;background:linear-gradient(135deg,#fff7ed 0%,#ffedd5 100%);">
        <strong style="font-size:15px;color:#0f172a;display:flex;align-items:center;gap:8px;">
          <i class="fa-solid fa-arrows-rotate" style="color:#ea580c;"></i>
          Transformação de Matéria-Prima
        </strong>
        <button type="button" id="modalTransformacaoMpFechar" style="border:none;background:transparent;color:#475569;font-size:18px;cursor:pointer;padding:4px 8px;"><i class="fa-solid fa-xmark"></i></button>
      </div>
      <div id="modalTransformacaoMpConteudo" style="padding:18px;overflow:auto;flex:1;display:flex;flex-direction:column;gap:14px;"></div>
      <div style="padding:14px 18px;border-top:1px solid #e5e7eb;background:#f8fafc;display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:10px;">
        <label style="display:flex;align-items:center;gap:7px;font-size:13px;color:#475569;cursor:pointer;">
          <input type="checkbox" id="modalTransformacaoMpSalvarTemplate" style="width:15px;height:15px;">
          Salvar como template para este fornecedor
        </label>
        <div style="display:flex;gap:8px;">
          <button type="button" id="modalTransformacaoMpCancelar" style="padding:10px 16px;border:1px solid #d1d5db;border-radius:8px;background:#fff;color:#475569;font-weight:700;cursor:pointer;font-size:14px;">Cancelar</button>
          <button type="button" id="modalTransformacaoMpExecutar" style="padding:10px 20px;border:none;border-radius:8px;background:linear-gradient(135deg,#ea580c 0%,#c2410c 100%);color:#fff;font-weight:700;cursor:pointer;font-size:14px;display:inline-flex;align-items:center;gap:7px;">
            <i class="fa-solid fa-check"></i> Executar Transformação
          </button>
        </div>
      </div>
    </div>
  `;
  document.body.appendChild(el);
}

function fecharModalTransformacaoMp() {
  const modal = document.getElementById('modalTransformacaoMp');
  if (modal) modal.style.display = 'none';
}

function calcularRateioAreaFrontend(itens, valorTotal) {
  const parsed = itens.map(it => ({
    ...it,
    _qtde: Number(it.qtde) || 0,
    _l: Number(it.largura_cm) || 0,
    _a: Number(it.altura_cm) || 0,
  }));
  const totalArea = parsed.reduce((acc, it) => acc + it._qtde * (it._l / 100) * (it._a / 100), 0);
  if (totalArea <= 0) return parsed.map(it => ({ ...it, area_unit_m2: 0, custo_unit: 0 }));
  const custoPorM2 = valorTotal / totalArea;
  return parsed.map(it => {
    const areaUnit = (it._l / 100) * (it._a / 100);
    return { ...it, area_unit_m2: +areaUnit.toFixed(6), custo_unit: +(areaUnit * custoPorM2).toFixed(4) };
  });
}

function formatarMoeda(v) {
  if (!Number.isFinite(Number(v))) return '—';
  return Number(v).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
}

function renderizarTabelaTransformacaoMp(itens, valorTotal) {
  const comCusto = calcularRateioAreaFrontend(itens, Number(valorTotal) || 0);
  const totalGeral = comCusto.reduce((acc, it) => acc + it.custo_unit * it._qtde, 0);
  return `
    <table style="width:100%;border-collapse:collapse;font-size:13px;">
      <thead>
        <tr style="background:#fef3c7;color:#92400e;font-weight:700;">
          <th style="padding:8px 10px;text-align:left;border:1px solid #fde68a;">SKU</th>
          <th style="padding:8px 10px;text-align:left;border:1px solid #fde68a;">Descrição</th>
          <th style="padding:8px 6px;text-align:center;border:1px solid #fde68a;white-space:nowrap;">Larg.(cm)</th>
          <th style="padding:8px 6px;text-align:center;border:1px solid #fde68a;white-space:nowrap;">Alt.(cm)</th>
          <th style="padding:8px 6px;text-align:center;border:1px solid #fde68a;">Qtde</th>
          <th style="padding:8px 6px;text-align:center;border:1px solid #fde68a;white-space:nowrap;">Área (m²)</th>
          <th style="padding:8px 6px;text-align:right;border:1px solid #fde68a;white-space:nowrap;">Custo/un</th>
          <th style="padding:8px 6px;text-align:right;border:1px solid #fde68a;">Subtotal</th>
          <th style="padding:8px 6px;text-align:center;border:1px solid #fde68a;"></th>
        </tr>
      </thead>
      <tbody id="transformacaoMpTbody">
        ${comCusto.map((it, i) => `
          <tr data-idx="${i}" style="background:${i % 2 === 0 ? '#fff' : '#fafafa'};">
            <td style="padding:6px 10px;border:1px solid #e5e7eb;"><input class="trmp-sku" data-idx="${i}" value="${escapeHtml(it.sku)}" style="width:130px;padding:4px 6px;border:1px solid #cbd5e1;border-radius:5px;font-size:12px;" /></td>
            <td style="padding:6px 10px;border:1px solid #e5e7eb;"><input class="trmp-desc" data-idx="${i}" value="${escapeHtml(it.descricao || '')}" style="width:180px;padding:4px 6px;border:1px solid #cbd5e1;border-radius:5px;font-size:12px;" /></td>
            <td style="padding:6px 6px;border:1px solid #e5e7eb;text-align:center;"><input class="trmp-larg" data-idx="${i}" value="${it.largura_cm}" type="number" min="0.01" step="0.01" style="width:65px;padding:4px 5px;border:1px solid #cbd5e1;border-radius:5px;font-size:12px;text-align:center;" /></td>
            <td style="padding:6px 6px;border:1px solid #e5e7eb;text-align:center;"><input class="trmp-alt" data-idx="${i}" value="${it.altura_cm}" type="number" min="0.01" step="0.01" style="width:65px;padding:4px 5px;border:1px solid #cbd5e1;border-radius:5px;font-size:12px;text-align:center;" /></td>
            <td style="padding:6px 6px;border:1px solid #e5e7eb;text-align:center;"><input class="trmp-qtde" data-idx="${i}" value="${it._qtde || 1}" type="number" min="0.0001" step="1" style="width:65px;padding:4px 5px;border:1px solid #cbd5e1;border-radius:5px;font-size:12px;text-align:center;" /></td>
            <td style="padding:6px 6px;border:1px solid #e5e7eb;text-align:center;color:#6b7280;" class="trmp-area-${i}">${it.area_unit_m2}</td>
            <td style="padding:6px 6px;border:1px solid #e5e7eb;text-align:right;font-weight:700;color:#b45309;" class="trmp-custo-${i}">${formatarMoeda(it.custo_unit)}</td>
            <td style="padding:6px 6px;border:1px solid #e5e7eb;text-align:right;" class="trmp-sub-${i}">${formatarMoeda(it.custo_unit * it._qtde)}</td>
            <td style="padding:6px 6px;border:1px solid #e5e7eb;text-align:center;">
              <button type="button" class="trmp-remover" data-idx="${i}" style="border:none;background:transparent;color:#ef4444;cursor:pointer;font-size:14px;" title="Remover linha"><i class="fa-solid fa-trash-can"></i></button>
            </td>
          </tr>
        `).join('')}
      </tbody>
      <tfoot>
        <tr style="background:#fff7ed;font-weight:700;color:#92400e;">
          <td colspan="7" style="padding:8px 10px;border:1px solid #fde68a;text-align:right;">Total rateado:</td>
          <td style="padding:8px 10px;border:1px solid #fde68a;text-align:right;" id="trmpTotalRateado">${formatarMoeda(totalGeral)}</td>
          <td style="border:1px solid #fde68a;"></td>
        </tr>
      </tfoot>
    </table>
  `;
}

function lerItensTransformacaoMp() {
  const tbody = document.getElementById('transformacaoMpTbody');
  if (!tbody) return [];
  return Array.from(tbody.querySelectorAll('tr[data-idx]')).map(tr => {
    const idx = tr.dataset.idx;
    return {
      sku:        (tr.querySelector(`.trmp-sku[data-idx="${idx}"]`)?.value || '').trim(),
      descricao:  (tr.querySelector(`.trmp-desc[data-idx="${idx}"]`)?.value || '').trim(),
      largura_cm: parseFloat(tr.querySelector(`.trmp-larg[data-idx="${idx}"]`)?.value || '0') || 0,
      altura_cm:  parseFloat(tr.querySelector(`.trmp-alt[data-idx="${idx}"]`)?.value || '0') || 0,
      qtde:       parseFloat(tr.querySelector(`.trmp-qtde[data-idx="${idx}"]`)?.value || '0') || 0,
    };
  }).filter(it => it.sku);
}

function atualizarCalculosTransformacaoMp() {
  const valorInput = document.getElementById('trmpValorTotal');
  const valorTotal = parseFloat(String(valorInput?.value || '0').replace(/\./g, '').replace(',', '.')) || 0;
  const itens = lerItensTransformacaoMp();
  const comCusto = calcularRateioAreaFrontend(itens, valorTotal);
  comCusto.forEach((it, i) => {
    const areaEl = document.querySelector(`.trmp-area-${i}`);
    const custoEl = document.querySelector(`.trmp-custo-${i}`);
    const subEl = document.querySelector(`.trmp-sub-${i}`);
    if (areaEl) areaEl.textContent = it.area_unit_m2;
    if (custoEl) custoEl.textContent = formatarMoeda(it.custo_unit);
    if (subEl) subEl.textContent = formatarMoeda(it.custo_unit * it._qtde);
  });
  const totalGeral = comCusto.reduce((acc, it) => acc + it.custo_unit * it._qtde, 0);
  const totalEl = document.getElementById('trmpTotalRateado');
  if (totalEl) totalEl.textContent = formatarMoeda(totalGeral);
}

function adicionarLinhaTransformacaoMp() {
  const itens = lerItensTransformacaoMp();
  itens.push({ sku: '', descricao: '', largura_cm: 0, altura_cm: 0, qtde: 1 });
  const valorInput = document.getElementById('trmpValorTotal');
  const valorTotal = parseFloat(String(valorInput?.value || '0').replace(/\./g, '').replace(',', '.')) || 0;
  const tbody = document.getElementById('transformacaoMpTbody');
  const tabelaWrap = tbody?.closest('div, table')?.parentElement;
  if (tabelaWrap) {
    tabelaWrap.innerHTML = renderizarTabelaTransformacaoMp(itens, valorTotal);
    ligarEventosTabelaTransformacaoMp(tabelaWrap, valorTotal);
  }
}

function ligarEventosTabelaTransformacaoMp(container, valorTotal) {
  container.querySelectorAll('.trmp-sku,.trmp-desc,.trmp-larg,.trmp-alt,.trmp-qtde').forEach(inp => {
    inp.addEventListener('input', atualizarCalculosTransformacaoMp);
  });
  container.querySelectorAll('.trmp-remover').forEach(btn => {
    btn.addEventListener('click', () => {
      const idx = Number(btn.dataset.idx);
      const itens = lerItensTransformacaoMp().filter((_, i) => i !== idx);
      const valorInput = document.getElementById('trmpValorTotal');
      const vt = parseFloat(String(valorInput?.value || '0').replace(/\./g, '').replace(',', '.')) || 0;
      container.innerHTML = renderizarTabelaTransformacaoMp(itens, vt);
      ligarEventosTabelaTransformacaoMp(container, vt);
    });
  });
}

async function abrirModalTransformacaoMp(dados) {
  criarModalTransformacaoMpSeNecessario();
  const modal = document.getElementById('modalTransformacaoMp');
  const conteudo = document.getElementById('modalTransformacaoMpConteudo');
  if (!modal || !conteudo) return;

  modal.style.display = 'flex';
  conteudo.innerHTML = '<div style="text-align:center;padding:32px;color:#94a3b8;"><i class="fa-solid fa-spinner fa-spin fa-2x"></i><div style="margin-top:10px;font-size:13px;">Carregando template...</div></div>';

  document.getElementById('modalTransformacaoMpFechar')?.addEventListener('click', fecharModalTransformacaoMp);
  document.getElementById('modalTransformacaoMpCancelar')?.addEventListener('click', fecharModalTransformacaoMp);

  const fornecedor = dados?.fornecedor_nome || '';
  const valorTotal = Number(dados?.valor_total) || 0;

  // Carrega template salvo
  let templateItens = [];
  try {
    const resp = await fetch(`/api/transformacao-mp/template?fornecedor=${encodeURIComponent(fornecedor)}`, { credentials: 'include' });
    const json = await resp.json().catch(() => ({}));
    if (json?.template?.itens && Array.isArray(json.template.itens)) {
      templateItens = json.template.itens;
    }
  } catch (_) {}

  // Se não tem template, pré-preenche com os SKUs padrão da ZINCA RAPIDO
  if (!templateItens.length && /ZINCA\s*RAPIDO/i.test(fornecedor)) {
    templateItens = [
      { sku: '03.MP.N.60409', descricao: 'Chapa Zincada 24,5×15,5cm', largura_cm: 24.5, altura_cm: 15.5, qtde: 1 },
      { sku: '03.MP.N.60410', descricao: 'Chapa Zincada 38×18cm',     largura_cm: 38,   altura_cm: 18,   qtde: 1 },
      { sku: '03.MP.N.60411', descricao: 'Chapa Zincada 40×33cm',     largura_cm: 40,   altura_cm: 33,   qtde: 1 },
      { sku: '03.MP.N.60412', descricao: 'Chapa Zincada 41×21cm',     largura_cm: 41,   altura_cm: 21,   qtde: 1 },
    ];
  }

  const valorFormatado = valorTotal > 0
    ? valorTotal.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 })
    : '';

  conteudo.innerHTML = `
    <div style="display:flex;align-items:center;flex-wrap:wrap;gap:14px;padding:12px 14px;background:#fff7ed;border-radius:8px;border:1px solid #fed7aa;">
      <div style="flex:1;min-width:200px;">
        <div style="font-size:12px;color:#92400e;font-weight:700;margin-bottom:2px;">Fornecedor</div>
        <div style="font-size:15px;color:#0f172a;font-weight:800;">${escapeHtml(fornecedor || '—')}</div>
      </div>
      <div>
        <div style="font-size:12px;color:#92400e;font-weight:700;margin-bottom:2px;">Valor Total NF-e</div>
        <input id="trmpValorTotal" type="text" value="${escapeHtml(valorFormatado)}" placeholder="0,00" inputmode="decimal"
          style="font-size:16px;font-weight:800;color:#b45309;padding:6px 10px;border:1.5px solid #fb923c;border-radius:7px;width:150px;text-align:right;" />
      </div>
      <div>
        <div style="font-size:12px;color:#92400e;font-weight:700;margin-bottom:2px;">NF-e</div>
        <div style="font-size:14px;color:#0f172a;">${escapeHtml(dados?.numero_nfe || '—')}</div>
      </div>
    </div>

    <div>
      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:8px;">
        <span style="font-size:13px;font-weight:700;color:#334155;">Itens para Transformação</span>
        <button type="button" id="trmpAdicionarLinha" style="border:none;background:#0f766e;color:#fff;border-radius:6px;padding:5px 12px;font-size:12px;font-weight:700;cursor:pointer;display:inline-flex;align-items:center;gap:5px;">
          <i class="fa-solid fa-plus"></i> Adicionar linha
        </button>
      </div>
      <div id="trmpTabelaWrap" style="overflow-x:auto;">
        ${renderizarTabelaTransformacaoMp(templateItens, valorTotal)}
      </div>
    </div>

    <div style="font-size:12px;color:#6b7280;padding:6px 10px;background:#f8fafc;border-radius:6px;border:1px solid #e2e8f0;line-height:1.7;">
      <strong>Lógica de rateio:</strong>
      Custo/un = (largura × altura) ÷ 10.000 × (Valor Total ÷ Área Total)<br>
      Área total = Σ (qtde × largura × altura) ÷ 10.000 de todos os itens
    </div>

    <div id="trmpMensagem" style="display:none;"></div>
  `;

  const tabelaWrap = document.getElementById('trmpTabelaWrap');
  ligarEventosTabelaTransformacaoMp(tabelaWrap, valorTotal);

  document.getElementById('trmpValorTotal')?.addEventListener('input', atualizarCalculosTransformacaoMp);

  document.getElementById('trmpAdicionarLinha')?.addEventListener('click', adicionarLinhaTransformacaoMp);

  document.getElementById('modalTransformacaoMpExecutar')?.addEventListener('click', () =>
    executarTransformacaoMp(dados)
  );
}

async function executarTransformacaoMp(dadosBase) {
  const btnExecutar = document.getElementById('modalTransformacaoMpExecutar');
  const msgEl = document.getElementById('trmpMensagem');
  if (!btnExecutar) return;

  const itens = lerItensTransformacaoMp();
  if (!itens.length) {
    if (msgEl) { msgEl.style.display = ''; msgEl.innerHTML = '<div style="background:#fef2f2;border:1px solid #fca5a5;color:#b91c1c;padding:10px 14px;border-radius:7px;font-size:13px;"><i class="fa-solid fa-triangle-exclamation"></i> Adicione ao menos um item.</div>'; }
    return;
  }

  const valorInput = document.getElementById('trmpValorTotal');
  const valorTotal = parseFloat(String(valorInput?.value || '0').replace(/\./g, '').replace(',', '.')) || 0;
  if (valorTotal <= 0) {
    if (msgEl) { msgEl.style.display = ''; msgEl.innerHTML = '<div style="background:#fef2f2;border:1px solid #fca5a5;color:#b91c1c;padding:10px 14px;border-radius:7px;font-size:13px;"><i class="fa-solid fa-triangle-exclamation"></i> Informe o valor total da NF-e.</div>'; }
    return;
  }

  const salvarTemplate = document.getElementById('modalTransformacaoMpSalvarTemplate')?.checked || false;
  btnExecutar.disabled = true;
  btnExecutar.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> Executando...';
  if (msgEl) msgEl.style.display = 'none';

  try {
    const resp = await fetch('/api/transformacao-mp/executar', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({
        n_id_receb: dadosBase?.n_id_receb || null,
        numero_nfe: dadosBase?.numero_nfe || null,
        fornecedor_nome: dadosBase?.fornecedor_nome || null,
        valor_total: valorTotal,
        itens,
        solicitante: dadosBase?.solicitante || (document.getElementById('userNameDisplay')?.textContent || '').trim() || null,
        salvar_template: salvarTemplate,
      }),
    });

    const json = await resp.json().catch(() => ({}));
    if (!resp.ok || !json?.ok) {
      throw new Error(json?.error || `Erro HTTP ${resp.status}`);
    }

    if (msgEl) {
      msgEl.style.display = '';
      msgEl.innerHTML = `
        <div style="background:#f0fdf4;border:1px solid #86efac;color:#166534;padding:12px 16px;border-radius:8px;font-size:13px;">
          <div style="font-weight:800;font-size:15px;margin-bottom:4px;"><i class="fa-solid fa-circle-check"></i> Transformação executada!</div>
          <div>${escapeHtml(json.message || '')}</div>
          <div style="margin-top:8px;font-size:12px;color:#4ade80;">
            ${(json.itens || []).map(it => `${escapeHtml(it.sku)}: SAI #${it.id_sai} + ENT #${it.id_ent}`).join('<br>')}
          </div>
          <div style="margin-top:8px;font-size:12px;color:#166534;">Ajustes executados diretamente no estoque Omie.</div>
        </div>
      `;
    }
    btnExecutar.innerHTML = '<i class="fa-solid fa-circle-check"></i> Concluído';
    btnExecutar.style.background = 'linear-gradient(135deg,#16a34a 0%,#15803d 100%)';
    btnExecutar.disabled = false;
    btnExecutar.onclick = fecharModalTransformacaoMp;
  } catch (err) {
    if (msgEl) {
      msgEl.style.display = '';
      msgEl.innerHTML = `<div style="background:#fef2f2;border:1px solid #fca5a5;color:#b91c1c;padding:10px 14px;border-radius:7px;font-size:13px;"><i class="fa-solid fa-triangle-exclamation"></i> ${escapeHtml(err?.message || 'Erro ao executar transformação.')}</div>`;
    }
    btnExecutar.disabled = false;
    btnExecutar.innerHTML = '<i class="fa-solid fa-check"></i> Executar Transformação';
  }
}

