async function precarregarLinksNfeLista(linhas = []) {
  const cache = obterMapaLinksNfeLista();
  const pendentes = obterSetPendentesLinksNfeLista();

  const candidatos = [];
  const vistos = new Set();

  linhas.forEach((linha) => {
    const numeroPedido = String(linha?.numeroPedidoRef || '').trim();
    const valorTotalNum = Number(linha?.valorTotalNum);
    const chave = gerarChaveLinkNfeLista(numeroPedido, valorTotalNum);
    if (!chave) return;
    if (vistos.has(chave)) return;
    vistos.add(chave);
    if (cache.has(chave) || pendentes.has(chave)) return;
    candidatos.push({
      chave,
      numeroPedido,
      valorTotal: Number(valorTotalNum.toFixed(2))
    });
  });

  if (!candidatos.length) return;

  candidatos.forEach(item => pendentes.add(item.chave));

  let houveAtualizacao = false;
  try {
    const resp = await fetch('/api/compras/pedidos-omie/nfe-disponibilidade', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({
        itens: candidatos.map((item) => ({
          numero_pedido: item.numeroPedido,
          valor_total: item.valorTotal
        }))
      })
    });

    const data = await resp.json().catch(() => ({}));
    const mapaResultados = new Map();
    const resultados = Array.isArray(data?.resultados) ? data.resultados : [];

    resultados.forEach((resultado) => {
      const numero = String(resultado?.numero_pedido || '').trim();
      const valor = Number(resultado?.valor_total);
      const chave = gerarChaveLinkNfeLista(numero, valor);
      if (!chave) return;
      mapaResultados.set(chave, {
        disponivel: !!resultado?.disponivel,
        c_numero_nfe: resultado?.c_numero_nfe ? String(resultado.c_numero_nfe) : null
      });
    });

    candidatos.forEach((item) => {
      const retorno = mapaResultados.get(item.chave);
      const novoValor = retorno || { disponivel: false, c_numero_nfe: null };
      cache.set(item.chave, novoValor);
      if (novoValor.disponivel) houveAtualizacao = true;
    });
  } catch (_err) {
    candidatos.forEach((item) => {
      cache.set(item.chave, { disponivel: false, c_numero_nfe: null });
    });
  } finally {
    candidatos.forEach(item => pendentes.delete(item.chave));
  }

  if (houveAtualizacao) renderizarLista();
}

// Objetivo: Renderizar tabela de lista extraindo dados dos cards do kanban
function renderizarLista() {
  const corpoTabela = document.getElementById('listaMinhasSolicitacoesCorpo');
  if (!corpoTabela) return;

  const itensKanbanFonte = Array.isArray(window.kanbanMinhasItens) ? window.kanbanMinhasItens : [];
  const mapaItensPorId = new Map(
    itensKanbanFonte
      .filter(item => item && item.id !== undefined && item.id !== null)
      .map(item => [String(item.id), item])
  );

  const valorLimpo = (valor) => String(valor || '').trim();
  const valorValido = (valor) => {
    const texto = valorLimpo(valor);
    if (!texto) return false;
    const textoLower = texto.toLowerCase();
    return !textoLower.startsWith('sem_') && textoLower !== 'sem numero' && textoLower !== 'n/a';
  };

  const regexReqCompleta = /^\d{8}-\d{6}-\d+$/;

  const compactarNumeroRequisicaoTabela = (valor) => {
    const texto = valorLimpo(valor);
    const match = texto.match(/^(\d{8})-(\d{6})-(\d+)$/);
    if (!match) return texto || 'N/A';
    return `${match[2]}-${match[3]}`;
  };

  const primeiroValorValido = (valores, filtro = null) => {
    for (const valor of valores) {
      const texto = valorLimpo(valor);
      if (!valorValido(texto)) continue;
      if (typeof filtro === 'function' && !filtro(texto)) continue;
      return texto;
    }
    return '';
  };

  const obterItensDoCard = (itemId, todosIds) => {
    const ids = String(todosIds || '')
      .split(',')
      .map(id => id.trim())
      .filter(Boolean);

    if (!ids.length && itemId) ids.push(String(itemId));

    return ids
      .map(id => mapaItensPorId.get(String(id)))
      .filter(Boolean);
  };

  const resolverNumerosTabela = (statusNormalizado, card, itensCard) => {
    const numeroPedidoData = valorLimpo(card.getAttribute('data-numero-pedido'));
    const grupoReqData = valorLimpo(card.getAttribute('data-grupo-requisicao'));
    const codIntPedData = valorLimpo(card.getAttribute('data-c-cod-int-ped'));

    const valoresRequisicao = [
      grupoReqData,
      codIntPedData,
      ...itensCard.map(item => item?.grupo_requisicao),
      ...itensCard.map(item => item?.cod_int_req_compra),
      ...itensCard.map(item => item?.c_cod_int_ped),
      ...itensCard.map(item => item?.numero_pedido)
    ];

    let requisicao = primeiroValorValido(
      valoresRequisicao,
      (texto) => regexReqCompleta.test(texto)
    );

    if (!requisicao) {
      requisicao = primeiroValorValido(valoresRequisicao);
    }

    const valoresPedido = [
      numeroPedidoData,
      ...itensCard.map(item => item?.numero),
      ...itensCard.map(item => item?.c_numero),
      ...itensCard.map(item => item?.cnumero),
      ...itensCard.map(item => item?.numero_pedido),
      ...itensCard.map(item => item?.n_cod_ped)
    ];

    let numeroPedido = primeiroValorValido(
      valoresPedido,
      (texto) => !regexReqCompleta.test(texto)
    );

    if (!numeroPedido) {
      numeroPedido = primeiroValorValido(valoresPedido);
    }

    if (statusNormalizado === 'aguardando compra preparação') {
      const pedidoPrioritario = primeiroValorValido(
        [
          ...itensCard.map(item => item?.numero),
          ...itensCard.map(item => item?.cnumero),
          ...itensCard.map(item => item?.c_numero),
          numeroPedido
        ],
        (texto) => !regexReqCompleta.test(texto)
      );
      if (pedidoPrioritario) numeroPedido = pedidoPrioritario;
    }

    return {
      requisicao: requisicao || 'N/A',
      numeroPedido: numeroPedido || '-'
    };
  };
  
  corpoTabela.innerHTML = '';
  
  // Procura todos os cards nos kanbans
  const todasAsColunas = document.querySelectorAll('.kanban-column-minhas');
  const linhas = [];
  let rowIndex = 0;
  
  todasAsColunas.forEach(coluna => {
    const status = coluna.getAttribute('data-status');
    const container = coluna.querySelector('.kanban-cards-minhas');
    if (!container) return;
    
    const cards = container.querySelectorAll('.kanban-card');
    const statusNormalizado = (status || '').toLowerCase().trim();

    // Mantém o modo tabela alinhado ao mesmo filtro de etapas aplicado no modo kanban.
    if (!deveExibirKanbanPorFiltro(statusNormalizado, cards.length)) return;
    
    cards.forEach(card => {
      // Ignora cards ocultos pelo filtro
      if (card.style.display === 'none') return;
      
      // Extrai dados dos atributos data-*
      const fornecedorData = card.getAttribute('data-fornecedor') || '';
      const solicitanteData = card.getAttribute('data-solicitante') || '';
      const idSolicitanteData = card.getAttribute('data-id-solicitante') || '-';
      const createdAt = card.getAttribute('data-created-at') || '';
      const dtPrevisao = card.getAttribute('data-dt-previsao') || '';
      const numeroPedidoData = card.getAttribute('data-numero-pedido') || '';
      const produtosData = card.getAttribute('data-produtos') || '';
      const itemId = card.getAttribute('data-item-id') || '';
      const todosIds = card.getAttribute('data-todos-ids') || '';

      const itensCard = obterItensDoCard(itemId, todosIds);
      const numerosTabela = resolverNumerosTabela(statusNormalizado, card, itensCard);
      const requisicao = numerosTabela.requisicao;
      const numeroPedido = numerosTabela.numeroPedido;
      
      // Formata datas
      const dataFormatada = createdAt ? new Date(createdAt).toLocaleDateString('pt-BR') : '-';
      const dataPrevisaoFormatada = dtPrevisao ? new Date(dtPrevisao).toLocaleDateString('pt-BR') : '-';
      let produtosLista = [];
      try {
        produtosLista = produtosData ? JSON.parse(decodeURIComponent(produtosData)) : [];
      } catch (err) {
        // Falha silenciosa ao parsear produtos
      }

      const expandirProdutosSemCadastroTabela = (produtos = [], itensOrigem = []) => {
        const semCadastroNoGrupo = Array.isArray(itensOrigem)
          && itensOrigem.some(item => String(item?.table_source || '').trim().toLowerCase() === 'compras_sem_cadastro');

        return (Array.isArray(produtos) ? produtos : []).flatMap((prod) => {
          const tableSourceProd = String(prod?.table_source || '').trim().toLowerCase();
          const ehSemCadastro = tableSourceProd === 'compras_sem_cadastro' || (semCadastroNoGrupo && !tableSourceProd);
          if (!ehSemCadastro) return [prod];

          const quantidadeConfiavel = obterQuantidadeConfiavel(prod, prod?.n_qtde ?? prod?.qtde ?? '-');
          const codigoConfiavel = String(prod?.produto_codigo || prod?.cod_prod || '-').trim() || '-';
          const descricaoConfiavel = String(prod?.produto_descricao || prod?.descricao || '-').trim() || '-';

          return [{
            ...prod,
            produto_codigo: codigoConfiavel,
            cod_prod: codigoConfiavel,
            produto_descricao: descricaoConfiavel,
            descricao: descricaoConfiavel,
            n_qtde: quantidadeConfiavel,
            qtde: quantidadeConfiavel
          }];
        });
      };

      produtosLista = expandirProdutosSemCadastroTabela(produtosLista, itensCard);

      const produtosHtml = Array.isArray(produtosLista) && produtosLista.length > 0
        ? `<table style="width:100%;border-collapse:collapse;font-size:11px;margin-top:8px;">
             <thead>
               <tr style="border-bottom:1px solid #d1d5db;background:#f3f4f6;">
                 <th style="text-align:left;padding:8px;font-weight:700;color:#374151;">Código</th>
                 <th style="text-align:left;padding:8px;font-weight:700;color:#374151;">Descrição</th>
                 <th style="text-align:center;padding:8px;font-weight:700;color:#374151;width:80px;">Unidade</th>
                 <th style="text-align:center;padding:8px;font-weight:700;color:#374151;width:80px;">Qtd</th>
                 <th style="text-align:right;padding:8px;font-weight:700;color:#374151;width:100px;">Valor Total</th>
               </tr>
             </thead>
             <tbody>
               ${produtosLista.map((prod, idx) => {
                 const codigo = prod.produto_codigo || prod.cod_prod || '-';
                 const desc = prod.produto_descricao || prod.descricao || '-';
                 const unidade = prod.c_unidade || prod.unidade || '-';
                 const qtde = prod.n_qtde || prod.qtde || '-';
                 const valorTotal = prod.n_val_tot || prod.valor_total || '-';
                 const linkNfePdf = String(prod.c_link_nfe_pdf || '').trim();
                 const linkNfeSeguro = /^(https?:\/\/|\/)/i.test(linkNfePdf) ? linkNfePdf : '';
                 // Converte qtde para número
                 const qtdeNum = typeof qtde === 'number' ? qtde : (typeof qtde === 'string' && qtde !== '-' ? parseFloat(qtde) : NaN);
                 const qtdeFormatada = !isNaN(qtdeNum) ? Math.round(qtdeNum).toLocaleString('pt-BR') : qtde;
                 const valorFormatado = typeof valorTotal === 'number' ? valorTotal.toLocaleString('pt-BR', {style:'currency', currency:'BRL'}) : valorTotal;
                 const valorComLink = linkNfeSeguro
                   ? `<div style="display:inline-flex;align-items:center;justify-content:flex-end;gap:6px;width:100%;">
                        <span>${valorFormatado}</span>
                        <a
                          href="${linkNfeSeguro}"
                          target="_blank"
                          rel="noopener"
                          onclick="event.stopPropagation();"
                          title="Abrir PDF da NF-e"
                          style="display:inline-flex;align-items:center;justify-content:center;width:18px;height:18px;border-radius:999px;border:1px solid #bfdbfe;background:#eff6ff;color:#2563eb;cursor:pointer;text-decoration:none;">
                          <i class="fa-solid fa-link" style="font-size:9px;"></i>
                        </a>
                      </div>`
                   : valorFormatado;
                 return `<tr style="border-bottom:1px solid #bfdbfe;background:#dbeafe;">
                   <td style="padding:8px;color:#1e3a5f;">${escapeHtml(codigo)}</td>
                   <td style="padding:8px;color:#1e3a5f;">${escapeHtml(desc)}</td>
                   <td style="padding:8px;text-align:center;color:#2563eb;">${escapeHtml(String(unidade))}</td>
                   <td style="padding:8px;text-align:center;color:#2563eb;">${qtdeFormatada}</td>
                   <td style="padding:8px;text-align:right;color:#1e3a5f;font-weight:500;">${valorComLink}</td>
                 </tr>`;
               }).join('')}
             </tbody>
           </table>`
        : '<div style="font-size:11px;color:#9ca3af;">Sem produtos cadastrados</div>';
      const rowId = `linha-${rowIndex++}`;
      
      // Texto pesquisável: inclui dados principais + códigos e descrições de produtos
      const produtosTexto = Array.isArray(produtosLista)
        ? produtosLista.map(p => `${p.produto_codigo || p.cod_prod || ''} ${p.produto_descricao || p.descricao || ''}`).join(' ')
        : '';

      // Calcula valor total: soma de n_val_tot de cada produto
      const valorTotalNum = Array.isArray(produtosLista)
        ? produtosLista.reduce((acc, p) => {
            const v = parseFloat(p.n_val_tot || p.valor_total || 0);
            return acc + (isNaN(v) ? 0 : v);
          }, 0)
        : 0;
      const valorTotalFormatado = valorTotalNum > 0
        ? valorTotalNum.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })
        : '-';
      const numeroPedidoRef = String(numeroPedido || numeroPedidoData || '').trim();
      const linksNfeProdutos = Array.isArray(produtosLista)
        ? [...new Set(
            produtosLista
              .map((p) => String(p?.c_link_nfe_pdf || '').trim())
              .filter((link) => /^(https?:\/\/|\/)/i.test(link))
          )]
        : [];
      
      const linhaMontada = {
        rowId,
        requisicao,
        numeroPedido,
        numeroPedidoRef,
        idSolicitante: (String(idSolicitanteData || '').trim() || '-'),
        solicitante: solicitanteData || '-',
        fornecedor: fornecedorData || '-',
        status,
        itemId,
        todosIds,
        valorTotalNum,
        valorTotal: valorTotalFormatado,
        data: dataFormatada,
        dataPrevisao: dataPrevisaoFormatada,
        dataPrevisaoRaw: dtPrevisao,
        produtosHtml,
        produtosTexto,
        linkNfePdf: linksNfeProdutos.length === 1 ? linksNfeProdutos[0] : '',
        linkNfeTitulo: linksNfeProdutos.length === 1 ? 'Abrir PDF da NF-e' : ''
      };
      linhas.push(linhaMontada);
    });
  });
  
  // Renderiza as linhas da tabela
  linhas.forEach((linha, indiceLinha) => {
    const tr = document.createElement('tr');
    const bordaSeparadora = indiceLinha === 0 ? '1px solid #e5e7eb' : '3px solid #000000';
    const bordaFinalGrupo = indiceLinha === linhas.length - 1 ? '1px solid #e5e7eb' : '3px solid #000000';
    tr.style.cssText = `border-top:${bordaSeparadora};border-bottom:0;transition:background 0.2s;cursor:pointer;`;
    tr.onmouseover = () => tr.style.background = '#f9fafb';
    tr.onmouseout = () => tr.style.background = 'transparent';
    
    // Armazena texto pesquisável completo (inclui produtos) para o filtro funcionar
    const textoSearch = [
      linha.requisicao,
      linha.numeroPedido,
      linha.idSolicitante,
      linha.solicitante,
      linha.fornecedor,
      linha.status,
      linha.data,
      linha.dataPrevisao,
      linha.produtosTexto
    ].join(' ').toLowerCase().replace(/\s+/g, ' ').trim();
    tr.setAttribute('data-search', textoSearch);
    
    const itensRelacionados = obterItensRelacionadosLinhaLista(linha);
    const fluxoStatusHtml = renderizarFluxoStatusCompras(linha.status, itensRelacionados);
    const statusArg = JSON.stringify(String(linha.status || ''));
    const itemIdArg = JSON.stringify(String(linha.itemId || ''));
    const todosIdsArg = JSON.stringify(String(linha.todosIds || ''));
    const numeroPedidoArg = JSON.stringify(String(linha.numeroPedido || ''));
    
    const statusNormalizadoLinha = normalizarTextoFluxoCompras(linha.status);

    // Define se o fornecedor deve ser exibido baseado no status
    const statusSemFornecedor = [
      'aguardando aprovacao da requisicao',
      'solicitado revisao',
      'aguardando cotacao',
      'cotado aguardando escolha',
      'cotado',
      'analise de cadastro',
      'aguardando compra preparacao',
      'requisicao'
    ];
    const exibeFornecedor = !statusSemFornecedor.includes(statusNormalizadoLinha);
    const fornecedorExibido = exibeFornecedor ? linha.fornecedor : '-';
    
    // Data de previsão só existe para Pedido de compra e Compra realizada
    const statusComPrevisao = ['aguardando compra', 'compra realizada'];
    const exibeDataPrevisao = statusComPrevisao.includes(statusNormalizadoLinha);
    const dataPrevisaoExibida = exibeDataPrevisao ? linha.dataPrevisao : '-';
    let dataPrevisaoStyle = 'color:#111827;';
    if (exibeDataPrevisao && linha.dataPrevisaoRaw) {
      const hoje = new Date();
      hoje.setHours(0, 0, 0, 0);
      const previsao = new Date(linha.dataPrevisaoRaw);
      previsao.setHours(0, 0, 0, 0);
      if (previsao < hoje) {
        dataPrevisaoStyle = 'color:#ef4444;font-weight:700;';
      }
    }

    const valorTotalComAcao = montarValorTotalComLinkNfe(linha);

    const statusBadgeEstilos = {
      'aguardando aprovacao da requisicao': { bg: '#eef2f7', color: '#475569', border: '#d7dee8' },
      'solicitado revisao': { bg: '#fff7ed', color: '#9a3412', border: '#fed7aa' },
      'aguardando cotacao': { bg: '#fffbeb', color: '#92400e', border: '#fde68a' },
      'cotado aguardando escolha': { bg: '#f5f3ff', color: '#5b21b6', border: '#ddd6fe' },
      'analise de cadastro': { bg: '#ecfeff', color: '#155e75', border: '#bae6fd' },
      'aguardando compra preparacao': { bg: '#ecfdf5', color: '#065f46', border: '#a7f3d0' },
      requisicao: { bg: '#ecfdf5', color: '#065f46', border: '#a7f3d0' },
      'aguardando compra': { bg: '#eff6ff', color: '#1d4ed8', border: '#bfdbfe' },
      'compra realizada': { bg: '#eff6ff', color: '#1e40af', border: '#bfdbfe' },
      'faturada pelo fornecedor': { bg: '#fff7ed', color: '#9a3412', border: '#fed7aa' },
      recebido: { bg: '#ecfdf5', color: '#166534', border: '#bbf7d0' },
      concluido: { bg: '#f1f5f9', color: '#334155', border: '#cbd5e1' }
    };
    const estiloStatusBadge = statusBadgeEstilos[statusNormalizadoLinha] || { bg: '#f8fafc', color: '#475569', border: '#d7dee8' };
    
    tr.innerHTML = `
      <td style="padding:12px 10px;font-size:12px;color:#111827;font-weight:700;text-align:center;white-space:nowrap;">${escapeHtml(linha.idSolicitante || '-')}</td>
      <td style="padding:12px 16px;font-size:12px;color:#111827;font-weight:500;">
        ${escapeHtml(compactarNumeroRequisicaoTabela(linha.requisicao))}
      </td>
      <td style="padding:12px 16px;font-size:11px;color:#6b7280;font-family:monospace;">${linha.numeroPedido}</td>
      <td style="padding:12px 16px;font-size:12px;color:#374151;">${escapeHtml(linha.solicitante)}</td>
      <td style="padding:12px 16px;font-size:12px;color:#111827;">${fornecedorExibido}</td>
      <td style="padding:12px 16px;text-align:center;">
        <span
          onclick='abrirModalPorStatusLista(${statusArg}, ${itemIdArg}, ${todosIdsArg}, ${numeroPedidoArg}, this); event.stopPropagation();'
          style="display:inline-flex;align-items:center;gap:5px;padding:5px 10px;background:${estiloStatusBadge.bg};color:${estiloStatusBadge.color};border:1px solid ${estiloStatusBadge.border};border-radius:999px;cursor:pointer;transition:opacity 0.15s;font-size:11px;font-weight:700;line-height:1;"
          onmouseover="if(!this.dataset.badgeTxt)this.style.opacity='0.82'"
          onmouseout="this.style.opacity='1'"
          title="Clique para abrir o painel desta solicitação">
          <span style="width:8px;height:8px;border-radius:50%;background:${estiloStatusBadge.color};display:inline-block;"></span>
          ${escapeHtml(linha.status || '-')}
        </span>
      </td>
      <td style="padding:12px 16px;font-size:12px;color:#111827;text-align:center;">${linha.data}</td>
      <td style="padding:12px 16px;font-size:12px;text-align:center;${dataPrevisaoStyle}">${dataPrevisaoExibida}</td>
      <td style="padding:12px 16px;font-size:12px;color:#059669;font-weight:600;text-align:right;white-space:nowrap;">${valorTotalComAcao}</td>
    `;
    tr.setAttribute('data-row-id', linha.rowId);
    tr.setAttribute('data-status-filter', statusNormalizadoLinha || '');
    tr.setAttribute('data-status-label', String(linha.status || '-'));
    tr.setAttribute('data-solicitante-filter', normalizarTextoFluxoCompras(linha.solicitante || '-'));
    tr.setAttribute('data-solicitante-label', String(linha.solicitante || '-'));
    
    corpoTabela.appendChild(tr);

    const trFluxo = document.createElement('tr');
    trFluxo.id = `lista-fluxo-${linha.rowId}`;
    trFluxo.setAttribute('data-parent-row-id', linha.rowId);
    trFluxo.innerHTML = `
      <td colspan="9" style="padding:10px 16px 8px;background:#f9fafb;border-bottom:0;">
        <div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;">
          <span style="font-size:12px;color:#111827;font-weight:600;">Produtos</span>
          <span style="font-size:12px;color:#9ca3af;font-weight:700;">-</span>
          <div style="flex:1;min-width:280px;">
            ${fluxoStatusHtml}
          </div>
          <button
            type="button"
            onclick="toggleListaProdutos('${linha.rowId}', event)"
            title="Ocultar produtos"
            aria-label="Ocultar produtos"
            style="background:#e5e7eb;border:1px solid #d1d5db;border-radius:999px;padding:3px 10px;font-size:10px;font-weight:700;cursor:pointer;color:#111827;">
            Ocultar
          </button>
        </div>
      </td>
    `;
    corpoTabela.appendChild(trFluxo);

    const trDetalhe = document.createElement('tr');
    trDetalhe.id = `lista-produtos-${linha.rowId}`;
    trDetalhe.style.display = 'table-row';
    trDetalhe.setAttribute('data-user-hidden', '0');
    trDetalhe.innerHTML = `
      <td colspan="9" style="padding:0 16px 12px;background:#f9fafb;border-bottom:${bordaFinalGrupo};">
        <div id="lista-produtos-conteudo-${linha.rowId}" style="display:block;">
          ${linha.produtosHtml}
        </div>
      </td>
    `;
    corpoTabela.appendChild(trDetalhe);
  });
  
  // Se não houver linhas, mostra mensagem
  if (linhas.length === 0) {
    const tr = document.createElement('tr');
    tr.innerHTML = '<td colspan="9" style="padding:32px 16px;text-align:center;color:#9ca3af;font-size:13px;">Nenhum item encontrado</td>';
    corpoTabela.appendChild(tr);
    atualizarIndicadorFiltroStatusLista();
    atualizarIndicadorFiltroSolicitanteLista();
    return;
  }

  atualizarIndicadorFiltroStatusLista();
  atualizarIndicadorFiltroSolicitanteLista();
  aplicarFiltrosModoLista(document.getElementById('kanbanFiltroGlobal')?.value || '');

}

// Comentário: alterna exibição da sublinha de produtos na lista
function toggleListaProdutos(rowId, event) {
  if (event && typeof event.stopPropagation === 'function') event.stopPropagation();
  const detalhe = document.getElementById(`lista-produtos-${rowId}`);
  const conteudo = document.getElementById(`lista-produtos-conteudo-${rowId}`);
  if (!detalhe || !conteudo) return;
  const aberto = conteudo.style.display !== 'none';
  detalhe.style.display = 'table-row';
  conteudo.style.display = aberto ? 'none' : 'block';
  detalhe.setAttribute('data-user-hidden', aberto ? '1' : '0');
  const btn = event?.currentTarget;
  if (btn) {
    btn.textContent = aberto ? 'Mostrar' : 'Ocultar';
    btn.title = aberto ? 'Mostrar produtos' : 'Ocultar produtos';
    btn.setAttribute('aria-label', aberto ? 'Mostrar produtos' : 'Ocultar produtos');
  }
}
window.toggleListaProdutos = toggleListaProdutos;

// Injeta uma vez o @keyframes do spinner no <head>
function _garantirCssSpinnerBadge() {
  if (document.getElementById('_badge_spin_kf')) return;
  const st = document.createElement('style');
  st.id = '_badge_spin_kf';
  st.textContent = '@keyframes _badgeSpin{0%{transform:rotate(0deg)}100%{transform:rotate(360deg)}}';
  document.head.appendChild(st);
}

// Mostra spinner no badge e monitora modais para restaurar quando abrir
function _spinnerBadgeIniciar(el, textoOriginal) {
  if (!el) return;
  _garantirCssSpinnerBadge();
  el.dataset.badgeTxt = textoOriginal;
  el.dataset.badgeHtml = el.innerHTML;
  el.style.pointerEvents = 'none';
  el.style.opacity = '1';
  // Adapta cor do spinner ao fundo do badge (transparente = escuro, colorido = branco)
  const bgComputado = window.getComputedStyle(el).backgroundColor || '';
  const bgTransp = el.style.background === 'transparent'
    || el.style.backgroundColor === 'transparent'
    || bgComputado === 'rgba(0, 0, 0, 0)'
    || bgComputado === 'transparent'
    || bgComputado === 'rgb(255, 255, 255)';
  const spinBorder = bgTransp ? 'rgba(0,0,0,0.2)' : 'rgba(255,255,255,0.35)';
  const spinTop    = bgTransp ? '#111827'           : '#fff';
  el.innerHTML =
    `<span style="display:inline-block;width:10px;height:10px;box-sizing:border-box;` +
    `border:2px solid ${spinBorder};border-top-color:${spinTop};border-radius:50%;` +
    `animation:_badgeSpin 0.7s linear infinite;vertical-align:middle;margin-right:5px;"></span>` +
    textoOriginal;

  // Verifica a cada 150 ms se algum modal ficou visível (máx ~5 s)
  let tentativas = 0;
  const id = setInterval(() => {
    tentativas++;
    const visivel = document.querySelector(
      '.modal.show, ' +
      '[id*="modal"][style*="display: flex"], [id*="modal"][style*="display:flex"], ' +
      '[id*="modal"][style*="display: block"], [id*="modal"][style*="display:block"], ' +
      '[id*="Modal"][style*="display: flex"], [id*="Modal"][style*="display:flex"], ' +
      '[id*="Modal"][style*="display: block"], [id*="Modal"][style*="display:block"]'
    );
    if (visivel || tentativas >= 34) {
      clearInterval(id);
      _spinnerBadgeRemover(el);
    }
  }, 150);
}

// Restaura o badge ao texto original
function _spinnerBadgeRemover(el) {
  if (!el) return;
  if (el.dataset.badgeHtml != null) {
    el.innerHTML = el.dataset.badgeHtml;
    delete el.dataset.badgeHtml;
  } else if (el.dataset.badgeTxt) {
    el.textContent = el.dataset.badgeTxt;
  }
  delete el.dataset.badgeTxt;
  el.style.pointerEvents = '';
}

// Objetivo: Ao clicar no badge de status na lista, abre o modal correspondente do kanban
function abrirModalPorStatusLista(status, itemId, todosIds, numeroPedido, el) {
  _spinnerBadgeIniciar(el, status);  // <-- exibe spinner imediatamente
  const s = (status || '').toLowerCase().trim();

  // Aprovação da requisição → modal de aprovação em lote
  if (s === 'aguardando aprovação da requisição') {
    if (typeof abrirModalAprovacaoRequisicao === 'function') abrirModalAprovacaoRequisicao();
    return;
  }

  // Revisão → modal de detalhes
  if (s === 'solicitado revisão' || s === 'retificar') {
    if (numeroPedido && numeroPedido !== '-' && typeof abrirModalDetalhesPedidoMinhas === 'function') {
      abrirModalDetalhesPedidoMinhas(numeroPedido, status, todosIds || null);
    }
    return;
  }

  // Aguardando cotação → modal de cotação do item
  if (s === 'aguardando cotação') {
    if (itemId && typeof abrirModalCotacaoKanban === 'function') {
      abrirModalCotacaoKanban(itemId);
    } else if (typeof abrirModalSelecaoItensCotacao === 'function') {
      abrirModalSelecaoItensCotacao();
    }
    return;
  }

  // Cotado aguardando escolha → modal de escolha da cotação
  if (s === 'cotado' || s === 'cotado aguardando escolha') {
    if (itemId && typeof abrirModalCotadoEscolhaItem === 'function') {
      abrirModalCotadoEscolhaItem(itemId);
    }
    return;
  }

  // Análise de cadastro → modal de análise
  if (s === 'analise de cadastro') {
    if (itemId && typeof abrirModalAnaliseCadastro === 'function') {
      abrirModalAnaliseCadastro(itemId);
    }
    return;
  }

  // Aguardando compra (preparação) → modal de seleção de itens para compra
  if (s === 'aguardando compra preparação') {
    if (typeof abrirModalSelecaoItensCompra === 'function') abrirModalSelecaoItensCompra();
    return;
  }

  // Pedido de compra / Aguardando compra / Compra realizada / Faturada / Recebido / Concluído
  // → modal de detalhes do pedido
  if (['aguardando compra', 'compra realizada', 'faturada pelo fornecedor', 'recebido', 'concluído', 'concluido'].includes(s)) {
    if (numeroPedido && numeroPedido !== '-' && typeof abrirModalDetalhesPedidoMinhas === 'function') {
      abrirModalDetalhesPedidoMinhas(numeroPedido, status, todosIds || null);
    }
    return;
  }
}
window.abrirModalPorStatusLista = abrirModalPorStatusLista;

// Função para exibir anexos de um item de aprovação
function exibirAnexosAprovacao(itemId, anexosStr) {
  console.log('[Anexos] Chamada da função com itemId:', itemId, 'anexosStr type:', typeof anexosStr);
  
  // Faz o parse da string JSON
  let anexos;
  try {
    if (typeof anexosStr === 'string') {
      console.log('[Anexos] Fazendo parse da string:', anexosStr.substring(0, 100));
      anexos = JSON.parse(anexosStr.replace(/&quot;/g, '"'));
    } else {
      anexos = anexosStr;
    }
    console.log('[Anexos] Parse bem-sucedido:', anexos);
  } catch (err) {
    console.error('[Anexos] Erro ao fazer parse:', err);
    console.error('[Anexos] String recebida:', anexosStr);
    alert('Erro ao carregar anexos: ' + err.message);
    return;
  }
  
  if (!anexos || !Array.isArray(anexos) || anexos.length === 0) {
    console.log('[Anexos] Nenhum anexo válido encontrado');
    alert('Este item não possui anexos');
    return;
  }
  
  console.log('[Anexos] Total de anexos:', anexos.length);
  
  // Função helper para escapar HTML
  const escapeHtml = (text) => {
    if (!text) return '';
    return text.replace(/&/g, '&amp;')
               .replace(/</g, '&lt;')
               .replace(/>/g, '&gt;')
               .replace(/"/g, '&quot;')
               .replace(/'/g, '&#039;');
  };
  
  // Helper para normalizar anexo: suporta string URL simples (Supabase) ou objeto {nome, url, tipo}
  const normalizarAnexoExibicao = (raw) => {
    if (typeof raw === 'string') {
      const segs = raw.split('/');
      const nomeArqBruto = decodeURIComponent((segs[segs.length - 1] || '').split('?')[0]);
      const nomeLimpo = nomeArqBruto.replace(/^\d+_/, '') || 'Arquivo';
      const ext = nomeLimpo.split('.').pop().toLowerCase();
      const tipoMap = { pdf: 'application/pdf', jpg: 'image/jpeg', jpeg: 'image/jpeg', png: 'image/png', xlsx: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet', xls: 'application/vnd.ms-excel' };
      return { url: raw, nome: nomeLimpo, tipo: tipoMap[ext] || null };
    }
    return { url: raw?.url || '#', nome: raw?.nome || 'Arquivo', tipo: raw?.tipo || null };
  };

  // Cria HTML dos anexos
  const anexosHtml = anexos.map((anexoRaw, idx) => {
    const anexo = normalizarAnexoExibicao(anexoRaw);
    const icone = anexo.tipo?.includes('pdf') ? 'fa-file-pdf' : 
                  anexo.tipo?.includes('image') ? 'fa-file-image' : 
                  anexo.tipo?.includes('word') ? 'fa-file-word' : 
                  anexo.tipo?.includes('excel') || anexo.tipo?.includes('spreadsheet') ? 'fa-file-excel' : 
                  'fa-file';
    
    const cor = anexo.tipo?.includes('pdf') ? '#ef4444' : 
                anexo.tipo?.includes('image') ? '#10b981' : 
                anexo.tipo?.includes('word') ? '#3b82f6' : 
                anexo.tipo?.includes('excel') ? '#059669' : 
                '#6b7280';
    
    return `
      <div style="background:white;border:2px solid #e5e7eb;border-radius:8px;padding:16px;display:flex;align-items:center;gap:12px;transition:all 0.2s;cursor:pointer;" 
           onmouseover="this.style.borderColor='#3b82f6';this.style.transform='translateY(-2px)';this.style.boxShadow='0 4px 12px rgba(59,130,246,0.2)'" 
           onmouseout="this.style.borderColor='#e5e7eb';this.style.transform='translateY(0)';this.style.boxShadow='none'"
           onclick="window.open('${anexo.url}', '_blank')">
        <div style="width:48px;height:48px;background:${cor}15;border-radius:8px;display:flex;align-items:center;justify-content:center;">
          <i class="fa-solid ${icone}" style="font-size:24px;color:${cor};"></i>
        </div>
        <div style="flex:1;min-width:0;">
          <div style="font-weight:600;color:#1f2937;font-size:14px;margin-bottom:4px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;" title="${escapeHtml(anexo.nome)}">${escapeHtml(anexo.nome)}</div>
          <div style="font-size:11px;color:#6b7280;">${anexo.tipo || 'Arquivo'}</div>
        </div>
        <div style="padding:8px 16px;background:#3b82f6;color:white;border-radius:6px;font-size:12px;font-weight:600;display:flex;align-items:center;gap:6px;">
          <i class="fa-solid fa-external-link-alt"></i>
          <span>Abrir</span>
        </div>
      </div>
    `;
  }).join('');
  
  // Cria modal
  const modalId = 'modalAnexosAprovacao';
  let modal = document.getElementById(modalId);
  
  if (!modal) {
    modal = document.createElement('div');
    modal.id = modalId;
    modal.className = 'modal';
    modal.style.display = 'none';
    modal.style.setProperty('z-index', '10003', 'important');
    document.body.appendChild(modal);
  }
  
  modal.innerHTML = `
    <div class="modal-content" style="max-width:700px;width:90%;max-height:80vh;overflow-y:auto;">
      <div class="modal-header" style="background:linear-gradient(135deg,#3b82f6 0%,#2563eb 100%);color:white;padding:20px;border-radius:8px 8px 0 0;">
        <h3 style="margin:0;display:flex;align-items:center;gap:10px;font-size:18px;">
          <i class="fa-solid fa-paperclip" style="font-size:20px;"></i>
          <span>Anexos do Item #${itemId}</span>
        </h3>
        <button class="modal-close" onclick="document.getElementById('${modalId}').style.display='none'" style="color:white;opacity:0.9;">&times;</button>
      </div>
      <div class="modal-body" style="padding:24px;background:#f9fafb;">
        <div style="background:#eff6ff;border:2px solid #3b82f6;border-radius:8px;padding:16px;margin-bottom:20px;">
          <div style="display:flex;align-items:center;gap:12px;">
            <i class="fa-solid fa-info-circle" style="color:#3b82f6;font-size:20px;"></i>
            <div style="color:#1e40af;font-size:13px;line-height:1.6;">
              Clique em qualquer anexo para abrir em uma nova aba
            </div>
          </div>
        </div>
        
        <div style="display:flex;flex-direction:column;gap:12px;">
          ${anexosHtml}
        </div>
        
        <div style="margin-top:20px;padding-top:20px;border-top:2px solid #e5e7eb;text-align:center;color:#6b7280;font-size:12px;">
          Total de ${anexos.length} anexo(s)
        </div>
      </div>
    </div>
  `;
  
  console.log('[Anexos] Modal criado, exibindo...');
  modal.style.display = 'flex';
  modal.style.setProperty('z-index', '10003', 'important');
  console.log('[Anexos] Modal exibido com sucesso');
}

