// Aplica uma árvore de permissões (já carregada) à UI
function _applyPermissionTreeToUI(data){
  // começa escondendo tudo
  const gated = findGatedCandidates();
  gated.forEach(el => el.classList.add('perm-hidden'));

  for (const n of (data && data.nodes) || []) {
    if (!n.selector) continue;
    document.querySelectorAll(n.selector).forEach(el => {
      el.classList.toggle('perm-hidden', !n.allowed);
    });
  }

  // Início sempre visível
  document.querySelectorAll('#menu-inicio').forEach(el => el.classList.remove('perm-hidden'));

  // Esconde categorias do menu lateral que não têm nenhum filho visível
  document.querySelectorAll('.side-wrapper').forEach(wrapper => {
    const filhos = wrapper.querySelectorAll('.side-menu > a');
    const algumVisivel = Array.from(filhos).some(a => !a.classList.contains('perm-hidden'));
    wrapper.classList.toggle('perm-hidden', !algumVisivel);
  });

  aplicarVisibilidadeMenuChatbotAdmin();

  // Se a guia ativa do produto ficou escondida, ativa a primeira guia visível
  const prodTabs = document.querySelector('#produtoTabs .main-header');
  if (prodTabs) {
    const activeTab = prodTabs.querySelector('.main-header-link.is-active');
    if (activeTab && activeTab.classList.contains('perm-hidden')) {
      activeTab.classList.remove('is-active');
      const firstVisible = prodTabs.querySelector('.main-header-link:not(.perm-hidden)');
      if (firstVisible) {
        firstVisible.classList.add('is-active');
        firstVisible.click();
      }
    }
  }

  // Atualiza card Relatórios da Início (depende de perm-hidden)
  try {
    if (typeof window.__renderCardsInicioAtalhos === 'function') {
      window.__renderCardsInicioAtalhos();
    }
  } catch (_) {}
}

// Logado: revela só o que a ÁRVORE permitir.
// Estratégia anti-flicker: aplica imediatamente cache local (se houver) e revalida em background.
async function applyCurrentUserPermissionsToUI(){
  const me = window.__sessionUser;
  if (!me) { applyLoggedOutUI(); return; }

  const cacheKey = `perm-tree:${me.id}`;
  let appliedFromCache = false;
  try {
    const raw = localStorage.getItem(cacheKey);
    if (raw) {
      const cached = JSON.parse(raw);
      if (cached && Array.isArray(cached.nodes)) {
        // Valida cache: verifica se todos os nós do DOM com selector estão presentes.
        // Se faltar algum, a cache está desatualizada — descarta e busca fresh.
        const cachedSelectors = new Set(cached.nodes.map(n => n.selector).filter(Boolean));
        const domNodes = document.querySelectorAll('[data-nav-selector]');
        const allPresent = Array.from(domNodes).every(el => {
          const sel = el.dataset.navSelector;
          return !sel || cachedSelectors.has(sel);
        });
        if (allPresent) {
          _applyPermissionTreeToUI(cached);
          appliedFromCache = true;
        } else {
          // Cache desatualizada (novos menus foram adicionados) — limpa e busca fresh
          try { localStorage.removeItem(cacheKey); } catch {}
        }
      }
    }
  } catch {}

  // Função que busca a árvore atualizada e re-aplica se mudou
  const refresh = async () => {
    try {
      const r = await fetch(`/api/users/${me.id}/permissions/tree`, { credentials:'include' });
      if (!r.ok) return;
      const data = await r.json();
      _applyPermissionTreeToUI(data);
      try { localStorage.setItem(cacheKey, JSON.stringify(data)); } catch {}
    } catch {}
  };

  if (appliedFromCache) {
    // Não bloqueia o boot: revalida em segundo plano
    refresh();
  } else {
    // Sem cache ou cache desatualizada: aguarda para não revelar UI vazia
    await refresh();
  }
  atualizarVisibilidadeGuiaSeparacao();
}

// Variável para rastrear se o usuário estava logado na última verificação
window.__wasLoggedInBefore = false;

// Checa auth no backend e aplica estado
async function ensureAuthVisibility(){
  try {
    // estado seguro imediato
    applyLoggedOutUI();

    const r  = await fetch('/api/auth/status', { credentials:'include' });
    const st = r.ok ? await r.json() : { loggedIn:false };
    
    // Compara com o estado anterior (não com o estado atual que pode ter mudado)
    const wasLoggedBefore = window.__wasLoggedInBefore;
    const isLoggedNow = st.loggedIn;
    
    console.log('[AUTH] Estado anterior:', wasLoggedBefore, '| Estado atual:', isLoggedNow);
    console.log('[AUTH] Mudança detectada?', wasLoggedBefore !== isLoggedNow);
    
    // Atualiza o estado para a próxima comparação
    window.__wasLoggedInBefore = isLoggedNow;
    
    window.__sessionUser = st.loggedIn ? st.user : null;
    console.log('[AUTH] window.__sessionUser atualizado:', window.__sessionUser);

    if (st.loggedIn) {
      await applyCurrentUserPermissionsToUI();
      // Notifica módulos que dependem do login (ex: atalhos flutuantes)
      document.dispatchEvent(new CustomEvent('auth:loggedIn', { detail: window.__sessionUser }));
      
      // Se estava deslogado E agora está logado, inicia monitoramento
      if (!wasLoggedBefore && isLoggedNow && typeof startVersionCheckLoop === 'function') {
        console.log('[UPDATE-CHECK] ✓✓✓ USUÁRIO FEZ LOGIN! Iniciando monitoramento de atualização...');
        startVersionCheckLoop();
      }
    }
    else {
      applyLoggedOutUI();
      
      // Se estava logado E agora está deslogado, para o monitoramento
      if (wasLoggedBefore && !isLoggedNow && typeof stopVersionCheckLoop === 'function') {
        console.log('[UPDATE-CHECK] Usuário fez logout. Parando monitoramento de atualização...');
        stopVersionCheckLoop();
      }
    }
  } catch {
    applyLoggedOutUI();
  }
  finally {
    // Libera a UI (remove anti-flicker / overlay) somente após permissões aplicadas
    try {
      document.body.classList.add('app-ready');
      const ov = document.getElementById('app-boot-overlay');
      if (ov) setTimeout(() => ov.remove(), 280);
    } catch {}
  }
}

