// ===== SISTEMA DE DETECÇÃO DE ATUALIZAÇÃO =================================
// Objetivo: Detectar quando há uma nova versão disponível no servidor
// e notificar o usuário para atualizar o cache do navegador

// Variável global para armazenar a versão atual do cliente
window.__appVersion = null;
window.__versionCheckInterval = null;
window.__updatePending = false; // Flag para saber se há atualização pendente

// Esconder o ícone IMEDIATAMENTE na inicialização
(function() {
  const icon = document.getElementById('config-icon');
  if (icon) {
    icon.style.display = 'none';
    console.log('[UPDATE-CHECK-INIT] Ícone de atualização escondido na inicialização');
  }
})();

// Função para limpar cache e recarregar a página
async function clearCacheAndReload() {
  try {
    console.log('[UPDATE-CHECK] Iniciando limpeza de cache...');
    
    // 1. Limpar localStorage
    if (localStorage) {
      localStorage.clear();
      console.log('[UPDATE-CHECK] localStorage limpo');
    }
    
    // 2. Limpar sessionStorage
    if (sessionStorage) {
      sessionStorage.clear();
      console.log('[UPDATE-CHECK] sessionStorage limpo');
    }
    
    // 3. Limpar IndexedDB
    if (window.indexedDB) {
      try {
        const databases = await window.indexedDB.databases?.();
        if (databases && Array.isArray(databases)) {
          for (const db of databases) {
            window.indexedDB.deleteDatabase(db.name);
            console.log(`[UPDATE-CHECK] IndexedDB "${db.name}" deletado`);
          }
        }
      } catch (err) {
        console.warn('[UPDATE-CHECK] Erro ao limpar IndexedDB:', err);
      }
    }
    
    // 4. Limpar Service Workers (se existentes)
    if ('serviceWorker' in navigator) {
      try {
        const registrations = await navigator.serviceWorker.getRegistrations();
        for (const registration of registrations) {
          await registration.unregister();
          console.log('[UPDATE-CHECK] Service Worker desregistrado');
        }
      } catch (err) {
        console.warn('[UPDATE-CHECK] Erro ao limpar Service Workers:', err);
      }
    }
    
    // 5. Resetar flags antes de recarregar
    window.__appVersion = null;
    window.__updatePending = false;
    
    // 6. Recarregar a página com hard-refresh (bypass cache)
    console.log('[UPDATE-CHECK] Recarregando página...');
    window.location.href = window.location.href;
    
    // Força reload ignorando cache
    setTimeout(() => {
      window.location.reload(true);
    }, 500);
    
  } catch (err) {
    console.error('[UPDATE-CHECK] Erro ao limpar cache:', err);
    // Fallback: apenas recarrega
    window.location.reload(true);
  }
}

// Função para verificar versão no servidor (do banco de dados)
async function checkForUpdates() {
  try {
    console.log('[UPDATE-CHECK] ========================================');
    console.log('[UPDATE-CHECK] Iniciando verificação de atualização...');
    
    const response = await fetch('/api/check-version', { 
      credentials: 'include',
      cache: 'no-store' // Força o navegador a não cachear
    });
    
    if (!response.ok) {
      console.warn('[UPDATE-CHECK] ❌ Falha ao verificar versão:', response.status);
      console.log('[UPDATE-CHECK] Resposta:', await response.text());
      return;
    }
    
    const data = await response.json();
    const serverVersion = data.version;
    
    console.log('[UPDATE-CHECK] ✓ Resposta do servidor:', data);
    console.log('[UPDATE-CHECK] Versão no servidor (BD): ', serverVersion);
    console.log('[UPDATE-CHECK] Versão no cliente: ', window.__appVersion);
    
    const updateIcon = document.getElementById('config-icon');
    
    // Se é a primeira verificação
    if (window.__appVersion === null) {
      console.log('[UPDATE-CHECK] 🔄 PRIMEIRA VERIFICAÇÃO - Sincronizando...');
      window.__appVersion = serverVersion;
      window.__updatePending = false;
      
      // Garante que ícone fica escondido
      if (updateIcon) {
        updateIcon.style.display = 'none';
        updateIcon.classList.remove('update-available');
        updateIcon.removeAttribute('data-update-available');
        console.log('[UPDATE-CHECK] ✓ Ícone escondido (primeira verificação)');
      }
      
      console.log('[UPDATE-CHECK] ✓ Versão do cliente definida para:', window.__appVersion);
      console.log('[UPDATE-CHECK] ========================================');
      return;
    }
    
    console.log('[UPDATE-CHECK] Comparando versões...');
    console.log('[UPDATE-CHECK] Servidor: "' + serverVersion + '" vs Cliente: "' + window.__appVersion + '"');
    console.log('[UPDATE-CHECK] São diferentes?', serverVersion !== window.__appVersion);
    
    // Se versão é DIFERENTE
    if (serverVersion !== window.__appVersion) {
      console.log('[UPDATE-CHECK] ⚠️ VERSÕES DIFERENTES!');
      console.log('[UPDATE-CHECK] ⚠️ ATUALIZAÇÃO DISPONÍVEL!');
      console.log('[UPDATE-CHECK] Servidor:', serverVersion, '≠ Cliente:', window.__appVersion);
      
      if (updateIcon) {
        console.log('[UPDATE-CHECK] Mostrando ícone de atualização...');
        updateIcon.style.display = 'inline-block';
        updateIcon.title = '✨ Atualização disponível! Clique para aplicar.';
        updateIcon.setAttribute('data-update-available', 'true');
        updateIcon.classList.add('update-available');
        
        console.log('[UPDATE-CHECK] ✨ Ícone exibido e animando');
      }
      
      window.__updatePending = true;
      console.log('[UPDATE-CHECK] ✓ Flag updatePending = true');
    } 
    // Se versão é IGUAL
    else {
      console.log('[UPDATE-CHECK] ✓ Versões iguais - Sistema sincronizado');
      
      if (updateIcon) {
        updateIcon.style.display = 'none';
        updateIcon.classList.remove('update-available');
        updateIcon.removeAttribute('data-update-available');
        console.log('[UPDATE-CHECK] ✓ Ícone escondido');
      }
      
      window.__updatePending = false;
      console.log('[UPDATE-CHECK] ✓ Flag updatePending = false');
    }
    
    console.log('[UPDATE-CHECK] ========================================');
    
  } catch (err) {
    console.error('[UPDATE-CHECK] ❌ ERRO ao verificar atualizações:', err);
    console.log('[UPDATE-CHECK] ========================================');
  }
}

// Função para iniciar verificação periódica
function startVersionCheckLoop() {
  // Se já tem um intervalo, cancela o anterior
  if (window.__versionCheckInterval) {
    clearInterval(window.__versionCheckInterval);
    console.log('[UPDATE-CHECK] Intervalo anterior cancelado');
  }
  
  console.log('[UPDATE-CHECK] Iniciando verificação imediata...');
  // Verifica imediatamente na primeira vez
  checkForUpdates();
  
  // Depois verifica a cada 5 minutos (300000 ms)
  // Você pode ajustar esse valor conforme necessário
  const CHECK_INTERVAL = 5 * 60 * 1000; // 5 minutos
  
  window.__versionCheckInterval = setInterval(() => {
    console.log('[UPDATE-CHECK] ⏱️ Verificação periódica (a cada 5 min)...');
    checkForUpdates();
  }, CHECK_INTERVAL);
  
  console.log('[UPDATE-CHECK] ✓ Loop de verificação iniciado (intervalo: 5 minutos)');
}

// Função para parar verificação periódica
function stopVersionCheckLoop() {
  if (window.__versionCheckInterval) {
    clearInterval(window.__versionCheckInterval);
    window.__versionCheckInterval = null;
    console.log('[UPDATE-CHECK] Loop de verificação parado');
  }
}

// Função para FORÇAR verificação AGORA (útil para testes)
window.forceUpdateCheck = function() {
  console.log('[UPDATE-CHECK] 🔄 VERIFICAÇÃO FORÇADA MANUALMENTE');
  checkForUpdates();
  console.log('[UPDATE-CHECK] ✓ Verificação forçada concluída');
  console.log('[UPDATE-CHECK] Dica: Use window.forceUpdateCheck() no console para testar novamente');
};

// ===== MONITORAMENTO DO AUTO-SYNC OMIE (PÁGINA SINCRONIZAÇÃO) =============
(function initOmieAutoSyncPainel() {
  const labels = {
    produtos_omie: 'Produtos',
    fornecedores: 'Fornecedores',
    pedidos_compra: 'Pedidos de Compra',
    requisicoes_compra: 'Requisições de Compra',
    recebimentos_nfe: 'Recebimentos NF-e',
  };

  const fmt = (iso) => {
    if (!iso) return '-';
    const d = new Date(iso);
    if (Number.isNaN(d.getTime())) return '-';
    return d.toLocaleString('pt-BR');
  };

  const montarResumoContagem = (details) => {
    if (!details || typeof details !== 'object') return '-';

    const atualizados = Number(details.total ?? details.sucesso ?? details.processados);
    const avaliados = Number(details.total_avaliados ?? details.totalRegistros ?? details.total_registros);
    const ignorados = Number(details.ignorados_etapa_80 ?? details.ignorados ?? 0);

    if (Number.isFinite(atualizados) && Number.isFinite(avaliados) && avaliados > 0) {
      return `${atualizados}/${avaliados}${ignorados > 0 ? ` (ignorados: ${ignorados})` : ''}`;
    }

    if (Number.isFinite(atualizados)) {
      return `${atualizados}`;
    }

    return '-';
  };

  function garantirBotoesExecucaoPorTabela() {
    const grid = document.getElementById('agendamentoTabelasGrid');
    if (!grid) return;

    const itens = Array.from(grid.querySelectorAll('label'));
    itens.forEach((item) => {
      const checkbox = item.querySelector('.agendamento-tabela');
      if (!checkbox) return;

      checkbox.style.setProperty('width', '18px', 'important');
      checkbox.style.setProperty('height', '18px', 'important');
      checkbox.style.setProperty('min-width', '18px', 'important');
      checkbox.style.setProperty('min-height', '18px', 'important');
      checkbox.style.setProperty('max-width', '18px', 'important');
      checkbox.style.setProperty('max-height', '18px', 'important');
      checkbox.style.setProperty('transform', 'none', 'important');
      checkbox.style.setProperty('appearance', 'auto', 'important');
      checkbox.style.setProperty('-webkit-appearance', 'auto', 'important');

      if (item.querySelector('.btn-omie-run-tabela')) return;

      item.style.display = 'grid';
      item.style.gridTemplateColumns = 'minmax(0, 1fr) auto';
      item.style.alignItems = 'center';
      item.style.columnGap = '10px';
      item.style.rowGap = '8px';
      item.style.padding = '12px';
      item.style.minHeight = '52px';

      const texto = item.querySelector('span');
      if (texto) {
        texto.style.flex = '1';
        texto.style.fontWeight = '600';
        texto.style.whiteSpace = 'nowrap';
        texto.style.overflow = 'hidden';
        texto.style.textOverflow = 'ellipsis';
      }

      const btn = document.createElement('button');
      btn.type = 'button';
      btn.className = 'btn-omie-run-tabela';
      btn.dataset.tabela = checkbox.value;
      btn.innerHTML = '<i class="fa-solid fa-bolt"></i> Sincronizar';
      btn.style.background = 'linear-gradient(135deg,#0ea5e9 0%,#0284c7 100%)';
      btn.style.color = 'white';
      btn.style.border = 'none';
      btn.style.padding = '7px 10px';
      btn.style.borderRadius = '6px';
      btn.style.fontSize = '12px';
      btn.style.fontWeight = '700';
      btn.style.cursor = 'pointer';
      btn.style.display = 'inline-flex';
      btn.style.alignItems = 'center';
      btn.style.gap = '5px';
      btn.style.whiteSpace = 'nowrap';
      btn.title = 'Executar sincronização somente desta tabela';

      item.appendChild(btn);
    });
  }

  function montarParametrosAutoSync(tabelasSelecionadas = []) {
    const payload = {};

    const dataInicialInput = document.getElementById('agendamentoDataInicial');
    const dataInicial = String(dataInicialInput?.value || '').trim();
    if (dataInicial) {
      payload.data_inicial = dataInicial;
    }

    return payload;
  }

  async function executarAutoSyncTabelaUnica(tabela, btn) {
    if (!tabela) return;
    const nomeTabela = labels[tabela] || tabela;
    const original = btn?.innerHTML || '';

    if (btn) {
      btn.disabled = true;
      btn.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> Executando';
    }

    try {
      const resp = await fetch('/api/omie/autosync/run', {
        method: 'POST',
        credentials: 'include',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          motivo: `manual-ui-${tabela}`,
          tabelas: [tabela],
          ...montarParametrosAutoSync([tabela])
        })
      });
      const data = await resp.json().catch(() => ({}));
      if (!resp.ok || !data?.ok) throw new Error(data?.error || `HTTP ${resp.status}`);

      await carregarStatusAutoSync();
      await carregarHistoricoAutoSync();
      alert(`Sincronização de ${nomeTabela} concluída com sucesso.`);
    } catch (err) {
      alert(`Erro ao sincronizar ${nomeTabela}: ${err.message || err}`);
    } finally {
      if (btn) {
        btn.disabled = false;
        btn.innerHTML = original;
      }
    }
  }

  async function carregarStatusAutoSync() {
    const resumoEl = document.getElementById('omieAutoSyncResumo');
    const tarefasEl = document.getElementById('omieAutoSyncExecucaoTabelas');
    if (!resumoEl || !tarefasEl) return;

    try {
      const resp = await fetch('/api/omie/autosync/status', { credentials: 'include' });
      const data = await resp.json();
      if (!resp.ok || !data?.ok) throw new Error(data?.error || `HTTP ${resp.status}`);

      const statusCor = data.running
        ? '#0ea5e9'
        : String(data.last_status || '').startsWith('error') || data.last_status === 'partial_error'
          ? '#ef4444'
          : '#16a34a';

      resumoEl.innerHTML = `
        <div style="background:white;border:1px solid #e2e8f0;border-radius:8px;padding:10px;">
          <div style="font-size:11px;color:#64748b;text-transform:uppercase;">Status</div>
          <div style="font-size:16px;font-weight:700;color:${statusCor};">${data.running ? 'Em execução' : (data.last_status || 'Aguardando')}</div>
        </div>
        <div style="background:white;border:1px solid #e2e8f0;border-radius:8px;padding:10px;">
          <div style="font-size:11px;color:#64748b;text-transform:uppercase;">Última execução</div>
          <div style="font-size:14px;font-weight:700;color:#0f172a;">${fmt(data.last_run_at)}</div>
        </div>
        <div style="background:white;border:1px solid #e2e8f0;border-radius:8px;padding:10px;">
          <div style="font-size:11px;color:#64748b;text-transform:uppercase;">Duração</div>
          <div style="font-size:14px;font-weight:700;color:#0f172a;">${data.last_duration_ms ? `${Math.round(data.last_duration_ms / 1000)}s` : '-'}</div>
        </div>
        <div style="background:white;border:1px solid #e2e8f0;border-radius:8px;padding:10px;">
          <div style="font-size:11px;color:#64748b;text-transform:uppercase;">Intervalo</div>
          <div style="font-size:14px;font-weight:700;color:#0f172a;">${Math.round((data.interval_ms || 0) / 60000)} min</div>
        </div>
      `;

      const tasks = Array.isArray(data.last_run_tasks) ? data.last_run_tasks : [];
      if (!tasks.length) {
        tarefasEl.innerHTML = '<div style="color:#64748b;font-size:12px;">Sem resultados de execução ainda.</div>';
      } else {
        tarefasEl.innerHTML = tasks.map((t) => {
          const ok = !!t.ok;
          const cor = ok ? '#16a34a' : '#ef4444';
          return `
            <div style="background:white;border:1px solid #e2e8f0;border-radius:8px;padding:10px;">
              <div style="font-size:12px;font-weight:700;color:#0f172a;">${labels[t.tabela] || t.tabela}</div>
              <div style="font-size:12px;color:${cor};font-weight:700;">${ok ? 'OK' : 'Erro'}</div>
              <div style="font-size:11px;color:#334155;">Atualizados: ${montarResumoContagem(t.details)}</div>
              <div style="font-size:11px;color:#64748b;">${t.duration_ms ? `${Math.round(t.duration_ms / 1000)}s` : '-'}</div>
              ${!ok && t.error ? `<div style="font-size:11px;color:#b91c1c;margin-top:4px;">${String(t.error).slice(0, 120)}</div>` : ''}
            </div>
          `;
        }).join('');
      }
    } catch (err) {
      resumoEl.innerHTML = `<div style="color:#b91c1c;font-size:12px;">Erro ao carregar status: ${err.message || err}</div>`;
      tarefasEl.innerHTML = '';
    }
  }

  async function carregarHistoricoAutoSync() {
    const histEl = document.getElementById('omieAutoSyncHistorico');
    if (!histEl) return;

    try {
      const resp = await fetch('/api/omie/autosync/history?limit=15', { credentials: 'include' });
      const data = await resp.json();
      if (!resp.ok || !data?.ok) throw new Error(data?.error || `HTTP ${resp.status}`);

      const hist = Array.isArray(data.history) ? data.history : [];
      if (!hist.length) {
        histEl.innerHTML = '<div style="color:#64748b;">Sem histórico ainda.</div>';
        return;
      }

      histEl.innerHTML = hist.map((h) => {
        const cor = h.status === 'ok' ? '#16a34a' : (h.status === 'partial_error' ? '#f59e0b' : '#ef4444');
        const tarefas = Array.isArray(h.tasks) ? h.tasks : [];
        const resumo = tarefas.map(t => {
          const tabela = labels[t.tabela] || t.tabela;
          const status = t.ok ? 'ok' : 'erro';
          const contagem = montarResumoContagem(t.details);
          return `${tabela}:${status} (${contagem})`;
        }).join(' | ');
        return `
          <div style="padding:8px 0;border-bottom:1px solid #e2e8f0;">
            <div style="font-weight:700;color:#0f172a;">${fmt(h.at)} <span style="color:${cor};font-weight:700;">(${h.status})</span></div>
            <div style="color:#475569;">Motivo: ${h.reason || '-'}</div>
            <div style="color:#475569;">Duração: ${h.duration_ms ? `${Math.round(h.duration_ms / 1000)}s` : '-'}</div>
            <div style="color:#334155;">${resumo || '-'}</div>
          </div>
        `;
      }).join('');
    } catch (err) {
      histEl.innerHTML = `<div style="color:#b91c1c;">Erro ao carregar histórico: ${err.message || err}</div>`;
    }
  }

  async function carregarLogAutoSyncAtual() {
    const logEl = document.getElementById('omieAutoSyncLogAtual');
    if (!logEl) return;

    try {
      const resp = await fetch('/api/omie/autosync/live-log?limit=120', { credentials: 'include' });
      const data = await resp.json();
      if (!resp.ok || !data?.ok) throw new Error(data?.error || `HTTP ${resp.status}`);

      const linhas = Array.isArray(data.lines) ? data.lines : [];
      if (!linhas.length) {
        logEl.textContent = 'Sem linhas de log recentes para o auto-sync.';
        return;
      }

      logEl.textContent = linhas.join('\n');
      logEl.scrollTop = logEl.scrollHeight;
    } catch (err) {
      logEl.textContent = `Erro ao carregar log atual: ${err.message || err}`;
    }
  }

  async function executarAutoSyncAgora() {
    const btn = document.getElementById('btnOmieAutoSyncExecutarAgora');
    const checked = Array.from(document.querySelectorAll('.agendamento-tabela:checked')).map(cb => cb.value);
    const tabelas = checked.length ? checked : ['produtos_omie', 'fornecedores', 'pedidos_compra', 'requisicoes_compra', 'recebimentos_nfe'];

    if (!btn) return;
    const original = btn.innerHTML;
    btn.disabled = true;
    btn.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> Executando...';

    try {
      const resp = await fetch('/api/omie/autosync/run', {
        method: 'POST',
        credentials: 'include',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          motivo: 'manual-ui',
          tabelas,
          ...montarParametrosAutoSync(tabelas)
        })
      });
      const data = await resp.json().catch(() => ({}));
      if (!resp.ok || !data?.ok) throw new Error(data?.error || `HTTP ${resp.status}`);
      await carregarStatusAutoSync();
      await carregarHistoricoAutoSync();
      await carregarLogAutoSyncAtual();
      alert('Sincronização executada com sucesso.');
    } catch (err) {
      alert('Erro ao executar sincronização: ' + (err.message || err));
    } finally {
      btn.disabled = false;
      btn.innerHTML = original;
    }
  }

  document.addEventListener('DOMContentLoaded', () => {
    const btnRun = document.getElementById('btnOmieAutoSyncExecutarAgora');
    const btnRefresh = document.getElementById('btnOmieAutoSyncAtualizar');

    if (btnRun) btnRun.addEventListener('click', executarAutoSyncAgora);
    document.addEventListener('click', async (event) => {
      const botaoTabela = event.target.closest('.btn-omie-run-tabela');
      if (!botaoTabela) return;
      event.preventDefault();
      event.stopPropagation();

      const tabela = String(botaoTabela.dataset.tabela || '').trim();
      await executarAutoSyncTabelaUnica(tabela, botaoTabela);
    });
    if (btnRefresh) btnRefresh.addEventListener('click', async () => {
      const original = btnRefresh.innerHTML;
      btnRefresh.disabled = true;
      btnRefresh.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> Atualizando...';
      try {
        await carregarStatusAutoSync();
        await carregarHistoricoAutoSync();
        await carregarLogAutoSyncAtual();
      } finally {
        btnRefresh.disabled = false;
        btnRefresh.innerHTML = original;
      }
    });

    garantirBotoesExecucaoPorTabela();
    carregarStatusAutoSync();
    carregarHistoricoAutoSync();
    carregarLogAutoSyncAtual();
    setInterval(() => {
      carregarStatusAutoSync();
    }, 30000);
  });
})();

// ===== FIM DO SISTEMA DE DETECÇÃO DE ATUALIZAÇÃO ===========================

// Função para aplicar tema
function aplicarTema(theme) {
  if (theme === 'light') {
    document.documentElement.classList.add('light-mode');
  } else {
    document.documentElement.classList.remove('light-mode');
  }
}

// Função para salvar tema no servidor
async function salvarTemaNoServidor(theme) {
  try {
    const resp = await fetch('/api/auth/tema', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({ theme })
    });
    
    if (!resp.ok) {
      console.warn('[DARK-LIGHT] Falha ao salvar tema no servidor:', resp.status);
    } else {
      console.log('[DARK-LIGHT] Tema salvo no servidor:', theme);
    }
  } catch (err) {
    console.warn('[DARK-LIGHT] Erro ao salvar tema:', err);
  }
}

// Carregar tema ao iniciar
document.addEventListener('DOMContentLoaded', async () => {
  try {
    // Tenta carregar do servidor (se estiver logado)
    const resp = await fetch('/api/auth/tema', { credentials: 'include' });
    if (resp.ok) {
      const data = await resp.json();
      aplicarTema(data.theme);
      console.log('[DARK-LIGHT] Tema carregado do servidor:', data.theme);
    } else {
      // Fallback: usar localStorage se não estiver logado
      const savedMode = localStorage.getItem('themeMode') || 'dark';
      aplicarTema(savedMode);
      console.log('[DARK-LIGHT] Tema carregado do localStorage:', savedMode);
    }
  } catch (err) {
    // Fallback: usar localStorage em caso de erro
    const savedMode = localStorage.getItem('themeMode') || 'dark';
    aplicarTema(savedMode);
    console.log('[DARK-LIGHT] Tema carregado do localStorage (fallback):', savedMode);
  }

  // Adiciona evento de clique no botão
  const darkLightBtn = document.querySelector('.dark-light');
  
  if (!darkLightBtn) {
    console.warn('[DARK-LIGHT] Botão .dark-light não encontrado no DOM');
    return;
  }
  
  darkLightBtn.addEventListener('click', async () => {
    const isDark = !document.documentElement.classList.contains('light-mode');
    const novoTema = isDark ? 'light' : 'dark';
    
    // Aplica tema localmente
    aplicarTema(novoTema);

    // Re-renderiza itens do WhatsApp para aplicar cores inline corretas
    if (typeof renderAtWhatsappConversationRows === 'function' && typeof atWhatsappConversationRows !== 'undefined') {
      try { renderAtWhatsappConversationRows(atWhatsappConversationRows); } catch (_) {}
    }

    // Re-renderiza kanban de solicitações para aplicar cores do tema
    if (typeof window._loadKanbanSolicitacoesTab === 'function') {
      try { window._loadKanbanSolicitacoesTab.force = true; window._loadKanbanSolicitacoesTab(); } catch (_) {}
    }
    
    // Salva no servidor
    await salvarTemaNoServidor(novoTema);
    
    // Fallback: salva no localStorage também
    localStorage.setItem('themeMode', novoTema);
    
    const mensagem = novoTema === 'light' ? 'Mudou para modo claro' : 'Mudou para modo escuro';
    console.log('[DARK-LIGHT]', mensagem);
  });
  
  // ===== Iniciar loop de verificação de atualização =====
  // Inicia o monitoramento de versão automaticamente quando usuário estiver logado
  if (window.__sessionUser && window.__sessionUser.id) {
    console.log('[UPDATE-CHECK] Usuário logado, iniciando monitoramento de atualização');
    startVersionCheckLoop();
  } else {
    console.log('[UPDATE-CHECK] Usuário não logado, monitoramento de atualização desativado');
  }
});

// Menu flutuante global: Produtos no mínimo (abre Lista de produtos filtrada)
document.addEventListener('DOMContentLoaded', () => {
  // Botão no menu lateral substituiu o floating — busca pelo novo id
  const btn = document.getElementById('menu-estoque-minimo');
  if (!btn) return;

  // Badge no item de menu lateral
  const sideBadge = document.getElementById('sideMinimoBadge');

  // Cache do último resultado para reutilizar entre clique e badge
  let _ultimosCodigos = null;
  let _carregando = false;

  function atualizaBadge(qtd) {
    const n = Number(qtd) || 0;
    if (sideBadge) {
      sideBadge.textContent = n > 999 ? '999+' : String(n);
      sideBadge.hidden = n <= 0;
    }
  }

  async function carregaMinimos({ silencioso = false } = {}) {
    if (_carregando) return _ultimosCodigos;
    _carregando = true;
    try {
      const resp = await fetch('/api/logistica/produtos-no-minimo', { credentials: 'include' });
      const data = await resp.json();
      if (!resp.ok || !data?.ok) throw new Error(data?.error || `HTTP ${resp.status}`);
      const itens = Array.isArray(data.itens) ? data.itens : [];
      _ultimosCodigos = new Set(
        itens.map(it => String(it.codigo || '').trim()).filter(Boolean)
      );
      atualizaBadge(_ultimosCodigos.size);
      return _ultimosCodigos;
    } catch (err) {
      console.error('[floating-menu] erro ao carregar produtos no mínimo:', err);
      if (!silencioso) alert(`Erro ao abrir lista filtrada: ${err.message || err}`);
      return null;
    } finally {
      _carregando = false;
    }
  }

  // Carrega contador silenciosamente ao abrir a página
  carregaMinimos({ silencioso: true });

  // Atualiza badge a cada 5 minutos sem incomodar o usuário
  setInterval(() => carregaMinimos({ silencioso: true }), 5 * 60 * 1000);

  async function _abrirEstoqueMinimo(btnEl) {
    if (btnEl) btnEl.disabled = true;
    try {
      const codigosNoMinimo = await carregaMinimos();
      if (!codigosNoMinimo) return;

      const btnTopLista = document.getElementById('menu-lista-produtos');
      const btnLateral = document.getElementById('btn-omie-list1')
                      || document.getElementById('btn-omie-list');

      if (btnTopLista) {
        btnTopLista.click();
      } else if (btnLateral) {
        btnLateral.click();
      }

      await new Promise(resolve => setTimeout(resolve, 120));

      if (typeof window.__setListaProdutosExternalFilter === 'function') {
        window.__setListaProdutosExternalFilter(
          (item) => codigosNoMinimo.has(String(item?.codigo || '').trim()),
          'Filtro: Produtos no mínimo'
        );
      }
    } finally {
      if (btnEl) btnEl.disabled = false;
    }
  }

  btn.addEventListener('click', (e) => { e.preventDefault(); _abrirEstoqueMinimo(btn); });

  // Expor para que atalhos flutuantes gerados por drag-and-drop possam chamar a mesma ação
  window.__atalhoAction = window.__atalhoAction || {};
  window.__atalhoAction['side:log:estoque-minimo'] = () => _abrirEstoqueMinimo(null);
});

